}
$Script:ClassPrefixes = @{
	$Script:SeverityClasses.Info     = "[?] "
	$Script:SeverityClasses.SubInfo  = "[?] "
	$Script:SeverityClasses.Finding  = "[!] "
	$Script:SeverityClasses.Hint     = "[+] "
	$Script:SeverityClasses.Note     = "[*] "
	$Script:SeverityClasses.Secure   = "[#] "
