$Script:NameToSID = @{}
foreach ($identity in $Script:WellKnownIdentities) {
	$sid = $identity.SID
	$name = $identity.Name
	$Script:SIDToName[$sid] = $name
	$Script:NameToSID[$name] = $sid
	if ($identity.Short) {
	    $Script:NameToSID[$identity.Short] = $sid
	}
}
