	}
}
function Get-ExceptionErrorInfo {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [System.Exception]$Exception,
	    [Parameter(Mandatory=$false)]
	    [string]$Context = "Operation",
	    [Parameter(Mandatory=$false)]
	    [switch]$IncludeOriginalMessage
	)
	$result = [PSCustomObject]@{
	    HResult        = $null
	    Win32Code      = $null
	    Name           = $null
	    Message        = $null
	    Category       = 'Unknown'
	    IsError        = $true
	    IsRetryable    = $false
	    IsAccessDenied = $false
	    IsNotFound     = $false
	    Context        = $Context
	    OriginalMessage = $Exception.Message
	}
	$hresult = $Exception.HResult
	if ($null -ne $hresult -and $hresult -ne 0) {
	    $result.HResult = $hresult
	    $result.Win32Code = $hresult -band 0xFFFF
	    $errorInfo = ConvertFrom-HResult -HResult $hresult
	    if ($errorInfo.Name -notmatch '^UNKNOWN') {
	        $result.Name = $errorInfo.Name
	        $result.Message = $errorInfo.Message
	        $result.Category = $errorInfo.Category
	        $result.IsError = $errorInfo.IsError
	        $result.IsRetryable = $errorInfo.IsRetryable
	        $result.IsAccessDenied = $errorInfo.IsAccessDenied
	        $result.IsNotFound = $errorInfo.IsNotFound
	        return $result
	    }
	}
	if ($Exception -is [System.UnauthorizedAccessException]) {
	    $result.Name = 'UnauthorizedAccessException'
	    $result.Message = 'Access denied'
	    $result.Category = 'AccessDenied'
	    $result.IsAccessDenied = $true
	    return $result
	}
	if ($Exception -is [System.Net.Sockets.SocketException]) {
	    $socketCode = $Exception.SocketErrorCode
	    $result.Win32Code = [int]$socketCode
	    $result.Name = "SocketException_$socketCode"
	    $result.Message = "Network error: $($Exception.Message)"
	    $result.Category = 'Network'
	    $result.IsRetryable = $true
	    return $result
	}
	if ($Exception -is [System.TimeoutException]) {
	    $result.Name = 'TimeoutException'
	    $result.Message = 'Operation timed out'
	    $result.Category = 'Timeout'
	    $result.IsRetryable = $true
	    return $result
	}
	if ($Exception -is [System.Security.Authentication.AuthenticationException]) {
	    $sslMsg = if ($Exception.InnerException) { $Exception.InnerException.Message } else { $Exception.Message }
	    $result.OriginalMessage = $sslMsg
	    if ($sslMsg -match 'certificate|trust|validation|verify|chain|revoked|expired') {
	        $result.Name = 'SSLCertificateError'
	        $result.Message = "SSL certificate validation failed: $sslMsg"
	        $result.Category = 'SSLCertificate'
	    }
	    elseif ($sslMsg -match 'closed|reset|aborted|refused|terminated') {
	        $result.Name = 'SSLConnectionClosed'
	        $result.Message = "Server closed SSL connection - may not support LDAPS or TLS version mismatch"
	        $result.Category = 'SSLConnection'
	    }
	    elseif ($sslMsg -match 'protocol|version|handshake|TLS|SSL') {
	        $result.Name = 'SSLProtocolError'
	        $result.Message = "TLS/SSL protocol error - server may require specific TLS version"
	        $result.Category = 'SSLProtocol'
	    }
	    elseif ($sslMsg -match 'timeout|timed out') {
	        $result.Name = 'SSLTimeout'
	        $result.Message = 'SSL handshake timed out'
	        $result.Category = 'Timeout'
	        $result.IsRetryable = $true
	    }
	    else {
	        $result.Name = 'SSLError'
	        $result.Message = "SSL/TLS handshake failed: $sslMsg"
	        $result.Category = 'SSLConnection'
	    }
	    return $result
	}
	if ($Exception.GetType().FullName -eq 'System.DirectoryServices.Protocols.LdapException') {
	    $ldapErrorCode = $Exception.ErrorCode
	    $ldapInfo = ConvertFrom-LDAPError -ErrorCode $ldapErrorCode
	    $result.Win32Code = $ldapErrorCode
	    $result.Name = $ldapInfo.Name
	    $result.Message = $ldapInfo.Message
	    $result.Category = $ldapInfo.Category
	    $result.IsError = $ldapInfo.IsError
	    $result.IsRetryable = $ldapInfo.IsRetryable
	    $result.IsAccessDenied = $ldapInfo.IsAccessDenied
	    $result.IsNotFound = $ldapInfo.IsNotFound
	    return $result
	}
	if ($IncludeOriginalMessage -or -not $hresult) {
	    $result.Message = "$Context error: $($Exception.Message)"
	} else {
	    $result.Message = "$Context error (0x{0:X8})" -f $hresult
	}
	return $result
}
function Test-ErrorRetryable {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [System.Exception]$Exception
	)
	$errorInfo = Get-ExceptionErrorInfo -Exception $Exception
	return $errorInfo.IsRetryable
}
function Test-ErrorAccessDenied {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [System.Exception]$Exception
	)
	$errorInfo = Get-ExceptionErrorInfo -Exception $Exception
	return $errorInfo.IsAccessDenied
}
function Test-LDAPErrorNotFound {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [System.Exception]$Exception
	)
	$LDAP_NO_SUCH_OBJECT = [int]0x80072030
	if ($Exception.HResult -eq $LDAP_NO_SUCH_OBJECT) {
	    return $true
	}
	if ($Exception.InnerException -and $Exception.InnerException.HResult -eq $LDAP_NO_SUCH_OBJECT) {
	    return $true
	}
	if ($Exception -is [System.DirectoryServices.DirectoryServicesCOMException] -and
	    $Exception.ErrorCode -eq $LDAP_NO_SUCH_OBJECT) {
	    return $true
	}
	if (($Exception.HResult -band 0xFFFF) -eq 0x2030) {
	    return $true
	}
	return $false
}
function Escape-LDAPFilterValue {
	[CmdletBinding()]
	[OutputType([string])]
	param(
	    [Parameter(Mandatory = $true, ValueFromPipeline = $true)]
	    [AllowEmptyString()]
	    [string]$Value
	)
	process {
	    if ([string]::IsNullOrEmpty($Value)) {
	        return $Value
	    }
	    $result = [System.Text.StringBuilder]::new($Value.Length * 2)
	    foreach ($char in $Value.ToCharArray()) {
	        switch ($char) {
	            '*'  { [void]$result.Append('\2a'); break }
	            '('  { [void]$result.Append('\28'); break }
	            ')'  { [void]$result.Append('\29'); break }
	            '\'  { [void]$result.Append('\5c'); break }
	            "`0" { [void]$result.Append('\00'); break }  # NUL character
	            default {
	                $charCode = [int]$char
	                if ($charCode -lt 32 -or $charCode -gt 126) {
	                    $bytes = [System.Text.Encoding]::UTF8.GetBytes([string]$char)
	                    foreach ($byte in $bytes) {
	                        [void]$result.Append('\')
	                        [void]$result.Append($byte.ToString('x2'))
	                    }
	                }
	                else {
	                    [void]$result.Append($char)
	                }
	            }
	        }
	    }
	    return $result.ToString()
	}
}
function Escape-LDAPFilterDN {
	[CmdletBinding()]
	[OutputType([string])]
	param(
	    [Parameter(Mandatory = $true, ValueFromPipeline = $true)]
	    [AllowEmptyString()]
	    [string]$DistinguishedName
	)
	process {
	    if ([string]::IsNullOrEmpty($DistinguishedName)) {
	        return $DistinguishedName
	    }
	    $result = [System.Text.StringBuilder]::new($DistinguishedName.Length * 2)
	    $chars = $DistinguishedName.ToCharArray()
	    $i = 0
	    while ($i -lt $chars.Length) {
	        $char = $chars[$i]
	        if ($char -eq '\') {
	            if (($i + 2) -lt $chars.Length) {
	                $next1 = $chars[$i + 1]
	                $next2 = $chars[$i + 2]
	                $isHex1 = ($next1 -ge '0' -and $next1 -le '9') -or ($next1 -ge 'a' -and $next1 -le 'f') -or ($next1 -ge 'A' -and $next1 -le 'F')
	                $isHex2 = ($next2 -ge '0' -and $next2 -le '9') -or ($next2 -ge 'a' -and $next2 -le 'f') -or ($next2 -ge 'A' -and $next2 -le 'F')
	                if ($isHex1 -and $isHex2) {
	                    [void]$result.Append($chars[$i])
	                    [void]$result.Append($chars[$i + 1])
	                    [void]$result.Append($chars[$i + 2])
	                    $i += 3
	                    continue
	                }
	            }
	            if (($i + 1) -lt $chars.Length) {
	                $next = $chars[$i + 1]
	                if ($next -eq ',' -or $next -eq '+' -or $next -eq '"' -or $next -eq '\' -or
	                    $next -eq '<' -or $next -eq '>' -or $next -eq ';' -or $next -eq '#' -or $next -eq ' ') {
	                    [void]$result.Append($chars[$i])
	                    [void]$result.Append($chars[$i + 1])
	                    $i += 2
	                    continue
	                }
	            }
	            [void]$result.Append('\5c')
	        }
	        elseif ($char -eq '*') {
	            [void]$result.Append('\2a')
	        }
	        elseif ($char -eq '(') {
	            [void]$result.Append('\28')
	        }
	        elseif ($char -eq ')') {
	            [void]$result.Append('\29')
	        }
	        elseif ($char -eq "`0") {
	            [void]$result.Append('\00')
	        }
	        else {
	            $charCode = [int]$char
	            if ($charCode -lt 32 -or $charCode -gt 126) {
	                $bytes = [System.Text.Encoding]::UTF8.GetBytes([string]$char)
	                foreach ($byte in $bytes) {
	                    [void]$result.Append('\')
	                    [void]$result.Append($byte.ToString('x2'))
	                }
	            }
	            else {
	                [void]$result.Append($char)
	            }
	        }
	        $i++
	    }
	    return $result.ToString()
	}
}
function Test-ValidComputerName {
	[CmdletBinding()]
	[OutputType([bool])]
	param(
	    [Parameter(Mandatory = $true, ValueFromPipeline = $true)]
	    [AllowEmptyString()]
	    [string]$ComputerName,
	    [Parameter(Mandatory = $false)]
	    [switch]$AllowFQDN,
	    [Parameter(Mandatory = $false)]
	    [switch]$AllowIPAddress
	)
	process {
	    if ([string]::IsNullOrWhiteSpace($ComputerName)) {
	        return $false
	    }
	    $name = $ComputerName.Trim()
	    if ($name -match '\.\.' -or $name -match '[\\/]') {
	        return $false
	    }
	    if ($name -match '[;&|`$<>]') {
	        return $false
	    }
	    if ($AllowIPAddress) {
	        $ipResult = $null
	        if ([System.Net.IPAddress]::TryParse($name, [ref]$ipResult)) {
	            if ($ipResult.AddressFamily -eq [System.Net.Sockets.AddressFamily]::InterNetworkV6) {
	                return $true
	            }
	        }
	    }
	    if ($name -match '\.') {
	        $ipv4Pattern = '^(?:(?:25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)\.){3}(?:25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)$'
	        if ($name -match $ipv4Pattern) {
	            if ($AllowIPAddress) {
	                return $true
	            }
	            return $false
	        }
	        if (-not $AllowFQDN) {
	            return $false
	        }
	        $fqdnPattern = '^(?=.{1,253}$)(?:[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?\.)+[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?$'
	        if ($name -match $fqdnPattern) {
	            return $true
	        }
	        return $false
	    }
	    if ($name.Length -lt 1 -or $name.Length -gt 15) {
	        return $false
	    }
	    if ($name -notmatch '^[a-zA-Z0-9]') {
	        return $false
	    }
	    if ($name -notmatch '[a-zA-Z0-9]$') {
	        return $false
	    }
	    if ($name -notmatch '^[a-zA-Z0-9_-]+$') {
	        return $false
	    }
	    if ($name -match '^\d+$') {
	        return $false
	    }
	    return $true
	}
}
function Test-ValidUNCPath {
	[CmdletBinding()]
	[OutputType([bool])]
	param(
	    [Parameter(Mandatory = $true, ValueFromPipeline = $true)]
	    [AllowEmptyString()]
	    [string]$UNCPath,
	    [Parameter(Mandatory = $false)]
	    [string[]]$AllowedHosts,
	    [Parameter(Mandatory = $false)]
	    [string[]]$AllowedShares
	)
	process {
	    if ([string]::IsNullOrWhiteSpace($UNCPath)) {
	        return $false
	    }
	    if ($UNCPath -notmatch '^\\\\') {
	        return $false
	    }
	    if ($UNCPath -match '\.\.') {
	        return $false
	    }
	    if ($UNCPath -match '[;&|`<>]') {
	        return $false
	    }
	    if ($UNCPath -notmatch '^\\\\([^\\]+)\\([^\\]+)') {
	        return $false
	    }
	    $uncHost = $Matches[1]
	    $share = $Matches[2]
	    if (-not (Test-ValidComputerName -ComputerName $uncHost -AllowFQDN -AllowIPAddress)) {
	        return $false
	    }
	    if ($AllowedHosts -and $AllowedHosts.Count -gt 0) {
	        $hostAllowed = $false
	        foreach ($allowedHost in $AllowedHosts) {
	            if ($uncHost -ieq $allowedHost) {
	                $hostAllowed = $true
	                break
	            }
	        }
	        if (-not $hostAllowed) {
	            return $false
	        }
	    }
	    if ($share -notmatch '^[a-zA-Z0-9_.-]+\$?$') {
	        return $false
	    }
	    if ($AllowedShares -and $AllowedShares.Count -gt 0) {
	        $shareAllowed = $false
	        foreach ($allowedShare in $AllowedShares) {
	            if ($share -ieq $allowedShare) {
	                $shareAllowed = $true
	                break
	            }
	        }
	        if (-not $shareAllowed) {
	            return $false
	        }
	    }
	    return $true
	}
}
function Write-adPEASOutput {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true, Position=0, ValueFromPipeline=$true)]
	    [AllowEmptyString()]
	    [string]$Text,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet("Info", "SubInfo", "Finding", "Hint", "Note", "Secure", "Standard")]
	    [string]$Class = "Standard",
	    [Parameter(Mandatory=$false)]
	    [switch]$NoPrefix,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoNewline,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoColor,
	    [Parameter(Mandatory=$false)]
	    [switch]$LeadingNewline
	)
	begin {
	    $ANSI = $Script:ANSI
	    $ANSI_esc = $Script:ANSI_esc
	}
	process {
	    $prefix = if (-not $NoPrefix) { Get-ClassPrefix -Class $Class } else { "" }
	    $plainText = $prefix + $Text
	    if ($LeadingNewline) {
	        $plainText = "`n" + $plainText
	    }
	    if ($Script:adPEAS_OutputColor -ne $false -and -not $NoColor) {
	        $color = Get-ClassColor -Class $Class
	        $coloredText = $color + $plainText + $ANSI["Reset"]
	        Write-Host $coloredText -NoNewline:$NoNewline
	    } else {
	        Write-Host $plainText -NoNewline:$NoNewline
	    }
	    if ($Script:adPEAS_Outputfile) {
	        if ($Script:adPEAS_OutputColor -ne $false -and -not $NoColor) {
	            $color = Get-ClassColor -Class $Class
	            $fileText = $color + $plainText + $ANSI["Reset"]
	        } else {
	            $fileText = $plainText -replace "$ANSI_esc\[\d+(;\d+)*m", ""
	        }
	        if (-not $NoNewline) {
	            $fileText = $fileText + "`n"
	        }
	        [System.IO.File]::AppendAllText($Script:adPEAS_Outputfile, $fileText, [System.Text.Encoding]::UTF8)
	    }
	}
}
function Write-adPEASAttribute {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [string]$Name,
	    [Parameter(Mandatory=$true)]
	    [string]$Value,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet("Info", "SubInfo", "Finding", "Hint", "Note", "Secure", "Standard")]
	    [string]$Class = "Standard",
	    [Parameter(Mandatory=$false)]
	    [ValidateSet("Info", "SubInfo", "Finding", "Hint", "Note", "Secure", "Standard")]
	    [string]$ValueClass,
	    [Parameter(Mandatory=$false)]
	    [int]$AlignAt = 45,
	    [Parameter(Mandatory=$false)]
	    [switch]$ColorValue
	)
	$ANSI = $Script:ANSI
	$ANSI_esc = $Script:ANSI_esc
	$IsContinuationLine = [string]::IsNullOrEmpty($Name)
	$prefix = if (-not $IsContinuationLine) { Get-ClassPrefix -Class $Class } else { "" }
	$hasPrefix = ($prefix.Length -gt 0)
	$paddingWidth = if ($hasPrefix) { $AlignAt - 4 } else { $AlignAt }
	$nameWithColon = if ($Name) { "${Name}:" } else { "" }
	$paddedName = $nameWithColon.PadRight($paddingWidth, ' ')
	$plainText = $prefix + $paddedName + $Value
	if ($Script:adPEAS_OutputColor -ne $false) {
	    $classColor = Get-ClassColor -Class $Class
	    if ($ColorValue -and $Class -notin @("Standard", "Secure")) {
	        $coloredText = $classColor + $plainText + $ANSI["Reset"]
	        Write-Host $coloredText
	    } elseif ($Class -eq "Secure") {
	        $nameOnlyWithColon = if ($Name) { "${Name}:" } else { "" }
	        $paddingSpaces = ' ' * ($paddingWidth - $nameOnlyWithColon.Length)
	        $coloredOutput = $classColor + $prefix + $nameOnlyWithColon + $ANSI["Reset"] +
	                        $paddingSpaces +
	                        $classColor + $Value + $ANSI["Reset"]
	        Write-Host $coloredOutput
	    } else {
	        $attrPart = $prefix + $paddedName
	        $effectiveValueClass = if ($ValueClass) { $ValueClass } else { "Standard" }
	        $valueColor = Get-ClassColor -Class $effectiveValueClass
	        Write-Host ($classColor + $attrPart + $ANSI["Reset"] + $valueColor + $Value + $ANSI["Reset"])
	    }
	} else {
	    Write-Host $plainText
	}
	if ($Script:adPEAS_Outputfile) {
	    if ($Script:adPEAS_OutputColor -ne $false) {
	        $classColor = Get-ClassColor -Class $Class
	        if ($ColorValue -and $Class -notin @("Standard", "Secure")) {
	            $fileText = $classColor + $plainText + $ANSI["Reset"]
	        } elseif ($Class -eq "Secure") {
	            $nameOnlyWithColon = if ($Name) { "${Name}:" } else { "" }
	            $paddingSpaces = ' ' * ($paddingWidth - $nameOnlyWithColon.Length)
	            $fileText = $classColor + $prefix + $nameOnlyWithColon + $ANSI["Reset"] +
	                        $paddingSpaces +
	                        $classColor + $Value + $ANSI["Reset"]
	        } else {
	            $attrPart = $prefix + $paddedName
	            $effectiveValueClass = if ($ValueClass) { $ValueClass } else { "Standard" }
	            $valueColor = Get-ClassColor -Class $effectiveValueClass
	            $fileText = $classColor + $attrPart + $ANSI["Reset"] + $valueColor + $Value + $ANSI["Reset"]
	        }
	    } else {
	        $fileText = $plainText -replace "$ANSI_esc\[\d+(;\d+)*m", ""
	    }
	    [System.IO.File]::AppendAllText($Script:adPEAS_Outputfile, $fileText + "`n", [System.Text.Encoding]::UTF8)
	}
}
function Show-EmptyLine {
	[CmdletBinding()]
	param()
	Write-Host ""
	if ($Script:adPEAS_Outputfile) {
	    [System.IO.File]::AppendAllText($Script:adPEAS_Outputfile, "`n", [System.Text.Encoding]::UTF8)
	}
}
function Write-adPEASLogo {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [string]$Version = "2.0"
	)
	$ANSI = $Script:ANSI
	$Legend = @{
	    "Info"    = "[?] Searching for juicy information"
	    "Finding" = "[!] Found a vulnerability which may be exploitable"
	    "Hint"    = "[+] Found some interesting information for further investigation"
	    "Note"    = "[*] Some kind of note"
	    "Secure"  = "[#] Some kind of secure configuration"
	}
	if ($Script:adPEAS_OutputColor -ne $false) {
	    foreach ($cls in @("Info", "Finding", "Hint", "Note", "Secure")) {
	        $color = Get-ClassColor -Class $cls
	        $Legend[$cls] = $color + $Legend[$cls] + $ANSI["Reset"]
	    }
	}
	$LogoStart = if ($Script:adPEAS_OutputColor -ne $false) { Get-ClassColor -Class "Info" } else { "" }
	$LogoStop = if ($Script:adPEAS_OutputColor -ne $false) { $ANSI["Reset"] } else { "" }
	$LogoText = @"
$LogoStart
	           _ _____  ______           _____
	          | |  __ \|  ____|   /\    / ____|
	  ____  __| | |__) | |__     /  \  | (___
	 / _  |/ _  |  ___/|  __|   / /\ \  \___ \
	| (_| | (_| | |    | |____ / ____ \ ____) |
	 \__,_|\__,_|_|    |______/_/    \_\_____/
	                                        Version $Version
$LogoStop
	Active Directory Enumeration
	by @61106960
$("")
	Legend
	    $($Legend["Info"])
	    $($Legend["Finding"])
	    $($Legend["Hint"])
	    $($Legend["Note"])
	    $($Legend["Secure"])
"@
	Write-Host $LogoText
	Write-Host ""
	if ($Script:adPEAS_Outputfile) {
	    if ($Script:adPEAS_OutputColor -ne $false) {
	        [System.IO.File]::AppendAllText($Script:adPEAS_Outputfile, $LogoText + "`n`n", [System.Text.Encoding]::UTF8)
	    } else {
	        $ANSI_esc = $Script:ANSI_esc
	        $FileLogoText = $LogoText -replace "$ANSI_esc\[\d+(;\d+)*m", ""
	        [System.IO.File]::AppendAllText($Script:adPEAS_Outputfile, $FileLogoText + "`n`n", [System.Text.Encoding]::UTF8)
	    }
	}
}
function Write-adPEASHeader {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$Value
	)
	$ANSI = $Script:ANSI
	$ANSI_esc = $Script:ANSI_esc
	$SeparatorLine = "=" * 70
	$HeaderLine = "+++++ $Value +++++"
	if ($Script:adPEAS_OutputColor -ne $false) {
	    $color = Get-ClassColor -Class "Info"
	    $output = "`n`n" + $color + $SeparatorLine + "`n" + $HeaderLine + "`n" + $SeparatorLine + $ANSI["Reset"]
	    Write-Host $output
	} else {
	    Write-Host ("`n`n" + $SeparatorLine)
	    Write-Host $HeaderLine
	    Write-Host $SeparatorLine
	}
	if ($Script:adPEAS_Outputfile) {
	    if ($Script:adPEAS_OutputColor -ne $false) {
	        $color = Get-ClassColor -Class "Info"
	        $fileOutput = "`n`n" + $color + $SeparatorLine + "`n" + $HeaderLine + "`n" + $SeparatorLine + $ANSI["Reset"] + "`n"
	        [System.IO.File]::AppendAllText($Script:adPEAS_Outputfile, $fileOutput, [System.Text.Encoding]::UTF8)
	    } else {
	        $fileOutput = "`n`n" + $SeparatorLine + "`n" + $HeaderLine + "`n" + $SeparatorLine + "`n"
	        [System.IO.File]::AppendAllText($Script:adPEAS_Outputfile, $fileOutput, [System.Text.Encoding]::UTF8)
	    }
	}
}
