	    $isAdmin = ($sid.Value -match '-512$|-519$') -or ($sid.Value -eq 'S-1-5-18')  # Domain/Enterprise Admins or SYSTEM
	    -not $isAdmin -and (
	        $_.ActiveDirectoryRights -match "GenericAll|WriteDacl|WriteOwner|WriteProperty"
