	        @{ Title = "Set-Acl - Microsoft Learn"; Url = "https://learn.microsoft.com/en-us/powershell/module/microsoft.powershell.security/set-acl" }
	    )
	    Tools = @("BloodHound", "PowerView")
	    MITRE = "T1098.002"
	    Triggers = @(
