	    Attack = @(
	        "1. Task path: C:\\Program Files\\App Folder\\task.exe"
	        "2. Attacker places C:\\Program.exe"
	        "3. Windows executes C:\\Program.exe instead"
	        "4. Attacker code runs with task privileges"
