function Export-FindingDefinitionsJson {
	[CmdletBinding()]
	param(
	    [switch]$Minified
	)
	$jsonObject = @{}
	foreach ($key in $Script:FindingDefinitions.Keys) {
	    $def = $Script:FindingDefinitions[$key]
	    $refs = [System.Collections.Generic.List[object]]::new()
	    if ($def.References) {
	        foreach ($ref in $def.References) {
	            $refs.Add(@{ title = $ref.Title; url = $ref.Url })
	        }
	    }
	    $tools = [System.Collections.Generic.List[object]]::new()
	    if ($def.Tools) {
	        foreach ($tool in $def.Tools) {
	            if ($tool -is [hashtable] -or $tool -is [System.Collections.Specialized.OrderedDictionary]) {
	                $tools.Add(@{ name = $tool.Name; url = $tool.Url })
	            } else {
	                $toolUrl = $Script:ToolUrls[$tool]
	                $tools.Add(@{ name = [string]$tool; url = $toolUrl })
	            }
	        }
	    }
	    $remediationCmds = [System.Collections.Generic.List[object]]::new()
	    if ($def.RemediationCommands) {
	        foreach ($cmd in $def.RemediationCommands) {
	            $remediationCmds.Add(@{ description = $cmd.Description; command = $cmd.Command })
	        }
	    }
	    $jsonObject[$key] = @{
	        title = $def.Title
	        risk = $def.Risk
	        baseScore = $def.BaseScore
	        description = $def.Description
	        impact = $def.Impact
	        attack = $def.Attack
	        remediation = $def.Remediation
	        remediationCommands = $remediationCmds.ToArray()
	        references = $refs.ToArray()
	        tools = $tools.ToArray()
	        mitre = $def.MITRE
	    }
	}
	if ($Minified) {
	    return ($jsonObject | ConvertTo-Json -Depth 10 -Compress)
	} else {
	    return ($jsonObject | ConvertTo-Json -Depth 10)
	}
}
$Script:FindingTriggerIndex = @{}
$triggerLists = @{}  # Temporary List<object> per attribute for O(1) append
foreach ($findingId in $Script:FindingDefinitions.Keys) {
	$definition = $Script:FindingDefinitions[$findingId]
	if (-not $definition.ContainsKey('Triggers') -or $null -eq $definition.Triggers) {
	    continue
	}
	foreach ($trigger in $definition.Triggers) {
	    if (-not $trigger.Attribute) { continue }
	    $attrName = $trigger.Attribute.ToLower()
	    if (-not $triggerLists.ContainsKey($attrName)) {
	        $triggerLists[$attrName] = [System.Collections.Generic.List[object]]::new()
	    }
	    $triggerLists[$attrName].Add(@{
	        FindingId      = $findingId
	        Pattern        = $trigger.Pattern
	        ExcludePattern = $trigger.ExcludePattern
	        Context        = $trigger.Context
	        Custom         = $trigger.Custom
	        Severity       = $trigger.Severity      # Optional: per-trigger severity override
	        SeverityOnly   = $trigger.SeverityOnly   # If $true, Get-FindingIdForAttribute skips this
	        ParentRisk     = $definition.Risk        # Parent definition risk level
	    })
	}
}
foreach ($key in $triggerLists.Keys) {
	$Script:FindingTriggerIndex[$key] = $triggerLists[$key].ToArray()
}
Remove-Variable -Name triggerLists -ErrorAction SilentlyContinue
function Get-FindingIdForAttribute {
	[CmdletBinding()]
	param(
	    [string]$Name,
	    $Value,
	    [string]$Context = $null
	)
	$match = Get-TriggerMatch -Name $Name -Value $Value -Context $Context
	return $match.FindingId
}
function Get-SeverityFromTrigger {
	[CmdletBinding()]
	param(
	    [string]$Name,
	    $Value,
	    [bool]$IsComputer = $false,
	    $SourceObject = $null,
	    [string]$Context = $null
	)
	$match = Get-TriggerMatch -Name $Name -Value $Value -IsComputer $IsComputer `
	    -SourceObject $SourceObject -Context $Context
	$severity = $match.Severity
	if ($severity -eq 'Standard') { return $null }
	return $severity
}
function Get-TriggerMatch {
	[CmdletBinding()]
	param(
	    [string]$Name,
	    $Value,
	    [bool]$IsComputer = $false,
	    $SourceObject = $null,
	    [string]$Context = $null
	)
	$noMatch = [PSCustomObject]@{ Severity = 'Standard'; FindingId = $null }
	if ([string]::IsNullOrEmpty($Name)) { return $noMatch }
	if (-not $IsComputer -and $SourceObject) {
	    $IsComputer = Test-IsComputerObject -Object $SourceObject
	}
	$attrNameLower = $Name.ToLower()
	$strValue = [string]$Value
	if (-not $Script:FindingTriggerIndex.ContainsKey($attrNameLower)) {
	    return $noMatch
	}
	$triggers = $Script:FindingTriggerIndex[$attrNameLower]
	$resultSeverity = $null
	$resultFindingId = $null
	foreach ($pass in @($true, $false)) {
	    foreach ($trigger in $triggers) {
	        $isSeverityOnly = [bool]$trigger.SeverityOnly
	        if ($isSeverityOnly -ne $pass) { continue }
	        if ($trigger.Context) {
	            if (-not $Context -or $Context -notmatch $trigger.Context) { continue }
	        }
	        if ($trigger.ExcludePattern) {
	            if ($strValue -match $trigger.ExcludePattern) { continue }
	        }
	        $matched = $false
	        if ($trigger.Custom) {
	            $customResult = Test-CustomTrigger -CustomType $trigger.Custom -Value $Value `
	                -IsComputer $IsComputer -SourceObject $SourceObject
	            if (-not $customResult) { continue }
	            if ($trigger.Pattern) {
	                if ($strValue -notmatch $trigger.Pattern) { continue }
	            }
	            $matched = $true
	        } elseif ($trigger.Pattern) {
	            if ($strValue -match $trigger.Pattern) { $matched = $true }
	        } else {
	            $matched = $true
	        }
	        if (-not $matched) { continue }
	        if ($null -eq $resultSeverity) {
	            $resultSeverity = if ($trigger.Severity) { $trigger.Severity } else { $trigger.ParentRisk }
	        }
	        if ($null -eq $resultFindingId -and -not $isSeverityOnly) {
	            $resultFindingId = $trigger.FindingId
	        }
	        if ($null -ne $resultSeverity -and $null -ne $resultFindingId) {
	            break
	        }
	    }
	    if ($null -ne $resultSeverity -and $null -ne $resultFindingId) {
	        break
	    }
	}
	if ($null -eq $resultSeverity -and $null -eq $resultFindingId) {
	    return $noMatch
	}
	return [PSCustomObject]@{
	    Severity  = if ($resultSeverity) { $resultSeverity } else { 'Standard' }
	    FindingId = $resultFindingId
	}
}
function Test-CustomTrigger {
	param(
	    [string]$CustomType,
	    $Value,
	    [bool]$IsComputer = $false,
	    $SourceObject = $null
	)
	switch ($CustomType) {
	    'is_not_computer' {
	        if ($IsComputer) { return $false }
	        if ($SourceObject -and (Test-IsComputerObject -Object $SourceObject)) {
	            return $false
	        }
	        return $true
	    }
	    'is_privileged_sid' {
	        $sid = if ($Value -is [string] -and $Value -match '^S-1-') { $Value }
	               elseif ($Value -is [PSCustomObject] -and $Value.PSObject.Properties['SID']) { $Value.SID }
	               else { $null }
	        if (-not $sid) { return $false }
	        $privResult = Test-IsPrivileged -Identity $sid
	        return ($privResult.Category -eq 'Privileged')
	    }
	    'is_operator_sid' {
	        $sid = if ($Value -is [string] -and $Value -match '^S-1-') { $Value }
	               elseif ($Value -is [PSCustomObject] -and $Value.PSObject.Properties['SID']) { $Value.SID }
	               else { $null }
	        if (-not $sid) { return $false }
	        $privResult = Test-IsPrivileged -Identity $sid
	        return ($privResult.Category -eq 'Operator')
	    }
	    'is_broad_group_sid' {
	        $sid = if ($Value -is [string] -and $Value -match '^S-1-') { $Value }
	               elseif ($Value -is [PSCustomObject] -and $Value.PSObject.Properties['SID']) { $Value.SID }
	               else { [string]$Value }
	        if (-not $sid) { return $false }
	        if (Get-Command -Name 'Test-IsBroadGroupSID' -ErrorAction SilentlyContinue) {
	            return (Test-IsBroadGroupSID -SID $sid)
	        }
	        $privResult = Test-IsPrivileged -Identity $sid
	        return ($privResult.Category -eq 'BroadGroup')
	    }
	    'is_not_default_owner' {
	        if ($SourceObject -and $SourceObject.OwnerSID) {
	            $isDefault = Test-IsDefaultOwner -SID $SourceObject.OwnerSID
	            return (-not $isDefault)
	        }
	        return $false
	    }
	    'is_within_forest_trust' {
	        if ($SourceObject -and $SourceObject.isWithinForest -eq $true) {
	            return $true
	        }
	        return $false
	    }
	    'is_gpo_finding_object' {
	        if (-not $SourceObject) { return $false }
	        $hasDangerousPerms = $SourceObject.PSObject.Properties['DangerousPermissions'] -and $SourceObject.DangerousPermissions
	        $hasDangerousSettings = $SourceObject.PSObject.Properties['DangerousSettings'] -and $SourceObject.DangerousSettings
	        return ($hasDangerousPerms -or $hasDangerousSettings)
	    }
	    'is_hardcoded_path' {
	        $strVal = [string]$Value
	        if ([string]::IsNullOrWhiteSpace($strVal)) { return $false }
	        return ($strVal -match '^\\\\[^\\]+\\' -or $strVal -match '^[A-Za-z]:[\\\/]')
	    }
	    'is_dc_uac' {
	        $allFlags = if ($SourceObject) { [string]$SourceObject } else { [string]$Value }
	        return ($allFlags -match 'SERVER_TRUST_ACCOUNT')
	    }
	    'is_exchange_eol' {
	        $strValue = [string]$Value
	        $severity = 'Standard'
	        if ($strValue -match '^\d+\.\d+\.\d+') {
	            $severity = Get-ExchangeSeverity -BuildNumber $strValue
	        } elseif ($SourceObject) {
	            $buildNum = if ($SourceObject.PSObject.Properties['ExchangeBuildNumber']) { $SourceObject.ExchangeBuildNumber } else { $null }
	            if ($buildNum) {
	                $severity = Get-ExchangeSeverity -BuildNumber $buildNum
	            } else {
	                $severity = Get-ExchangeSeverity -ProductName $strValue
	            }
	        } else {
	            $severity = Get-ExchangeSeverity -ProductName $strValue
	        }
	        return ($severity -ne 'Standard')
	    }
	    'credential_needs_review' {
	        if ($SourceObject -and $SourceObject.credentialType -and $SourceObject.credentialType -match '\(needs review\)') {
	            return $true
	        }
	        return $false
	    }
	    'dangerous_rights_expected' {
	        if ($SourceObject -and $SourceObject.dangerousRightsSeverity) {
	            return ($SourceObject.dangerousRightsSeverity -in @('Expected', 'Attention', 'Hint'))
	        }
	        return $false
	    }
	    'is_dnsadmins_sid' {
	        $sid = if ($Value -is [string] -and $Value -match '^S-1-') { $Value }
	               elseif ($Value -is [PSCustomObject] -and $Value.PSObject.Properties['SID']) { $Value.SID }
	               else { $null }
	        if (-not $sid) { return $false }
	        $resolvedName = ConvertFrom-SID -SID $sid
	        return ($resolvedName -match '\\DnsAdmins$')
	    }
	    'days_over_365' {
	        $strValue = [string]$Value
	        if ($strValue -match '^(\d+)') {
	            return ([int]$Matches[1] -gt 365)
	        }
	        return $false
	    }
	    'days_91_to_365' {
	        $strValue = [string]$Value
	        if ($strValue -match '^(\d+)') {
	            $days = [int]$Matches[1]
	            return ($days -gt 90 -and $days -le 365)
	        }
	        return $false
	    }
	    'days_181_to_365' {
	        $strValue = [string]$Value
	        if ($strValue -match '^(\d+)') {
	            $days = [int]$Matches[1]
	            return ($days -gt 180 -and $days -le 365)
	        }
	        return $false
	    }
	    'lt_8' {
	        $strValue = [string]$Value
	        if ($strValue -match 'Disabled') { return $true }
	        $intValue = 0
	        if ([int]::TryParse($strValue, [ref]$intValue)) {
	            return ($intValue -lt 8)
	        }
	        if ($strValue -match '^(\d+)') {
	            if ([int]::TryParse($Matches[1], [ref]$intValue)) {
	                return ($intValue -lt 8)
	            }
	        }
	        return $false
	    }
	    'affected_computers_gt_10' {
	        $intValue = 0
	        if ([int]::TryParse([string]$Value, [ref]$intValue)) {
	            return ($intValue -gt 10)
	        }
	        return $false
	    }
	    'affected_computers_gt_0' {
	        $intValue = 0
	        if ([int]::TryParse([string]$Value, [ref]$intValue)) {
	            return ($intValue -gt 0 -and $intValue -le 10)
	        }
	        return $false
	    }
	    'pwdAge_gt_1825' {
	        $pwdDate = Get-DateFromValue -Value $Value
	        if ($pwdDate) {
	            $pwdAge = ((Get-Date) - $pwdDate).Days
	            return ($pwdAge -gt 1825)
	        }
	        return $false
	    }
	    'pwdAge_365_1825' {
	        $pwdDate = Get-DateFromValue -Value $Value
	        if ($pwdDate) {
	            $pwdAge = ((Get-Date) - $pwdDate).Days
	            return ($pwdAge -gt 365 -and $pwdAge -le 1825)
	        }
	        return $false
	    }
	    'gt_0' {
	        $intValue = 0
	        if ([int]::TryParse([string]$Value, [ref]$intValue)) {
	            return ($intValue -gt 0)
	        }
	        return $false
	    }
	    'lt_12' {
	        $strValue = [string]$Value
	        $intValue = 0
	        if ([int]::TryParse($strValue, [ref]$intValue)) {
	            return ($intValue -lt 12)
	        }
	        if ($strValue -match '^(\d+)') {
	            if ([int]::TryParse($Matches[1], [ref]$intValue)) {
	                return ($intValue -lt 12)
	            }
	        }
	        return $false
	    }
	    'lt_10_minutes' {
	        $strValue = [string]$Value
	        if ($strValue -match 'Forever|Permanent|manual') {
	            return $false
	        }
	        $intValue = 0
	        if ([int]::TryParse($strValue, [ref]$intValue)) {
	            return ($intValue -gt 0 -and $intValue -lt 10)
	        }
	        if ($strValue -match '^(\d+)') {
	            if ([int]::TryParse($Matches[1], [ref]$intValue)) {
	                return ($intValue -gt 0 -and $intValue -lt 10)
	            }
	        }
	        return $false
	    }
	    default {
	        return $false
	    }
	}
}
function Get-DateFromValue {
	param($Value)
	if ($null -eq $Value) { return $null }
	if ($Value -is [DateTime]) {
	    return $Value
	}
	if ($Value -is [Int64] -or $Value -is [long]) {
	    if ($Value -gt 0) {
	        try {
	            return [DateTime]::FromFileTime($Value)
	        } catch {
	            return $null
	        }
	    }
	    return $null
	}
	$strValue = [string]$Value
	if ([string]::IsNullOrEmpty($strValue)) { return $null }
	$longValue = 0
	if ([long]::TryParse($strValue, [ref]$longValue) -and $longValue -gt 0) {
	    try {
	        return [DateTime]::FromFileTime($longValue)
	    } catch {
	    }
	}
	$dtValue = [DateTime]::MinValue
	if ([DateTime]::TryParse($strValue, [ref]$dtValue)) {
	    return $dtValue
	}
	return $null
}
function Get-AttributeSeverity {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$Name,
	    [Parameter(Mandatory=$false)]
	    $Value,
	    [Parameter(Mandatory=$false)]
	    [bool]$IsComputer = $false,
	    [Parameter(Mandatory=$false)]
	    $SourceObject = $null
	)
	if (-not $IsComputer -and $SourceObject) {
	    if ($SourceObject.objectClass) {
	        $IsComputer = $SourceObject.objectClass -contains 'computer' -or
	                      $SourceObject.objectClass -eq 'computer' -or
	                      ($SourceObject.objectClass -is [string] -and $SourceObject.objectClass -match 'computer')
	    }
	    if (-not $IsComputer -and $SourceObject.sAMAccountName -and $SourceObject.sAMAccountName -match '\$$') {
	        $IsComputer = $true
	    }
	}
	$triggerSeverity = Get-SeverityFromTrigger -Name $Name -Value $Value `
	    -IsComputer $IsComputer -SourceObject $SourceObject
	if ($null -ne $triggerSeverity) {
	    return $triggerSeverity
	}
	return "Standard"
}
function Convert-DNsToMemberInfo {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [array]$DistinguishedNames
	)
	$DistinguishedNames | ForEach-Object {
	    $dn = $_
	    $cn = if ($dn -match '^CN=([^,]+)') { $Matches[1] } else { $dn }
	    [PSCustomObject]@{
	        DisplayName = $cn
	        DN = $dn
	        SID = ConvertTo-SID -Identity $dn
	    }
	}
}
function Get-MemberClass {
	param($MemberInfo)
	Get-AttributeSeverity -Name 'Member' -Value $MemberInfo.SID
}
function Get-ExchangeGroupMemberClass {
	param($MemberInfo)
	$sid = $MemberInfo.SID
	$dn = $MemberInfo.DN
	if (-not $sid) {
	    return "Hint"
	}
	if ($dn -and $dn -match 'OU=Microsoft Exchange Security Groups') {
	    return "Hint"
	}
	if ($Script:LdapConnection -and $sid) {
	    try {
	        $exchangeCheck = Test-IsExchangeServer -Identity $sid
	        if ($exchangeCheck.IsExchangeServer) {
	            return "Hint"
	        }
	    } catch {
	        Write-Debug "[Get-ExchangeGroupMemberClass] Exchange server check failed for SID $sid - $($_.Exception.Message)"
	    }
	}
	if ($Script:LdapConnection -and $sid) {
	    try {
	        $sidHex = ConvertTo-LDAPSIDHex -SID $sid
	        if ($sidHex) {
	            $obj = @(Get-DomainObject -LDAPFilter "(objectSid=$sidHex)" -Properties 'objectClass')[0]
	            if ($obj -and $obj.objectClass) {
	                $objectClasses = @($obj.objectClass)
	                if ($objectClasses -contains 'computer') {
	                    return "Hint"
	                }
	            }
	        }
	    } catch {
	        Write-Debug "[Get-ExchangeGroupMemberClass] Computer account check failed for SID $sid - $($_.Exception.Message)"
	    }
	}
	$privilegeCheck = Test-IsPrivileged -Identity $sid -IncludeOperators
	if ($privilegeCheck.IsPrivileged -eq $true) {
	    return "Hint"
	}
	if ($dn -and ($dn -match 'CN=Computers,' -or $dn -match 'OU=.*Server')) {
	    return "Hint"
	}
	$name = $MemberInfo.DisplayName
	if ($name -and $name -match '\$$') {
	    return "Hint"
	}
	return "Finding"
}
function Get-MemberOfClass {
	param($GroupInfo)
	Get-AttributeSeverity -Name 'MemberOf' -Value $GroupInfo
}
function Get-SIDHistoryClass {
	param([string]$SID)
	Get-AttributeSeverity -Name 'sIDHistory' -Value $SID
}
function Convert-MemberOfToRenderValues {
	[CmdletBinding()]
	param([string]$Name, $Value, $Context)
	$memberOfArray = @($Value)
	$memberOfObjects = Convert-DNsToMemberInfo -DistinguishedNames $memberOfArray
	$renderValues = @()
	foreach ($groupInfo in $memberOfObjects) {
	    $groupClass = Get-MemberOfClass -GroupInfo $groupInfo
	    $findingId = switch ($groupClass) {
	        'Finding' { 'PRIVILEGED_GROUP_MEMBERSHIP' }
	        'Hint'    { 'OPERATOR_GROUP_MEMBERSHIP' }
	        default   { $null }
	    }
	    $renderValues += New-RenderValue -Display $groupInfo.DisplayName `
	        -Severity $groupClass -FindingId $findingId `
	        -RawValue $groupInfo.DN -Metadata @{ SID = $groupInfo.SID }
	}
	$maxSev = Get-MaxSeverityFromValues -Values $renderValues
	return @{
	    RowType             = 'MultiValue'
	    OverallSeverity     = $maxSev
	    ForceAttributeClass = ($maxSev -ne 'Standard')
	    Values              = $renderValues
	}
}
function Convert-PrivilegedGroupsToRenderValues {
	[CmdletBinding()]
	param([string]$Name, $Value, $Context)
	$privGroupValues = @($Value)
	$firstItem = $privGroupValues | Select-Object -First 1
	$isNewFormat = $firstItem -is [PSCustomObject] -and $firstItem.PSObject.Properties['SID']
	$renderValues = @()
	if ($isNewFormat) {
	    foreach ($entry in $privGroupValues) {
	        $sid = $entry.SID
	        $displayText = $entry.DisplayText
	        $triggerResult = if ($sid) {
	            Get-TriggerMatch -Name 'privilegedGroups' -Value $sid
	        } else { [PSCustomObject]@{ Severity = 'Hint'; FindingId = $null } }
	        $severity = if ($triggerResult.Severity -ne 'Standard') { $triggerResult.Severity } else { 'Standard' }
	        $findingId = $triggerResult.FindingId
	        $renderValues += New-RenderValue -Display $displayText `
	            -Severity $severity -FindingId $findingId `
	            -RawValue $entry -Metadata @{ SID = $sid }
	    }
	} else {
	    foreach ($g in $privGroupValues) {
	        $triggerResult = Get-TriggerMatch -Name 'privilegedGroups' -Value $g
	        $severity = if ($triggerResult.Severity -ne 'Standard') { $triggerResult.Severity } else { 'Standard' }
	        $renderValues += New-RenderValue -Display ([string]$g) -Severity $severity `
	            -FindingId $triggerResult.FindingId -RawValue $g
	    }
	}
	$maxSev = Get-MaxSeverityFromValues -Values $renderValues
	return @{
	    RowType             = 'MultiValue'
	    OverallSeverity     = $maxSev
	    ForceAttributeClass = ($maxSev -ne 'Standard')
	    Values              = $renderValues
	}
}
function Convert-MemberToRenderValues {
	[CmdletBinding()]
	param([string]$Name, $Value, $Context)
	$memberArray = @($Value)
	$memberObjects = Convert-DNsToMemberInfo -DistinguishedNames $memberArray
	$isExchangeGroup = $Context.IsExchangeGroup
	$renderValues = @()
	foreach ($memberInfo in $memberObjects) {
	    if ($isExchangeGroup) {
	        $memberClass = Get-ExchangeGroupMemberClass -MemberInfo $memberInfo
	        $findingId = switch ($memberClass) {
	            'Finding' { 'EXCHANGE_GROUP_LOW_PRIV_MEMBER' }
	            default   { $null }
	        }
	    } else {
	        $memberClass = Get-MemberClass -MemberInfo $memberInfo
	        $findingId = switch ($memberClass) {
	            'Finding' { 'PRIVILEGED_GROUP_MEMBERSHIP' }
	            default   { $null }
	        }
	    }
	    $renderValues += New-RenderValue -Display $memberInfo.DisplayName `
	        -Severity $memberClass -FindingId $findingId `
	        -RawValue $memberInfo.DN -Metadata @{ SID = $memberInfo.SID }
	}
	$maxSev = Get-MaxSeverityFromValues -Values $renderValues
	return @{
	    RowType             = 'MultiValue'
	    OverallSeverity     = $maxSev
	    ForceAttributeClass = $true
	    Values              = $renderValues
	}
}
function Convert-UACToRenderValues {
	[CmdletBinding()]
	param([string]$Name, $Value, $Context)
	$uacFlags = @($Value)
	$allFlagsStr = $uacFlags -join ' '
	$renderValues = @()
	foreach ($flag in $uacFlags) {
	    $flagStr = [string]$flag
	    $match = Get-TriggerMatch -Name 'userAccountControl' -Value $flagStr -SourceObject $allFlagsStr
	    $renderValues += New-RenderValue -Display $flagStr -Severity $match.Severity -FindingId $match.FindingId -RawValue $flag
	}
	$maxSev = Get-MaxSeverityFromValues -Values $renderValues
	return @{
	    RowType             = 'MultiValue'
	    OverallSeverity     = $maxSev
	    ForceAttributeClass = ($maxSev -ne 'Standard')
	    Values              = $renderValues
	}
}
function Convert-SPNToRenderValues {
	[CmdletBinding()]
	param([string]$Name, $Value, $Context)
	$spnValues = @($Value)
	$renderValues = @()
	$isComputer = $Context.IsComputer
	foreach ($spn in $spnValues) {
	    if ($isComputer) {
	        $renderValues += New-RenderValue -Display ([string]$spn) -Severity 'Standard' -RawValue $spn
	    } else {
	        $match = Get-TriggerMatch -Name 'servicePrincipalName' -Value $spn -IsComputer $false
	        $renderValues += New-RenderValue -Display ([string]$spn) -Severity $match.Severity -FindingId $match.FindingId -RawValue $spn
	    }
	}
	$maxSev = Get-MaxSeverityFromValues -Values $renderValues
	return @{
	    RowType             = 'MultiValue'
	    OverallSeverity     = $maxSev
	    ForceAttributeClass = (-not $isComputer)
	    Values              = $renderValues
	}
}
function Convert-SIDHistoryToRenderValues {
	[CmdletBinding()]
	param([string]$Name, $Value, $Context)
	$sidHistoryRaw = @($Value)
	$renderValues = @()
	foreach ($sidEntry in $sidHistoryRaw) {
	    $sidString = $null
	    if ($sidEntry -is [byte[]]) {
	        try {
	            $secId = New-Object System.Security.Principal.SecurityIdentifier($sidEntry, 0)
	            $sidString = $secId.Value
	        } catch { continue }
	    } elseif ($sidEntry -is [string]) {
	        $sidString = $sidEntry
	    } else { continue }
	    if ($sidString) {
	        $sidClass = Get-SIDHistoryClass -SID $sidString
	        $resolvedName = ConvertFrom-SID -SID $sidString
	        $display = if ($resolvedName -and $resolvedName -ne $sidString) {
	            "$resolvedName ($sidString)"
	        } else { $sidString }
	        $findingId = Get-FindingIdForAttribute -Name 'sIDHistory' -Value $sidString
	        $renderValues += New-RenderValue -Display $display -Severity $sidClass `
	            -FindingId $findingId -RawValue $sidString -Metadata @{ ResolvedName = $resolvedName }
	    }
	}
	if ($renderValues.Count -eq 0) { return $null }
	$maxSev = Get-MaxSeverityFromValues -Values $renderValues
	return @{
	    DisplayName         = 'sIDHistory (SID History Injection risk!)'
	    RowType             = 'MultiValue'
	    OverallSeverity     = $maxSev
	    ForceAttributeClass = $true
	    Values              = $renderValues
	}
}
function Convert-OwnerToRenderValues {
	[CmdletBinding()]
	param([string]$Name, $Value, $Context)
	$ownerSID = $Context.OwnerSID
	if (-not $ownerSID) { return $null }
	$domainSID = $Script:LDAPContext.DomainSID
	$isDefault = Test-IsDefaultOwner -SID $ownerSID -DomainSID $domainSID
	if ($isDefault) {
	    return @{
	        RowType             = 'SingleValue'
	        OverallSeverity     = 'Standard'
	        ForceAttributeClass = $false
	        Values              = @(
	            New-RenderValue -Display ([string]$Value) -Severity 'Standard' -RawValue $Value
	        )
	    }
	}
	$findingId = Get-FindingIdForAttribute -Name 'Owner' -Value $Value
	if (-not $findingId) { $findingId = 'NON_DEFAULT_COMPUTER_OWNERS' }
	return @{
	    DisplayName         = 'Owner (non-default)'
	    RowType             = 'SingleValue'
	    OverallSeverity     = 'Finding'
	    ForceAttributeClass = $true
	    Values              = @(
	        New-RenderValue -Display ([string]$Value) -Severity 'Finding' -FindingId $findingId -RawValue $Value
	    )
	}
}
function Convert-GMSAToRenderValues {
	[CmdletBinding()]
	param([string]$Name, $Value, $Context)
	$gmsaPrincipals = @()
	if ($Value -is [PSCustomObject] -and $Value.PSObject.Properties['ACEs']) {
	    $gmsaPrincipals = @($Value.ACEs | Where-Object { $_.Type -eq 'Allow' } | ForEach-Object {
	        [PSCustomObject]@{ Name = $_.Name; SID = $_.SID }
	    })
	}
	elseif ($Value -is [array]) {
	    $firstItem = $Value | Select-Object -First 1
	    if ($firstItem -is [PSCustomObject] -and $firstItem.PSObject.Properties['Name'] -and $firstItem.PSObject.Properties['SID']) {
	        $gmsaPrincipals = @($Value)
	    } else {
	        $gmsaAllowEntries = @($Value | Where-Object { $_ -match '^Allow\s+-' })
	        $gmsaPrincipals = @($gmsaAllowEntries | ForEach-Object {
	            $principalName = if ($_ -match '^Allow\s+-\s+(.+?)\s+-\s+') { $Matches[1] } else { $_ }
	            [PSCustomObject]@{ Name = $principalName; SID = $null }
	        })
	    }
	}
	if ($gmsaPrincipals.Count -eq 0) { return $null }
	$renderValues = @()
	foreach ($principal in $gmsaPrincipals) {
	    $severity = 'Hint'
	    $findingId = 'GMSA_MEMBERSHIP_INFO'
	    if ($principal.SID) {
	        $privResult = Test-IsPrivileged -Identity $principal.SID
	        if ($privResult.Category -eq 'Privileged') {
	            $severity = 'Finding'
	            $findingId = 'GMSA_PASSWORD_READABLE'
	        }
	        elseif ($privResult.Category -in @('Operator', 'BroadGroup')) {
	            $severity = 'Finding'
	            $findingId = 'GMSA_PASSWORD_READABLE'
	        }
	    }
	    $renderValues += New-RenderValue -Display $principal.Name -Severity $severity `
	        -FindingId $findingId -RawValue $principal -Metadata @{ SID = $principal.SID }
	}
	$maxSev = Get-MaxSeverityFromValues -Values $renderValues
	return @{
	    DisplayName         = 'PrincipalsAllowedToRetrievePassword'
	    RowType             = 'MultiValue'
	    OverallSeverity     = $maxSev
	    ForceAttributeClass = $true
	    Values              = $renderValues
	}
}
function Convert-DangerousRightsToRenderValues {
	[CmdletBinding()]
	param([string]$Name, $Value, $Context)
	$sourceObject = $Context.SourceObject
	$rightsValues = if ($Value -is [string] -and $Value -match ',') {
	    @($Value -split ',\s*' | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
	} else {
	    @($Value)
	}
	$overallClass = Get-AttributeSeverity -Name 'dangerousRightsSeverity' `
	    -Value $Context.DangerousRightsSeverity -SourceObject $sourceObject
	$displayName = if ($sourceObject.dangerousRightsESC) {
	    "dangerousRights [$($sourceObject.dangerousRightsESC)]"
	} else { 'dangerousRights' }
	$renderValues = @()
	foreach ($right in $rightsValues) {
	    $rightStr = [string]$right
	    $findingId = if ($Context.IsExchangeGroup) {
	        'EXCHANGE_GROUP_PERMISSIONS'
	    } else {
	        Get-FindingIdForAttribute -Name 'dangerousRights' -Value $rightStr
	    }
	    $renderValues += New-RenderValue -Display $rightStr -Severity $overallClass `
	        -FindingId $findingId -RawValue $right
	}
	return @{
	    DisplayName         = $displayName
	    RowType             = 'MultiValue'
	    OverallSeverity     = $overallClass
	    ForceAttributeClass = $true
	    Values              = $renderValues
	}
}
