function Render-ConsoleObject {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    $Model,
	    [Parameter(Mandatory=$false)]
	    [int]$AlignAt = 45
	)
	$outputSomething = $false
	foreach ($row in $Model.Primary) {
	    Render-ConsoleRow -Row $row -AlignAt $AlignAt
	    $outputSomething = $true
	}
	foreach ($row in $Model.PostObject) {
	    Render-ConsolePostObjectRow -Row $row
	    $outputSomething = $true
	}
	if ($outputSomething) {
	    Show-EmptyLine
	}
}
function Render-ConsoleRow {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    $Row,
	    [Parameter(Mandatory=$false)]
	    [int]$AlignAt = 45
	)
	switch ($Row.RowType) {
	    'SingleValue' {
	        $val = $Row.Values[0]
	        $colorValue = ($Row.OverallSeverity -ne 'Standard')
	        Write-adPEASAttribute -Name $Row.Name -Value $val.Display -Class $Row.OverallSeverity -AlignAt $AlignAt -ColorValue:$colorValue
	    }
	    'MultiValue' {
	        $classifiedValues = @()
	        foreach ($val in $Row.Values) {
	            $classifiedValues += [PSCustomObject]@{ Value = $val.Display; Class = $val.Severity }
	        }
	        if ($classifiedValues.Count -eq 0) { return }
	        $attrClass = if ($Row.ForceAttributeClass -or $Row.OverallSeverity -ne 'Standard') {
	            $Row.OverallSeverity
	        } else { 'Standard' }
	        $attrPrefix = Get-ClassPrefix -Class $attrClass
	        $hasAttrPrefix = ($attrPrefix.Length -gt 0)
	        $ANSI = $Script:ANSI
	        $attrPadding = if ($hasAttrPrefix) { $AlignAt - 4 } else { $AlignAt }
	        $paddedAttrName = "$($Row.Name):".PadRight($attrPadding, ' ')
	        $firstVal = $classifiedValues[0]
	        $firstLinePlain = $attrPrefix + $paddedAttrName + $firstVal.Value
	        if ($Script:adPEAS_OutputColor -ne $false) {
	            $attrColor = Get-ClassColor -Class $attrClass
	            $valColor = Get-ClassColor -Class $firstVal.Class
	            if ($attrClass -eq "Secure") {
	                $nameOnlyWithColon = "$($Row.Name):"
	                $paddingSpaces = ' ' * ($attrPadding - $nameOnlyWithColon.Length)
	                $coloredOutput = $attrColor + $attrPrefix + $nameOnlyWithColon + $ANSI["Reset"] + $paddingSpaces + $valColor + $firstVal.Value + $ANSI["Reset"]
	                Write-Host $coloredOutput
	            } else {
	                $attrPart = $attrColor + $attrPrefix + $paddedAttrName + $ANSI["Reset"]
	                Write-Host ($attrPart + $valColor + $firstVal.Value + $ANSI["Reset"])
	            }
	        } else {
	            Write-Host $firstLinePlain
	        }
	        if ($Script:adPEAS_Outputfile) {
	            if ($Script:adPEAS_OutputColor -ne $false) {
	                $attrColor = Get-ClassColor -Class $attrClass
	                $valColor = Get-ClassColor -Class $firstVal.Class
	                if ($attrClass -eq "Secure") {
	                    $nameOnlyWithColon = "$($Row.Name):"
	                    $paddingSpaces = ' ' * ($attrPadding - $nameOnlyWithColon.Length)
	                    $fileText = $attrColor + $attrPrefix + $nameOnlyWithColon + $ANSI["Reset"] + $paddingSpaces + $valColor + $firstVal.Value + $ANSI["Reset"]
	                } else {
	                    $fileText = $attrColor + $attrPrefix + $paddedAttrName + $ANSI["Reset"] + $valColor + $firstVal.Value + $ANSI["Reset"]
	                }
	            } else {
	                $fileText = $firstLinePlain
	            }
	            [System.IO.File]::AppendAllText($Script:adPEAS_Outputfile, $fileText + "`n", [System.Text.Encoding]::UTF8)
	        }
	        $indent = " " * $AlignAt
	        for ($i = 1; $i -lt $classifiedValues.Count; $i++) {
	            $cv = $classifiedValues[$i]
	            $linePlain = $indent + $cv.Value
	            if ($Script:adPEAS_OutputColor -ne $false) {
	                $lineColor = Get-ClassColor -Class $cv.Class
	                Write-Host ($indent + $lineColor + $cv.Value + $ANSI["Reset"])
	            } else {
	                Write-Host $linePlain
	            }
	            if ($Script:adPEAS_Outputfile) {
	                if ($Script:adPEAS_OutputColor -ne $false) {
	                    $lineColor = Get-ClassColor -Class $cv.Class
	                    $fileText = $indent + $lineColor + $cv.Value + $ANSI["Reset"]
	                } else {
	                    $fileText = $linePlain
	                }
	                [System.IO.File]::AppendAllText($Script:adPEAS_Outputfile, $fileText + "`n", [System.Text.Encoding]::UTF8)
	            }
	        }
	    }
	    'Image' {
	        $val = $Row.Values[0]
	        Write-adPEASAttribute -Name $Row.Name -Value $val.Display -AlignAt $AlignAt
	    }
	}
}
function Render-ConsolePostObjectRow {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    $Row
	)
	$val = $Row.Values[0]
	$hashLabel = switch ($Row.RawName) {
	    'KerberoastingHash' {
	        if ($val.RawValue -is [PSCustomObject] -and $val.RawValue.PSObject.Properties['KerberoastingHashType']) {
	            $val.RawValue.KerberoastingHashType
	        } else { 'Kerberoast Hash' }
	    }
	    'ASREPRoastingHash' {
	        if ($val.RawValue -is [PSCustomObject] -and $val.RawValue.PSObject.Properties['ASREPRoastingHashType']) {
	            $val.RawValue.ASREPRoastingHashType
	        } else { 'AS-REP Roast Hash' }
	    }
	    default { $Row.Name }
	}
	Show-Line "${hashLabel}:" -Class "Finding" -NoCollect
	Write-adPEASOutput -Text $val.Display -Class "Finding" -NoPrefix
}
function Render-HtmlObject {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    $Model,
	    [Parameter(Mandatory=$true)]
	    [string]$ObjectId,
	    [Parameter(Mandatory=$false)]
	    [string]$Severity = 'Standard'
	)
	$primaryHtml = [System.Text.StringBuilder]::new()
	$extendedHtml = [System.Text.StringBuilder]::new()
	foreach ($row in $Model.Primary) {
	    [void]$primaryHtml.AppendLine((Render-HtmlRow -Row $row))
	}
	foreach ($row in $Model.Extended) {
	    [void]$extendedHtml.AppendLine((Render-HtmlRow -Row $row))
	}
	foreach ($row in $Model.PostObject) {
	    [void]$primaryHtml.AppendLine((Render-HtmlRow -Row $row))
	}
	$html = [System.Text.StringBuilder]::new()
	[void]$html.Append($primaryHtml.ToString())
	$extendedContent = $extendedHtml.ToString().Trim()
	if ($extendedContent) {
	    $extendedCount = $Model.Extended.Count
	    [void]$html.AppendLine("                        <div class=`"extended-attrs-toggle`" onclick=`"toggleExtendedAttrs('$ObjectId')`">")
	    [void]$html.AppendLine("                            <span class=`"toggle-icon`" id=`"icon-$ObjectId`">&#9654;</span>")
	    [void]$html.AppendLine("                            <span>Show $extendedCount more attribute(s)</span>")
	    [void]$html.AppendLine("                        </div>")
	    [void]$html.AppendLine("                        <div class=`"extended-attrs`" id=`"ext-$ObjectId`" style=`"display: none;`">")
	    [void]$html.Append($extendedContent)
	    [void]$html.AppendLine("                        </div>")
	}
	return $html.ToString()
}
function Render-HtmlRow {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    $Row
	)
	$nameHtml = ConvertTo-HtmlEncode $Row.Name
	switch ($Row.RowType) {
	    'SingleValue' {
	        $val = $Row.Values[0]
	        $displayHtml = ConvertTo-HtmlEncode $val.Display
	        $valueHtml = Format-HtmlValueSpan -DisplayHtml $displayHtml -Severity $val.Severity -FindingId $val.FindingId
	        $classAttr = Get-HtmlValueClassAttr -Severity $Row.OverallSeverity
	        $attrNameEncoded = ConvertTo-HtmlEncode $Row.Name
	        return "                        <div class=`"attr-row`" draggable=`"true`" data-attr-name=`"$attrNameEncoded`"><div class=`"attr-name`">$nameHtml</div><div$classAttr>$valueHtml</div></div>"
	    }
	    'MultiValue' {
	        $valuesHtml = @()
	        foreach ($val in $Row.Values) {
	            $displayHtml = ConvertTo-HtmlEncode $val.Display
	            $valuesHtml += Format-HtmlValueSpan -DisplayHtml $displayHtml -Severity $val.Severity -FindingId $val.FindingId
	        }
	        $displayValue = $valuesHtml -join '<br>'
	        $attrNameEncoded = ConvertTo-HtmlEncode $Row.Name
	        return "                        <div class=`"attr-row`" draggable=`"true`" data-attr-name=`"$attrNameEncoded`"><div class=`"attr-name`">$nameHtml</div><div class=`"attr-value`">$displayValue</div></div>"
	    }
	    'Image' {
	        $val = $Row.Values[0]
	        $rawValue = $val.RawValue
	        $isImageData = $false
	        if ($rawValue -is [PSCustomObject]) {
	            if ($rawValue.psobject.TypeNames -contains 'adPEAS.ImageData') {
	                $isImageData = $true
	            }
	            elseif ($rawValue.PSObject.Properties['Base64'] -and $rawValue.PSObject.Properties['MimeType']) {
	                $isImageData = $true
	            }
	        }
	        if ($isImageData) {
	            $allowedMimeTypes = @('image/jpeg', 'image/png', 'image/gif', 'image/bmp', 'image/webp')
	            $mimeType = if ($rawValue.MimeType -in $allowedMimeTypes) { $rawValue.MimeType } else { 'image/png' }
	            $imgSrc = "data:$mimeType;base64,$($rawValue.Base64)"
	            $imgTypeEncoded = ConvertTo-HtmlEncode $rawValue.ImageType
	            $imgSizeEncoded = ConvertTo-HtmlEncode $rawValue.SizeKB
	            $imgTitle = "$imgTypeEncoded image, $imgSizeEncoded KB"
	            $altText = ConvertTo-HtmlEncode $Row.Name
	            $displayValue = "<img src=`"$imgSrc`" alt=`"$altText`" title=`"$imgTitle`" style=`"max-width: 96px; max-height: 96px; border: 1px solid #555; border-radius: 4px;`" /><br><span style=`"font-size: 0.85em; color: #888;`">$imgTitle</span>"
	            $attrNameEncoded = ConvertTo-HtmlEncode $Row.Name
	            return "                        <div class=`"attr-row`" draggable=`"true`" data-attr-name=`"$attrNameEncoded`"><div class=`"attr-name`">$nameHtml</div><div class=`"attr-value`">$displayValue</div></div>"
	        }
	        $displayHtml = ConvertTo-HtmlEncode $val.Display
	        $attrNameEncoded = ConvertTo-HtmlEncode $Row.Name
	        return "                        <div class=`"attr-row`" draggable=`"true`" data-attr-name=`"$attrNameEncoded`"><div class=`"attr-name`">$nameHtml</div><div class=`"attr-value`">$displayHtml</div></div>"
	    }
	    'Hash' {
	        $val = $Row.Values[0]
	        $displayHtml = ConvertTo-HtmlEncode $val.Display
	        $dataAttr = if ($val.FindingId) { " data-finding-id=`"$(ConvertTo-HtmlEncode $val.FindingId)`"" } else { "" }
	        $valueHtml = "<span class=`"finding`"$dataAttr>$displayHtml</span>"
	        $attrNameEncoded = ConvertTo-HtmlEncode $Row.Name
	        return "                        <div class=`"attr-row`" draggable=`"true`" data-attr-name=`"$attrNameEncoded`"><div class=`"attr-name`">$nameHtml</div><div class=`"attr-value`">$valueHtml</div></div>"
	    }
	    default {
	        $val = if ($Row.Values.Count -gt 0) { $Row.Values[0] } else { $null }
	        $displayHtml = if ($val) { ConvertTo-HtmlEncode $val.Display } else { '' }
	        $attrNameEncoded = ConvertTo-HtmlEncode $Row.Name
	        return "                        <div class=`"attr-row`" draggable=`"true`" data-attr-name=`"$attrNameEncoded`"><div class=`"attr-name`">$nameHtml</div><div class=`"attr-value`">$displayHtml</div></div>"
	    }
	}
}
function Format-HtmlValueSpan {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$DisplayHtml,
	    [Parameter(Mandatory=$false)]
	    [string]$Severity = 'Standard',
	    [Parameter(Mandatory=$false)]
	    [string]$FindingId = $null
	)
	if ($Severity -eq 'Standard' -or -not $Severity) {
	    return $DisplayHtml
	}
	$cssClass = ConvertTo-HtmlEncode $Severity.ToLower()
	$dataAttr = if ($FindingId) { " data-finding-id=`"$(ConvertTo-HtmlEncode $FindingId)`"" } else { "" }
	return "<span class=`"$cssClass`"$dataAttr>$DisplayHtml</span>"
}
function Get-HtmlValueClassAttr {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [string]$Severity = 'Standard'
	)
	if ($Severity -eq 'Standard' -or -not $Severity) {
	    return " class=`"attr-value`""
	}
	$cssClass = ConvertTo-HtmlEncode $Severity.ToLower()
	return " class=`"attr-value $cssClass`""
}
function Get-FindingBaseScores {
	$scores = @{}
	if ($null -eq $Script:FindingDefinitions) {
	    Write-Warning "[Get-FindingBaseScores] FindingDefinitions not loaded"
	    return $scores
	}
	foreach ($entry in $Script:FindingDefinitions.GetEnumerator()) {
	    $findingId = $entry.Key
	    $definition = $entry.Value
	    if ($definition.ContainsKey('BaseScore')) {
	        $scores[$findingId] = $definition.BaseScore
	    } else {
	        $risk = if ($definition.ContainsKey('Risk')) { $definition.Risk } else { 'Standard' }
	        $scores[$findingId] = switch ($risk) {
	            'Finding' { $Script:SeverityFallbackScores[$Script:SeverityClasses.Finding] }
	            'Hint'    { $Script:SeverityFallbackScores[$Script:SeverityClasses.Hint] }
	            'Note'    { $Script:SeverityFallbackScores[$Script:SeverityClasses.Note] }
	            'Secure'  { $Script:SeverityFallbackScores[$Script:SeverityClasses.Secure] }
	            default   { 0 }
	        }
	    }
	}
	return $scores
}
$Script:SeverityFallbackScores = @{
	$Script:SeverityClasses.Finding  = 35    # Red findings without keyword match
	$Script:SeverityClasses.Hint     = 15    # Yellow hints without keyword match
	$Script:SeverityClasses.Note     = 0     # Green notes
	$Script:SeverityClasses.Secure   = 0     # Secure configurations
	$Script:SeverityClasses.Standard = 0     # Standard output (no severity)
}
