	    TitleFormat = "MSA: {Name}"
	    Module = "Accounts"
	    Category = "Accounts"
	    SectionTitle = "Standalone Managed Service Accounts"
	    Summary = "Identifies standalone Managed Service Accounts (legacy sMSAs)."
