function Get-adPEASHelp {
	[CmdletBinding()]
	param(
	    [ValidateSet('QuickStart','Checks','Commands')]
	    [string[]]$Section
	)
	$showAll = -not $Section
	$showQuickStart = $showAll -or ($Section -contains 'QuickStart')
	$showChecks = $showAll -or ($Section -contains 'Checks')
	$showCommands = $showAll -or ($Section -contains 'Commands')
	if ($showQuickStart) {
	    Show-SubHeader "Quick Start"
	    Show-Line "Simple scan (Windows Auth):" -Class Hint
	    Show-Line "Invoke-adPEAS -Domain 'contoso.com'"
	    Show-EmptyLine
	    Show-Line "Session-based with credentials:" -Class Hint
	    Show-Line "Connect-adPEAS -Domain 'contoso.com' -Credential (Get-Credential)"
	    Show-Line "Invoke-adPEAS"
	    Show-EmptyLine
	    Show-Line "On domain-joined machines, Kerberos authentication with -Password/-NTHash/-AES*Key/-Certificate replace Kerberos tickets." -Class Note
	    Show-Line "Use Connect-adPEAS with -ForceNTLM or -ForceSimpleBind to avoid this."
	    Show-EmptyLine
	    Show-Line "More help:" -Class Hint
	    Show-Line "Get-adPEASHelp"
	    Show-Line "Get-Help Connect-adPEAS -Examples"
	    Show-Line "Get-Help <Command> -Detailed"
	    Show-EmptyLine
	}
	if ($showChecks) {
	    Show-SubHeader "Security Check Modules"
	    Show-Line "Run all modules:" -Class Hint
	    Show-Line "Invoke-adPEAS (without -Module)"
	    Show-EmptyLine
	    Show-Line "Run specific modules only:" -Class Hint
	    Show-Line "Invoke-adPEAS -Module 'Domain','Creds','ADCS'"
	    Show-EmptyLine
	    $moduleOrder = [ordered]@{
	        'Domain'      = "Domain Configuration"
	        'Creds'       = "Credential Exposure"
	        'Rights'      = "Access Permissions"
	        'Delegation'  = "Delegation Settings"
	        'ADCS'        = "AD Certificate Services"
	        'Accounts'    = "Privileged Accounts"
	        'GPO'         = "Group Policy Objects"
	        'Computer'    = "Computer Security"
	        'Application' = "Application Infrastructure"
	        'Bloodhound'  = "BloodHound Data"
	    }
	    $checksByModule = @{}
	    if ($Script:ObjectTypeDefinitions) {
	        foreach ($entry in $Script:ObjectTypeDefinitions.GetEnumerator()) {
	            $mod = $entry.Value.Module
	            if ($mod -and $moduleOrder.Contains($mod)) {
	                if (-not $checksByModule[$mod]) { $checksByModule[$mod] = @() }
	                $title = $entry.Value.SectionTitle
	                $summary = $entry.Value.Summary
	                if ($title -and ($checksByModule[$mod].Title -notcontains $title)) {
	                    $checksByModule[$mod] += @{ Title = $title; Summary = $summary }
	                }
	            }
	        }
	    }
	    foreach ($mod in $moduleOrder.Keys) {
	        $desc = $moduleOrder[$mod]
	        Show-Line "$($desc): -Module $mod" -Class Hint
	        $checks = $checksByModule[$mod]
	        if ($checks) {
	            foreach ($check in $checks) {
	                Show-KeyValue $check.Title $check.Summary
	            }
	        }
	        Show-EmptyLine
	    }
	}
	if ($showCommands) {
	    Show-SubHeader "Additional Core and Helper Modules"
	    Show-Line "Connection:" -Class Hint
	    Show-KeyValue "Connect-adPEAS" "Establish LDAP session"
	    Show-KeyValue "Disconnect-adPEAS" "Close LDAP session"
	    Show-KeyValue "Get-adPEASSession" "Show session status"
	    Show-EmptyLine
	    Show-Line "AD Queries:" -Class Hint
	    Show-KeyValue "Get-DomainUser" "Query AD users"
	    Show-KeyValue "Get-DomainComputer" "Query AD computers"
	    Show-KeyValue "Get-DomainGroup" "Query AD groups"
	    Show-KeyValue "Get-DomainGPO" "Query Group Policy Objects"
	    Show-KeyValue "Get-DomainObject" "Query any AD object"
	    Show-KeyValue "Get-ObjectACL" "Query object ACLs"
	    Show-KeyValue "Get-CertificateTemplate" "Query certificate templates"
	    Show-KeyValue "Get-CertificateAuthority" "Query certificate authorities"
	    Show-EmptyLine
	    Show-Line "AD Modifications:" -Class Hint
	    Show-KeyValue "Set-DomainUser" "Modify user attributes"
	    Show-KeyValue "Set-DomainComputer" "Modify computer attributes"
	    Show-KeyValue "Set-DomainGroup" "Modify group attributes"
	    Show-KeyValue "Set-DomainObject" "Modify any AD object"
	    Show-KeyValue "Set-DomainGPO" "Modify Group Policy Objects"
	    Show-KeyValue "Set-CertificateTemplate" "Modify certificate templates"
	    Show-KeyValue "New-DomainUser" "Create AD user"
	    Show-KeyValue "New-DomainComputer" "Create AD computer"
	    Show-KeyValue "New-DomainGroup" "Create AD group"
	    Show-KeyValue "New-DomainGPO" "Create Group Policy Object"
	    Show-EmptyLine
	    Show-Line "Kerberos Authentication:" -Class Hint
	    Show-KeyValue "Invoke-KerberosAuth" "Request TGT (Password/Hash/Key/Cert)"
	    Show-KeyValue "Request-ServiceTicket" "Request TGS for a service"
	    Show-KeyValue "Import-KerberosTicket" "Pass-the-Ticket (inject into session)"
	    Show-EmptyLine
	    Show-Line "Credential Attacks:" -Class Hint
	    Show-KeyValue "Invoke-Kerberoast" "Kerberoasting (request service tickets)"
	    Show-KeyValue "Invoke-ASREPRoast" "AS-REP Roasting (no preauth)"
	    Show-KeyValue "Invoke-DCSync" "DCSync (directory replication)"
	    Show-KeyValue "Invoke-PasswordSpray" "Password spraying"
	    Show-EmptyLine
	    Show-Line "Offensive Actions:" -Class Hint
	    Show-KeyValue "Invoke-TicketForge" "Golden/Silver/Diamond Tickets"
	    Show-KeyValue "Invoke-S4U" "S4U delegation attacks"
	    Show-KeyValue "Invoke-RBCDOperation" "Resource-Based Constrained Delegation"
	    Show-KeyValue "Invoke-ShadowCredentialOperation" "Shadow Credentials"
	    Show-KeyValue "Request-ADCSCertificate" "Request ADCS certificate"
	    Show-EmptyLine
	}
}
function Get-AuthenticatedDirectoryEntry {
	[CmdletBinding()]
	[OutputType([System.DirectoryServices.DirectoryEntry])]
	param(
	    [Parameter(Mandatory=$true, Position=0)]
	    [string]$DistinguishedName,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential
	)
	process {
	    try {
	        if (-not $Script:LDAPContext) {
	            Write-Error "[Get-AuthenticatedDirectoryEntry] No LDAP context available. Use Connect-adPEAS first."
	            return $null
	        }
	        $server = $Script:LDAPContext.Server
	        $useLDAPS = $Script:LDAPContext.UseLDAPS
	        $port = $Script:LDAPContext.Port
	        if ($server) {
	            if ($useLDAPS) {
	                $Path = "LDAP://${server}:${port}/$DistinguishedName"
	            } else {
	                $Path = "LDAP://$server/$DistinguishedName"
	            }
	        } else {
	            $Path = "LDAP://$DistinguishedName"
	        }
	        $authTypes = [System.DirectoryServices.AuthenticationTypes]::Secure
	        if ($useLDAPS) {
	            $authTypes = $authTypes -bor [System.DirectoryServices.AuthenticationTypes]::SecureSocketsLayer
	        }
	        $cred = if ($Credential) { $Credential } elseif ($Script:LDAPCredential) { $Script:LDAPCredential } else { $null }
	        if ($cred) {
	            $NetworkCred = $cred.GetNetworkCredential()
	            $Entry = New-Object System.DirectoryServices.DirectoryEntry(
	                $Path,
	                $cred.UserName,
	                $NetworkCred.Password,
	                $authTypes
	            )
	        }
	        else {
	            $Entry = New-Object System.DirectoryServices.DirectoryEntry($Path, $null, $null, $authTypes)
	        }
	        return $Entry
	    }
	    catch {
	        Write-Error "[Get-AuthenticatedDirectoryEntry] Failed to get DirectoryEntry for '$DistinguishedName': $_"
	        return $null
	    }
	}
}
function Show-ConnectionError {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [ValidateSet(
	        "AuthenticationFailed",
	        "NetworkError",
	        "CertificateError",
	        "SSLHandshakeError",
	        "PFXLoadError",
	        "PermissionError",
	        "DomainError",
	        "KerberosError",
	        "NTLMDisabledError",
	        "TicketImportError",
	        "GenericError"
	    )]
	    [string]$ErrorType,
	    [Parameter(Mandatory=$false)]
	    [string]$Details,
	    [Parameter(Mandatory=$false)]
	    [object]$ErrorCode,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet("Kerberos", "LDAP", "Win32", "HRESULT")]
	    [string]$ErrorCodeType,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoThrow
	)
	process {
	    if ($Details) {
	        $Details = $Details.Trim()
	    }
	    $ThrowMessage = "Connection failed"
	    $resolvedDetails = $null
	    if ($null -ne $ErrorCode -and $ErrorCodeType -and $ErrorCodeType -ne "Kerberos") {
	        switch ($ErrorCodeType) {
	            "LDAP" {
	                switch ([int]$ErrorCode) {
	                    1  { $resolvedDetails = "Reason: LDAP server denied the request - credentials were not accepted or bind resulted in anonymous access." }  # LDAP_OPERATIONS_ERROR
	                    8  { $resolvedDetails = "Reason: LDAP signing or channel binding is enforced by domain policy." }  # LDAP_STRONG_AUTH_REQUIRED
	                    49 { $resolvedDetails = "Reason: Wrong username or password." }  # LDAP_INVALID_CREDENTIALS
	                    50 { $resolvedDetails = "Reason: The account does not have sufficient privileges for this operation." }  # LDAP_INSUFFICIENT_RIGHTS
	                    81 { $resolvedDetails = "Reason: Cannot connect to the LDAP server - verify hostname and port." }  # LDAP_SERVER_DOWN
	                    82 { $resolvedDetails = "Reason: Authentication negotiation failed - Kerberos SPN mismatch, invalid ticket, or NTLM negotiation error." }  # LDAP_LOCAL_ERROR
	                    91 { $resolvedDetails = "Reason: Cannot establish TCP connection to LDAP server." }  # LDAP_CONNECT_ERROR
	                    default {
	                        $lookupInfo = ConvertFrom-LDAPError -ErrorCode $ErrorCode
	                        if ($lookupInfo -and $lookupInfo.Message) { $resolvedDetails = "Reason: $($lookupInfo.Message)" }
	                    }
	                }
	            }
	            "Win32" {
	                switch ([int]$ErrorCode) {
	                    1326 { $resolvedDetails = "Reason: Wrong username or password." }  # ERROR_LOGON_FAILURE
	                    1327 { $resolvedDetails = "Reason: Account has restrictions that prevent logon." }  # ERROR_ACCOUNT_RESTRICTION
	                    1328 { $resolvedDetails = "Reason: Account is not allowed to log on at this time." }  # ERROR_INVALID_LOGON_HOURS
	                    1329 { $resolvedDetails = "Reason: Account is not allowed to log on from this workstation." }  # ERROR_INVALID_WORKSTATION
	                    1330 { $resolvedDetails = "Reason: Password has expired - change password required." }  # ERROR_PASSWORD_EXPIRED
	                    1331 { $resolvedDetails = "Reason: Account is disabled." }  # ERROR_ACCOUNT_DISABLED
	                    1385 { $resolvedDetails = "Reason: Logon type (network) is not granted for this account." }  # ERROR_LOGON_TYPE_NOT_GRANTED
	                    5    { $resolvedDetails = "Reason: Access denied - insufficient privileges." }  # ERROR_ACCESS_DENIED
	                    53   { $resolvedDetails = "Reason: Network path not found - verify server hostname." }  # ERROR_BAD_NETPATH
	                    1355 { $resolvedDetails = "Reason: Domain not found - verify domain name." }  # ERROR_NO_SUCH_DOMAIN
	                    default {
	                        $lookupInfo = ConvertFrom-Win32Error -ErrorCode $ErrorCode
	                        if ($lookupInfo -and $lookupInfo.Message) { $resolvedDetails = "Reason: $($lookupInfo.Message)" }
	                    }
	                }
	            }
	            "HRESULT" {
	                $lookupInfo = ConvertFrom-HResult -HResult $ErrorCode
	                if ($lookupInfo -and $lookupInfo.Message -and $lookupInfo.Message -notmatch '^Unknown') { $resolvedDetails = "Reason: $($lookupInfo.Message)" }
	            }
	        }
	    }
	    $effectiveDetails = if ($Details) { $Details } elseif ($resolvedDetails) { $resolvedDetails } else { $null }
	    switch ($ErrorType) {
	        "AuthenticationFailed" {
	            $detailsArray = @()
	            if ($effectiveDetails) {
	                $detailsArray += $effectiveDetails
	            }
	            $IsWindowsAuth = $Script:AuthInfo.ParameterSet -eq 'WindowsAuth'
	            $IsNTLMImpersonation = $Script:AuthInfo.NTLMImpersonation -eq $true
	            $hints = @()
	            if ($IsWindowsAuth -and -not $IsNTLMImpersonation) {
	                $hints += "If using Windows Authentication, your Kerberos ticket may have expired."
	            }
	            Show-Message -Type Error -Title "Authentication failed: Invalid credentials" -Details $detailsArray -Hints $hints
	            $ThrowMessage = "Authentication failed"
	        }
	        "NetworkError" {
	            $detailsArray = @()
	            if ($effectiveDetails) {
	                $detailsArray += $effectiveDetails
	            }
	            Show-Message -Type Error -Title "Connection failed: Server unreachable" -Details $detailsArray
	            $ThrowMessage = "Network error: Server unreachable"
	        }
	        "CertificateError" {
	            $detailsArray = @()
	            if ($effectiveDetails) {
	                $detailsArray += $effectiveDetails
	            } else {
	                $detailsArray += "Use LDAP instead (remove -UseLDAPS) or fix certificate validation"
	            }
	            $hints = @(
	                "Try: -IgnoreSSLErrors to bypass certificate validation",
	                "Or: Remove -UseLDAPS to use unencrypted LDAP"
	            )
	            Show-Message -Type Error -Title "LDAPS failed: Certificate validation error" -Details $detailsArray -Hints $hints
	            $ThrowMessage = "LDAPS certificate error"
	        }
	        "SSLHandshakeError" {
	            $detailsArray = @()
	            if ($effectiveDetails) {
	                $detailsArray += $effectiveDetails
	            }
	            $hints = @(
	                "Server may not support LDAPS on port 636",
	                "Server may require specific TLS version (1.2+)",
	                "Try: Remove -UseLDAPS to use unencrypted LDAP"
	            )
	            Show-Message -Type Error -Title "LDAPS failed: SSL/TLS handshake error" -Details $detailsArray -Hints $hints
	            $ThrowMessage = "LDAPS SSL handshake failed"
	        }
	        "PFXLoadError" {
	            $detailsArray = @()
	            if ($effectiveDetails) {
	                $detailsArray += $effectiveDetails
	            }
	            $hints = @(
	                "Verify: Certificate password is correct",
	                "Verify: File is a valid PFX/P12 certificate and certificate contains a private key"
	            )
	            Show-Message -Type Error -Title "Certificate load failed" -Details $detailsArray -Hints $hints
	            $ThrowMessage = "Certificate load failed"
	        }
	        "PermissionError" {
	            $detailsArray = @()
	            if ($effectiveDetails) {
	                $detailsArray += $effectiveDetails
	            }
	            Show-Message -Type Error -Title "Access denied: Insufficient privileges" -Details $detailsArray
	            $ThrowMessage = "Permission denied"
	        }
	        "DomainError" {
	            $detailsArray = @()
	            if ($effectiveDetails) {
	                $detailsArray += $effectiveDetails
	            }
	            Show-Message -Type Error -Title "Domain not found or unreachable" -Details $detailsArray
	            $ThrowMessage = "Domain error"
	        }
	        "KerberosError" {
	            $detailsArray = @()
	            if ($null -ne $ErrorCode -and $ErrorCodeType -eq "Kerberos") {
	                switch ($ErrorCode) {
	                    6 {  # KDC_ERR_C_PRINCIPAL_UNKNOWN
	                        $detailsArray += "Reason: User not found in the domain."
	                    }
	                    12 {  # KDC_ERR_POLICY
	                        $detailsArray += "Reason: KDC policy rejects the request (check account restrictions)."
	                    }
	                    14 {  # KDC_ERR_ETYPE_NOSUPP
	                        $detailsArray += "Reason: RC4 encryption disabled - use -AES256Key instead of -NTHash"
	                    }
	                    18 {  # KDC_ERR_CLIENT_REVOKED
	                        $detailsArray += "Reason: Account is disabled or locked out."
	                    }
	                    23 {  # KDC_ERR_KEY_EXPIRED
	                        $detailsArray += "Reason: Password has expired - change password required."
	                    }
	                    24 {  # KDC_ERR_PREAUTH_FAILED
	                        $detailsArray += "Reason: Wrong password, hash, or key."
	                    }
	                    25 {  # KDC_ERR_PREAUTH_REQUIRED
	                        $detailsArray += "Reason: Pre-authentication required (internal error)."
	                    }
	                    7 {  # KDC_ERR_S_PRINCIPAL_UNKNOWN
	                        $detailsArray += "Reason: Service principal (SPN) not found in the domain."
	                    }
	                    26 {  # KDC_ERR_SERVER_NOMATCH
	                        $detailsArray += "Reason: Requested server and ticket don't match."
	                    }
	                    29 {  # KDC_ERR_SVC_UNAVAILABLE
	                        $detailsArray += "Reason: KDC service unavailable - check if DC is reachable."
	                    }
	                    37 {  # KRB_AP_ERR_SKEW
	                        $detailsArray += "Reason: Clock skew too great - sync system time with DC (max 5 min difference)."
	                    }
	                    31 {  # KRB_AP_ERR_BAD_INTEGRITY
	                        $detailsArray += "Reason: Integrity check failed - wrong key or corrupted ticket."
	                    }
	                    32 {  # KRB_AP_ERR_TKT_EXPIRED
	                        $detailsArray += "Reason: Ticket has expired - request a new ticket."
	                    }
	                    33 {  # KRB_AP_ERR_TKT_NYV
	                        $detailsArray += "Reason: Ticket not yet valid - check system time."
	                    }
	                    41 {  # KRB_AP_ERR_MODIFIED
	                        $detailsArray += "Reason: Message stream modified - ticket checksum validation failed."
	                        $detailsArray += "This usually means the wrong key was used for encryption/signing."
	                    }
	                    62 {  # KDC_ERR_CLIENT_NOT_TRUSTED
	                        $detailsArray += "Reason: Client certificate not trusted by KDC."
	                        $detailsArray += "This typically means the Domain Controller lacks PKINIT support."
	                        $detailsArray += ""
	                        $detailsArray += "PKINIT Prerequisites (Shadow Credentials / Certificate Auth):"
	                        $detailsArray += "  1. AD CS must be installed in the domain, OR"
	                        $detailsArray += "  2. DC must have a certificate from another PKI"
	                        $detailsArray += "  3. DC certificate must have 'Kerberos Authentication' EKU"
	                        $detailsArray += ""
	                        $detailsArray += "Alternative: Use Schannel/LDAPS authentication instead:"
	                        $detailsArray += "  - PassTheCert tool (LDAP/S with certificate)"
	                        $detailsArray += "  - Or use RBCD attack if you have write access to the target"
	                    }
	                    63 {  # KDC_ERR_KDC_NOT_TRUSTED
	                        $detailsArray += "Reason: KDC certificate not trusted by client."
	                    }
	                    64 {  # KDC_ERR_INVALID_SIG
	                        $detailsArray += "Reason: Invalid signature in PKINIT request."
	                    }
	                    66 {  # KDC_ERR_CERTIFICATE_MISMATCH
	                        $detailsArray += "Reason: Certificate doesn't match the principal name."
	                    }
	                    70 {  # KDC_ERR_CANT_VERIFY_CERTIFICATE
	                        $detailsArray += "Reason: Cannot verify certificate - check CA trust chain."
	                    }
	                    71 {  # KDC_ERR_INVALID_CERTIFICATE
	                        $detailsArray += "Reason: Invalid certificate - not valid for Kerberos authentication."
	                    }
	                    72 {  # KDC_ERR_REVOKED_CERTIFICATE
	                        $detailsArray += "Reason: Certificate has been revoked."
	                    }
	                    77 {  # KDC_ERR_INCONSISTENT_KEY_PURPOSE
	                        $detailsArray += "Reason: Certificate cannot be used for PKINIT client authentication."
	                        $detailsArray += "The certificate's Extended Key Usage (EKU) must include:"
	                        $detailsArray += "  - Smart Card Logon (1.3.6.1.4.1.311.20.2.2), or"
	                        $detailsArray += "  - Client Authentication (1.3.6.1.5.5.7.3.2)"
	                    }
	                    79 {  # KDC_ERR_PA_CHECKSUM_MUST_BE_INCLUDED
	                        $detailsArray += "Reason: Windows Server 2022+ requires paChecksum2 with SHA-256."
	                        $detailsArray += "This error indicates the PKINIT request is missing the SHA-256 checksum."
	                        $detailsArray += ""
	                        $detailsArray += "Note: This should not occur with the current adPEAS version."
	                        $detailsArray += "If you see this error, please report it as a bug."
	                    }
	                    default {
	                        if ($Script:KERBEROS_ERROR_CODES -and $Script:KERBEROS_ERROR_CODES.ContainsKey([int]$ErrorCode)) {
	                            $errorInfo = $Script:KERBEROS_ERROR_CODES[[int]$ErrorCode]
	                            $detailsArray += "Reason: $($errorInfo.Name): $($errorInfo.Description)"
	                        }
	                        elseif ($Details) {
	                            $detailsArray += $Details
	                        }
	                        else {
	                            $detailsArray += "Reason: KDC error code: $ErrorCode"
	                        }
	                    }
	                }
	            }
	            elseif ($effectiveDetails) {
	                $detailsArray += $effectiveDetails
	            }
	            Show-Message -Type Error -Title "Authentication failed: Invalid credentials" -Details $detailsArray
	            $ThrowMessage = "Authentication failed"
	        }
	        "NTLMDisabledError" {
	            $detailsArray = @("Windows SSPI negotiation failed - NTLM unavailable and Kerberos not possible")
	            if ($effectiveDetails) {
	                $detailsArray += "Technical: $effectiveDetails"
	            }
	            $hints = @(
	                "Use explicit credentials with Kerberos or SimpleBind:",
	                "  Connect-adPEAS -Domain 'domain.com' -Username 'user' -Password 'pass'",
	                "  Connect-adPEAS -Domain 'domain.com' -Username 'user' -Password 'pass' -ForceSimpleBind"
	            )
	            Show-Message -Type Error -Title "Authentication failed: NTLM is disabled" -Details $detailsArray -Hints $hints
	            $ThrowMessage = "NTLM disabled - use explicit credentials or Kerberos"
	        }
	        "TicketImportError" {
	            $detailsArray = @()
	            if ($effectiveDetails -match "Invalid kirbi file|Invalid ccache file") {
	                $detailsArray += $effectiveDetails
	                Show-Message -Type Error -Title "Invalid ticket file format" -Details $detailsArray
	            }
	            else {
	                if ($effectiveDetails) {
	                    if ($effectiveDetails -match "non-domain-joined|Remote Credential Guard") {
	                        $detailsArray += "PTT requires domain-joined machine or elevated privileges"
	                    } else {
	                        $detailsArray += $effectiveDetails
	                    }
	                }
	                Show-Message -Type Error -Title "Ticket import failed (Pass-the-Ticket)" -Details $detailsArray
	            }
	            $ThrowMessage = "Ticket import failed"
	        }
	        "GenericError" {
	            $detailsArray = @()
	            if ($effectiveDetails) {
	                $detailsArray += $effectiveDetails
	            }
	            Show-Message -Type Error -Title "Connection failed" -Details $detailsArray
	            $ThrowMessage = "Connection failed"
	        }
	    }
	    if (-not $NoThrow) {
	        throw $ThrowMessage
	    }
	}
}
function ConvertFrom-KeyCredentialLink {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false, ValueFromPipeline=$true)]
	    [byte[]]$KeyCredentialBytes,
	    [Parameter(Mandatory=$false)]
	    [string]$DNWithBinary,
	    [Parameter(Mandatory=$false)]
	    [switch]$Raw
	)
	process {
	    try {
	        if ($DNWithBinary) {
	            if ($DNWithBinary -match '^B:(\d+):([0-9A-Fa-f]+)(?::(.+))?$') {
	                $HexData = $Matches[2]
	                $KeyCredentialBytes = [byte[]]::new($HexData.Length / 2)
	                for ($i = 0; $i -lt $HexData.Length; $i += 2) {
	                    $KeyCredentialBytes[$i / 2] = [Convert]::ToByte($HexData.Substring($i, 2), 16)
	                }
	            } else {
	                if ($Raw) {
	                    return [PSCustomObject]@{
	                        Success = $false
	                        Error = "Invalid DNWithBinary format"
	                    }
	                }
	                return "[Invalid format]"
	            }
	        }
	        if (-not $KeyCredentialBytes -or $KeyCredentialBytes.Length -lt 8) {
	            if ($Raw) {
	                return [PSCustomObject]@{
	                    Success = $false
	                    Error = "Invalid or empty KeyCredentialLink data"
	                }
	            }
	            return "[Invalid data]"
	        }
	        $Version = [BitConverter]::ToUInt32($KeyCredentialBytes, 0)
	        if ($Version -ne 0x00000200) {
	            if ($Raw) {
	                return [PSCustomObject]@{
	                    Success = $false
	                    Error = "Unknown version: 0x$($Version.ToString('X8'))"
	                    Version = $Version
	                }
	            }
	            return "[Unknown version: 0x$($Version.ToString('X8'))]"
	        }
	        $Result = [PSCustomObject]@{
	            Success = $true
	            Version = 2
	            KeyID = $null
	            KeyIDHex = $null
	            DeviceID = $null
	            KeyCreationTime = $null
	            KeyLastLogonTime = $null
	            KeyUsage = $null
	            KeyUsageText = $null
	            KeySource = $null
	            KeySourceText = $null
	            KeyMaterialLength = 0
	            CustomKeyInfo = $null
	            RawBytes = $KeyCredentialBytes
	            ByteLength = $KeyCredentialBytes.Length
	        }
	        $Offset = 4
	        while ($Offset + 3 -le $KeyCredentialBytes.Length) {
	            $EntryLength = [BitConverter]::ToUInt16($KeyCredentialBytes, $Offset)
	            $Offset += 2
	            $EntryType = $KeyCredentialBytes[$Offset]
	            $Offset += 1
	            if ($Offset + $EntryLength -gt $KeyCredentialBytes.Length) {
	                break
	            }
	            $EntryData = if ($EntryLength -gt 0) { $KeyCredentialBytes[$Offset..($Offset + $EntryLength - 1)] } else { @() }
	            $Offset += $EntryLength
	            switch ($EntryType) {
	                0x01 {  # KeyID (SHA256 hash of public key)
	                    if ($EntryData.Length -ge 16) {
	                        $Result.KeyIDHex = [BitConverter]::ToString($EntryData).Replace('-', '').ToLower()
	                        $Result.KeyID = $Result.KeyIDHex.Substring(0, 16) + "..."
	                    }
	                }
	                0x02 {  # KeyHash (SHA256 of entries 3-9)
	                }
	                0x03 {  # KeyMaterial (BCRYPT_RSAKEY_BLOB)
	                    $Result.KeyMaterialLength = $EntryLength
	                }
	                0x04 {  # KeyUsage
	                    if ($EntryData.Length -ge 1) {
	                        $Result.KeyUsage = $EntryData[0]
	                        $Result.KeyUsageText = switch ($EntryData[0]) {
	                            0x01 { "NGC" }
	                            0x02 { "FIDO" }
	                            0x07 { "FEK" }
	                            default { "0x$($EntryData[0].ToString('X2'))" }
	                        }
	                    }
	                }
	                0x05 {  # KeySource
	                    if ($EntryData.Length -ge 1) {
	                        $Result.KeySource = $EntryData[0]
	                        $Result.KeySourceText = switch ($EntryData[0]) {
	                            0x00 { "AD" }
	                            0x01 { "AzureAD" }
	                            default { "0x$($EntryData[0].ToString('X2'))" }
	                        }
	                    }
	                }
	                0x06 {  # DeviceId (GUID)
	                    if ($EntryData.Length -eq 16) {
	                        try {
	                            $Result.DeviceID = (New-Object GUID(,$EntryData)).ToString()
	                        } catch {
	                            $Result.DeviceID = [BitConverter]::ToString($EntryData).Replace('-', '').ToLower()
	                        }
	                    }
	                }
	                0x07 {  # CustomKeyInformation
	                    $Result.CustomKeyInfo = [BitConverter]::ToString($EntryData).Replace('-', '').ToLower()
	                }
	                0x08 {  # KeyApproximateLastLogonTimeStamp (FILETIME)
	                    if ($EntryData.Length -eq 8) {
	                        try {
	                            $FileTime = [BitConverter]::ToInt64($EntryData, 0)
	                            if ($FileTime -gt 0) {
	                                $Result.KeyLastLogonTime = [DateTime]::FromFileTimeUtc($FileTime)
	                            }
	                        } catch { }
	                    }
	                }
	                0x09 {  # KeyCreationTime (FILETIME)
	                    if ($EntryData.Length -eq 8) {
	                        try {
	                            $FileTime = [BitConverter]::ToInt64($EntryData, 0)
	                            if ($FileTime -gt 0) {
	                                $Result.KeyCreationTime = [DateTime]::FromFileTimeUtc($FileTime)
	                            }
	                        } catch { }
	                    }
	                }
	            }
	        }
	        if ($Raw) {
	            return $Result
	        }
	        $Parts = @()
	        if ($Result.DeviceID) {
	            $Parts += "DeviceID: $($Result.DeviceID)"
	        }
	        if ($Result.KeyCreationTime) {
	            $Parts += "Created: $($Result.KeyCreationTime.ToString('yyyy-MM-dd HH:mm'))"
	        }
	        if ($Parts.Count -gt 0) {
	            return $Parts -join " | "
	        }
	        return "KeyCredential ($($KeyCredentialBytes.Length) bytes)"
	    } catch {
	        if ($Raw) {
	            return [PSCustomObject]@{
	                Success = $false
	                Error = $_.Exception.Message
	            }
	        }
	        return "[Parse error: $($_.Exception.Message)]"
	    }
	}
}
function Connect-LDAP {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$UseLDAPS,
	    [Parameter(Mandatory=$false)]
	    [bool]$IgnoreSSLErrors = $true,
	    [Parameter(Mandatory=$false)]
	    [ValidateRange(5, 600)]
	    [int]$TimeoutSeconds = 30,
	    [Parameter(Mandatory=$false)]
	    [switch]$AsGlobalCatalog,
	    [Parameter(Mandatory=$false)]
	    [System.Security.Cryptography.X509Certificates.X509Certificate2]$ClientCertificate,
	    [Parameter(Mandatory=$false)]
	    [switch]$ForceNTLM,
	    [Parameter(Mandatory=$false)]
	    [switch]$SuppressErrorDisplay
	)
	begin {
	    $Script:ConnectionState = $null
	    $Script:LastLDAPErrorCode = $null
	    if ($IgnoreSSLErrors) {
	        [System.Net.ServicePointManager]::ServerCertificateValidationCallback = {$true}
	        [System.Net.ServicePointManager]::CheckCertificateRevocationList = $false
	    }
	    function Resolve-LDAPConnectionError {
	        param(
	            [Parameter(Mandatory)] $ErrorRecord,
	            [string]$Context = "Connection",
	            [switch]$BindSucceeded  # Set when Bind() succeeded but a subsequent SendRequest() failed
	        )
	        $ex = $ErrorRecord.Exception
	        $innerEx = $ex.InnerException
	        $ldapEx = $null
	        $dirOpEx = $null
	        $walker = $ex
	        while ($walker) {
	            $typeName = $walker.GetType().FullName
	            if ($typeName -eq 'System.DirectoryServices.Protocols.LdapException') {
	                $ldapEx = $walker
	                break
	            }
	            if ($typeName -eq 'System.DirectoryServices.Protocols.DirectoryOperationException') {
	                $dirOpEx = $walker
	            }
	            $walker = $walker.InnerException
	        }
	        $msg = if ($ldapEx) { $ldapEx.Message } elseif ($dirOpEx) { $dirOpEx.Message } elseif ($innerEx) { $innerEx.Message } else { $ex.Message }
	        $errorInfo = $null
	        $ldapErrorCode = $null
	        if ($ldapEx) {
	            $ldapErrorCode = $ldapEx.ErrorCode
	            $errorInfo = ConvertFrom-LDAPError -ErrorCode $ldapErrorCode
	        } elseif ($dirOpEx) {
	            if ($dirOpEx.Response -and $dirOpEx.Response.ResultCode) {
	                $ldapErrorCode = [int]$dirOpEx.Response.ResultCode
	            } else {
	                $ldapErrorCode = 8
	            }
	            $errorInfo = ConvertFrom-LDAPError -ErrorCode $ldapErrorCode
	        } elseif ($innerEx -and $innerEx.PSObject.Properties['ErrorCode']) {
	            $code = $innerEx.ErrorCode
	            $errorInfo = ConvertFrom-HResult -HResult $code
	            if ($errorInfo.LDAPCode) { $ldapErrorCode = $errorInfo.LDAPCode }
	        } else {
	        }
	        $Script:LastLDAPErrorCode = $ldapErrorCode
	        $Script:LastLDAPErrorDetails = $msg
	        $errorType = switch ($errorInfo.Category) {
	            'AccessDenied' { if ($errorInfo.Name -match 'LOGON|CREDENTIALS|OPERATIONS_ERROR') { "AuthenticationFailed" } else { "PermissionError" } }
	            'Network'      { "NetworkError" }
	            'Domain'       { "DomainError" }
	            'Timeout'      { "NetworkError" }
	            'LDAP'         { "GenericError" }
	            default        { "GenericError" }
	        }
	        if ($ldapErrorCode -eq 81 -and $BindSucceeded) {
	            $errorType = "GenericError"
	        }
	        $Script:ConnectionState = $errorType
	        if (-not $SuppressErrorDisplay) {
	            if ($null -ne $ldapErrorCode) {
	                $extraDetails = $null
	                if ($ldapErrorCode -eq 81 -and $BindSucceeded) {
	                    $extraDetails = "Bind() succeeded but the server did not respond to the search request. The LDAP server may not fully support authenticated queries."
	                }
	                elseif ($ldapErrorCode -eq 82 -and $BindSucceeded) {
	                    $extraDetails = "GSSAPI/NTLM negotiation failed during Bind() - the server may not support this authentication mechanism."
	                }
	                if ($extraDetails) {
	                    Show-ConnectionError -ErrorType $errorType -ErrorCode $ldapErrorCode -ErrorCodeType "LDAP" -Details $extraDetails -NoThrow
	                } else {
	                    Show-ConnectionError -ErrorType $errorType -ErrorCode $ldapErrorCode -ErrorCodeType "LDAP" -NoThrow
	                }
	            } else {
	                Show-ConnectionError -ErrorType $errorType -Details $msg -NoThrow
	            }
	        }
	    }
	}
	process {
	    try {
	        if ($AsGlobalCatalog) {
	            if ([string]::IsNullOrEmpty($Domain) -or [string]::IsNullOrEmpty($Server)) {
	                return $null
	            }
	            $DomainDN = "DC=" + ($Domain -replace "\.", ",DC=")
	        } else {
	            if ([string]::IsNullOrEmpty($Domain)) {
	                try {
	                    $CurrentDomain = [System.DirectoryServices.ActiveDirectory.Domain]::GetCurrentDomain()
	                    $Domain = $CurrentDomain.Name
	                } catch {
	                    $Script:ConnectionState = "DomainError"
	                    Show-ConnectionError -ErrorType "DomainError" -Details "Domain parameter required or system must be domain-joined" -NoThrow
	                    return $null
	                }
	            }
	            if ([string]::IsNullOrEmpty($Server)) {
	                $Server = $Domain
	            }
	            $DomainDN = "DC=" + ($Domain -replace "\.", ",DC=")
	        }
	        $ResolvedIPs = $null
	        $ResolvedIPString = $null
	        $CustomDnsServer = $null
	        if ($Script:LDAPContext -and $Script:LDAPContext['DnsServer']) {
	            $CustomDnsServer = $Script:LDAPContext['DnsServer']
	        }
	        try {
	            if ($CustomDnsServer) {
	                $ResolvedIPString = Resolve-adPEASName -Name $Server -DnsServer $CustomDnsServer
	                if ($ResolvedIPString) {
	                } else {
	                    throw "Custom DNS resolution failed for $Server"
	                }
	            } else {
	                $ResolvedIPs = [System.Net.Dns]::GetHostAddresses($Server)
	                if (-not $ResolvedIPs -or $ResolvedIPs.Count -eq 0) {
	                    throw "DNS resolution returned no addresses"
	                }
	                $ResolvedIPString = $ResolvedIPs[0].IPAddressToString
	            }
	        } catch {
	            $Script:ConnectionState = "DomainError"
	            $Detail = if ($Server -eq $Domain) {
	                "Domain '$Domain' could not be resolved"
	            } else {
	                "Server '$Server' could not be resolved"
	            }
	            Show-ConnectionError -ErrorType "DomainError" -Details $Detail -NoThrow
	            return $null
	        }
	        $ConnectTarget = if ($CustomDnsServer -and $ResolvedIPString) { $ResolvedIPString } else { $Server }
	        $ServerReachable = $false
	        $TestPort = if ($AsGlobalCatalog) {
	            if ($UseLDAPS) { 3269 } else { 3268 }
	        } else {
	            if ($UseLDAPS) { 636 } else { 389 }
	        }
	        try {
	            $TcpClient = New-Object System.Net.Sockets.TcpClient
	            $ConnectTask = $TcpClient.BeginConnect($ConnectTarget, $TestPort, $null, $null)
	            $WaitHandle = $ConnectTask.AsyncWaitHandle
	            if ($WaitHandle.WaitOne(2000, $false)) {
	                $TcpClient.EndConnect($ConnectTask)
	                $ServerReachable = $true
	            }
	            $TcpClient.Close()
	        } catch {
	        }
	        if (-not $ServerReachable) {
	            $Script:ConnectionState = "NetworkError"
	            $PortDesc = "$TestPort ($(if ($AsGlobalCatalog) { 'GC' } else { if ($UseLDAPS) { 'LDAPS' } else { 'LDAP' } }))"
	            Show-ConnectionError -ErrorType "NetworkError" -Details "Port $PortDesc unreachable on $Server" -NoThrow
	            return $null
	        }
	        if ($UseLDAPS) {
	            $SSLPort = $TestPort  # Already set to 3269 for GC, 636 for normal LDAPS
	            $SSLTestPassed = $false
	            $sslErrorInfo = $null
	            try {
	                $TcpClientSSL = New-Object System.Net.Sockets.TcpClient
	                $TcpClientSSL.Connect($ConnectTarget, $SSLPort)
	                $SslStream = New-Object System.Net.Security.SslStream(
	                    $TcpClientSSL.GetStream(),
	                    $false,
	                    { param($sslSender, $cert, $chain, $errors)
	                        return $IgnoreSSLErrors -or ($errors -eq [System.Net.Security.SslPolicyErrors]::None)
	                    }
	                )
	                $SslStream.AuthenticateAsClient($Server)
	                $SSLTestPassed = $true
	                if ($SslStream.RemoteCertificate) {
	                    if ($IgnoreSSLErrors) {
	                        try {
	                            $cert2 = New-Object System.Security.Cryptography.X509Certificates.X509Certificate2($SslStream.RemoteCertificate)
	                            $chain = New-Object System.Security.Cryptography.X509Certificates.X509Chain
	                            $chain.ChainPolicy.RevocationMode = [System.Security.Cryptography.X509Certificates.X509RevocationMode]::NoCheck
	                            $chain.ChainPolicy.RevocationFlag = [System.Security.Cryptography.X509Certificates.X509RevocationFlag]::EntireChain
	                            $chain.ChainPolicy.VerificationFlags = [System.Security.Cryptography.X509Certificates.X509VerificationFlags]::AllFlags
	                            [void]$chain.Build($cert2)
	                            $chain.Reset()
	                        } catch {
	                        }
	                    }
	                }
	                $SslStream.Close()
	                $TcpClientSSL.Close()
	            }
	            catch {
	                $sslErrorInfo = Get-ExceptionErrorInfo -Exception $_.Exception -Context "SSL handshake"
	                if ($sslErrorInfo.Category -eq 'SSLCertificate' -and -not $IgnoreSSLErrors) {
	                }
	            }
	            if (-not $SSLTestPassed) {
	                $errorType = if ($sslErrorInfo.Category -eq 'SSLCertificate') { "CertificateError" } else { "SSLHandshakeError" }
	                $Script:ConnectionState = $errorType
	                Show-ConnectionError -ErrorType $errorType -Details $sslErrorInfo.Message -NoThrow
	                return $null
	            }
	        }
	        $Script:AnonymousAccessEnabled = $false
	        $Script:AnonymousAccessDetails = $null
	        if ($AsGlobalCatalog) {
	        }
	        elseif ($UseLDAPS) {
	        }
	        $AnonLdapConn = $null
	        if (-not $UseLDAPS -and -not $AsGlobalCatalog) {
	        try {
	            $AnonTarget = if ($CustomDnsServer -and $ResolvedIPString) { $ResolvedIPString } else { $Server }
	            $AnonIdentifier = New-Object System.DirectoryServices.Protocols.LdapDirectoryIdentifier($AnonTarget, 389)
	            $AnonLdapConn = New-Object System.DirectoryServices.Protocols.LdapConnection($AnonIdentifier)
	            $AnonLdapConn.SessionOptions.ProtocolVersion = 3
	            $AnonLdapConn.Timeout = [TimeSpan]::FromSeconds(2)
	            $AnonLdapConn.SessionOptions.SendTimeout = [TimeSpan]::FromSeconds(2)
	            $AnonLdapConn.AuthType = [System.DirectoryServices.Protocols.AuthType]::Anonymous
	            $AnonLdapConn.Bind()
	            $AnonSearchRequest = New-Object System.DirectoryServices.Protocols.SearchRequest(
	                $DomainDN,
	                "(objectClass=domainDNS)",
	                [System.DirectoryServices.Protocols.SearchScope]::Base,
	                @("distinguishedName", "name", "objectSid")
	            )
	            $AnonSearchResponse = $AnonLdapConn.SendRequest($AnonSearchRequest)
	            if ($AnonSearchResponse -and $AnonSearchResponse.Entries.Count -gt 0) {
	                $AnonEntry = $AnonSearchResponse.Entries[0]
	                if ($AnonEntry.DistinguishedName) {
	                    $Script:AnonymousAccessEnabled = $true
	                    $ReadableAttrs = @()
	                    foreach ($attr in $AnonEntry.Attributes.AttributeNames) {
	                        $ReadableAttrs += $attr
	                    }
	                    $CanEnumUsers = $false
	                    $UserCount = 0
	                    try {
	                        $UserSearchRequest = New-Object System.DirectoryServices.Protocols.SearchRequest(
	                            $DomainDN,
	                            "(objectClass=user)",
	                            [System.DirectoryServices.Protocols.SearchScope]::Subtree,
	                            @("sAMAccountName")
	                        )
	                        $UserSearchRequest.SizeLimit = 5  # Just test if we can read any
	                        $UserSearchResponse = $AnonLdapConn.SendRequest($UserSearchRequest)
	                        $UserCount = $UserSearchResponse.Entries.Count
	                        if ($UserCount -gt 0) {
	                            $CanEnumUsers = $true
	                        }
	                    } catch {
	                    }
	                    $Script:AnonymousAccessDetails = @{
	                        CanReadDomainRoot = $true
	                        ReadableAttributes = $ReadableAttrs
	                        CanEnumerateUsers = $CanEnumUsers
	                        UsersSampled = $UserCount
	                    }
	                    if ($CanEnumUsers) {
	                    }
	                }
	            }
	        } catch {
	            $Script:AnonymousAccessEnabled = $false
	        } finally {
	            if ($AnonLdapConn) {
	                try { $AnonLdapConn.Dispose() } catch { }
	            }
	        }
	        }  # End of: if (-not $UseLDAPS -and -not $AsGlobalCatalog)
	        $ConnectionEstablished = $false
	        $LdapProtocolConn = $null
	        $LDAPPort = if ($AsGlobalCatalog) {
	            if ($UseLDAPS) { 3269 } else { 3268 }
	        } else {
	            if ($UseLDAPS) { 636 } else { 389 }
	        }
	        $LDAPTarget = $Server
	        $ProtocolDisplay = if ($AsGlobalCatalog) { "GC" } elseif ($UseLDAPS) { "LDAPS" } else { "LDAP" }
	        try {
	            Add-Type -AssemblyName System.DirectoryServices.Protocols -ErrorAction Stop
	            $LdapIdentifier = New-Object System.DirectoryServices.Protocols.LdapDirectoryIdentifier($LDAPTarget, $LDAPPort)
	            $LdapProtocolConn = New-Object System.DirectoryServices.Protocols.LdapConnection($LdapIdentifier)
	            if ($ClientCertificate) {
	                $LdapProtocolConn.ClientCertificates.Add($ClientCertificate) | Out-Null
	                $LdapProtocolConn.SessionOptions.SecureSocketLayer = $true
	                $LdapProtocolConn.SessionOptions.VerifyServerCertificate = { param($conn, $cert) return $true }
	            } else {
	                $LdapProtocolConn.SessionOptions.ProtocolVersion = 3
	                $LdapProtocolConn.Timeout = [TimeSpan]::FromSeconds($TimeoutSeconds)
	                $SendTimeoutSeconds = [Math]::Max(5, [Math]::Floor($TimeoutSeconds / 2))
	                $LdapProtocolConn.SessionOptions.SendTimeout = [TimeSpan]::FromSeconds($SendTimeoutSeconds)
	                $LdapProtocolConn.SessionOptions.ReferralChasing = [System.DirectoryServices.Protocols.ReferralChasingOptions]::None
	                if ($UseLDAPS) {
	                    $LdapProtocolConn.SessionOptions.SecureSocketLayer = $true
	                    if ($IgnoreSSLErrors) {
	                        $LdapProtocolConn.SessionOptions.VerifyServerCertificate = { param($conn, $cert) return $true }
	                    }
	                }
	            }
	            if ($ClientCertificate) {
	            }
	            elseif ($Credential -and $ForceNTLM) {
	                $NtlmNetCred = $Credential.GetNetworkCredential()
	                $NtlmUser   = $NtlmNetCred.UserName
	                $NtlmDomain = $NtlmNetCred.Domain
	                $NtlmPass   = $NtlmNetCred.Password
	                $LdapProtocolConn.AuthType  = [System.DirectoryServices.Protocols.AuthType]::Ntlm
	                $LdapProtocolConn.Credential = New-Object System.Net.NetworkCredential($NtlmUser, $NtlmPass, $NtlmDomain)
	            }
	            elseif ($Credential) {
	                $NetworkCred = $Credential.GetNetworkCredential()
	                $UserName = $NetworkCred.UserName  # Username part only (without domain prefix)
	                $Password = $NetworkCred.Password
	                $CredDomain = $NetworkCred.Domain  # Domain part (if user specified DOMAIN\user)
	                if (-not [string]::IsNullOrEmpty($CredDomain)) {
	                    $UserName = "$CredDomain\$UserName"
	                }
	                elseif ($UserName -match '@') {
	                }
	                else {
	                    if ($Domain) {
	                        $UserName = "$UserName@$Domain"
	                    } else {
	                    }
	                }
	                $LdapProtocolConn.AuthType = [System.DirectoryServices.Protocols.AuthType]::Basic
	                $LdapProtocolConn.Credential = New-Object System.Net.NetworkCredential($UserName, $Password)
	            } else {
	                $LdapProtocolConn.AuthType = [System.DirectoryServices.Protocols.AuthType]::Negotiate
	            }
	            $LdapBindSucceeded = $false
	            if ($ClientCertificate) {
	                $LdapBindSucceeded = $true  # AutoBind - treat as succeeded for error context
	            } else {
	                $bindStopwatch = [System.Diagnostics.Stopwatch]::StartNew()
	                $LdapProtocolConn.Bind()
	                $bindStopwatch.Stop()
	                $LdapBindSucceeded = $true
	            }
	            if ($AsGlobalCatalog) {
	                $ConnectionEstablished = $true
	                try {
	                    $gcRootDSE = New-Object System.DirectoryServices.Protocols.SearchRequest(
	                        "", "(objectClass=*)",
	                        [System.DirectoryServices.Protocols.SearchScope]::Base,
	                        @("isGlobalCatalogReady")
	                    )
	                    $gcRootDSEResponse = $LdapProtocolConn.SendRequest($gcRootDSE)
	                    $isGC = $false
	                    if ($gcRootDSEResponse -and $gcRootDSEResponse.Entries.Count -gt 0) {
	                        $gcReadyAttr = $gcRootDSEResponse.Entries[0].Attributes["isglobalcatalogready"]
	                        if ($gcReadyAttr -and $gcReadyAttr.Count -gt 0) {
	                            $isGC = ([string]$gcReadyAttr[0]) -eq "TRUE"
	                        }
	                    }
	                    if (-not $isGC) {
	                        try { $LdapProtocolConn.Dispose() } catch { }
	                        return $null
	                    }
	                } catch {
	                    try { $LdapProtocolConn.Dispose() } catch { }
	                    return $null
	                }
	                return $LdapProtocolConn
	            }
	            if ($ClientCertificate) {
	            }
	            $SearchRequest = New-Object System.DirectoryServices.Protocols.SearchRequest(
	                $DomainDN,
	                "(objectClass=domainDNS)",
	                [System.DirectoryServices.Protocols.SearchScope]::Base,
	                @("distinguishedName", "name")
	            )
	            $SearchResponse = $LdapProtocolConn.SendRequest($SearchRequest)
	            if ($SearchResponse -and $SearchResponse.Entries.Count -gt 0) {
	                $TestDN = $SearchResponse.Entries[0].DistinguishedName
	                $ConnectionEstablished = $true
	                $Script:LdapConnection = $LdapProtocolConn
	            } else {
	                throw "$ProtocolDisplay search returned no results"
	            }
	        } catch {
	            if ($ClientCertificate) {
	                if ($_.Exception.InnerException) {
	                }
	                if ($_.Exception -is [System.DirectoryServices.Protocols.DirectoryOperationException]) {
	                    $dirEx = $_.Exception
	                }
	            }
	            Resolve-LDAPConnectionError -ErrorRecord $_ -Context "LDAP connection" -BindSucceeded:$LdapBindSucceeded
	            if ($LdapProtocolConn) {
	                try { $LdapProtocolConn.Dispose() } catch { }
	            }
	        }
	        if (-not $ConnectionEstablished) {
	            return $null
	        }
	        $RootDSEData = @{}
	        try {
	            $RootDSERequest = New-Object System.DirectoryServices.Protocols.SearchRequest
	            $RootDSERequest.DistinguishedName = ""  # Empty DN = RootDSE
	            $RootDSERequest.Filter = "(objectClass=*)"
	            $RootDSERequest.Scope = [System.DirectoryServices.Protocols.SearchScope]::Base
	            $attributesToExtract = @(
	                "defaultNamingContext",
	                "configurationNamingContext",
	                "schemaNamingContext",
	                "rootDomainNamingContext",
	                "dnsHostName",
	                "domainFunctionality",
	                "forestFunctionality"
	            )
	            foreach ($attr in $attributesToExtract) {
	                [void]$RootDSERequest.Attributes.Add($attr)
	            }
	            $RootDSEResponse = $Script:LdapConnection.SendRequest($RootDSERequest)
	            if ($RootDSEResponse -and $RootDSEResponse.Entries.Count -gt 0) {
	                $RootDSEEntry = $RootDSEResponse.Entries[0]
	                foreach ($attrName in $attributesToExtract) {
	                    if ($RootDSEEntry.Attributes.Contains($attrName)) {
	                        $dirAttr = $RootDSEEntry.Attributes[$attrName]
	                        if ($dirAttr -and $dirAttr.Count -gt 0) {
	                            $value = $dirAttr.GetValues([string])[0]
	                            $RootDSEData[$attrName] = $value
	                        }
	                    } else {
	                    }
	                }
	            } else {
	                throw "RootDSE query returned no results"
	            }
	        } catch {
	            Resolve-LDAPConnectionError -ErrorRecord $_ -Context "RootDSE retrieval"
	            return $null
	        }
	        $ActualDCName = if ($RootDSEData["dnsHostName"]) {
	            $RootDSEData["dnsHostName"]
	        } else {
	            $Server
	        }
	        $DomainInfo = @{
	            Domain = $Domain
	            Server = $ActualDCName
	            DomainDN = $DomainDN
	            Protocol = if ($UseLDAPS) { "LDAPS" } else { "LDAP" }
	            Port = if ($UseLDAPS) { 636 } else { 389 }
	            DefaultNamingContext = $RootDSEData["defaultNamingContext"]
	            ConfigurationNamingContext = $RootDSEData["configurationNamingContext"]
	            ConfigurationDN = $RootDSEData["configurationNamingContext"]
	            SchemaNamingContext = $RootDSEData["schemaNamingContext"]
	            RootDomainNamingContext = $RootDSEData["rootDomainNamingContext"]
	            DnsHostName = $RootDSEData["dnsHostName"]
	            DomainFunctionality = $RootDSEData["domainFunctionality"]
	            ForestFunctionality = $RootDSEData["forestFunctionality"]
	            LdapConnection = $Script:LdapConnection  # Primary connection for all operations
	            Credential = $Credential
	            Timestamp = Get-Date
	            Connected = $true
	            UseLDAPS = $UseLDAPS
	            ExplicitServer = $PSBoundParameters.ContainsKey('Server')
	            ExplicitDomain = $PSBoundParameters.ContainsKey('Domain')
	            ExplicitCredential = $PSBoundParameters.ContainsKey('Credential')
	            ClientCertificate = $ClientCertificate  # X509Certificate2 object for session reuse
	        }
	        $DomainSID = $null
	        try {
	            $SIDRequest = New-Object System.DirectoryServices.Protocols.SearchRequest(
	                $DomainDN,
	                "(objectClass=domainDNS)",
	                [System.DirectoryServices.Protocols.SearchScope]::Base,
	                @("objectSid")
	            )
	            $SIDResponse = $Script:LdapConnection.SendRequest($SIDRequest)
	            if ($SIDResponse -and $SIDResponse.Entries.Count -gt 0 -and $SIDResponse.Entries[0].Attributes["objectsid"]) {
	                $SIDBytes = $SIDResponse.Entries[0].Attributes["objectsid"][0]
	                $DomainSID = (New-Object System.Security.Principal.SecurityIdentifier($SIDBytes, 0)).Value
	            }
	        } catch {
	        }
	        $DomainInfo['DomainSID'] = $DomainSID
	        $DomainInfo['AnonymousAccessEnabled'] = $Script:AnonymousAccessEnabled
	        $DomainInfo['AnonymousAccessDetails'] = $Script:AnonymousAccessDetails
	        $AuthenticatedUser = $null
	        $AuthenticatedUserDN = $null
	        $AuthenticatedUserSAM = $null
	        try {
	            if ($Credential) {
	                $AuthenticatedUser = $Credential.UserName
	                $CredentialSAM = $Credential.UserName
	                if ($CredentialSAM -match '\\') {
	                    $CredentialSAM = $CredentialSAM.Split('\')[1]
	                } elseif ($CredentialSAM -match '@') {
	                    $CredentialSAM = $CredentialSAM.Split('@')[0]
	                }
	                try {
	                    $UserRequest = New-Object System.DirectoryServices.Protocols.SearchRequest(
	                        $DomainDN,
	                        "(sAMAccountName=$CredentialSAM)",
	                        [System.DirectoryServices.Protocols.SearchScope]::Subtree,
	                        @("distinguishedName", "sAMAccountName", "userPrincipalName")
	                    )
	                    $UserResponse = $Script:LdapConnection.SendRequest($UserRequest)
	                    if ($UserResponse -and $UserResponse.Entries.Count -gt 0) {
	                        $UserEntry = $UserResponse.Entries[0]
	                        $AuthenticatedUserDN = $UserEntry.DistinguishedName
	                        if ($UserEntry.Attributes["samaccountname"]) {
	                            $AuthenticatedUserSAM = $UserEntry.Attributes["samaccountname"][0]
	                        }
	                    }
	                } catch {
	                }
	            } else {
	                try {
	                    $WhoAmIRequest = New-Object System.DirectoryServices.Protocols.ExtendedRequest("1.3.6.1.4.1.4203.1.11.3")
	                    $WhoAmIResponse = $Script:LdapConnection.SendRequest($WhoAmIRequest)
	                    if ($WhoAmIResponse -and $WhoAmIResponse.ResponseValue) {
	                        $WhoAmIResult = [System.Text.Encoding]::UTF8.GetString($WhoAmIResponse.ResponseValue)
	                        if ($WhoAmIResult -match '^u:(.+)$') {
	                            $AuthenticatedUser = $Matches[1]
	                        } elseif ($WhoAmIResult -match '^dn:(.+)$') {
	                            $AuthenticatedUserDN = $Matches[1]
	                            if ($AuthenticatedUserDN -match '^CN=([^,]+)') {
	                                $AuthenticatedUser = $Matches[1]
	                            } else {
	                                $AuthenticatedUser = $AuthenticatedUserDN
	                            }
	                        } else {
	                            $AuthenticatedUser = $WhoAmIResult
	                        }
	                    }
	                } catch {
	                    $DomainNetBIOS = $Domain.Split('.')[0].ToUpper()
	                    try {
	                        $TGTStatus = Test-KerberosTGTExists -Detailed -Force
	                        if ($TGTStatus.Valid -and $TGTStatus.ClientName) {
	                            $AuthenticatedUser = "$DomainNetBIOS\$($TGTStatus.ClientName)"
	                        } else {
	                            $AuthenticatedUser = "$DomainNetBIOS\[Kerberos Authenticated]"
	                        }
	                    } catch {
	                        $AuthenticatedUser = "$DomainNetBIOS\[Kerberos Authenticated]"
	                    }
	                }
	            }
	            if ([string]::IsNullOrEmpty($AuthenticatedUser)) {
	                $AuthenticatedUser = "[LDAP Identity Unknown]"
	            }
	            $DomainInfo['AuthenticatedUser'] = $AuthenticatedUser
	            $DomainInfo['AuthenticatedUserDN'] = $AuthenticatedUserDN
	            $DomainInfo['AuthenticatedUserSAM'] = $AuthenticatedUserSAM
	            if ($AuthenticatedUser -notmatch '^\[' -and -not $Credential) {
	                $DomainInfo['DetectedKerberos'] = $true
	            } else {
	                $DomainInfo['DetectedKerberos'] = $false
	            }
	        } catch {
	            $DomainInfo['AuthenticatedUser'] = "[Error determining identity]"
	        }
	        if ($Script:LDAPContext) {
	            foreach ($key in $DomainInfo.Keys) {
	                $Script:LDAPContext[$key] = $DomainInfo[$key]
	            }
	        }
	        else {
	            $Script:LDAPContext = $DomainInfo
	        }
	        $Script:LDAPCredential = $Credential
	        $Script:ConnectionState = "Success"
	        if (-not $Script:LDAPContext['AuthMethod']) {
	            if ($ClientCertificate) {
	                $Script:LDAPContext['AuthMethod'] = 'Schannel'
	            }
	            elseif ($Credential) {
	                $Script:LDAPContext['AuthMethod'] = 'SimpleBind'
	            } else {
	                $Script:LDAPContext['AuthMethod'] = 'WindowsAuth'
	            }
	        }
	        return $DomainInfo
	    } catch {
	        if (-not $Script:ConnectionState) {
	            Resolve-LDAPConnectionError -ErrorRecord $_ -Context "Unhandled error"
	        }
	        return $null
	    }
	}
	end {
	    if ($Script:LdapConnection) {
	    }
	}
}
function Connect-adPEAS {
	[CmdletBinding(DefaultParameterSetName='WindowsAuth')]
	param(
	    [Parameter(Mandatory=$false, ParameterSetName='WindowsAuth')]
	    [Parameter(Mandatory=$true, ParameterSetName='PSCredential')]
	    [Parameter(Mandatory=$true, ParameterSetName='UsernamePassword')]
	    [Parameter(Mandatory=$true, ParameterSetName='Certificate')]
	    [Parameter(Mandatory=$true, ParameterSetName='NTHash')]
	    [Parameter(Mandatory=$true, ParameterSetName='AES256')]
	    [Parameter(Mandatory=$true, ParameterSetName='AES128')]
	    [Parameter(Mandatory=$true, ParameterSetName='Kirbi')]
	    [Parameter(Mandatory=$true, ParameterSetName='Ccache')]
	    [AllowEmptyString()]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [switch]$UseLDAPS,
	    [Parameter(Mandatory=$false)]
	    [bool]$IgnoreSSLErrors = $true,
	    [Parameter(Mandatory=$false)]
	    [string]$DnsServer,
	    [Parameter(Mandatory=$false)]
	    [switch]$PatchHostsFile,
	    [Parameter(Mandatory=$false)]
	    [switch]$Quiet,
	    [Parameter(Mandatory=$false, ParameterSetName='WindowsAuth')]
	    [switch]$UseWindowsAuth,
	    [Parameter(Mandatory=$true, ParameterSetName='PSCredential')]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$true, ParameterSetName='UsernamePassword')]
	    [Parameter(Mandatory=$true, ParameterSetName='NTHash')]
	    [Parameter(Mandatory=$true, ParameterSetName='AES256')]
	    [Parameter(Mandatory=$true, ParameterSetName='AES128')]
	    [Parameter(Mandatory=$false, ParameterSetName='Certificate')]
	    [Parameter(Mandatory=$false, ParameterSetName='Kirbi')]
	    [Parameter(Mandatory=$false, ParameterSetName='Ccache')]
	    [AllowEmptyString()]
	    [string]$Username,
	    [Parameter(Mandatory=$false, ParameterSetName='UsernamePassword')]
	    $Password,  # Accepts SecureString or String (allows empty passwords for PASSWD_NOTREQD accounts)
	    [Parameter(Mandatory=$true, ParameterSetName='Certificate')]
	    [AllowEmptyString()]
	    [string]$Certificate,
	    [Parameter(Mandatory=$false, ParameterSetName='Certificate')]
	    $CertificatePassword = "",  # Accepts SecureString or String. Default: empty (for unprotected PFX)
	    [Parameter(Mandatory=$false, ParameterSetName='Certificate')]
	    [switch]$ForcePassTheCert,
	    [Parameter(Mandatory=$true, ParameterSetName='NTHash')]
	    [AllowEmptyString()]
	    [string]$NTHash,
	    [Parameter(Mandatory=$true, ParameterSetName='AES256')]
	    [AllowEmptyString()]
	    [string]$AES256Key,
	    [Parameter(Mandatory=$true, ParameterSetName='AES128')]
	    [AllowEmptyString()]
	    [string]$AES128Key,
	    [Parameter(Mandatory=$true, ParameterSetName='Kirbi')]
	    [AllowEmptyString()]
	    [string]$Kirbi,
	    [Parameter(Mandatory=$true, ParameterSetName='Ccache')]
	    [AllowEmptyString()]
	    [string]$Ccache,
	    [Parameter(Mandatory=$false, ParameterSetName='PSCredential')]
	    [Parameter(Mandatory=$false, ParameterSetName='UsernamePassword')]
	    [switch]$ForceNTLM,
	    [Parameter(Mandatory=$false, ParameterSetName='WindowsAuth')]
	    [Parameter(Mandatory=$false, ParameterSetName='PSCredential')]
	    [Parameter(Mandatory=$false, ParameterSetName='UsernamePassword')]
	    [Parameter(Mandatory=$false, ParameterSetName='Certificate')]
	    [Parameter(Mandatory=$false, ParameterSetName='NTHash')]
	    [Parameter(Mandatory=$false, ParameterSetName='AES256')]
	    [Parameter(Mandatory=$false, ParameterSetName='AES128')]
	    [Parameter(Mandatory=$false, ParameterSetName='Kirbi')]
	    [Parameter(Mandatory=$false, ParameterSetName='Ccache')]
	    [switch]$ForceSimpleBind,
	    [Parameter(Mandatory=$false, ParameterSetName='WindowsAuth')]
	    [Parameter(Mandatory=$false, ParameterSetName='PSCredential')]
	    [Parameter(Mandatory=$false, ParameterSetName='UsernamePassword')]
	    [Parameter(Mandatory=$false, ParameterSetName='Certificate')]
	    [Parameter(Mandatory=$false, ParameterSetName='NTHash')]
	    [Parameter(Mandatory=$false, ParameterSetName='AES256')]
	    [Parameter(Mandatory=$false, ParameterSetName='AES128')]
	    [Parameter(Mandatory=$false, ParameterSetName='Kirbi')]
	    [Parameter(Mandatory=$false, ParameterSetName='Ccache')]
	    [switch]$ForceKerberos,
	    [Parameter(Mandatory=$false, ParameterSetName='WindowsAuth')]
	    [Parameter(Mandatory=$false, ParameterSetName='PSCredential')]
	    [Parameter(Mandatory=$false, ParameterSetName='UsernamePassword')]
	    [Parameter(Mandatory=$false, ParameterSetName='Certificate')]
	    [Parameter(Mandatory=$false, ParameterSetName='NTHash')]
	    [Parameter(Mandatory=$false, ParameterSetName='AES256')]
	    [Parameter(Mandatory=$false, ParameterSetName='AES128')]
	    [Parameter(Mandatory=$false, ParameterSetName='Kirbi')]
	    [Parameter(Mandatory=$false, ParameterSetName='Ccache')]
	    [string]$License,
	    [Parameter(Mandatory=$false, ParameterSetName='WindowsAuth')]
	    [Parameter(Mandatory=$false, ParameterSetName='PSCredential')]
	    [Parameter(Mandatory=$false, ParameterSetName='UsernamePassword')]
	    [Parameter(Mandatory=$false, ParameterSetName='Certificate')]
	    [Parameter(Mandatory=$false, ParameterSetName='NTHash')]
	    [Parameter(Mandatory=$false, ParameterSetName='AES256')]
	    [Parameter(Mandatory=$false, ParameterSetName='AES128')]
	    [Parameter(Mandatory=$false, ParameterSetName='Kirbi')]
	    [Parameter(Mandatory=$false, ParameterSetName='Ccache')]
	    [switch]$BuildCompletionCache,
	    [Parameter(Mandatory=$false)]
	    [ValidateRange(5, 600)]
	    [int]$TimeoutSeconds = 30
	)
	begin {
	    if ($PSBoundParameters.ContainsKey('License') -and $License) {
	        if (Test-Path $License -ErrorAction SilentlyContinue) {
	            $Script:RuntimeLicense = Get-Content $License -Raw -Encoding UTF8
	        }
	        else {
	            Write-Warning "[Connect-adPEAS] License file not found: $License"
	        }
	    }
	    $existingSession = $Script:LDAPContext -or $Script:LdapConnection -or
	                      ($Script:NTLMTokenHandle -and $Script:NTLMTokenHandle -ne [IntPtr]::Zero)
	    if ($existingSession) {
	        if ($Script:NTLMTokenHandle -and $Script:NTLMTokenHandle -ne [IntPtr]::Zero) {
	            try {
	                Invoke-RevertToSelf -TokenHandle $Script:NTLMTokenHandle
	            }
	            catch {
	            }
	            $Script:NTLMTokenHandle = [IntPtr]::Zero
	        }
	        if ($Script:LdapConnection) {
	            try {
	                $Script:LdapConnection.Dispose()
	            }
	            catch {
	            }
	        }
	        if ($Script:LDAPContext -and $Script:LDAPContext['HostsEntries'] -and $Script:LDAPContext['HostsEntries'].Count -gt 0) {
	            try {
	                $hostsResult = Remove-adPEASHostsEntry
	                if ($hostsResult.Success -and $hostsResult.RemovedCount -gt 0) {
	                }
	            }
	            catch {
	            }
	        }
	        $Script:LdapConnection = $null
	        $Script:LDAPContext = $null
	        $Script:LDAPCredential = $null
	        $Script:AuthInfo = $null
	        $Script:adPEAS_Outputfile = $null
	        $Script:HTMLOutputPath = $null
	        if ($Script:PrivilegedCheckCache) { $Script:PrivilegedCheckCache = @{} }
	        if ($Script:SIDResolutionCache) { $Script:SIDResolutionCache = @{} }
	        if ($Script:SIDVerboseCache) { $Script:SIDVerboseCache = @{} }
	        if ($Script:NameToSIDCache) { $Script:NameToSIDCache = @{} }
	        if ($Script:CompletionCache) {
	            try { Clear-CompletionCache } catch { }
	        }
	    }
	    $ParamSetDisplay = switch ($PSCmdlet.ParameterSetName) {
	        'PSCredential' { 'PSCredential Object' }
	        'UsernamePassword' { 'Username/Password' }
	        'Certificate' { 'Certificate (PKINIT)' }
	        'WindowsAuth' { 'Windows Authentication' }
	        'NTHash' { 'NT-Hash (Overpass-the-Hash)' }
	        'AES256' { 'AES256 Key (Pass-the-Key)' }
	        'AES128' { 'AES128 Key (Pass-the-Key)' }
	        'Kirbi' { 'Kirbi Ticket File (Pass-the-Ticket)' }
	        'Ccache' { 'Ccache Ticket File (Pass-the-Ticket)' }
	        default { $PSCmdlet.ParameterSetName }
	    }
	}
	process {
	    try {
	        if ($Host.Name -eq 'Windows PowerShell ISE Host') {
	            Write-Warning "PowerShell ISE is deprecated and not supported by adPEAS. Console output may be garbled. Use powershell.exe or VS Code instead."
	        }
	        $AuthMethod = $PSCmdlet.ParameterSetName
	        if ($ForceNTLM -and $ForceKerberos) {
	            Show-ConnectionError -ErrorType "GenericError" -Details "-ForceNTLM and -ForceKerberos are mutually exclusive" -NoThrow
	            return $null
	        }
	        if ($ForceSimpleBind -and $ForceKerberos) {
	            Show-ConnectionError -ErrorType "GenericError" -Details "-ForceSimpleBind and -ForceKerberos are mutually exclusive" -NoThrow
	            return $null
	        }
	        if ($ForceNTLM -and $ForceSimpleBind) {
	            Show-ConnectionError -ErrorType "GenericError" -Details "-ForceNTLM and -ForceSimpleBind are mutually exclusive" -NoThrow
	            return $null
	        }
	        if ($PSBoundParameters.ContainsKey('Domain') -and [string]::IsNullOrWhiteSpace($Domain)) {
	            Show-ConnectionError -ErrorType "GenericError" -Details "Domain name must not be empty" -NoThrow
	            return $null
	        }
	        if ($AuthMethod -in @('UsernamePassword','NTHash','AES256','AES128') -and [string]::IsNullOrWhiteSpace($Username)) {
	            Show-ConnectionError -ErrorType "GenericError" -Details "Username must not be empty" -NoThrow
	            return $null
	        }
	        if ($AuthMethod -eq 'Certificate' -and [string]::IsNullOrWhiteSpace($Certificate)) {
	            Show-ConnectionError -ErrorType "GenericError" -Details "Certificate path or Base64 string must not be empty" -NoThrow
	            return $null
	        }
	        if ($AuthMethod -eq 'Kirbi' -and [string]::IsNullOrWhiteSpace($Kirbi)) {
	            Show-ConnectionError -ErrorType "GenericError" -Details "Kirbi ticket file path or Base64 string must not be empty" -NoThrow
	            return $null
	        }
	        if ($AuthMethod -eq 'Ccache' -and [string]::IsNullOrWhiteSpace($Ccache)) {
	            Show-ConnectionError -ErrorType "GenericError" -Details "Ccache ticket file path must not be empty" -NoThrow
	            return $null
	        }
	        if ($AuthMethod -eq 'NTHash') {
	            if ($NTHash -notmatch '^[0-9a-fA-F]{32}$') {
	                $Detail = if ($NTHash.Length -ne 32) { "Expected 32 hex chars, got $($NTHash.Length)" } else { "Contains non-hex characters" }
	                Show-ConnectionError -ErrorType "GenericError" -Details "Invalid NT-Hash format: $Detail" -NoThrow
	                return $null
	            }
	        }
	        elseif ($AuthMethod -eq 'AES256') {
	            if ($AES256Key -notmatch '^[0-9a-fA-F]{64}$') {
	                $Detail = if ($AES256Key.Length -ne 64) { "Expected 64 hex chars, got $($AES256Key.Length)" } else { "Contains non-hex characters" }
	                Show-ConnectionError -ErrorType "GenericError" -Details "Invalid AES256 key format: $Detail" -NoThrow
	                return $null
	            }
	        }
	        elseif ($AuthMethod -eq 'AES128') {
	            if ($AES128Key -notmatch '^[0-9a-fA-F]{32}$') {
	                $Detail = if ($AES128Key.Length -ne 32) { "Expected 32 hex chars, got $($AES128Key.Length)" } else { "Contains non-hex characters" }
	                Show-ConnectionError -ErrorType "GenericError" -Details "Invalid AES128 key format: $Detail" -NoThrow
	                return $null
	            }
	        }
	        $Script:AuthInfo = @{
	            Method = $null              # 'Kerberos' or 'SimpleBind' or 'WindowsSSPI' or 'NTLM Impersonation'
	            ParameterSet = $AuthMethod  # Original parameter set name
	            KerberosUsed = $false       # Was Kerberos actually used?
	            TGTInfo = $null             # TGT details if Kerberos was used
	            NTLMImpersonation = $ForceNTLM.IsPresent  # Track if NTLM impersonation was requested
	        }
	        if (-not $Script:LDAPContext) {
	            $Script:LDAPContext = @{}
	        }
	        if ($UseLDAPS) {
	            $Script:LDAPContext['UseLDAPS'] = $true
	        }
	        if ($DnsServer) {
	            $Script:LDAPContext['DnsServer'] = $DnsServer
	            $Script:LDAPContext['DnsCache'] = [System.Collections.Generic.Dictionary[string,string]]::new([System.StringComparer]::OrdinalIgnoreCase)
	            try {
	                $null = Resolve-DnsName -Name $Domain -Server $DnsServer -Type A -DnsOnly -ErrorAction Stop
	            }
	            catch {
	                Write-Warning "[Connect-adPEAS] DNS server $DnsServer not reachable or cannot resolve '$Domain'"
	            }
	            if ($PatchHostsFile) {
	                $isAdmin = Test-adPEASAdminPrivileges
	                if (-not $isAdmin) {
	                    Write-Warning "[Connect-adPEAS] -PatchHostsFile requires Administrator privileges!"
	                    Write-Warning "[Connect-adPEAS] Hosts file patching will be skipped. Run as Administrator for full functionality."
	                    $PatchHostsFile = $false
	                }
	                else {
	                    $Script:LDAPContext['PatchHostsFile'] = $true
	                    $earlyResolveTarget = if ($Server) { $Server } else { $Domain }
	                    $resolvedIP = Resolve-adPEASName -Name $earlyResolveTarget -DnsServer $DnsServer
	                    if ($resolvedIP) {
	                        $hostsPatched = @()
	                        if ($Server) {
	                            $patchResult = Add-adPEASHostsEntry -IPAddress $resolvedIP -Hostname $Server -Force
	                            if ($patchResult.Success) {
	                                $hostsPatched += $Server
	                            }
	                            Start-Sleep -Milliseconds 50
	                        }
	                        if ($Domain -ne $Server) {
	                            $patchResult = Add-adPEASHostsEntry -IPAddress $resolvedIP -Hostname $Domain -Force
	                            if ($patchResult.Success) {
	                                $hostsPatched += $Domain
	                            }
	                        }
	                        $Script:LDAPContext['HostsEntries'] = $hostsPatched
	                        $Script:LDAPContext['EarlyHostsPatched'] = $true
	                        if ($hostsPatched.Count -gt 0) {
	                            Show-Line "Patched hosts file with $($hostsPatched.Count) entries (cleanup on Disconnect-adPEAS)" -Class Info
	                        }
	                    }
	                    else {
	                        Write-Warning "[Connect-adPEAS] Could not resolve $earlyResolveTarget via custom DNS - hosts patching skipped"
	                    }
	                }
	            }
	        }
	        if ($AuthMethod -eq 'WindowsAuth' -and -not $Domain) {
	            try {
	                $Domain = [System.DirectoryServices.ActiveDirectory.Domain]::GetCurrentDomain().Name
	            } catch {
	                Show-ConnectionError -ErrorType "DomainError" -Details "Specify domain with -Domain parameter" -NoThrow
	                return $null
	            }
	        }
	        $AuthMethodDisplay = switch ($AuthMethod) {
	            'PSCredential' { 'PSCredential Object' }
	            'UsernamePassword' { 'Username/Password' }
	            'Certificate' { if ($ForcePassTheCert) { 'Certificate (Pass-the-Cert/Schannel)' } else { 'Certificate (PKINIT)' } }
	            'WindowsAuth' { 'Windows Authentication' }
	            'NTHash' { 'NT-Hash (Overpass-the-Hash)' }
	            'AES256' { 'AES256 Key (Pass-the-Key)' }
	            'AES128' { 'AES128 Key (Pass-the-Key)' }
	            'Kirbi' { 'Kirbi Ticket File (Pass-the-Ticket)' }
	            'Ccache' { 'Ccache Ticket File (Pass-the-Ticket)' }
	            default { $AuthMethod }
	        }
	        switch ($AuthMethod) {
	            { $_ -in @('PSCredential', 'UsernamePassword') } {
	                if ($AuthMethod -eq 'PSCredential') {
	                    if ($Server) { Write-Log "[Connect-adPEAS] Server: $Server" }
	                    $bstr = [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($Credential.Password)
	                    try {
	                        $PlainPassword = [System.Runtime.InteropServices.Marshal]::PtrToStringAuto($bstr)
	                    }
	                    finally {
	                        [System.Runtime.InteropServices.Marshal]::ZeroFreeBSTR($bstr)
	                    }
	                    $CredUsername = $Credential.UserName
	                    $SamAccountName = $CredUsername
	                    $UserRealm = $null  # null = same as target domain
	                    if ($CredUsername -match '^([^\\]+)\\(.+)$') {
	                        $UserDomainPrefix = $Matches[1]
	                        $SamAccountName = $Matches[2]
	                        $targetPrefix = ($Domain -split '\.')[0]
	                        if ($UserDomainPrefix -ine $targetPrefix -and $UserDomainPrefix -ine $Domain) {
	                            $UserRealm = $UserDomainPrefix
	                            if ($UserRealm -match '\.') {
	                            } else {
	                            }
	                        }
	                    }
	                    elseif ($CredUsername -match '^(.+)@([^@]+)$') {
	                        $SamAccountName = $Matches[1]
	                        $upnDomain = $Matches[2]
	                        if ($upnDomain -ine $Domain) {
	                            $UserRealm = $upnDomain
	                        }
	                    }
	                    $CredObject = $Credential
	                }
	                else {
	                    if ($Server) { Write-Log "[Connect-adPEAS] Server: $Server" }
	                    if ($null -eq $Password -or $Password -eq '') {
	                        $PlainPassword = ""
	                        $SecurePassword = New-Object System.Security.SecureString
	                    }
	                    elseif ($Password -is [string]) {
	                        $PlainPassword = $Password
	                        $SecurePassword = ConvertTo-SecureString -String $Password -AsPlainText -Force
	                    }
	                    elseif ($Password -is [System.Security.SecureString]) {
	                        $SecurePassword = $Password
	                        $bstr = [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($Password)
	                        try {
	                            $PlainPassword = [System.Runtime.InteropServices.Marshal]::PtrToStringAuto($bstr)
	                        }
	                        finally {
	                            [System.Runtime.InteropServices.Marshal]::ZeroFreeBSTR($bstr)
	                        }
	                    }
	                    elseif ($Password -is [int] -or $Password -is [long] -or $Password -is [double]) {
	                        $PlainPassword = $Password.ToString()
	                        $SecurePassword = ConvertTo-SecureString -String $PlainPassword -AsPlainText -Force
	                    }
	                    else {
	                        throw "Password must be either String, SecureString, or empty"
	                    }
	                    $CredentialUsername = $Username
	                    if ($Username -notmatch '\\' -and $Username -notmatch '@') {
	                        $NetBIOSDomain = ($Domain -split '\.')[0].ToUpper()
	                        $CredentialUsername = "$NetBIOSDomain\$Username"
	                    }
	                    $CredObject = New-Object System.Management.Automation.PSCredential($CredentialUsername, $SecurePassword)
	                    $SamAccountName = $Username
	                    $UserRealm = $null  # null = same as target domain, set when cross-domain detected
	                    if ($Username -match '^([^\\]+)\\(.+)$') {
	                        $UserDomainPrefix = $Matches[1]
	                        $SamAccountName = $Matches[2]
	                        $targetPrefix = ($Domain -split '\.')[0]
	                        if ($UserDomainPrefix -ine $targetPrefix -and $UserDomainPrefix -ine $Domain) {
	                            $UserRealm = $UserDomainPrefix
	                            if ($UserRealm -match '\.') {
	                            } else {
	                            }
	                        }
	                    }
	                    elseif ($Username -match '^(.+)@([^@]+)$') {
	                        $SamAccountName = $Matches[1]
	                        $upnDomain = $Matches[2]
	                        if ($upnDomain -ine $Domain) {
	                            $UserRealm = $upnDomain
	                        }
	                    }
	                }
	                if ($Server) {
	                    $ResolvedIP = Resolve-adPEASName -Name $Server
	                    $DCResolution = [PSCustomObject]@{ Hostname = $Server; IP = $ResolvedIP }
	                    if (-not $ResolvedIP) {
	                        Show-ConnectionError -ErrorType "DomainError" -Details "Server '$Server' could not be resolved - check DNS or use an IP address" -NoThrow
	                        return $null
	                    }
	                } else {
	                    $DCResolution = Resolve-adPEASName -Domain $Domain
	                    if (-not $DCResolution -or -not $DCResolution.Hostname) {
	                        Show-ConnectionError -ErrorType "DomainError" -Details "Could not discover a Domain Controller for '$Domain' - DNS resolution failed. Use -Server to specify a DC manually." -NoThrow
	                        return $null
	                    }
	                }
	                $KerberosAuthSuccess = $false
	                $Connection = $null
	                if ($ForceNTLM) {
	                    $ConnParams = @{}
	                    $ConnParams['Domain'] = $Domain
	                    if ($Server) {
	                        $ConnParams['Server'] = $Server
	                    } elseif ($DCResolution -and $DCResolution.Hostname) {
	                        $ConnParams['Server'] = $DCResolution.Hostname
	                    }
	                    if ($UseLDAPS) { $ConnParams['UseLDAPS'] = $true }
	                    $ConnParams['IgnoreSSLErrors'] = $IgnoreSSLErrors
	                    $ConnParams['TimeoutSeconds'] = $TimeoutSeconds
	                    $ConnParams['Credential'] = $CredObject
	                    $ConnParams['ForceNTLM'] = $true
	                    $Connection = Connect-LDAP @ConnParams
	                    if (-not $Connection) {
	                        return $null
	                    }
	                    $Script:AuthInfo.Method = 'NTLM'
	                    $Script:AuthInfo.KerberosUsed = $false
	                    $Script:AuthInfo.NTLMImpersonation = $false
	                    $Script:LDAPContext['Credential'] = $CredObject
	                }
	                elseif (-not $ForceSimpleBind -and $UserRealm -and $UserRealm -notmatch '\.') {
	                    Show-Line "Cross-domain authentication (NetBIOS): using NTLM/SimpleBind" -Class Hint
	                }
	                elseif (-not $ForceSimpleBind) {
	                    $UserRealmDC = $null
	                    if ($UserRealm -and $UserRealm -match '\.') {
	                        $UserRealmDC = Resolve-adPEASName -Domain $UserRealm
	                        if (-not $UserRealmDC -or -not $UserRealmDC.IP) {
	                            Show-Line "Cross-domain: could not find KDC for '$UserRealm' - using NTLM/SimpleBind" -Class Hint
	                            $UserRealmDC = $null
	                            $UserRealm = $null  # Clear to prevent cross-domain Kerberos attempt
	                        } else {
	                        }
	                    }
	                    $KerbFlowParams = @{
	                        SamAccountName = $SamAccountName
	                        Domain = $Domain
	                        DCHostname = $DCResolution.Hostname
	                        Password = $PlainPassword
	                        IgnoreSSLErrors = $IgnoreSSLErrors
	                    }
	                    if ($DCResolution.IP) { $KerbFlowParams['DCIP'] = $DCResolution.IP }
	                    if ($Server) { $KerbFlowParams['Server'] = $Server }
	                    if ($UseLDAPS) { $KerbFlowParams['UseLDAPS'] = $true }
	                    if ($UserRealm -and $UserRealmDC) {
	                        $KerbFlowParams['UserRealm'] = $UserRealm
	                        $KerbFlowParams['UserRealmKDC'] = $UserRealmDC.IP
	                    }
	                    $KerbFlowResult = Invoke-KerberosAuthFlow @KerbFlowParams
	                    if ($KerbFlowResult.Success) {
	                        $KerberosAuthSuccess = $true
	                        $Connection = $KerbFlowResult.Connection
	                        $Script:AuthInfo.Method = 'Kerberos'
	                        $Script:AuthInfo.KerberosUsed = $true
	                        $Script:AuthInfo.TGTInfo = @{
	                            UserName = $KerbFlowResult.TGTResult.UserName
	                            Domain = $KerbFlowResult.TGTResult.Domain
	                            EncryptionType = $KerbFlowResult.TGTResult.EncryptionType
	                            Method = $KerbFlowResult.TGTResult.Method
	                            AuthTime = $KerbFlowResult.TGTResult.AuthTime
	                            StartTime = $KerbFlowResult.TGTResult.StartTime
	                            EndTime = $KerbFlowResult.TGTResult.EndTime
	                            RenewTill = $KerbFlowResult.TGTResult.RenewTill
	                            ClockSkew = $KerbFlowResult.TGTResult.ClockSkew
	                        }
	                    }
	                    else {
	                        $ErrorMessage = $KerbFlowResult.Error
	                        $KdcErrorCode = $KerbFlowResult.ErrorCode
	                        $IsCrossDomain = $null -ne $UserRealm
	                        if ($null -ne $KdcErrorCode -and $KdcErrorCode -in $Script:KDC_FATAL_ERROR_CODES -and -not $IsCrossDomain) {
	                            Show-ConnectionError -ErrorType "KerberosError" -ErrorCode $KdcErrorCode -ErrorCodeType "Kerberos" -NoThrow
	                            return $null
	                        }
	                        if ($IsCrossDomain) {
	                            Show-Line "Cross-domain authentication: falling back to NTLM/SimpleBind" -Class Hint
	                        }
	                        $IsDnsResolutionIssue = $ErrorMessage -match "Kerberos tickets obtained successfully.*LDAP connection failed"
	                        if ($IsDnsResolutionIssue) {
	                            Show-Line "Kerberos TGT/TGS acquired successfully, but LDAP requires hostname resolution" -Class Note
	                            Show-Line "Use -PatchHostsFile for full Kerberos authentication" -Class Note
	                        }
	                        $IsPTTError = $ErrorMessage -match "non-domain-joined|Remote Credential Guard|Ticket import failed|ticket not used|ticket not usable"
	                        if ($IsPTTError) {
	                        }
	                        if ($ForceKerberos) {
	                            if ($KerbFlowResult.IsNetworkError) {
	                                $NetworkServer = if ($KerbFlowResult.NetworkErrorServer) { $KerbFlowResult.NetworkErrorServer } else { $Server }
	                                Show-ConnectionError -ErrorType "NetworkError" -Details "Port 88 (Kerberos) unreachable on $NetworkServer" -NoThrow
	                            }
	                            else {
	                                if ($null -ne $KdcErrorCode) {
	                                    Show-ConnectionError -ErrorType "KerberosError" -ErrorCode $KdcErrorCode -ErrorCodeType "Kerberos" -NoThrow
	                                } else {
	                                    Show-ConnectionError -ErrorType "KerberosError" -Details $ErrorMessage -NoThrow
	                                }
	                            }
	                            return $null
	                        }
	                        Show-Line "Kerberos failed - trying NTLM impersonation" -Class Info
	                    }
	                }
	                else {
	                }
	                if (-not $KerberosAuthSuccess -and -not $ForceNTLM) {
	                    if (-not $ForceSimpleBind) {
	                        $ConnParams = @{}
	                        $ConnParams['Domain'] = $Domain
	                        if ($Server) {
	                            $ConnParams['Server'] = $Server
	                        } elseif ($DCResolution -and $DCResolution.Hostname) {
	                            $ConnParams['Server'] = $DCResolution.Hostname
	                        }
	                        if ($UseLDAPS) { $ConnParams['UseLDAPS'] = $true }
	                        $ConnParams['IgnoreSSLErrors'] = $IgnoreSSLErrors
	                        $ConnParams['TimeoutSeconds'] = $TimeoutSeconds
	                        $ConnParams['Credential'] = $CredObject
	                        $ConnParams['ForceNTLM'] = $true
	                        $Connection = Connect-LDAP @ConnParams
	                        if (-not $Connection) {
	                            Show-Line "NTLM failed - falling back to SimpleBind" -Class Hint
	                        }
	                        else {
	                            $Script:AuthInfo.Method = 'NTLM'
	                            $Script:AuthInfo.KerberosUsed = $false
	                            $Script:AuthInfo.NTLMImpersonation = $false
	                            $Script:LDAPContext['Credential'] = $CredObject
	                            Show-Line "Connected via NTLM (supports LDAP signing)" -Class Hint
	                        }
	                    }
	                    if (-not $Connection) {
	                        $ConnParams = @{}
	                        $ConnParams['Domain'] = $Domain
	                        if ($Server) {
	                            $ConnParams['Server'] = $Server
	                        } elseif ($DCResolution -and $DCResolution.Hostname) {
	                            $ConnParams['Server'] = $DCResolution.Hostname
	                        }
	                        if ($UseLDAPS) { $ConnParams['UseLDAPS'] = $true }
	                        $ConnParams['IgnoreSSLErrors'] = $IgnoreSSLErrors
	                        $ConnParams['TimeoutSeconds'] = $TimeoutSeconds
	                        $ConnParams['Credential'] = $CredObject
	                        if (-not $UseLDAPS) {
	                            $ConnParams['SuppressErrorDisplay'] = $true
	                        }
	                        $Connection = Connect-LDAP @ConnParams
	                        $ConnParams.Remove('SuppressErrorDisplay')
	                        if (-not $Connection -and $Script:LastLDAPErrorCode -eq 1) {
	                            $Script:ConnectionState = "AuthenticationFailed"
	                        }
	                        if (-not $Connection -and -not $UseLDAPS -and $Script:LastLDAPErrorCode -ne 8) {
	                            if ($Script:ConnectionState) {
	                                if ($null -ne $Script:LastLDAPErrorCode) {
	                                    Show-ConnectionError -ErrorType $Script:ConnectionState -ErrorCode $Script:LastLDAPErrorCode -ErrorCodeType "LDAP" -NoThrow
	                                } else {
	                                    Show-ConnectionError -ErrorType $Script:ConnectionState -Details $Script:LastLDAPErrorDetails -NoThrow
	                                }
	                            }
	                        }
	                        if (-not $Connection -and -not $UseLDAPS -and $Script:LastLDAPErrorCode -eq 8) {
	                            Show-Line "LDAP signing/channel binding required - auto-upgrading to LDAPS" -Class Hint
	                            $ConnParams['UseLDAPS'] = $true
	                            $Connection = Connect-LDAP @ConnParams
	                        }
	                        if (-not $Connection) {
	                            return $null
	                        }
	                        $Script:AuthInfo.Method = 'SimpleBind'
	                        $Script:AuthInfo.KerberosUsed = $false
	                    }
	                }
	            }
	            'Certificate' {
	                if ($Server) {
	                }
	                if ($CertificatePassword -is [System.Security.SecureString]) {
	                    $bstr = [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($CertificatePassword)
	                    try {
	                        $PlainCertPassword = [System.Runtime.InteropServices.Marshal]::PtrToStringAuto($bstr)
	                    }
	                    finally {
	                        [System.Runtime.InteropServices.Marshal]::ZeroFreeBSTR($bstr)
