	                        $san = $ext.Format($false)
	                        $upnMatches = [regex]::Matches($san, "Principal Name[=:]([^,\r\n]+)")
	                        foreach ($m in $upnMatches) {
	                            $upnValue = $m.Groups[1].Value.Trim()
	                            if ($upnValue -match "^([^@]+)@") {
