	                        foreach ($m in $dnsMatches) {
	                            $dnsValue = $m.Groups[1].Value.Trim()
	                            $hostPart = ($dnsValue -split '\.')[0]
	                            $certIdentities += [PSCustomObject]@{
	                                Type = "DNS"
	                                Value = $dnsValue
	                                CName = "$hostPart`$"  # computer account
	                            }
	                        }
	                    }
	                }
	                if ($certIdentities.Count -eq 0) {
	                    if ($Cert.Subject -match "CN=([^,]+)") {
	                        $cnValue = $Matches[1]
	                        if ($cnValue -match "^([^.]+)\.(.+\..+)$") {
