	                                Type = "CN"
	                                Value = $cnValue
	                                CName = "$($Matches[1])`$"
	                            }
	                        } else {
	                            $certIdentities += [PSCustomObject]@{
	                                Type = "CN"
	                                Value = $cnValue
	                                CName = $cnValue
