	                                if ($CertNameFlag -band 0x00400000) { $CertNameFlags += "SUBJECT_ALT_REQUIRE_DOMAIN_DNS" }
	                                if ($CertNameFlag -band 0x00800000) { $CertNameFlags += "SUBJECT_ALT_REQUIRE_SPN" }
	                                if ($CertNameFlag -band 0x01000000) { $CertNameFlags += "SUBJECT_ALT_REQUIRE_DIRECTORY_GUID" }
	                                if ($CertNameFlag -band 0x02000000) { $CertNameFlags += "SUBJECT_ALT_REQUIRE_UPN" }
	                                if ($CertNameFlag -band 0x04000000) { $CertNameFlags += "SUBJECT_ALT_REQUIRE_EMAIL" }
	                                if ($CertNameFlag -band 0x08000000) { $CertNameFlags += "SUBJECT_ALT_REQUIRE_DNS" }
	                                if ($CertNameFlag -band 0x10000000) { $CertNameFlags += "SUBJECT_REQUIRE_DNS_AS_CN" }
	                                if ($CertNameFlag -band 0x20000000) { $CertNameFlags += "SUBJECT_REQUIRE_EMAIL" }
	                                if ($CertNameFlag -band 0x40000000) { $CertNameFlags += "SUBJECT_REQUIRE_COMMON_NAME" }
	                                if ($CertNameFlag -band 0x80000000) { $CertNameFlags += "SUBJECT_REQUIRE_DIRECTORY_PATH" }
	                                if ($CertNameFlag -band 0x00000008) { $CertNameFlags += "OLD_CERT_SUPPLIES_SUBJECT_AND_ALT_NAME" }
	                                if ($CertNameFlags.Count -gt 0) {
	                                    $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $CertNameFlags
	                                } else {
	                                    $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value @("NONE")
	                                }
	                            } catch {
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $PropValue[0]
	                            }
	                        } elseif ($PropNameLower -eq 'mspki-enrollment-flag') {
	                            try {
	                                $EnrollFlag = [Int32]$PropValue[0]
	                                $EnrollFlags = @()
	                                if ($EnrollFlag -band 0x00000001) { $EnrollFlags += "INCLUDE_SYMMETRIC_ALGORITHMS" }
	                                if ($EnrollFlag -band 0x00000002) { $EnrollFlags += "PEND_ALL_REQUESTS" }
	                                if ($EnrollFlag -band 0x00000004) { $EnrollFlags += "PUBLISH_TO_KRA_CONTAINER" }
	                                if ($EnrollFlag -band 0x00000008) { $EnrollFlags += "PUBLISH_TO_DS" }
	                                if ($EnrollFlag -band 0x00000010) { $EnrollFlags += "AUTO_ENROLLMENT_CHECK_USER_DS_CERTIFICATE" }
	                                if ($EnrollFlag -band 0x00000020) { $EnrollFlags += "AUTO_ENROLLMENT" }
	                                if ($EnrollFlag -band 0x00000040) { $EnrollFlags += "PREVIOUS_APPROVAL_VALIDATE_REENROLLMENT" }
	                                if ($EnrollFlag -band 0x00000100) { $EnrollFlags += "USER_INTERACTION_REQUIRED" }
	                                if ($EnrollFlag -band 0x00000400) { $EnrollFlags += "REMOVE_INVALID_CERTIFICATE_FROM_PERSONAL_STORE" }
	                                if ($EnrollFlag -band 0x00000800) { $EnrollFlags += "ALLOW_ENROLL_ON_BEHALF_OF" }
	                                if ($EnrollFlag -band 0x00001000) { $EnrollFlags += "ADD_OCSP_NOCHECK" }
	                                if ($EnrollFlag -band 0x00002000) { $EnrollFlags += "ENABLE_KEY_REUSE_ON_NT_TOKEN_KEYSET_STORAGE_FULL" }
	                                if ($EnrollFlag -band 0x00004000) { $EnrollFlags += "NOREVOCATIONINFOINISSUEDCERTS" }
	                                if ($EnrollFlag -band 0x00008000) { $EnrollFlags += "INCLUDE_BASIC_CONSTRAINTS_FOR_EE_CERTS" }
	                                if ($EnrollFlag -band 0x00010000) { $EnrollFlags += "ALLOW_PREVIOUS_APPROVAL_KEYBASEDRENEWAL_VALIDATE_REENROLLMENT" }
	                                if ($EnrollFlag -band 0x00020000) { $EnrollFlags += "ISSUANCE_POLICIES_FROM_REQUEST" }
	                                if ($EnrollFlag -band 0x00040000) { $EnrollFlags += "SKIP_AUTO_RENEWAL" }
	                                if ($EnrollFlag -band 0x00080000) { $EnrollFlags += "NO_SECURITY_EXTENSION" }
	                                if ($EnrollFlags.Count -gt 0) {
	                                    $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $EnrollFlags
	                                } else {
	                                    $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value @("NONE")
	                                }
	                            } catch {
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $PropValue[0]
	                            }
	                        } elseif ($PropNameLower -eq 'mspki-private-key-flag') {
	                            try {
	                                $PrivKeyFlag = [Int32]$PropValue[0]
	                                $PrivKeyFlags = @()
	                                if ($PrivKeyFlag -band 0x00000001) { $PrivKeyFlags += "REQUIRE_PRIVATE_KEY_ARCHIVAL" }
	                                if ($PrivKeyFlag -band 0x00000010) { $PrivKeyFlags += "EXPORTABLE_KEY" }
	                                if ($PrivKeyFlag -band 0x00000020) { $PrivKeyFlags += "STRONG_KEY_PROTECTION_REQUIRED" }
	                                if ($PrivKeyFlag -band 0x00000040) { $PrivKeyFlags += "REQUIRE_ALTERNATE_SIGNATURE_ALGORITHM" }
	                                if ($PrivKeyFlag -band 0x00000080) { $PrivKeyFlags += "REQUIRE_SAME_KEY_RENEWAL" }
	                                if ($PrivKeyFlag -band 0x00000100) { $PrivKeyFlags += "USE_LEGACY_PROVIDER" }
	                                if ($PrivKeyFlag -band 0x00002000) { $PrivKeyFlags += "ATTEST_REQUIRED" }
	                                if ($PrivKeyFlag -band 0x00001000) { $PrivKeyFlags += "ATTEST_PREFERRED" }
	                                if ($PrivKeyFlag -band 0x00004000) { $PrivKeyFlags += "ATTESTATION_WITHOUT_POLICY" }
	                                if ($PrivKeyFlag -band 0x00000200) { $PrivKeyFlags += "EK_TRUST_ON_USE" }
	                                if ($PrivKeyFlag -band 0x00000400) { $PrivKeyFlags += "EK_VALIDATE_CERT" }
	                                if ($PrivKeyFlag -band 0x00000800) { $PrivKeyFlags += "EK_VALIDATE_KEY" }
	                                if ($PrivKeyFlag -band 0x00200000) { $PrivKeyFlags += "HELLO_LOGON_KEY" }
	                                if ($PrivKeyFlags.Count -gt 0) {
	                                    $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $PrivKeyFlags
	                                } else {
	                                    $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value @("NONE")
	                                }
	                            } catch {
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $PropValue[0]
	                            }
	                        } elseif ($PropNameLower -eq 'pkidefaultkeyspec') {
	                            try {
	                                $KeySpec = [Int32]$PropValue[0]
	                                $KeySpecName = switch ($KeySpec) {
	                                    1 { "AT_KEYEXCHANGE (Key Exchange)" }
	                                    2 { "AT_SIGNATURE (Digital Signature)" }
	                                    default { "Unknown ($KeySpec)" }
	                                }
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $KeySpecName
	                            } catch {
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $PropValue[0]
	                            }
	                        } elseif ($PropNameLower -eq 'msrassavedframedipaddress') {
	                            try {
	                                $IPBytes = [BitConverter]::GetBytes([Int32]$PropValue[0])
	                                $IPAddr = [System.Net.IPAddress]::new($IPBytes)
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $IPAddr.ToString()
	                            } catch {
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $PropValue[0]
	                            }
	                        } elseif ($PropNameLower -eq 'msexchversion') {
	                            try {
	                                $Version = [Int64]$PropValue[0]
	                                $Major = ($Version -shr 48) -band 0xFFFF
	                                $Minor = ($Version -shr 32) -band 0xFFFF
	                                $Build = ($Version -shr 16) -band 0xFFFF
	                                $Revision = $Version -band 0xFFFF
	                                $VersionString = "$Major.$Minor.$Build.$Revision"
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $VersionString
	                            } catch {
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $PropValue[0]
	                            }
	                        } elseif ($PropNameLower -eq 'msexchelcmailboxflags') {
	                            try {
	                                $ELCFlags = [Int32]$PropValue[0]
	                                $ELCFlagList = @()
	                                if ($ELCFlags -band 1) { $ELCFlagList += "MRM_POLICY_APPLIED" }
	                                if ($ELCFlags -band 2) { $ELCFlagList += "SINGLE_ITEM_RECOVERY" }
	                                if ($ELCFlags -band 4) { $ELCFlagList += "CALENDAR_VERSION_STORE" }
	                                if ($ELCFlags -band 8) { $ELCFlagList += "LITIGATION_HOLD" }
	                                if ($ELCFlags -band 16) { $ELCFlagList += "DUMPSTER_EXTENDED" }
	                                if ($ELCFlags -band 32) { $ELCFlagList += "SITE_MAILBOX_HOLD" }
	                                if ($ELCFlags -band 64) { $ELCFlagList += "ARCHIVE_ENABLED" }
	                                if ($ELCFlags -band 128) { $ELCFlagList += "ELC_PROCESSING_DISABLED" }
	                                if ($ELCFlagList.Count -gt 0) {
	                                    $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $ELCFlagList
	                                } else {
	                                    $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value @("NONE")
	                                }
	                            } catch {
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $PropValue[0]
	                            }
	                        } elseif ($PropNameLower -eq 'gplink') {
	                            try {
	                                $GPLinkString = $PropValue[0]
	                                $GPLinks = @()
	                                $Pattern = '(?i)\[LDAP://cn=\{([^\}]+)\}[^\]]+;(\d+)\]'
	                                $GPLinkMatches = [regex]::Matches($GPLinkString, $Pattern)
	                                foreach ($Match in $GPLinkMatches) {
	                                    $GUID = $Match.Groups[1].Value
	                                    $LinkOptions = [int]$Match.Groups[2].Value
	                                    $Status = if ($LinkOptions -band 1) { "Disabled" } else { "Enabled" }
	                                    if ($LinkOptions -band 2) { $Status += " (Enforced)" }
	                                    $GPLinks += "GPO {$GUID} [$Status]"
	                                }
	                                if ($GPLinks.Count -gt 0) {
	                                    $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $GPLinks
	                                } else {
	                                    $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $PropValue[0]
	                                }
	                            } catch {
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $PropValue[0]
	                            }
	                        } elseif ($PropNameLower -match '^msexch.*quota$' -or $PropNameLower -eq 'mdbstoragequota' -or $PropNameLower -eq 'mdboverquotalimit' -or $PropNameLower -eq 'mdboverhardquotalimit') {
	                            try {
	                                $QuotaBytes = [Int64]$PropValue[0]
	                                if ($QuotaBytes -eq 0) {
	                                    $QuotaString = "Unlimited"
	                                } elseif ($QuotaBytes -lt 1KB) {
	                                    $QuotaString = "$QuotaBytes bytes"
	                                } elseif ($QuotaBytes -lt 1MB) {
	                                    $QuotaKB = [Math]::Round($QuotaBytes / 1KB, 2)
	                                    $QuotaString = "$QuotaKB KB"
	                                } elseif ($QuotaBytes -lt 1GB) {
	                                    $QuotaMB = [Math]::Round($QuotaBytes / 1MB, 2)
	                                    $QuotaString = "$QuotaMB MB"
	                                } elseif ($QuotaBytes -lt 1TB) {
	                                    $QuotaGB = [Math]::Round($QuotaBytes / 1GB, 2)
	                                    $QuotaString = "$QuotaGB GB"
	                                } else {
	                                    $QuotaTB = [Math]::Round($QuotaBytes / 1TB, 2)
	                                    $QuotaString = "$QuotaTB TB"
	                                }
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $QuotaString
	                            } catch {
	                                $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $PropValue[0]
	                            }
	                        } else {
	                            $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value $PropValue[0]
	                        }
	                    }
	                } else {
	                    $Obj | Add-Member -Force -MemberType NoteProperty -Name $PropName -Value @($PropValue)
	                }
	            }
	            $SortedPropertyNames = $Obj.PSObject.Properties.Name | Sort-Object
	            $SortedObj = [PSCustomObject]@{}
	            foreach ($SortedPropName in $SortedPropertyNames) {
	                $SortedObj | Add-Member -Force -MemberType NoteProperty -Name $SortedPropName -Value $Obj.$SortedPropName
	            }
	            [void]$OutputObjects.Add($SortedObj)
	        }
	        return $OutputObjects
	    } catch {
	        if (Test-LDAPErrorNotFound -Exception $_.Exception) {
	            return @()
	        } else {
	            throw
	        }
	    }
	}
}
function Get-DomainObject {
	[CmdletBinding()]
	param(
	    [Parameter(Position=0, ValueFromPipeline=$true, ValueFromPipelineByPropertyName=$true)]
	    [Alias('distinguishedName', 'Name')]
	    [string]$Identity,
	    [Parameter(Mandatory=$false)]
	    [string]$ObjectClass,
	    [Parameter(Mandatory=$false)]
	    [string]$LDAPFilter,
	    [Parameter(Mandatory=$false)]
	    [string[]]$Properties,
	    [Parameter(Mandatory=$false)]
	    [switch]$ShowOwner,
	    [Parameter(Mandatory=$false)]
	    [string]$SearchBase,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('Subtree', 'OneLevel', 'Base')]
	    [string]$Scope = 'Subtree',
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$Raw,
	    [Parameter(Mandatory=$false)]
	    [int]$ResultLimit = 0,
	    [Parameter(Mandatory=$false)]
	    [switch]$IsEnabled,
	    [Parameter(Mandatory=$false)]
	    [switch]$IsDisabled,
	    [Parameter(Mandatory=$false)]
	    [switch]$PasswordNeverExpires,
	    [Parameter(Mandatory=$false)]
	    [switch]$PasswordNotRequired,
	    [Parameter(Mandatory=$false)]
	    [switch]$TrustedForDelegation,
	    [Parameter(Mandatory=$false)]
	    [switch]$TrustedToAuthForDelegation,
	    [Parameter(Mandatory=$false)]
	    [switch]$HasSPN,
	    [Parameter(Mandatory=$false)]
	    [switch]$AdminCount,
	    [Parameter(Mandatory=$false)]
	    [switch]$PasswordMustChange,
	    [Parameter(Mandatory=$false)]
	    [switch]$LockedOut,
	    [Parameter(Mandatory=$false)]
	    [switch]$SmartcardRequired,
	    [Parameter(Mandatory=$false)]
	    [switch]$AccountExpired,
	    [Parameter(Mandatory=$false)]
	    [switch]$AccountNeverExpires,
	    [Parameter(Mandatory=$false)]
	    [switch]$PreauthNotRequired,
	    [Parameter(Mandatory=$false)]
	    [switch]$DESOnly,
	    [Parameter(Mandatory=$false)]
	    [switch]$ReversibleEncryption,
	    [Parameter(Mandatory=$false)]
	    [switch]$NotDelegated
	)
	begin {
	    $ConnectionParams = @{}
	    if ($Domain) { $ConnectionParams['Domain'] = $Domain }
	    if ($Server) { $ConnectionParams['Server'] = $Server }
	    if ($Credential) { $ConnectionParams['Credential'] = $Credential }
	    if (-not (Ensure-LDAPConnection @ConnectionParams)) {
	        return
	    }
	    if ($Script:SIDVerboseCache) {
	        $Script:SIDVerboseCache.Clear()
	    }
	}
	process {
	    if (-not $Script:LDAPContext) {
	        return $null
	    }
	    try {
	        if ($LDAPFilter -and -not $Identity -and -not $ObjectClass) {
	            $Filter = $LDAPFilter
	        } else {
	            $Filter = "(objectClass=*)"
	            if ($Identity) {
	                $crossDomainInfo = Resolve-CrossDomainIdentity -Identity $Identity
	                $crossDomainQuery = $crossDomainInfo.IsCrossDomain
	                $targetDomainDN = $crossDomainInfo.TargetDomainDN
	                $targetDomainFQDN = $crossDomainInfo.TargetDomainFQDN
	                $Identity = $crossDomainInfo.Identity
	                if ($crossDomainQuery) {
	                }
	                if ($Identity -match '^S-1-5-.*') {
	                    $SIDObj = New-Object System.Security.Principal.SecurityIdentifier($Identity)
	                    $SIDBytes = New-Object byte[] $SIDObj.BinaryLength
	                    $SIDObj.GetBinaryForm($SIDBytes, 0)
	                    $SIDHex = ($SIDBytes | ForEach-Object { '\' + $_.ToString('X2') }) -join ''
	                    $IdentityFilter = "(objectSid=$SIDHex)"
	                } elseif ($Identity -match '^CN=.*|^OU=.*|^DC=.*') {
	                    $IdentityFilter = "(distinguishedName=$Identity)"
	                } elseif ($Identity -match '^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$') {
	                    $GUIDObj = [System.Guid]::Parse($Identity)
	                    $GUIDBytes = $GUIDObj.ToByteArray()
	                    $GUIDHex = ($GUIDBytes | ForEach-Object { '\' + $_.ToString('X2') }) -join ''
	                    $IdentityFilter = "(objectGUID=$GUIDHex)"
	                } else {
	                    $IdentityFilter = "(|(sAMAccountName=$Identity)(cn=$Identity)(name=$Identity))"
	                }
	                $Filter = "(&$Filter$IdentityFilter)"
	            }
	            if ($ObjectClass) {
	                $Filter = "(&$Filter(objectClass=$ObjectClass))"
	            }
	            if ($LDAPFilter) {
	                $Filter = "(&$Filter$LDAPFilter)"
	            }
	        }
	        $accountFilters = @()
	        if ($IsEnabled) {
	            $accountFilters += "(!(userAccountControl:1.2.840.113556.1.4.803:=2))"
	        }
	        if ($IsDisabled) {
	            $accountFilters += "(userAccountControl:1.2.840.113556.1.4.803:=2)"
	        }
	        if ($PasswordNeverExpires) {
	            $accountFilters += "(userAccountControl:1.2.840.113556.1.4.803:=65536)"
	        }
	        if ($PasswordNotRequired) {
	            $accountFilters += "(userAccountControl:1.2.840.113556.1.4.803:=32)"
	        }
	        if ($TrustedForDelegation) {
	            $accountFilters += "(userAccountControl:1.2.840.113556.1.4.803:=524288)"
	        }
	        if ($TrustedToAuthForDelegation) {
	            $accountFilters += "(userAccountControl:1.2.840.113556.1.4.803:=16777216)"
	        }
	        if ($HasSPN) {
	            $accountFilters += "(servicePrincipalName=*)"
	        }
	        if ($AdminCount) {
	            $accountFilters += "(adminCount=1)"
	        }
	        if ($PasswordMustChange) {
	            $accountFilters += "(pwdLastSet=0)"
	        }
	        if ($LockedOut) {
	            $accountFilters += "(lockoutTime>=1)"
	        }
	        if ($SmartcardRequired) {
	            $accountFilters += "(userAccountControl:1.2.840.113556.1.4.803:=262144)"
	        }
	        if ($AccountExpired) {
	            $accountFilters += "(&(accountExpires>=1)(!(accountExpires=9223372036854775807)))"
	            $Script:FilterAccountExpired = $true
	        }
	        if ($AccountNeverExpires) {
	            $accountFilters += "(|(accountExpires=0)(accountExpires=9223372036854775807))"
	        }
	        if ($PreauthNotRequired) {
	            $accountFilters += "(userAccountControl:1.2.840.113556.1.4.803:=4194304)"
	        }
	        if ($DESOnly) {
	            $accountFilters += "(userAccountControl:1.2.840.113556.1.4.803:=2097152)"
	        }
	        if ($ReversibleEncryption) {
	            $accountFilters += "(userAccountControl:1.2.840.113556.1.4.803:=128)"
	        }
	        if ($NotDelegated) {
	            $accountFilters += "(userAccountControl:1.2.840.113556.1.4.803:=1048576)"
	        }
	        if ($accountFilters.Count -gt 0) {
	            $allAccountFilters = $accountFilters -join ''
	            $Filter = "(&$Filter$allAccountFilters)"
	        }
	        $SearchParams = @{
	            Filter = $Filter
	        }
	        if ($Properties) {
	            $SearchParams['Properties'] = $Properties
	        }
	        if ($ShowOwner) {
	            if ($Properties) {
	                if ($Properties -inotcontains 'nTSecurityDescriptor') {
	                    $SearchParams['Properties'] = $Properties + 'nTSecurityDescriptor'
	                }
	            } else {
	                $SearchParams['AdditionalProperties'] = @('nTSecurityDescriptor')
	            }
	        }
	        if ($targetDomainDN) {
	            $SearchParams['SearchBase'] = $targetDomainDN
	        } elseif ($SearchBase) {
	            $SearchParams['SearchBase'] = $SearchBase
	        }
	        if ($Scope) {
	            $SearchParams['Scope'] = $Scope
	        }
	        if ($Raw) {
	            $SearchParams['Raw'] = $true
	        }
	        if ($ResultLimit -gt 0) {
	            $SearchParams['SizeLimit'] = $ResultLimit
	        }
	        if ($crossDomainQuery) {
	            $gcConn = Get-GCConnection
	            if ($gcConn) {
	                $SearchParams['LdapConnection'] = $gcConn
	                if (-not $targetDomainDN -and $SearchParams.ContainsKey('SearchBase')) {
	                    $SearchParams.Remove('SearchBase')
	                }
	            } else {
	            }
	        }
	        $Objects = @(Invoke-LDAPSearch @SearchParams)
	        if ($targetDomainFQDN -and $Objects.Count -gt 0) {
	            $FilteredObjects = @()
	            foreach ($Obj in $Objects) {
	                if ($Obj.distinguishedName) {
	                    if (Test-DomainMatch -DistinguishedName $Obj.distinguishedName -TargetDomainFQDN $targetDomainFQDN) {
	                        $FilteredObjects += $Obj
	                    }
	                } else {
	                    $FilteredObjects += $Obj
	                }
	            }
	            $Objects = $FilteredObjects
	        }
	        if ($AccountExpired -and $Objects.Count -gt 0) {
	            $Now = [DateTime]::UtcNow
	            $NowFileTime = $Now.ToFileTimeUtc()
	            $FilteredObjects = @()
	            foreach ($Obj in $Objects) {
	                if ($Obj.accountExpires) {
	                    try {
	                        $ExpireTime = $Obj.accountExpires
	                        if ($ExpireTime -is [string]) {
	                            $ExpireTime = [Int64]::Parse($ExpireTime)
	                        }
	                        if ($ExpireTime -lt $NowFileTime) {
	                            $FilteredObjects += $Obj
	                        }
	                    } catch {
	                    }
	                }
	            }
	            $Objects = $FilteredObjects
	        }
	        if ($ShowOwner) {
	            foreach ($Object in $Objects) {
	                if ($Object.nTSecurityDescriptor -and $Object.nTSecurityDescriptor.Owner) {
	                    $Object | Add-Member -NotePropertyName 'Owner' -NotePropertyValue $Object.nTSecurityDescriptor.Owner.Name -Force
	                    $Object | Add-Member -NotePropertyName 'OwnerSID' -NotePropertyValue $Object.nTSecurityDescriptor.Owner.SID -Force
	                } else {
	                }
	            }
	        }
	        return $Objects
	    } catch {
	        throw
	    }
	}
	end {
	}
}
function Get-ObjectACL {
	[CmdletBinding(DefaultParameterSetName='Identity')]
	param(
	    [Parameter(Position=0, ValueFromPipeline=$true, ValueFromPipelineByPropertyName=$true, ParameterSetName='Identity')]
	    [Alias('samAccountName', 'Name')]
	    [string]$Identity,
	    [Parameter(ValueFromPipelineByPropertyName=$true, ParameterSetName='DN')]
	    [Alias('DN')]
	    [string]$DistinguishedName,
	    [Parameter(Mandatory=$false)]
	    [string[]]$Trustee,
	    [Parameter(Mandatory=$false)]
	    [string[]]$ExcludeTrustee,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('GenericAll', 'GenericRead', 'GenericWrite', 'GenericExecute',
	                 'CreateChild', 'DeleteChild', 'ListChildren', 'Self',
	                 'ReadProperty', 'WriteProperty', 'DeleteTree', 'ListObject',
	                 'ExtendedRight', 'Delete', 'ReadControl', 'WriteDacl', 'WriteOwner', 'Synchronize')]
	    [string[]]$Rights,
	    [Parameter(Mandatory=$false)]
	    [string[]]$ExtendedRight,
	    [Parameter(Mandatory=$false)]
	    [switch]$DangerousOnly,
	    [Parameter(Mandatory=$false)]
	    [switch]$WriteOnly,
	    [Parameter(Mandatory=$false)]
	    [switch]$ExtendedRightsOnly,
	    [Parameter(Mandatory=$false)]
	    [switch]$ExplicitOnly,
	    [Parameter(Mandatory=$false)]
	    [switch]$AllowOnly,
	    [Parameter(Mandatory=$false)]
	    [switch]$DenyOnly,
	    [Parameter(Mandatory=$false)]
	    [switch]$IncludeObjectInfo,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoResolveGUIDs,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoResolveSIDs,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential
	)
	begin {
	}
	process {
	    try {
	        $connectionParams = @{}
	        if ($Domain) { $connectionParams['Domain'] = $Domain }
	        if ($Server) { $connectionParams['Server'] = $Server }
	        if ($Credential) { $connectionParams['Credential'] = $Credential }
	        if (-not (Ensure-LDAPConnection @connectionParams)) {
	            return $null
	        }
	        $targetDN = $null
	        $targetObject = $null
	        if ($DistinguishedName) {
	            $targetDN = $DistinguishedName
	        }
	        elseif ($Identity) {
	            if ($Identity -match '^(CN|OU|DC)=') {
	                $targetDN = $Identity
	            }
	            else {
	                $targetObject = @(Get-DomainObject -Identity $Identity -Properties 'distinguishedName','objectClass','nTSecurityDescriptor' -Raw @connectionParams)[0]
	                if (-not $targetObject) {
	                    Write-Warning "[Get-ObjectACL] Object not found: $Identity"
	                    return $null
	                }
	                $targetDN = $targetObject.distinguishedName
	            }
	        }
	        else {
	            Write-Warning "[Get-ObjectACL] No Identity or DistinguishedName specified"
	            return $null
	        }
	        if (-not $targetObject -or -not $targetObject.nTSecurityDescriptor) {
	            $targetObject = @(Get-DomainObject -Identity $targetDN -Properties 'distinguishedName','objectClass','nTSecurityDescriptor' -Raw @connectionParams)[0]
	            if (-not $targetObject) {
	                Write-Warning "[Get-ObjectACL] Failed to retrieve object: $targetDN"
	                return $null
	            }
	        }
	        if (-not $targetObject.nTSecurityDescriptor) {
	            Write-Warning "[Get-ObjectACL] No nTSecurityDescriptor available for: $targetDN (access denied or not present)"
	            return $null
	        }
	        $securityDescriptor = $targetObject.nTSecurityDescriptor
	        if ($securityDescriptor -is [PSCustomObject] -and $securityDescriptor.ACEs) {
	            $parsedSD = $securityDescriptor
	        }
	        elseif ($securityDescriptor -is [System.DirectoryServices.ActiveDirectorySecurity] -or
	                $securityDescriptor -is [byte[]] -or
	                ($securityDescriptor -is [System.Array] -and -not ($securityDescriptor -is [byte[]]))) {
	            $sdParsed = ConvertTo-AccessRules -SecurityDescriptorBytes $securityDescriptor
	            if (-not $sdParsed) {
	                Write-Warning "[Get-ObjectACL] Failed to parse nTSecurityDescriptor for: $targetDN"
	                return $null
	            }
	            $OwnerSID = $sdParsed.OwnerSID
	            $OwnerName = if (-not $NoResolveSIDs) { ConvertFrom-SID -SID $OwnerSID } else { $OwnerSID }
	            $DACL = $sdParsed.AccessRules
	            $ACEList = @()
	            foreach ($ACE in $DACL) {
	                $TrusteeSID = $ACE.IdentityReference.Value
	                $TrusteeName = if (-not $NoResolveSIDs) { ConvertFrom-SID -SID $TrusteeSID } else { $TrusteeSID }
	                $RightsArray = @()
	                $ADRights = $ACE.ActiveDirectoryRights
	                foreach ($Right in $Script:AllActiveDirectoryRights) {
	                    if (($ADRights -band $Right) -eq $Right) {
	                        $RightsArray += $Right.ToString()
	                    }
	                }
	                $ObjectTypeGuid = if ($ACE.ObjectType -and $ACE.ObjectType -ne [System.Guid]::Empty) {
	                    $ACE.ObjectType.ToString()
	                } else { $null }
	                $ObjectTypeName = $null
	                if ($ObjectTypeGuid -and (-not $NoResolveGUIDs)) {
	                    $ObjectTypeName = Get-ExtendedRightName -GUID $ObjectTypeGuid
	                }
	                if ($ObjectTypeName -and ($RightsArray -contains 'ExtendedRight')) {
	                    $RightsArray = $RightsArray | Where-Object { $_ -ne 'ExtendedRight' }
	                    $RightsArray += $ObjectTypeName
	                }
	                $InheritedObjectTypeGuid = if ($ACE.InheritedObjectType -and $ACE.InheritedObjectType -ne [System.Guid]::Empty) {
	                    $ACE.InheritedObjectType.ToString()
	                } else { $null }
	                $ACEObj = [PSCustomObject]@{
	                    AccessControlType    = $ACE.AccessControlType.ToString()
	                    Trustee              = $TrusteeName
	                    TrusteeSID           = $TrusteeSID
	                    Rights               = ($RightsArray -join ', ')
	                    RightsRaw            = $RightsArray
	                    ObjectType           = $ObjectTypeGuid
	                    ObjectTypeName       = $ObjectTypeName
	                    InheritedObjectType  = $InheritedObjectTypeGuid
	                    IsInherited          = $ACE.IsInherited
	                    InheritanceFlags     = $ACE.InheritanceFlags.ToString()
	                    PropagationFlags     = $ACE.PropagationFlags.ToString()
	                }
	                $ACEList += $ACEObj
	            }
	            $parsedSD = [PSCustomObject]@{
	                Owner    = $OwnerName
	                OwnerSID = $OwnerSID
	                ACEs     = $ACEList
	            }
	        }
	        else {
	            Write-Warning "[Get-ObjectACL] Unknown nTSecurityDescriptor format for: $targetDN (Type: $($securityDescriptor.GetType().FullName))"
	            return $null
	        }
	        $filteredACEs = $parsedSD.ACEs
	        if ($AllowOnly) {
	            $filteredACEs = $filteredACEs | Where-Object { $_.AccessControlType -eq 'Allow' }
	        }
	        if ($DenyOnly) {
	            $filteredACEs = $filteredACEs | Where-Object { $_.AccessControlType -eq 'Deny' }
	        }
	        if ($ExplicitOnly) {
	            $filteredACEs = $filteredACEs | Where-Object { $_.IsInherited -eq $false }
	        }
	        if ($Trustee) {
	            $filteredACEs = $filteredACEs | Where-Object {
	                $ace = $_
	                $matchFound = $false
	                foreach ($t in $Trustee) {
	                    if ($ace.Trustee -like $t -or $ace.TrusteeSID -like $t) {
	                        $matchFound = $true
	                        break
	                    }
	                }
	                $matchFound
	            }
	        }
	        if ($ExcludeTrustee) {
	            $filteredACEs = $filteredACEs | Where-Object {
	                $ace = $_
	                $excluded = $false
	                foreach ($t in $ExcludeTrustee) {
	                    if ($ace.Trustee -like $t -or $ace.TrusteeSID -like $t) {
	                        $excluded = $true
	                        break
	                    }
	                }
	                -not $excluded
	            }
	        }
	        if ($DangerousOnly) {
	            $filteredACEs = $filteredACEs | Where-Object {
	                $ace = $_
	                $hasDangerous = $false
	                foreach ($right in $ace.RightsRaw) {
	                    if ($Script:DangerousRights -contains $right) {
	                        $hasDangerous = $true
	                        break
	                    }
	                    if ($right -match 'DS-Replication|Force-Change-Password|All-Extended-Rights') {
	                        $hasDangerous = $true
	                        break
	                    }
	                }
	                $hasDangerous
	            }
	        }
	        if ($WriteOnly) {
	            $filteredACEs = $filteredACEs | Where-Object {
	                $ace = $_
	                $hasWrite = $false
	                foreach ($right in $ace.RightsRaw) {
	                    if ($Script:WriteRights -contains $right) {
	                        $hasWrite = $true
	                        break
	                    }
	                }
	                $hasWrite
	            }
	        }
	        if ($ExtendedRightsOnly) {
	            $filteredACEs = $filteredACEs | Where-Object {
	                ($_.RightsRaw -contains 'ExtendedRight') -or ($null -ne $_.ObjectTypeName)
	            }
	        }
	        if ($Rights) {
	            $filteredACEs = $filteredACEs | Where-Object {
	                $ace = $_
	                $hasRight = $false
	                foreach ($right in $Rights) {
	                    if ($ace.RightsRaw -contains $right) {
	                        $hasRight = $true
	                        break
	                    }
	                }
	                $hasRight
	            }
	        }
	        if ($ExtendedRight) {
	            $filteredACEs = $filteredACEs | Where-Object {
	                $ace = $_
	                $hasExtRight = $false
	                foreach ($extRight in $ExtendedRight) {
	                    if ($ace.ObjectTypeName -like $extRight -or $ace.RightsRaw -contains $extRight) {
	                        $hasExtRight = $true
	                        break
	                    }
	                }
	                $hasExtRight
	            }
	        }
	        $result = [PSCustomObject]@{
	            ObjectDN    = $targetDN
	            ObjectClass = if ($targetObject.objectClass) {
	                if ($targetObject.objectClass -is [array]) { $targetObject.objectClass[-1] }
	                else { $targetObject.objectClass }
	            } else { "Unknown" }
	            Owner       = $parsedSD.Owner
	            OwnerSID    = $parsedSD.OwnerSID
	            ACECount    = @($filteredACEs).Count
	            ACEs        = @($filteredACEs)
	        }
	        return $result
	    } catch {
	        Write-Error "[Get-ObjectACL] Failed to get ACL for object: $_"
	        return $null
	    }
	}
	end {
	}
}
function Set-DomainObject {
	[CmdletBinding(DefaultParameterSetName='SetAttributes')]
	param(
	    [Parameter(Mandatory=$true, Position=0, ValueFromPipeline=$true, ValueFromPipelineByPropertyName=$true)]
	    [Alias('distinguishedName', 'Name', 'sAMAccountName')]
	    [string]$Identity,
	    [Parameter(Mandatory=$false, ParameterSetName='SetAttributes')]
	    [hashtable]$Set,
	    [Parameter(Mandatory=$false, ParameterSetName='SetAttributes')]
	    [hashtable]$Append,
	    [Parameter(Mandatory=$false, ParameterSetName='SetAttributes')]
	    [hashtable]$Remove,
	    [Parameter(Mandatory=$false, ParameterSetName='SetAttributes')]
	    [string[]]$Clear,
	    [Parameter(Mandatory=$true, ParameterSetName='GrantACE')]
	    [switch]$GrantACE,
	    [Parameter(Mandatory=$true, ParameterSetName='RevokeACE')]
	    [switch]$RevokeACE,
	    [Parameter(Mandatory=$true, ParameterSetName='DenyACE')]
	    [switch]$DenyACE,
	    [Parameter(Mandatory=$true, ParameterSetName='ClearACE')]
	    [switch]$ClearACE,
	    [Parameter(Mandatory=$true, ParameterSetName='SetOwner')]
	    [switch]$SetOwner,
	    [Parameter(Mandatory=$true, ParameterSetName='GrantACE')]
	    [Parameter(Mandatory=$true, ParameterSetName='RevokeACE')]
	    [Parameter(Mandatory=$true, ParameterSetName='DenyACE')]
	    [Parameter(Mandatory=$true, ParameterSetName='ClearACE')]
	    [Parameter(Mandatory=$true, ParameterSetName='SetOwner')]
	    [string]$Principal,
	    [Parameter(Mandatory=$false, ParameterSetName='GrantACE')]
	    [Parameter(Mandatory=$false, ParameterSetName='RevokeACE')]
	    [Parameter(Mandatory=$false, ParameterSetName='DenyACE')]
	    [ValidateSet(
	        'GenericAll', 'GenericRead', 'GenericWrite', 'GenericExecute',
	        'Delete', 'ReadControl', 'WriteDacl', 'WriteOwner',
	        'CreateChild', 'DeleteChild', 'ListChildren', 'Self',
	        'ReadProperty', 'WriteProperty', 'DeleteTree', 'ListObject',
	        'ExtendedRight', 'ControlAccess'
	    )]
	    [string]$Rights,
	    [Parameter(Mandatory=$false, ParameterSetName='GrantACE')]
	    [Parameter(Mandatory=$false, ParameterSetName='RevokeACE')]
	    [Parameter(Mandatory=$false, ParameterSetName='DenyACE')]
	    [ValidateSet(
	        'DCSync', 'ForceChangePassword', 'ResetPassword', 'AddMember',
	        'SendAs', 'ReceiveAs',
	        'ReadLAPSPassword',
	        'AutoEnroll', 'CertEnroll',
	        'AllowedToAuthenticate',
	        'ReplicateDirectory', 'InstallReplica', 'CloneDC',
	        'MigrateSIDHistory',
	        'ApplyGroupPolicy', 'CreateGPOLink',
	        'GenerateRSoPLogging', 'GenerateRSoPPlanning',
	        'ReanimateTombstones',
	        'SelfMembership',
	        'AllExtendedRights'
	    )]
	    [string]$ExtendedRight,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$PassThru,
	    [Parameter(Mandatory=$false)]
	    [string]$SearchBase
	)
	begin {
	    if ($PSCmdlet.ParameterSetName -in @('GrantACE', 'RevokeACE', 'DenyACE')) {
	        if (-not $Rights -and -not $ExtendedRight) {
	            throw "[Set-DomainObject] $($PSCmdlet.ParameterSetName) requires either -Rights or -ExtendedRight parameter"
	        }
	    }
	}
	process {
	    $ConnectionParams = @{}
	    if ($Domain) { $ConnectionParams['Domain'] = $Domain }
	    if ($Server) { $ConnectionParams['Server'] = $Server }
	    if ($Credential) { $ConnectionParams['Credential'] = $Credential }
	    if (-not (Ensure-LDAPConnection @ConnectionParams)) {
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = $PSCmdlet.ParameterSetName
	                Object = $Identity
	                Success = $false
	                Message = "No LDAP connection available"
	            }
	        }
	        return $false
	    }
	    try {
	        $Filter = "(objectClass=*)"
	        $crossDomainQuery = $false
	        $targetDomainDN = $null
	        $targetDomainFQDN = $null
	        if ($Identity) {
	            if ($Identity -match '^([^\\]+)\\(.+)$') {
	                $crossDomainInfo = Resolve-CrossDomainIdentity -Identity $Identity
	                $crossDomainQuery = $crossDomainInfo.IsCrossDomain
	                $targetDomainDN = $crossDomainInfo.TargetDomainDN
	                $targetDomainFQDN = $crossDomainInfo.TargetDomainFQDN
	                $Identity = $crossDomainInfo.Identity
	                if ($crossDomainQuery) {
	                }
	            }
	            if ($Identity -match '^S-1-5-.*') {
	                $SIDObj = New-Object System.Security.Principal.SecurityIdentifier($Identity)
	                $SIDBytes = New-Object byte[] $SIDObj.BinaryLength
	                $SIDObj.GetBinaryForm($SIDBytes, 0)
	                $SIDHex = ($SIDBytes | ForEach-Object { '\' + $_.ToString('X2') }) -join ''
	                $IdentityFilter = "(objectSid=$SIDHex)"
	            } elseif ($Identity -match '^CN=.*|^OU=.*|^DC=.*') {
	                $IdentityFilter = "(distinguishedName=$Identity)"
	            } elseif ($Identity -match '^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$') {
	                $GUIDObj = [System.Guid]::Parse($Identity)
	                $GUIDBytes = $GUIDObj.ToByteArray()
	                $GUIDHex = ($GUIDBytes | ForEach-Object { '\' + $_.ToString('X2') }) -join ''
	                $IdentityFilter = "(objectGUID=$GUIDHex)"
	            } else {
	                $IdentityFilter = "(|(sAMAccountName=$Identity)(cn=$Identity)(name=$Identity))"
	            }
	            $Filter = "(&$Filter$IdentityFilter)"
	        }
	        if ($PSCmdlet.ParameterSetName -ne 'SetAttributes') {
	            $SearchParams = @{
	                Filter = $Filter
	                Properties = @('distinguishedName', 'nTSecurityDescriptor')
	                SizeLimit = 10  # Increased for cross-domain (may return multiple before filtering)
	                Raw = $true
	            }
	            if ($crossDomainQuery) {
	                $gcConn = Get-GCConnection
	                if ($gcConn) {
	                    $SearchParams['LdapConnection'] = $gcConn
	                    $SearchParams['SearchBase'] = $targetDomainDN
	                } else {
	                }
	            } elseif ($SearchBase) {
	                $SearchParams['SearchBase'] = $SearchBase
	            }
	            $SearchResult = Invoke-LDAPSearch @SearchParams
	            if ($crossDomainQuery -and $targetDomainFQDN -and $SearchResult) {
	                $ResultArray = @($SearchResult)
	                $FilteredResults = @()
	                foreach ($res in $ResultArray) {
	                    if ($res.distinguishedName) {
	                        if (Test-DomainMatch -DistinguishedName $res.distinguishedName -TargetDomainFQDN $targetDomainFQDN) {
	                            $FilteredResults += $res
	                        }
	                    }
	                }
	                $SearchResult = $FilteredResults
	            }
	            $SearchResult = @($SearchResult)[0]
	            if (-not $SearchResult) {
	                Write-Error "[Set-DomainObject] Object not found: $Identity"
	                return $false
	            }
	            $ResultArray = @($SearchResult)
	            $ObjectDN = $ResultArray[0].distinguishedName
	            $PrincipalSID = $null
	            $ResolvedSIDString = ConvertTo-SID -Identity $Principal
	            if ($ResolvedSIDString) {
	                $PrincipalSID = New-Object System.Security.Principal.SecurityIdentifier($ResolvedSIDString)
	            } else {
	                Write-Error "[Set-DomainObject] Failed to resolve principal '$Principal' - ensure the identity exists in AD"
	                return $false
	            }
	            if (-not $ResultArray[0].nTSecurityDescriptor) {
	                Write-Error "[Set-DomainObject] Failed to retrieve Security Descriptor for: $ObjectDN"
	                return $false
	            }
	            $ACL = New-Object System.DirectoryServices.ActiveDirectorySecurity
	            $ACL.SetSecurityDescriptorBinaryForm($ResultArray[0].nTSecurityDescriptor)
	            $ACEsAdded = 0
	            $ACEsRemoved = 0
	            switch ($PSCmdlet.ParameterSetName) {
	                'GrantACE' {
	                    $ACEsAdded = Add-ACEToACL -ACL $ACL -PrincipalSID $PrincipalSID -Rights $Rights -ExtendedRight $ExtendedRight -AccessType 'Allow' -Operation 'Add'
	                }
	                'RevokeACE' {
	                    $ACEsRemoved = Add-ACEToACL -ACL $ACL -PrincipalSID $PrincipalSID -Rights $Rights -ExtendedRight $ExtendedRight -AccessType 'Allow' -Operation 'Remove'
	                }
	                'DenyACE' {
	                    $ACEsAdded = Add-ACEToACL -ACL $ACL -PrincipalSID $PrincipalSID -Rights $Rights -ExtendedRight $ExtendedRight -AccessType 'Deny' -Operation 'Add'
	                }
	                'ClearACE' {
	                    $ACEs = $ACL.GetAccessRules($true, $true, [System.Security.Principal.SecurityIdentifier])
	                    foreach ($ACE in $ACEs) {
	                        if ($ACE.IdentityReference -eq $PrincipalSID) {
	                            $removed = $ACL.RemoveAccessRule($ACE)
	                            if ($removed) {
	                                $ACEsRemoved++
	                            }
	                        }
	                    }
	                }
	                'SetOwner' {
	                    $ACL.SetOwner($PrincipalSID)
	                }
	            }
	            try {
	                $SDBytes = $ACL.GetSecurityDescriptorBinaryForm()
	                $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                $ModifyRequest.DistinguishedName = $ObjectDN
	                $SDModification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                $SDModification.Name = "nTSecurityDescriptor"
	                $SDModification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                $SDModification.Add($SDBytes) | Out-Null
	                $ModifyRequest.Modifications.Add($SDModification) | Out-Null
	                $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                if ($Response.ResultCode -eq [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                    $OperationMsg = switch ($PSCmdlet.ParameterSetName) {
	                        'GrantACE'  { "Granted $ACEsAdded ACE(s) on object: $ObjectDN" }
	                        'RevokeACE' { "Revoked $ACEsRemoved ACE(s) from object: $ObjectDN" }
	                        'DenyACE'   { "Added $ACEsAdded Deny ACE(s) on object: $ObjectDN" }
	                        'ClearACE'  { "Removed $ACEsRemoved ACE(s) for principal '$Principal' on object: $ObjectDN" }
	                        'SetOwner'  { "Changed owner to '$Principal' on object: $ObjectDN" }
	                    }
	                    if ($PassThru) {
	                        return [PSCustomObject]@{
	                            Operation = $PSCmdlet.ParameterSetName
	                            Object = $ObjectDN
	                            Principal = $Principal
	                            ACEsAdded = $ACEsAdded
	                            ACEsRemoved = $ACEsRemoved
	                            Success = $true
	                            Message = $OperationMsg
	                        }
	                    } else {
	                        Show-Line $OperationMsg -Class Hint
	                    }
	                    return $true
	                } else {
	                    if ($PassThru) {
	                        return [PSCustomObject]@{
	                            Operation = $PSCmdlet.ParameterSetName
	                            Object = $ObjectDN
	                            Success = $false
	                            Message = "ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                    }
	                    return $false
	                }
	            } catch {
	                if ($PassThru) {
	                    return [PSCustomObject]@{
	                        Operation = $PSCmdlet.ParameterSetName
	                        Object = $ObjectDN
	                        Success = $false
	                        Message = $_.Exception.Message
	                    }
	                }
	                return $false
	            }
	        }
	        $SearchParams = @{
	            Filter = $Filter
	            Properties = @('distinguishedName')
	            SizeLimit = 10  # Increased for cross-domain (may return multiple before filtering)
	        }
	        if ($crossDomainQuery) {
	            $gcConn = Get-GCConnection
	            if ($gcConn) {
	                $SearchParams['LdapConnection'] = $gcConn
	                $SearchParams['SearchBase'] = $targetDomainDN
	            } else {
	            }
	        } elseif ($SearchBase) {
	            $SearchParams['SearchBase'] = $SearchBase
	        }
	        $SearchResult = Invoke-LDAPSearch @SearchParams
	        if ($crossDomainQuery -and $targetDomainFQDN -and $SearchResult) {
	            $ResultArray = @($SearchResult)
	            $FilteredResults = @()
	            foreach ($res in $ResultArray) {
	                if ($res.distinguishedName) {
	                    if (Test-DomainMatch -DistinguishedName $res.distinguishedName -TargetDomainFQDN $targetDomainFQDN) {
	                        $FilteredResults += $res
	                    }
	                }
	            }
	            $SearchResult = $FilteredResults
	        }
	        $SearchResult = @($SearchResult)[0]
	        if (-not $SearchResult) {
	            Write-Error "[Set-DomainObject] Object not found: $Identity"
	            return $false
	        }
	        $ResultArray = @($SearchResult)
	        $ObjectDN = $ResultArray[0].distinguishedName
	        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	        $ModifyRequest.DistinguishedName = $ObjectDN
	        $ModificationsAdded = $false
	        if ($Set -and $Set.Count -gt 0) {
	            foreach ($AttrName in $Set.Keys) {
	                $AttrValue = $Set[$AttrName]
	                try {
	                    $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                    $Modification.Name = $AttrName
	                    $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                    if ($AttrValue -is [array]) {
	                        foreach ($item in $AttrValue) {
	                            $Modification.Add($item) | Out-Null
	                        }
	                    } else {
	                        $Modification.Add($AttrValue) | Out-Null
	                    }
	                    $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                    $ModificationsAdded = $true
	                } catch {
	                    Write-Warning "[Set-DomainObject] Failed to prepare SET for ${AttrName}: $_"
	                }
	            }
	        }
	        if ($Append -and $Append.Count -gt 0) {
	            foreach ($AttrName in $Append.Keys) {
	                $AttrValue = $Append[$AttrName]
	                try {
	                    $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                    $Modification.Name = $AttrName
	                    $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Add
	                    if ($AttrValue -is [array]) {
	                        foreach ($item in $AttrValue) {
	                            $Modification.Add($item) | Out-Null
	                        }
	                    } else {
	                        $Modification.Add($AttrValue) | Out-Null
	                    }
	                    $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                    $ModificationsAdded = $true
	                } catch {
	                    Write-Warning "[Set-DomainObject] Failed to prepare APPEND for ${AttrName}: $_"
	                }
	            }
	        }
	        if ($Remove -and $Remove.Count -gt 0) {
	            foreach ($AttrName in $Remove.Keys) {
	                $AttrValue = $Remove[$AttrName]
	                try {
	                    $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                    $Modification.Name = $AttrName
	                    $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	                    if ($AttrValue -is [array]) {
	                        foreach ($item in $AttrValue) {
	                            $Modification.Add($item) | Out-Null
	                        }
	                    } else {
	                        $Modification.Add($AttrValue) | Out-Null
	                    }
	                    $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                    $ModificationsAdded = $true
	                } catch {
	                    Write-Warning "[Set-DomainObject] Failed to prepare REMOVE for ${AttrName}: $_"
	                }
	            }
	        }
	        if ($Clear -and $Clear.Count -gt 0) {
	            foreach ($AttrName in $Clear) {
	                try {
	                    $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                    $Modification.Name = $AttrName
	                    $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	                    $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                    $ModificationsAdded = $true
	                } catch {
	                    Write-Warning "[Set-DomainObject] Failed to prepare CLEAR for ${AttrName}: $_"
	                }
	            }
	        }
	        if ($ModificationsAdded) {
	            try {
	                $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                if ($Response.ResultCode -eq [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                    if ($PassThru) {
	                        return [PSCustomObject]@{
	                            Operation = "SetAttributes"
	                            Object = $ObjectDN
	                            Success = $true
	                            Message = "Attributes successfully modified"
	                        }
	                    }
	                    return $true
	                } else {
	                    Write-Error "[Set-DomainObject] ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                    if ($PassThru) {
	                        return [PSCustomObject]@{
	                            Operation = "SetAttributes"
	                            Object = $ObjectDN
	                            Success = $false
	                            Message = "ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                    }
	                    return $false
	                }
	            } catch {
	                Write-Error "[Set-DomainObject] Failed to commit changes: $_"
	                if ($PassThru) {
	                    return [PSCustomObject]@{
	                        Operation = "SetAttributes"
	                        Object = $ObjectDN
	                        Success = $false
	                        Message = $_.Exception.Message
	                    }
	                }
	                return $false
	            }
	        } else {
	            if ($PassThru) {
	                return [PSCustomObject]@{
	                    Operation = "SetAttributes"
	                    Object = $ObjectDN
	                    Success = $true
	                    NoOp = $true
	                    Message = "No modifications specified"
	                }
	            }
	            Show-Line "No modifications specified for object: $ObjectDN" -Class Note
	            return $true
	        }
	    } catch {
	        Write-Error "[Set-DomainObject] Error: $_"
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = $PSCmdlet.ParameterSetName
	                Object = $Identity
	                Success = $false
	                Message = $_.Exception.Message
	            }
	        }
	        return $false
	    }
	}
	end {
	}
}
function Add-ACEToACL {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [System.DirectoryServices.ActiveDirectorySecurity]$ACL,
	    [Parameter(Mandatory=$true)]
	    [System.Security.Principal.SecurityIdentifier]$PrincipalSID,
	    [Parameter(Mandatory=$false)]
	    [string]$Rights,
	    [Parameter(Mandatory=$false)]
	    [string]$ExtendedRight,
	    [Parameter(Mandatory=$true)]
	    [ValidateSet('Allow', 'Deny')]
	    [string]$AccessType,
	    [Parameter(Mandatory=$true)]
	    [ValidateSet('Add', 'Remove')]
	    [string]$Operation
	)
	$ACECount = 0
	$AccessControlType = [System.Security.AccessControl.AccessControlType]::$AccessType
	if ($ExtendedRight) {
	    $ReadPropertyGUID = $Script:ReadPropertyAliases[$ExtendedRight]
	    if ($ReadPropertyGUID) {
	        $ObjectType = New-Object Guid($ReadPropertyGUID)
	        $ACE = New-Object System.DirectoryServices.ActiveDirectoryAccessRule(
	            $PrincipalSID,
	            [System.DirectoryServices.ActiveDirectoryRights]::ReadProperty,
	            $AccessControlType,
	            $ObjectType,
	            [System.DirectoryServices.ActiveDirectorySecurityInheritance]::None
	        )
	        if ($Operation -eq 'Add') {
	            $ACL.AddAccessRule($ACE)
	            $ACECount++
	        } else {
	            $removed = $ACL.RemoveAccessRule($ACE)
	            if ($removed) {
	                $ACECount++
	            } else {
	            }
	        }
	    }
	    elseif (($WritePropertyGUID = $Script:WritePropertyAliases[$ExtendedRight])) {
	        $ObjectType = New-Object Guid($WritePropertyGUID)
	        $ACE = New-Object System.DirectoryServices.ActiveDirectoryAccessRule(
	            $PrincipalSID,
	            [System.DirectoryServices.ActiveDirectoryRights]::WriteProperty,
	            $AccessControlType,
	            $ObjectType,
	            [System.DirectoryServices.ActiveDirectorySecurityInheritance]::None
	        )
	        if ($Operation -eq 'Add') {
	            $ACL.AddAccessRule($ACE)
	            $ACECount++
	        } else {
	            $removed = $ACL.RemoveAccessRule($ACE)
	            if ($removed) {
	                $ACECount++
	            } else {
	            }
	        }
	    } else {
	        $GUIDs = $Script:ExtendedRightsAliases[$ExtendedRight]
	        if (-not $GUIDs) {
	            Write-Error "[Add-ACEToACL] Unknown ExtendedRight alias: $ExtendedRight"
	            return 0
	        }
	        $GUIDList = if ($GUIDs -is [array]) { $GUIDs } else { @($GUIDs) }
	        foreach ($GUID in $GUIDList) {
	            $ObjectType = New-Object Guid($GUID)
	            $ACE = New-Object System.DirectoryServices.ActiveDirectoryAccessRule(
	                $PrincipalSID,
	                [System.DirectoryServices.ActiveDirectoryRights]::ExtendedRight,
	                $AccessControlType,
	                $ObjectType,
	                [System.DirectoryServices.ActiveDirectorySecurityInheritance]::None
	            )
	            if ($Operation -eq 'Add') {
	                $ACL.AddAccessRule($ACE)
	                $ACECount++
	            } else {
	                $removed = $ACL.RemoveAccessRule($ACE)
	                if ($removed) {
	                    $ACECount++
	                } else {
	                }
	            }
	        }
	    }
	} elseif ($Rights) {
	    $ADRights = [System.DirectoryServices.ActiveDirectoryRights]::$Rights
	    $ACE = New-Object System.DirectoryServices.ActiveDirectoryAccessRule(
	        $PrincipalSID,
	        $ADRights,
	        $AccessControlType
	    )
	    if ($Operation -eq 'Add') {
	        $ACL.AddAccessRule($ACE)
	        $ACECount++
	    } else {
	        $removed = $ACL.RemoveAccessRule($ACE)
	        if ($removed) {
	            $ACECount++
	        } else {
	        }
	    }
	}
	return $ACECount
}
function Get-DomainUser {
	[CmdletBinding(DefaultParameterSetName='Default')]
	param(
	    [Parameter(Position=0, ValueFromPipeline=$true, ValueFromPipelineByPropertyName=$true)]
	    [Alias('samAccountName', 'Name', 'User')]
	    [string]$Identity,
	    [Parameter(Mandatory=$false)]
	    [switch]$SPN,
	    [Parameter(Mandatory=$false)]
	    [switch]$AdminCount,
	    [Parameter(Mandatory=$false)]
	    [switch]$Unconstrained,
	    [Parameter(Mandatory=$false)]
	    [switch]$Constrained,
	    [Parameter(Mandatory=$false)]
	    [switch]$RBCD,
	    [Parameter(Mandatory=$false)]
	    [switch]$TrustedToAuth,
	    [Parameter(Mandatory=$false)]
	    [switch]$DisallowDelegation,
	    [Parameter(Mandatory=$false)]
	    [switch]$PreauthNotRequired,
	    [Parameter(Mandatory=$false)]
	    [switch]$PasswordNotRequired,
	    [Parameter(Mandatory=$false)]
	    [switch]$PasswordNeverExpires,
	    [Parameter(Mandatory=$false)]
	    [switch]$PasswordMustChange,
	    [Parameter(Mandatory=$false)]
	    [switch]$Enabled,
	    [Parameter(Mandatory=$false)]
	    [switch]$Disabled,
	    [Parameter(Mandatory=$false)]
	    [switch]$LockedOut,
	    [Parameter(Mandatory=$false)]
	    [switch]$SmartcardRequired,
	    [Parameter(Mandatory=$false)]
	    [switch]$AccountExpired,
	    [Parameter(Mandatory=$false)]
	    [switch]$AccountNeverExpires,
	    [Parameter(Mandatory=$false)]
	    [switch]$DESOnly,
	    [Parameter(Mandatory=$false)]
	    [switch]$ReversibleEncryption,
	    [Parameter(ParameterSetName='GMSA')]
	    [switch]$GMSA,
	    [Parameter(Mandatory=$false)]
	    [switch]$ShowGMSADetails,
	    [Parameter(Mandatory=$false)]
	    [string]$LDAPFilter,
	    [Parameter(Mandatory=$false)]
	    [string[]]$Properties,
	    [Parameter(Mandatory=$false)]
	    [switch]$ShowOwner,
	    [Parameter(Mandatory=$false)]
	    [string]$SearchBase,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$Raw,
	    [Parameter(Mandatory=$false)]
	    [int]$ResultLimit = 0
	)
	begin {
	    if ($ShowGMSADetails -and -not $GMSA) {
	    }
	}
	process {
	    try {
	        if ($GMSA) {
	            $Filter = "(|(objectClass=msDS-ManagedServiceAccount)(objectClass=msDS-GroupManagedServiceAccount))"
	        } else {
	            $Filter = "(&(objectCategory=person)(objectClass=user)(!(objectClass=computer)))"
	        }
	        if ($Unconstrained) {
	            $Filter = "(&$Filter(userAccountControl:1.2.840.113556.1.4.803:=524288))"
	        }
	        if ($Constrained) {
	            $Filter = "(&$Filter(msDS-AllowedToDelegateTo=*))"
	        }
	        if ($RBCD) {
	            $Filter = "(&$Filter(msDS-AllowedToActOnBehalfOfOtherIdentity=*))"
	        }
	        if ($LDAPFilter) {
	            $Filter = "(&$Filter$LDAPFilter)"
	        }
	        $GetParams = @{
	            LDAPFilter = $Filter
	        }
	        if ($ShowGMSADetails -and $GMSA) {
	            if ($Properties) {
	                $MSAProperties = @(
	                    'msds-hostserviceaccountbl',
	                    'pwdlastset',
	                    'msds-managedpasswordinterval',
	                    'msds-groupmsamembership',
	                    'msds-managedpasswordid',
	                    'msds-managedpasswordpreviousid',
	                    'principalsallowedtoretrievemanagedpassword',
	                    'serviceprincipalname',
	                    'objectclass'
	                )
	                $GetParams['Properties'] = $Properties + $MSAProperties | Select-Object -Unique
	            }
	        } elseif ($Properties) {
	            $GetParams['Properties'] = $Properties
	        }
	        if ($Identity) {
	            $GetParams['Identity'] = $Identity
	        }
	        if ($ShowOwner) { $GetParams['ShowOwner'] = $true }
	        if ($SearchBase) { $GetParams['SearchBase'] = $SearchBase }
	        if ($Domain) { $GetParams['Domain'] = $Domain }
	        if ($Server) { $GetParams['Server'] = $Server }
	        if ($Credential) { $GetParams['Credential'] = $Credential }
	        if ($Raw) { $GetParams['Raw'] = $true }
	        if ($Enabled) { $GetParams['IsEnabled'] = $true }
	        if ($Disabled) { $GetParams['IsDisabled'] = $true }
	        if ($PasswordNeverExpires) { $GetParams['PasswordNeverExpires'] = $true }
	        if ($PasswordNotRequired) { $GetParams['PasswordNotRequired'] = $true }
	        if ($PasswordMustChange) { $GetParams['PasswordMustChange'] = $true }
	        if ($SPN) { $GetParams['HasSPN'] = $true }
	        if ($AdminCount) { $GetParams['AdminCount'] = $true }
	        if ($TrustedToAuth) { $GetParams['TrustedToAuthForDelegation'] = $true }
	        if ($DisallowDelegation) { $GetParams['NotDelegated'] = $true }
	        if ($PreauthNotRequired) { $GetParams['PreauthNotRequired'] = $true }
	        if ($LockedOut) { $GetParams['LockedOut'] = $true }
	        if ($SmartcardRequired) { $GetParams['SmartcardRequired'] = $true }
	        if ($AccountExpired) { $GetParams['AccountExpired'] = $true }
	        if ($AccountNeverExpires) { $GetParams['AccountNeverExpires'] = $true }
	        if ($DESOnly) { $GetParams['DESOnly'] = $true }
	        if ($ReversibleEncryption) { $GetParams['ReversibleEncryption'] = $true }
	        if ($ResultLimit -gt 0) { $GetParams['ResultLimit'] = $ResultLimit }
	        $Users = @(Get-DomainObject @GetParams)
	        if ($ShowGMSADetails -and $GMSA -and $Users.Count -gt 0) {
	            foreach ($User in $Users) {
	                if ($User.'msds-groupmsamembership') {
	                    $AllowedPrincipals = @()
	                    try {
	                        $SD = New-Object System.DirectoryServices.ActiveDirectorySecurity
	                        $SD.SetSecurityDescriptorBinaryForm($User.'msds-groupmsamembership')
	                        $DACL = $SD.GetAccessRules($true, $true, [System.Security.Principal.SecurityIdentifier])
	                        foreach ($ACE in $DACL) {
	                            if ($ACE.AccessControlType -eq 'Allow') {
	                                $TrusteeSID = $ACE.IdentityReference.Value
	                                $PrincipalName = ConvertFrom-SID -SID $TrusteeSID
	                                if (-not $PrincipalName) {
	                                    $PrincipalName = $TrusteeSID
	                                }
	                                $AllowedPrincipals += [PSCustomObject]@{
	                                    Name = $PrincipalName
	                                    SID = $TrusteeSID
	                                    DisplayText = $PrincipalName
	                                }
	                            }
	                        }
	                        $User.'msds-groupmsamembership' = $AllowedPrincipals
	                    } catch {
	                    }
	                }
	                if ($User.'msds-managedpasswordid') {
	                    try {
	                        $PasswordIdBytes = $User.'msds-managedpasswordid'
	                        if ($PasswordIdBytes.Length -ge 16) {
	                            $GuidBytes = [byte[]]::new(16)
	                            [Array]::Copy($PasswordIdBytes, 0, $GuidBytes, 0, 16)
	                            $KeyGUID = [GUID]::new($GuidBytes)
	                            $TimeString = ""
	                            if ($PasswordIdBytes.Length -ge 24) {
	                                $FileTimeBytes = [byte[]]::new(8)
	                                [Array]::Copy($PasswordIdBytes, 16, $FileTimeBytes, 0, 8)
	                                $FileTime = [BitConverter]::ToInt64($FileTimeBytes, 0)
	                                if ($FileTime -ge 119600064000000000 -and $FileTime -lt 2650467743990000000) {
	                                    try {
	                                        $PasswordCreationTime = [DateTime]::FromFileTime($FileTime)
	                                        $TimeString = ", Created: $PasswordCreationTime"
	                                    } catch {}
	                                }
	                            }
	                            $User.'msds-managedpasswordid' = "Key GUID: $($KeyGUID.ToString())$TimeString"
	                        }
	                    } catch {
	                    }
	                }
	                if ($User.'msds-managedpasswordpreviousid') {
	                    try {
	                        $PrevPasswordIdBytes = $User.'msds-managedpasswordpreviousid'
	                        if ($PrevPasswordIdBytes.Length -ge 16) {
	                            $GuidBytes = [byte[]]::new(16)
	                            [Array]::Copy($PrevPasswordIdBytes, 0, $GuidBytes, 0, 16)
	                            $KeyGUID = [GUID]::new($GuidBytes)
	                            $TimeString = ""
	                            if ($PrevPasswordIdBytes.Length -ge 24) {
	                                $FileTimeBytes = [byte[]]::new(8)
	                                [Array]::Copy($PrevPasswordIdBytes, 16, $FileTimeBytes, 0, 8)
	                                $FileTime = [BitConverter]::ToInt64($FileTimeBytes, 0)
	                                if ($FileTime -ge 119600064000000000 -and $FileTime -lt 2650467743990000000) {
	                                    try {
	                                        $PrevPasswordCreationTime = [DateTime]::FromFileTime($FileTime)
	                                        $TimeString = ", Created: $PrevPasswordCreationTime"
	                                    } catch {}
	                                }
	                            }
	                            $User.'msds-managedpasswordpreviousid' = "Key GUID: $($KeyGUID.ToString())$TimeString"
	                        }
	                    } catch {
	                    }
	                }
	            }
	        }
	        return $Users
	    } catch {
	        throw
	    }
	}
	end {
	}
}
function Get-DomainComputer {
	[CmdletBinding()]
	param(
	    [Parameter(Position=0, ValueFromPipeline=$true, ValueFromPipelineByPropertyName=$true)]
	    [Alias('samAccountName', 'Name', 'Computer', 'DNSHostName')]
	    [string]$Identity,
	    [Parameter(Mandatory=$false)]
	    [string]$OperatingSystem,
	    [Parameter(Mandatory=$false)]
	    [switch]$SPN,
	    [Parameter(Mandatory=$false)]
	    [switch]$Unconstrained,
	    [Parameter(Mandatory=$false)]
	    [switch]$Constrained,
	    [Parameter(Mandatory=$false)]
	    [switch]$RBCD,
	    [Parameter(Mandatory=$false)]
	    [switch]$TrustedToAuth,
	    [Parameter(Mandatory=$false)]
	    [switch]$LAPS,
	    [Parameter(Mandatory=$false)]
	    [switch]$Enabled,
	    [Parameter(Mandatory=$false)]
	    [switch]$Disabled,
	    [Parameter(Mandatory=$false)]
	    [switch]$HighValueSPN,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('MSSQL', 'Exchange', 'SCCM', 'WSUS', 'ADFS', 'CA', 'SCOM', 'Backup', 'HyperV', 'RDP', 'WinRM', 'HTTP', 'FTP')]
	    [string]$KnownSPN,
	    [Parameter(Mandatory=$false)]
	    [string]$LDAPFilter,
	    [Parameter(Mandatory=$false)]
	    [string[]]$Properties,
	    [Parameter(Mandatory=$false)]
	    [switch]$ShowOwner,
	    [Parameter(Mandatory=$false)]
	    [string]$SearchBase,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$Raw,
	    [Parameter(Mandatory=$false)]
	    [int]$ResultLimit = 0
	)
	begin {
	}
	process {
	    try {
	        $Filter = "(&(objectCategory=computer)(objectClass=computer))"
	        if ($OperatingSystem) {
	            $Filter = "(&$Filter(operatingSystem=$OperatingSystem))"
	        }
	        if ($Unconstrained) {
	            $Filter = "(&$Filter(userAccountControl:1.2.840.113556.1.4.803:=524288)(!(primaryGroupID=516)))"
	        }
	        if ($Constrained) {
	            $Filter = "(&$Filter(msDS-AllowedToDelegateTo=*))"
	        }
	        if ($RBCD) {
	            $Filter = "(&$Filter(msDS-AllowedToActOnBehalfOfOtherIdentity=*))"
	        }
	        if ($LAPS) {
	            $Filter = "(&$Filter(|(ms-Mcs-AdmPwdExpirationTime=*)(msLAPS-PasswordExpirationTime=*)))"
	        }
	        if ($HighValueSPN) {
	            $HighValueSPNFilter = "(|" +
	                "(servicePrincipalName=MSSQLSvc/*)" +           # SQL Server
	                "(&(|(servicePrincipalName=exchangeMDB/*)(servicePrincipalName=exchangeRFR/*)(servicePrincipalName=exchangeAB/*))(!(primaryGroupID=516)))" +  # Exchange (exclude DCs)
	                "(servicePrincipalName=SMS Site Server/*)" +    # SCCM/MECM
	                "(servicePrincipalName=CmRcService/*)" +        # SCCM Remote Control
	                "(servicePrincipalName=adfssrv/*)" +            # ADFS
	                "(servicePrincipalName=certsvc/*)" +            # Certificate Authority
	                "(servicePrincipalName=MSOMHSvc/*)" +           # SCOM
	                "(servicePrincipalName=MSOMSdkSvc/*)" +         # SCOM SDK
	                "(servicePrincipalName=wbengine/*)" +           # Windows Backup
	                "(servicePrincipalName=veeam*)" +               # Veeam Backup
	                "(servicePrincipalName=wsusService/*)" +        # WSUS
	                ")"
	            $Filter = "(&$Filter$HighValueSPNFilter)"
	        }
	        if ($KnownSPN) {
	            $SPNFilter = switch ($KnownSPN) {
	                'MSSQL'    { "(servicePrincipalName=MSSQLSvc/*)" }
	                'Exchange' { "(&(|(servicePrincipalName=exchangeMDB/*)(servicePrincipalName=exchangeRFR/*)(servicePrincipalName=exchangeAB/*))(!(primaryGroupID=516)))" }
	                'SCCM'     { "(|(servicePrincipalName=SMS Site Server/*)(servicePrincipalName=CmRcService/*))" }
	                'WSUS'     { "(|(servicePrincipalName=wsusService/*)(servicePrincipalName=WSUS/*))" }
	                'ADFS'     { "(servicePrincipalName=adfssrv/*)" }
	                'CA'       { "(servicePrincipalName=certsvc/*)" }
	                'SCOM'     { "(|(servicePrincipalName=MSOMHSvc/*)(servicePrincipalName=MSOMSdkSvc/*))" }
	                'Backup'   { "(|(servicePrincipalName=wbengine/*)(servicePrincipalName=veeam*))" }
	                'HyperV'   { "(|(servicePrincipalName=Microsoft Virtual Console Service/*)(servicePrincipalName=vmms/*))" }
	                'RDP'      { "(servicePrincipalName=TERMSRV/*)" }
	                'WinRM'    { "(servicePrincipalName=WSMAN/*)" }
	                'HTTP'     { "(servicePrincipalName=HTTP/*)" }
	                'FTP'      { "(servicePrincipalName=FTP/*)" }
	            }
	            $Filter = "(&$Filter$SPNFilter)"
	        }
	        if ($LDAPFilter) {
	            $Filter = "(&$Filter$LDAPFilter)"
	        }
	        $GetParams = @{
	            LDAPFilter = $Filter
	        }
	        if ($Identity) {
	            $GetParams['Identity'] = $Identity
	        }
	        if ($Properties) { $GetParams['Properties'] = $Properties }
	        if ($ShowOwner) { $GetParams['ShowOwner'] = $true }
	        if ($SearchBase) { $GetParams['SearchBase'] = $SearchBase }
	        if ($Domain) { $GetParams['Domain'] = $Domain }
	        if ($Server) { $GetParams['Server'] = $Server }
	        if ($Credential) { $GetParams['Credential'] = $Credential }
	        if ($Raw) { $GetParams['Raw'] = $true }
	        if ($Enabled) { $GetParams['IsEnabled'] = $true }
	        if ($Disabled) { $GetParams['IsDisabled'] = $true }
	        if ($SPN) { $GetParams['HasSPN'] = $true }
	        if ($TrustedToAuth) { $GetParams['TrustedToAuthForDelegation'] = $true }
	        if ($ResultLimit -gt 0) { $GetParams['ResultLimit'] = $ResultLimit }
	        $Computers = @(Get-DomainObject @GetParams)
	        return $Computers
	    } catch {
	        throw
	    }
	}
	end {
	}
}
function Get-DomainGroup {
	[CmdletBinding(DefaultParameterSetName='Default')]
	param(
	    [Parameter(Position=0, ValueFromPipeline=$true, ValueFromPipelineByPropertyName=$true)]
	    [Alias('samAccountName', 'Name', 'Group')]
	    [string]$Identity,
	    [Parameter(Mandatory=$false)]
	    [switch]$AdminCount,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('DomainLocal','Global','Universal')]
	    [string]$GroupScope,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('Security','Distribution')]
	    [string]$GroupCategory,
	    [Parameter(Mandatory=$false)]
	    [string]$LDAPFilter,
	    [Parameter(Mandatory=$false)]
	    [string[]]$Properties,
	    [Parameter(Mandatory=$false)]
	    [switch]$ShowOwner,
	    [Parameter(Mandatory=$false)]
	    [switch]$ShowMembers,
	    [Parameter(Mandatory=$false)]
	    [string]$SearchBase,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$Raw
	)
	begin {
	}
	process {
	    try {
	        if ($ShowMembers -and -not $Identity) {
	            $ShowMembers = $false
	        }
	        $Filter = "(objectClass=group)"
	        if ($AdminCount) {
	            $Filter = "(&$Filter(adminCount=1))"
	        }
	        if ($GroupScope) {
	            switch ($GroupScope) {
	                'Global' {
	                    $Filter = "(&$Filter(groupType:1.2.840.113556.1.4.803:=2))"
	                }
	                'DomainLocal' {
	                    $Filter = "(&$Filter(groupType:1.2.840.113556.1.4.803:=4))"
	                }
	                'Universal' {
	                    $Filter = "(&$Filter(groupType:1.2.840.113556.1.4.803:=8))"
	                }
	            }
	        }
	        if ($GroupCategory) {
	            switch ($GroupCategory) {
	                'Security' {
	                    $Filter = "(&$Filter(groupType:1.2.840.113556.1.4.803:=2147483648))"
	                }
	                'Distribution' {
	                    $Filter = "(&$Filter(!(groupType:1.2.840.113556.1.4.803:=2147483648)))"
	                }
	            }
	        }
	        if ($LDAPFilter) {
	            $Filter = "(&$Filter$LDAPFilter)"
	        }
	        $GetParams = @{
	            LDAPFilter = $Filter
	        }
	        if ($Identity) {
	            $GetParams['Identity'] = $Identity
	        }
	        if ($Properties) { $GetParams['Properties'] = $Properties }
	        if ($ShowOwner) { $GetParams['ShowOwner'] = $true }
	        if ($SearchBase) { $GetParams['SearchBase'] = $SearchBase }
	        if ($Domain) { $GetParams['Domain'] = $Domain }
	        if ($Server) { $GetParams['Server'] = $Server }
	        if ($Credential) { $GetParams['Credential'] = $Credential }
	        if ($Raw) { $GetParams['Raw'] = $true }
	        $Groups = @(Get-DomainObject @GetParams)
	        if ($ShowMembers) {
	            foreach ($Group in $Groups) {
	                if ($Group.member) {
	                    return $Group.member
	                } else {
	                    return @()
	                }
	            }
	        }
	        return $Groups
	    } catch {
	        throw
	    }
	}
	end {
	}
}
function Get-DomainGPO {
	[CmdletBinding()]
	param(
	    [Parameter(Position=0, ValueFromPipeline=$true, ValueFromPipelineByPropertyName=$true)]
	    [Alias('DisplayName', 'Name', 'GPO')]
	    [string]$Identity,
	    [Parameter(Mandatory=$false)]
	    [Alias('LinkedOU')]
	    [string]$AppliedToOU,
	    [Parameter(Mandatory=$false)]
	    [switch]$Enabled,
	    [Parameter(Mandatory=$false)]
	    [switch]$Disabled,
	    [Parameter(Mandatory=$false)]
	    [string]$LDAPFilter,
	    [Parameter(Mandatory=$false)]
	    [string[]]$Properties,
	    [Parameter(Mandatory=$false)]
	    [switch]$ShowLinkedOU,
	    [Parameter(Mandatory=$false)]
	    [switch]$ShowDangerousSettings,
	    [Parameter(Mandatory=$false)]
	    [switch]$ShowPermissions,
	    [Parameter(Mandatory=$false)]
	    [string]$SearchBase,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$Raw
	)
	begin {
	}
	process {
	    try {
	        $isUnfilteredCall = -not $Identity -and -not $LDAPFilter -and -not $AppliedToOU -and -not $Enabled -and -not $Disabled -and -not $ShowLinkedOU -and -not $ShowDangerousSettings -and -not $ShowPermissions -and -not $Properties -and -not $SearchBase -and -not $Raw
	        if ($isUnfilteredCall -and $Script:CachedAllGPOs) {
	            return $Script:CachedAllGPOs
	        }
	        if ($ShowLinkedOU -and -not $Identity) {
	            $ShowLinkedOU = $false
	        }
	        $Filter = "(objectClass=groupPolicyContainer)"
	        if ($Identity) {
	            if ($Identity -match '^CN=.*') {
	                $IdentityFilter = "(distinguishedName=$Identity)"
	            } elseif ($Identity -match '^\{?[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}\}?$') {
	                $CleanGUID = $Identity.Trim('{}')
	                $IdentityFilter = "(name={$CleanGUID})"
	            } else {
	                $IdentityFilter = "(displayName=$Identity)"
	            }
	            $Filter = "(&$Filter$IdentityFilter)"
	        }
	        if ($Enabled) {
	            $Filter = "(&$Filter(flags=0))"
	        }
	        if ($Disabled) {
	            $Filter = "(&$Filter(flags=3))"
	        }
	        if ($AppliedToOU) {
	            $OUParams = @{
	                Identity = $AppliedToOU
	                Properties = @('gPLink')
	            }
	            $OU = Get-DomainObject @OUParams | Select-Object -First 1
	            if ($OU -and $OU.gPLink) {
	                $GPOGUIDs = @()
	                $gPLinkMatches = [regex]::Matches($OU.gPLink, '\{([0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12})\}')
	                foreach ($Match in $gPLinkMatches) {
	                    $GPOGUIDs += $Match.Groups[1].Value
	                }
	                if ($GPOGUIDs.Count -eq 0) {
	                    return
	                }
	                if ($GPOGUIDs.Count -eq 1) {
	                    $LinkedFilter = "(name={$($GPOGUIDs[0])})"
	                } else {
	                    $LinkedFilterParts = $GPOGUIDs | ForEach-Object { "(name={$_})" }
	                    $LinkedFilter = "(|$($LinkedFilterParts -join ''))"
	                }
	                $Filter = "(&$Filter$LinkedFilter)"
	            } else {
	                return
	            }
	        }
	        if ($LDAPFilter) {
	            $Filter = "(&$Filter$LDAPFilter)"
	        }
	        $GetParams = @{
	            LDAPFilter = $Filter
	        }
	        if ($Properties) {
	            $GetParams['Properties'] = $Properties
	        }
	        if ($SearchBase) { $GetParams['SearchBase'] = $SearchBase }
	        if ($Domain) { $GetParams['Domain'] = $Domain }
	        if ($Server) { $GetParams['Server'] = $Server }
	        if ($Credential) { $GetParams['Credential'] = $Credential }
	        if ($Raw) { $GetParams['Raw'] = $true }
	        $GPOs = @(Get-DomainObject @GetParams)
	        foreach ($GPO in $GPOs) {
	            if ($GPO.versionNumber) {
	                $VersionNum = [int]$GPO.versionNumber
	                $ComputerVersion = $VersionNum -shr 16
	                $UserVersion = $VersionNum -band 0xFFFF
	                $GPO | Add-Member -NotePropertyName "ComputerVersion" -NotePropertyValue $ComputerVersion -Force
	                $GPO | Add-Member -NotePropertyName "UserVersion" -NotePropertyValue $UserVersion -Force
	            }
	            if ($null -ne $GPO.flags) {
	                $FlagsValue = [int]$GPO.flags
	                $Status = switch ($FlagsValue) {
	                    0 { "Enabled" }
	                    1 { "User portion disabled" }
	                    2 { "Computer portion disabled" }
	                    3 { "All settings disabled" }
	                    default { "Unknown ($FlagsValue)" }
	                }
	                $GPO | Add-Member -NotePropertyName "GPOStatus" -NotePropertyValue $Status -Force
	            }
	            $CSENames = @{
	                '{00000000-0000-0000-0000-000000000000}' = 'Core GPO Engine'
	                '{0E28E245-9368-4853-AD84-6DA3BA35BB75}' = 'Group Policy Preference Client Side Extension'
	                '{16BE69FA-4209-4250-88CB-716CF41954E0}' = 'Central Access Policy Configuration'
	                '{17D89FEC-5C44-4972-B12D-241CAEF74509}' = 'Group Policy Local Users and Groups'
	                '{1A6364EB-776B-4120-ADE1-B63A406A76B5}' = 'Group Policy Device Settings'
	                '{25537BA6-77A8-11D2-9B6C-0000F8080861}' = 'Folder Redirection'
	                '{2EA1A81B-48E5-45E9-8BB7-A6E3AC170006}' = 'Group Policy Disk Quota'
	                '{3060E8D0-7020-11D2-842D-00C04FA372D4}' = 'Remote Installation Services'
	                '{35378EAC-683F-11D2-A89A-00C04FBBCFA2}' = 'Registry'
	                '{3610EDA5-77EF-11D2-8DC5-00C04FA31A66}' = 'Disk Quota'
	                '{3A0DBA37-F8B2-4356-83DE-3E90BD5C261F}' = 'Group Policy Network Options'
	                '{426031c0-0b47-4852-b0ca-ac3d37bfcb39}' = 'QoS Packet Scheduler'
	                '{42B5FAAE-6536-11D2-AE5A-0000F87571E3}' = 'Scripts'
	                '{4CFB60C1-FAA6-47f1-89AA-0B18730C9FD3}' = 'Internet Explorer Zonemapping'
	                '{5794DAFD-BE60-433f-88A2-1A31939AC01F}' = 'Group Policy Drive Maps'
	                '{6232C319-91AC-4931-9385-E70C2B099F0E}' = 'Group Policy Folder Options'
	                '{62C1845D-C4A6-4ACB-BBB0-C895FD090385}' = 'Microsoft Offline Files'
	                '{6A4C88C6-C502-4f74-8F60-2CB23EDC24E2}' = 'Group Policy Network Shares'
	                '{6C5A2A86-9EB3-42B9-AA83-A7371BA011B9}' = 'Windows Search Group Policy Extension'
	                '{728EE579-943C-4519-9EF7-AB56765798ED}' = 'Group Policy Data Sources'
	                '{74EE6C03-5363-4554-B161-627540339CAB}' = 'Group Policy Scheduled Tasks'
	                '{7933F41E-56F8-41d6-A31C-4148A711EE93}' = 'Windows Search Group Policy Extension'
	                '{79F92669-4224-476C-9C5C-6EFB4D87DF4A}' = 'Local Users and Groups'
	                '{7B849a69-220F-451E-B3FE-2CB811AF94AE}' = 'Internet Explorer Zonemapping'
	                '{827D319E-6EAC-11D2-A4EA-00C04F79F83A}' = 'Security'
	                '{8A28E2C5-8D06-49A4-A08C-632DAA493E17}' = 'Deployed Printer Connections'
	                '{91FBB303-0CD5-4055-BF42-E512A681B325}' = 'Group Policy Services'
	                '{942A8E4F-A261-11D1-A760-00C04FB9603F}' = 'Software Installation'
	                '{9AD2BAFE-63B4-4883-A08C-C3C6196BCAFD}' = 'Power Options'
	                '{A2E30F80-D7DE-11D2-BBDE-00C04F86AE3B}' = 'Internet Explorer Branding'
	                '{A3F3E39B-5D83-4940-B954-28315B82F0A8}' = 'Group Policy Drive Maps'
	                '{AADCED64-746C-4633-A97C-D61349046527}' = 'Group Policy Folders'
	                '{B087BE9D-ED37-454F-AF9C-04291E351182}' = 'Group Policy Preferences'
	                '{B1BE8D72-6EAC-11D2-A4EA-00C04F79F83A}' = 'EFS Recovery'
	                '{B587E2B1-4D59-4E7E-AED9-22B9DF11D053}' = '802.3 Group Policy'
	                '{B9CCA4DE-E2B9-4CBD-BF7D-11B6EBFBDDF7}' = 'Group Policy Network Options'
	                '{BC75B1ED-5833-4858-9BB4-B1E212E5790D}' = 'Group Policy INI Files'
	                '{C418DD9D-0D14-4EFB-8FBF-CFE535C8FAC7}' = 'Group Policy Shortcuts'
	                '{C631DF4C-088F-4156-B058-4375F0853CD8}' = 'Microsoft Offline Files'
	                '{CDEAFC3D-948D-49DD-AB12-E578BA4AF7AA}' = 'TCPIP'
	                '{D02B1F72-3407-48AE-BA88-E8213C6761F1}' = 'Wireless Group Policy'
	                '{E437BC1C-AA7D-11D2-A382-00C04F991E27}' = 'IP Security'
	                '{E47248BA-94CC-49C4-BBB5-9EB7F05183D0}' = 'Group Policy Internet Settings'
	                '{E4F48E54-F38D-4884-BFB9-D4D2E5729C18}' = 'Group Policy Start Menu Settings'
	                '{E5094040-C46C-4115-B030-04FB2E545B00}' = 'Group Policy Regional Options'
	                '{E62688F0-25FD-4c90-BFF5-F508B9D2E31F}' = 'Group Policy Environment'
	                '{E6BEFC42-E5F6-4AEB-B560-A2C1A6BEC5F0}' = 'Audit Policy'
	                '{F3CCC681-B74C-4060-9F26-CD84525DCA2A}' = 'Audit Policy Configuration'
	                '{F9C77450-3A41-477E-9310-9ACD617BD9E3}' = 'Group Policy Applications'
	                '{FC715823-C5FB-11D1-9EEF-00A0C90347FF}' = 'Internet Explorer Maintenance Extension Protocol'
	                '{FBF687E6-F063-4D9F-9F4F-FD9A26ACDD5F}' = 'Certificates'
	                '{7150F9BF-48AD-4DA4-A49C-29EF4A8369BA}' = 'Group Policy Infrastructure'
	            }
	            $ToolNames = @{
	                '{0ACDD40C-75AC-47AB-BAA0-BF6DE7E7FE63}' = 'Wireless Group Policy'
	                '{0E28E245-9368-4853-AD84-6DA3BA35BB75}' = 'Group Policy Preference Tool'
	                '{16BE69FA-4209-4250-88CB-716CF41954E0}' = 'Central Access Policy'
	                '{17D89FEC-5C44-4972-B12D-241CAEF74509}' = 'Group Policy Local Users and Groups'
	                '{1A6364EB-776B-4120-ADE1-B63A406A76B5}' = 'Group Policy Device Settings'
	                '{25537BA6-77A8-11D2-9B6C-0000F8080861}' = 'Folder Redirection'
	                '{2EA1A81B-48E5-45E9-8BB7-A6E3AC170006}' = 'Group Policy Disk Quota'
	                '{3060E8CE-7020-11D2-842D-00C04FA372D4}' = 'Remote Installation Services'
	                '{3610EDA4-77EF-11D2-8DC5-00C04FA31A66}' = 'Disk Quota'
	                '{3A0DBA37-F8B2-4356-83DE-3E90BD5C261F}' = 'Group Policy Network Options'
	                '{40B6664F-4972-11D1-A7CA-0000F87571E3}' = 'Scripts'
	                '{426031c0-0b47-4852-b0ca-ac3d37bfcb39}' = 'QoS Packet Scheduler'
	                '{4CFB60C1-FAA6-47f1-89AA-0B18730C9FD3}' = 'Internet Explorer Zonemapping'
	                '{53D6AB1B-2488-11D1-A28C-00C04FB94F17}' = 'Registry Editor'
	                '{5794DAFD-BE60-433f-88A2-1A31939AC01F}' = 'Group Policy Drive Maps'
	                '{6232C319-91AC-4931-9385-E70C2B099F0E}' = 'Group Policy Folder Options'
	                '{6A4C88C6-C502-4f74-8F60-2CB23EDC24E2}' = 'Group Policy Network Shares'
	                '{6C5A2A86-9EB3-42B9-AA83-A7371BA011B9}' = 'Windows Search Group Policy Extension'
	                '{7150F9BF-48AD-4DA4-A49C-29EF4A8369BA}' = 'Group Policy Infrastructure'
	                '{728EE579-943C-4519-9EF7-AB56765798ED}' = 'Group Policy Data Sources'
	                '{74EE6C03-5363-4554-B161-627540339CAB}' = 'Group Policy Scheduled Tasks'
	                '{7933F41E-56F8-41d6-A31C-4148A711EE93}' = 'Windows Search Group Policy Extension'
	                '{79F92669-4224-476C-9C5C-6EFB4D87DF4A}' = 'Local Users and Groups'
	                '{7B849a69-220F-451E-B3FE-2CB811AF94AE}' = 'Internet Explorer Zonemapping'
	                '{803E14A0-B4FB-11D0-A0D0-00A0C90F574B}' = 'Security Settings'
	                '{8A28E2C5-8D06-49A4-A08C-632DAA493E17}' = 'Deployed Printer Connections'
	                '{91FBB303-0CD5-4055-BF42-E512A681B325}' = 'Group Policy Services'
	                '{942A8E4F-A261-11D1-A760-00C04FB9603F}' = 'Software Installation'
	                '{9AD2BAFE-63B4-4883-A08C-C3C6196BCAFD}' = 'Power Options'
	                '{A2E30F80-D7DE-11D2-BBDE-00C04F86AE3B}' = 'Internet Explorer Branding'
	                '{A3F3E39B-5D83-4940-B954-28315B82F0A8}' = 'Group Policy Drive Maps'
	                '{AADCED64-746C-4633-A97C-D61349046527}' = 'Group Policy Folders'
	                '{B05566AC-FE9C-4368-BE01-7A4CBB6CBA11}' = 'Group Policy Preference Tool'
	                '{B087BE9D-ED37-454F-AF9C-04291E351182}' = 'Group Policy Preferences'
	                '{B1BE8D72-6EAC-11D2-A4EA-00C04F79F83A}' = 'EFS Recovery'
	                '{B587E2B1-4D59-4E7E-AED9-22B9DF11D053}' = '802.3 Group Policy'
	                '{B9CCA4DE-E2B9-4CBD-BF7D-11B6EBFBDDF7}' = 'Group Policy Network Options'
	                '{BC75B1ED-5833-4858-9BB4-B1E212E5790D}' = 'Group Policy INI Files'
	                '{BEE07A6A-EC9F-4659-B8C9-0B1937907C83}' = 'Group Policy Preference CSE'
	                '{C418DD9D-0D14-4EFB-8FBF-CFE535C8FAC7}' = 'Group Policy Shortcuts'
	                '{62C1845D-C4A6-4ACB-BBB0-C895FD090385}' = 'Microsoft Offline Files'
	                '{C631DF4C-088F-4156-B058-4375F0853CD8}' = 'Microsoft Offline Files'
	                '{CDEAFC3D-948D-49DD-AB12-E578BA4AF7AA}' = 'TCPIP'
	                '{D02B1F72-3407-48AE-BA88-E8213C6761F1}' = 'Wireless Group Policy'
	                '{E437BC1C-AA7D-11D2-A382-00C04F991E27}' = 'IP Security'
	                '{E47248BA-94CC-49C4-BBB5-9EB7F05183D0}' = 'Group Policy Internet Settings'
	                '{E4F48E54-F38D-4884-BFB9-D4D2E5729C18}' = 'Group Policy Start Menu Settings'
	                '{E5094040-C46C-4115-B030-04FB2E545B00}' = 'Group Policy Regional Options'
	                '{E62688F0-25FD-4c90-BFF5-F508B9D2E31F}' = 'Group Policy Environment'
	                '{E6BEFC42-E5F6-4AEB-B560-A2C1A6BEC5F0}' = 'Audit Policy Configuration'
	                '{F3CCC681-B74C-4060-9F26-CD84525DCA2A}' = 'Audit Policy Configuration'
	                '{F9C77450-3A41-477E-9310-9ACD617BD9E3}' = 'Group Policy Applications'
	                '{FC715823-C5FB-11D1-9EEF-00A0C90347FF}' = 'Internet Explorer Maintenance Extension Protocol'
	                '{FBF687E6-F063-4D9F-9F4F-FD9A26ACDD5F}' = 'Certificates'
	            }
	            if ($GPO.gPCMachineExtensionNames) {
	                $ExtensionString = $GPO.gPCMachineExtensionNames
	                $ExtensionPairs = [regex]::Matches($ExtensionString, '\[(\{[0-9a-fA-F-]+\})(\{[0-9a-fA-F-]+\})\]')
	                $ParsedExtensions = @()
	                foreach ($Match in $ExtensionPairs) {
	                    $CSEGUID = $Match.Groups[1].Value
	                    $ToolGUID = $Match.Groups[2].Value
	                    $CSEName = if ($CSENames.ContainsKey($CSEGUID)) { $CSENames[$CSEGUID] } else { $CSEGUID }
	                    $ToolName = if ($ToolNames.ContainsKey($ToolGUID)) { $ToolNames[$ToolGUID] } else { $ToolGUID }
	                    $ParsedExtensions += "$CSEName ($ToolName)"
	                }
	                $GPO.gPCMachineExtensionNames = $ParsedExtensions
	            }
	            if ($GPO.gPCUserExtensionNames) {
	                $ExtensionString = $GPO.gPCUserExtensionNames
	                $ExtensionPairs = [regex]::Matches($ExtensionString, '\[(\{[0-9a-fA-F-]+\})(\{[0-9a-fA-F-]+\})\]')
	                $ParsedExtensions = @()
	                foreach ($Match in $ExtensionPairs) {
	                    $CSEGUID = $Match.Groups[1].Value
	                    $ToolGUID = $Match.Groups[2].Value
	                    $CSEName = if ($CSENames.ContainsKey($CSEGUID)) { $CSENames[$CSEGUID] } else { $CSEGUID }
	                    $ToolName = if ($ToolNames.ContainsKey($ToolGUID)) { $ToolNames[$ToolGUID] } else { $ToolGUID }
	                    $ParsedExtensions += "$CSEName ($ToolName)"
	                }
	                $GPO.gPCUserExtensionNames = $ParsedExtensions
	            }
	        }
	        if ($ShowLinkedOU) {
	            $AllOUs = @(Get-DomainObject `
	                -LDAPFilter "(|(objectClass=organizationalUnit)(objectClass=domain))" `
	                -Properties @('distinguishedName', 'gPLink') `
	                -SearchBase $Script:LDAPContext.DomainDN | Where-Object { $_.gPLink })
	            $GPO = $GPOs[0]
	            $LinkedOUs = @()
	            $GPOGUID = $GPO.name  # GPO GUID (already includes braces like {GUID})
	            foreach ($OU in $AllOUs) {
	                if ($OU.gPLink -match [regex]::Escape($GPOGUID)) {
	                    $LinkedOUs += $OU.distinguishedName
	                }
	            }
	            return $LinkedOUs
	        }
	        if ($ShowPermissions) {
	            $RawParams = @{
	                LDAPFilter = $Filter
	                Properties = @('distinguishedName', 'nTSecurityDescriptor')
	                Raw = $true
	            }
	            if ($SearchBase) { $RawParams['SearchBase'] = $SearchBase }
	            $RawGPOs = @(Get-DomainObject @RawParams)
	            $ACLLookup = @{}
	            foreach ($RawGPO in $RawGPOs) {
	                if ($RawGPO.nTSecurityDescriptor -and $RawGPO.nTSecurityDescriptor -is [byte[]]) {
	                    $ACLLookup[$RawGPO.distinguishedName] = $RawGPO.nTSecurityDescriptor
	                }
	            }
	            foreach ($GPO in $GPOs) {
	                $DangerousPermissions = @()
	                $SecurityDescriptorBytes = $ACLLookup[$GPO.distinguishedName]
	                if ($SecurityDescriptorBytes) {
	                    try {
	                        $RawSD = New-Object System.DirectoryServices.ActiveDirectorySecurity
	                        $RawSD.SetSecurityDescriptorBinaryForm($SecurityDescriptorBytes)
	                        $DACL = $RawSD.GetAccessRules($true, $true, [System.Security.Principal.SecurityIdentifier])
	                        $DangerousRightsEnum = @(
	                            [System.DirectoryServices.ActiveDirectoryRights]::WriteProperty,
	                            [System.DirectoryServices.ActiveDirectoryRights]::WriteDacl,
	                            [System.DirectoryServices.ActiveDirectoryRights]::WriteOwner,
	                            [System.DirectoryServices.ActiveDirectoryRights]::GenericAll,
	                            [System.DirectoryServices.ActiveDirectoryRights]::GenericWrite
	                        )
	                        foreach ($ACE in $DACL) {
	                            $HasDangerousRights = $false
	                            $GrantedRights = @()
	                            foreach ($Right in $DangerousRightsEnum) {
	                                if ($ACE.ActiveDirectoryRights -band $Right) {
	                                    $HasDangerousRights = $true
	                                    $GrantedRights += $Right.ToString()
	                                }
	                            }
	                            if ($HasDangerousRights -and $ACE.AccessControlType -eq 'Allow') {
	                                $TrusteeSID = $ACE.IdentityReference.Value
	                                $TrusteeName = ConvertFrom-SID -SID $TrusteeSID
	                                $category = (Test-IsPrivileged -Identity $TrusteeSID).Category
	                                if ($category -ne 'Privileged') {
	                                    $Severity = "Medium"
	                                    if ($GrantedRights -contains 'GenericAll' -or $GrantedRights -contains 'WriteDacl' -or $GrantedRights -contains 'WriteOwner') {
	                                        $Severity = "High"
	                                    }
	                                    if ($category -eq 'BroadGroup') {
	                                        $Severity = "Critical"
	                                    }
	                                    $DangerousPermissions += [PSCustomObject]@{
	                                        Trustee = $TrusteeName
	                                        TrusteeSID = $TrusteeSID
	                                        Rights = $GrantedRights -join ', '
	                                        Severity = $Severity
	                                        Description = "Non-privileged principal has GPO modification rights - potential privilege escalation"
	                                    }
	                                }
	                            }
	                        }
	                    } catch {
	                    }
	                }
	                $GPO | Add-Member -NotePropertyName "DangerousPermissions" -NotePropertyValue $DangerousPermissions -Force
	                if ($DangerousPermissions.Count -gt 0) {
	                }
	            }
	        }
	        if ($ShowDangerousSettings) {
	            $resolvedSmbIP = $null
	            if ($Script:LDAPContext -and $Script:LDAPContext['DnsServer'] -and $Script:LDAPContext['ServerIP']) {
	                $resolvedSmbIP = $Script:LDAPContext['ServerIP']
	            }
	            Invoke-SMBAccess -Description "Analyzing GPO dangerous settings" -ErrorHandling "Warn" -ScriptBlock {
	            foreach ($GPO in $GPOs) {
	                $DangerousSettings = @()
	                $GPOPath = $GPO.gPCFileSysPath
	                if ($resolvedSmbIP -and $GPOPath -match '^\\\\([^\\]+)\\') {
	                    $uncHost = $Matches[1]
	                    $ipTest = $null
	                    if (-not [System.Net.IPAddress]::TryParse($uncHost, [ref]$ipTest)) {
	                        $GPOPath = $GPOPath -replace "^\\\\[^\\]+\\", "\\$resolvedSmbIP\"
	                    }
	                }
	                if ($GPOPath -and (Test-Path $GPOPath -ErrorAction SilentlyContinue)) {
	                    $ScheduledTasksPath = Join-Path $GPOPath "Machine\Preferences\ScheduledTasks\ScheduledTasks.xml"
	                    if (Test-Path $ScheduledTasksPath -ErrorAction SilentlyContinue) {
	                        try {
	                            [xml]$TasksXML = Get-Content $ScheduledTasksPath -ErrorAction SilentlyContinue
	                            $TaskCount = @($TasksXML.ScheduledTasks.ChildNodes | Where-Object { $_.name -ne '#comment' }).Count
	                            if ($TaskCount -gt 0) {
	                                $DangerousSettings += [PSCustomObject]@{
	                                    Type = "Scheduled Tasks"
	                                    Severity = "High"
	                                    Description = "$TaskCount scheduled task(s) configured - potential for arbitrary code execution"
	                                    Path = $ScheduledTasksPath
	                                }
	                            }
	                        } catch {
	                        }
	                    }
	                    $ComputerScriptsIni = Join-Path $GPOPath "Machine\Scripts\scripts.ini"
	                    if (Test-Path $ComputerScriptsIni -ErrorAction SilentlyContinue) {
	                        $ScriptContent = Get-Content $ComputerScriptsIni -Raw -ErrorAction SilentlyContinue
	                        if ($ScriptContent -and $ScriptContent.Trim().Length -gt 0) {
	                            $DangerousSettings += [PSCustomObject]@{
	                                Type = "Computer Startup/Shutdown Scripts"
	                                Severity = "High"
	                                Description = "Computer scripts configured - runs as SYSTEM on boot/shutdown"
	                                Path = $ComputerScriptsIni
	                            }
	                        }
	                    }
	                    $UserScriptsIni = Join-Path $GPOPath "User\Scripts\scripts.ini"
	                    if (Test-Path $UserScriptsIni -ErrorAction SilentlyContinue) {
	                        $ScriptContent = Get-Content $UserScriptsIni -Raw -ErrorAction SilentlyContinue
	                        if ($ScriptContent -and $ScriptContent.Trim().Length -gt 0) {
	                            $DangerousSettings += [PSCustomObject]@{
	                                Type = "User Logon/Logoff Scripts"
	                                Severity = "Medium"
	                                Description = "User scripts configured - runs in user context"
	                                Path = $UserScriptsIni
	                            }
	                        }
	                    }
	                    $RegistryXMLPaths = @(
	                        (Join-Path $GPOPath "Machine\Preferences\Registry\Registry.xml"),
	                        (Join-Path $GPOPath "User\Preferences\Registry\Registry.xml")
	                    )
	                    foreach ($RegPath in $RegistryXMLPaths) {
	                        if (Test-Path $RegPath -ErrorAction SilentlyContinue) {
	                            try {
	                                [xml]$RegXML = Get-Content $RegPath -ErrorAction SilentlyContinue
	                                $RegCount = @($RegXML.RegistrySettings.ChildNodes | Where-Object { $_.name -ne '#comment' }).Count
	                                if ($RegCount -gt 0) {
	                                    $RunKeys = $RegXML.SelectNodes("//Registry") | Where-Object {
	                                        $_.Properties.key -match "\\Software\\Microsoft\\Windows\\CurrentVersion\\Run"
	                                    }
	                                    $Context = if ($RegPath -match "\\Machine\\") { "Machine" } else { "User" }
	                                    if ($RunKeys.Count -gt 0) {
	                                        $DangerousSettings += [PSCustomObject]@{
	                                            Type = "Registry Run Keys ($Context)"
	                                            Severity = "High"
	                                            Description = "$($RunKeys.Count) Run key(s) configured - potential persistence mechanism"
	                                            Path = $RegPath
	                                        }
	                                    } else {
	                                        $DangerousSettings += [PSCustomObject]@{
	                                            Type = "Registry Settings ($Context)"
	                                            Severity = "Low"
	                                            Description = "$RegCount registry setting(s) configured"
	                                            Path = $RegPath
	                                        }
	                                    }
	                                }
	                            } catch {
	                            }
	                        }
	                    }
	                    $GroupsXMLPaths = @(
	                        (Join-Path $GPOPath "Machine\Preferences\Groups\Groups.xml"),
	                        (Join-Path $GPOPath "User\Preferences\Groups\Groups.xml")
	                    )
	                    foreach ($GroupPath in $GroupsXMLPaths) {
	                        if (Test-Path $GroupPath -ErrorAction SilentlyContinue) {
	                            try {
	                                [xml]$GroupXML = Get-Content $GroupPath -ErrorAction SilentlyContinue
	                                $GroupCount = @($GroupXML.Groups.ChildNodes | Where-Object { $_.name -ne '#comment' }).Count
	                                if ($GroupCount -gt 0) {
	                                    $AdminGroups = $GroupXML.SelectNodes("//Group") | Where-Object {
	                                        $_.Properties.groupSid -eq 'S-1-5-32-544'
	                                    }
	                                    $Context = if ($GroupPath -match "\\Machine\\") { "Machine" } else { "User" }
	                                    if ($AdminGroups.Count -gt 0) {
	                                        $DangerousSettings += [PSCustomObject]@{
	                                            Type = "Local Administrators Modification ($Context)"
	                                            Severity = "Critical"
	                                            Description = "Administrators group modification - potential privilege escalation"
	                                            Path = $GroupPath
	                                        }
	                                    } else {
	                                        $DangerousSettings += [PSCustomObject]@{
	                                            Type = "Local Group Membership ($Context)"
	                                            Severity = "Medium"
	                                            Description = "$GroupCount local group modification(s)"
	                                            Path = $GroupPath
	                                        }
	                                    }
	                                }
	                            } catch {
	                            }
	                        }
	                    }
	                    $ServicesXMLPath = Join-Path $GPOPath "Machine\Preferences\Services\Services.xml"
	                    if (Test-Path $ServicesXMLPath -ErrorAction SilentlyContinue) {
	                        try {
	                            [xml]$ServicesXML = Get-Content $ServicesXMLPath -ErrorAction SilentlyContinue
	                            $ServiceCount = @($ServicesXML.Services.ChildNodes | Where-Object { $_.name -ne '#comment' }).Count
	                            if ($ServiceCount -gt 0) {
	                                $DangerousSettings += [PSCustomObject]@{
	                                    Type = "Service Configuration"
	                                    Severity = "High"
	                                    Description = "$ServiceCount service(s) configured - potential for privilege escalation"
	                                    Path = $ServicesXMLPath
	                                }
	                            }
	                        } catch {
	                        }
	                    }
	                } else {
	                }
	                $GPO | Add-Member -NotePropertyName "DangerousSettings" -NotePropertyValue $DangerousSettings -Force
	                if ($DangerousSettings.Count -gt 0) {
	                }
	            }
	            } # End Invoke-SMBAccess ScriptBlock
	        }
	        if ($isUnfilteredCall -and $GPOs.Count -gt 0) {
	            $Script:CachedAllGPOs = $GPOs
	        }
	        return $GPOs
	    } catch {
	        throw
	    }
	}
	end {
	}
}
function Get-CertificateTemplate {
	[CmdletBinding(DefaultParameterSetName='All')]
	[OutputType([System.Management.Automation.PSCustomObject])]
	param(
	    [Parameter(Mandatory=$false, Position=0, ParameterSetName='Identity')]
	    [Alias('Name')]
	    [string]$Identity,
	    [Parameter(Mandatory=$false, ParameterSetName='Filter')]
	    [string]$LDAPFilter,
	    [Parameter(Mandatory=$false)]
	    [string[]]$Properties,
	    [Parameter(Mandatory=$false)]
	    [string]$SearchBase,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$Raw,
	    [Parameter(Mandatory=$false)]
	    [switch]$ShowAll,
	    [Parameter(Mandatory=$false)]
	    [switch]$EnrolleeSuppliesSubject,
	    [Parameter(Mandatory=$false)]
	    [switch]$Export,
	    [Parameter(Mandatory=$false)]
	    [string]$ExportPath,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoSecurityExtension,
	    [Parameter(Mandatory=$false)]
	    [switch]$ClientAuthentication,
	    [Parameter(Mandatory=$false)]
	    [switch]$ExportableKey,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoManagerApproval,
	    [Parameter(Mandatory=$false)]
	    [switch]$EnrollmentAllowed
	)
	begin {
	}
	process {
	    $ConnectionParams = @{}
	    if ($Domain) { $ConnectionParams['Domain'] = $Domain }
	    if ($Server) { $ConnectionParams['Server'] = $Server }
	    if ($Credential) { $ConnectionParams['Credential'] = $Credential }
	    if (-not (Ensure-LDAPConnection @ConnectionParams)) {
	        return
	    }
	    try {
	        if ($Export -and -not $Raw) {
	            $Raw = $true
	        }
	        if (-not $SearchBase) {
	            $ConfigNC = $Script:LDAPContext.ConfigurationNamingContext
	            if (-not $ConfigNC) {
	                Write-Error "Could not determine Configuration partition. Ensure LDAP connection is established."
	                return
	            }
	            $SearchBase = "CN=Certificate Templates,CN=Public Key Services,CN=Services,$ConfigNC"
	        }
	        $Filter = "(objectClass=pKICertificateTemplate)"
	        if ($PSCmdlet.ParameterSetName -eq 'Identity') {
	            $Filter = "(&(objectClass=pKICertificateTemplate)(|(cn=$Identity)(displayName=$Identity)(distinguishedName=$Identity)))"
	        }
	        elseif ($PSCmdlet.ParameterSetName -eq 'Filter') {
	            $Filter = "(&(objectClass=pKICertificateTemplate)$LDAPFilter)"
	        }
	        $RequiredProperties = @('cn', 'displayName', 'distinguishedName')
	        if ($Properties) {
	            $AllProperties = $RequiredProperties + $Properties | Select-Object -Unique
	        } else {
	            $AllProperties = @(
	                'cn',
	                'displayName',
	                'distinguishedName',
	                'objectGUID',
	                'whenCreated',
	                'whenChanged',
	                'revision',
	                'flags',
	                'msPKI-Certificate-Name-Flag',
	                'msPKI-Enrollment-Flag',
	                'msPKI-Private-Key-Flag',
	                'msPKI-Minimal-Key-Size',
	                'msPKI-RA-Signature',
	                'pKIDefaultKeySpec',
	                'pKIKeyUsage',
	                'msPKI-Template-Schema-Version',
	                'msPKI-Template-Minor-Revision',
	                'pKIExtendedKeyUsage',
	                'msPKI-Certificate-Application-Policy',
	                'pKICriticalExtensions',
	                'msPKI-Certificate-Policy',
	                'pKIMaxIssuingDepth',
	                'pKIExpirationPeriod',
	                'pKIOverlapPeriod',
	                'pKIDefaultCSPs',
	                'msPKI-Supersede-Templates',
	                'nTSecurityDescriptor',
	                'msPKI-Cert-Template-OID'
	            )
	        }
	        $GetParams = @{
	            LDAPFilter = $Filter
	            SearchBase = $SearchBase
	            Properties = $AllProperties
	        }
	        if ($Domain) { $GetParams['Domain'] = $Domain }
	        if ($Server) { $GetParams['Server'] = $Server }
	        if ($Credential) { $GetParams['Credential'] = $Credential }
	        if ($Raw) { $GetParams['Raw'] = $true }
	        $Templates = Get-DomainObject @GetParams
	        $Templates = @($Templates)
	        if ($Templates -and $Templates.Count -gt 0) {
	            $TemplateCAMap = @{}
	            $EnrollmentServicesBase = "CN=Enrollment Services,CN=Public Key Services,CN=Services,$ConfigNC"
	            try {
	                $CAs = Get-DomainObject -LDAPFilter "(objectClass=pKIEnrollmentService)" -SearchBase $EnrollmentServicesBase -Properties @('cn', 'certificateTemplates') -Raw
	                if ($CAs) {
	                    foreach ($CA in @($CAs)) {
	                        if ($CA.certificateTemplates) {
	                            $CAName = if ($CA.cn) { [string]$CA.cn } else { 'Unknown' }
	                            foreach ($tmpl in @($CA.certificateTemplates)) {
	                                if (-not $TemplateCAMap.ContainsKey($tmpl)) {
	                                    $TemplateCAMap[$tmpl] = [System.Collections.Generic.List[string]]::new()
	                                }
	                                $TemplateCAMap[$tmpl].Add($CAName)
	                            }
	                        }
	                    }
	                    if (-not $ShowAll) {
	                        $EnabledTemplates = $Templates | Where-Object { $TemplateCAMap.ContainsKey($_.cn) }
	                        if ($EnabledTemplates) {
	                            $ResultTemplates = $EnabledTemplates
	                        }
	                        else {
	                            $ResultTemplates = $null
	                        }
	                    }
	                    else {
	                        $ResultTemplates = $Templates
	                    }
	                }
	                else {
	                    Write-Warning "No Certificate Authorities found. Cannot determine which templates are enabled."
	                    Write-Warning "Returning all templates instead."
	                    $ResultTemplates = $Templates
	                }
	            }
	            catch {
	                Write-Warning "Error querying CA enrollment services: $_"
	                Write-Warning "Returning all templates instead."
	                $ResultTemplates = $Templates
	            }
	            if ($ResultTemplates) {
	                foreach ($tmpl in @($ResultTemplates)) {
	                    $caList = if ($TemplateCAMap.ContainsKey($tmpl.cn)) { @($TemplateCAMap[$tmpl.cn]) } else { @() }
	                    $tmpl | Add-Member -NotePropertyName 'PublishedOn' -NotePropertyValue $caList -Force
	                }
	            }
	            if ($ResultTemplates -and ($EnrolleeSuppliesSubject -or $NoSecurityExtension -or $ClientAuthentication -or $ExportableKey -or $NoManagerApproval -or $EnrollmentAllowed)) {
	                $FilteredTemplates = $ResultTemplates
	                if ($EnrolleeSuppliesSubject) {
	                    $FilteredTemplates = $FilteredTemplates | Where-Object {
	                        if ($_.'msPKI-Certificate-Name-Flag' -is [int]) {
	                            ([int]$_.'msPKI-Certificate-Name-Flag') -band 0x00000001
	                        } else {
	                            $_.'msPKI-Certificate-Name-Flag' -contains 'ENROLLEE_SUPPLIES_SUBJECT'
	                        }
	                    }
	                }
	                if ($NoSecurityExtension) {
	                    $FilteredTemplates = $FilteredTemplates | Where-Object {
	                        if ($_.'msPKI-Enrollment-Flag' -is [int]) {
	                            ([int]$_.'msPKI-Enrollment-Flag') -band 0x00080000
	                        } else {
	                            $_.'msPKI-Enrollment-Flag' -contains 'NO_SECURITY_EXTENSION'
	                        }
	                    }
	                }
	                if ($ClientAuthentication) {
	                    $FilteredTemplates = $FilteredTemplates | Where-Object {
	                        ($_.pKIExtendedKeyUsage -match '1\.3\.6\.1\.5\.5\.7\.3\.2') -or
	                        ($_.'msPKI-Certificate-Application-Policy' -match '1\.3\.6\.1\.5\.5\.7\.3\.2')
	                    }
	                }
	                if ($ExportableKey) {
	                    $FilteredTemplates = $FilteredTemplates | Where-Object {
	                        if ($_.'msPKI-Private-Key-Flag' -is [int]) {
	                            ([int]$_.'msPKI-Private-Key-Flag') -band 0x00000010
	                        } else {
	                            $_.'msPKI-Private-Key-Flag' -contains 'EXPORTABLE_KEY'
	                        }
	                    }
	                }
	                if ($NoManagerApproval) {
	                    $FilteredTemplates = $FilteredTemplates | Where-Object {
	                        if ($_.'msPKI-Enrollment-Flag' -is [int]) {
	                            -not (([int]$_.'msPKI-Enrollment-Flag') -band 0x00000002)
	                        } else {
	                            $_.'msPKI-Enrollment-Flag' -notcontains 'PEND_ALL_REQUESTS'
	                        }
	                    }
	                }
	                if ($EnrollmentAllowed) {
	                    $FilteredTemplates = $FilteredTemplates | Where-Object {
	                        if ($_.nTSecurityDescriptor) {
	                            if ($_.nTSecurityDescriptor -is [byte[]]) {
	                                $SD = New-Object System.DirectoryServices.ActiveDirectorySecurity
	                                $SD.SetSecurityDescriptorBinaryForm($_.nTSecurityDescriptor)
	                                $CertEnrollGuid = [Guid]"0e10c968-78fb-11d2-90d4-00c04f79dc55"
	                                $AllExtendedRightsGuid = [Guid]"00000000-0000-0000-0000-000000000000"
	                                $SD.Access | Where-Object {
	                                    $_.AccessControlType -eq 'Allow' -and
	                                    ($_.ObjectType -eq $CertEnrollGuid -or $_.ObjectType -eq $AllExtendedRightsGuid)
	                                }
	                            } else {
	                                $SDLines = $_.nTSecurityDescriptor
	                                ($SDLines -match 'Certificate-Enrollment' -or
	                                 $SDLines -match 'Certificate-AutoEnrollment' -or
	                                 $SDLines -match 'All-Extended-Rights').Count -gt 0
	                            }
	                        } else {
	                            $false
	                        }
	                    }
	                }
	                if ($FilteredTemplates) {
	                    if ($Properties) {
	                        $OutputProperties = @('cn', 'PublishedOn') + $Properties | Select-Object -Unique
	                        return $FilteredTemplates | Select-Object $OutputProperties
	                    } else {
	                        return $FilteredTemplates
	                    }
	                }
	                else {
	                    return $null
	                }
	            }
	            else {
	                if ($Properties) {
	                    $OutputProperties = @('cn', 'PublishedOn') + $Properties
	                    $UniqueProperties = @()
	                    $SeenProperties = @{}
	                    foreach ($prop in $OutputProperties) {
	                        $propLower = $prop.ToLower()
	                        if (-not $SeenProperties.ContainsKey($propLower)) {
	                            $UniqueProperties += $prop
	                            $SeenProperties[$propLower] = $true
	                        }
	                    }
	                    $ResultTemplates = $ResultTemplates | Select-Object $UniqueProperties
	                }
	            }
	            if ($Export) {
	                if (-not $ExportPath) {
	                    $Timestamp = Get-Date -Format "yyyyMMdd-HHmmss"
	                    if ($ResultTemplates.Count -eq 1) {
	                        $TemplateName = $ResultTemplates[0].cn
	                        $ExportPath = "CertTemplate_${TemplateName}_${Timestamp}.json"
	                    } else {
	                        $ExportPath = "CertTemplates_${Timestamp}.json"
	                    }
	                }
	                $ExcludedAttributes = @(
	                    'ntsecuritydescriptor',
	                    'objectguid',
	                    'whencreated',
	                    'whenchanged'
	                )
	                $ExportData = @()
	                foreach ($template in $ResultTemplates) {
	                    $FullTemplateParams = @{
	                        LDAPFilter = "(cn=$($template.cn))"
	                        SearchBase = $SearchBase
	                        Properties = @('*')  # Load ALL attributes
	                        Raw = $true          # Raw values for restore
	                    }
	                    if ($Domain) { $FullTemplateParams['Domain'] = $Domain }
	                    if ($Server) { $FullTemplateParams['Server'] = $Server }
	                    if ($Credential) { $FullTemplateParams['Credential'] = $Credential }
	                    $FullTemplate = @(Get-DomainObject @FullTemplateParams)[0]
	                    if (-not $FullTemplate) {
	                        Write-Warning "[Get-CertificateTemplate] Failed to re-query template '$($template.cn)' for export"
	                        continue
	                    }
	                    $ExportObject = [ordered]@{}
	                    $FullTemplate.PSObject.Properties | Where-Object {
	                        $ExcludedAttributes -notcontains $_.Name.ToLower()
	                    } | ForEach-Object {
	                        $ExportObject[$_.Name] = $_.Value
	                    }
	                    $ExportData += $ExportObject
	                }
	                $ExportFile = @{
	                    ExportedAt = Get-Date -Format "yyyy-MM-dd HH:mm:ss"
	                    ExportedBy = "$env:USERDOMAIN\$env:USERNAME"
	                    Domain = $Script:LDAPContext.Domain
	                    TemplateCount = $ExportData.Count
	                    Templates = $ExportData
	                }
	                $exportResult = Export-adPEASFile -Path $ExportPath -Content $ExportFile -Type Json -SanitizeFilename
	                if ($exportResult.Success) {
	                } else {
	                    Write-Error "Failed to export templates: $($exportResult.Message)"
	                }
	            }
	            return $ResultTemplates
	        }
	        else {
	            return $null
	        }
	    }
	    catch {
	        [PSCustomObject]@{
	            _QueryError = $true
	            ErrorMessage = $_.Exception.Message
	        }
	    }
	}
	end {
	}
}
function Set-CertificateTemplate {
	[CmdletBinding(SupportsShouldProcess=$true, ConfirmImpact='Low')]
	[OutputType([System.Management.Automation.PSCustomObject])]
	param(
	    [Parameter(Mandatory=$true, Position=0)]
	    [Alias('Name')]
	    [string]$Identity,
	    [Parameter(Mandatory=$false)]
	    [switch]$AllowEnrolleeSuppliesSubject,
	    [Parameter(Mandatory=$false)]
	    [switch]$AddClientAuthentication,
	    [Parameter(Mandatory=$false)]
	    [switch]$AllowExportableKey,
	    [Parameter(Mandatory=$false)]
	    [switch]$RemoveManagerApproval,
	    [Parameter(Mandatory=$false)]
	    [string]$GrantEnrollment,
	    [Parameter(Mandatory=$false)]
	    [string]$GrantFullControl,
	    [Parameter(Mandatory=$false)]
	    [string]$GrantWrite,
	    [Parameter(Mandatory=$false)]
	    [string]$RevokeEnrollment,
	    [Parameter(Mandatory=$false)]
	    [switch]$DisableEnrolleeSuppliesSubject,
	    [Parameter(Mandatory=$false)]
	    [switch]$AddManagerApproval,
	    [Parameter(Mandatory=$false)]
	    [string]$RemoveEKU,
	    [Parameter(Mandatory=$false)]
	    [switch]$AddAnyPurposeEKU,
	    [Parameter(Mandatory=$false)]
	    [switch]$ClearEKUs,
	    [Parameter(Mandatory=$false)]
	    [switch]$AddSmartcardLogon,
	    [Parameter(Mandatory=$false)]
	    [string]$SetOwner,
	    [Parameter(Mandatory=$false)]
	    [string]$GrantAutoEnroll,
	    [Parameter(Mandatory=$false)]
	    [string]$Export,
	    [Parameter(Mandatory=$false)]
	    [string]$Import,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential
	)
	begin {
	    $Modifications = @()
	}
	process {
	    $ConnectionParams = @{}
	    if ($PSBoundParameters.ContainsKey('Domain')) { $ConnectionParams['Domain'] = $Domain }
	    if ($PSBoundParameters.ContainsKey('Server')) { $ConnectionParams['Server'] = $Server }
	    if ($PSBoundParameters.ContainsKey('Credential')) { $ConnectionParams['Credential'] = $Credential }
	    if (-not (Ensure-LDAPConnection @ConnectionParams)) {
	        return [PSCustomObject]@{
	            Operation = "ModifyCertificateTemplate"
	            Template = $Identity
	            Success = $false
	            Message = "No LDAP connection available"
	        }
	    }
	    try {
	        if ($Import) {
	            if (-not (Test-Path -Path $Import -PathType Leaf)) {
	                throw "Import file not found or is a directory: $Import"
	            }
	            try {
	                $ImportData = Get-Content -Path $Import -Raw | ConvertFrom-Json
	            }
	            catch {
	                throw "Failed to parse import file (invalid JSON): $_"
	            }
	            if (-not $ImportData.Templates) {
	                throw "Invalid import file format: Missing 'Templates' array"
	            }
	            $ConfigNC = $Script:LDAPContext.ConfigurationNamingContext
	            $TemplatesBase = "CN=Certificate Templates,CN=Public Key Services,CN=Services,$ConfigNC"
	            $RestoredCount = 0
	            $FailedCount = 0
	            foreach ($BackupTemplate in $ImportData.Templates) {
	                try {
	                    $TemplateName = $BackupTemplate.cn
	                    $BackupAttributeNames = @($BackupTemplate.PSObject.Properties | ForEach-Object { $_.Name })
	                    $RequiredProperties = @('cn', 'displayName', 'distinguishedName')
	                    $AllProperties = @($BackupAttributeNames) + $RequiredProperties | Select-Object -Unique
	                    $ExistingTemplate = @(Get-CertificateTemplate -Identity $TemplateName -ShowAll -Raw -Properties $AllProperties)[0]
	                    if (-not $ExistingTemplate) {
	                        Write-Warning "[!] Template '$TemplateName' does not exist in AD - skipping"
	                        $FailedCount++
	                        continue
	                    }
	                    $TemplateDN = $ExistingTemplate.distinguishedName
	                    $RestoreAttributes = @{}
	                    $ExcludedAttributes = @(
	                        'cn',                        # Identity, not restorable
	                        'name',                      # Usually same as cn, system-managed
	                        'distinguishedname',         # Identity, not restorable
	                        'objectguid',                # System-generated
	                        'objectcategory',            # System-generated
	                        'objectclass',               # System-generated
	                        'instancetype',              # System-generated
	                        'whencreated',               # System-generated timestamp
	                        'whenchanged',               # System-generated timestamp
	                        'dscorepropagationdata',     # System-generated replication metadata
	                        'usncreated',                # System-generated USN
	                        'usnchanged',                # System-generated USN
	                        'ntsecuritydescriptor',      # ACLs handled separately
	                        'pkiexpirationperiod',       # Binary attribute, cannot restore via JSON
	                        'pkioverlapperiod',          # Binary attribute, cannot restore via JSON
	                        'pkidefaultkeyspec',         # Converted value, restore raw instead
	                        'pkikeyusage',               # Converted value, restore raw instead
	                        'revision',                  # Auto-incremented, don't restore old value
	                        'showinadvancedviewonly'     # UI-specific, not critical
	                    )
	                    $BackupTemplate.PSObject.Properties | Where-Object {
	                        $ExcludedAttributes -notcontains $_.Name.ToLower() -and $null -ne $_.Value
	                    } | ForEach-Object {
	                        $AttributeName = $_.Name
	                        $BackupValue = $_.Value
	                        $CurrentValue = $ExistingTemplate.$AttributeName
	                        $ValuesMatch = $false
	                        if ($null -eq $CurrentValue -and $null -eq $BackupValue) {
	                            $ValuesMatch = $true
	                        }
	                        elseif ($null -eq $CurrentValue -or $null -eq $BackupValue) {
	                            $ValuesMatch = $false
	                        }
	                        elseif ($BackupValue -is [System.Array] -and $CurrentValue -is [System.Array]) {
	                            if ($BackupValue.Count -eq $CurrentValue.Count) {
	                                $ValuesMatch = $true
	                                for ($i = 0; $i -lt $BackupValue.Count; $i++) {
	                                    if ($BackupValue[$i] -ne $CurrentValue[$i]) {
	                                        $ValuesMatch = $false
	                                        break
	                                    }
	                                }
	                            }
	                        }
	                        else {
	                            $ValuesMatch = ($BackupValue -eq $CurrentValue)
	                        }
	                        if (-not $ValuesMatch) {
	                            $AttributeValue = $BackupValue
	                            if ($AttributeValue -is [System.Array]) {
	                                $AttributeValue = [string[]]@($AttributeValue)
	                            }
	                            $RestoreAttributes[$AttributeName] = $AttributeValue
	                        }
	                        else {
	                        }
	                    }
	                    if ($RestoreAttributes.Count -eq 0) {
	                        Show-Line "Template '$TemplateName' already matches backup - no changes needed" -Class Note
	                        continue
	                    }
	                    if ($PSCmdlet.ShouldProcess($TemplateName, "Restore template from backup")) {
	                        try {
	                            $null = Set-DomainObject -Identity $TemplateDN -Set $RestoreAttributes -SearchBase $TemplatesBase -ErrorAction Stop
	                            $RestoredCount++
	                            Show-Line "Successfully restored template: $TemplateName ($($RestoreAttributes.Count) attributes)" -Class Hint
	                        }
	                        catch {
	                            Write-Warning "[!] Failed to restore template '$TemplateName': $($_.Exception.Message)"
	                            $FailedCount++
	                        }
	                    }
	                }
	                catch {
	                    Write-Warning "[!] Error processing template '$TemplateName': $($_.Exception.Message)"
	                    $FailedCount++
	                }
	            }
	            return
	        }
	        if ($Export) {
	            $ConfigNC = $Script:LDAPContext.ConfigurationNamingContext
	            $TemplatesBase = "CN=Certificate Templates,CN=Public Key Services,CN=Services,$ConfigNC"
	            $TemplateInfo = @(Get-CertificateTemplate -Identity $Identity -ShowAll -Raw)[0]
	            if (-not $TemplateInfo) {
	                throw "Certificate template '$Identity' not found"
	            }
	            $TemplateName = $TemplateInfo.cn
	            $ExportData = [ordered]@{
	                ExportDate = (Get-Date -Format "yyyy-MM-dd HH:mm:ss")
	                ExportedBy = "$env:USERDOMAIN\$env:USERNAME"
	                TemplateCount = 1
	                Templates = @(
	                    $TemplateInfo
	                )
	            }
	            try {
	                $ExportData | ConvertTo-Json -Depth 10 | Set-Content -Path $Export -Encoding UTF8 -ErrorAction Stop
	                Show-Line "Successfully exported template '$TemplateName' to: $Export" -Class Hint
	            }
	            catch {
	                throw "Failed to write export file: $_"
	            }
	            return
	        }
	        $ModificationParams = @(
	            'AllowEnrolleeSuppliesSubject',
	            'AddClientAuthentication',
	            'AllowExportableKey',
	            'RemoveManagerApproval',
	            'GrantEnrollment',
	            'GrantFullControl',
	            'GrantWrite',
	            'RevokeEnrollment',
	            'DisableEnrolleeSuppliesSubject',
	            'AddManagerApproval',
	            'RemoveEKU',
	            'AddAnyPurposeEKU',
	            'ClearEKUs',
	            'AddSmartcardLogon',
	            'SetOwner',
	            'GrantAutoEnroll'
	        )
	        $HasModification = $false
	        foreach ($param in $ModificationParams) {
	            if ($PSBoundParameters.ContainsKey($param)) {
	                $HasModification = $true
	                break
	            }
	        }
	        if (-not $HasModification) {
	            Show-NoParametersError -FunctionName "Set-CertificateTemplate"
	            return $null
	        }
	        $ConfigNC = $Script:LDAPContext.ConfigurationNamingContext
	        $TemplatesBase = "CN=Certificate Templates,CN=Public Key Services,CN=Services,$ConfigNC"
	        $TemplateInfo = @(Get-CertificateTemplate -Identity $Identity -ShowAll -Raw)[0]
	        if (-not $TemplateInfo) {
	            throw "Certificate template '$Identity' not found"
	        }
	        $TemplateDN = $TemplateInfo.distinguishedName
	        $TemplateName = $TemplateInfo.cn
	        $HasAnyModification = ($AllowEnrolleeSuppliesSubject -or $AllowExportableKey -or $RemoveManagerApproval -or
	            $DisableEnrolleeSuppliesSubject -or $AddManagerApproval -or $AddClientAuthentication -or
	            $RemoveClientAuthentication -or $RemoveEKU -or $AddAnyPurposeEKU -or $ClearEKUs -or
	            $AddSmartcardLogon -or $GrantEnrollment -or $GrantFullControl -or $GrantWrite -or
	            $RevokeEnrollment -or $SetOwner -or $GrantAutoEnroll)
	        if ($HasAnyModification) {
	            $CurrentRevision = if ($TemplateInfo.revision) { [int]$TemplateInfo.revision } else { 0 }
	            $writeTest = Set-DomainObject -Identity $TemplateDN -Set @{'revision' = $CurrentRevision} -SearchBase $TemplatesBase -ErrorAction SilentlyContinue
	            if ($writeTest -eq $false) {
	                throw "Insufficient permissions to modify template '$TemplateName'. Ensure the current user has Write access to the certificate template object."
	            }
	        }
	        if ($AllowEnrolleeSuppliesSubject) {
	            if ($PSCmdlet.ShouldProcess($TemplateName, "Enable ENROLLEE_SUPPLIES_SUBJECT flag") -eq $true) {
	                $CurrentFlags = if ($TemplateInfo.'msPKI-Certificate-Name-Flag') {
	                    [int]$TemplateInfo.'msPKI-Certificate-Name-Flag'
	                } else { 0 }
	                $NewFlags = 0x00000001  # ENROLLEE_SUPPLIES_SUBJECT only (clear all other flags)
	                $null = Set-DomainObject -Identity $TemplateDN -Set @{'msPKI-Certificate-Name-Flag' = $NewFlags} -SearchBase $TemplatesBase
	                $Modifications += "Enabled ENROLLEE_SUPPLIES_SUBJECT (cleared all other subject name flags)"
	            }
	        }
	        if ($AllowExportableKey) {
	            if ($PSCmdlet.ShouldProcess($TemplateName, "Enable EXPORTABLE_KEY flag") -eq $true) {
	                $CurrentFlags = if ($TemplateInfo.'msPKI-Private-Key-Flag') {
	                    [int]$TemplateInfo.'msPKI-Private-Key-Flag'
	                } else { 0 }
	                $NewFlags = $CurrentFlags -bor 0x00000010  # EXPORTABLE_KEY
	                $null = Set-DomainObject -Identity $TemplateDN -Set @{'msPKI-Private-Key-Flag' = $NewFlags} -SearchBase $TemplatesBase
	                $Modifications += "Enabled EXPORTABLE_KEY"
	            }
	        }
	        if ($RemoveManagerApproval) {
	            if ($PSCmdlet.ShouldProcess($TemplateName, "Remove manager approval requirement") -eq $true) {
	                $CurrentFlags = if ($TemplateInfo.'msPKI-Enrollment-Flag') {
	                    [int]$TemplateInfo.'msPKI-Enrollment-Flag'
	                } else { 0 }
	                $NewFlags = $CurrentFlags -band (-bnot 0x00000002)  # Remove PEND_ALL_REQUESTS
	                $null = Set-DomainObject -Identity $TemplateDN -Set @{'msPKI-Enrollment-Flag' = $NewFlags} -SearchBase $TemplatesBase
	                $Modifications += "Removed manager approval requirement"
	            }
	        }
	        if ($DisableEnrolleeSuppliesSubject) {
	            if ($PSCmdlet.ShouldProcess($TemplateName, "Disable ENROLLEE_SUPPLIES_SUBJECT flag") -eq $true) {
	                $CurrentFlags = if ($TemplateInfo.'msPKI-Certificate-Name-Flag') {
	                    [int]$TemplateInfo.'msPKI-Certificate-Name-Flag'
	                } else { 0 }
	                $NewFlags = $CurrentFlags -band (-bnot 0x00000001)  # Remove ENROLLEE_SUPPLIES_SUBJECT
	                if ($NewFlags -eq 0) {
	                    $NewFlags = 0x02000000
	                }
	                $null = Set-DomainObject -Identity $TemplateDN -Set @{'msPKI-Certificate-Name-Flag' = $NewFlags} -SearchBase $TemplatesBase
	                $Modifications += "Disabled ENROLLEE_SUPPLIES_SUBJECT (restored CA-supplied subject)"
	            }
	        }
	        if ($AddManagerApproval) {
	            if ($PSCmdlet.ShouldProcess($TemplateName, "Add manager approval requirement") -eq $true) {
	                $CurrentFlags = if ($TemplateInfo.'msPKI-Enrollment-Flag') {
	                    [int]$TemplateInfo.'msPKI-Enrollment-Flag'
	                } else { 0 }
	                $NewFlags = $CurrentFlags -bor 0x00000002  # Add PEND_ALL_REQUESTS
	                $null = Set-DomainObject -Identity $TemplateDN -Set @{'msPKI-Enrollment-Flag' = $NewFlags} -SearchBase $TemplatesBase
	                $Modifications += "Added manager approval requirement"
	            }
	        }
	        if ($AddClientAuthentication) {
	            if ($PSCmdlet.ShouldProcess($TemplateName, "Add Client Authentication EKU") -eq $true) {
	                $ClientAuthOID = "1.3.6.1.5.5.7.3.2"
	                $CurrentEKU = @()
	                if ($TemplateInfo.pKIExtendedKeyUsage) {
	                    $ekuValue = $TemplateInfo.pKIExtendedKeyUsage
	                    if ($ekuValue -is [System.Array]) {
	                        $CurrentEKU = @($ekuValue | ForEach-Object { [string]$_ })
	                    }
	                    else {
	                        $CurrentEKU = @([string]$ekuValue)
	                    }
	                }
	                if ($CurrentEKU -notcontains $ClientAuthOID) {
	                    $NewEKU = [string[]]@($CurrentEKU + $ClientAuthOID)
	                    $null = Set-DomainObject -Identity $TemplateDN -Set @{'pKIExtendedKeyUsage' = $NewEKU} -SearchBase $TemplatesBase
	                    $Modifications += "Added Client Authentication EKU"
	                } else {
	                    $Modifications += "Client Authentication EKU already present (no change)"
	                }
	            }
	        }
	        if ($RemoveEKU) {
	            if ($PSCmdlet.ShouldProcess($TemplateName, "Remove EKU: $RemoveEKU") -eq $true) {
	                $CurrentEKU = @()
	                if ($TemplateInfo.pKIExtendedKeyUsage) {
	                    $ekuValue = $TemplateInfo.pKIExtendedKeyUsage
	                    if ($ekuValue -is [System.Array]) {
	                        $CurrentEKU = @($ekuValue | ForEach-Object { [string]$_ })
	                    }
	                    else {
	                        $CurrentEKU = @([string]$ekuValue)
	                    }
	                }
	                if ($CurrentEKU -contains $RemoveEKU) {
	                    $NewEKU = [string[]]@($CurrentEKU | Where-Object { $_ -ne $RemoveEKU })
	                    if ($NewEKU.Count -gt 0) {
	                        $null = Set-DomainObject -Identity $TemplateDN -Set @{'pKIExtendedKeyUsage' = $NewEKU} -SearchBase $TemplatesBase
	                    }
	                    else {
	                        $null = Set-DomainObject -Identity $TemplateDN -Clear @('pKIExtendedKeyUsage') -SearchBase $TemplatesBase
	                    }
	                    $Modifications += "Removed EKU: $RemoveEKU"
	                }
	                else {
	                    $Modifications += "EKU $RemoveEKU not present (no change)"
	                }
	            }
	        }
	        if ($AddAnyPurposeEKU) {
	            if ($PSCmdlet.ShouldProcess($TemplateName, "Add Any Purpose EKU (ESC2)") -eq $true) {
	                $AnyPurposeOID = "2.5.29.37.0"
	                $CurrentEKU = @()
	                if ($TemplateInfo.pKIExtendedKeyUsage) {
	                    $ekuValue = $TemplateInfo.pKIExtendedKeyUsage
	                    if ($ekuValue -is [System.Array]) {
	                        $CurrentEKU = @($ekuValue | ForEach-Object { [string]$_ })
	                    }
	                    else {
	                        $CurrentEKU = @([string]$ekuValue)
	                    }
	                }
	                if ($CurrentEKU -notcontains $AnyPurposeOID) {
	                    $NewEKU = [string[]]@($CurrentEKU + $AnyPurposeOID)
	                    $null = Set-DomainObject -Identity $TemplateDN -Set @{'pKIExtendedKeyUsage' = $NewEKU} -SearchBase $TemplatesBase
	                    $Modifications += "Added Any Purpose EKU (2.5.29.37.0) - ESC2"
	                }
	                else {
	                    $Modifications += "Any Purpose EKU already present (no change)"
	                }
	            }
	        }
	        if ($ClearEKUs) {
	            if ($PSCmdlet.ShouldProcess($TemplateName, "Clear all EKUs (ESC2 variant)") -eq $true) {
	                $CurrentEKU = @()
	                if ($TemplateInfo.pKIExtendedKeyUsage) {
	                    $ekuValue = $TemplateInfo.pKIExtendedKeyUsage
	                    if ($ekuValue -is [System.Array]) {
	                        $CurrentEKU = @($ekuValue | ForEach-Object { [string]$_ })
	                    }
	                    else {
	                        $CurrentEKU = @([string]$ekuValue)
	                    }
	                }
	                if ($CurrentEKU.Count -gt 0) {
	                    $null = Set-DomainObject -Identity $TemplateDN -Clear @('pKIExtendedKeyUsage') -SearchBase $TemplatesBase
	                    $Modifications += "Cleared all EKUs ($($CurrentEKU.Count) removed) - ESC2 variant"
	                }
	                else {
	                    $Modifications += "No EKUs present (no change)"
	                }
	            }
	        }
	        if ($AddSmartcardLogon) {
	            if ($PSCmdlet.ShouldProcess($TemplateName, "Add Smartcard Logon EKU") -eq $true) {
	                $SmartcardLogonOID = "1.3.6.1.4.1.311.20.2.2"
	                $CurrentEKU = @()
	                if ($TemplateInfo.pKIExtendedKeyUsage) {
	                    $ekuValue = $TemplateInfo.pKIExtendedKeyUsage
	                    if ($ekuValue -is [System.Array]) {
	                        $CurrentEKU = @($ekuValue | ForEach-Object { [string]$_ })
	                    }
	                    else {
	                        $CurrentEKU = @([string]$ekuValue)
	                    }
	                }
	                if ($CurrentEKU -notcontains $SmartcardLogonOID) {
	                    $NewEKU = [string[]]@($CurrentEKU + $SmartcardLogonOID)
	                    $null = Set-DomainObject -Identity $TemplateDN -Set @{'pKIExtendedKeyUsage' = $NewEKU} -SearchBase $TemplatesBase
	                    $Modifications += "Added Smartcard Logon EKU (1.3.6.1.4.1.311.20.2.2) for PKINIT"
	                }
	                else {
	                    $Modifications += "Smartcard Logon EKU already present (no change)"
	                }
	            }
	        }
	        if ($GrantEnrollment -or $GrantFullControl -or $GrantWrite -or $RevokeEnrollment -or $SetOwner -or $GrantAutoEnroll) {
	            $CurrentRevision = if ($TemplateInfo.revision) {
	                [int]$TemplateInfo.revision
	            } else { 0 }
	            $NewRevision = $CurrentRevision + 1
	            $null = Set-DomainObject -Identity $TemplateDN -Set @{'revision' = $NewRevision} -SearchBase $TemplatesBase
	        }
	        if ($GrantEnrollment -or $GrantFullControl -or $GrantWrite -or $RevokeEnrollment -or $SetOwner -or $GrantAutoEnroll) {
	            if ($GrantEnrollment) {
	                if ($PSCmdlet.ShouldProcess($TemplateName, "Grant Certificate-Enrollment to $GrantEnrollment") -eq $true) {
	                    try {
	                        $result = Set-DomainObject -Identity $TemplateDN `
	                                                    -GrantACE `
	                                                    -Principal $GrantEnrollment `
	                                                    -ExtendedRight 'CertEnroll' `
	                                                    -SearchBase $TemplatesBase `
	                                                    -ErrorAction Stop
	                        if ($result) {
	                            $Modifications += "Granted Certificate-Enrollment to $GrantEnrollment"
	                        }
	                        else {
	                            Write-Warning "[Set-CertificateTemplate] ACL modification failed - this may be an AD CS LDAP limitation"
	                            Write-Warning "[Set-CertificateTemplate] Try using LDAPS (-UseLDAPS) or use certutil.exe for ACL modifications"
	                            $Modifications += "Failed to grant Certificate-Enrollment (LDAP constraint)"
	                        }
	                    }
	                    catch {
	                        Write-Warning "[Set-CertificateTemplate] Failed to grant Certificate-Enrollment: $_"
	                        Write-Warning "[Set-CertificateTemplate] Certificate template ACL modifications via LDAP may require LDAPS"
	                        $Modifications += "Failed to grant Certificate-Enrollment to $GrantEnrollment"
	                    }
	                }
	            }
	            if ($GrantFullControl) {
	                if ($PSCmdlet.ShouldProcess($TemplateName, "Grant Full Control to $GrantFullControl") -eq $true) {
	                    try {
	                        $result = Set-DomainObject -Identity $TemplateDN `
	                                                   -GrantACE `
	                                                   -Principal $GrantFullControl `
	                                                   -Rights 'GenericAll' `
	                                                   -SearchBase $TemplatesBase `
	                                                   -ErrorAction Stop
	                        if ($result) {
	                            $Modifications += "Granted Full Control to $GrantFullControl"
	                        }
	                        else {
	                            Write-Warning "[Set-CertificateTemplate] ACL modification failed - this may be an AD CS LDAP limitation"
	                            $Modifications += "Failed to grant Full Control (LDAP constraint)"
	                        }
	                    }
	                    catch {
	                        Write-Warning "[Set-CertificateTemplate] Failed to grant Full Control: $_"
	                        $Modifications += "Failed to grant Full Control to $GrantFullControl"
	                    }
	                }
	            }
	            if ($GrantWrite) {
	                if ($PSCmdlet.ShouldProcess($TemplateName, "Grant WriteProperty to $GrantWrite") -eq $true) {
	                    try {
	                        $result = Set-DomainObject -Identity $TemplateDN `
	                                                   -GrantACE `
	                                                   -Principal $GrantWrite `
	                                                   -Rights 'WriteProperty' `
	                                                   -SearchBase $TemplatesBase `
	                                                   -ErrorAction Stop
	                        if ($result) {
	                            $Modifications += "Granted WriteProperty to $GrantWrite"
	                        }
	                        else {
	                            Write-Warning "[Set-CertificateTemplate] ACL modification failed - this may be an AD CS LDAP limitation"
	                            $Modifications += "Failed to grant WriteProperty (LDAP constraint)"
	                        }
	                    }
	                    catch {
	                        Write-Warning "[Set-CertificateTemplate] Failed to grant WriteProperty: $_"
	                        $Modifications += "Failed to grant WriteProperty to $GrantWrite"
	                    }
	                }
	            }
	            if ($RevokeEnrollment) {
	                if ($PSCmdlet.ShouldProcess($TemplateName, "Revoke Certificate-Enrollment from $RevokeEnrollment") -eq $true) {
	                    try {
	                        $result = Set-DomainObject -Identity $TemplateDN `
	                                                   -RevokeACE `
	                                                   -Principal $RevokeEnrollment `
	                                                   -ExtendedRight 'CertEnroll' `
	                                                   -SearchBase $TemplatesBase `
	                                                   -ErrorAction Stop
	                        if ($result) {
	                            $Modifications += "Revoked Certificate-Enrollment from $RevokeEnrollment"
	                        }
	                        else {
	                            Write-Warning "[Set-CertificateTemplate] ACL modification failed - this may be an AD CS LDAP limitation"
	                            $Modifications += "Failed to revoke Certificate-Enrollment (LDAP constraint)"
	                        }
	                    }
	                    catch {
	                        Write-Warning "[Set-CertificateTemplate] Failed to revoke Certificate-Enrollment: $_"
	                        $Modifications += "Failed to revoke Certificate-Enrollment from $RevokeEnrollment"
	                    }
	                }
	            }
	            if ($SetOwner) {
	                if ($PSCmdlet.ShouldProcess($TemplateName, "Set Owner to $SetOwner") -eq $true) {
	                    try {
	                        $result = Set-DomainObject -Identity $TemplateDN `
	                                                   -SetOwner `
	                                                   -Principal $SetOwner `
	                                                   -SearchBase $TemplatesBase `
	                                                   -ErrorAction Stop
	                        if ($result) {
	                            $Modifications += "Changed owner to $SetOwner"
	                        }
	                        else {
	                            Write-Warning "[Set-CertificateTemplate] Owner modification failed - this may require TakeOwnership permission"
	                            $Modifications += "Failed to change owner (insufficient permissions)"
	                        }
	                    }
	                    catch {
	                        Write-Warning "[Set-CertificateTemplate] Failed to change owner: $_"
	                        $Modifications += "Failed to change owner to $SetOwner"
	                    }
	                }
	            }
	            if ($GrantAutoEnroll) {
	                if ($PSCmdlet.ShouldProcess($TemplateName, "Grant Certificate-AutoEnrollment to $GrantAutoEnroll") -eq $true) {
	                    try {
	                        $result = Set-DomainObject -Identity $TemplateDN `
	                                                   -GrantACE `
	                                                   -Principal $GrantAutoEnroll `
	                                                   -ExtendedRight 'CertAutoEnroll' `
	                                                   -SearchBase $TemplatesBase `
	                                                   -ErrorAction Stop
	                        if ($result) {
	                            $Modifications += "Granted Certificate-AutoEnrollment to $GrantAutoEnroll"
	                        }
	                        else {
	                            Write-Warning "[Set-CertificateTemplate] ACL modification failed - this may be an AD CS LDAP limitation"
	                            $Modifications += "Failed to grant Certificate-AutoEnrollment (LDAP constraint)"
	                        }
	                    }
	                    catch {
	                        Write-Warning "[Set-CertificateTemplate] Failed to grant Certificate-AutoEnrollment: $_"
	                        $Modifications += "Failed to grant Certificate-AutoEnrollment to $GrantAutoEnroll"
	                    }
	                }
	            }
	        }
	        $ACLModificationsMade = ($GrantEnrollment -or $GrantFullControl -or $GrantWrite -or $RevokeEnrollment -or $SetOwner -or $GrantAutoEnroll)
	        if ($Modifications.Count -gt 0 -and -not $ACLModificationsMade) {
	            $CurrentRevision = if ($TemplateInfo.revision) {
	                [int]$TemplateInfo.revision
	            } else { 0 }
	            $NewRevision = $CurrentRevision + 1
	            $null = Set-DomainObject -Identity $TemplateDN -Set @{'revision' = $NewRevision} -SearchBase $TemplatesBase
	        }
	        Show-Line "Template modified successfully: $TemplateName" -Class Hint
	        Show-Line "Modifications applied: $($Modifications -join ', ')"
	        Get-CertificateTemplate -Identity $Identity -ShowAll
	    } catch {
	        $ErrorMessage = $_.Exception.Message
	        if ($ErrorMessage -match "Insufficient permissions to modify template") {
	            Write-Warning "[!] $ErrorMessage"
	            throw
	        }
	        if ($ErrorMessage -match "Access is denied|Insufficient rights|UnauthorizedAccessException") {
	            Show-Error -Type Permission -Message "modify template" -Target $Identity -Reason $ErrorMessage
	        }
	        elseif ($ErrorMessage -match "not found|does not exist") {
	            Show-Error -Type NotFound -Message "Certificate template" -Target $Identity
	        }
	        else {
	            Show-Error -Type Operation -Message "Failed to modify template" -Target $Identity -Reason $ErrorMessage
	        }
	        return $null
	    }
	}
	end {
	}
}
function Set-DomainUser {
	[CmdletBinding(DefaultParameterSetName='SetPassword')]
	param(
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetPassword')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ChangePassword')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetOwner')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='GrantRights')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetRBCD')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearRBCD')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='AddShadowCredential')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearShadowCredentials')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetSPN')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearSPN')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetDontReqPreauth')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearDontReqPreauth')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='EnableAccount')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='DisableAccount')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='UnlockAccount')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetPasswordNotRequired')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearPasswordNotRequired')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetPasswordCantChange')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearPasswordCantChange')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetReversibleEncryption')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearReversibleEncryption')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetPasswordNeverExpires')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearPasswordNeverExpires')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetSmartcardRequired')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearSmartcardRequired')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetNotDelegated')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearNotDelegated')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetPasswordExpired')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearPasswordExpired')]
	    [Alias('samAccountName', 'User')]
	    [string]$Identity,
	    [Parameter(ParameterSetName='SetPassword', Mandatory=$true)]
	    [Parameter(ParameterSetName='ChangePassword', Mandatory=$true)]
	    [string]$NewPassword,
	    [Parameter(ParameterSetName='ChangePassword', Mandatory=$true)]
	    [string]$OldPassword,
	    [Parameter(ParameterSetName='SetOwner', Mandatory=$true)]
	    [string]$Owner,
	    [Parameter(ParameterSetName='GrantRights', Mandatory=$true)]
	    [ValidateSet('GenericAll','GenericWrite','ResetPassword','WriteDacl','WriteOwner')]
	    [string]$GrantRights,
	    [Parameter(ParameterSetName='GrantRights', Mandatory=$true)]
	    [Parameter(ParameterSetName='ClearRBCD', Mandatory=$false)]
	    [string]$Principal,
	    [Parameter(ParameterSetName='SetRBCD', Mandatory=$true)]
	    [string]$AddRBCD,
	    [Parameter(ParameterSetName='ClearRBCD', Mandatory=$true)]
	    [switch]$ClearRBCD,
	    [Parameter(ParameterSetName='AddShadowCredential', Mandatory=$true)]
	    [switch]$AddShadowCredential,
	    [Parameter(ParameterSetName='ClearShadowCredentials', Mandatory=$true)]
	    [switch]$ClearShadowCredentials,
	    [Parameter(ParameterSetName='AddShadowCredential', Mandatory=$false)]
	    [Parameter(ParameterSetName='ClearShadowCredentials', Mandatory=$false)]
	    [string]$DeviceID,
	    [Parameter(ParameterSetName='AddShadowCredential', Mandatory=$false)]
	    [switch]$NoPassword,
	    [Parameter(ParameterSetName='ClearRBCD', Mandatory=$false)]
	    [Parameter(ParameterSetName='ClearShadowCredentials', Mandatory=$false)]
	    [Parameter(ParameterSetName='ClearSPN', Mandatory=$false)]
	    [switch]$Force,
	    [Parameter(ParameterSetName='SetSPN', Mandatory=$true)]
	    [string]$SetSPN,
	    [Parameter(ParameterSetName='ClearSPN', Mandatory=$true)]
	    [string]$ClearSPN,
	    [Parameter(ParameterSetName='SetDontReqPreauth', Mandatory=$true)]
	    [switch]$DontReqPreauth,
	    [Parameter(ParameterSetName='ClearDontReqPreauth', Mandatory=$true)]
	    [switch]$ClearDontReqPreauth,
	    [Parameter(ParameterSetName='EnableAccount', Mandatory=$true)]
	    [switch]$Enable,
	    [Parameter(ParameterSetName='DisableAccount', Mandatory=$true)]
	    [switch]$Disable,
	    [Parameter(ParameterSetName='UnlockAccount', Mandatory=$true)]
	    [switch]$Unlock,
	    [Parameter(ParameterSetName='SetPasswordNotRequired', Mandatory=$true)]
	    [switch]$PasswordNotRequired,
	    [Parameter(ParameterSetName='ClearPasswordNotRequired', Mandatory=$true)]
	    [switch]$ClearPasswordNotRequired,
	    [Parameter(ParameterSetName='SetPasswordCantChange', Mandatory=$true)]
	    [switch]$PasswordCantChange,
	    [Parameter(ParameterSetName='ClearPasswordCantChange', Mandatory=$true)]
	    [switch]$ClearPasswordCantChange,
	    [Parameter(ParameterSetName='SetReversibleEncryption', Mandatory=$true)]
	    [switch]$ReversibleEncryption,
	    [Parameter(ParameterSetName='ClearReversibleEncryption', Mandatory=$true)]
	    [switch]$ClearReversibleEncryption,
	    [Parameter(ParameterSetName='SetPasswordNeverExpires', Mandatory=$true)]
	    [switch]$PasswordNeverExpires,
	    [Parameter(ParameterSetName='ClearPasswordNeverExpires', Mandatory=$true)]
	    [switch]$ClearPasswordNeverExpires,
	    [Parameter(ParameterSetName='SetSmartcardRequired', Mandatory=$true)]
	    [switch]$SmartcardRequired,
	    [Parameter(ParameterSetName='ClearSmartcardRequired', Mandatory=$true)]
	    [switch]$ClearSmartcardRequired,
	    [Parameter(ParameterSetName='SetNotDelegated', Mandatory=$true)]
	    [switch]$NotDelegated,
	    [Parameter(ParameterSetName='ClearNotDelegated', Mandatory=$true)]
	    [switch]$ClearNotDelegated,
	    [Parameter(ParameterSetName='SetPasswordExpired', Mandatory=$true)]
	    [switch]$PasswordExpired,
	    [Parameter(ParameterSetName='ClearPasswordExpired', Mandatory=$true)]
	    [switch]$ClearPasswordExpired,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [switch]$PassThru,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential
	)
	begin {
	}
	process {
	    $ConnectionParams = @{}
	    if ($Domain) { $ConnectionParams['Domain'] = $Domain }
	    if ($Server) { $ConnectionParams['Server'] = $Server }
	    if ($Credential) { $ConnectionParams['Credential'] = $Credential }
	    if (-not (Ensure-LDAPConnection @ConnectionParams)) {
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = $PSCmdlet.ParameterSetName
	                User = $Identity
	                Success = $false
	                Message = "No LDAP connection available"
	            }
	        }
	        return
	    }
	    try {
	        $TargetUser = @(Get-DomainUser -Identity $Identity @ConnectionParams)[0]
	        if (-not $TargetUser) {
	            throw "User '$Identity' not Found"
	        }
	        $UserDN = $TargetUser.distinguishedName
	        $UserEntry = $null
	        switch ($PSCmdlet.ParameterSetName) {
	            'SetPassword' {
	                $PasswordSet = $false
	                $primaryError = $null
	                try {
	                    $quotedPwd = '"' + $NewPassword + '"'
	                    $pwdBytes = [System.Text.Encoding]::Unicode.GetBytes($quotedPwd)
	                    $PwdModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                    $PwdModifyRequest.DistinguishedName = $UserDN
	                    $PwdMod = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                    $PwdMod.Name = "unicodePwd"
	                    $PwdMod.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                    $PwdMod.Add($pwdBytes) | Out-Null
	                    $PwdModifyRequest.Modifications.Add($PwdMod) | Out-Null
	                    $PwdResponse = $Script:LdapConnection.SendRequest($PwdModifyRequest)
	                    if ($PwdResponse.ResultCode -eq [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                        $PasswordSet = $true
	                    }
	                }
	                catch {
	                    $primaryError = $_.Exception.Message
	                }
	                if (-not $PasswordSet) {
	                    if (-not $Credential -and -not $Script:LDAPCredential) {
	                        Write-Warning "[Set-DomainUser] DirectoryEntry fallback uses current Windows user context, not the Kerberos-authenticated session identity. Password operation may fail or use wrong identity."
	                    }
	                    $UserEntry = Get-AuthenticatedDirectoryEntry -DistinguishedName $UserDN -Credential $Credential
	                    if (-not $UserEntry) { throw "Failed to get DirectoryEntry for password reset" }
	                    try {
	                        $UserEntry.Invoke("SetPassword", $NewPassword)
	                        $UserEntry.CommitChanges()
	                        $PasswordSet = $true
	                    }
	                    catch {
	                        $errorMsg = "Failed to reset password."
	                        if ($primaryError) {
	                            $errorMsg += " LDAP: $primaryError"
	                        }
	                        $errorMsg += " ADSI fallback: $_"
	                        throw $errorMsg
	                    }
	                }
	                if ($PassThru) {
	                    return [PSCustomObject]@{
	                        Operation = "PasswordReset"
	                        User = $TargetUser.sAMAccountName
	                        DistinguishedName = $UserDN
	                        Success = $true
	                        Message = "Password successfully reset"
	                    }
	                } else {
	                    Show-Line "Successfully reset password for user: $($TargetUser.sAMAccountName)" -Class Hint
	                }
	            }
	            'ChangePassword' {
	                $PasswordChanged = $false
	                $primaryError = $null
	                try {
	                    $quotedOld = '"' + $OldPassword + '"'
	                    $quotedNew = '"' + $NewPassword + '"'
	                    $oldPwdBytes = [System.Text.Encoding]::Unicode.GetBytes($quotedOld)
	                    $newPwdBytes = [System.Text.Encoding]::Unicode.GetBytes($quotedNew)
	                    $ChgModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                    $ChgModifyRequest.DistinguishedName = $UserDN
	                    $DelMod = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                    $DelMod.Name = "unicodePwd"
	                    $DelMod.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	                    $DelMod.Add($oldPwdBytes) | Out-Null
	                    $ChgModifyRequest.Modifications.Add($DelMod) | Out-Null
	                    $AddMod = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                    $AddMod.Name = "unicodePwd"
	                    $AddMod.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Add
	                    $AddMod.Add($newPwdBytes) | Out-Null
	                    $ChgModifyRequest.Modifications.Add($AddMod) | Out-Null
	                    $ChgResponse = $Script:LdapConnection.SendRequest($ChgModifyRequest)
	                    if ($ChgResponse.ResultCode -eq [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                        $PasswordChanged = $true
	                    }
	                }
	                catch {
	                    $primaryError = $_.Exception.Message
	                }
	                if (-not $PasswordChanged) {
	                    if (-not $Credential -and -not $Script:LDAPCredential) {
	                        Write-Warning "[Set-DomainUser] DirectoryEntry fallback uses current Windows user context, not the Kerberos-authenticated session identity. Password operation may fail or use wrong identity."
	                    }
	                    $UserEntry = Get-AuthenticatedDirectoryEntry -DistinguishedName $UserDN -Credential $Credential
	                    if (-not $UserEntry) { throw "Failed to get DirectoryEntry for password change" }
	                    try {
	                        $UserEntry.Invoke("ChangePassword", @($OldPassword, $NewPassword))
	                        $UserEntry.CommitChanges()
	                        $PasswordChanged = $true
	                    }
	                    catch {
	                        $errorMsg = "Failed to change password."
	                        if ($primaryError) {
	                            $errorMsg += " LDAP: $primaryError"
	                        }
	                        $errorMsg += " ADSI fallback: $_. Verify the old password is correct and the new password meets the domain password policy."
	                        throw $errorMsg
	                    }
	                }
	                if ($PassThru) {
	                    return [PSCustomObject]@{
	                        Operation = "PasswordChange"
	                        User = $TargetUser.sAMAccountName
	                        DistinguishedName = $UserDN
	                        Success = $true
	                        Message = "Password successfully changed"
	                    }
	                } else {
	                    Show-Line "Successfully changed password for user: $($TargetUser.sAMAccountName)" -Class Hint
	                }
	            }
	            'SetOwner' {
	                try {
	                    $Result = Set-DomainObject -Identity $UserDN -SetOwner -Principal $Owner @ConnectionParams
	                    if ($Result) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetOwner"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                NewOwner = $Owner
	                                Success = $true
	                                Message = "Owner successfully changed"
	                            }
	                        } else {
	                            Show-Line "Successfully changed owner of $($TargetUser.sAMAccountName) to: $Owner" -Class Hint
	                        }
	                    } else {
	                        throw "Set-DomainObject returned false"
	                    }
	                } catch {
	                    throw "Failed to set owner: $_"
	                }
	            }
	            'GrantRights' {
	                try {
	                    $Result = switch ($GrantRights) {
	                        'GenericAll'    { Set-DomainObject -Identity $UserDN -GrantACE -Principal $Principal -Rights GenericAll @ConnectionParams }
	                        'GenericWrite'  { Set-DomainObject -Identity $UserDN -GrantACE -Principal $Principal -Rights GenericWrite @ConnectionParams }
	                        'WriteDacl'     { Set-DomainObject -Identity $UserDN -GrantACE -Principal $Principal -Rights WriteDacl @ConnectionParams }
	                        'WriteOwner'    { Set-DomainObject -Identity $UserDN -GrantACE -Principal $Principal -Rights WriteOwner @ConnectionParams }
	                        'ResetPassword' { Set-DomainObject -Identity $UserDN -GrantACE -Principal $Principal -ExtendedRight ForceChangePassword @ConnectionParams }
	                    }
	                    if ($Result) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "GrantRights"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                Principal = $Principal
	                                Rights = $GrantRights
	                                Success = $true
	                                Message = "Rights successfully granted"
	                            }
	                        } else {
	                            Show-Line "Successfully granted $GrantRights to $Principal on: $($TargetUser.sAMAccountName)" -Class Hint
	                        }
	                    } else {
	                        throw "Set-DomainObject returned false"
	                    }
	                } catch {
	                    throw "Failed to grant rights: $_"
	                }
	            }
	            'SetRBCD' {
	                $result = Invoke-RBCDOperation -TargetDN $UserDN -TargetSAMAccountName $TargetUser.sAMAccountName -TargetType 'User' -AddRBCD $AddRBCD -PassThru:$PassThru -ConnectionParams $ConnectionParams
	                if ($PassThru -and $result) {
	                    return $result
	                }
	            }
	            'ClearRBCD' {
	                $result = Invoke-RBCDOperation -TargetDN $UserDN -TargetSAMAccountName $TargetUser.sAMAccountName -TargetType 'User' -ClearRBCD -Principal $Principal -Force:$Force -PassThru:$PassThru -ConnectionParams $ConnectionParams
	                if ($PassThru -and $result) {
	                    return $result
	                }
	            }
	            'AddShadowCredential' {
	                $UserUPN = if ($TargetUser.userPrincipalName) {
	                    $TargetUser.userPrincipalName
	                } else {
	                    "$($TargetUser.sAMAccountName)@$($Script:LDAPContext.Domain.ToUpper())"
	                }
	                $result = Invoke-ShadowCredentialOperation -TargetDN $UserDN -TargetSAMAccountName $TargetUser.sAMAccountName -TargetType 'User' -TargetUPN $UserUPN -AddShadowCredential -DeviceID $DeviceID -NoPassword:$NoPassword -PassThru:$PassThru
	                if ($PassThru -and $result) {
	                    return $result
	                }
	            }
	            'ClearShadowCredentials' {
	                $result = Invoke-ShadowCredentialOperation -TargetDN $UserDN -TargetSAMAccountName $TargetUser.sAMAccountName -TargetType 'User' -ClearShadowCredentials -DeviceID $DeviceID -Force:$Force -PassThru:$PassThru
	                if ($PassThru -and $result) {
	                    return $result
	                }
	            }
	            'SetSPN' {
	                try {
	                    $CurrentSPNs = @()
	                    if ($TargetUser.servicePrincipalName) {
	                        $spnValue = $TargetUser.servicePrincipalName
	                        if ($spnValue -is [System.Array]) {
	                            $CurrentSPNs = @($spnValue | ForEach-Object { [string]$_ })
	                        }
	                        else {
	                            $CurrentSPNs = @([string]$spnValue)
	                        }
	                    }
	                    if ($CurrentSPNs -contains $SetSPN) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetSPN"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                SPN = $SetSPN
	                                Success = $true
	                                Message = "SPN already present (no change)"
	                            }
	                        } else {
	                            Show-Line "SPN '$SetSPN' already present on: $($TargetUser.sAMAccountName)" -Class Note
	                        }
	                    }
	                    else {
	                        $NewSPNs = [string[]]@($CurrentSPNs + $SetSPN)
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $UserDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "servicePrincipalName"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        foreach ($spn in $NewSPNs) {
	                            $Modification.Add($spn) | Out-Null
	                        }
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetSPN"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                SPN = $SetSPN
	                                AllSPNs = $NewSPNs
	                                Success = $true
	                                Message = "SPN added - user is now Kerberoastable"
	                            }
	                        } else {
	                            Show-Line "Successfully added SPN '$SetSPN' to: $($TargetUser.sAMAccountName)" -Class Hint
	                            Show-Line "User is now Kerberoastable!" -Class Finding
	                        }
	                    }
	                } catch {
	                    throw "Failed to set SPN: $_"
	                }
	            }
	            'ClearSPN' {
	                try {
	                    $CurrentSPNs = @()
	                    if ($TargetUser.servicePrincipalName) {
	                        $spnValue = $TargetUser.servicePrincipalName
	                        if ($spnValue -is [System.Array]) {
	                            $CurrentSPNs = @($spnValue | ForEach-Object { [string]$_ })
	                        }
	                        else {
	                            $CurrentSPNs = @([string]$spnValue)
	                        }
	                    }
	                    if ($CurrentSPNs.Count -eq 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearSPN"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                Success = $true
	                                Message = "No SPNs present (no change)"
	                            }
	                        } else {
	                            Show-Line "No SPNs present on: $($TargetUser.sAMAccountName)" -Class Note
	                        }
	                    }
	                    elseif ($Force) {
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $UserDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "servicePrincipalName"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearSPN"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                RemovedSPNs = $CurrentSPNs
	                                Success = $true
	                                Message = "All $($CurrentSPNs.Count) SPN(s) removed"
	                            }
	                        } else {
	                            Show-Line "Successfully removed all $($CurrentSPNs.Count) SPN(s) from: $($TargetUser.sAMAccountName)" -Class Hint
	                        }
	                    }
	                    elseif ($CurrentSPNs -contains $ClearSPN) {
	                        $NewSPNs = [string[]]@($CurrentSPNs | Where-Object { $_ -ne $ClearSPN })
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $UserDN
	                        if ($NewSPNs.Count -eq 0) {
	                            $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                            $Modification.Name = "servicePrincipalName"
	                            $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	                        } else {
	                            $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                            $Modification.Name = "servicePrincipalName"
	                            $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                            foreach ($spn in $NewSPNs) {
	                                $Modification.Add($spn) | Out-Null
	                            }
	                        }
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearSPN"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                RemovedSPN = $ClearSPN
	                                RemainingSPNs = $NewSPNs
	                                Success = $true
	                                Message = "SPN removed"
	                            }
	                        } else {
	                            Show-Line "Successfully removed SPN '$ClearSPN' from: $($TargetUser.sAMAccountName)" -Class Hint
	                        }
	                    }
	                    else {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearSPN"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                Success = $false
	                                Message = "SPN '$ClearSPN' not found on user. Use -Force to remove all SPNs."
	                            }
	                        } else {
	                            Show-Line "SPN '$ClearSPN' not found on: $($TargetUser.sAMAccountName)" -Class Note
	                            Show-Line "Current SPNs: $($CurrentSPNs -join ', ')" -Class Note
	                            Show-Line "Use -Force to remove all SPNs" -Class Note
	                        }
	                    }
	                } catch {
	                    throw "Failed to clear SPN: $_"
	                }
	            }
	            'SetDontReqPreauth' {
	                try {
	                    $CurrentUAC = if ($TargetUser.userAccountControl) {
	                        [int]$TargetUser.userAccountControl
	                    } else { 512 }  # Default: NORMAL_ACCOUNT
	                    $DONT_REQ_PREAUTH = 0x400000
	                    if (($CurrentUAC -band $DONT_REQ_PREAUTH) -ne 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetDontReqPreauth"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                Success = $true
	                                Message = "DONT_REQ_PREAUTH already set (no change)"
	                            }
	                        } else {
	                            Show-Line "DONT_REQ_PREAUTH already set on: $($TargetUser.sAMAccountName)" -Class Note
	                        }
	                    }
	                    else {
	                        $NewUAC = $CurrentUAC -bor $DONT_REQ_PREAUTH
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $UserDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "userAccountControl"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add([string]$NewUAC) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetDontReqPreauth"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                OldUAC = $CurrentUAC
	                                NewUAC = $NewUAC
	                                Success = $true
	                                Message = "DONT_REQ_PREAUTH flag set - user is now AS-REP roastable!"
	                            }
	                        } else {
	                            Show-Line "Successfully set DONT_REQ_PREAUTH on: $($TargetUser.sAMAccountName)" -Class Hint
	                            Show-Line "User is now ASREPRoastable!" -Class Finding
	                        }
	                    }
	                } catch {
	                    throw "Failed to set DONT_REQ_PREAUTH: $_"
	                }
	            }
	            'ClearDontReqPreauth' {
	                try {
	                    $CurrentUAC = if ($TargetUser.userAccountControl) {
	                        [int]$TargetUser.userAccountControl
	                    } else { 512 }
	                    $DONT_REQ_PREAUTH = 0x400000
	                    if (($CurrentUAC -band $DONT_REQ_PREAUTH) -eq 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearDontReqPreauth"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                Success = $true
	                                Message = "DONT_REQ_PREAUTH already cleared (no change)"
	                            }
	                        } else {
	                            Show-Line "DONT_REQ_PREAUTH already cleared on: $($TargetUser.sAMAccountName)" -Class Note
	                        }
	                    }
	                    else {
	                        $NewUAC = $CurrentUAC -band (-bnot $DONT_REQ_PREAUTH)
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $UserDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "userAccountControl"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add([string]$NewUAC) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearDontReqPreauth"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                OldUAC = $CurrentUAC
	                                NewUAC = $NewUAC
	                                Success = $true
	                                Message = "DONT_REQ_PREAUTH flag cleared - pre-authentication is required again"
	                            }
	                        } else {
	                            Show-Line "Successfully cleared DONT_REQ_PREAUTH on: $($TargetUser.sAMAccountName)" -Class Hint
	                        }
	                    }
	                } catch {
	                    throw "Failed to clear DONT_REQ_PREAUTH: $_"
	                }
	            }
	            'EnableAccount' {
	                try {
	                    $CurrentUAC = if ($TargetUser.userAccountControl) {
	                        [int]$TargetUser.userAccountControl
	                    } else { 512 }
	                    $ACCOUNTDISABLE = 0x2
	                    if (($CurrentUAC -band $ACCOUNTDISABLE) -eq 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "EnableAccount"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                Success = $true
	                                Message = "Account already enabled (no change)"
	                            }
	                        } else {
	                            Show-Line "Account already enabled: $($TargetUser.sAMAccountName)" -Class Note
	                        }
	                    }
	                    else {
	                        $NewUAC = $CurrentUAC -band (-bnot $ACCOUNTDISABLE)
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $UserDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "userAccountControl"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add([string]$NewUAC) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "EnableAccount"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                OldUAC = $CurrentUAC
	                                NewUAC = $NewUAC
	                                Success = $true
	                                Message = "Account enabled"
	                            }
	                        } else {
	                            Show-Line "Successfully enabled account: $($TargetUser.sAMAccountName)" -Class Hint
	                        }
	                    }
	                } catch {
	                    throw "Failed to enable account: $_"
	                }
	            }
	            'DisableAccount' {
	                try {
	                    $CurrentUAC = if ($TargetUser.userAccountControl) {
