	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearSmartcardRequired"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                OldUAC = $CurrentUAC
	                                NewUAC = $NewUAC
	                                Success = $true
	                                Message = "SMARTCARD_REQUIRED flag cleared - smartcard no longer required"
	                            }
	                        } else {
	                            Show-Line "Successfully cleared SMARTCARD_REQUIRED on: $($TargetUser.sAMAccountName)" -Class Hint
	                        }
	                    }
	                } catch {
	                    throw "Failed to clear SMARTCARD_REQUIRED: $_"
	                }
	            }
	            'SetNotDelegated' {
	                try {
	                    $CurrentUAC = if ($TargetUser.userAccountControl) { [int]$TargetUser.userAccountControl } else { 512 }
	                    $NOT_DELEGATED = 0x100000
	                    if (($CurrentUAC -band $NOT_DELEGATED) -ne 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetNotDelegated"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                Success = $true
	                                Message = "NOT_DELEGATED already set (no change)"
	                            }
	                        } else {
	                            Show-Line "NOT_DELEGATED already set on: $($TargetUser.sAMAccountName)" -Class Note
	                        }
	                    } else {
	                        $NewUAC = $CurrentUAC -bor $NOT_DELEGATED
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $UserDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "userAccountControl"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add([string]$NewUAC) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetNotDelegated"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                OldUAC = $CurrentUAC
	                                NewUAC = $NewUAC
	                                Success = $true
	                                Message = "NOT_DELEGATED flag set - account marked as sensitive"
	                            }
	                        } else {
	                            Show-Line "Successfully set NOT_DELEGATED on: $($TargetUser.sAMAccountName)" -Class Hint
	                        }
	                    }
	                } catch {
	                    throw "Failed to set NOT_DELEGATED: $_"
	                }
	            }
	            'ClearNotDelegated' {
	                try {
	                    $CurrentUAC = if ($TargetUser.userAccountControl) { [int]$TargetUser.userAccountControl } else { 512 }
	                    $NOT_DELEGATED = 0x100000
	                    if (($CurrentUAC -band $NOT_DELEGATED) -eq 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearNotDelegated"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                Success = $true
	                                Message = "NOT_DELEGATED already cleared (no change)"
	                            }
	                        } else {
	                            Show-Line "NOT_DELEGATED already cleared on: $($TargetUser.sAMAccountName)" -Class Note
	                        }
	                    } else {
	                        $NewUAC = $CurrentUAC -band (-bnot $NOT_DELEGATED)
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $UserDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "userAccountControl"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add([string]$NewUAC) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearNotDelegated"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                OldUAC = $CurrentUAC
	                                NewUAC = $NewUAC
	                                Success = $true
	                                Message = "NOT_DELEGATED flag cleared - account can be delegated again"
	                            }
	                        } else {
	                            Show-Line "Successfully cleared NOT_DELEGATED on: $($TargetUser.sAMAccountName)" -Class Hint
	                        }
	                    }
	                } catch {
	                    throw "Failed to clear NOT_DELEGATED: $_"
	                }
	            }
	            'SetPasswordExpired' {
	                try {
	                    $CurrentUAC = if ($TargetUser.userAccountControl) { [int]$TargetUser.userAccountControl } else { 512 }
	                    $PASSWORD_EXPIRED = 0x800000
	                    if (($CurrentUAC -band $PASSWORD_EXPIRED) -ne 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetPasswordExpired"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                Success = $true
	                                Message = "PASSWORD_EXPIRED already set (no change)"
	                            }
	                        } else {
	                            Show-Line "PASSWORD_EXPIRED already set on: $($TargetUser.sAMAccountName)" -Class Note
	                        }
	                    } else {
	                        $NewUAC = $CurrentUAC -bor $PASSWORD_EXPIRED
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $UserDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "userAccountControl"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add([string]$NewUAC) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetPasswordExpired"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                OldUAC = $CurrentUAC
	                                NewUAC = $NewUAC
	                                Success = $true
	                                Message = "PASSWORD_EXPIRED flag set"
	                            }
	                        } else {
	                            Show-Line "Successfully set PASSWORD_EXPIRED on: $($TargetUser.sAMAccountName)" -Class Hint
	                        }
	                    }
	                } catch {
	                    throw "Failed to set PASSWORD_EXPIRED: $_"
	                }
	            }
	            'ClearPasswordExpired' {
	                try {
	                    $CurrentUAC = if ($TargetUser.userAccountControl) { [int]$TargetUser.userAccountControl } else { 512 }
	                    $PASSWORD_EXPIRED = 0x800000
	                    if (($CurrentUAC -band $PASSWORD_EXPIRED) -eq 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearPasswordExpired"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                Success = $true
	                                Message = "PASSWORD_EXPIRED already cleared (no change)"
	                            }
	                        } else {
	                            Show-Line "PASSWORD_EXPIRED already cleared on: $($TargetUser.sAMAccountName)" -Class Note
	                        }
	                    } else {
	                        $NewUAC = $CurrentUAC -band (-bnot $PASSWORD_EXPIRED)
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $UserDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "userAccountControl"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add([string]$NewUAC) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearPasswordExpired"
	                                User = $TargetUser.sAMAccountName
	                                DistinguishedName = $UserDN
	                                OldUAC = $CurrentUAC
	                                NewUAC = $NewUAC
	                                Success = $true
	                                Message = "PASSWORD_EXPIRED flag cleared"
	                            }
	                        } else {
	                            Show-Line "Successfully cleared PASSWORD_EXPIRED on: $($TargetUser.sAMAccountName)" -Class Hint
	                        }
	                    }
	                } catch {
	                    throw "Failed to clear PASSWORD_EXPIRED: $_"
	                }
	            }
	        }
	    } catch {
	        $UserIdentifier = $Identity
	        $ErrorMsg = $_.Exception.Message
	        if ($PSCmdlet.ParameterSetName -in @('SetPassword', 'ChangePassword') -and $ErrorMsg -match "user name or password is incorrect|password is incorrect") {
	            $ErrorMsg = "Authentication failed for password operation on '$UserIdentifier'. This typically occurs when using a computer account or non-interactive session. Try using explicit credentials with -Credential or -Username/-Password, or use LDAPS (-UseLDAPS) for unicodePwd support."
	        }
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = $PSCmdlet.ParameterSetName
	                User = $UserIdentifier
	                Success = $false
	                Message = $ErrorMsg
	            }
	        } else {
	            Write-Warning "[!] $ErrorMsg"
	        }
	    } finally {
	        if ($UserEntry) {
	            try { $UserEntry.Dispose() } catch { }
	        }
	    }
	}
	end {
	}
}
function Set-DomainGroup {
	[CmdletBinding(DefaultParameterSetName='AddMember')]
	param(
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='AddMember')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='RemoveMember')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearMembers')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetDescription')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearDescription')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ConvertToSecurity')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ConvertToDistribution')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetOwner')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='GrantRights')]
	    [Alias('samAccountName', 'Name', 'Group')]
	    [string]$Identity,
	    [Parameter(ParameterSetName='AddMember', Mandatory=$true)]
	    [string[]]$AddMember,
	    [Parameter(ParameterSetName='RemoveMember', Mandatory=$true)]
	    [string[]]$RemoveMember,
	    [Parameter(ParameterSetName='ClearMembers', Mandatory=$true)]
	    [switch]$ClearMembers,
	    [Parameter(ParameterSetName='SetDescription', Mandatory=$true)]
	    [string]$SetDescription,
	    [Parameter(ParameterSetName='ClearDescription', Mandatory=$true)]
	    [switch]$ClearDescription,
	    [Parameter(ParameterSetName='ConvertToSecurity', Mandatory=$true)]
	    [switch]$ConvertToSecurity,
	    [Parameter(ParameterSetName='ConvertToDistribution', Mandatory=$true)]
	    [switch]$ConvertToDistribution,
	    [Parameter(ParameterSetName='SetOwner', Mandatory=$true)]
	    [string]$Owner,
	    [Parameter(ParameterSetName='GrantRights', Mandatory=$true)]
	    [ValidateSet('GenericAll','GenericWrite','WriteMembers','WriteDacl','WriteOwner')]
	    [string]$GrantRights,
	    [Parameter(ParameterSetName='GrantRights', Mandatory=$true)]
	    [string]$Principal,
	    [Parameter(ParameterSetName='ClearMembers', Mandatory=$false)]
	    [switch]$Force,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [switch]$PassThru,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential
	)
	begin {
	}
	process {
	    $ConnectionParams = @{}
	    if ($Domain) { $ConnectionParams['Domain'] = $Domain }
	    if ($Server) { $ConnectionParams['Server'] = $Server }
	    if ($Credential) { $ConnectionParams['Credential'] = $Credential }
	    if (-not (Ensure-LDAPConnection @ConnectionParams)) {
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = $PSCmdlet.ParameterSetName
	                Group = $Identity
	                Success = $false
	                Message = "No LDAP connection available"
	            }
	        }
	        return
	    }
	    try {
	        $TargetGroup = @(Get-DomainGroup -Identity $Identity @ConnectionParams)[0]
	        if (-not $TargetGroup) {
	            throw "Group '$Identity' not Found"
	        }
	        $GroupDN = $TargetGroup.distinguishedName
	        $ExistingMembersLower = @()
	        if ($TargetGroup.member) {
	            $ExistingMembersLower = @($TargetGroup.member | ForEach-Object { $_.ToLower() })
	        }
	        switch ($PSCmdlet.ParameterSetName) {
	            'AddMember' {
	                $AddedMembers = @()
	                $AddedMemberDNs = @()
	                $SkippedMembers = @()
	                $FailedMembers = @()
	                foreach ($MemberIdentity in $AddMember) {
	                    try {
	                        $MemberObject = @(Get-DomainObject -Identity $MemberIdentity @ConnectionParams)[0]
	                        if (-not $MemberObject) {
	                            throw "Member '$MemberIdentity' not found"
	                        }
	                        $MemberDN = $MemberObject.distinguishedName
	                        if ($ExistingMembersLower -contains $MemberDN.ToLower()) {
	                            $SkippedMembers += $MemberIdentity
	                            continue
	                        }
	                        $AddedMembers += $MemberIdentity
	                        $AddedMemberDNs += $MemberDN
	                    } catch {
	                        Write-Warning "[Set-DomainGroup] Failed to resolve member '$MemberIdentity': $_"
	                        $FailedMembers += $MemberIdentity
	                    }
	                }
	                if ($AddedMembers.Count -gt 0) {
	                    try {
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $GroupDN
	                        foreach ($dn in $AddedMemberDNs) {
	                            $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                            $Modification.Name = "member"
	                            $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Add
	                            $Modification.Add($dn) | Out-Null
	                            $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        }
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if (-not $PassThru) {
	                            $msg = "Successfully added $($AddedMembers.Count) member(s) to: $($TargetGroup.sAMAccountName)"
	                            if ($SkippedMembers.Count -gt 0) {
	                                $msg += " ($($SkippedMembers.Count) already existed)"
	                            }
	                            Show-Line $msg -Class Hint
	                        }
	                    } catch {
	                        throw "Failed to commit changes: $_"
	                    }
	                } elseif ($SkippedMembers.Count -gt 0 -and $FailedMembers.Count -eq 0) {
	                    if (-not $PassThru) {
	                        Show-Line "All $($SkippedMembers.Count) member(s) already exist in: $($TargetGroup.sAMAccountName)" -Class Note
	                    }
	                }
	                if ($PassThru) {
	                    return [PSCustomObject]@{
	                        Operation = "AddMember"
	                        Group = $TargetGroup.sAMAccountName
	                        DistinguishedName = $GroupDN
	                        AddedMembers = $AddedMembers
	                        SkippedMembers = $SkippedMembers
	                        FailedMembers = $FailedMembers
	                        Success = ($FailedMembers.Count -eq 0)
	                        Message = "Added $($AddedMembers.Count), skipped $($SkippedMembers.Count) (already existed), $($FailedMembers.Count) failed"
	                    }
	                }
	            }
	            'RemoveMember' {
	                $RemovedMembers = @()
	                $RemovedMemberDNs = @()
	                $SkippedMembers = @()
	                $FailedMembers = @()
	                foreach ($MemberIdentity in $RemoveMember) {
	                    try {
	                        $MemberObject = @(Get-DomainObject -Identity $MemberIdentity @ConnectionParams)[0]
	                        if (-not $MemberObject) {
	                            throw "Member '$MemberIdentity' not found"
	                        }
	                        $MemberDN = $MemberObject.distinguishedName
	                        if ($ExistingMembersLower -notcontains $MemberDN.ToLower()) {
	                            $SkippedMembers += $MemberIdentity
	                            continue
	                        }
	                        $RemovedMembers += $MemberIdentity
	                        $RemovedMemberDNs += $MemberDN
	                    } catch {
	                        Write-Warning "[Set-DomainGroup] Failed to resolve member '$MemberIdentity': $_"
	                        $FailedMembers += $MemberIdentity
	                    }
	                }
	                if ($RemovedMembers.Count -gt 0) {
	                    try {
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $GroupDN
	                        foreach ($dn in $RemovedMemberDNs) {
	                            $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                            $Modification.Name = "member"
	                            $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	                            $Modification.Add($dn) | Out-Null
	                            $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        }
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if (-not $PassThru) {
	                            $msg = "Successfully removed $($RemovedMembers.Count) member(s) from: $($TargetGroup.sAMAccountName)"
	                            if ($SkippedMembers.Count -gt 0) {
	                                $msg += " ($($SkippedMembers.Count) were not members)"
	                            }
	                            Show-Line $msg -Class Hint
	                        }
	                    } catch {
	                        throw "Failed to commit changes: $_"
	                    }
	                } elseif ($SkippedMembers.Count -gt 0 -and $FailedMembers.Count -eq 0) {
	                    if (-not $PassThru) {
	                        Show-Line "None of the $($SkippedMembers.Count) specified member(s) were in: $($TargetGroup.sAMAccountName)" -Class Note
	                    }
	                }
	                if ($PassThru) {
	                    return [PSCustomObject]@{
	                        Operation = "RemoveMember"
	                        Group = $TargetGroup.sAMAccountName
	                        DistinguishedName = $GroupDN
	                        RemovedMembers = $RemovedMembers
	                        SkippedMembers = $SkippedMembers
	                        FailedMembers = $FailedMembers
	                        Success = ($FailedMembers.Count -eq 0)
	                        Message = "Removed $($RemovedMembers.Count), skipped $($SkippedMembers.Count) (not members), $($FailedMembers.Count) failed"
	                    }
	                }
	            }
	            'ClearMembers' {
	                $CurrentMembers = @()
	                if ($TargetGroup.member) {
	                    if ($TargetGroup.member -is [System.Array]) {
	                        $CurrentMembers = @($TargetGroup.member)
	                    }
	                    else {
	                        $CurrentMembers = @($TargetGroup.member)
	                    }
	                }
	                if ($CurrentMembers.Count -eq 0) {
	                    if ($PassThru) {
	                        return [PSCustomObject]@{
	                            Operation = "ClearMembers"
	                            Group = $TargetGroup.sAMAccountName
	                            DistinguishedName = $GroupDN
	                            Success = $true
	                            Message = "Group has no members (no change)"
	                        }
	                    } else {
	                        Show-Line "Group has no members: $($TargetGroup.sAMAccountName)" -Class Note
	                    }
	                }
	                elseif (-not $Force) {
	                    if ($PassThru) {
	                        return [PSCustomObject]@{
	                            Operation = "ClearMembers"
	                            Group = $TargetGroup.sAMAccountName
	                            DistinguishedName = $GroupDN
	                            MemberCount = $CurrentMembers.Count
	                            Success = $false
	                            Message = "Group has $($CurrentMembers.Count) members. Use -Force to confirm removal of all members."
	                        }
	                    } else {
	                        Show-Line "Group '$($TargetGroup.sAMAccountName)' has $($CurrentMembers.Count) members" -Class Note
	                        Show-Line "Use -Force to confirm removal of all members" -Class Note
	                    }
	                }
	                else {
	                    try {
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $GroupDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "member"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearMembers"
	                                Group = $TargetGroup.sAMAccountName
	                                DistinguishedName = $GroupDN
	                                RemovedCount = $CurrentMembers.Count
	                                Success = $true
	                                Message = "Removed all $($CurrentMembers.Count) member(s)"
	                            }
	                        } else {
	                            Show-Line "Successfully removed all $($CurrentMembers.Count) member(s) from: $($TargetGroup.sAMAccountName)" -Class Hint
	                        }
	                    } catch {
	                        throw "Failed to clear members: $_"
	                    }
	                }
	            }
	            'SetDescription' {
	                try {
	                    $CurrentDescription = $TargetGroup.description
	                    if ($CurrentDescription -eq $SetDescription) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetDescription"
	                                Group = $TargetGroup.sAMAccountName
	                                DistinguishedName = $GroupDN
	                                Success = $true
	                                Message = "Description already set to this value (no change)"
	                            }
	                        } else {
	                            Show-Line "Description already set to this value: $($TargetGroup.sAMAccountName)" -Class Note
	                        }
	                    }
	                    else {
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $GroupDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "description"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add($SetDescription) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetDescription"
	                                Group = $TargetGroup.sAMAccountName
	                                DistinguishedName = $GroupDN
	                                OldDescription = $CurrentDescription
	                                NewDescription = $SetDescription
	                                Success = $true
	                                Message = "Description updated"
	                            }
	                        } else {
	                            Show-Line "Successfully set description for: $($TargetGroup.sAMAccountName)" -Class Hint
	                        }
	                    }
	                } catch {
	                    throw "Failed to set description: $_"
	                }
	            }
	            'ClearDescription' {
	                try {
	                    $CurrentDescription = $TargetGroup.description
	                    if (-not $CurrentDescription) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearDescription"
	                                Group = $TargetGroup.sAMAccountName
	                                DistinguishedName = $GroupDN
	                                Success = $true
	                                Message = "Description already empty (no change)"
	                            }
	                        } else {
	                            Show-Line "Description already empty: $($TargetGroup.sAMAccountName)" -Class Note
	                        }
	                    }
	                    else {
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $GroupDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "description"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearDescription"
	                                Group = $TargetGroup.sAMAccountName
	                                DistinguishedName = $GroupDN
	                                OldDescription = $CurrentDescription
	                                Success = $true
	                                Message = "Description cleared"
	                            }
	                        } else {
	                            Show-Line "Successfully cleared description for: $($TargetGroup.sAMAccountName)" -Class Hint
	                        }
	                    }
	                } catch {
	                    throw "Failed to clear description: $_"
	                }
	            }
	            'ConvertToSecurity' {
	                try {
	                    $CurrentGroupType = [int]$TargetGroup.groupType
	                    $SECURITY_ENABLED = [int]0x80000000
	                    if (($CurrentGroupType -band $SECURITY_ENABLED) -ne 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ConvertToSecurity"
	                                Group = $TargetGroup.sAMAccountName
	                                DistinguishedName = $GroupDN
	                                Success = $true
	                                Message = "Group is already a Security group (no change)"
	                            }
	                        } else {
	                            Show-Line "Group is already a Security group: $($TargetGroup.sAMAccountName)" -Class Note
	                        }
	                    }
	                    else {
	                        $NewGroupType = $CurrentGroupType -bor $SECURITY_ENABLED
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $GroupDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "groupType"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add([string]$NewGroupType) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ConvertToSecurity"
	                                Group = $TargetGroup.sAMAccountName
	                                DistinguishedName = $GroupDN
	                                OldGroupType = $CurrentGroupType
	                                NewGroupType = $NewGroupType
	                                Success = $true
	                                Message = "Converted to Security group - can now be used for permissions"
	                            }
	                        } else {
	                            Show-Line "Successfully converted to Security group: $($TargetGroup.sAMAccountName)" -Class Hint
	                            Show-Line "Group can now be used for permission assignments!" -Class Finding
	                        }
	                    }
	                } catch {
	                    throw "Failed to convert to Security group: $_"
	                }
	            }
	            'ConvertToDistribution' {
	                try {
	                    $CurrentGroupType = [int]$TargetGroup.groupType
	                    $SECURITY_ENABLED = [int]0x80000000
	                    if (($CurrentGroupType -band $SECURITY_ENABLED) -eq 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ConvertToDistribution"
	                                Group = $TargetGroup.sAMAccountName
	                                DistinguishedName = $GroupDN
	                                Success = $true
	                                Message = "Group is already a Distribution group (no change)"
	                            }
	                        } else {
	                            Show-Line "Group is already a Distribution group: $($TargetGroup.sAMAccountName)" -Class Note
	                        }
	                    }
	                    else {
	                        $NewGroupType = $CurrentGroupType -band (-bnot $SECURITY_ENABLED)
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $GroupDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "groupType"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add([string]$NewGroupType) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ConvertToDistribution"
	                                Group = $TargetGroup.sAMAccountName
	                                DistinguishedName = $GroupDN
	                                OldGroupType = $CurrentGroupType
	                                NewGroupType = $NewGroupType
	                                Success = $true
	                                Message = "Converted to Distribution group - can no longer be used for permissions"
	                            }
	                        } else {
	                            Show-Line "Successfully converted to Distribution group: $($TargetGroup.sAMAccountName)" -Class Hint
	                            Show-Line "Group can no longer be used for permissions (effectively disarmed)!" -Class Finding
	                        }
	                    }
	                } catch {
	                    throw "Failed to convert to Distribution group: $_"
	                }
	            }
	            'SetOwner' {
	                try {
	                    $Result = Set-DomainObject -Identity $GroupDN -SetOwner -Principal $Owner @ConnectionParams
	                    if ($null -eq $Result) {
	                        throw "Set-DomainObject returned no result - operation may have failed silently"
	                    }
	                    if ($Result -is [PSCustomObject] -and $Result.PSObject.Properties['Success'] -and -not $Result.Success) {
	                        throw "Set-DomainObject failed: $($Result.Message)"
	                    }
	                    if ($Result -eq $false) {
	                        throw "Set-DomainObject returned false"
	                    }
	                    if ($PassThru) {
	                        return [PSCustomObject]@{
	                            Operation = "SetOwner"
	                            Group = $TargetGroup.sAMAccountName
	                            DistinguishedName = $GroupDN
	                            NewOwner = $Owner
	                            Success = $true
	                            Message = "Owner successfully changed"
	                        }
	                    } else {
	                        Show-Line "Successfully changed owner of $($TargetGroup.sAMAccountName) to: $Owner" -Class Hint
	                    }
	                } catch {
	                    throw "Failed to set owner: $_"
	                }
	            }
	            'GrantRights' {
	                try {
	                    $Result = switch ($GrantRights) {
	                        'GenericAll'   { Set-DomainObject -Identity $GroupDN -GrantACE -Principal $Principal -Rights GenericAll @ConnectionParams }
	                        'GenericWrite' { Set-DomainObject -Identity $GroupDN -GrantACE -Principal $Principal -Rights GenericWrite @ConnectionParams }
	                        'WriteDacl'    { Set-DomainObject -Identity $GroupDN -GrantACE -Principal $Principal -Rights WriteDacl @ConnectionParams }
	                        'WriteOwner'   { Set-DomainObject -Identity $GroupDN -GrantACE -Principal $Principal -Rights WriteOwner @ConnectionParams }
	                        'WriteMembers' { Set-DomainObject -Identity $GroupDN -GrantACE -Principal $Principal -ExtendedRight AddMember @ConnectionParams }
	                    }
	                    if ($null -eq $Result) {
	                        throw "Set-DomainObject returned no result - operation may have failed silently"
	                    }
	                    if ($Result -is [PSCustomObject] -and $Result.PSObject.Properties['Success'] -and -not $Result.Success) {
	                        throw "Set-DomainObject failed: $($Result.Message)"
	                    }
	                    if ($Result -eq $false) {
	                        throw "Set-DomainObject returned false"
	                    }
	                    if ($PassThru) {
	                        return [PSCustomObject]@{
	                            Operation = "GrantRights"
	                            Group = $TargetGroup.sAMAccountName
	                            DistinguishedName = $GroupDN
	                            Principal = $Principal
	                            Rights = $GrantRights
	                            Success = $true
	                            Message = "Rights successfully granted"
	                        }
	                    } else {
	                        Show-Line "Successfully granted $GrantRights to $Principal on: $($TargetGroup.sAMAccountName)" -Class Hint
	                    }
	                } catch {
	                    throw "Failed to grant rights: $_"
	                }
	            }
	        }
	    } catch {
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = $PSCmdlet.ParameterSetName
	                Group = $Identity
	                Success = $false
	                Message = $_.Exception.Message
	            }
	        } else {
	            Write-Error "[Set-DomainGroup] $($_.Exception.Message)"
	        }
	    } finally {
	    }
	}
	end {
	}
}
function Set-DomainComputer {
	[CmdletBinding(DefaultParameterSetName='SetRBCD')]
	param(
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetRBCD')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearRBCD')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetOwner')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='GrantRights')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='AddShadowCredential')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearShadowCredentials')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='EnableAccount')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='DisableAccount')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetTrustedForDelegation')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearTrustedForDelegation')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetConstrainedDelegation')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearConstrainedDelegation')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetTrustedToAuthForDelegation')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearTrustedToAuthForDelegation')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetPasswordNotRequired')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearPasswordNotRequired')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetPasswordNeverExpires')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearPasswordNeverExpires')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetNotDelegated')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearNotDelegated')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='SetDontReqPreauth')]
	    [Parameter(Position=0, Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ClearDontReqPreauth')]
	    [Alias('samAccountName', 'Computer', 'DNSHostName')]
	    [string]$Identity,
	    [Parameter(ParameterSetName='SetRBCD', Mandatory=$true)]
	    [string]$AddRBCD,
	    [Parameter(ParameterSetName='ClearRBCD', Mandatory=$true)]
	    [switch]$ClearRBCD,
	    [Parameter(ParameterSetName='SetOwner', Mandatory=$true)]
	    [string]$Owner,
	    [Parameter(ParameterSetName='GrantRights', Mandatory=$true)]
	    [ValidateSet('GenericAll','GenericWrite','WriteDacl','WriteOwner')]
	    [string]$GrantRights,
	    [Parameter(ParameterSetName='GrantRights', Mandatory=$true)]
	    [Parameter(ParameterSetName='ClearRBCD', Mandatory=$false)]
	    [string]$Principal,
	    [Parameter(ParameterSetName='AddShadowCredential', Mandatory=$true)]
	    [switch]$AddShadowCredential,
	    [Parameter(ParameterSetName='ClearShadowCredentials', Mandatory=$true)]
	    [switch]$ClearShadowCredentials,
	    [Parameter(ParameterSetName='AddShadowCredential', Mandatory=$false)]
	    [Parameter(ParameterSetName='ClearShadowCredentials', Mandatory=$false)]
	    [Alias('RemoveDeviceID', 'TargetDeviceID')]
	    [string]$DeviceID,
	    [Parameter(ParameterSetName='AddShadowCredential', Mandatory=$false)]
	    [switch]$NoPassword,
	    [Parameter(ParameterSetName='ClearRBCD', Mandatory=$false)]
	    [Parameter(ParameterSetName='ClearShadowCredentials', Mandatory=$false)]
	    [Parameter(ParameterSetName='ClearConstrainedDelegation', Mandatory=$false)]
	    [switch]$Force,
	    [Parameter(ParameterSetName='EnableAccount', Mandatory=$true)]
	    [switch]$Enable,
	    [Parameter(ParameterSetName='DisableAccount', Mandatory=$true)]
	    [switch]$Disable,
	    [Parameter(ParameterSetName='SetTrustedForDelegation', Mandatory=$true)]
	    [switch]$SetTrustedForDelegation,
	    [Parameter(ParameterSetName='ClearTrustedForDelegation', Mandatory=$true)]
	    [switch]$ClearTrustedForDelegation,
	    [Parameter(ParameterSetName='SetConstrainedDelegation', Mandatory=$true)]
	    [string[]]$SetConstrainedDelegation,
	    [Parameter(ParameterSetName='ClearConstrainedDelegation', Mandatory=$true)]
	    [switch]$ClearConstrainedDelegation,
	    [Parameter(ParameterSetName='SetTrustedToAuthForDelegation', Mandatory=$true)]
	    [switch]$SetTrustedToAuthForDelegation,
	    [Parameter(ParameterSetName='ClearTrustedToAuthForDelegation', Mandatory=$true)]
	    [switch]$ClearTrustedToAuthForDelegation,
	    [Parameter(ParameterSetName='SetPasswordNotRequired', Mandatory=$true)]
	    [switch]$PasswordNotRequired,
	    [Parameter(ParameterSetName='ClearPasswordNotRequired', Mandatory=$true)]
	    [switch]$ClearPasswordNotRequired,
	    [Parameter(ParameterSetName='SetPasswordNeverExpires', Mandatory=$true)]
	    [switch]$PasswordNeverExpires,
	    [Parameter(ParameterSetName='ClearPasswordNeverExpires', Mandatory=$true)]
	    [switch]$ClearPasswordNeverExpires,
	    [Parameter(ParameterSetName='SetNotDelegated', Mandatory=$true)]
	    [switch]$NotDelegated,
	    [Parameter(ParameterSetName='ClearNotDelegated', Mandatory=$true)]
	    [switch]$ClearNotDelegated,
	    [Parameter(ParameterSetName='SetDontReqPreauth', Mandatory=$true)]
	    [switch]$DontReqPreauth,
	    [Parameter(ParameterSetName='ClearDontReqPreauth', Mandatory=$true)]
	    [switch]$ClearDontReqPreauth,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [switch]$PassThru,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential
	)
	begin {
	}
	process {
	    $ConnectionParams = @{}
	    if ($Domain) { $ConnectionParams['Domain'] = $Domain }
	    if ($Server) { $ConnectionParams['Server'] = $Server }
	    if ($Credential) { $ConnectionParams['Credential'] = $Credential }
	    if (-not (Ensure-LDAPConnection @ConnectionParams)) {
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = $PSCmdlet.ParameterSetName
	                Computer = $Identity
	                Success = $false
	                Message = "No LDAP connection available"
	            }
	        }
	        return
	    }
	    try {
	        $TargetComputer = @(Get-DomainComputer -Identity $Identity @ConnectionParams)[0]
	        if (-not $TargetComputer) {
	            throw "Computer '$Identity' not Found"
	        }
	        $ComputerDN = $TargetComputer.distinguishedName
	        switch ($PSCmdlet.ParameterSetName) {
	            'SetRBCD' {
	                $result = Invoke-RBCDOperation -TargetDN $ComputerDN -TargetSAMAccountName $TargetComputer.sAMAccountName -TargetType 'Computer' -AddRBCD $AddRBCD -PassThru:$PassThru -ConnectionParams $ConnectionParams
	                if ($PassThru -and $result) {
	                    return $result
	                }
	            }
	            'ClearRBCD' {
	                $result = Invoke-RBCDOperation -TargetDN $ComputerDN -TargetSAMAccountName $TargetComputer.sAMAccountName -TargetType 'Computer' -ClearRBCD -Principal $Principal -Force:$Force -PassThru:$PassThru -ConnectionParams $ConnectionParams
	                if ($PassThru -and $result) {
	                    return $result
	                }
	            }
	            'SetOwner' {
	                try {
	                    $Result = Set-DomainObject -Identity $ComputerDN -SetOwner -Principal $Owner @ConnectionParams
	                    if ($Result) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetOwner"
	                                Computer = $TargetComputer.sAMAccountName
	                                DistinguishedName = $ComputerDN
	                                NewOwner = $Owner
	                                Success = $true
	                                Message = "Owner successfully changed"
	                            }
	                        } else {
	                            Show-Line "Successfully changed owner of $($TargetComputer.sAMAccountName) to: $Owner" -Class Hint
	                        }
	                    } else {
	                        throw "Set-DomainObject returned false"
	                    }
	                } catch {
	                    throw "Failed to set owner: $_"
	                }
	            }
	            'GrantRights' {
	                try {
	                    $Result = Set-DomainObject -Identity $ComputerDN -GrantACE -Principal $Principal -Rights $GrantRights @ConnectionParams
	                    if ($Result) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "GrantRights"
	                                Computer = $TargetComputer.sAMAccountName
	                                DistinguishedName = $ComputerDN
	                                Principal = $Principal
	                                Rights = $GrantRights
	                                Success = $true
	                                Message = "Rights successfully granted"
	                            }
	                        } else {
	                            Show-Line "Successfully granted $GrantRights to $Principal on: $($TargetComputer.sAMAccountName)" -Class Hint
	                        }
	                    } else {
	                        throw "Set-DomainObject returned false"
	                    }
	                } catch {
	                    throw "Failed to grant rights: $_"
	                }
	            }
	            'AddShadowCredential' {
	                $ComputerUPN = "$($TargetComputer.sAMAccountName)@$($Script:LDAPContext.Domain.ToUpper())"
	                $result = Invoke-ShadowCredentialOperation -TargetDN $ComputerDN -TargetSAMAccountName $TargetComputer.sAMAccountName -TargetType 'Computer' -TargetUPN $ComputerUPN -AddShadowCredential -DeviceID $DeviceID -NoPassword:$NoPassword -PassThru:$PassThru
	                if ($PassThru -and $result) {
	                    return $result
	                }
	            }
	            'ClearShadowCredentials' {
	                $result = Invoke-ShadowCredentialOperation -TargetDN $ComputerDN -TargetSAMAccountName $TargetComputer.sAMAccountName -TargetType 'Computer' -ClearShadowCredentials -DeviceID $DeviceID -Force:$Force -PassThru:$PassThru
	                if ($PassThru -and $result) {
	                    return $result
	                }
	            }
	            'EnableAccount' {
	                try {
	                    $CurrentUAC = if ($TargetComputer.userAccountControl) {
	                        [int]$TargetComputer.userAccountControl
	                    } else { 4096 }  # Default: WORKSTATION_TRUST_ACCOUNT
	                    $ACCOUNTDISABLE = 0x2
	                    if (($CurrentUAC -band $ACCOUNTDISABLE) -eq 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "EnableAccount"
	                                Computer = $TargetComputer.sAMAccountName
	                                DistinguishedName = $ComputerDN
	                                Success = $true
	                                Message = "Account already enabled (no change)"
	                            }
	                        } else {
	                            Show-Line "Account already enabled: $($TargetComputer.sAMAccountName)" -Class Note
	                        }
	                    }
	                    else {
	                        $NewUAC = $CurrentUAC -band (-bnot $ACCOUNTDISABLE)
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $ComputerDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "userAccountControl"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add([string]$NewUAC) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "EnableAccount"
	                                Computer = $TargetComputer.sAMAccountName
	                                DistinguishedName = $ComputerDN
	                                OldUAC = $CurrentUAC
	                                NewUAC = $NewUAC
	                                Success = $true
	                                Message = "Account enabled"
	                            }
	                        } else {
	                            Show-Line "Successfully enabled account: $($TargetComputer.sAMAccountName)" -Class Hint
	                        }
	                    }
	                } catch {
	                    throw "Failed to enable account: $_"
	                }
	            }
	            'DisableAccount' {
	                try {
	                    $CurrentUAC = if ($TargetComputer.userAccountControl) {
	                        [int]$TargetComputer.userAccountControl
	                    } else { 4096 }
	                    $ACCOUNTDISABLE = 0x2
	                    if (($CurrentUAC -band $ACCOUNTDISABLE) -ne 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "DisableAccount"
	                                Computer = $TargetComputer.sAMAccountName
	                                DistinguishedName = $ComputerDN
	                                Success = $true
	                                Message = "Account already disabled (no change)"
	                            }
	                        } else {
	                            Show-Line "Account already disabled: $($TargetComputer.sAMAccountName)" -Class Note
	                        }
	                    }
	                    else {
	                        $NewUAC = $CurrentUAC -bor $ACCOUNTDISABLE
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $ComputerDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "userAccountControl"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add([string]$NewUAC) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "DisableAccount"
	                                Computer = $TargetComputer.sAMAccountName
	                                DistinguishedName = $ComputerDN
	                                OldUAC = $CurrentUAC
	                                NewUAC = $NewUAC
	                                Success = $true
	                                Message = "Account disabled"
	                            }
	                        } else {
	                            Show-Line "Successfully disabled account: $($TargetComputer.sAMAccountName)" -Class Hint
	                        }
	                    }
	                } catch {
	                    throw "Failed to disable account: $_"
	                }
	            }
	            'SetTrustedForDelegation' {
	                try {
	                    $CurrentUAC = if ($TargetComputer.userAccountControl) {
	                        [int]$TargetComputer.userAccountControl
	                    } else { 4096 }
	                    $TRUSTED_FOR_DELEGATION = 0x80000
	                    if (($CurrentUAC -band $TRUSTED_FOR_DELEGATION) -ne 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetTrustedForDelegation"
	                                Computer = $TargetComputer.sAMAccountName
	                                DistinguishedName = $ComputerDN
	                                Success = $true
	                                Message = "Unconstrained Delegation already enabled (no change)"
	                            }
	                        } else {
	                            Show-Line "Unconstrained Delegation already enabled on: $($TargetComputer.sAMAccountName)" -Class Note
	                        }
	                    }
	                    else {
	                        $NewUAC = $CurrentUAC -bor $TRUSTED_FOR_DELEGATION
	                        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	                        $ModifyRequest.DistinguishedName = $ComputerDN
	                        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	                        $Modification.Name = "userAccountControl"
	                        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                        $Modification.Add([string]$NewUAC) | Out-Null
	                        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	                        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	                        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	                        }
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "SetTrustedForDelegation"
	                                Computer = $TargetComputer.sAMAccountName
	                                DistinguishedName = $ComputerDN
	                                OldUAC = $CurrentUAC
	                                NewUAC = $NewUAC
	                                Success = $true
	                                Message = "Unconstrained Delegation enabled - computer can now impersonate ANY user to ANY service!"
	                            }
	                        } else {
	                            Show-Line "Successfully enabled Unconstrained Delegation for: $($TargetComputer.sAMAccountName)" -Class Hint
	                            Show-Line "Computer can now impersonate ANY user to ANY service!" -Class Finding
	                        }
	                    }
	                } catch {
	                    throw "Failed to enable Unconstrained Delegation: $_"
	                }
	            }
	            'ClearTrustedForDelegation' {
	                try {
	                    $CurrentUAC = if ($TargetComputer.userAccountControl) {
	                        [int]$TargetComputer.userAccountControl
	                    } else { 4096 }
	                    $TRUSTED_FOR_DELEGATION = 0x80000
	                    if (($CurrentUAC -band $TRUSTED_FOR_DELEGATION) -eq 0) {
	                        if ($PassThru) {
	                            return [PSCustomObject]@{
	                                Operation = "ClearTrustedForDelegation"
	                                Computer = $TargetComputer.sAMAccountName
	                                DistinguishedName = $ComputerDN
