	            $resultToReturn = $Script:_SetOwnerResult
	            $Script:_SetOwnerResult = $null  # Clean up Script-scope variable
	            return $resultToReturn
	        } elseif ($PassThru -and $PSCmdlet.ParameterSetName -eq 'GrantRights' -and $Script:_GrantRightsResult) {
	            $resultToReturn = $Script:_GrantRightsResult
	            $Script:_GrantRightsResult = $null  # Clean up Script-scope variable
	            return $resultToReturn
	        }
	    } catch {
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = $PSCmdlet.ParameterSetName
	                GPO = $Identity
	                Success = $false
	                Message = $_.Exception.Message
	            }
	        } else {
	            Write-Error "[Set-DomainGPO] $($_.Exception.Message)"
	        }
	    }
	}
	end {
	    $Script:_SetOwnerResult = $null
	    $Script:_GrantRightsResult = $null
	}
}
function Sync-GPOSYSVOLPermissions {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$GPODN,
	    [Parameter(Mandatory=$true)]
	    [string]$GPOName,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential
	)
	try {
	    $GPOGUID = if ($GPODN -match 'CN=(\{[0-9A-Fa-f\-]{36}\})') { $Matches[1] } else { $null }
	    if (-not $GPOGUID) {
	        return [PSCustomObject]@{
	            Operation = "SyncSYSVOL"
	            GPO = $GPOName
	            Success = $false
	            Message = "Could not extract GUID from GPO DN: $GPODN"
	        }
	    }
	    $ADACEs = $null
	    $ADOwner = $null
	    $SDResult = @(Invoke-LDAPSearch -Filter "(distinguishedName=$GPODN)" -Properties @('nTSecurityDescriptor') -SizeLimit 1 -Raw)[0]
	    if (-not $SDResult -or -not $SDResult.nTSecurityDescriptor) {
	        throw "Could not read security descriptor from GPO: $GPODN"
	    }
	    $SDBytes = [byte[]]($SDResult.nTSecurityDescriptor)
	    $ADSecurityDescriptor = New-Object System.DirectoryServices.ActiveDirectorySecurity
	    $ADSecurityDescriptor.SetSecurityDescriptorBinaryForm($SDBytes)
	    $ADACEs = $ADSecurityDescriptor.GetAccessRules($true, $false, [System.Security.Principal.SecurityIdentifier])
	    $ADOwner = $ADSecurityDescriptor.GetOwner([System.Security.Principal.SecurityIdentifier])
	    $emptyGuid = [System.Guid]::Empty
	    $SYSVOLACEData = @()
	    foreach ($ADACE in $ADACEs) {
	        if ($ADACE.ObjectType -ne $emptyGuid) {
	            continue
	        }
	        $TrusteeSID = $ADACE.IdentityReference.Value
	        $ADRights = [int]$ADACE.ActiveDirectoryRights
	        $AccessType = $ADACE.AccessControlType
	        $NTFSRights = [System.Security.AccessControl.FileSystemRights]::None
	        if ($ADRights -ge 0xF0000) {
	            $NTFSRights = [System.Security.AccessControl.FileSystemRights]::FullControl
	        }
	        elseif (($ADRights -band 0x20028) -eq 0x20028 -or (($ADRights -band 0x20) -eq 0x20 -and ($ADRights -band 0x10000) -ne 0)) {
	            $NTFSRights = [System.Security.AccessControl.FileSystemRights]::Modify
	        }
	        else {
	            $NTFSRights = [System.Security.AccessControl.FileSystemRights]::ReadAndExecute
	        }
	        $SYSVOLACEData += @{
	            TrusteeSID = $TrusteeSID
	            NTFSRights = $NTFSRights
	            AccessType = $AccessType
	        }
	    }
	    $ConsolidatedACEs = @{}
	    foreach ($ace in $SYSVOLACEData) {
	        $key = "$($ace.TrusteeSID)|$($ace.AccessType)"
	        if ($ConsolidatedACEs.ContainsKey($key)) {
	            $existing = $ConsolidatedACEs[$key]
	            if ([int]$ace.NTFSRights -gt [int]$existing.NTFSRights) {
	                $ConsolidatedACEs[$key] = $ace
	            }
	        } else {
	            $ConsolidatedACEs[$key] = $ace
	        }
	    }
	    $SYSVOLACEData = @($ConsolidatedACEs.Values)
	    $domainName = $Script:LDAPContext.Domain
	    $gpoGuid = $GPOGUID
	    $ownerSID = $ADOwner.Value
	    $smbResult = Invoke-SMBAccess -Description "Sync GPO SYSVOL permissions" -ErrorHandling Stop -ScriptBlock {
	        param($basePath)
	        $gpoBasePath = Join-Path $basePath "$domainName\Policies\$gpoGuid"
	        if (-not (Test-Path $gpoBasePath)) {
	            throw "SYSVOL folder not found: $gpoBasePath"
	        }
	        $acl = Get-Acl -Path $gpoBasePath
	        $acl.SetAccessRuleProtection($true, $false)
	        $acl.Access | ForEach-Object { $acl.RemoveAccessRule($_) | Out-Null }
	        try {
	            $ownerIdentity = New-Object System.Security.Principal.SecurityIdentifier($ownerSID)
	            $acl.SetOwner($ownerIdentity)
	        } catch {
	        }
	        foreach ($aceData in $SYSVOLACEData) {
	            try {
	                $sid = New-Object System.Security.Principal.SecurityIdentifier($aceData.TrusteeSID)
	                $rule = New-Object System.Security.AccessControl.FileSystemAccessRule(
	                    $sid,
	                    $aceData.NTFSRights,
	                    ([System.Security.AccessControl.InheritanceFlags]::ContainerInherit -bor [System.Security.AccessControl.InheritanceFlags]::ObjectInherit),
	                    [System.Security.AccessControl.PropagationFlags]::None,
	                    $aceData.AccessType
	                )
	                $acl.AddAccessRule($rule)
	            } catch {
	            }
	        }
	        Set-Acl -Path $gpoBasePath -AclObject $acl -ErrorAction Stop
	        foreach ($subPath in @((Join-Path $gpoBasePath "Machine"), (Join-Path $gpoBasePath "User"))) {
	            if (Test-Path $subPath) {
	                try {
	                    $subAcl = Get-Acl -Path $subPath
	                    $subAcl.SetAccessRuleProtection($false, $false)
	                    Set-Acl -Path $subPath -AclObject $subAcl -ErrorAction SilentlyContinue
	                } catch {
	                }
	            }
	        }
	        return @{
	            Success = $true
	            SYSVOLPath = $gpoBasePath
	            ACECount = $SYSVOLACEData.Count
	        }
	    }.GetNewClosure()
	    if ($smbResult -and $smbResult.Success) {
	        return [PSCustomObject]@{
	            Operation = "SyncSYSVOL"
	            GPO = $GPOName
	            GPOGUID = $GPOGUID
	            SYSVOLPath = $smbResult.SYSVOLPath
	            ACECount = $smbResult.ACECount
	            Success = $true
	            Message = "SYSVOL permissions synchronized successfully"
	        }
	    } else {
	        return [PSCustomObject]@{
	            Operation = "SyncSYSVOL"
	            GPO = $GPOName
	            Success = $false
	            Message = "SYSVOL sync returned no result"
	        }
	    }
	} catch {
	    return [PSCustomObject]@{
	        Operation = "SyncSYSVOL"
	        GPO = $GPOName
	        Success = $false
	        Message = $_.Exception.Message
	    }
	}
}
function Update-GPOVersion {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$GPODN,
	    [Parameter(Mandatory=$true)]
	    [string]$GPOName,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$IncrementMachine,
	    [Parameter(Mandatory=$false)]
	    [switch]$IncrementUser
	)
	try {
	    if (-not $IncrementMachine -and -not $IncrementUser) {
	        $IncrementMachine = $true
	    }
	    $GPOGUID = if ($GPODN -match 'CN=(\{[0-9A-Fa-f\-]{36}\})') { $Matches[1] } else { $null }
	    if (-not $GPOGUID) {
	        return [PSCustomObject]@{
	            Operation = "UpdateGPOVersion"
	            GPO = $GPOName
	            Success = $false
	            Message = "Could not extract GUID from GPO DN: $GPODN"
	        }
	    }
	    $gpoResult = @(Invoke-LDAPSearch -Filter "(distinguishedName=$GPODN)" -Properties @('versionNumber') -SizeLimit 1)[0]
	    $currentVersion = if ($gpoResult -and $gpoResult.versionNumber) { [int]$gpoResult.versionNumber } else { 0 }
	    $userVersion = [math]::Floor($currentVersion / 65536)
	    $machineVersion = $currentVersion -band 0xFFFF
	    if ($IncrementMachine) {
	        $machineVersion++
	    }
	    if ($IncrementUser) {
	        $userVersion++
	    }
	    $newVersion = ($userVersion * 65536) + $machineVersion
	    $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	    $ModifyRequest.DistinguishedName = $GPODN
	    $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	    $Modification.Name = "versionNumber"
	    $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	    $Modification.Add([string]$newVersion) | Out-Null
	    $ModifyRequest.Modifications.Add($Modification) | Out-Null
	    $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	    if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	        throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	    }
	    $domainName = $Script:LDAPContext.Domain
	    $gpoGuid = $GPOGUID
	    $newVersionVal = $newVersion
	    $smbResult = Invoke-SMBAccess -Description "Update GPO version in GPT.INI" -ErrorHandling Continue -ScriptBlock {
	        param($basePath)
	        $gptIniPath = Join-Path $basePath "$domainName\Policies\$gpoGuid\GPT.INI"
	        if (-not (Test-Path $gptIniPath)) {
	            $gptIniContent = "[General]`r`nVersion=$newVersionVal"
	        } else {
	            $gptIniContent = Get-Content -Path $gptIniPath -Raw
	            if ($gptIniContent -match 'Version=\d+') {
	                $gptIniContent = $gptIniContent -replace 'Version=\d+', "Version=$newVersionVal"
	            } else {
	                if ($gptIniContent -match '\[General\]') {
	                    $gptIniContent = $gptIniContent -replace '(\[General\])', "`$1`r`nVersion=$newVersionVal"
	                } else {
	                    $gptIniContent = "[General]`r`nVersion=$newVersionVal`r`n$gptIniContent"
	                }
	            }
	        }
	        Set-Content -Path $gptIniPath -Value $gptIniContent -Force -ErrorAction Stop
	        return @{
	            Success = $true
	            GPTIniPath = $gptIniPath
	        }
	    }.GetNewClosure()
	    $sysvolSuccess = $smbResult -and $smbResult.Success
	    return [PSCustomObject]@{
	        Operation = "UpdateGPOVersion"
	        GPO = $GPOName
	        GPOGUID = $GPOGUID
	        PreviousVersion = $currentVersion
	        NewVersion = $newVersion
	        UserVersion = $userVersion
	        MachineVersion = $machineVersion
	        SYSVOLUpdated = $sysvolSuccess
	        Success = $true
	        Message = "GPO version updated successfully"
	    }
	} catch {
	    return [PSCustomObject]@{
	        Operation = "UpdateGPOVersion"
	        GPO = $GPOName
	        Success = $false
	        Message = $_.Exception.Message
	    }
	}
}
function New-DomainUser {
	[CmdletBinding()]
	param(
	    [Parameter(Position=0, Mandatory=$true)]
	    [string]$Name,
	    [Parameter(Position=1, Mandatory=$false)]
	    [Alias('NewPassword')]
	    [string]$Password,
	    [Parameter(Mandatory=$false)]
	    [string]$OrganizationalUnit,
	    [Parameter(Mandatory=$false)]
	    [string]$Description,
	    [Parameter(Mandatory=$false)]
	    [bool]$Enabled = $true,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$PassThru
	)
	begin {
	}
	process {
	    $ConnectionParams = @{}
	    if ($Domain) { $ConnectionParams['Domain'] = $Domain }
	    if ($Server) { $ConnectionParams['Server'] = $Server }
	    if ($Credential) { $ConnectionParams['Credential'] = $Credential }
	    if (-not (Ensure-LDAPConnection @ConnectionParams)) {
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = "CreateUser"
	                User = $Name
	                Success = $false
	                Message = "No LDAP connection available"
	            }
	        }
	        return
	    }
	    try {
	        if ($OrganizationalUnit) {
	            $TargetOU = $OrganizationalUnit
	        } else {
	            $TargetOU = "CN=Users,$($Script:LDAPContext.DomainDN)"
	        }
	        $UserDN = "CN=$Name,$TargetOU"
	        $AddRequest = New-Object System.DirectoryServices.Protocols.AddRequest
	        $AddRequest.DistinguishedName = $UserDN
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("objectClass", "user"))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("sAMAccountName", $Name))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("userPrincipalName", "$Name@$($Script:LDAPContext.Domain)"))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("userAccountControl", "514"))) | Out-Null
	        if ($Description) {
	            $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("description", $Description))) | Out-Null
	        }
	        $AddResponse = $Script:LdapConnection.SendRequest($AddRequest)
	        if ($AddResponse.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	            throw "LDAP AddRequest failed: $($AddResponse.ResultCode) - $($AddResponse.ErrorMessage)"
	        }
	        $PasswordToSet = $Password
	        $PasswordGenerated = $false
	        if (-not $PasswordToSet) {
	            $PasswordToSet = New-SafePassword -Length 20
	            $PasswordGenerated = $true
	        }
	        $PasswordSet = $false
	        try {
	            $quotedPwd = '"' + $PasswordToSet + '"'
	            $pwdBytes = [System.Text.Encoding]::Unicode.GetBytes($quotedPwd)
	            $PwdModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	            $PwdModifyRequest.DistinguishedName = $UserDN
	            $PwdMod = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	            $PwdMod.Name = "unicodePwd"
	            $PwdMod.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	            $PwdMod.Add($pwdBytes) | Out-Null
	            $PwdModifyRequest.Modifications.Add($PwdMod) | Out-Null
	            $PwdResponse = $Script:LdapConnection.SendRequest($PwdModifyRequest)
	            if ($PwdResponse.ResultCode -eq [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                $PasswordSet = $true
	            }
	        }
	        catch {
	            $primaryError = $_.Exception.Message
	        }
	        if (-not $PasswordSet) {
	            if (-not $Credential -and -not $Script:LDAPCredential) {
	                Write-Warning "[New-DomainUser] DirectoryEntry fallback uses current Windows user context, not the Kerberos-authenticated session identity. Password operation may fail or use wrong identity."
	            }
	            $UserEntry = Get-AuthenticatedDirectoryEntry -DistinguishedName $UserDN -Credential $Credential
	            if (-not $UserEntry) {
	                try {
	                    $DelReq = New-Object System.DirectoryServices.Protocols.DeleteRequest($UserDN)
	                    $Script:LdapConnection.SendRequest($DelReq) | Out-Null
	                } catch { }
	                throw "Failed to get DirectoryEntry for password setting"
	            }
	            try {
	                $UserEntry.Invoke("SetPassword", $PasswordToSet)
	                $UserEntry.CommitChanges()
	                $PasswordSet = $true
	            }
	            catch {
	                try {
	                    $DelReq = New-Object System.DirectoryServices.Protocols.DeleteRequest($UserDN)
	                    $Script:LdapConnection.SendRequest($DelReq) | Out-Null
	                } catch { }
	                $errorMsg = "Failed to set password."
	                if ($primaryError) {
	                    $errorMsg += " LDAP: $primaryError"
	                }
	                $errorMsg += " ADSI fallback: $_"
	                throw $errorMsg
	            }
	            finally {
	                if ($UserEntry) { $UserEntry.Dispose() }
	            }
	        }
	        if ($Enabled) {
	            $EnableRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	            $EnableRequest.DistinguishedName = $UserDN
	            $EnableMod = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	            $EnableMod.Name = "userAccountControl"
	            $EnableMod.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	            $EnableMod.Add("512") | Out-Null  # NORMAL_ACCOUNT only (enabled)
	            $EnableRequest.Modifications.Add($EnableMod) | Out-Null
	            $EnableResponse = $Script:LdapConnection.SendRequest($EnableRequest)
	            if ($EnableResponse.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                throw "Failed to enable account: $($EnableResponse.ResultCode) - $($EnableResponse.ErrorMessage)"
	            }
	        }
	        if ($PassThru) {
	            $Result = [PSCustomObject]@{
	                Operation = "CreateUser"
	                User = $Name
	                DistinguishedName = $UserDN
	                Enabled = $Enabled
	                Success = $true
	                Message = "User successfully created"
	            }
	            if ($PasswordGenerated) {
	                $Result | Add-Member -NotePropertyName "Password" -NotePropertyValue $PasswordToSet
	            }
	            return $Result
	        } else {
	            Show-Line "Successfully created user: $Name" -Class Hint
	            Show-KeyValue "Distinguished Name:" $UserDN
	            Show-KeyValue "Enabled:" $Enabled
	            if ($PasswordGenerated) {
	                Show-KeyValue "Password (SAVE THIS!):" $PasswordToSet -Class Finding
	            } else {
	                Show-KeyValue "Password:" "[Custom password set]"
	            }
	        }
	    }
	    catch {
	        Write-Error "[New-DomainUser] Failed to create user '$Name': $_"
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = "CreateUser"
	                User = $Name
	                Success = $false
	                Message = $_.Exception.Message
	            }
	        }
	    }
	}
}
function New-DomainComputer {
	[CmdletBinding()]
	param(
	    [Parameter(Position=0, Mandatory=$true)]
	    [Alias('ComputerName')]
	    [string]$Name,
	    [Parameter(Position=1, Mandatory=$false)]
	    [Alias('ComputerPassword')]
	    [string]$Password,
	    [Parameter(Mandatory=$false)]
	    [string]$OrganizationalUnit,
	    [Parameter(Mandatory=$false)]
	    [string]$Description,
	    [Parameter(Mandatory=$false)]
	    [bool]$Enabled = $true,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$PassThru
	)
	begin {
	}
	process {
	    $ConnectionParams = @{}
	    if ($Domain) { $ConnectionParams['Domain'] = $Domain }
	    if ($Server) { $ConnectionParams['Server'] = $Server }
	    if ($Credential) { $ConnectionParams['Credential'] = $Credential }
	    if (-not (Ensure-LDAPConnection @ConnectionParams)) {
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = "CreateComputer"
	                Computer = $Name
	                Success = $false
	                Message = "No LDAP connection available"
	            }
	        }
	        return
	    }
	    try {
	        if (-not $Name.EndsWith('$')) {
	            $Name = "$Name$"
	        }
	        if ($OrganizationalUnit) {
	            $TargetOU = $OrganizationalUnit
	        } else {
	            $TargetOU = "CN=Computers,$($Script:LDAPContext.DomainDN)"
	        }
	        $ComputerNameWithoutDollar = $Name.TrimEnd('$')
	        $ComputerDN = "CN=$ComputerNameWithoutDollar,$TargetOU"
	        $AddRequest = New-Object System.DirectoryServices.Protocols.AddRequest
	        $AddRequest.DistinguishedName = $ComputerDN
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("objectClass", "computer"))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("sAMAccountName", $Name))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("userPrincipalName", "$Name@$($Script:LDAPContext.Domain)"))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("dNSHostName", "$ComputerNameWithoutDollar.$($Script:LDAPContext.Domain)"))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("userAccountControl", "4098"))) | Out-Null
	        if ($Description) {
	            $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("description", $Description))) | Out-Null
	        }
	        $AddResponse = $Script:LdapConnection.SendRequest($AddRequest)
	        if ($AddResponse.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	            throw "LDAP AddRequest failed: $($AddResponse.ResultCode) - $($AddResponse.ErrorMessage)"
	        }
	        $PasswordToSet = $Password
	        $PasswordGenerated = $false
	        if (-not $PasswordToSet) {
	            $PasswordToSet = New-SafePassword -Length 20
	            $PasswordGenerated = $true
	        }
	        $PasswordSet = $false
	        try {
	            $quotedPwd = '"' + $PasswordToSet + '"'
	            $pwdBytes = [System.Text.Encoding]::Unicode.GetBytes($quotedPwd)
	            $PwdModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	            $PwdModifyRequest.DistinguishedName = $ComputerDN
	            $PwdMod = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	            $PwdMod.Name = "unicodePwd"
	            $PwdMod.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	            $PwdMod.Add($pwdBytes) | Out-Null
	            $PwdModifyRequest.Modifications.Add($PwdMod) | Out-Null
	            $PwdResponse = $Script:LdapConnection.SendRequest($PwdModifyRequest)
	            if ($PwdResponse.ResultCode -eq [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                $PasswordSet = $true
	            }
	        }
	        catch {
	            $primaryError = $_.Exception.Message
	        }
	        if (-not $PasswordSet) {
	            if (-not $Credential -and -not $Script:LDAPCredential) {
	                Write-Warning "[New-DomainComputer] DirectoryEntry fallback uses current Windows user context, not the Kerberos-authenticated session identity. Password operation may fail or use wrong identity."
	            }
	            $ComputerEntry = Get-AuthenticatedDirectoryEntry -DistinguishedName $ComputerDN -Credential $Credential
	            if (-not $ComputerEntry) {
	                try {
	                    $DelReq = New-Object System.DirectoryServices.Protocols.DeleteRequest($ComputerDN)
	                    $Script:LdapConnection.SendRequest($DelReq) | Out-Null
	                } catch { }
	                throw "Failed to get DirectoryEntry for password setting"
	            }
	            try {
	                $ComputerEntry.Invoke("SetPassword", $PasswordToSet)
	                $ComputerEntry.CommitChanges()
	                $PasswordSet = $true
	            }
	            catch {
	                try {
	                    $DelReq = New-Object System.DirectoryServices.Protocols.DeleteRequest($ComputerDN)
	                    $Script:LdapConnection.SendRequest($DelReq) | Out-Null
	                } catch { }
	                $errorMsg = "Failed to set password."
	                if ($primaryError) {
	                    $errorMsg += " LDAP: $primaryError"
	                }
	                $errorMsg += " ADSI fallback: $_"
	                throw $errorMsg
	            }
	            finally {
	                if ($ComputerEntry) { $ComputerEntry.Dispose() }
	            }
	        }
	        if ($Enabled) {
	            $EnableRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	            $EnableRequest.DistinguishedName = $ComputerDN
	            $EnableMod = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	            $EnableMod.Name = "userAccountControl"
	            $EnableMod.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	            $EnableMod.Add("4096") | Out-Null  # WORKSTATION_TRUST_ACCOUNT only (enabled)
	            $EnableRequest.Modifications.Add($EnableMod) | Out-Null
	            $EnableResponse = $Script:LdapConnection.SendRequest($EnableRequest)
	            if ($EnableResponse.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                throw "Failed to enable account: $($EnableResponse.ResultCode) - $($EnableResponse.ErrorMessage)"
	            }
	        }
	        if ($PassThru) {
	            $Result = [PSCustomObject]@{
	                Operation = "CreateComputer"
	                Computer = $Name
	                DistinguishedName = $ComputerDN
	                DNSHostName = "$ComputerNameWithoutDollar.$($Script:LDAPContext.Domain)"
	                Enabled = $Enabled
	                Success = $true
	                Message = "Computer successfully created"
	            }
	            if ($PasswordGenerated) {
	                $Result | Add-Member -NotePropertyName "Password" -NotePropertyValue $PasswordToSet
	            }
	            return $Result
	        } else {
	            Show-Line "Successfully created computer: $Name" -Class Hint
	            Show-KeyValue "Distinguished Name:" $ComputerDN
	            Show-KeyValue "DNS Hostname:" "$ComputerNameWithoutDollar.$($Script:LDAPContext.Domain)"
	            Show-KeyValue "Enabled:" $Enabled
	            if ($PasswordGenerated) {
	                Show-KeyValue "Password (SAVE THIS!):" $PasswordToSet -Class Finding
	            } else {
	                Show-KeyValue "Password:" "[Custom password set]"
	            }
	        }
	    }
	    catch {
	        Write-Error "[New-DomainComputer] Failed to create computer '$Name': $_"
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = "CreateComputer"
	                Computer = $Name
	                Success = $false
	                Message = $_.Exception.Message
	            }
	        }
	    }
	}
}
function New-DomainGroup {
	[CmdletBinding()]
	param(
	    [Parameter(Position=0, Mandatory=$true)]
	    [Alias('GroupName')]
	    [string]$Name,
	    [Parameter(Mandatory=$false)]
	    [string]$OrganizationalUnit,
	    [Parameter(Mandatory=$false)]
	    [string]$Description,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('Global', 'Universal', 'DomainLocal')]
	    [string]$GroupScope = 'Global',
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('Security', 'Distribution')]
	    [string]$GroupType = 'Security',
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$PassThru
	)
	begin {
	}
	process {
	    $ConnectionParams = @{}
	    if ($Domain) { $ConnectionParams['Domain'] = $Domain }
	    if ($Server) { $ConnectionParams['Server'] = $Server }
	    if ($Credential) { $ConnectionParams['Credential'] = $Credential }
	    if (-not (Ensure-LDAPConnection @ConnectionParams)) {
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = "CreateGroup"
	                Group = $Name
	                Success = $false
	                Message = "No LDAP connection available"
	            }
	        }
	        return
	    }
	    try {
	        if ($OrganizationalUnit) {
	            $TargetOU = $OrganizationalUnit
	        } else {
	            $TargetOU = "CN=Users,$($Script:LDAPContext.DomainDN)"
	        }
	        $GroupTypeFlag = 0
	        switch ($GroupScope) {
	            'Global'      { $GroupTypeFlag = 0x00000002 }
	            'DomainLocal' { $GroupTypeFlag = 0x00000004 }
	            'Universal'   { $GroupTypeFlag = 0x00000008 }
	        }
	        if ($GroupType -eq 'Security') {
	            $GroupTypeFlag = $GroupTypeFlag -bor 0x80000000
	        }
	        $GroupDN = "CN=$Name,$TargetOU"
	        $AddRequest = New-Object System.DirectoryServices.Protocols.AddRequest
	        $AddRequest.DistinguishedName = $GroupDN
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("objectClass", "group"))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("sAMAccountName", $Name))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("groupType", [string]$GroupTypeFlag))) | Out-Null
	        if ($Description) {
	            $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("description", $Description))) | Out-Null
	        }
	        $Response = $Script:LdapConnection.SendRequest($AddRequest)
	        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	            throw "LDAP AddRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	        }
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = "CreateGroup"
	                Group = $Name
	                DistinguishedName = $GroupDN
	                GroupType = $GroupType
	                GroupScope = $GroupScope
	                Success = $true
	                Message = "Group successfully created"
	            }
	        } else {
	            Show-Line "Successfully created group: $Name" -Class Hint
	            Show-KeyValue "Distinguished Name:" $GroupDN
	            Show-KeyValue "Type:" $GroupType
	            Show-KeyValue "Scope:" $GroupScope
	        }
	    }
	    catch {
	        Write-Error "[New-DomainGroup] Failed to create group '$Name': $_"
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = "CreateGroup"
	                Group = $Name
	                Success = $false
	                Message = $_.Exception.Message
	            }
	        }
	    }
	}
}
function New-DomainGPO {
	[CmdletBinding()]
	param(
	    [Parameter(Position=0, Mandatory=$true)]
	    [string]$DisplayName,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoSYSVOL,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [switch]$PassThru
	)
	begin {
	}
	process {
	    $ConnectionParams = @{}
	    if ($Domain) { $ConnectionParams['Domain'] = $Domain }
	    if ($Server) { $ConnectionParams['Server'] = $Server }
	    if ($Credential) { $ConnectionParams['Credential'] = $Credential }
	    if (-not (Ensure-LDAPConnection @ConnectionParams)) {
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = "CreateGPO"
	                GPO = $DisplayName
	                Success = $false
	                Message = "No LDAP connection available"
	            }
	        }
	        return
	    }
	    try {
	        $GPOGUID = [System.Guid]::NewGuid().ToString().ToUpper()
	        $GPOGUIDWithBraces = "{$GPOGUID}"
	        $PoliciesContainer = "CN=Policies,CN=System,$($Script:LDAPContext.DomainDN)"
	        $GPODN = "CN=$GPOGUIDWithBraces,$PoliciesContainer"
	        $gPCFileSysPath = "\\$($Script:LDAPContext.Domain)\SysVol\$($Script:LDAPContext.Domain)\Policies\$GPOGUIDWithBraces"
	        $AddRequest = New-Object System.DirectoryServices.Protocols.AddRequest
	        $AddRequest.DistinguishedName = $GPODN
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("objectClass", "groupPolicyContainer"))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("displayName", $DisplayName))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("flags", "0"))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("versionNumber", "0"))) | Out-Null
	        $AddRequest.Attributes.Add((New-Object System.DirectoryServices.Protocols.DirectoryAttribute("gPCFileSysPath", $gPCFileSysPath))) | Out-Null
	        $Response = $Script:LdapConnection.SendRequest($AddRequest)
	        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	            throw "LDAP AddRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	        }
	        $SYSVOLCreated = $false
	        $SYSVOLError = $null
	        if (-not $NoSYSVOL) {
	            try {
	                $SDResult = @(Invoke-LDAPSearch -Filter "(distinguishedName=$GPODN)" -Properties @('nTSecurityDescriptor') -SizeLimit 1 -Raw)[0]
	                if (-not $SDResult -or -not $SDResult.nTSecurityDescriptor) {
	                    throw "Failed to read security descriptor from GPO object"
	                }
	                $SDBytes = [byte[]]($SDResult.nTSecurityDescriptor)
	                $ADSecurityDescriptor = New-Object System.DirectoryServices.ActiveDirectorySecurity
	                $ADSecurityDescriptor.SetSecurityDescriptorBinaryForm($SDBytes)
	                $ADACEs = $ADSecurityDescriptor.GetAccessRules($true, $false, [System.Security.Principal.SecurityIdentifier])
	                $ADOwner = $ADSecurityDescriptor.GetOwner([System.Security.Principal.SecurityIdentifier])
	                $SYSVOLACEData = @()
	                foreach ($ADACE in $ADACEs) {
	                    $TrusteeSID = $ADACE.IdentityReference.Value
	                    $ADRights = [int]$ADACE.ActiveDirectoryRights
	                    $AccessType = $ADACE.AccessControlType
	                    $NTFSRights = [System.Security.AccessControl.FileSystemRights]::None
	                    if ($ADRights -ge 0xF0000) {
	                        $NTFSRights = [System.Security.AccessControl.FileSystemRights]::FullControl
	                    }
	                    elseif (($ADRights -band 0x20028) -eq 0x20028 -or (($ADRights -band 0x20) -eq 0x20 -and ($ADRights -band 0x10000) -ne 0)) {
	                        $NTFSRights = [System.Security.AccessControl.FileSystemRights]::Modify
	                    }
	                    else {
	                        $NTFSRights = [System.Security.AccessControl.FileSystemRights]::ReadAndExecute
	                    }
	                    $SYSVOLACEData += @{
	                        TrusteeSID = $TrusteeSID
	                        NTFSRights = $NTFSRights
	                        AccessType = $AccessType
	                    }
	                }
	                $ConsolidatedACEs = @{}
	                foreach ($ace in $SYSVOLACEData) {
	                    $key = "$($ace.TrusteeSID)|$($ace.AccessType)"
	                    if ($ConsolidatedACEs.ContainsKey($key)) {
	                        $existing = $ConsolidatedACEs[$key]
	                        if ([int]$ace.NTFSRights -gt [int]$existing.NTFSRights) {
	                            $ConsolidatedACEs[$key] = $ace
	                        }
	                    } else {
	                        $ConsolidatedACEs[$key] = $ace
	                    }
	                }
	                $SYSVOLACEData = @($ConsolidatedACEs.Values)
	                $domainName = $Script:LDAPContext.Domain
	                $gpoGuid = $GPOGUIDWithBraces
	                $gpoDisplayName = $DisplayName
	                $ownerSID = $ADOwner.Value
	                $smbResult = Invoke-SMBAccess -Description "Create GPO SYSVOL folders" -ErrorHandling Stop -ScriptBlock {
	                    param($basePath)
	                    $gpoBasePath = Join-Path $basePath "$domainName\Policies\$gpoGuid"
	                    $machinePath = Join-Path $gpoBasePath "Machine"
	                    $userPath = Join-Path $gpoBasePath "User"
	                    $gptIniPath = Join-Path $gpoBasePath "GPT.INI"
	                    if (-not (Test-Path $gpoBasePath)) {
	                        $null = New-Item -Path $gpoBasePath -ItemType Directory -Force -ErrorAction Stop
	                    }
	                    if (-not (Test-Path $machinePath)) {
	                        $null = New-Item -Path $machinePath -ItemType Directory -Force -ErrorAction Stop
	                    }
	                    if (-not (Test-Path $userPath)) {
	                        $null = New-Item -Path $userPath -ItemType Directory -Force -ErrorAction Stop
	                    }
	                    $gptIniContent = "[General]`r`nVersion=0`r`ndisplayName=$gpoDisplayName"
	                    Set-Content -Path $gptIniPath -Value $gptIniContent -Force -ErrorAction Stop
	                    try {
	                        $acl = Get-Acl -Path $gpoBasePath
	                        $acl.SetAccessRuleProtection($true, $false)
	                        $acl.Access | ForEach-Object { $acl.RemoveAccessRule($_) | Out-Null }
	                        try {
	                            $ownerIdentity = New-Object System.Security.Principal.SecurityIdentifier($ownerSID)
	                            $acl.SetOwner($ownerIdentity)
	                        } catch {
	                        }
	                        foreach ($aceData in $SYSVOLACEData) {
	                            try {
	                                $sid = New-Object System.Security.Principal.SecurityIdentifier($aceData.TrusteeSID)
	                                $rule = New-Object System.Security.AccessControl.FileSystemAccessRule(
	                                    $sid,
	                                    $aceData.NTFSRights,
	                                    ([System.Security.AccessControl.InheritanceFlags]::ContainerInherit -bor [System.Security.AccessControl.InheritanceFlags]::ObjectInherit),
	                                    [System.Security.AccessControl.PropagationFlags]::None,
	                                    $aceData.AccessType
	                                )
	                                $acl.AddAccessRule($rule)
	                            } catch {
	                            }
	                        }
	                        Set-Acl -Path $gpoBasePath -AclObject $acl -ErrorAction Stop
	                        Set-Acl -Path $machinePath -AclObject $acl -ErrorAction SilentlyContinue
	                        Set-Acl -Path $userPath -AclObject $acl -ErrorAction SilentlyContinue
	                    } catch {
	                    }
	                    return @{
	                        Success = $true
	                        GPOPath = $gpoBasePath
	                        MachinePath = $machinePath
	                        UserPath = $userPath
	                        GptIniPath = $gptIniPath
	                    }
	                }.GetNewClosure()
	                if ($smbResult -and $smbResult.Success) {
	                    $SYSVOLCreated = $true
	                    $SYSVOLResult = $smbResult
	                } else {
	                    $SYSVOLError = "SMB access returned no result"
	                }
	            }
	            catch {
	                $SYSVOLError = $_.Exception.Message
	                if (-not $PassThru) {
	                    Write-Warning "[New-DomainGPO] Failed to create SYSVOL folders: $SYSVOLError"
	                    Write-Warning "    The GPO AD object was created, but SYSVOL structure is missing."
	                    Write-Warning "    GPO will appear broken in GPMC until SYSVOL is populated manually."
	                }
	            }
	        } else {
	        }
	        $resultMessage = if ($SYSVOLCreated) {
	            "GPO created successfully (AD object + SYSVOL)"
	        } elseif ($NoSYSVOL) {
	            "GPO AD object created (SYSVOL skipped by request)"
	        } else {
	            "GPO AD object created (SYSVOL creation failed: $SYSVOLError)"
	        }
	        if ($PassThru) {
	            $Result = [PSCustomObject]@{
	                Operation = "CreateGPO"
	                DisplayName = $DisplayName
	                GUID = $GPOGUIDWithBraces
	                DistinguishedName = $GPODN
	                SYSVOLPath = $gPCFileSysPath
	                SYSVOLCreated = $SYSVOLCreated
	                Success = $true
	                Message = $resultMessage
	            }
	            if ($SYSVOLError) {
	                $Result | Add-Member -NotePropertyName "SYSVOLError" -NotePropertyValue $SYSVOLError
	            }
	            return $Result
	        } else {
	            Show-Line "Successfully created GPO AD object: $DisplayName" -Class Hint
	            Show-KeyValue "Distinguished Name:" $GPODN
	            Show-KeyValue "GUID:" $GPOGUIDWithBraces
	            Show-KeyValue "SYSVOL Path:" $gPCFileSysPath
	            if ($SYSVOLCreated -and $SYSVOLResult) {
	                Show-Line "SYSVOL folder structure created successfully" -Class Hint
	                Show-KeyValue "Machine folder:" $SYSVOLResult.MachinePath
	                Show-KeyValue "User folder:" $SYSVOLResult.UserPath
	                Show-KeyValue "GPT.INI:" $SYSVOLResult.GptIniPath
	            } elseif ($NoSYSVOL) {
	                Show-Line "SYSVOL creation skipped (-NoSYSVOL)" -Class Note
	            }
	        }
	    }
	    catch {
	        Write-Error "[New-DomainGPO] Failed to create GPO '$DisplayName': $_"
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = "CreateGPO"
	                DisplayName = $DisplayName
	                Success = $false
	                Message = $_.Exception.Message
	            }
	        }
	    }
	}
}
function Get-CertificateAuthority {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [string]$Identity,
	    [Parameter(Mandatory=$false)]
	    [string[]]$Properties,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential
	)
	begin {
	}
	process {
	    if (-not (Ensure-LDAPConnection @PSBoundParameters)) {
	        return
	    }
	    $ldapServer = $Script:LDAPContext.Server
	    $configNC = $Script:LDAPContext.ConfigurationNamingContext
	    if (-not $configNC) {
	        Write-Error "[Get-CertificateAuthority] No Configuration Naming Context available in LDAP session."
	        return
	    }
	    $enrollmentPath = "CN=Enrollment Services,CN=Public Key Services,CN=Services,$configNC"
	    $defaultProperties = @(
	        'cn',
	        'displayName',
	        'distinguishedName',
	        'objectGUID',
	        'dNSHostName',
	        'cACertificate',
	        'certificateTemplates',
	        'nTSecurityDescriptor',
	        'objectClass',
	        'whenCreated',
	        'whenChanged',
	        'flags'
	    )
	    if ($Properties) {
	        $allPropertiesToLoad = $defaultProperties + $Properties | Select-Object -Unique
	    } else {
	        $allPropertiesToLoad = $defaultProperties
	    }
	    try {
	        if ($Identity) {
	            $filter = "(&(objectClass=pKIEnrollmentService)(cn=$Identity))"
	        } else {
	            $filter = "(objectClass=pKIEnrollmentService)"
	        }
	        $results = Invoke-LDAPSearch -Filter $filter -SearchBase $enrollmentPath -Properties $allPropertiesToLoad -Scope OneLevel
	        if (-not $results) {
	            return
	        }
	        $resultsArray = @($results)
	        foreach ($entry in $resultsArray) {
	            $ca = [PSCustomObject]@{
	                Name = $entry.cn
	                DisplayName = $entry.displayName
	                DistinguishedName = $entry.distinguishedName
	                ObjectGUID = $entry.objectGUID
	                DNSHostName = $entry.dNSHostName
	                Flags = if ($entry.flags) { [int]$entry.flags } else { 0 }
	                CertificateTemplates = if ($entry.certificateTemplates) {
	                    @($entry.certificateTemplates)
	                } else { @() }
	                CACertificate = $entry.cACertificate
	                SecurityDescriptor = $entry.nTSecurityDescriptor
	                Created = $entry.whenCreated
	                Modified = $entry.whenChanged
	                RawEntry = $entry
	            }
	            Write-Output $ca
	        }
	    }
	    catch {
	        [PSCustomObject]@{
	            _QueryError = $true
	            ErrorMessage = $_.Exception.Message
	        }
	    }
	}
	end {
	}
}
function Write-Log {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true, Position = 0)]
	    [string]$Message,
	    [Parameter(Mandatory = $false)]
	    [ValidateSet('Info', 'Verbose', 'Debug', 'Warning', 'Error')]
	    [string]$Level = 'Verbose'
	)
	switch ($Level) {
	    'Verbose' { Write-Verbose $Message }
	    'Debug'   { Write-Debug $Message }
	    'Warning' { Write-Warning $Message }
	    'Error'   { Write-Warning $Message }
	    default   { Write-Host $Message }
	}
	if ($Script:adPEAS_Outputfile -and $Script:adPEAS_VerboseLogging) {
	    try {
	        $timestamp = Get-Date -Format "yyyy-MM-dd HH:mm:ss"
	        "$timestamp [$Level] $Message" | Add-Content -Path $Script:adPEAS_Outputfile -ErrorAction SilentlyContinue
	    }
	    catch {
	    }
	}
}
function New-SafePassword {
	[CmdletBinding()]
	[OutputType([string])]
	param(
	    [Parameter(Mandatory=$false)]
	    [ValidateRange(8, 128)]
	    [int]$Length = 20,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoSpecialChars
	)
	process {
	    $Lowercase = 'abcdefghijklmnopqrstuvwxyz'
	    $Uppercase = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'
	    $Digits = '0123456789'
	    $SafeSpecials = '@#^*()_-+={[]}:.?,~'
	    if ($NoSpecialChars) {
	        $CharSet = $Lowercase + $Uppercase + $Digits
	    } else {
	        $CharSet = $Lowercase + $Uppercase + $Digits + $SafeSpecials
	    }
	    $CharArray = $CharSet.ToCharArray()
	    $RNG = [System.Security.Cryptography.RandomNumberGenerator]::Create()
	    try {
	        $Password = [System.Text.StringBuilder]::new($Length)
	        $RandomBytes = New-Object byte[] 1
	        for ($i = 0; $i -lt $Length; $i++) {
	            $RNG.GetBytes($RandomBytes)
	            $Index = [int]$RandomBytes[0] % $CharArray.Length
	            [void]$Password.Append($CharArray[$Index])
	        }
	        $PasswordString = $Password.ToString()
	        $HasLower = $PasswordString -cmatch '[a-z]'
	        $HasUpper = $PasswordString -cmatch '[A-Z]'
	        $HasDigit = $PasswordString -match '[0-9]'
	        $HasSpecial = if (-not $NoSpecialChars) { $PasswordString -match '[@#^*()_\-+={}\[\]:.,?~]' } else { $true }
	        if (-not ($HasLower -and $HasUpper -and $HasDigit -and $HasSpecial)) {
	            return New-SafePassword -Length $Length -NoSpecialChars:$NoSpecialChars
	        }
	        return $PasswordString
	    }
	    finally {
	        $RNG.Dispose()
	    }
	}
}
function ConvertTo-FormattedACE {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true, ValueFromPipeline=$true, Position=0)]
	    [byte[]]$SecurityDescriptor,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoResolveSIDs
	)
	process {
	    try {
	        $RawSD = New-Object System.DirectoryServices.ActiveDirectorySecurity
	        $RawSD.SetSecurityDescriptorBinaryForm($SecurityDescriptor)
	        $OwnerSID = $RawSD.GetOwner([System.Security.Principal.SecurityIdentifier]).Value
	        $OwnerName = if (-not $NoResolveSIDs) {
	            ConvertFrom-SID -SID $OwnerSID
	        } else {
	            $OwnerSID
	        }
	        $DACL = $RawSD.GetAccessRules($true, $true, [System.Security.Principal.SecurityIdentifier])
	        $ACEList = @()
	        foreach ($ACE in $DACL) {
	            $TrusteeSID = $ACE.IdentityReference.Value
	            $TrusteeName = if (-not $NoResolveSIDs) {
	                ConvertFrom-SID -SID $TrusteeSID
	            } else {
	                $TrusteeSID
	            }
	            $RightsArray = @()
	            $ADRights = $ACE.ActiveDirectoryRights
	            foreach ($Right in $Script:AllActiveDirectoryRights) {
	                if (($ADRights -band $Right) -eq $Right) {
	                    $RightsArray += $Right.ToString()
	                }
	            }
	            $ObjectTypeGuid = if ($ACE.ObjectType -and $ACE.ObjectType -ne [System.Guid]::Empty) {
	                $ACE.ObjectType.ToString()
	            } else { $null }
	            $ObjectTypeName = if ($ObjectTypeGuid) {
	                Get-ExtendedRightName -GUID $ObjectTypeGuid
	            } else { $null }
	            if ($ObjectTypeName -and ($RightsArray -contains "ExtendedRight")) {
	                $RightsArray = $RightsArray | Where-Object { $_ -ne "ExtendedRight" }
	                $RightsArray += $ObjectTypeName
	            }
	            $InheritedObjectTypeGuid = if ($ACE.InheritedObjectType -and $ACE.InheritedObjectType -ne [System.Guid]::Empty) {
	                $ACE.InheritedObjectType.ToString()
	            } else { $null }
	            $RightsFormatted = $RightsArray -join ', '
	            $ACEObj = [PSCustomObject]@{
	                AccessControlType   = $ACE.AccessControlType.ToString()
	                Trustee             = $TrusteeName
	                TrusteeSID          = $TrusteeSID
	                Rights              = $RightsFormatted
	                RightsRaw           = $RightsArray
	                ObjectType          = $ObjectTypeGuid
	                ObjectTypeName      = $ObjectTypeName
	                InheritedObjectType = $InheritedObjectTypeGuid
	                IsInherited         = $ACE.IsInherited
	                InheritanceFlags    = $ACE.InheritanceFlags.ToString()
	                PropagationFlags    = $ACE.PropagationFlags.ToString()
	            }
	            $ACEList += $ACEObj
	        }
	        return [PSCustomObject]@{
	            Owner     = $OwnerName
	            OwnerSID  = $OwnerSID
	            ACEs      = $ACEList
	        }
	    } catch {
	        Write-Error "[ConvertTo-FormattedACE] Error parsing security descriptor: $_"
	        return $null
	    }
	}
}
function ConvertFrom-SecurityDescriptor {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [byte[]]$SecurityDescriptorBytes
	)
	try {
	    $SD = New-Object System.DirectoryServices.ActiveDirectorySecurity
	    $SD.SetSecurityDescriptorBinaryForm($SecurityDescriptorBytes)
	    $OwnerSID = $SD.GetOwner([System.Security.Principal.SecurityIdentifier]).Value
	    $OwnerName = ConvertFrom-SID -SID $OwnerSID
	    $OwnerObject = [PSCustomObject]@{
	        SID = $OwnerSID
	        Name = $OwnerName
	        DisplayText = "Owner: $OwnerName"
	    }
	    $ACEList = @()
	    foreach ($ACE in $SD.Access) {
	        $PrincipalSID = $null
	        $PrincipalName = $null
	        try {
	            $sidObj = $ACE.IdentityReference.Translate([System.Security.Principal.SecurityIdentifier])
	            $PrincipalSID = $sidObj.Value
	        } catch {
	            $Principal = $ACE.IdentityReference.Value
	            if ($Principal -match '^S-1-') {
	                $PrincipalSID = $Principal
	            }
	        }
	        $Principal = $ACE.IdentityReference.Value
	        if ($Principal -match '^S-1-') {
	            $PrincipalName = ConvertFrom-SID -SID $Principal
	        } else {
	            $PrincipalName = $Principal
	            if (-not $PrincipalSID) {
	                $PrincipalSID = ConvertTo-SID -Identity $Principal
	            }
	        }
	        $ACEType = $ACE.AccessControlType
	        $Rights = $ACE.ActiveDirectoryRights -replace '\s', ''
	        $RightsDisplay = $Rights
	        if ($Rights -match 'ExtendedRight' -and $ACE.ObjectType -ne [System.Guid]::Empty) {
	            $ObjectTypeGUID = $ACE.ObjectType.ToString()
	            $ExtendedRightName = Get-ExtendedRightName -GUID $ObjectTypeGUID
	            if ($ExtendedRightName) {
	                $RightsDisplay = $Rights -replace 'ExtendedRight', "ExtendedRight ($ExtendedRightName)"
	            } else {
	                $RightsDisplay = $Rights -replace 'ExtendedRight', "ExtendedRight ({$ObjectTypeGUID})"
	            }
	        }
	        $DisplayText = "$ACEType - $PrincipalName - $RightsDisplay"
	        $ACEList += [PSCustomObject]@{
	            SID = $PrincipalSID
	            Name = $PrincipalName
	            Type = $ACEType.ToString()
	            Rights = $Rights
	            RightsDisplay = $RightsDisplay
	            ObjectType = if ($ACE.ObjectType -ne [System.Guid]::Empty) { $ACE.ObjectType.ToString() } else { $null }
	            DisplayText = $DisplayText
	        }
	    }
	    return [PSCustomObject]@{
	        Owner = $OwnerObject
	        ACEs = $ACEList
	    }
	} catch {
	    throw
	}
}
function ConvertTo-AccessRules {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    $SecurityDescriptorBytes
	)
	if ($SecurityDescriptorBytes -is [System.DirectoryServices.ActiveDirectorySecurity]) {
	    $SD = $SecurityDescriptorBytes
	}
	else {
	    $sdBytes = $SecurityDescriptorBytes
	    if ($sdBytes -is [System.Array] -and -not ($sdBytes -is [byte[]])) {
	        $sdBytes = $sdBytes[0]
	    }
	    if (-not ($sdBytes -is [byte[]])) {
	        return $null
	    }
	    $SD = New-Object System.DirectoryServices.ActiveDirectorySecurity
	    $SD.SetSecurityDescriptorBinaryForm($sdBytes)
	}
	$OwnerSID = $SD.GetOwner([System.Security.Principal.SecurityIdentifier]).Value
	$AccessRules = $SD.GetAccessRules($true, $true, [System.Security.Principal.SecurityIdentifier])
	return [PSCustomObject]@{
	    SecurityDescriptor = $SD
	    AccessRules        = $AccessRules
	    OwnerSID           = $OwnerSID
	}
}
function Get-GCConnection {
	[CmdletBinding()]
	param()
	if ($Script:GCConnection) {
	    return $Script:GCConnection
	}
	if (-not $Script:LdapConnection -or
	    -not ($Script:LDAPContext -is [hashtable]) -or
	    -not $Script:LDAPContext.ContainsKey('Domain') -or
	    -not $Script:LDAPContext.ContainsKey('Server')) {
	    return $null
	}
	$targets = @()
	if ($Script:LDAPContext.ContainsKey('Server') -and $Script:LDAPContext['Server']) {
	    $targets += $Script:LDAPContext['Server']
	}
	$rootDomainFQDN = $null
	if ($Script:LDAPContext.ContainsKey('RootDomainNamingContext') -and $Script:LDAPContext['RootDomainNamingContext']) {
	    $dcParts = @()
	    $rnc = $Script:LDAPContext['RootDomainNamingContext']
	    while ($rnc -match '^DC=([^,]+),?(.*)$') {
	        $dcParts += $Matches[1]
	        $rnc = $Matches[2]
	    }
	    if ($dcParts.Count -gt 0) {
	        $rootDomainFQDN = ($dcParts -join '.')
	    }
	}
	if ($rootDomainFQDN -and
	    $rootDomainFQDN -ne $Script:LDAPContext['Server'] -and
	    $rootDomainFQDN -ne $Script:LDAPContext['Domain']) {
	    $targets += $rootDomainFQDN
	}
	if ($Script:LDAPContext.ContainsKey('Domain') -and
	    $Script:LDAPContext['Domain'] -and
	    $Script:LDAPContext['Domain'] -ne $Script:LDAPContext['Server']) {
	    $targets += $Script:LDAPContext['Domain']
	}
	$ConnectParams = @{
	    Domain          = $Script:LDAPContext['Domain']
	    AsGlobalCatalog = $true
	    IgnoreSSLErrors = $true
	    TimeoutSeconds  = 5
	}
	if ($Script:LDAPContext.ContainsKey('UseLDAPS') -and $Script:LDAPContext['UseLDAPS']) {
	    $ConnectParams['UseLDAPS'] = $true
	}
	if ($Script:LDAPContext.ContainsKey('AuthMethod') -and
	    $Script:LDAPContext['AuthMethod'] -eq 'Schannel' -and
	    $Script:LDAPContext.ContainsKey('ClientCertificate') -and
	    $Script:LDAPContext['ClientCertificate']) {
	    $ConnectParams['ClientCertificate'] = $Script:LDAPContext['ClientCertificate']
	    $ConnectParams['UseLDAPS'] = $true
	}
	else {
	    $kerbUsed = $Script:LDAPContext.ContainsKey('KerberosUsed') -and ($Script:LDAPContext['KerberosUsed'] -eq $true)
	    $winAuth = $Script:LDAPContext.ContainsKey('AuthMethod') -and ($Script:LDAPContext['AuthMethod'] -eq 'WindowsAuth')
	    $useNegotiate = $kerbUsed -or $winAuth
	    if (-not $useNegotiate -and $Script:LDAPCredential) {
	        $ConnectParams['Credential'] = $Script:LDAPCredential
	    }
	}
	foreach ($GCTarget in $targets) {
	    $ConnectParams['Server'] = $GCTarget
	    $GCConn = Connect-LDAP @ConnectParams
	    if ($GCConn) {
	        $Script:GCConnection = $GCConn
	        return $GCConn
	    }
	}
	return $null
}
function Resolve-SIDViaGC {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$SIDHex,
	    [Parameter(Mandatory=$true)]
	    [string]$SID
	)
	try {
	    $gcConn = Get-GCConnection
	    if (-not $gcConn) { return $null }
	    $gcResults = @(Invoke-LDAPSearch -Filter "(objectSid=$SIDHex)" -Properties @("sAMAccountName","distinguishedName") -SizeLimit 1 -LdapConnection $gcConn -Raw)
	    $gcResult = if ($gcResults -and $gcResults.Count -gt 0) { $gcResults[0] } else { $null }
	    if ($gcResult) {
	        $accountName = $gcResult.sAMAccountName
	        $gcDN = $gcResult.distinguishedName
	        if ($accountName -and $gcDN) {
	            if ($gcDN -match 'DC=([^,]+)') {
	                $gcDomainName = $Matches[1].ToUpper()
	            } else {
	                $gcDomainName = "FOREST"
	            }
	            $resolvedName = "${gcDomainName}\$accountName"
	            return $resolvedName
	        }
	    }
	    return $null
	} catch {
	    if ($_.Exception.InnerException -is [System.DirectoryServices.Protocols.LdapException] -or
	        $_.Exception -is [System.ObjectDisposedException]) {
	        try { if ($Script:GCConnection) { $Script:GCConnection.Dispose() } } catch { }
	        $Script:GCConnection = $null
	    }
	    return $null
	}
}
function Resolve-CrossDomainIdentity {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$Identity
	)
	$result = [PSCustomObject]@{
	    Domain = $null
	    Identity = $Identity
	    IsCrossDomain = $false
	    TargetDomainDN = $null
	    TargetDomainFQDN = $null
	}
	if ($Identity -notmatch '^(.+)\\(.+)$') {
	    return $result
	}
	$specifiedDomain = $Matches[1]
	$result.Identity = $Matches[2]
	$result.Domain = $specifiedDomain
	if (-not $Script:LDAPContext -or -not $Script:LDAPContext.Domain) {
	    return $result
	}
	$currentDomain = $Script:LDAPContext.Domain.Split('.')[0]  # Extract NetBIOS from FQDN
	if ($specifiedDomain -eq $currentDomain) {
	    return $result
	}
	$result.IsCrossDomain = $true
	try {
	    $configurationDN = $Script:LDAPContext.ConfigurationNamingContext
	    if (-not $configurationDN) {
	        $forestRootParts = $Script:LDAPContext.Domain.Split('.')
	        $configurationDN = "CN=Configuration," + (($forestRootParts | ForEach-Object { "DC=$_" }) -join ',')
	    }
	    $partitionsDN = "CN=Partitions,$configurationDN"
	    $partitionResults = @(Invoke-LDAPSearch `
	        -Filter "(nETBIOSName=$specifiedDomain)" `
	        -SearchBase $partitionsDN `
	        -Properties @("nCName") `
	        -SizeLimit 1 `
	        -Raw)
	    if ($partitionResults.Count -gt 0 -and $partitionResults[0].nCName) {
	        $result.TargetDomainDN = $partitionResults[0].nCName
	        $result.TargetDomainFQDN = (($result.TargetDomainDN -replace 'DC=', '' -replace ',', '.')).ToLower()
	    } else {
	    }
	}
	catch {
	}
	return $result
}
function Test-DomainMatch {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$DistinguishedName,
	    [Parameter(Mandatory=$true)]
	    [string]$TargetDomainFQDN
	)
	$dnParts = $DistinguishedName -split ','
	$dcParts = $dnParts | Where-Object { $_ -match '^DC=' } | ForEach-Object { $_ -replace '^DC=', '' }
	$objDomainFQDN = ($dcParts -join '.').ToLower()
	$match = ($objDomainFQDN -eq $TargetDomainFQDN.ToLower())
	if (-not $match) {
	}
	return $match
}
function ConvertFrom-SID {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true, ValueFromPipeline=$true)]
	    [ValidateNotNullOrEmpty()]
	    [string]$SID
	)
	begin {
	    $Script:UNRESOLVABLE_MARKER = "[UNRESOLVABLE]"
	    if (-not $Script:SIDResolutionCache) {
	        $Script:SIDResolutionCache = @{}
	    }
	    if (-not $Script:SIDVerboseCache) {
	        $Script:SIDVerboseCache = @{}
	    }
	    if (-not $Script:NameToSIDCache) {
	        $Script:NameToSIDCache = @{}
	    }
	    if (-not $Script:ForeignDomainCache) {
	        $Script:ForeignDomainCache = @{}
	    }
	}
	process {
	    if (-not $Script:LdapConnection) {
	        Show-NoSessionError -Context "ConvertFrom-SID"
	        return $SID
	    }
	    if ($Script:SIDResolutionCache.ContainsKey($SID)) {
	        $cachedValue = $Script:SIDResolutionCache[$SID]
	        if ($cachedValue.StartsWith($Script:UNRESOLVABLE_MARKER)) {
	            return $cachedValue.Substring($Script:UNRESOLVABLE_MARKER.Length)
	        }
	        return $cachedValue
	    }
	    if ($Script:SIDToName.ContainsKey($SID)) {
	        $resolvedName = $Script:SIDToName[$SID]
	        $Script:SIDResolutionCache[$SID] = $resolvedName
	        $Script:SIDVerboseCache[$SID] = $true
	        $Script:NameToSIDCache[$resolvedName] = $SID
	        return $resolvedName
	    }
	    try {
	        $SIDObj = New-Object System.Security.Principal.SecurityIdentifier($SID)
	        $SIDBytes = New-Object byte[] $SIDObj.BinaryLength
	        $SIDObj.GetBinaryForm($SIDBytes, 0)
	        $SIDHex = ($SIDBytes | ForEach-Object { '\' + $_.ToString('X2') }) -join ''
	        $skipLocalLookup = $false
	        if ($SID -match '^S-1-5-21-(\d+-\d+-\d+)-\d+$') {
	            $sidDomainPart = $matches[1]
	            if ($Script:LDAPContext -and $Script:LDAPContext.DomainSID) {
	                if ($Script:LDAPContext.DomainSID -match '^S-1-5-21-(\d+-\d+-\d+)') {
	                    $localDomainPart = $matches[1]
	                    if ($sidDomainPart -ne $localDomainPart) {
	                        $skipLocalLookup = $true
	                    }
	                }
	            }
	        }
	        $results = @()
	        if (-not $skipLocalLookup) {
	            $results = @(Invoke-LDAPSearch -Filter "(objectSid=$SIDHex)" -Properties "sAMAccountName","distinguishedName","objectClass" -SizeLimit 1)
	        }
	        if ($results -and $results.Count -gt 0) {
	            $result = $results[0]
	            $samAccountName = $result.sAMAccountName
	            if ([string]::IsNullOrWhiteSpace($samAccountName)) {
	                if ($Script:SIDToName.ContainsKey($SID)) {
	                    $resolvedName = $Script:SIDToName[$SID]
	                    $Script:SIDResolutionCache[$SID] = $resolvedName
	                    $Script:SIDVerboseCache[$SID] = $true
	                    return $resolvedName
	                }
	                if ($Script:LDAPContext -and $Script:LDAPContext.Domain) {
	                    $resolvedName = "$SID (UNRESOLVABLE in $($Script:LDAPContext.Domain.ToUpper()))"
	                } else {
	                    $resolvedName = "$SID (UNRESOLVABLE)"
	                }
	                $Script:SIDResolutionCache[$SID] = "$Script:UNRESOLVABLE_MARKER$resolvedName"
	                $Script:SIDVerboseCache[$SID] = $true
	                return $resolvedName
	            }
	            $DN = $result.distinguishedName
	            if ($DN -match 'DC=([^,]+)') {
	                $domainName = $Matches[1].ToUpper()
	            } elseif ($Script:LDAPContext.Domain) {
	                $domainName = $Script:LDAPContext.Domain.Split('.')[0].ToUpper()
	            } else {
	                $domainName = "UNKNOWN"
	            }
	            $accountName = "${domainName}\$samAccountName"
	            $Script:SIDResolutionCache[$SID] = $accountName
	            $Script:SIDVerboseCache[$SID] = $true
	            $Script:NameToSIDCache[$accountName] = $SID
	            return $accountName
	        } else {
	            if ($Script:SIDToName.ContainsKey($SID)) {
	                $resolvedName = $Script:SIDToName[$SID]
	                $Script:SIDResolutionCache[$SID] = $resolvedName
	                $Script:SIDVerboseCache[$SID] = $true
	                $Script:NameToSIDCache[$resolvedName] = $SID
	                return $resolvedName
	            }
	            if ($SID -match '^S-1-5-21-(\d+-\d+-\d+)-\d+$') {
	                $sidDomainPart = $matches[1]
	                $currentDomainSID = $null
	                if ($Script:LDAPContext -and $Script:LDAPContext.DomainSID) {
	                    $currentDomainSID = $Script:LDAPContext.DomainSID
	                }
	                if ($currentDomainSID -and $currentDomainSID -match '^S-1-5-21-(\d+-\d+-\d+)') {
	                    $currentDomainPart = $matches[1]
	                    if ($sidDomainPart -eq $currentDomainPart) {
	                        if ($Script:LDAPContext -and $Script:LDAPContext.Domain) {
	                            $resolvedName = "$SID (UNRESOLVABLE in $($Script:LDAPContext.Domain.ToUpper()))"
	                        } else {
	                            $resolvedName = "$SID (UNRESOLVABLE)"
	                        }
	                        $Script:SIDResolutionCache[$SID] = "$Script:UNRESOLVABLE_MARKER$resolvedName"
	                        $Script:SIDVerboseCache[$SID] = $true
	                        return $resolvedName
	                    }
	                }
	            }
	            $gcResolved = Resolve-SIDViaGC -SIDHex $SIDHex -SID $SID
	            if ($gcResolved) {
	                if ($SID -match '^S-1-5-21-(\d+-\d+-\d+)-\d+$') {
	                    $sidDomainPart = $matches[1]
	                    if ($gcResolved -match '^([^\\]+)\\') {
	                        $foreignDomainName = $matches[1]
	                        $Script:ForeignDomainCache[$sidDomainPart] = $foreignDomainName
	                    }
	                }
	                $Script:SIDResolutionCache[$SID] = $gcResolved
	                $Script:SIDVerboseCache[$SID] = $true
	                $Script:NameToSIDCache[$gcResolved] = $SID
	                return $gcResolved
	            }
	            if ($SID -match '^S-1-5-21-(\d+-\d+-\d+)-\d+$') {
	                $sidDomainPart = $matches[1]
	                if ($Script:ForeignDomainCache.ContainsKey($sidDomainPart)) {
	                    $foreignDomain = $Script:ForeignDomainCache[$sidDomainPart]
	                    $resolvedName = "$SID (UNRESOLVABLE in $foreignDomain)"
	                } else {
	                    $resolvedName = "$SID (FOREIGN)"
	                }
	            } else {
	                $resolvedName = "$SID (UNRESOLVABLE)"
	            }
	            $Script:SIDResolutionCache[$SID] = "$Script:UNRESOLVABLE_MARKER$resolvedName"
	            $Script:SIDVerboseCache[$SID] = $true
	            return $resolvedName
	        }
	    } catch {
	        if ($Script:LDAPContext -and $Script:LDAPContext.Domain) {
	            $resolvedName = "$SID (UNRESOLVABLE in $($Script:LDAPContext.Domain.ToUpper()))"
	        } else {
	            $resolvedName = "$SID (UNRESOLVABLE)"
	        }
	        $Script:SIDResolutionCache[$SID] = "$Script:UNRESOLVABLE_MARKER$resolvedName"
	        $Script:SIDVerboseCache[$SID] = $true
	        return $resolvedName
	    }
	}
}
function ConvertTo-LDAPSIDHex {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true, ValueFromPipeline=$true)]
	    [ValidateNotNullOrEmpty()]
	    [string]$SID
	)
	process {
	    try {
	        $SIDObj = New-Object System.Security.Principal.SecurityIdentifier($SID)
	        $SIDBytes = New-Object byte[] $SIDObj.BinaryLength
	        $SIDObj.GetBinaryForm($SIDBytes, 0)
	        return ($SIDBytes | ForEach-Object { '\' + $_.ToString('X2') }) -join ''
	    } catch {
	        return $null
	    }
	}
}
function ConvertTo-SID {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true, ValueFromPipeline=$true)]
	    [ValidateNotNullOrEmpty()]
	    [string]$Identity
	)
	begin {
	    if (-not $Script:NameToSIDCache) {
	        $Script:NameToSIDCache = @{}
	    }
	}
	process {
	    $Identity = $Identity.Trim()
	    if ([string]::IsNullOrEmpty($Identity)) {
	        return $null
	    }
	    if ($Identity -match '^S-1-\d+-') {
	        return $Identity
	    }
	    if (-not $Script:LdapConnection) {
	        Show-NoSessionError -Context "ConvertTo-SID"
	        return $null
	    }
	    if ($Script:NameToSIDCache.ContainsKey($Identity)) {
	        $cachedSID = $Script:NameToSIDCache[$Identity]
	        if ($cachedSID) {
	        } else {
	        }
	        return $cachedSID
	    }
	    if ($Script:NameToSID.ContainsKey($Identity)) {
	        $sid = $Script:NameToSID[$Identity]
	        $Script:NameToSIDCache[$Identity] = $sid
	        return $sid
	    }
	    if ($Identity -notmatch '^CN=') {
	        try {
	            $ntAccount = New-Object System.Security.Principal.NTAccount($Identity)
	            $sidObj = $ntAccount.Translate([System.Security.Principal.SecurityIdentifier])
	            if ($sidObj) {
	                $sid = $sidObj.Value
	                $Script:NameToSIDCache[$Identity] = $sid
	                return $sid
	            }
	        }
	        catch {
	        }
	    }
	    try {
	        $filter = $null
	        if ($Identity -match '^CN=.+,DC=') {
	            $escapedDN = $Identity -replace '\\', '\\5c' -replace '\(', '\\28' -replace '\)', '\\29' -replace '\*', '\\2a'
	            $filter = "(distinguishedName=$escapedDN)"
	            $results = Invoke-LDAPSearch -Filter $filter -Properties "objectSid","sAMAccountName","distinguishedName" -SizeLimit 1
	            $resultsArray = @($results)
	            if ($resultsArray.Count -gt 0 -and $resultsArray[0]) {
	                $result = $resultsArray[0]
	                $propNames = @($result.PSObject.Properties.Name)
	                $sid = $result.objectSid
	                if ($sid) {
	                    $Script:NameToSIDCache[$Identity] = $sid
	                    if ($result.sAMAccountName) {
	                        $sam = $result.sAMAccountName
	                        if ($Identity -match 'DC=([^,]+)') {
	                            $domainName = $Matches[1].ToUpper()
	                            $fullName = "$domainName\$sam"
	                            if (-not $Script:NameToSIDCache.ContainsKey($fullName)) {
	                                $Script:NameToSIDCache[$fullName] = $sid
	                            }
	                        }
	                    }
	                    return $sid
	                }
	                else {
	                    return $null
	                }
	            }
	            else {
	                return $null
	            }
	        }
	        elseif ($Identity -match '^[^@]+@[^@]+\.[^@]+$') {
	            $filter = "(userPrincipalName=$Identity)"
	        }
	        elseif ($Identity -match '^([^\\]+)\\(.+)$') {
	            $crossDomainInfo = Resolve-CrossDomainIdentity -Identity $Identity
	            if ($crossDomainInfo.IsCrossDomain) {
	                $gcConn = Get-GCConnection
	                if (-not $gcConn) {
	                    return $null
	                }
	                $filter = "(sAMAccountName=$($crossDomainInfo.Identity))"
	                $searchBase = $crossDomainInfo.TargetDomainDN
	                $results = Invoke-LDAPSearch -Filter $filter -Properties "objectSid","sAMAccountName","distinguishedName" -SizeLimit 10 -SearchBase $searchBase -LdapConnection $gcConn
	                if ($results -and $crossDomainInfo.TargetDomainFQDN) {
	                    $resultsArray = @($results)
	                    $filteredResults = @()
	                    foreach ($res in $resultsArray) {
	                        if ($res.distinguishedName) {
	                            if (Test-DomainMatch -DistinguishedName $res.distinguishedName -TargetDomainFQDN $crossDomainInfo.TargetDomainFQDN) {
	                                $filteredResults += $res
	                            }
	                        }
	                    }
	                    $results = $filteredResults
	                }
	            } else {
	                $filter = "(sAMAccountName=$($crossDomainInfo.Identity))"
	                $results = Invoke-LDAPSearch -Filter $filter -Properties "objectSid","sAMAccountName","distinguishedName" -SizeLimit 1
	            }
	        }
	        else {
	            $filter = "(sAMAccountName=$Identity)"
	            $results = Invoke-LDAPSearch -Filter $filter -Properties "objectSid","sAMAccountName","distinguishedName" -SizeLimit 1
	        }
	        $resultsArray = @($results)
	        if ($resultsArray.Count -gt 0 -and $resultsArray[0]) {
	            $result = $resultsArray[0]
	            $sid = $result.objectSid
	            $Script:NameToSIDCache[$Identity] = $sid
	            if ($result.sAMAccountName -and $result.distinguishedName) {
	                $sam = $result.sAMAccountName
	                $dn = $result.distinguishedName
	                if ($dn -match 'DC=([^,]+)') {
	                    $domainName = $Matches[1].ToUpper()
	                    $fullName = "$domainName\$sam"
	                    if (-not $Script:NameToSIDCache.ContainsKey($fullName)) {
	                        $Script:NameToSIDCache[$fullName] = $sid
	                    }
	                }
	            }
	            return $sid
	        }
	        else {
	            $Script:NameToSIDCache[$Identity] = $null
	            return $null
	        }
	    }
	    catch {
	        return $null
	    }
	}
}
if (-not $Script:PrivilegedCheckCache) {
	$Script:PrivilegedCheckCache = @{}
