	        [char[]]@(0x3F, 0x48, 0x2B),  # 95 _
	        [char[]]@(0x7B, 0x55, 0x28),  # 96 `
	        [char[]]@(0x78, 0x70, 0x23),  # 97 a
	        [char[]]@(0x29, 0x69, 0x41),  # 98 b
	        [char[]]@(0x28, 0x2E, 0x34),  # 99 c
	        [char[]]@(0x73, 0x4C, 0x09),  # 100 d
	        [char[]]@(0x59, 0x21, 0x2A),  # 101 e
	        [char[]]@(0x33, 0x24, 0x44),  # 102 f
	        [char[]]@(0x7F, 0x4E, 0x3F),  # 103 g
	        [char[]]@(0x6D, 0x50, 0x77),  # 104 h
	        [char[]]@(0x55, 0x09, 0x3B),  # 105 i
	        [char[]]@(0x53, 0x56, 0x55),  # 106 j
	        [char[]]@(0x7C, 0x73, 0x69),  # 107 k
	        [char[]]@(0x3A, 0x35, 0x61),  # 108 l
	        [char[]]@(0x5F, 0x61, 0x63),  # 109 m
	        [char[]]@(0x65, 0x4B, 0x50),  # 110 n
	        [char[]]@(0x46, 0x58, 0x67),  # 111 o
	        [char[]]@(0x58, 0x3B, 0x51),  # 112 p
	        [char[]]@(0x31, 0x57, 0x49),  # 113 q
	        [char[]]@(0x69, 0x22, 0x4F),  # 114 r
	        [char[]]@(0x6C, 0x6D, 0x46),  # 115 s
	        [char[]]@(0x5A, 0x4D, 0x68),  # 116 t
	        [char[]]@(0x48, 0x25, 0x7C),  # 117 u
	        [char[]]@(0x27, 0x28, 0x36),  # 118 v
	        [char[]]@(0x5C, 0x46, 0x70),  # 119 w
	        [char[]]@(0x3D, 0x4A, 0x6E),  # 120 x
	        [char[]]@(0x24, 0x32, 0x7A),  # 121 y
	        [char[]]@(0x79, 0x41, 0x2F),  # 122 z
	        [char[]]@(0x37, 0x3D, 0x5F),  # 123 {
	        [char[]]@(0x60, 0x5F, 0x4B),  # 124 |
	        [char[]]@(0x51, 0x4F, 0x5A),  # 125 }
	        [char[]]@(0x20, 0x42, 0x2C),  # 126 ~
	        [char[]]@(0x36, 0x65, 0x57)   # 127
	    )
	    $script:VBECombination = @(
	        0, 1, 2, 0, 1, 2, 1, 2, 2, 1, 2, 1, 0, 2, 1, 2,
	        0, 2, 1, 2, 0, 0, 1, 2, 2, 1, 0, 2, 1, 2, 2, 1,
	        0, 0, 2, 1, 2, 1, 2, 0, 2, 0, 0, 1, 2, 0, 2, 1,
	        0, 2, 1, 2, 0, 0, 1, 2, 2, 0, 0, 1, 2, 0, 2, 1
	    )
	    $script:VBEBadBytes = @(60, 62, 64)  # < > @
	}
	process {
	    try {
	        if ($EncodedScript -match '#@~\^.{6}==(.+).{6}==\^#~@') {
	            $encodedData = $Matches[1]
	            if ([string]::IsNullOrEmpty($encodedData)) {
	                return ""
	            }
	            $processedData = $encodedData
	            $processedData = $processedData -replace '@&', "`n"    # Line feed (chr(10))
	            $processedData = $processedData -replace '@#', "`r"    # Carriage return (chr(13))
	            $processedData = $processedData -replace '@\*', '>'    # Greater than
	            $processedData = $processedData -replace '@!', '<'     # Less than
	            $processedData = $processedData -replace '@\$', '@'    # At sign
	            $decoded = New-Object System.Text.StringBuilder
	            $index = -1
	            foreach ($char in $processedData.ToCharArray()) {
	                $byteValue = [int][char]$char
	                if ($byteValue -lt 128) {
	                    $index++
	                }
	                if (($byteValue -eq 9 -or ($byteValue -gt 31 -and $byteValue -lt 128)) -and
	                    $byteValue -notin $script:VBEBadBytes) {
	                    if ($byteValue -lt $script:VBEDecodings.Count) {
	                        $triplet = $script:VBEDecodings[$byteValue]
	                        $combinationIndex = $script:VBECombination[$index % 64]
	                        $decodedChar = $triplet[$combinationIndex]
	                        [void]$decoded.Append($decodedChar)
	                    } else {
	                        [void]$decoded.Append($char)
	                    }
	                } else {
	                    [void]$decoded.Append($char)
	                }
	            }
	            $decodedScript = $decoded.ToString()
	            return $decodedScript
	        } else {
	            return $EncodedScript
	        }
	    } catch {
	        return "[VBE Decoding Failed: $_]"
	    }
	}
	end {
	}
}
function ConvertFrom-Base64OrFile {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true)]
	    [string]$InputValue,
	    [Parameter(Mandatory = $false)]
	    [ValidateSet("Kirbi", "Ccache", "Certificate", "Any")]
	    [string]$ExpectedFormat = "Any",
	    [Parameter(Mandatory = $false)]
	    [string]$ParameterName = "Input"
	)
	process {
	    $result = [PSCustomObject]@{
	        Success = $false
	        Data    = $null
	        Source  = $null
	        Format  = $null
	        Error   = $null
	    }
	    if ([string]::IsNullOrWhiteSpace($InputValue)) {
	        $result.Error = "$ParameterName cannot be empty"
	        return $result
	    }
	    $decodedBytes = $null
	    $isValidBase64 = $false
	    try {
	        $base64String = $InputValue.Trim()
	        $base64String = $base64String -replace '-', '+' -replace '_', '/'
	        $paddingNeeded = $base64String.Length % 4
	        if ($paddingNeeded -gt 0) {
	            $base64String += ('=' * (4 - $paddingNeeded))
	        }
	        $isPathLike = $base64String -match '^[A-Za-z]:\\' -or        # Windows absolute path
	                      $base64String -match '^\\\\' -or                 # UNC path
	                      $base64String -match '^\.\.?[/\\]' -or           # Relative path
	                      $base64String -match '^[/~]' -or                 # Unix path
	                      $base64String -match '\.[a-zA-Z0-9]{2,5}$' -and  # File extension
	                      $base64String.Length -lt 100                      # Short string with extension
	        if ($isPathLike) {
	        }
	        else {
	            $base64Pattern = '^[A-Za-z0-9+/=]+$'
	            if ($base64String -match $base64Pattern -and $base64String.Length -ge 4) {
	                $decodedBytes = [Convert]::FromBase64String($base64String)
	                if ($decodedBytes.Length -gt 0) {
	                    $formatValid = $false
	                    $detectedFormat = "Unknown"
	                    switch ($ExpectedFormat) {
	                        "Kirbi" {
	                            if ($decodedBytes[0] -eq 0x76) {
	                                $formatValid = $true
	                                $detectedFormat = "KRB-CRED"
	                            }
	                            elseif ($decodedBytes[0] -eq 0x61) {
	                                $formatValid = $true
	                                $detectedFormat = "RawTicket"
	                            }
	                            else {
	                            }
	                        }
	                        "Ccache" {
	                            if ($decodedBytes.Length -ge 2) {
	                                $version = ([uint16]$decodedBytes[0] -shl 8) -bor $decodedBytes[1]
	                                if ($version -ge 0x0501 -and $version -le 0x0504) {
	                                    $formatValid = $true
	                                    $detectedFormat = "Ccache-v$($version -band 0xFF)"
	                                }
	                                else {
	                                }
	                            }
	                        }
	                        "Certificate" {
	                            if ($decodedBytes[0] -eq 0x30) {
	                                if ($decodedBytes.Length -ge 2) {
	                                    $formatValid = $true
	                                    $detectedFormat = "PFX/PKCS12"
	                                }
	                            }
	                            else {
	                            }
	                        }
	                        "Any" {
	                            $formatValid = $true
	                            if ($decodedBytes[0] -eq 0x76) { $detectedFormat = "KRB-CRED" }
	                            elseif ($decodedBytes[0] -eq 0x61) { $detectedFormat = "RawTicket" }
	                            elseif ($decodedBytes.Length -ge 2 -and (([uint16]$decodedBytes[0] -shl 8) -bor $decodedBytes[1]) -ge 0x0501 -and (([uint16]$decodedBytes[0] -shl 8) -bor $decodedBytes[1]) -le 0x0504) { $detectedFormat = "Ccache" }
	                            elseif ($decodedBytes[0] -eq 0x30) { $detectedFormat = "ASN.1" }
	                            else { $detectedFormat = "Binary" }
	                        }
	                    }
	                    if ($formatValid) {
	                        $isValidBase64 = $true
	                        $result.Success = $true
	                        $result.Data = $decodedBytes
	                        $result.Source = "Base64"
	                        $result.Format = $detectedFormat
	                        return $result
	                    }
	                    else {
	                        $decodedBytes = $null
	                    }
	                }
	            }
	            else {
	            }
	        }
	    }
	    catch {
	        $decodedBytes = $null
	    }
	    if (Test-Path -Path $InputValue -PathType Leaf) {
	        try {
	            $fileBytes = [System.IO.File]::ReadAllBytes($InputValue)
	            if ($fileBytes.Length -eq 0) {
	                $result.Error = "File is empty: $InputValue"
	                return $result
	            }
	            $detectedFormat = "Unknown"
	            $formatValid = $false
	            switch ($ExpectedFormat) {
	                "Kirbi" {
	                    if ($fileBytes[0] -eq 0x76) {
	                        $formatValid = $true
	                        $detectedFormat = "KRB-CRED"
	                    }
	                    elseif ($fileBytes[0] -eq 0x61) {
	                        $formatValid = $true
	                        $detectedFormat = "RawTicket"
	                    }
	                    else {
	                        $result.Error = "Invalid Kirbi file format. Expected KRB-CRED (0x76) or Ticket (0x61), got 0x$($fileBytes[0].ToString('X2'))"
	                        return $result
	                    }
	                }
	                "Ccache" {
	                    if ($fileBytes.Length -ge 2) {
	                        $version = ([uint16]$fileBytes[0] -shl 8) -bor $fileBytes[1]
	                        if ($version -ge 0x0501 -and $version -le 0x0504) {
	                            $formatValid = $true
	                            $detectedFormat = "Ccache-v$($version -band 0xFF)"
	                        }
	                        else {
	                            $result.Error = "Invalid Ccache file format. Expected version 0x0501-0x0504, got 0x$($version.ToString('X4'))"
	                            return $result
	                        }
	                    }
	                    else {
	                        $result.Error = "Ccache file too small"
	                        return $result
	                    }
	                }
	                "Certificate" {
	                    if ($fileBytes[0] -eq 0x30) {
	                        $formatValid = $true
	                        $detectedFormat = "PFX/PKCS12"
	                    }
	                    elseif ($fileBytes.Length -ge 10) {
	                        $header = [System.Text.Encoding]::ASCII.GetString($fileBytes, 0, [Math]::Min(11, $fileBytes.Length))
	                        if ($header.StartsWith("-----BEGIN")) {
	                            $formatValid = $true
	                            $detectedFormat = "PEM"
	                        }
	                    }
	                    if (-not $formatValid) {
	                        $result.Error = "Invalid certificate file format. Expected PFX/PKCS12 (0x30) or PEM"
	                        return $result
	                    }
	                }
	                "Any" {
	                    $formatValid = $true
	                    if ($fileBytes[0] -eq 0x76) { $detectedFormat = "KRB-CRED" }
	                    elseif ($fileBytes[0] -eq 0x61) { $detectedFormat = "RawTicket" }
	                    elseif ($fileBytes.Length -ge 2 -and (([uint16]$fileBytes[0] -shl 8) -bor $fileBytes[1]) -ge 0x0501 -and (([uint16]$fileBytes[0] -shl 8) -bor $fileBytes[1]) -le 0x0504) { $detectedFormat = "Ccache" }
	                    elseif ($fileBytes[0] -eq 0x30) { $detectedFormat = "ASN.1" }
	                    else { $detectedFormat = "Binary" }
	                }
	            }
	            $result.Success = $true
	            $result.Data = $fileBytes
	            $result.Source = "File"
	            $result.Format = $detectedFormat
	            return $result
	        }
	        catch {
	            $result.Error = "Failed to read file '$InputValue': $_"
	            return $result
	        }
	    }
	    else {
	        if ($isValidBase64 -eq $false -and $null -eq $decodedBytes) {
	            $result.Error = "Input is neither a valid Base64 string nor an existing file path: $InputValue"
	        }
	        else {
	            $result.Error = "File not found: $InputValue"
	        }
	        return $result
	    }
	}
}
function ConvertFrom-ManagedPassword {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true, ValueFromPipeline = $true)]
	    [byte[]]$Blob,
	    [Parameter(Mandatory = $false)]
	    [switch]$AsSecureString
	)
	begin {
	    $HeaderSize = 16
	}
	process {
	    try {
	        if ($null -eq $Blob) {
	            return $null
	        }
	        if ($Blob.Length -lt $HeaderSize) {
	            return $null
	        }
	        $stream = New-Object System.IO.MemoryStream($Blob, $false)
	        $reader = New-Object System.IO.BinaryReader($stream)
	        try {
	            $version = $reader.ReadUInt16()
	            if ($version -ne 1) {
	                return $null
	            }
	            [void]$reader.ReadUInt16()
	            $length = $reader.ReadInt32()
	            if ($Blob.Length -lt $length) {
	                return $null
	            }
	            $currentPasswordOffset = $reader.ReadUInt16()
	            $previousPasswordOffset = $reader.ReadUInt16()
	            $queryPasswordIntervalOffset = $reader.ReadUInt16()
	            $unchangedPasswordIntervalOffset = $reader.ReadUInt16()
	            if ($currentPasswordOffset -lt $HeaderSize) {
	                return $null
	            }
	            if ($queryPasswordIntervalOffset -lt $currentPasswordOffset) {
	                return $null
	            }
	            $minRequiredLength = $unchangedPasswordIntervalOffset + 8
	            if ($Blob.Length -lt $minRequiredLength) {
	                return $null
	            }
	            $currentPasswordEnd = if ($previousPasswordOffset -gt 0 -and $previousPasswordOffset -gt $currentPasswordOffset) {
	                $previousPasswordOffset
	            } else {
	                $queryPasswordIntervalOffset
	            }
	            if ($currentPasswordEnd -le $currentPasswordOffset) {
	                return $null
	            }
	            $currentPasswordLength = $currentPasswordEnd - $currentPasswordOffset
	            $currentPasswordBytes = New-Object byte[] $currentPasswordLength
	            [Array]::Copy($Blob, $currentPasswordOffset, $currentPasswordBytes, 0, $currentPasswordLength)
	            $currentPassword = Read-NullTerminatedUnicodeString -Bytes $currentPasswordBytes
	            if ([string]::IsNullOrEmpty($currentPassword)) {
	            }
	            $previousPassword = $null
	            if ($previousPasswordOffset -gt 0 -and $previousPasswordOffset -gt $currentPasswordOffset -and $previousPasswordOffset -lt $queryPasswordIntervalOffset) {
	                $previousPasswordLength = $queryPasswordIntervalOffset - $previousPasswordOffset
	                $previousPasswordBytes = New-Object byte[] $previousPasswordLength
	                [Array]::Copy($Blob, $previousPasswordOffset, $previousPasswordBytes, 0, $previousPasswordLength)
	                $previousPassword = Read-NullTerminatedUnicodeString -Bytes $previousPasswordBytes
	            }
	            $queryIntervalBytes = New-Object byte[] 8
	            [Array]::Copy($Blob, $queryPasswordIntervalOffset, $queryIntervalBytes, 0, 8)
	            $queryIntervalTicks = [BitConverter]::ToInt64($queryIntervalBytes, 0)
	            $queryPasswordInterval = [TimeSpan]::FromTicks($queryIntervalTicks)
	            $unchangedIntervalBytes = New-Object byte[] 8
	            [Array]::Copy($Blob, $unchangedPasswordIntervalOffset, $unchangedIntervalBytes, 0, 8)
	            $unchangedIntervalTicks = [BitConverter]::ToInt64($unchangedIntervalBytes, 0)
	            $unchangedPasswordInterval = [TimeSpan]::FromTicks($unchangedIntervalTicks)
	            $currentNTHash = $null
	            $previousNTHash = $null
	            if (-not [string]::IsNullOrEmpty($currentPassword)) {
	                $currentNTHash = Get-NTHashFromPassword -Password $currentPassword
	            }
	            if (-not [string]::IsNullOrEmpty($previousPassword)) {
	                $previousNTHash = Get-NTHashFromPassword -Password $previousPassword
	            }
	            if ($AsSecureString) {
	                $secureCurrentPassword = $null
	                $securePreviousPassword = $null
	                if (-not [string]::IsNullOrEmpty($currentPassword)) {
	                    $secureCurrentPassword = New-Object System.Security.SecureString
	                    foreach ($char in $currentPassword.ToCharArray()) {
	                        $secureCurrentPassword.AppendChar($char)
	                    }
	                    $secureCurrentPassword.MakeReadOnly()
	                }
	                if (-not [string]::IsNullOrEmpty($previousPassword)) {
	                    $securePreviousPassword = New-Object System.Security.SecureString
	                    foreach ($char in $previousPassword.ToCharArray()) {
	                        $securePreviousPassword.AppendChar($char)
	                    }
	                    $securePreviousPassword.MakeReadOnly()
	                }
	                return [PSCustomObject]@{
	                    Version                   = $version
	                    CurrentPassword           = $secureCurrentPassword
	                    PreviousPassword          = $securePreviousPassword
	                    CurrentNTHash             = $currentNTHash
	                    PreviousNTHash            = $previousNTHash
	                    QueryPasswordInterval     = $queryPasswordInterval
	                    UnchangedPasswordInterval = $unchangedPasswordInterval
	                }
	            } else {
	                return [PSCustomObject]@{
	                    Version                   = $version
	                    CurrentPassword           = $currentPassword
	                    PreviousPassword          = $previousPassword
	                    CurrentNTHash             = $currentNTHash
	                    PreviousNTHash            = $previousNTHash
	                    QueryPasswordInterval     = $queryPasswordInterval
	                    UnchangedPasswordInterval = $unchangedPasswordInterval
	                }
	            }
	        } finally {
	            if ($reader) { $reader.Dispose() }
	            if ($stream) { $stream.Dispose() }
	        }
	    } catch {
	        return $null
	    }
	}
}
function Read-NullTerminatedUnicodeString {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true)]
	    [AllowEmptyCollection()]
	    [byte[]]$Bytes
	)
	if ($null -eq $Bytes -or $Bytes.Length -lt 2) {
	    return [string]::Empty
	}
	$effectiveLength = $Bytes.Length
	if ($effectiveLength % 2 -ne 0) {
	    $effectiveLength = $effectiveLength - 1
	}
	if ($effectiveLength -lt 2) {
	    return [string]::Empty
	}
	$nullIndex = -1
	for ($i = 0; $i -lt $effectiveLength; $i += 2) {
	    if ($Bytes[$i] -eq 0 -and $Bytes[$i + 1] -eq 0) {
	        $nullIndex = $i
	        break
	    }
	}
	if ($nullIndex -eq -1) {
	    $nullIndex = $effectiveLength
	}
	if ($nullIndex -eq 0) {
	    return [string]::Empty
	}
	return [System.Text.Encoding]::Unicode.GetString($Bytes, 0, $nullIndex)
}
function Get-NTHashFromPassword {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true)]
	    [AllowEmptyString()]
	    [string]$Password
	)
	if ([string]::IsNullOrEmpty($Password)) {
	    return $null
	}
	try {
	    $passwordBytes = [System.Text.Encoding]::Unicode.GetBytes($Password)
	    $ntHashBytes = Get-MD4Hash -Data $passwordBytes
	    if ($null -eq $ntHashBytes -or $ntHashBytes.Length -ne 16) {
	        return $null
	    }
	    $ntHashHex = ($ntHashBytes | ForEach-Object { $_.ToString("X2") }) -join ''
	    return $ntHashHex
	} catch {
	    return $null
	}
}
function ConvertFrom-LAPSEncryptedPassword {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true, ValueFromPipeline = $true)]
	    [byte[]]$Blob,
	    [Parameter(Mandatory = $false)]
	    [switch]$Decrypt
	)
	begin {
	    $HeaderSize = 16
	}
	process {
	    try {
	        if ($null -eq $Blob) {
	            return $null
	        }
	        if ($Blob.Length -lt 20) {
	            return $null
	        }
	        $encryptedData = $null
	        $updateTimestamp = $null
	        if ($Blob[0] -eq 0x30) {
	            $encryptedData = $Blob
	        } else {
	            try {
	                $highDword = [BitConverter]::ToUInt32($Blob, 0)
	                $lowDword = [BitConverter]::ToUInt32($Blob, 4)
	                $fileTime = ([Int64]$highDword -shl 32) -bor [Int64]$lowDword
	                $minFileTime = 125911584000000000  # 2000-01-01
	                $maxFileTime = 157766880000000000  # 2100-01-01
	                if ($fileTime -gt $minFileTime -and $fileTime -lt $maxFileTime) {
	                    $updateTimestamp = [DateTime]::FromFileTimeUtc($fileTime)
	                } else {
	                }
	            } catch {
	            }
	            $encryptedSize = [BitConverter]::ToUInt32($Blob, 8)
	            $flags = [BitConverter]::ToUInt32($Blob, 12)
	            if ($Blob.Length -ge $HeaderSize + $encryptedSize) {
	                $encryptedData = New-Object byte[] $encryptedSize
	                [Array]::Copy($Blob, $HeaderSize, $encryptedData, 0, $encryptedSize)
	            } else {
	                $remainingSize = $Blob.Length - $HeaderSize
	                $encryptedData = New-Object byte[] $remainingSize
	                [Array]::Copy($Blob, $HeaderSize, $encryptedData, 0, $remainingSize)
	            }
	        }
	        $targetSID = $null
	        $contentEncryptionAlgorithm = $null
	        $keyEncryptionAlgorithm = $null
	        try {
	            $cmsInfo = Parse-CMSEnvelopedData -Data $encryptedData
	            if ($cmsInfo) {
	                $targetSID = $cmsInfo.TargetSID
	                $contentEncryptionAlgorithm = $cmsInfo.ContentEncryptionAlgorithm
	                $keyEncryptionAlgorithm = $cmsInfo.KeyEncryptionAlgorithm
	            }
	        } catch {
	        }
	        $targetSIDName = $null
	        if ($targetSID) {
	            try {
	                $targetSIDName = ConvertFrom-SID -SID $targetSID
	            } catch {
	                $targetSIDName = $targetSID
	            }
	        }
	        $result = [PSCustomObject]@{
	            UpdateTimestamp            = $updateTimestamp
	            EncryptedSize              = if ($encryptedData) { $encryptedData.Length } else { $Blob.Length }
	            TargetSID                  = $targetSID
	            TargetSIDName              = $targetSIDName
	            ContentEncryptionAlgorithm = $contentEncryptionAlgorithm
	            KeyEncryptionAlgorithm     = $keyEncryptionAlgorithm
	            Password                   = $null
	            Account                    = $null
	            DecryptionSucceeded        = $false
	            DecryptionError            = $null
	        }
	        if ($Decrypt) {
	            try {
	                $decryptedData = $null
	                try {
	                    $decryptedData = Invoke-NCryptUnprotectSecret -ProtectedBlob $Blob
	                } catch {
	                    $fullError = $_.Exception.Message
	                    if ($encryptedData -and $encryptedData.Length -ne $Blob.Length) {
	                        try {
	                            $decryptedData = Invoke-NCryptUnprotectSecret -ProtectedBlob $encryptedData
	                        } catch {
	                            throw $fullError
	                        }
	                    } else {
	                        throw
	                    }
	                }
	                if ($decryptedData -and $decryptedData.Length -gt 0) {
	                    $jsonString = [System.Text.Encoding]::Unicode.GetString($decryptedData)
	                    $jsonString = $jsonString.TrimEnd([char]0)
	                    if ($jsonString.StartsWith('{')) {
	                        try {
	                            $lapsData = $jsonString | ConvertFrom-Json
	                            if ($null -ne $lapsData.p) {
	                                $result.Password = $lapsData.p
	                                $result.Account = $lapsData.n
	                                $result.DecryptionSucceeded = $true
	                                if ($lapsData.t) {
	                                    try {
	                                        $fileTime = [Convert]::ToInt64($lapsData.t, 16)
	                                        $result.UpdateTimestamp = [DateTime]::FromFileTimeUtc($fileTime)
	                                    } catch {
	                                    }
	                                }
	                            } else {
	                                $result.DecryptionError = "JSON structure invalid - missing 'p' property"
	                            }
	                        } catch {
	                            $result.DecryptionError = "JSON parse error: $_"
	                        }
	                    } else {
	                        $result.Password = $jsonString
	                        $result.DecryptionSucceeded = $true
	                    }
	                } else {
	                    $result.DecryptionError = "NCryptUnprotectSecret returned empty data"
	                }
	            } catch {
	                $errorMessage = $_.Exception.Message
	                $result.DecryptionError = $errorMessage
	                if ($errorMessage -match "0x8009310B") {
	                    $result.DecryptionError = "DPAPI-NG not supported - requires domain-joined system for LAPS v2 encrypted password decryption"
	                } elseif ($errorMessage -match "0x8009002C") {
	                    $result.DecryptionError = "CMS format error - encrypted blob may be corrupted or incompatible"
	                } elseif ($errorMessage -match "0x80090034" -or $errorMessage -match "NTE_DECRYPTION_FAILURE") {
	                    $result.DecryptionError = "Access denied - current user is not authorized to decrypt this password"
	                } elseif ($errorMessage -match "0x80070005" -or $errorMessage -match "ACCESS_DENIED") {
	                    $result.DecryptionError = "Access denied - not a member of authorized group ($targetSIDName)"
	                }
	            }
	        }
	        return $result
	    } catch {
	        return $null
	    }
	}
}
function Parse-CMSEnvelopedData {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true)]
	    [byte[]]$Data
	)
	$result = @{
	    TargetSID = $null
	    ContentEncryptionAlgorithm = $null
	    KeyEncryptionAlgorithm = $null
	}
	try {
	    for ($i = 0; $i -lt $Data.Length - 8; $i++) {
	        if ($Data[$i] -eq 0x01 -and $Data[$i + 1] -ge 4 -and $Data[$i + 1] -le 6) {
	            $subAuthCount = $Data[$i + 1]
	            if ($i + 8 + ($subAuthCount * 4) -gt $Data.Length) {
	                continue
	            }
	            if ($Data[$i + 2] -eq 0 -and $Data[$i + 3] -eq 0 -and
	                $Data[$i + 4] -eq 0 -and $Data[$i + 5] -eq 0 -and
	                $Data[$i + 6] -eq 0 -and $Data[$i + 7] -eq 5) {
	                $subAuths = @()
	                for ($j = 0; $j -lt $subAuthCount; $j++) {
	                    $offset = $i + 8 + ($j * 4)
	                    $subAuth = [BitConverter]::ToUInt32($Data, $offset)
	                    $subAuths += $subAuth
	                }
	                $sidString = "S-1-5-" + ($subAuths -join '-')
	                if ($sidString -match '^S-1-5-21-\d+-\d+-\d+(-\d+)?$') {
	                    $result.TargetSID = $sidString
	                    break
	                }
	            }
	        }
	    }
	    $aes256GcmOid = @(0x60, 0x86, 0x48, 0x01, 0x65, 0x03, 0x04, 0x01, 0x2E)
	    if (Find-BytePattern -Data $Data -Pattern $aes256GcmOid) {
	        $result.ContentEncryptionAlgorithm = "AES-256-GCM (2.16.840.1.101.3.4.1.46)"
	    }
	} catch {
	}
	return $result
}
function Find-BytePattern {
	[CmdletBinding()]
	param(
	    [byte[]]$Data,
	    [byte[]]$Pattern
	)
	if ($null -eq $Data -or $null -eq $Pattern -or $Data.Length -lt $Pattern.Length) {
	    return $false
	}
	for ($i = 0; $i -le $Data.Length - $Pattern.Length; $i++) {
	    $match = $true
	    for ($j = 0; $j -lt $Pattern.Length; $j++) {
	        if ($Data[$i + $j] -ne $Pattern[$j]) {
	            $match = $false
	            break
	        }
	    }
	    if ($match) {
	        return $true
	    }
	}
	return $false
}
function Invoke-NCryptUnprotectSecret {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true)]
	    [byte[]]$ProtectedBlob
	)
	$ncryptSignatures = @"
using System;
using System.Runtime.InteropServices;
public class NCryptInterop
{
	// NCryptUnprotectSecret flags
	public const int NCRYPT_UNPROTECT_NO_DECRYPT = 0x00000001;
	public const int NCRYPT_SILENT_FLAG = 0x00000040;
	// SECURITY_STATUS values
	public const int ERROR_SUCCESS = 0;
	public const int NTE_DECRYPTION_FAILURE = unchecked((int)0x80090034);
	[StructLayout(LayoutKind.Sequential)]
	public struct NCryptDescriptor
	{
	    public IntPtr pDescriptorString;
	}
	[DllImport("ncrypt.dll", CharSet = CharSet.Unicode)]
	public static extern int NCryptUnprotectSecret(
	    IntPtr phDescriptor,           // Optional output descriptor handle
	    int dwFlags,                   // Flags
	    [In] byte[] pbProtectedBlob,   // Protected data
	    int cbProtectedBlob,           // Size of protected data
	    IntPtr pMemPara,               // Memory allocation (NULL = LocalAlloc)
	    IntPtr hWnd,                   // Window handle for UI (NULL for silent)
	    out IntPtr ppbData,            // Output: decrypted data
	    out int pcbData                // Output: size of decrypted data
	);
	[DllImport("kernel32.dll")]
	public static extern IntPtr LocalFree(IntPtr hMem);
}
"@
	if (-not ([System.Management.Automation.PSTypeName]'NCryptInterop').Type) {
	    try {
	        Add-Type -TypeDefinition $ncryptSignatures -Language CSharp -ErrorAction Stop
	    } catch {
	        if ($_.Exception.Message -notmatch "already exists") {
	            throw $_
	        }
	    }
	}
	$ppbData = [IntPtr]::Zero
	$pcbData = 0
	try {
	    $result = [NCryptInterop]::NCryptUnprotectSecret(
	        [IntPtr]::Zero,                      # No descriptor output needed
	        [NCryptInterop]::NCRYPT_SILENT_FLAG, # Silent mode
	        $ProtectedBlob,                      # Protected data
	        $ProtectedBlob.Length,               # Size
	        [IntPtr]::Zero,                      # Default memory allocation
	        [IntPtr]::Zero,                      # No UI window
	        [ref]$ppbData,                       # Output pointer
	        [ref]$pcbData                        # Output size
	    )
	    if ($result -ne 0) {
	        $errorHex = "0x{0:X8}" -f $result
	        throw "NCryptUnprotectSecret failed with error code $errorHex"
	    }
	    if ($ppbData -eq [IntPtr]::Zero -or $pcbData -eq 0) {
	        throw "NCryptUnprotectSecret returned empty data"
	    }
	    $decryptedData = New-Object byte[] $pcbData
	    [System.Runtime.InteropServices.Marshal]::Copy($ppbData, $decryptedData, 0, $pcbData)
	    return $decryptedData
	} finally {
	    if ($ppbData -ne [IntPtr]::Zero) {
	        [void][NCryptInterop]::LocalFree($ppbData)
	    }
	}
}
function ConvertFrom-SupplementalCredentials {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [byte[]]$Data
	)
	process {
	    try {
	        if (-not $Data -or $Data.Length -lt 110) {
	            return $null
	        }
	        $offset = 0
	        $offset += 4
	        $length = [BitConverter]::ToUInt32($Data, $offset)
	        $offset += 4
	        $offset += 100
	        $signature = [BitConverter]::ToUInt16($Data, $offset)
	        $offset += 2
	        if ($signature -ne 0x0050) {
	            return $null
	        }
	        $propertyCount = [BitConverter]::ToUInt16($Data, $offset)
	        $offset += 2
	        $properties = @{}
	        for ($i = 0; $i -lt $propertyCount; $i++) {
	            if ($offset + 6 -gt $Data.Length) {
	                break
	            }
	            $nameLength = [BitConverter]::ToUInt16($Data, $offset)
	            $offset += 2
	            $valueLength = [BitConverter]::ToUInt16($Data, $offset)
	            $offset += 2
	            $offset += 2
	            if ($offset + $nameLength -gt $Data.Length) {
	                break
	            }
	            $propertyName = [System.Text.Encoding]::Unicode.GetString($Data, $offset, $nameLength)
	            $offset += $nameLength
	            if ($offset + $valueLength -gt $Data.Length) {
	                break
	            }
	            $propertyValueHex = [System.Text.Encoding]::ASCII.GetString($Data, $offset, $valueLength)
	            $offset += $valueLength
	            if ($propertyValueHex.Length % 2 -ne 0) {
	                continue
	            }
	            try {
	                $propertyValueBytes = for ($j = 0; $j -lt $propertyValueHex.Length; $j += 2) {
	                    [Convert]::ToByte($propertyValueHex.Substring($j, 2), 16)
	                }
	            }
	            catch {
	                continue
	            }
	            $properties[$propertyName] = $propertyValueBytes
	        }
	        $aes256Key = $null
	        $aes128Key = $null
	        $desKey = $null
	        $kerberosSalt = $null
	        if ($properties.ContainsKey('Primary:Kerberos-Newer-Keys')) {
	            $kerberosData = $properties['Primary:Kerberos-Newer-Keys']
	            $result = Parse-KerberosNewerKeys -Data $kerberosData
	            if ($result) {
	                $aes256Key = $result.AES256Key
	                $aes128Key = $result.AES128Key
	                if ($result.DESKey) { $desKey = $result.DESKey }
	                $kerberosSalt = $result.Salt
	            } else {
	            }
	        }
	        if (-not $desKey -and $properties.ContainsKey('Primary:Kerberos')) {
	            $kerberosData = $properties['Primary:Kerberos']
	            $desKeyFromOld = Parse-KerberosKeys -Data $kerberosData
	            if ($desKeyFromOld) { $desKey = $desKeyFromOld }
	        }
	        $cleartextPassword = $null
	        if ($properties.ContainsKey('Primary:CLEARTEXT')) {
	            $cleartextData = $properties['Primary:CLEARTEXT']
	            $cleartextPassword = [System.Text.Encoding]::Unicode.GetString($cleartextData)
	        }
	        $wdigestHashes = @()
	        if ($properties.ContainsKey('Primary:WDigest')) {
	            $wdigestData = $properties['Primary:WDigest']
	            $wdigestHashes = Parse-WDigestHashes -Data $wdigestData
	        }
	        return [PSCustomObject]@{
	            AES256Key = $aes256Key
	            AES128Key = $aes128Key
	            DESKey = $desKey
	            KerberosSalt = $kerberosSalt
	            CleartextPassword = $cleartextPassword
	            WDigestHashes = $wdigestHashes
	        }
	    }
	    catch {
	        return $null
	    }
	}
}
function Parse-KerberosNewerKeys {
	[CmdletBinding()]
	param([byte[]]$Data)
	try {
	    if ($Data.Length -lt 20) { return $null }
	    $offset = 0
	    $revision = [BitConverter]::ToUInt16($Data, $offset)
	    $offset += 2
	    $flags = [BitConverter]::ToUInt16($Data, $offset)
	    $offset += 2
	    $credentialCount = [BitConverter]::ToUInt16($Data, $offset)
	    $offset += 2
	    $serviceCredentialCount = [BitConverter]::ToUInt16($Data, $offset)
	    $offset += 2
	    $oldCredentialCount = [BitConverter]::ToUInt16($Data, $offset)
	    $offset += 2
	    $olderCredentialCount = [BitConverter]::ToUInt16($Data, $offset)
	    $offset += 2
	    $defaultSaltLength = [BitConverter]::ToUInt16($Data, $offset)
	    $offset += 2
	    $offset += 2
	    $defaultSaltOffset = [BitConverter]::ToUInt32($Data, $offset)
	    $offset += 4
	    $salt = $null
	    if ($defaultSaltLength -gt 0 -and $defaultSaltOffset -lt $Data.Length -and ($defaultSaltOffset + $defaultSaltLength) -le $Data.Length) {
	        $salt = [System.Text.Encoding]::Unicode.GetString($Data, $defaultSaltOffset, $defaultSaltLength)
	    }
	    $aes256Key = $null
	    $aes128Key = $null
	    $desKey = $null
	    for ($i = 0; $i -lt $credentialCount; $i++) {
	        $entrySize = if ($i -eq 0) { 28 } else { 24 }
	        if ($offset + $entrySize -gt $Data.Length) {
	            break
	        }
	        $offset += 2
	        $offset += 2
	        $offset += 4
	        if ($i -eq 0) {
	            $offset += 4
	        }
	        $offset += 4
	        $keyType = [BitConverter]::ToUInt32($Data, $offset)
	        $offset += 4
	        $keyLength = [BitConverter]::ToUInt32($Data, $offset)
	        $offset += 4
	        $keyOffset = [BitConverter]::ToUInt32($Data, $offset)
	        $offset += 4
	        if ($keyOffset -lt $Data.Length -and ($keyOffset + $keyLength) -le $Data.Length) {
	            $keyBytes = $Data[$keyOffset..($keyOffset + $keyLength - 1)]
	            $keyHex = ($keyBytes | ForEach-Object { $_.ToString('x2') }) -join ''
	            switch ($keyType) {
	                18 {
	                    $aes256Key = $keyHex
	                    $keySize = $keyHex.Length / 2
	                }
	                17 {
	                    $aes128Key = $keyHex
	                    $keySize = $keyHex.Length / 2
	                }
	                3 {
	                    $desKey = $keyHex
	                    $keySize = $keyHex.Length / 2
	                }
	                default {
	                }
	            }
	        } else {
	        }
	    }
	    return [PSCustomObject]@{
	        AES256Key = $aes256Key
	        AES128Key = $aes128Key
	        DESKey = $desKey
	        Salt = $salt
	    }
	}
	catch {
	    return $null
	}
}
function Parse-KerberosKeys {
	[CmdletBinding()]
	param([byte[]]$Data)
	try {
	    if ($Data.Length -lt 20) { return $null }
	    $offset = 0
	    $revision = [BitConverter]::ToUInt16($Data, $offset)
	    $offset += 2
	    $offset += 2  # Flags
	    $credentialCount = [BitConverter]::ToUInt16($Data, $offset)
	    $offset += 2
	    $offset += 2  # ServiceCredentialCount
	    $offset += 2  # OldCredentialCount
	    $offset += 2  # OlderCredentialCount
	    $offset += 2  # DefaultSaltLength
	    $offset += 2  # DefaultSaltMaximumLength
	    $offset += 4  # DefaultSaltOffset
	    for ($i = 0; $i -lt $credentialCount; $i++) {
	        if ($offset + 20 -gt $Data.Length) { break }
	        $offset += 8  # Reserved
	        $offset += 4  # IterationCount
	        $keyType = [BitConverter]::ToUInt32($Data, $offset)
	        $offset += 4
	        $keyLength = [BitConverter]::ToUInt32($Data, $offset)
	        $offset += 4
	        $keyOffset = [BitConverter]::ToUInt32($Data, $offset)
	        $offset += 4
	        if ($keyType -eq 3 -and $keyOffset -lt $Data.Length -and ($keyOffset + $keyLength) -le $Data.Length) {  # DES-CBC-MD5
	            $keyBytes = $Data[$keyOffset..($keyOffset + $keyLength - 1)]
	            return ($keyBytes | ForEach-Object { $_.ToString('x2') }) -join ''
	        }
	    }
	    return $null
	}
	catch {
	    return $null
	}
}
function Parse-WDigestHashes {
	[CmdletBinding()]
	param([byte[]]$Data)
	try {
	    if ($Data.Length -lt (16 + 29 * 16)) {
	        return @()
	    }
	    $hashes = @()
	    $offset = 16  # Skip 16-byte header (not 8!)
	    for ($i = 1; $i -le 29; $i++) {
	        if ($offset + 16 -gt $Data.Length) { break }
	        $hashBytes = $Data[$offset..($offset + 15)]
	        $hashHex = ($hashBytes | ForEach-Object { $_.ToString('x2') }) -join ''
	        if ($hashHex -ne '00000000000000000000000000000000') {
	            $hashes += "${i}: $hashHex"
	        }
	        $offset += 16
	    }
	    return $hashes
	}
	catch {
	    return @()
	}
}
function Get-CurrentUserTokenGroups {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [switch]$Force
	)
	if (-not $Force -and $Script:CurrentUserTokenGroups) {
	    return $Script:CurrentUserTokenGroups
	}
	if (-not $Script:LdapConnection -or -not $Script:LDAPContext) {
	    return @()
	}
	try {
	    $TokenResults = Invoke-LDAPSearch -Filter "(objectClass=*)" -Properties "tokenGroups" -Scope "Base" -Raw
	    $TokenGroupSIDs = @()
	    if ($TokenResults -and $TokenResults.Count -gt 0) {
	        $TokenResult = $TokenResults[0]
	        $tokenGroupsAttr = $TokenResult.tokenGroups
	        if ($tokenGroupsAttr) {
	            $tokenGroupsArray = if ($tokenGroupsAttr -is [array]) { $tokenGroupsAttr } else { @($tokenGroupsAttr) }
	            foreach ($sidBytes in $tokenGroupsArray) {
	                try {
	                    if ($sidBytes -is [byte[]]) {
	                        $sid = New-Object System.Security.Principal.SecurityIdentifier($sidBytes, 0)
	                        $TokenGroupSIDs += $sid.Value
	                    }
	                } catch {
	                }
	            }
	        } else {
	        }
	    } else {
	    }
	    $Script:CurrentUserTokenGroups = $TokenGroupSIDs
	    return $TokenGroupSIDs
	} catch {
	    return @()
	}
}
function Test-SIDInTokenGroups {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$SID
	)
	$tokenGroups = Get-CurrentUserTokenGroups
	if (-not $tokenGroups -or $tokenGroups.Count -eq 0) {
	    return $false
	}
	return ($tokenGroups -contains $SID)
}
function Get-adPEASSession {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [switch]$TestConnection,
	    [Parameter(Mandatory=$false)]
	    [switch]$Quiet
	)
	process {
	    $hasLdapConnection = ($null -ne $Script:LdapConnection)
	    if (-not $Script:LDAPContext -or -not $hasLdapConnection) {
	        if ($TestConnection) {
	            if (-not $Quiet) {
	                Show-SubHeader "Checking connection health..."
	                Show-KeyValue "Session Variables:" "FAIL: No active session found" -Class Finding
	                return
	            }
	            return $false
	        } else {
	            Show-NoSessionError -Context "Get-adPEASSession"
	            return $null
	        }
	    }
	    if ($TestConnection) {
	        try {
	            if (-not $Quiet) {
	                Show-Line "Health:" -Class Hint
	                Show-SubHeader "Checking connection health..."
	            }
	            $testResults = @{
	                SessionExists = $true
	                ConnectionValid = $false
	                QuerySuccessful = $false
	                Latency = $null
	                HealthStatus = "Unknown"
	                Errors = @()
	            }
	            if (-not $Quiet) {
	                Show-KeyValue "Session Variables:" "PASS" -Class Standard
	            }
	            if ($hasLdapConnection) {
	                $protocol = if ($Script:LDAPContext.UseLDAPS) { "LDAPS" } else { "LDAP" }
	                if (-not $Quiet) {
	                    Show-KeyValue "LDAP Connection Object:" "PASS (LdapConnection for $protocol)" -Class Standard
	                }
	            }
	            else {
	                if (-not $Quiet) {
	                    Show-KeyValue "LDAP Connection Object:" "FAIL: No connection object found" -Class Finding
	                    return
	                }
	                return $false
	            }
	            $queryStartTime = Get-Date
	            try {
	                $testQuery = Invoke-LDAPSearch -Filter "(objectClass=domain)" -SearchBase $Script:LDAPContext.DomainDN -Properties "name" -Scope Base
	                if (-not $testQuery) {
	                    if (-not $Quiet) {
	                        Show-KeyValue "LDAP Query Execution:" "FAIL: Test query returned no results" -Class Finding
	                        return
	                    }
	                    return $false
	                }
	                $queryEndTime = Get-Date
	                $latency = ($queryEndTime - $queryStartTime).TotalMilliseconds
	                if (-not $Quiet) {
	                    Show-KeyValue "LDAP Query Execution:" "PASS (Latency: $([math]::Round($latency, 2)) ms)" -Class Standard
	                }
	                $testResults.QuerySuccessful = $true
	                $testResults.Latency = [math]::Round($latency, 2)
	            }
	            catch {
	                if (-not $Quiet) {
	                    Show-KeyValue "LDAP Query Execution:" "FAIL: $($_.Exception.Message)" -Class Finding
	                    return
	                }
	                return $false
	            }
	            $testResults.HealthStatus = "Healthy"
	            if (-not $Quiet) {
	                Show-KeyValue "Result:" "PASS (All tests passed - Connection is healthy)" -Class Note
	                Show-EmptyLine
	                return
	            }
	            return $true
	        }
	        catch {
	            if (-not $Quiet) {
	                Show-KeyValue "Unexpected Error:" "FAIL: $($_.Exception.Message)" -Class Finding
	                Show-EmptyLine
	                return
	            }
	            return $false
	        }
	    }
	    else {
	        Show-SubHeader "Displaying active session information..."
	        Show-Line "Connection:" -Class Hint
	        Show-KeyValue "Domain:" $Script:LDAPContext.Domain
	        if ($Script:LDAPContext.DomainSID) {
	            Show-KeyValue "Domain SID:" $Script:LDAPContext.DomainSID
	        }
	        Show-KeyValue "Server:" $Script:LDAPContext.Server
	        if ($Script:LDAPContext['ServerIP']) {
	            Show-KeyValue "Server IP:" $Script:LDAPContext['ServerIP']
	        }
	        Show-KeyValue "Protocol:" "$($Script:LDAPContext.Protocol) (Port $($Script:LDAPContext.Port))"
	        Show-KeyValue "Domain DN:" $Script:LDAPContext.DomainDN
	        Show-EmptyLine
	        Show-Line "Authentication:" -Class Hint
	        if ($Script:LDAPContext.KerberosUsed -and $Script:LDAPContext.TGTInfo -and $Script:LDAPContext.TGTInfo.UserName) {
	            $TGTUser = "$($Script:LDAPContext.TGTInfo.UserName)@$($Script:LDAPContext.TGTInfo.Domain)"
	            Show-KeyValue "Authenticated as:" $TGTUser
	            if ($Script:LDAPContext.AuthenticatedUserSID) {
	                Show-KeyValue "User SID:" $Script:LDAPContext.AuthenticatedUserSID
	            }
	            if ($Script:LDAPContext.TGTInfo.NTHash) {
	                Show-KeyValue "NT-Hash:" $Script:LDAPContext.TGTInfo.NTHash
	            }
	        }
	        elseif ($Script:LDAPContext.AuthenticatedUser) {
	            Show-KeyValue "Authenticated as:" $Script:LDAPContext.AuthenticatedUser
	            if ($Script:LDAPContext.AuthenticatedUserSID) {
	                Show-KeyValue "User SID:" $Script:LDAPContext.AuthenticatedUserSID
	            }
	            if ($Script:LDAPContext.IdentityMismatch) {
	                Show-KeyValue "Local Identity:" $Script:LDAPContext.LocalIdentity
	                Show-Line "  Identity Mismatch: DETECTED" -Class Hint
	            }
	            if ($Script:LDAPContext.AuthenticatedUserDN) {
	                Show-KeyValue "Distinguished Name:" $Script:LDAPContext.AuthenticatedUserDN
	            }
	            if ($Script:LDAPContext.AuthenticatedUserUPN) {
	                Show-KeyValue "User Principal Name:" $Script:LDAPContext.AuthenticatedUserUPN
	            }
	        }
	        elseif ($Script:LDAPContext.Credential) {
	            Show-KeyValue "Authenticated as:" $Script:LDAPContext.Credential.UserName
	        }
	        else {
	            Show-KeyValue "Authenticated as:" "$env:USERDOMAIN\$env:USERNAME"
	        }
	        $AuthMethodDisplay = switch ($Script:LDAPContext.AuthMethod) {
	            'Kerberos' {
	                if ($Script:LDAPContext.TGTInfo) {
	                    'Kerberos (TGT/TGS)'
	                } else {
	                    'Kerberos (SSPI)'
	                }
	            }
	            'Schannel' { 'Schannel (TLS Client Certificate)' }
	            'SimpleBind' { if ($Script:LDAPContext.UseLDAPS) { 'SimpleBind (LDAPS)' } else { 'SimpleBind (LDAP)' } }
	            'WindowsSSPI' { 'Windows SSPI (Negotiate)' }
	            'WindowsAuth' { 'Windows Authentication (Negotiate)' }
	            'NTLM' { if ($Script:LDAPContext.UseLDAPS) { 'NTLM (LDAPS)' } else { 'NTLM (LDAP)' } }
	            'NTLM Impersonation' { 'NTLM Impersonation (runas /netonly)' }
	            default { 'Unknown' }
	        }
	        Show-KeyValue "Authentication Method:" $AuthMethodDisplay
	        if ($Script:LDAPContext.KerberosUsed -and $Script:LDAPContext.TGTInfo) {
	            $TGT = $Script:LDAPContext.TGTInfo
	            $ETypeDisplay = switch ($TGT.EncryptionType) {
	                17 { 'AES128-CTS-HMAC-SHA1' }
	                18 { 'AES256-CTS-HMAC-SHA1' }
	                23 { 'RC4-HMAC (NTLM)' }
	                default { "etype $($TGT.EncryptionType)" }
	            }
	            Show-KeyValue "TGT Encryption:" $ETypeDisplay
	            if ($TGT.Method) {
	                Show-KeyValue "TGT Method:" $TGT.Method
	            }
	            if ($TGT.Domain) {
	                Show-KeyValue "TGT Realm:" $TGT.Domain
	            }
	            if ($TGT.ClockSkew -and $TGT.ClockSkew -is [TimeSpan]) {
	                $skewSeconds = [Math]::Round($TGT.ClockSkew.TotalSeconds)
	                $skewAbs = [Math]::Abs($skewSeconds)
	                $skewSign = if ($skewSeconds -ge 0) { "+" } else { "-" }
	                if ($skewAbs -ge 3600) {
	                    $skewDisplay = "${skewSign}$([Math]::Floor($skewAbs / 3600))h $([Math]::Floor(($skewAbs % 3600) / 60))m"
	                } elseif ($skewAbs -ge 60) {
	                    $skewDisplay = "${skewSign}$([Math]::Floor($skewAbs / 60))m $($skewAbs % 60)s"
	                } else {
	                    $skewDisplay = "${skewSign}${skewAbs}s"
	                }
	                if ($skewAbs -gt 300) {
	                    Show-KeyValue "Clock Skew:" "$skewDisplay (WARNING: exceeds 5-minute Kerberos limit!)" -Class Finding
	                } elseif ($skewAbs -gt 270) {
	                    Show-KeyValue "Clock Skew:" "$skewDisplay (WARNING: close to 5-minute Kerberos limit)" -Class Finding
	                } elseif ($skewAbs -gt 60) {
	                    Show-KeyValue "Clock Skew:" $skewDisplay -Class Hint
	                } else {
	                    Show-KeyValue "Clock Skew:" $skewDisplay
	                }
	            }
	            $LiveTicketStatus = Test-KerberosTGTExists -Detailed -Force
	            if ($LiveTicketStatus.Valid) {
	                $endTimeLocal = $LiveTicketStatus.EndTime.ToLocalTime()
	                $now = Get-Date
	                $timeRemaining = $LiveTicketStatus.EndTime - $now
	                if ($timeRemaining.TotalSeconds -gt 0) {
	                    $remainingDisplay = "{0:hh\:mm\:ss}" -f $timeRemaining
	                    Show-KeyValue "TGT Valid Until:" "$($endTimeLocal.ToString('yyyy-MM-dd HH:mm:ss')) (in $remainingDisplay)"
	                }
	                else {
	                    Show-KeyValue "TGT Valid Until:" "$($endTimeLocal.ToString('yyyy-MM-dd HH:mm:ss'))" -Class Finding
	                    Write-Warning "[!] TGT EXPIRED - Re-authentication required!"
	                }
	            }
	            elseif ($LiveTicketStatus.TicketCount -eq 0) {
	                Show-KeyValue "TGT Status:" "NO TICKETS IN CACHE - Re-authenticate with Connect-adPEAS" -Class Finding
	            }
	            elseif (-not $LiveTicketStatus.TGTPresent) {
	                Show-KeyValue "TGT Status:" "NO TGT FOUND ($($LiveTicketStatus.TicketCount) service tickets) - Re-authenticate with Connect-adPEAS" -Class Finding
	            }
	            elseif ($LiveTicketStatus.Expired) {
	                $expiredTime = if ($LiveTicketStatus.EndTime) {
	                    $LiveTicketStatus.EndTime.ToLocalTime().ToString('yyyy-MM-dd HH:mm:ss')
	                } else { "unknown" }
	                Show-KeyValue "TGT Status:" "EXPIRED at $expiredTime - Re-authenticate with Connect-adPEAS" -Class Finding
	            }
	            elseif ($LiveTicketStatus.ClientMatch -eq $false) {
	                $tgtClient = $LiveTicketStatus.ClientName
	                $expectedClient = $Script:LDAPContext.TGTInfo.UserName
	                Show-KeyValue "TGT Status:" "CLIENT MISMATCH (TGT=$tgtClient, Expected=$expectedClient) - Re-authenticate with Connect-adPEAS" -Class Finding
	            }
	            else {
	                Show-KeyValue "TGT Status:" "INVALID - Re-authenticate with Connect-adPEAS" -Class Finding
	            }
	        }
	        Show-EmptyLine
	        Show-Line "Session:" -Class Hint
	        if ($Script:LDAPContext.SessionStartTime) {
	            $sessionDuration = (Get-Date) - $Script:LDAPContext.SessionStartTime
	            Show-KeyValue "Session Started:" $Script:LDAPContext.SessionStartTime
	            Show-KeyValue "Session Duration:" $sessionDuration.ToString('hh\:mm\:ss')
	        }
	        if ($Script:LDAPContext.KerberosUsed) {
	            if (-not $LiveTicketStatus) {
	                $LiveTicketStatus = Test-KerberosTGTExists -Detailed -Force
	            }
	            if ($LiveTicketStatus.Valid) {
	                Show-KeyValue "Connection State:" "Connected (Kerberos TGT valid)"
	            }
	            elseif ($LiveTicketStatus.TicketCount -eq 0) {
	                Show-KeyValue "Connection State:" "DEGRADED (No Kerberos tickets)" -Class Finding
	            }
	            elseif (-not $LiveTicketStatus.TGTPresent) {
	                Show-KeyValue "Connection State:" "DEGRADED (No TGT, only service tickets)" -Class Finding
	            }
	            elseif ($LiveTicketStatus.Expired) {
	                Show-KeyValue "Connection State:" "DEGRADED (TGT expired)" -Class Finding
	            }
	            elseif ($LiveTicketStatus.ClientMatch -eq $false) {
	                Show-KeyValue "Connection State:" "DEGRADED (TGT client mismatch)" -Class Finding
	            }
	            else {
	                Show-KeyValue "Connection State:" "DEGRADED (TGT invalid)" -Class Finding
	            }
	        }
	        elseif ($Script:LDAPContext.AuthMethod -eq 'Schannel') {
	            Show-KeyValue "Connection State:" "Connected (Schannel/TLS)"
	        }
	        else {
	            Show-KeyValue "Connection State:" "Connected"
	        }
	        Show-EmptyLine
	        Show-Line "Help:" -Class Hint
	        Show-KeyValue "Get-adPEASSession -TestConnection" "Test connection health"
	        Show-KeyValue "Disconnect-adPEAS" "End the session"
	        Show-EmptyLine
	    }
	}
}
function Test-KerberosTGTExists {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [switch]$Force,
	    [Parameter(Mandatory=$false)]
	    [switch]$Detailed
	)
	if (-not $Force -and $Script:LDAPContext) {
	    $lastCheck = $Script:LDAPContext['KerberosLastCheck']
	    if ($lastCheck -and ((Get-Date) - $lastCheck).TotalSeconds -lt 60) {
	        $cachedValid = $Script:LDAPContext['KerberosValid']
	        if ($Detailed) {
	            return [PSCustomObject]@{
	                Valid = $cachedValid
	                TicketCount = $Script:LDAPContext['KerberosTicketCount']
	                TGTPresent = $Script:LDAPContext['KerberosTGTPresent']
	                ClientMatch = $Script:LDAPContext['KerberosClientMatch']
	                ServerName = $Script:LDAPContext['KerberosServerName']
	                Realm = $Script:LDAPContext['KerberosRealm']
	                ClientName = $Script:LDAPContext['KerberosClientName']
	                EndTime = $Script:LDAPContext['KerberosEndTime']
	                Expired = $Script:LDAPContext['KerberosExpired']
	                EncryptionType = $Script:LDAPContext['KerberosEncryptionType']
	                TicketFlags = $Script:LDAPContext['KerberosTicketFlags']
	                Cached = $true
	            }
	        }
	        return $cachedValid
	    }
	}
	$LsaSignatures = @'
	    [DllImport("secur32.dll", SetLastError = true)]
	    public static extern uint LsaConnectUntrusted(out IntPtr LsaHandle);
	    [DllImport("secur32.dll", SetLastError = true)]
	    public static extern uint LsaLookupAuthenticationPackage(
	        IntPtr LsaHandle,
	        ref LSA_STRING PackageName,
	        out uint AuthenticationPackage);
	    [DllImport("secur32.dll", SetLastError = true)]
	    public static extern uint LsaCallAuthenticationPackage(
	        IntPtr LsaHandle,
	        uint AuthenticationPackage,
	        IntPtr ProtocolSubmitBuffer,
	        uint SubmitBufferLength,
	        out IntPtr ProtocolReturnBuffer,
	        out uint ReturnBufferLength,
	        out int ProtocolStatus);
	    [DllImport("secur32.dll", SetLastError = true)]
	    public static extern uint LsaDeregisterLogonProcess(IntPtr LsaHandle);
	    [DllImport("secur32.dll", SetLastError = true)]
	    public static extern uint LsaFreeReturnBuffer(IntPtr Buffer);
	    [StructLayout(LayoutKind.Sequential)]
	    public struct LSA_STRING
	    {
	        public ushort Length;
	        public ushort MaximumLength;
	        public IntPtr Buffer;
	    }
	    [StructLayout(LayoutKind.Sequential)]
	    public struct UNICODE_STRING
	    {
	        public ushort Length;
	        public ushort MaximumLength;
	        public IntPtr Buffer;
	    }
	    // Request structure for both MessageType 1 and 14
	    [StructLayout(LayoutKind.Sequential)]
	    public struct KERB_QUERY_TKT_CACHE_REQUEST
	    {
	        public int MessageType;
	        public long LogonId;       // LUID - use 0 for current session
	    }
	    // Response header for MessageType 1 (simple count)
	    [StructLayout(LayoutKind.Sequential)]
	    public struct KERB_QUERY_TKT_CACHE_RESPONSE
	    {
	        public int MessageType;
	        public int CountOfTickets;
	    }
	    // Response header for MessageType 14 (extended info)
	    [StructLayout(LayoutKind.Sequential)]
	    public struct KERB_QUERY_TKT_CACHE_EX_RESPONSE
	    {
	        public int MessageType;
	        public int CountOfTickets;
	        // Followed by KERB_TICKET_CACHE_INFO_EX array
	    }
	    // Single ticket cache entry (extended)
	    // Size: 104 bytes on x64, 56 bytes on x86
	    [StructLayout(LayoutKind.Sequential)]
	    public struct KERB_TICKET_CACHE_INFO_EX
	    {
	        public UNICODE_STRING ClientName;      // 16 bytes (x64) / 8 bytes (x86)
	        public UNICODE_STRING ClientRealm;     // 16 bytes (x64) / 8 bytes (x86)
