function Ensure-LDAPConnection {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential
	)
	$HasExplicitParams = $PSBoundParameters.ContainsKey('Domain') -or
	                    $PSBoundParameters.ContainsKey('Server') -or
	                    $PSBoundParameters.ContainsKey('Credential')
	if (-not $HasExplicitParams -and $Script:LDAPContext) {
	    if ($Script:LDAPContext['SessionInvalid']) {
	        return $false
	    }
	    $UsernameDisplay = $Script:LDAPContext.AuthenticatedUser
	    $AuthMethod = $Script:LDAPContext['AuthMethod']
	    $KerberosAuthMethods = @('Kerberos', 'PKINIT', 'OverpassTheHash', 'PassTheKey', 'PassTheTicket')
	    if ($AuthMethod -in $KerberosAuthMethods) {
	        $ticketCheck = Test-KerberosTGTExists -Detailed
	        if (-not $ticketCheck.Valid) {
	            $errorDetails = "Kerberos TGT no longer valid"
	            if ($ticketCheck.TicketCount -eq 0) {
	                $errorDetails = "No Kerberos tickets in cache (purged or never obtained)"
	            } elseif ($ticketCheck.Expired) {
	                $expiredTime = if ($ticketCheck.EndTime) { $ticketCheck.EndTime.ToString('yyyy-MM-dd HH:mm:ss') } else { "unknown" }
	                $errorDetails = "Kerberos TGT expired at $expiredTime"
	            } elseif ($ticketCheck.ClientMatch -eq $false) {
	                $errorDetails = "Kerberos TGT client mismatch (TGT=$($ticketCheck.ClientName), Expected=$($Script:LDAPContext.TGTInfo.UserName))"
	            }
	            $errorDetails += ". Re-authenticate with Connect-adPEAS."
	            Show-ConnectionError -ErrorType "AuthenticationFailed" -Details $errorDetails -NoThrow
	            $Script:LDAPContext['SessionInvalid'] = $true
	            Show-Line "Aborting scan - LDAP session is no longer valid. Re-authenticate with Connect-adPEAS." -Class Finding
	            return $false
	        }
	    }
	    return $true
	}
	if (-not $HasExplicitParams -and -not $Script:LDAPContext) {
	    $CallingFunction = (Get-PSCallStack)[1].Command
	    Show-NoSessionError -Context $CallingFunction
	    return $false
	}
	$TargetDomain = $Domain
	if (-not $TargetDomain) {
	    try {
	        $CurrentDomain = [System.DirectoryServices.ActiveDirectory.Domain]::GetCurrentDomain()
	        $TargetDomain = $CurrentDomain.Name
	    } catch {
	        throw "Could not detect current domain. Please specify -Domain parameter."
	    }
	}
	$TargetServer = $Server
	$NeedNewConnection = $false
	if (-not $Script:LDAPContext) {
	    $NeedNewConnection = $true
	} else {
	    if ($Domain -and $Script:LDAPContext.Domain -ne $TargetDomain) {
	        $NeedNewConnection = $true
	    }
	    if ($TargetServer -and $Script:LDAPContext.Server -ne $TargetServer) {
	        $NeedNewConnection = $true
	    }
	    if ($Credential) {
	        $NeedNewConnection = $true
	    }
	    if (-not $NeedNewConnection) {
	        $UsernameDisplay = $Script:LDAPContext.AuthenticatedUser
	    }
	}
	if ($NeedNewConnection) {
	    $ServerDisplay = if ($TargetServer) { $TargetServer } else { 'auto-discovery' }
	    try {
	        $ConnectionParams = @{}
	        if ($TargetDomain) { $ConnectionParams['Domain'] = $TargetDomain }
	        if ($TargetServer) { $ConnectionParams['Server'] = $TargetServer }
	        if ($Credential) { $ConnectionParams['Credential'] = $Credential }
	        if ($Script:LDAPContext -and $Script:LDAPContext['ClientCertificate']) {
	            $ConnectionParams['ClientCertificate'] = $Script:LDAPContext['ClientCertificate']
	            $ConnectionParams['UseLDAPS'] = $true  # Schannel requires LDAPS
	        }
	        Connect-LDAP @ConnectionParams | Out-Null
	        $UsernameDisplay = $Script:LDAPContext.AuthenticatedUser
	    } catch {
	        throw
	    }
	}
	return $true
}
function Test-AccountActivity {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true, ValueFromPipeline=$true)]
	    [object]$ADObject,
	    [Parameter(Mandatory=$false)]
	    [switch]$IsActive,
	    [Parameter(Mandatory=$false)]
	    [switch]$IsInactive,
	    [Parameter(Mandatory=$false)]
	    [int]$InactiveDays = 0,  # 0 = use $Script:DefaultInactiveDays
	    [Parameter(Mandatory=$false)]
	    [switch]$IsEnabled,
	    [Parameter(Mandatory=$false)]
	    [switch]$IsDisabled,
	    [Parameter(Mandatory=$false)]
	    [switch]$NeverLoggedIn,
	    [Parameter(Mandatory=$false)]
	    [switch]$HasLoggedIn,
	    [Parameter(Mandatory=$false)]
	    [int]$PasswordAgeDays = 0,
	    [Parameter(Mandatory=$false)]
	    [int]$PasswordChangedInYear = 0,
	    [Parameter(Mandatory=$false)]
	    [int]$PasswordChangedBeforeYear = 0,
	    [Parameter(Mandatory=$false)]
	    [int]$PasswordChangedAfterYear = 0,
	    [Parameter(Mandatory=$false)]
	    [switch]$PasswordNeverSet,
	    [Parameter(Mandatory=$false)]
	    [switch]$PasswordNeverExpires,
	    [Parameter(Mandatory=$false)]
	    [switch]$PasswordNotRequired,
	    [Parameter(Mandatory=$false)]
	    [switch]$IncludeDetails
	)
	begin {
	    if ($IsActive -and $IsInactive) {
	        throw "Parameters -IsActive and -IsInactive are mutually exclusive"
	    }
	    if ($IsEnabled -and $IsDisabled) {
	        throw "Parameters -IsEnabled and -IsDisabled are mutually exclusive"
	    }
	    if ($NeverLoggedIn -and $HasLoggedIn) {
	        throw "Parameters -NeverLoggedIn and -HasLoggedIn are mutually exclusive"
	    }
	}
	process {
	    $effectiveInactiveDays = if ($InactiveDays -gt 0) {
	        $InactiveDays
	    } elseif ($Script:DefaultInactiveDays) {
	        $Script:DefaultInactiveDays
	    } else {
	        90  # Fallback if no global constant exists
	    }
	    if ($InactiveDays -gt 0 -and -not $IsActive -and -not $IsInactive) {
	        $IsInactive = $true
	    }
	    $uacValue = $ADObject.userAccountControl
	    $uac = 0
	    if ($uacValue -is [array]) {
	        $uacValue = $uacValue[0]
	    }
	    if ($null -ne $uacValue) {
	        if ($uacValue -is [int] -or $uacValue -is [long]) {
	            $uac = [int]$uacValue
	        }
	        elseif ($uacValue -is [string]) {
	            $parsed = 0
	            if ([int]::TryParse($uacValue, [ref]$parsed)) {
	                $uac = $parsed
	            }
	        }
	    }
	    $accountEnabled = -not (($uac -band 0x0002) -eq 0x0002)
	    $hasPasswordNeverExpires = ($uac -band 0x10000) -eq 0x10000
	    $hasPasswordNotRequired = ($uac -band 0x0020) -eq 0x0020
	    if ($IsEnabled -and -not $accountEnabled) {
	        return  # Filter out: wanted enabled, but account is disabled
	    }
	    if ($IsDisabled -and $accountEnabled) {
	        return  # Filter out: wanted disabled, but account is enabled
	    }
	    if ($PasswordNeverExpires -and -not $hasPasswordNeverExpires) {
	        return  # Filter out: wanted PasswordNeverExpires, but flag not set
	    }
	    if ($PasswordNotRequired -and -not $hasPasswordNotRequired) {
	        return  # Filter out: wanted PasswordNotRequired, but flag not set
	    }
	    $lastLogonTimestamp = $ADObject.lastLogonTimestamp
	    $lastActivityDate = $null
	    $hasEverLoggedIn = $false
	    if ($lastLogonTimestamp) {
	        if ($lastLogonTimestamp -is [array]) {
	            $lastLogonTimestamp = $lastLogonTimestamp[0]
	        }
	        $lastActivityDate = Convert-ADTimestamp -Value $lastLogonTimestamp
	        if ($lastActivityDate) {
	            $hasEverLoggedIn = $true
	        }
	    }
	    if ($NeverLoggedIn -and $hasEverLoggedIn) {
	        return  # Filter out: wanted never logged in, but has logged in
	    }
	    if ($HasLoggedIn -and -not $hasEverLoggedIn) {
	        return  # Filter out: wanted has logged in, but never logged in
	    }
	    if ($IsActive -or $IsInactive) {
	        if (-not $hasEverLoggedIn) {
	            if ($IsActive) {
	                return  # Filter out: never logged in, not active
	            }
	            if ($IsInactive) {
	                return  # Filter out: never logged in, not inactive either (use -NeverLoggedIn)
	            }
	        }
	        $cutoffDate = (Get-Date).AddDays(-$effectiveInactiveDays)
	        $isAccountActive = $lastActivityDate -gt $cutoffDate
	        if ($IsActive -and -not $isAccountActive) {
	            return  # Filter out: wanted active, but inactive
	        }
	        if ($IsInactive -and $isAccountActive) {
	            return  # Filter out: wanted inactive, but active
	        }
	    }
	    $pwdLastSet = $ADObject.pwdLastSet
	    $passwordSetDate = $null
	    $passwordYear = $null
	    $daysSincePasswordChange = $null
	    $passwordWasNeverSet = $true
	    if ($pwdLastSet) {
	        if ($pwdLastSet -is [array]) {
	            $pwdLastSet = $pwdLastSet[0]
	        }
	        $passwordSetDate = Convert-ADTimestamp -Value $pwdLastSet
	        if ($passwordSetDate) {
	            $passwordWasNeverSet = $false
	            $passwordYear = $passwordSetDate.Year
	            $daysSincePasswordChange = [math]::Floor(((Get-Date) - $passwordSetDate).TotalDays)
	        }
	    }
	    if ($PasswordNeverSet -and -not $passwordWasNeverSet) {
	        return  # Filter out: wanted password never set, but it was set
	    }
	    if ($PasswordAgeDays -gt 0) {
	        if ($passwordWasNeverSet -or $daysSincePasswordChange -lt $PasswordAgeDays) {
	            return  # Filter out: password not old enough (or never set)
	        }
	    }
	    if ($PasswordChangedInYear -gt 0) {
	        if ($passwordWasNeverSet -or $passwordYear -ne $PasswordChangedInYear) {
	            return  # Filter out: password not from target year
	        }
	    }
	    if ($PasswordChangedBeforeYear -gt 0) {
	        if ($passwordWasNeverSet -or $passwordYear -ge $PasswordChangedBeforeYear) {
	            return  # Filter out: password not before target year
	        }
	    }
	    if ($PasswordChangedAfterYear -gt 0) {
	        if ($passwordWasNeverSet -or $passwordYear -le $PasswordChangedAfterYear) {
	            return  # Filter out: password not after target year
	        }
	    }
	    if ($IncludeDetails) {
	        $details = [PSCustomObject]@{
	            IsEnabled = $accountEnabled
	            IsActive = if ($hasEverLoggedIn) { $lastActivityDate -gt (Get-Date).AddDays(-$effectiveInactiveDays) } else { $false }
	            LastActivity = $lastActivityDate
	            DaysSinceActivity = if ($lastActivityDate) { [math]::Floor(((Get-Date) - $lastActivityDate).TotalDays) } else { $null }
	            NeverLoggedIn = -not $hasEverLoggedIn
	            PasswordLastSet = $passwordSetDate
	            PasswordYear = $passwordYear
	            DaysSincePasswordChange = $daysSincePasswordChange
	            PasswordNeverSet = $passwordWasNeverSet
	            HasPasswordNeverExpires = $hasPasswordNeverExpires
	            HasPasswordNotRequired = $hasPasswordNotRequired
	        }
	        $ADObject | Add-Member -NotePropertyName "ActivityDetails" -NotePropertyValue $details -PassThru
	    }
	    else {
	        $ADObject
	    }
	}
}
function Convert-ADTimestamp {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    $Value
	)
	try {
	    if ($Value -is [DateTime]) {
	        return $Value
	    }
	    elseif ($Value -is [long] -or $Value -is [int]) {
	        if ($Value -le 0 -or $Value -eq 9223372036854775807) {
	            return $null
	        }
	        return [DateTime]::FromFileTime([long]$Value)
	    }
	    elseif ($Value -is [string]) {
	        $parsed = 0L
	        if ([long]::TryParse($Value, [ref]$parsed)) {
	            if ($parsed -le 0 -or $parsed -eq 9223372036854775807) {
	                return $null
	            }
	            return [DateTime]::FromFileTime($parsed)
	        }
	        $parsedDate = [DateTime]::MinValue
	        if ([DateTime]::TryParse($Value, [ref]$parsedDate)) {
	            return $parsedDate
	        }
	    }
	}
	catch {
	}
	return $null
}
if (-not $Script:SMBShareAccessCache) {
	$Script:SMBShareAccessCache = @{}
}
if (-not $Script:SYSVOLFileCache) {
	$Script:SYSVOLFileCache = $null  # $null = not yet populated
}
function Reset-SYSVOLFileCache {
	[CmdletBinding()]
	param()
	$Script:SYSVOLFileCache = $null
}
function Get-CachedSYSVOLFiles {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    $Filter,
	    [Parameter(Mandatory=$false)]
	    [string]$SYSVOLPath
	)
	if (-not $SYSVOLPath) {
	    if (-not $Script:LDAPContext -or -not $Script:LDAPContext.Server) {
	        return @()
	    }
	    $dcServer = $Script:LDAPContext.Server
	    $domainFQDN = $Script:LDAPContext.Domain
	    $SYSVOLPath = "\\$dcServer\SYSVOL\$domainFQDN"
	}
	if ($null -eq $Script:SYSVOLFileCache) {
	    if (-not (Test-Path $SYSVOLPath)) {
	        $Script:SYSVOLFileCache = @()
	        return @()
	    }
	    $topLevelDirs = @(Get-ChildItem -Force -Path $SYSVOLPath -Directory -ErrorAction SilentlyContinue)
	    $allFiles = [System.Collections.Generic.List[object]]::new()
	    if ($topLevelDirs.Count -gt 0) {
	        $subDirs = [System.Collections.Generic.List[object]]::new()
	        foreach ($topDir in $topLevelDirs) {
	            $childDirs = @(Get-ChildItem -Force -Path $topDir.FullName -Directory -ErrorAction SilentlyContinue)
	            if ($childDirs.Count -gt 0) {
	                foreach ($cd in $childDirs) { $subDirs.Add($cd) }
	            } else {
	                $subDirs.Add($topDir)
	            }
	        }
	        $totalDirs = $subDirs.Count
	        $currentDirIndex = 0
	        $showProgress = $totalDirs -gt $Script:ProgressThreshold
	        foreach ($dir in $subDirs) {
	            $currentDirIndex++
	            if ($showProgress) {
	                Show-Progress -Activity "Building SYSVOL file cache" -Current $currentDirIndex -Total $totalDirs -ObjectName $dir.Name
	            }
	            $dirFiles = @(Get-ChildItem -Force -Path $dir.FullName -Recurse -ErrorAction SilentlyContinue | Where-Object { -not $_.PSIsContainer })
	            foreach ($f in $dirFiles) { $allFiles.Add($f) }
	        }
	        if ($showProgress) {
	            Show-Progress -Activity "Building SYSVOL file cache" -Completed
	        }
	        $rootFiles = @(Get-ChildItem -Force -Path $SYSVOLPath -File -ErrorAction SilentlyContinue)
	        foreach ($f in $rootFiles) { $allFiles.Add($f) }
	    } else {
	        $allFiles = [System.Collections.Generic.List[object]]::new(
	            @(Get-ChildItem -Force -Path $SYSVOLPath -Recurse -ErrorAction SilentlyContinue | Where-Object { -not $_.PSIsContainer })
	        )
	    }
	    $Script:SYSVOLFileCache = @($allFiles)
	}
	$filterArray = @($Filter)
	$results = @($Script:SYSVOLFileCache | Where-Object {
	    $fileName = $_.Name
	    $matched = $false
	    foreach ($f in $filterArray) {
	        if ($fileName -like $f) {
	            $matched = $true
	            break
	        }
	    }
	    $matched
	})
	return $results
}
function Get-CachedSYSVOLContent {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$Path
	)
	if (-not $Script:SYSVOLContentCache) {
	    $Script:SYSVOLContentCache = @{}
	}
	$cacheKey = $Path.ToLowerInvariant()
	if ($Script:SYSVOLContentCache.ContainsKey($cacheKey)) {
	    return $Script:SYSVOLContentCache[$cacheKey]
	}
	if (-not (Test-Path $Path)) {
	    return $null
	}
	$content = Get-Content -Path $Path -Raw -ErrorAction SilentlyContinue
	if ($null -ne $content) {
	    $Script:SYSVOLContentCache[$cacheKey] = $content
	}
	return $content
}
function Reset-SMBShareAccessCache {
	[CmdletBinding()]
	param()
	$Script:SMBShareAccessCache = @{}
	$Script:SYSVOLContentCache = @{}
}
function Test-SysvolAccessible {
	[CmdletBinding()]
	param()
	if (-not $Script:LDAPContext -or -not $Script:LDAPContext.Server) {
	    return $null  # No session - unknown
	}
	$smbServer = $Script:LDAPContext.Server
	$kerberosUsed = $Script:LDAPContext['KerberosUsed']
	if (-not $kerberosUsed -and $Script:LDAPContext['DnsServer']) {
	    if ($Script:LDAPContext['ServerIP']) {
	        $smbServer = $Script:LDAPContext['ServerIP']
	    }
	}
	$shareKey = "\\$smbServer\SYSVOL".ToLower()
	if ($Script:SMBShareAccessCache.ContainsKey($shareKey)) {
	    return $false  # Previously failed
	}
	return $null  # Not attempted yet (or succeeded)
}
function Invoke-SMBAccess {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [ScriptBlock]$ScriptBlock,
	    [Parameter(Mandatory=$false)]
	    [string]$UNCPath,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [string]$Description,
	    [Parameter(Mandatory=$false)]
	    [ValidateRange(0, 10)]
	    [int]$RetryCount = 2,
	    [Parameter(Mandatory=$false)]
	    [ValidateRange(1, 300)]
	    [int]$Timeout = 5,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('Silent', 'Warn', 'Stop')]
	    [string]$ErrorHandling = 'Silent'
	)
	begin {
	    $operationDesc = if ($Description) { $Description } else { "SMB access" }
	}
	process {
	    $driveName = $null
	    $driveMounted = $false
	    $credToUse = $null
	    try {
	        if ($Credential) {
	            $credToUse = $Credential
	        }
	        elseif ($Script:LDAPCredential) {
	            $credToUse = $Script:LDAPCredential
	        }
	        elseif ($Script:LDAPContext -and $Script:LDAPContext['Credential']) {
	            if ($Script:LDAPContext['KerberosUsed']) {
	                $credToUse = $null
	            }
	            else {
	                $credToUse = $Script:LDAPContext['Credential']
	            }
	        }
	        else {
	        }
	        $targetPath = $UNCPath
	        if ($targetPath) {
	            if (-not (Test-ValidUNCPath -UNCPath $targetPath)) {
	                $errorMsg = "Invalid or potentially malicious UNC path: '$targetPath'. Path traversal or invalid format detected."
	                switch ($ErrorHandling) {
	                    'Warn' { Write-Warning $errorMsg; return $null }
	                    'Stop' { throw $errorMsg }
	                    default { return $null }
	                }
	            }
	        }
	        if (-not $targetPath) {
	            if ($Script:LDAPContext -and $Script:LDAPContext.Server) {
	                $smbServer = $Script:LDAPContext.Server
	                $kerberosUsed = $Script:LDAPContext['KerberosUsed']
	                $hostsPatched = $Script:LDAPContext['EarlyHostsPatched']
	                if ($kerberosUsed -and $hostsPatched) {
	                }
	                elseif ($kerberosUsed) {
	                }
	                elseif ($Script:LDAPContext['DnsServer']) {
	                    $resolvedIP = $null
	                    if ($Script:LDAPContext['ServerIP']) {
	                        $resolvedIP = $Script:LDAPContext['ServerIP']
	                    }
	                    elseif ($Script:LDAPContext['DnsCache'] -and $Script:LDAPContext['DnsCache'].ContainsKey($smbServer.ToLower())) {
	                        $resolvedIP = $Script:LDAPContext['DnsCache'][$smbServer.ToLower()]
	                    }
	                    else {
	                        $resolvedIP = Resolve-adPEASName -Name $smbServer
	                        if ($resolvedIP) {
	                        }
	                    }
	                    if ($resolvedIP) {
	                        $smbServer = $resolvedIP
	                    }
	                    else {
	                    }
	                }
	                else {
	                }
	                $targetPath = "\\$smbServer\SYSVOL"
	            } else {
	                $errorMsg = "No UNC path specified and cannot auto-detect SYSVOL (LDAPContext not available)"
	                switch ($ErrorHandling) {
	                    'Warn' { Write-Warning $errorMsg }
	                    'Stop' { throw $errorMsg }
	                }
	                return & $ScriptBlock
	            }
	        }
	        else {
	            $kerberosUsed = $Script:LDAPContext -and $Script:LDAPContext['KerberosUsed']
	            if (-not $kerberosUsed -and $Script:LDAPContext -and $Script:LDAPContext['DnsServer'] -and $UNCPath -match '^\\\\([^\\]+)\\') {
	                $uncHost = $Matches[1]
	                $ipTest = $null
	                if (-not [System.Net.IPAddress]::TryParse($uncHost, [ref]$ipTest)) {
	                    $resolvedIP = $null
	                    if ($Script:LDAPContext['DnsCache'] -and $Script:LDAPContext['DnsCache'].ContainsKey($uncHost.ToLower())) {
	                        $resolvedIP = $Script:LDAPContext['DnsCache'][$uncHost.ToLower()]
	                    }
	                    elseif ($Script:LDAPContext['ServerIP'] -and ($uncHost.ToLower() -eq $Script:LDAPContext.Server.ToLower() -or $uncHost.ToLower() -eq $Script:LDAPContext.Domain.ToLower())) {
	                        $resolvedIP = $Script:LDAPContext['ServerIP']
	                    }
	                    else {
	                        $resolvedIP = Resolve-adPEASName -Name $uncHost
	                    }
	                    if ($resolvedIP) {
	                        $targetPath = $UNCPath -replace "^\\\\[^\\]+\\", "\\$resolvedIP\"
	                    }
	                }
	            }
	            elseif ($kerberosUsed) {
	            }
	        }
	        $shareKey = $null
	        if ($targetPath -match '^(\\\\[^\\]+\\[^\\]+)') {
	            $shareKey = $Matches[1].ToLower()
	        }
	        if ($shareKey -and $Script:SMBShareAccessCache.ContainsKey($shareKey)) {
	            $cachedError = $Script:SMBShareAccessCache[$shareKey]
	            switch ($ErrorHandling) {
	                'Warn' { Write-Warning "SMB access skipped (previously failed): $cachedError"; return $null }
	                'Stop' { throw "SMB access skipped (previously failed): $cachedError" }
	                default { return $null }
	            }
	        }
	        $attempt = 0
	        $success = $false
	        $lastError = $null
	        $kerberosSession = $Script:LDAPContext -and $Script:LDAPContext['KerberosUsed']
	        if ($kerberosSession) {
	        }
	        while (-not $success -and $attempt -le $RetryCount) {
	            $attempt++
	            if ($attempt -gt 1) {
	                Start-Sleep -Seconds 2
	            }
	            try {
	                $driveName = "adPEAS_SMB_$(Get-Random -Minimum 1000 -Maximum 9999)"
	                if ($kerberosSession -or $credToUse) {
	                    try {
	                        if ($credToUse) {
	                            New-PSDrive -Name $driveName -PSProvider FileSystem -Root $targetPath -Credential $credToUse -Scope Script -ErrorAction Stop | Out-Null
	                        } else {
	                            New-PSDrive -Name $driveName -PSProvider FileSystem -Root $targetPath -Scope Script -ErrorAction Stop | Out-Null
	                        }
	                        $driveMounted = $true
	                        & $ScriptBlock $targetPath
	                        $success = $true
	                    } catch {
	                        throw $_.Exception.Message
	                    }
	                } else {
	                    try {
	                        $runspace = [runspacefactory]::CreateRunspace()
	                        $runspace.Open()
	                        $powershell = [powershell]::Create()
	                        $powershell.Runspace = $runspace
	                        $scriptText = @"
param(`$driveName, `$targetPath)
try {
	New-PSDrive -Name `$driveName -PSProvider FileSystem -Root `$targetPath -Scope Global -ErrorAction Stop | Out-Null
	return @{ Success = `$true; Error = `$null }
} catch {
	return @{ Success = `$false; Error = `$_.Exception.Message }
}
"@
	                        $null = $powershell.AddScript($scriptText)
	                        $null = $powershell.AddParameter('driveName', $driveName)
	                        $null = $powershell.AddParameter('targetPath', $targetPath)
	                        $asyncResult = $powershell.BeginInvoke()
	                        $timeoutMs = $Timeout * 1000
	                        $completed = $asyncResult.AsyncWaitHandle.WaitOne($timeoutMs)
	                        if ($completed) {
	                            $result = $powershell.EndInvoke($asyncResult)
	                            if ($result -and $result.Success) {
	                                $driveMounted = $true
	                                & $ScriptBlock $targetPath
	                            } else {
	                                $errorMsg = if ($result -and $result.Error) { $result.Error } else { "Unknown error during PSDrive mount" }
	                                throw $errorMsg
	                            }
	                        } else {
	                            throw "PSDrive mount timeout after $Timeout seconds (SMB connection could not be established)"
	                        }
	                    } finally {
	                        if ($powershell) {
	                            $powershell.Stop()
	                            $powershell.Dispose()
	                        }
	                        if ($runspace) {
	                            $runspace.Close()
	                            $runspace.Dispose()
	                        }
	                    }
	                    $success = $true
	                }
	            } catch {
	                $lastError = $_
	                $errorInfo = Get-ExceptionErrorInfo -Exception $_.Exception -Context "SMB"
	                if (-not $errorInfo.IsRetryable -or $attempt -gt $RetryCount) {
	                    throw
	                }
	            }
	        }
	        if (-not $success) {
	            throw $lastError
	        }
	    } catch {
	        $errorMsg = "SMB access failed: $_"
	        if ($shareKey) {
	            $Script:SMBShareAccessCache[$shareKey] = [string]$_
	        }
	        switch ($ErrorHandling) {
	            'Silent' {
	                return $null
	            }
	            'Warn' {
	                Write-Warning $errorMsg
	                return $null
	            }
	            'Stop' {
	                throw $errorMsg
	            }
	        }
	    } finally {
	        if ($Script:LastProgressUpdate -and $Script:LastProgressUpdate.Count -gt 0) {
	            foreach ($activityKey in @($Script:LastProgressUpdate.Keys)) {
	                try { Write-Progress -Activity $activityKey -Completed } catch { }
	            }
	            $Script:LastProgressUpdate = @{}
	        }
	        if ($driveMounted -and $driveName) {
	            try {
	                Remove-PSDrive -Name $driveName -Force -ErrorAction SilentlyContinue
	            } catch {
	            }
	        }
	    }
	}
	end {
	}
}
if (-not $Script:ProgressThreshold) {
	$Script:ProgressThreshold = 30
}
function Show-Progress {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [string]$Activity = "Processing",
	    [Parameter(Mandatory=$false)]
	    [int]$Current = 0,
	    [Parameter(Mandatory=$false)]
	    [int]$Total = 0,
	    [Parameter(Mandatory=$false)]
	    [string]$ObjectName,
	    [Parameter(Mandatory=$false)]
	    [int]$MinInterval = 250,
	    [Parameter(Mandatory=$false)]
	    [switch]$Completed
	)
	if (-not $Script:LastProgressUpdate) {
	    $Script:LastProgressUpdate = @{}
	}
	$activityKey = $Activity
	if ($Completed) {
	    Write-Progress -Activity $Activity -Completed
	    if ($Script:LastProgressUpdate.ContainsKey($activityKey)) {
	        $Script:LastProgressUpdate.Remove($activityKey)
	    }
	    return
	}
	if ($Total -eq 0 -or $Current -gt $Total) {
	    return
	}
	$now = [DateTime]::UtcNow
	if ($Script:LastProgressUpdate.ContainsKey($activityKey)) {
	    $elapsed = ($now - $Script:LastProgressUpdate[$activityKey]).TotalMilliseconds
	    if ($Current -ne 1 -and $Current -ne $Total -and $elapsed -lt $MinInterval) {
	        return
	    }
	}
	$Script:LastProgressUpdate[$activityKey] = $now
	$percentComplete = [math]::Min(100, [int](($Current / $Total) * 100))
	$status = "Testing $Current of $Total"
	if ($ObjectName) {
	    $status += " - $ObjectName"
	}
	Write-Progress -Activity $Activity -Status $status -PercentComplete $percentComplete -CurrentOperation "$percentComplete% complete"
}
$Script:ASN1_BOOLEAN           = 0x01
$Script:ASN1_INTEGER           = 0x02
$Script:ASN1_BIT_STRING        = 0x03
$Script:ASN1_OCTET_STRING      = 0x04
$Script:ASN1_NULL              = 0x05
$Script:ASN1_OBJECT_IDENTIFIER = 0x06
$Script:ASN1_UTF8_STRING       = 0x0C
$Script:ASN1_SEQUENCE          = 0x30  # Constructed
$Script:ASN1_SET               = 0x31  # Constructed
$Script:ASN1_PRINTABLE_STRING  = 0x13
$Script:ASN1_IA5_STRING        = 0x16
$Script:ASN1_UTC_TIME          = 0x17
$Script:ASN1_GENERALIZED_TIME  = 0x18
$Script:ASN1_GENERAL_STRING    = 0x1B
$Script:ASN1_CLASS_UNIVERSAL   = 0x00
$Script:ASN1_CLASS_APPLICATION = 0x40
$Script:ASN1_CLASS_CONTEXT     = 0x80
$Script:ASN1_CLASS_PRIVATE     = 0xC0
$Script:ASN1_CONSTRUCTED       = 0x20
function New-ASN1Length {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [int]$Length
	)
	if ($Length -lt 0) {
	    throw "ASN.1 length cannot be negative"
	}
	if ($Length -lt 128) {
	    return [byte[]]@($Length)
	}
	else {
	    $lengthBytes = [System.Collections.Generic.List[byte]]::new()
	    $tempLength = $Length
	    while ($tempLength -gt 0) {
	        $lengthBytes.Insert(0, [byte]($tempLength -band 0xFF))
	        $tempLength = $tempLength -shr 8
	    }
	    $result = [byte[]]@(0x80 -bor $lengthBytes.Count) + $lengthBytes.ToArray()
	    return $result
	}
}
function Read-ASN1Length {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [byte[]]$Data,
	    [Parameter(Mandatory=$true)]
	    [int]$Offset
	)
	if ($Offset -ge $Data.Length) {
	    throw "ASN.1 length: offset beyond data"
	}
	$firstByte = $Data[$Offset]
	if ($firstByte -lt 128) {
	    return @{
	        Length = [int]$firstByte
	        BytesConsumed = 1
	    }
	}
	elseif ($firstByte -eq 0x80) {
	    throw "ASN.1 indefinite length not supported in DER"
	}
	else {
	    $numLengthBytes = $firstByte -band 0x7F
	    if ($Offset + 1 + $numLengthBytes -gt $Data.Length) {
	        throw "ASN.1 length: insufficient data for long form"
	    }
	    [long]$length = 0
	    for ($i = 0; $i -lt $numLengthBytes; $i++) {
	        $length = ($length -shl 8) -bor $Data[$Offset + 1 + $i]
	    }
	    return @{
	        Length = $length
	        BytesConsumed = 1 + $numLengthBytes
	    }
	}
}
function New-ASN1Integer {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [object]$Value
	)
	$bytes = $null
	if ($Value -is [byte[]]) {
	    $bytes = $Value
	}
	elseif ($Value -is [array]) {
	    $bytes = [byte[]]($Value | ForEach-Object { [byte]$_ })
	}
	elseif ($Value -is [int] -or $Value -is [int64] -or $Value -is [uint32] -or $Value -is [uint64]) {
	    if ($Value -eq 0) {
	        $bytes = @(0x00)
	    }
	    else {
	        $tempValue = [uint64]$Value
	        $byteList = [System.Collections.Generic.List[byte]]::new()
	        while ($tempValue -gt 0) {
	            $byteList.Insert(0, [byte]($tempValue -band 0xFF))
	            $tempValue = $tempValue -shr 8
	        }
	        $bytes = $byteList.ToArray()
	        if ($bytes[0] -band 0x80) {
	            $bytes = @(0x00) + $bytes
	        }
	    }
	}
	elseif ($Value -is [System.Numerics.BigInteger]) {
	    $bytes = $Value.ToByteArray()
	    [Array]::Reverse($bytes)  # .NET uses little-endian
	    while ($bytes.Length -gt 1 -and $bytes[0] -eq 0 -and -not ($bytes[1] -band 0x80)) {
	        $bytes = [byte[]]$bytes[1..($bytes.Length - 1)]
	    }
	}
	else {
	    throw "Unsupported integer type: $($Value.GetType().Name)"
	}
	$tag = [byte]$Script:ASN1_INTEGER
	$lengthBytes = New-ASN1Length -Length $bytes.Length
	return [byte[]](@($tag) + $lengthBytes + $bytes)
}
function New-ASN1OctetString {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [byte[]]$Value = @()
	)
	if ($null -eq $Value) { $Value = @() }
	$tag = [byte]$Script:ASN1_OCTET_STRING
	$lengthBytes = New-ASN1Length -Length $Value.Length
	if ($Value.Length -eq 0) {
	    return [byte[]](@($tag) + $lengthBytes)
	}
	return [byte[]](@($tag) + $lengthBytes + $Value)
}
function New-ASN1BitString {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [byte[]]$Value,
	    [Parameter(Mandatory=$false)]
	    [int]$UnusedBits = 0
	)
	if ($UnusedBits -lt 0 -or $UnusedBits -gt 7) {
	    throw "UnusedBits must be 0-7"
	}
	$tag = [byte]$Script:ASN1_BIT_STRING
	$content = @([byte]$UnusedBits) + $Value
	$lengthBytes = New-ASN1Length -Length $content.Length
	return [byte[]](@($tag) + $lengthBytes + $content)
}
function New-ASN1Boolean {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [bool]$Value
	)
	$tag = [byte]$Script:ASN1_BOOLEAN
	$content = if ($Value) { 0xFF } else { 0x00 }
	return [byte[]]@($tag, 0x01, $content)
}
function New-ASN1Null {
	return [byte[]]@($Script:ASN1_NULL, 0x00)
}
function New-ASN1ObjectIdentifier {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$OID
	)
	$components = $OID.Split('.') | ForEach-Object { [int]$_ }
	if ($components.Count -lt 2) {
	    throw "OID must have at least 2 components"
	}
	$bytes = [System.Collections.Generic.List[byte]]::new()
	$bytes.Add([byte](($components[0] * 40) + $components[1]))
	for ($i = 2; $i -lt $components.Count; $i++) {
	    $value = $components[$i]
	    if ($value -eq 0) {
	        $bytes.Add(0x00)
	    }
	    else {
	        $encoded = [System.Collections.Generic.List[byte]]::new()
	        while ($value -gt 0) {
	            $encoded.Insert(0, [byte](($value -band 0x7F) -bor 0x80))
	            $value = $value -shr 7
	        }
	        $encoded[$encoded.Count - 1] = $encoded[$encoded.Count - 1] -band 0x7F
	        $bytes.AddRange($encoded)
	    }
	}
	$tag = [byte]$Script:ASN1_OBJECT_IDENTIFIER
	$lengthBytes = New-ASN1Length -Length $bytes.Count
	return [byte[]](@($tag) + $lengthBytes + $bytes.ToArray())
}
function New-ASN1GeneralString {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$Value
	)
	$bytes = [System.Text.Encoding]::ASCII.GetBytes($Value)
	$tag = [byte]$Script:ASN1_GENERAL_STRING
	$lengthBytes = New-ASN1Length -Length $bytes.Length
	return [byte[]](@($tag) + $lengthBytes + $bytes)
}
