	                currentSearchQuery = e.target.value.toLowerCase();
	                applyFilters();
	            }, UI_CONSTANTS.SEARCH_DEBOUNCE_DELAY);
	        });
	        // Initialize finding tooltips
	        initFindingTooltips();
	        // Initialize check help tooltips
