	    // Clear all adPEAS data from localStorage
	    function clearAdPEASData() {
	        const keys = Object.keys(localStorage).filter(k => k.startsWith('adpeas-'));
	        const count = keys.length;
	        if (count === 0) {
	            announceToScreenReader('No adPEAS data found in storage.');
	            alert('No adPEAS data found in browser storage.');
	            return;
	        }
	        const confirmMsg = 'This will remove all adPEAS data from your browser:\n\n' +
	            '• Completed findings (checkboxes) for ALL reports\n' +
	            '• Theme preference\n\n' +
	            'Found ' + count + ' stored item(s).\n\n' +
	            'The page will reload after clearing. Continue?';
	        if (confirm(confirmMsg)) {
	            keys.forEach(k => localStorage.removeItem(k));
	            announceToScreenReader('All adPEAS data cleared. Reloading page.');
	            location.reload();
	        }
	    }
	    function toggleShortcutHelp() {
	        const backdrop = document.getElementById('shortcutBackdrop');
	        const modal = document.getElementById('shortcutHelp');
	        const isOpening = !modal.classList.contains('visible');
	        backdrop.classList.toggle('visible');
	        modal.classList.toggle('visible');
	        if (isOpening) {
	            // Focus trap and announce
	            trapFocus(modal);
	            announceToScreenReader('Help dialog opened. Press Escape to close.');
	        } else {
	            restoreFocus();
	        }
	    }
	    function hideShortcutHelp() {
	        document.getElementById('shortcutBackdrop').classList.remove('visible');
	        document.getElementById('shortcutHelp').classList.remove('visible');
	        restoreFocus();
	    }
	    // ============================================================
	    // TOP PRIORITY ACTIONS with Context-Aware Risk Scoring
	    // ============================================================
	    // ==========================================================================
	    // CONTEXT-AWARE SCORING SYSTEM
	    // ==========================================================================
	    // Score = BASE_SCORE * IMPACT_MODIFIER * EXPLOITABILITY_MODIFIER * SECURITY_MODIFIER + CORRELATION
	    //
	    // Definitions are maintained centrally in: src/modules/Core/adPEAS-ScoringDefinitions.ps1
	    // Documentation: docs/10-Risk-Scoring-System.md
	    // ==========================================================================
	    // ---- BEGIN AUTO-GENERATED SCORING DEFINITIONS ----
	    // Source: adPEAS-ScoringDefinitions.ps1
{{SCORING_DEFINITIONS}}
	    // ---- END AUTO-GENERATED SCORING DEFINITIONS ----
	    // Exploitability modifiers for cracking-based attacks
	    // Uses values from securityModifiers, passwordAgeModifiers, passwordLengthModifiers, etc.
	    function getExploitabilityModifier(accountInfo, findingType) {
	        let modifier = 1.0;
	        // Only apply these modifiers to attacks that require cracking
	        const crackingAttacks = ['kerberoast', 'asrep', 'preauth'];
	        const isCrackingAttack = crackingAttacks.some(a => findingType.includes(a));
	        if (!isCrackingAttack || !accountInfo) {
	            return modifier;
	        }
	        // Get domain password policy for context-aware age evaluation
	        const maxPwdAgeDays = scoringContext?.domainInfo?.maxPwdAgeDays || 0;
	        const minPwdLength = scoringContext?.domainInfo?.minPwdLength || 0;
	        // Password age factor - relative to policy, not absolute
	        if (accountInfo.pwdAgeDays !== null && accountInfo.pwdAgeDays > 0) {
	            const pwdAge = accountInfo.pwdAgeDays;
	            if (maxPwdAgeDays > 0) {
	                // Policy exists - evaluate relative to policy
	                const policyMultiples = pwdAge / maxPwdAgeDays;
	                if (policyMultiples >= 10) {
	                    modifier *= passwordAgeModifiers.multiplier_10x;
	                } else if (policyMultiples >= 5) {
	                    modifier *= passwordAgeModifiers.multiplier_5x;
	                } else if (policyMultiples >= 3) {
	                    modifier *= passwordAgeModifiers.multiplier_3x;
	                } else if (policyMultiples >= 2) {
	                    modifier *= passwordAgeModifiers.multiplier_2x;
	                } else if (policyMultiples >= 1) {
	                    modifier *= passwordAgeModifiers.multiplier_1x;
	                } else {
	                    modifier *= passwordAgeModifiers.within_policy;
	                }
	            } else {
	                // No policy (never expires) - use absolute thresholds
	                if (pwdAge > 365 * 5) {
	                    modifier *= passwordAgeModifiers.multiplier_5x;
	                } else if (pwdAge > 365 * 2) {
	                    modifier *= passwordAgeModifiers.multiplier_2x;
	                } else if (pwdAge > 365) {
	                    modifier *= passwordAgeModifiers.multiplier_1x;
	                }
	            }
	        }
	        // Password policy strength affects cracking difficulty
	        const complexityEnabled = scoringContext?.domainInfo?.complexityEnabled || false;
	        // Password length impact on cracking time
	        if (minPwdLength > 0) {
	            if (minPwdLength < 8) {
	                modifier *= passwordLengthModifiers.very_weak;
	            } else if (minPwdLength < 12) {
	                modifier *= passwordLengthModifiers.weak;
	            } else if (minPwdLength < 16) {
	                modifier *= passwordLengthModifiers.standard;
	            } else {
	                modifier *= passwordLengthModifiers.strong;
	            }
	        }
	        // Password complexity
	        if (!complexityEnabled) {
	            modifier *= passwordComplexityModifiers.disabled;
	        } else {
	            modifier *= passwordComplexityModifiers.enabled;
	        }
	        // Combined weak policy scenario (short + no complexity)
	        if (minPwdLength > 0 && minPwdLength < 10 && !complexityEnabled) {
	            modifier *= 1.15;  // Additional penalty for very weak combination
	        }
	        // Encryption type factor (RC4 = much easier to crack)
	        if (accountInfo.encryptionTypes && accountInfo.encryptionTypes.length > 0) {
	            const hasRC4Only = accountInfo.encryptionTypes.includes('RC4-HMAC') &&
	                               !accountInfo.encryptionTypes.includes('AES256') &&
	                               !accountInfo.encryptionTypes.includes('AES128');
	            const hasAES = accountInfo.encryptionTypes.includes('AES256') ||
	                           accountInfo.encryptionTypes.includes('AES128');
	            if (hasRC4Only) {
	                modifier *= encryptionTypeModifiers.rc4_only;
	            } else if (hasAES && !accountInfo.encryptionTypes.includes('RC4-HMAC')) {
	                modifier *= encryptionTypeModifiers.aes256;
	            }
	        }
	        return modifier;
	    }
	    // Security configuration modifiers - REDUCE score for secure settings
	    // Uses values from securityModifiers object
	    function getSecurityModifier(accountInfo, findingType) {
	        if (!accountInfo || !accountInfo.uacFlags) {
	            return 1.0;
	        }
	        let modifier = 1.0;
	        const flags = accountInfo.uacFlags;
	        const isCrackingAttack = ['kerberoast', 'asrep', 'preauth'].some(a => findingType.includes(a));
	        const isCredentialAttack = ['credential', 'password', 'gpp', 'autoadmin'].some(a => findingType.includes(a));
	        // ========================================
	        // ACCOUNT STATUS FLAGS (affect ALL attacks)
	        // ========================================
	        if (flags.includes('ACCOUNTDISABLE') || flags.includes('Disabled')) {
	            modifier *= securityModifiers.ACCOUNTDISABLE;
	        }
	        if (flags.includes('LOCKOUT') || flags.includes('Locked')) {
	            modifier *= securityModifiers.LOCKOUT;
	        }
	        // ========================================
	        // KERBEROS SECURITY FLAGS (affect cracking attacks)
	        // ========================================
	        if (isCrackingAttack) {
	            if (flags.includes('SMARTCARD_REQUIRED') || flags.includes('SmartcardRequired')) {
	                modifier *= securityModifiers.SMARTCARD_REQUIRED;
	            }
	            if (accountInfo.isProtectedUser) {
	                modifier *= securityModifiers.PROTECTED_USERS;
	            }
	        }
	        // ========================================
	        // DELEGATION FLAGS (affect delegation attacks)
	        // ========================================
	        const isDelegationAttack = ['delegation', 'rbcd', 'constrained', 'unconstrained'].some(a => findingType.includes(a));
	        if (isDelegationAttack) {
	            if (flags.includes('NOT_DELEGATED') || flags.includes('NotDelegated') ||
	                flags.includes('AccountNotDelegated') || flags.includes('Sensitive')) {
	                modifier *= securityModifiers.NOT_DELEGATED;
	            }
	        }
	        // ========================================
	        // PASSWORD FLAGS (affect credential attacks)
	        // ========================================
	        if (isCrackingAttack || isCredentialAttack) {
	            if (flags.includes('PASSWORD_EXPIRED') || flags.includes('PasswordExpired')) {
	                modifier *= securityModifiers.PASSWORD_EXPIRED;
	            }
	        }
	        // ========================================
	        // ENCRYPTION FLAGS (affect Kerberoast specifically)
	        // ========================================
	        if (flags.includes('USE_DES_KEY_ONLY') || flags.includes('DESKeyOnly')) {
	            modifier *= securityModifiers.USE_DES_KEY_ONLY;
	        }
	        return modifier;
	    }
	    // Get account info from scoring context
	    function getAccountInfoFromCard(card) {
	        if (!scoringContext || !scoringContext.accounts) {
	            return null;
	        }
	        // Try to find account by extracting identifiers from card content
	        const objectDetails = card.querySelectorAll('.object-detail');
	        for (const detail of objectDetails) {
	            // Look for sAMAccountName or distinguishedName in the card
	            const rows = detail.querySelectorAll('.attr-row');
	            for (const row of rows) {
	                const nameEl = row.querySelector('.attr-name');
	                const valueEl = row.querySelector('.attr-value');
	                if (!nameEl || !valueEl) continue;
	                const attrName = nameEl.textContent.trim().toLowerCase();
	                const attrValue = valueEl.textContent.trim();
	                // Match by objectSid first (most reliable)
	                if (attrName === 'objectsid' && scoringContext.accounts[attrValue]) {
	                    return scoringContext.accounts[attrValue];
	                }
	                // Match by DN
	                if (attrName === 'distinguishedname' && scoringContext.accounts[attrValue]) {
	                    return scoringContext.accounts[attrValue];
	                }
	                // Match by sAMAccountName (iterate through accounts)
	                if (attrName === 'samaccountname') {
	                    for (const [key, acct] of Object.entries(scoringContext.accounts)) {
	                        if (acct.name && acct.name.toLowerCase() === attrValue.toLowerCase()) {
	                            return acct;
	                        }
	                    }
	                }
	            }
	        }
	        return null;
	    }
	    // Check if account appears in multiple risky findings (correlation bonus)
	    // Uses values from correlationBonus object
	    // Non-admin accounts get ENHANCED correlation bonus - they represent potential attack paths
	    function getCorrelationBonus(accountInfo) {
	        if (!scoringContext || !scoringContext.correlations || !accountInfo) {
	            return 0;
	        }
	        // Find correlations for this account
	        const accountId = accountInfo.sid || accountInfo.dn || accountInfo.name;
	        const correlation = scoringContext.correlations[accountId];
	        if (!correlation) {
	            return 0;
	        }
	        // Determine if this is a non-admin account
	        const isNonAdmin = !accountInfo.isAdmin && accountInfo.adminTier === 'none';
	        let bonus = 0;
	        // Dangerous combinations get max bonus
	        if (correlation.hasDCSync && (correlation.hasKerberoast || correlation.hasASREP)) {
	            bonus = isNonAdmin ? correlationBonus.nonAdminMaxBonus : correlationBonus.maxBonus;
	        } else if (correlation.hasDelegation && correlation.hasKerberoast) {
	            const perFinding = isNonAdmin ? correlationBonus.nonAdminPerFinding : correlationBonus.perFinding;
	            const maxBonus = isNonAdmin ? correlationBonus.nonAdminMaxBonus : correlationBonus.maxBonus;
	            bonus = Math.min(perFinding * 2, maxBonus);
	        } else if (correlation.count >= 2) {
	            // Non-admin with 3+ findings = enhanced bonus (potential privilege escalation path)
	            if (isNonAdmin && correlation.count >= correlationBonus.nonAdminThreshold) {
	                // Enhanced correlation for non-admins appearing in multiple findings
	                bonus = Math.min((correlation.count - 1) * correlationBonus.nonAdminPerFinding, correlationBonus.nonAdminMaxBonus);
	            } else {
	                // Standard correlation for admins or non-admins below threshold
	                bonus = Math.min((correlation.count - 1) * correlationBonus.perFinding, correlationBonus.maxBonus);
	            }
	        }
	        return bonus;
	    }
	    // Calculate score with full breakdown for transparency
	    function calculateFindingScoreWithBreakdown(card) {
	        const severity = card.dataset.severity || 'note';
	        const breakdown = {
	            severity: severity,
	            baseScore: 0,
	            matchedPattern: null,
	            impactMod: 1.0,
	            impactReason: 'Standard',
	            exploitMod: 1.0,
	            exploitReasons: [],
	            securityMod: 1.0,
	            securityReasons: [],
	            correlationBonus: 0,
	            correlationReason: null,
	            finalScore: 0
	        };
	        // Note and Secure = no security issue
	        if (severity === 'note' || severity === 'secure') {
	            breakdown.baseScore = 0;
	            breakdown.finalScore = 0;
	            return breakdown;
	        }
	        // HINT severity = informational findings
	        if (severity === 'hint') {
	            breakdown.baseScore = severityBaseScores['hint'] || 15;
	            breakdown.finalScore = breakdown.baseScore;
	            breakdown.matchedPattern = 'hint (informational)';
	            return breakdown;
	        }
	        // Get finding title
	        const title = (card.querySelector('.finding-title')?.textContent || '').toLowerCase();
	        // 1. Determine BASE score from finding type
	        breakdown.baseScore = severityBaseScores[severity] || 5;
	        for (const [pattern, score] of Object.entries(findingBaseScores)) {
	            if (title.includes(pattern.toLowerCase())) {
	                if (score > breakdown.baseScore) {
	                    breakdown.baseScore = score;
	                    breakdown.matchedPattern = pattern;
	                }
	            }
	        }
	        // DCSync/Replication Rights are ALWAYS maximum
	        if (breakdown.matchedPattern === 'dcsync' || breakdown.matchedPattern === 'replication rights') {
	            breakdown.finalScore = 100;
	            breakdown.impactReason = 'Maximum (DCSync)';
	            return breakdown;
	        }
	        // 2. Get account context
	        const accountInfo = getAccountInfoFromCard(card);
	        // 3. Apply IMPACT modifier
	        if (accountInfo && accountInfo.adminTier) {
	            breakdown.impactMod = impactMultipliers[accountInfo.adminTier] || impactMultipliers.none;
	            const tierNames = { tier0: 'Tier 0 (Domain Admin)', tier1: 'Tier 1 (Server Admin)', tier2: 'Tier 2 (Workstation Admin)', none: 'Non-Admin' };
	            breakdown.impactReason = tierNames[accountInfo.adminTier] || 'Standard';
	        }
	        // 4. Apply EXPLOITABILITY modifier with reasons
	        breakdown.exploitMod = getExploitabilityModifier(accountInfo, title);
	        if (accountInfo) {
	            if (accountInfo.pwdAgeDays > 365) {
	                breakdown.exploitReasons.push('Old password (' + Math.round(accountInfo.pwdAgeDays / 365) + 'y)');
	            }
	            if (accountInfo.encryptionTypes && accountInfo.encryptionTypes.includes('RC4-HMAC') && !accountInfo.encryptionTypes.includes('AES256')) {
	                breakdown.exploitReasons.push('RC4 encryption');
	            }
	        }
	        if (breakdown.exploitReasons.length === 0 && breakdown.exploitMod !== 1.0) {
	            breakdown.exploitReasons.push(breakdown.exploitMod > 1 ? 'Easier to exploit' : 'Harder to exploit');
	        }
	        // 5. Apply SECURITY modifier with reasons
	        breakdown.securityMod = getSecurityModifier(accountInfo, title);
	        if (accountInfo && accountInfo.uacFlags) {
	            const flags = accountInfo.uacFlags;
	            if (flags.includes('ACCOUNTDISABLE') || flags.includes('Disabled')) {
	                breakdown.securityReasons.push('Disabled');
	            }
	            if (flags.includes('SMARTCARD_REQUIRED') || flags.includes('SmartcardRequired')) {
	                breakdown.securityReasons.push('Smartcard required');
	            }
	            if (accountInfo.isProtectedUser) {
	                breakdown.securityReasons.push('Protected Users');
	            }
	        }
	        if (breakdown.securityReasons.length === 0 && breakdown.securityMod !== 1.0) {
	            breakdown.securityReasons.push(breakdown.securityMod < 1 ? 'Mitigated' : 'Vulnerable');
	        }
	        // 6. Add correlation bonus
	        breakdown.correlationBonus = getCorrelationBonus(accountInfo);
	        if (breakdown.correlationBonus > 0) {
	            breakdown.correlationReason = 'Appears in multiple findings';
	        }
	        // Calculate final score
	        let rawScore = Math.round(breakdown.baseScore * breakdown.impactMod * breakdown.exploitMod * breakdown.securityMod) + breakdown.correlationBonus;
	        breakdown.finalScore = Math.min(Math.max(rawScore, 0), 100);
	        return breakdown;
	    }
	    // Simple wrapper for backwards compatibility
	    function calculateFindingScore(card) {
	        return calculateFindingScoreWithBreakdown(card).finalScore;
	    }
	    // Format score breakdown as tooltip text
	    function formatScoreBreakdown(breakdown) {
	        if (breakdown.finalScore === 0) {
	            return 'No risk score (informational)';
	        }
	        let lines = [];
	        lines.push('Score Breakdown:');
	        lines.push('─────────────────');
	        lines.push('Base: ' + breakdown.baseScore + (breakdown.matchedPattern ? ' (' + breakdown.matchedPattern + ')' : ''));
	        if (breakdown.impactMod !== 1.0) {
	            lines.push('Impact: ×' + breakdown.impactMod.toFixed(2) + ' (' + breakdown.impactReason + ')');
	        }
	        if (breakdown.exploitMod !== 1.0) {
	            const reasons = breakdown.exploitReasons.length > 0 ? breakdown.exploitReasons.join(', ') : '';
	            lines.push('Exploitability: ×' + breakdown.exploitMod.toFixed(2) + (reasons ? ' (' + reasons + ')' : ''));
	        }
	        if (breakdown.securityMod !== 1.0) {
	            const reasons = breakdown.securityReasons.length > 0 ? breakdown.securityReasons.join(', ') : '';
	            lines.push('Security: ×' + breakdown.securityMod.toFixed(2) + (reasons ? ' (' + reasons + ')' : ''));
	        }
	        if (breakdown.correlationBonus > 0) {
	            lines.push('Correlation: +' + breakdown.correlationBonus + (breakdown.correlationReason ? ' (' + breakdown.correlationReason + ')' : ''));
	        }
	        lines.push('─────────────────');
	        lines.push('Final: ' + breakdown.finalScore);
	        return lines.join('\n');
	    }
	    // Format score breakdown as styled HTML tooltip content
	    function formatScoreBreakdownHtml(breakdown) {
	        if (breakdown.finalScore === 0) {
	            return `
	                <div class="score-tooltip-header">
	                    <span class="score-tooltip-title">Score Breakdown</span>
	                    <span class="score-tooltip-final info">0</span>
	                </div>
	                <div class="score-tooltip-body">
	                    <div class="score-tooltip-row">
	                        <span class="score-tooltip-label">No risk score (informational)</span>
	                    </div>
	                </div>
	            `;
	        }
	        const scoreClass = breakdown.finalScore >= scoreThresholds.critical ? 'critical' :
	                           breakdown.finalScore >= scoreThresholds.high ? 'high' :
	                           breakdown.finalScore >= scoreThresholds.medium ? 'medium' :
	                           breakdown.finalScore >= scoreThresholds.low ? 'low' : 'info';
	        let rowsHtml = '';
	        // Base Score
	        rowsHtml += `
	            <div class="score-tooltip-row">
	                <span class="score-tooltip-label">Base Score${breakdown.matchedPattern ? `<span class="reason">${escapeHtml(breakdown.matchedPattern)}</span>` : ''}</span>
	                <span class="score-tooltip-value positive">${breakdown.baseScore}</span>
	            </div>
	        `;
	        // Impact Modifier
	        if (breakdown.impactMod !== 1.0) {
	            rowsHtml += `
	                <div class="score-tooltip-row">
	                    <span class="score-tooltip-label">Impact<span class="reason">${escapeHtml(breakdown.impactReason)}</span></span>
	                    <span class="score-tooltip-value modifier">×${breakdown.impactMod.toFixed(2)}</span>
	                </div>
	            `;
	        }
	        // Exploitability Modifier
	        if (breakdown.exploitMod !== 1.0) {
	            const reasons = breakdown.exploitReasons.length > 0 ? breakdown.exploitReasons.join(', ') : '';
	            rowsHtml += `
	                <div class="score-tooltip-row">
	                    <span class="score-tooltip-label">Exploitability${reasons ? `<span class="reason">${escapeHtml(reasons)}</span>` : ''}</span>
	                    <span class="score-tooltip-value modifier">×${breakdown.exploitMod.toFixed(2)}</span>
	                </div>
	            `;
	        }
	        // Security Modifier
	        if (breakdown.securityMod !== 1.0) {
	            const reasons = breakdown.securityReasons.length > 0 ? breakdown.securityReasons.join(', ') : '';
	            rowsHtml += `
	                <div class="score-tooltip-row">
	                    <span class="score-tooltip-label">Security${reasons ? `<span class="reason">${escapeHtml(reasons)}</span>` : ''}</span>
	                    <span class="score-tooltip-value modifier">×${breakdown.securityMod.toFixed(2)}</span>
	                </div>
	            `;
	        }
	        // Correlation Bonus
	        if (breakdown.correlationBonus > 0) {
	            rowsHtml += `
	                <div class="score-tooltip-row">
	                    <span class="score-tooltip-label">Correlation${breakdown.correlationReason ? `<span class="reason">${escapeHtml(breakdown.correlationReason)}</span>` : ''}</span>
	                    <span class="score-tooltip-value positive">+${breakdown.correlationBonus}</span>
	                </div>
	            `;
	        }
	        return `
	            <div class="score-tooltip-header">
	                <span class="score-tooltip-title">Score Breakdown</span>
	                <span class="score-tooltip-final ${scoreClass}">${breakdown.finalScore}</span>
	            </div>
	            <div class="score-tooltip-body">
	                ${rowsHtml}
	            </div>
	        `;
	    }
	    // Active score tooltip reference
	    let activeScoreTooltip = null;
	    // Initialize score tooltips for styled display
	    function initScoreTooltips() {
	        // Create tooltip container
	        const tooltipDiv = document.createElement('div');
	        tooltipDiv.id = 'scoreTooltip';
	        tooltipDiv.className = 'score-tooltip';
	        tooltipDiv.setAttribute('role', 'tooltip');
	        document.body.appendChild(tooltipDiv);
	        // Close tooltip when clicking outside
	        document.addEventListener('click', function(e) {
	            if (activeScoreTooltip && !e.target.closest('.score-tooltip') && !e.target.closest('[data-score-breakdown]')) {
	                closeScoreTooltip();
	            }
	        });
	        // Close on Escape key
	        document.addEventListener('keydown', function(e) {
	            if (e.key === 'Escape' && activeScoreTooltip) {
	                closeScoreTooltip();
	            }
	        });
	    }
	    function showScoreTooltip(trigger, breakdown) {
	        const tooltip = document.getElementById('scoreTooltip');
	        if (!tooltip) return;
	        // Close any previously open tooltip first
	        if (activeScoreTooltip) {
	            closeScoreTooltip();
	        }
	        // Build tooltip HTML
	        tooltip.innerHTML = formatScoreBreakdownHtml(breakdown);
	        // Make visible for positioning measurement
	        tooltip.style.visibility = 'hidden';
	        tooltip.classList.add('visible');
	        // Position tooltip
	        positionScoreTooltip(tooltip, trigger);
	        // Show tooltip
	        tooltip.style.visibility = 'visible';
	        activeScoreTooltip = tooltip;
	    }
	    function closeScoreTooltip() {
	        const tooltip = document.getElementById('scoreTooltip');
	        if (tooltip) {
	            tooltip.classList.remove('visible');
	        }
	        activeScoreTooltip = null;
	    }
	    function positionScoreTooltip(tooltip, trigger) {
	        const triggerRect = trigger.getBoundingClientRect();
	        const tooltipRect = tooltip.getBoundingClientRect();
	        const viewportWidth = window.innerWidth;
	        const viewportHeight = window.innerHeight;
	        const padding = UI_CONSTANTS.VIEWPORT_PADDING;
	        // Default: position below the trigger, centered
	        let left = triggerRect.left + (triggerRect.width / 2) - (tooltipRect.width / 2);
	        let top = triggerRect.bottom + 8;
	        // Adjust horizontal position if tooltip would overflow
	        if (left < padding) {
	            left = padding;
	        } else if (left + tooltipRect.width > viewportWidth - padding) {
	            left = viewportWidth - tooltipRect.width - padding;
	        }
	        // If tooltip would overflow bottom, position above trigger
	        if (top + tooltipRect.height > viewportHeight - padding) {
	            top = triggerRect.top - tooltipRect.height - 8;
	        }
	        // Ensure not above viewport
	        if (top < padding) {
	            top = padding;
	        }
	        tooltip.style.left = left + 'px';
	        tooltip.style.top = top + 'px';
	    }
	    // Calculate score from finding metadata (JSON-based, no DOM traversal)
	    function calculateScoreFromMetadata(findingMeta) {
	        const severity = findingMeta.severity || 'note';
	        const breakdown = {
	            severity: severity,
	            baseScore: 0,
	            matchedPattern: null,
	            impactMod: 1.0,
	            impactReason: 'Standard',
	            exploitMod: 1.0,
	            exploitReasons: [],
	            securityMod: 1.0,
	            securityReasons: [],
	            correlationBonus: 0,
	            correlationReason: null,
	            finalScore: 0
	        };
	        // Note and Secure = no security issue
	        if (severity === 'note' || severity === 'secure') {
	            return breakdown;
	        }
	        // HINT severity = informational findings
	        if (severity === 'hint') {
	            breakdown.baseScore = severityBaseScores['hint'] || 15;
	            breakdown.finalScore = breakdown.baseScore;
	            breakdown.matchedPattern = 'hint (informational)';
	            return breakdown;
	        }
	        // Get finding title
	        const title = (findingMeta.title || '').toLowerCase();
	        // 1. Determine BASE score from finding type
	        breakdown.baseScore = severityBaseScores[severity] || 5;
	        for (const [pattern, score] of Object.entries(findingBaseScores)) {
	            if (title.includes(pattern.toLowerCase())) {
	                if (score > breakdown.baseScore) {
	                    breakdown.baseScore = score;
	                    breakdown.matchedPattern = pattern;
	                }
	            }
	        }
	        // 1b. Check vulnerability tags (e.g., ADCS ESC1, ESC4) against findingBaseScores
	        // When the card title (e.g., "Certificate Templates") doesn't match,
	        // but objects contain vulnerability tags, use the highest matching score
	        if (findingMeta.vulnerabilities && findingMeta.vulnerabilities.length > 0) {
	            for (const vulnTag of findingMeta.vulnerabilities) {
	                const vulnLower = vulnTag.toLowerCase();
	                for (const [pattern, score] of Object.entries(findingBaseScores)) {
	                    // Match "esc1" against FindingID keys like "esc1_template", "esc1_vulnerable_..."
	                    if (pattern.toLowerCase().startsWith(vulnLower + '_') || pattern.toLowerCase() === vulnLower) {
	                        if (score > breakdown.baseScore) {
	                            breakdown.baseScore = score;
	                            breakdown.matchedPattern = pattern + ' (via ' + vulnTag + ')';
	                        }
	                    }
	                }
	            }
	        }
	        // DCSync/Replication Rights are ALWAYS maximum
	        if (breakdown.matchedPattern && (breakdown.matchedPattern.startsWith('dcsync') || breakdown.matchedPattern.startsWith('replication rights'))) {
	            breakdown.finalScore = 100;
	            breakdown.impactReason = 'Maximum (DCSync)';
	            return breakdown;
	        }
	        // 2. Get account context from scoringContext using accountSID
	        const accountInfo = findingMeta.accountSID ? scoringContext?.accounts?.[findingMeta.accountSID] : null;
	        // 3. Apply IMPACT modifier
	        if (accountInfo && accountInfo.adminTier) {
	            breakdown.impactMod = impactMultipliers[accountInfo.adminTier] || impactMultipliers.none;
	            const tierNames = { tier0: 'Tier 0 (Domain Admin)', tier1: 'Tier 1 (Server Admin)', tier2: 'Tier 2 (Workstation Admin)', none: 'Non-Admin' };
	            breakdown.impactReason = tierNames[accountInfo.adminTier] || 'Standard';
	        }
	        // 4. Apply EXPLOITABILITY modifier with reasons
	        breakdown.exploitMod = getExploitabilityModifier(accountInfo, title);
	        if (accountInfo) {
	            if (accountInfo.pwdAgeDays > 365) {
	                breakdown.exploitReasons.push('Old password (' + Math.round(accountInfo.pwdAgeDays / 365) + 'y)');
	            }
	            if (accountInfo.encryptionTypes && accountInfo.encryptionTypes.includes('RC4-HMAC') && !accountInfo.encryptionTypes.includes('AES256')) {
	                breakdown.exploitReasons.push('RC4 encryption');
	            }
	        }
	        if (breakdown.exploitReasons.length === 0 && breakdown.exploitMod !== 1.0) {
	            breakdown.exploitReasons.push(breakdown.exploitMod > 1 ? 'Easier to exploit' : 'Harder to exploit');
	        }
	        // 5. Apply SECURITY modifier with reasons
	        breakdown.securityMod = getSecurityModifier(accountInfo, title);
	        if (accountInfo && accountInfo.uacFlags) {
	            const flags = accountInfo.uacFlags;
	            if (flags.includes('ACCOUNTDISABLE') || flags.includes('Disabled')) {
	                breakdown.securityReasons.push('Disabled');
	            }
	            if (flags.includes('SMARTCARD_REQUIRED') || flags.includes('SmartcardRequired')) {
	                breakdown.securityReasons.push('Smartcard required');
	            }
	            if (accountInfo.isProtectedUser) {
	                breakdown.securityReasons.push('Protected Users');
	            }
	        }
	        if (breakdown.securityReasons.length === 0 && breakdown.securityMod !== 1.0) {
	            breakdown.securityReasons.push(breakdown.securityMod < 1 ? 'Mitigated' : 'Vulnerable');
	        }
	        // 6. Add correlation bonus
	        breakdown.correlationBonus = getCorrelationBonus(accountInfo);
	        if (breakdown.correlationBonus > 0) {
	            breakdown.correlationReason = 'Appears in multiple findings';
	        }
	        // Calculate final score
	        let rawScore = Math.round(breakdown.baseScore * breakdown.impactMod * breakdown.exploitMod * breakdown.securityMod) + breakdown.correlationBonus;
	        breakdown.finalScore = Math.min(Math.max(rawScore, 0), 100);
	        return breakdown;
	    }
	    // Find the best matching findingDefinition for a given finding card metadata
	    // Priority: 1) findingIds from metadata, 2) vulnerability tags, 3) title keyword matching
	    function findBestFindingDefinition(meta) {
	        if (!findingDefinitions || !meta) return null;
	        let bestKey = null;
	        let bestScore = 0;
	        // 1. Direct FindingId lookup (most reliable — from attribute trigger matching)
	        if (meta.findingIds && meta.findingIds.length > 0) {
	            for (const fid of meta.findingIds) {
	                if (findingDefinitions[fid]) {
	                    const score = findingBaseScores[fid] || 0;
	                    if (score > bestScore || !bestKey) {
	                        bestScore = score;
	                        bestKey = fid;
	                    }
	                }
	            }
	        }
	        // 2. Vulnerability tags (e.g., "ESC1" → "ESC1_TEMPLATE")
	        if (!bestKey && meta.vulnerabilities && meta.vulnerabilities.length > 0) {
	            for (const vulnTag of meta.vulnerabilities) {
	                const vulnLower = vulnTag.toLowerCase();
	                for (const [key, score] of Object.entries(findingBaseScores)) {
	                    if (key.toLowerCase().startsWith(vulnLower + '_') || key.toLowerCase() === vulnLower) {
	                        if (score > bestScore && findingDefinitions[key]) {
	                            bestScore = score;
	                            bestKey = key;
	                        }
	                    }
	                }
	            }
	        }
	        // 3. Fallback: title keyword matching
	        if (!bestKey) {
	            const titleLower = (meta.title || '').toLowerCase();
	            for (const [key, score] of Object.entries(findingBaseScores)) {
	                if (titleLower.includes(key.toLowerCase()) && score > bestScore && findingDefinitions[key]) {
	                    bestScore = score;
	                    bestKey = key;
	                }
	            }
	        }
	        return bestKey ? findingDefinitions[bestKey] : null;
	    }
	    function generateTopPriorityActions() {
	        const container = document.getElementById('topActionsContainer');
	        if (!container) return;
	        // ========== OPTIMIZED: Use JSON-based scoring if available ==========
	        // This avoids DOM traversal for initial score calculation
	        let scoredFindings = [];
	        let totalCriticalCount = 0;
	        if (scoringContext?.findingCards?.length > 0) {
	            // NEW: JSON-based scoring (no DOM traversal needed)
	            const criticalFindings = scoringContext.findingCards.filter(f => f.severity === 'finding');
	            totalCriticalCount = criticalFindings.length;
	            if (criticalFindings.length > 0) {
	                scoredFindings = criticalFindings.map((meta, idx) => {
	                    const breakdown = calculateScoreFromMetadata(meta);
	                    return {
	                        meta: meta,
	                        index: idx,
	                        score: breakdown.finalScore,
	                        breakdown: breakdown,
	                        title: meta.title || 'Unknown Finding',
	                        section: meta.section || meta.category || 'Unknown'
	                    };
	                }).sort((a, b) => b.score - a.score);
	            }
	        } else {
	            // FALLBACK: DOM-based scoring (legacy behavior)
	            const allCards = Array.from(document.querySelectorAll('.finding-card'));
	            const findingCards = allCards.filter(card => card.dataset.severity === 'finding');
	            totalCriticalCount = findingCards.length;
	            if (findingCards.length > 0) {
	                scoredFindings = findingCards.map((card, idx) => {
	                    const breakdown = calculateFindingScoreWithBreakdown(card);
	                    return {
	                        card: card,
	                        index: idx,
	                        score: breakdown.finalScore,
	                        breakdown: breakdown,
	                        title: card.querySelector('.finding-title')?.textContent || 'Unknown Finding',
	                        section: card.closest('.section')?.querySelector('.section-title')?.textContent || 'Unknown'
	                    };
	                }).sort((a, b) => b.score - a.score);
	            }
	        }
	        if (totalCriticalCount === 0) {
	            // No critical findings - show success message
	            container.innerHTML = `
	                <div class="top-actions" style="border-color: var(--note); background: linear-gradient(135deg, var(--note-bg) 0%, var(--bg-card) 100%);">
	                    <div class="top-actions-header">
	                        <div class="top-actions-title" style="color: var(--note);">
	                            <span class="icon">&#10003;</span>
	                            No Critical Findings
	                        </div>
	                    </div>
	                    <p style="margin: 0; color: var(--text-muted);">No high-priority security issues were detected. Review the hints and notes for potential improvements.</p>
	                </div>
	            `;
	            return;
	        }
	        // Take top 3
	        const top3 = scoredFindings.slice(0, 3);
	        // Generate HTML
	        let actionsHTML = `
	            <div class="top-actions">
	                <div class="top-actions-header">
	                    <div class="top-actions-title">
	                        <span class="icon">&#9889;</span>
	                        Top Priority Actions
	                    </div>
	                    <div style="display: flex; align-items: center; gap: 12px;">
	                        <span style="font-size: 12px; color: var(--text-muted);">${totalCriticalCount} critical findings total</span>
	                        <button class="top-actions-toggle" onclick="toggleTopActions()" title="Toggle Top Priority Actions">
	                            <span class="toggle-icon">&#9660;</span>
	                        </button>
	                    </div>
	                </div>
	                <div class="top-actions-list">
	        `;
	        top3.forEach((item, index) => {
	            // Resolve objectType and card ID from JSON metadata or DOM
	            let cardId = '';
	            let objectType = '';
	            let checkTitle = item.title;
	            if (item.meta) {
	                // JSON-based path: objectType from metadata
	                objectType = item.meta.objectType || '';
	                checkTitle = item.meta.title || item.title;
	            } else if (item.card) {
	                // DOM-based fallback
	                cardId = item.card.dataset.cardId || '';
	                const checkHelpBtn = item.card.querySelector('.check-help-btn');
	                objectType = checkHelpBtn?.dataset.objectType || '';
	                checkTitle = checkHelpBtn?.dataset.checkTitle || item.title;
	            }
	            // Look up check description for professional title and impact text
	            const checkInfo = (objectType && checkDescriptions) ? checkDescriptions[objectType] : null;
	            // Professional title: checkDescriptions.title > internal check title
	            const displayTitle = checkInfo?.title || item.title;
	            // Impact description from checkDescriptions.whyItMatters
	            const impactText = checkInfo?.whyItMatters || '';
	            // Remediation from findingDefinitions (best match by findingIds/vulnerabilities/title)
	            const findingDef = findBestFindingDefinition(item.meta || { title: item.title });
	            const remediationText = findingDef?.remediation?.[0] || '';
	            // Object count for "N affected" label
	            const objectCount = item.meta?.objectCount || 0;
	            // Build meta line: "N affected | Section"
	            let metaHtml = '';
	            if (objectCount > 0) {
	                metaHtml += `<span class="top-action-count">${objectCount} affected</span>`;
	            }
	            metaHtml += `<span class="top-action-section">${escapeHtml(item.section)}</span>`;
	            // Build buttons HTML (info button + score badge)
	            let buttonsHtml = '';
	            if (checkInfo) {
	                buttonsHtml += `<button class="top-action-info-btn" onclick="event.stopPropagation(); showTopActionInfo(this, '${escapeHtml(objectType)}', '${escapeHtml(checkTitle)}')" data-object-type="${escapeHtml(objectType)}" data-check-title="${escapeHtml(checkTitle)}" title="More Info">?</button>`;
	            }
	            const scoreClass = item.score >= scoreThresholds.critical ? 'score-critical' : item.score >= scoreThresholds.high ? 'score-high' : item.score >= scoreThresholds.medium ? 'score-medium' : item.score >= scoreThresholds.low ? 'score-low' : 'score-info';
	            const breakdownJson = escapeJsonForAttr(item.breakdown);
	            buttonsHtml += `<span class="top-action-score ${scoreClass}" data-score-breakdown='${breakdownJson}' onclick="event.stopPropagation(); showScoreTooltip(this, JSON.parse(this.dataset.scoreBreakdown));" style="cursor: pointer;">${item.score}</span>`;
	            // Build detail lines (impact + remediation)
	            let detailsHtml = '';
	            if (impactText) {
	                detailsHtml += `<div class="top-action-details">${escapeHtml(impactText)}</div>`;
	            }
	            if (remediationText) {
	                detailsHtml += `<div class="top-action-fix">&rarr; ${escapeHtml(remediationText)}</div>`;
	            }
	            actionsHTML += `
	                <div class="top-action-item" data-target-card="${cardId}" data-target-title="${escapeHtml(checkTitle)}" data-target-index="${item.index}" onclick="scrollToFindingCard(this)" style="cursor: pointer;">
	                    <div class="top-action-rank">${index + 1}</div>
	                    <div class="top-action-content">
	                        <div class="top-action-title">${escapeHtml(displayTitle)}</div>
	                        <div class="top-action-meta">${metaHtml}</div>
	                        ${detailsHtml}
	                    </div>
	                    <div class="top-action-buttons" onclick="event.stopPropagation()">${buttonsHtml}</div>
	                </div>
	            `;
	        });
	        actionsHTML += `
	                </div>
	            </div>
	        `;
	        container.innerHTML = actionsHTML;
	    }
	    function scrollToFindingCard(element) {
	        const cardId = element.dataset.targetCard;
	        const targetTitle = element.dataset.targetTitle;
	        const targetIndex = parseInt(element.dataset.targetIndex);
	        let card = cardId ? document.querySelector('.finding-card[data-card-id="' + cardId + '"]') : null;
	        // Second try: find by data-check-title
	        if (!card && targetTitle) {
	            const allCards = Array.from(document.querySelectorAll('.finding-card'));
	            card = allCards.find(c => {
	                const helpBtn = c.querySelector('.check-help-btn');
	                return helpBtn && helpBtn.dataset.checkTitle === targetTitle;
	            });
	        }
	        // Fallback: find by index among finding cards
	        if (!card && targetIndex >= 0) {
	            const findingCards = Array.from(document.querySelectorAll('.finding-card')).filter(c => c.dataset.severity === 'finding');
	            card = findingCards[targetIndex];
	        }
	        if (!card) return;
	        // Reset filters to ensure the card is visible
	        currentSeverityFilter = 'all';
	        currentCategoryFilter = 'all';
	        currentSearchQuery = '';
	        // Update filter UI
	        document.querySelectorAll('.severity-filter').forEach(f => f.classList.remove('active'));
	        document.querySelectorAll('.nav-item[data-category]').forEach(f => f.classList.remove('active'));
	        const allSeverityFilter = document.querySelector('.severity-filter[data-severity="all"]');
	        const allCategoryFilter = document.querySelector('.nav-item[data-category="all"]');
	        if (allSeverityFilter) allSeverityFilter.classList.add('active');
	        if (allCategoryFilter) allCategoryFilter.classList.add('active');
	        const searchInput = document.getElementById('searchInput');
	        if (searchInput) searchInput.value = '';
	        // Apply filters to show all cards and sections
	        applyFilters();
	        // Ensure the card is visible
	        card.style.display = '';
	        // Collapse all other cards first, then expand only the target card
	        document.querySelectorAll('.finding-card.expanded').forEach(c => c.classList.remove('expanded'));
	        card.classList.add('expanded');
	        // Highlight the category in the sidebar
	        highlightCategoryForCard(card);
	        // Remove any previous highlight
	        document.querySelectorAll('.finding-card.keyboard-focused').forEach(c => c.classList.remove('keyboard-focused'));
	        // Use setTimeout to ensure the DOM has fully updated after view switch + filter changes
	        setTimeout(() => {
	            card.scrollIntoView({ behavior: 'auto', block: 'center' });
	            card.classList.add('keyboard-focused');
	            setTimeout(() => card.classList.remove('keyboard-focused'), UI_CONSTANTS.KEYBOARD_FOCUS_DURATION);
	        }, 150);
	    }
	    function showTopActionInfo(btn, objectType, checkTitle) {
	        // Look up check description by ObjectType
	        if (!objectType || !checkDescriptions[objectType]) return;
	        const checkInfo = checkDescriptions[objectType];
	        // Build tooltip content similar to check tooltip
	        let content = '<div class="top-action-tooltip-content">';
	        content += '<div class="top-action-tooltip-header">' + escapeHtml(checkTitle) + '</div>';
	        if (checkInfo.summary) {
	            content += '<div class="top-action-tooltip-section">';
	            content += '<div class="top-action-tooltip-label">Summary</div>';
	            content += '<div class="top-action-tooltip-text">' + escapeHtml(checkInfo.summary) + '</div>';
	            content += '</div>';
	        }
	        if (checkInfo.whyItMatters) {
	            content += '<div class="top-action-tooltip-section">';
	            content += '<div class="top-action-tooltip-label">Why It Matters</div>';
	            content += '<div class="top-action-tooltip-text">' + escapeHtml(checkInfo.whyItMatters) + '</div>';
	            content += '</div>';
	        }
	        if (checkInfo.whatWeCheck && checkInfo.whatWeCheck.length > 0) {
	            content += '<div class="top-action-tooltip-section">';
	            content += '<div class="top-action-tooltip-label">What We Check</div>';
	            content += '<ul class="top-action-tooltip-list">';
	            checkInfo.whatWeCheck.forEach(item => {
	                content += '<li>' + escapeHtml(item) + '</li>';
	            });
	            content += '</ul>';
	            content += '</div>';
	        }
	        if (checkInfo.filteringNote) {
	            content += '<div class="top-action-tooltip-section top-action-tooltip-note">';
	            content += '<div class="top-action-tooltip-label">Note</div>';
	            content += '<div class="top-action-tooltip-text">' + escapeHtml(checkInfo.filteringNote) + '</div>';
	            content += '</div>';
	        }
	        content += '</div>';
	        // Show as tooltip near the button
	        showTooltipAt(btn, content);
	    }
	    // Track active floating tooltip and its event listener for cleanup
	    let activeFloatingTooltip = null;
	    let activeFloatingTooltipListener = null;
	    function showTooltipAt(element, content) {
	        // Remove any existing tooltip and clean up its event listener
	        if (activeFloatingTooltip) {
	            activeFloatingTooltip.remove();
	            if (activeFloatingTooltipListener) {
	                document.removeEventListener('click', activeFloatingTooltipListener);
	                activeFloatingTooltipListener = null;
	            }
	            activeFloatingTooltip = null;
	        }
	        // Create tooltip
	        const tooltip = document.createElement('div');
	        tooltip.className = 'remediation-floating-tooltip';
	        tooltip.innerHTML = content;
	        document.body.appendChild(tooltip);
	        activeFloatingTooltip = tooltip;
	        // Position near element with smart positioning
	        const rect = element.getBoundingClientRect();
	        const tooltipRect = tooltip.getBoundingClientRect();
	        const viewportHeight = window.innerHeight;
	        const viewportWidth = window.innerWidth;
	        // Calculate vertical position - prefer below, but go above if not enough space
	        let top;
	        if (rect.bottom + tooltipRect.height + 20 > viewportHeight) {
	            // Not enough space below - show above
	            top = rect.top + window.scrollY - tooltipRect.height - 8;
	        } else {
	            // Show below
	            top = rect.bottom + window.scrollY + 8;
	        }
	        // Calculate horizontal position
	        let left = rect.left + window.scrollX - 100;
	        if (left + tooltipRect.width > viewportWidth - UI_CONSTANTS.VIEWPORT_PADDING) {
	            left = viewportWidth - tooltipRect.width - 20;
	        }
	        if (left < UI_CONSTANTS.VIEWPORT_PADDING) {
	            left = UI_CONSTANTS.VIEWPORT_PADDING;
	        }
	        tooltip.style.top = top + 'px';
	        tooltip.style.left = left + 'px';
	        // Create named listener for proper cleanup
	        activeFloatingTooltipListener = function closeTooltip(e) {
	            if (!tooltip.contains(e.target) && e.target !== element) {
	                tooltip.remove();
	                document.removeEventListener('click', closeTooltip);
	                activeFloatingTooltip = null;
	                activeFloatingTooltipListener = null;
	            }
	        };
	        // Close on outside click (with small delay to prevent immediate close)
	        setTimeout(() => {
	            if (activeFloatingTooltip === tooltip) {
	                document.addEventListener('click', activeFloatingTooltipListener);
	            }
	        }, UI_CONSTANTS.TOOLTIP_CLOSE_DELAY);
	    }
	    // ============================================================
	    // SCORE SORT STATE
	    // ============================================================
	    // Populate score badges into finding card headers
	    function populateCardScores() {
	        const cards = document.querySelectorAll('.finding-card');
	        if (!cards.length) return;
	        cards.forEach((card, index) => {
	            const severity = card.dataset.severity || 'note';
	            // Note and Secure cards have no score
	            if (severity === 'note' || severity === 'secure') return;
	            // Calculate score from JSON metadata (preferred) or DOM fallback
	            let breakdown;
	            const cardIndex = parseInt(card.dataset.cardIndex);
	            if (!isNaN(cardIndex) && scoringContext?.findingCards?.[cardIndex]) {
	                breakdown = calculateScoreFromMetadata(scoringContext.findingCards[cardIndex]);
	            } else {
	                breakdown = calculateFindingScoreWithBreakdown(card);
	            }
	            if (breakdown.finalScore <= 0) return;
	            // Determine score class
	            const scoreClass = breakdown.finalScore >= scoreThresholds.critical ? 'score-critical' :
	                               breakdown.finalScore >= scoreThresholds.high ? 'score-high' :
	                               breakdown.finalScore >= scoreThresholds.medium ? 'score-medium' :
	                               breakdown.finalScore >= scoreThresholds.low ? 'score-low' : 'score-info';
	            // Create score badge element
	            const badge = document.createElement('span');
	            badge.className = 'score-badge ' + scoreClass;
	            badge.textContent = breakdown.finalScore;
	            badge.dataset.scoreBreakdown = JSON.stringify(breakdown);
	            badge.title = 'Risk Score (click for details)';
	            badge.addEventListener('click', function(e) {
	                e.stopPropagation();
	                showScoreTooltip(this, breakdown);
	            });
	            // Insert badge into finding-meta area (before chevron, after count)
	            const meta = card.querySelector('.finding-meta');
	            const chevron = meta?.querySelector('.finding-toggle');
	            if (meta && chevron) {
	                meta.insertBefore(badge, chevron);
	            }
	            // Store score on the card element for sorting
	            card.dataset.score = breakdown.finalScore;
	        });
	    }
	    // Severity order for sorting (lower = more critical)
	    const SEVERITY_ORDER = { 'finding': 0, 'hint': 1, 'note': 2, 'secure': 3 };
	    // Sort all finding cards by score (descending), then by severity
	    // Called once after populateCardScores() — sections are hidden, cards are flat-sorted
	    function sortCardsByScore() {
	        const container = document.getElementById('cardViewContainer');
	        if (!container) return;
	        const allCards = Array.from(container.querySelectorAll('.finding-card'));
	        if (allCards.length === 0) return;
	        const scoredCards = allCards.map(card => ({
	            element: card,
	            score: parseInt(card.dataset.score) || 0,
	            severity: SEVERITY_ORDER[card.dataset.severity] ?? 99
	        }));
	        // Sort by score descending, then by severity
	        scoredCards.sort((a, b) => {
	            if (b.score !== a.score) return b.score - a.score;
	            return a.severity - b.severity;
	        });
	        // Hide all sections (cards are shown flat)
	        container.querySelectorAll('.section').forEach(s => s.style.display = 'none');
	        // Append sorted cards directly to container
	        scoredCards.forEach(item => container.appendChild(item.element));
	    }
	    function expandAllCards() {
	        // Expand all finding cards
	        document.querySelectorAll('.finding-card').forEach(card => {
	            card.classList.add('expanded');
	        });
	        // Expand top priority actions
	        const topActions = document.querySelector('.top-actions');
	        if (topActions) {
	            topActions.classList.remove('collapsed');
	            updateTopActionsToggleIcon(topActions);
	        }
	    }
	    function collapseAllCards() {
	        // Collapse all finding cards
	        document.querySelectorAll('.finding-card').forEach(card => {
	            card.classList.remove('expanded');
	        });
	        // Collapse top priority actions
	        const topActions = document.querySelector('.top-actions');
	        if (topActions) {
	            topActions.classList.add('collapsed');
	            updateTopActionsToggleIcon(topActions);
	        }
	    }
	    function toggleTopActions() {
	        const topActions = document.querySelector('.top-actions');
	        if (topActions) {
	            topActions.classList.toggle('collapsed');
	            updateTopActionsToggleIcon(topActions);
	        }
	    }
	    function updateTopActionsToggleIcon(topActions) {
	        const toggleIcon = topActions.querySelector('.toggle-icon');
	        if (toggleIcon) {
	            toggleIcon.innerHTML = topActions.classList.contains('collapsed') ? '&#9654;' : '&#9660;';
	        }
	    }
	    // ============================================================
	    // COPY BUTTON for Remediation
	    // ============================================================
	    function copyToClipboard(button, text) {
	        navigator.clipboard.writeText(text).then(() => {
	            button.classList.add('copied');
	            const originalText = button.textContent;
	            button.textContent = 'Copied!';
	            setTimeout(() => {
	                button.classList.remove('copied');
	                button.textContent = originalText;
	            }, UI_CONSTANTS.COPY_FEEDBACK_DURATION);
	        }).catch(err => {
	            console.error('Failed to copy:', err);
	            button.textContent = 'Failed';
	            setTimeout(() => {
	                button.textContent = 'Copy';
	            }, UI_CONSTANTS.COPY_FEEDBACK_DURATION);
	        });
	    }
	    // ============================================================
	    // DRAG & DROP Attribute Reordering
	    // ============================================================
	    function initAttributeDragAndDrop() {
	        let draggedElement = null;
	        document.addEventListener('dragstart', function(e) {
	            if (e.target.classList.contains('attr-row') && e.target.draggable) {
	                draggedElement = e.target;
	                e.target.classList.add('dragging');
	                e.dataTransfer.effectAllowed = 'move';
	                e.dataTransfer.setData('text/html', e.target.innerHTML);
	            }
	        });
	        document.addEventListener('dragend', function(e) {
	            if (e.target.classList.contains('attr-row')) {
	                e.target.classList.remove('dragging');
	                // Remove all drag-over indicators
	                document.querySelectorAll('.attr-row.drag-over').forEach(el => {
	                    el.classList.remove('drag-over');
	                });
	                draggedElement = null;
	            }
	        });
	        document.addEventListener('dragover', function(e) {
	            if (!draggedElement) return;
	            const target = e.target.closest('.attr-row');
	            if (!target || target === draggedElement) return;
	            e.preventDefault();
	            e.dataTransfer.dropEffect = 'move';
	            // Remove previous drag-over indicators
	            document.querySelectorAll('.attr-row.drag-over').forEach(el => {
	                if (el !== target) el.classList.remove('drag-over');
	            });
	            // Add drag-over indicator to current target
	            target.classList.add('drag-over');
	        });
	        document.addEventListener('drop', function(e) {
	            if (!draggedElement) return;
	            const target = e.target.closest('.attr-row');
	            if (!target || target === draggedElement) return;
	            e.preventDefault();
	            e.stopPropagation();
	            // Get target parent container
	            const targetParent = target.parentNode;
	            // Determine insertion position based on mouse Y position
	            const targetRect = target.getBoundingClientRect();
	            const midPoint = targetRect.top + (targetRect.height / 2);
	            if (e.clientY < midPoint) {
	                // Insert before target
	                targetParent.insertBefore(draggedElement, target);
	            } else {
	                // Insert after target
	                if (target.nextSibling) {
	                    targetParent.insertBefore(draggedElement, target.nextSibling);
	                } else {
	                    targetParent.appendChild(draggedElement);
	                }
	            }
	            // Remove drag-over indicator
	            target.classList.remove('drag-over');
	            // Update extended attributes counter after cross-container moves
	            updateExtendedAttrCounters(draggedElement);
	        });
	    }
	    // Update the "Show/Hide N more attribute(s)" counter after drag & drop
	    function updateExtendedAttrCounters(movedElement) {
	        // Find the closest object-body container
	        const objectBody = movedElement.closest('.object-body');
	        if (!objectBody) return;
	        const extSection = objectBody.querySelector('.extended-attrs');
	        const toggleBtn = objectBody.querySelector('.extended-attrs-toggle');
	        if (!extSection || !toggleBtn) return;
	        // Count remaining attr-rows in extended section
	        const extCount = extSection.querySelectorAll(':scope > .attr-row').length;
	        const textSpan = toggleBtn.querySelector('span:last-child');
	        if (!textSpan) return;
	        if (extCount === 0) {
	            // No more extended attributes — hide toggle and section
	            toggleBtn.style.display = 'none';
	            extSection.style.display = 'none';
	        } else {
	            toggleBtn.style.display = '';
	            // Update counter text, preserve Show/Hide prefix
	            const currentText = textSpan.textContent;
	            const prefix = currentText.startsWith('Hide') ? 'Hide' : 'Show';
	            textSpan.textContent = prefix + ' ' + extCount + ' more attribute(s)';
	        }
	    }
	    // ============================================================
	    //  PRINT / PDF PREPARATION
	    //  Ensures all content is expanded and a Table of Contents
	    //  is generated before the browser renders the print layout.
	    // ============================================================
	    // State snapshot to restore after printing
	    var printStateSnapshot = null;
	    function preparePrint() {
	        // Save current state so we can restore after printing
	        printStateSnapshot = {
	            expandedCards: [],
	            collapsedTopActions: false,
	            hiddenCompletedState: false
	        };
	        // Remember which cards were NOT expanded (so we can collapse them back)
	        document.querySelectorAll('.finding-card:not(.expanded)').forEach(function(card) {
	            printStateSnapshot.expandedCards.push(card);
	        });
	        // Remember top-actions state
	        var topActions = document.querySelector('.top-actions');
	        if (topActions && topActions.classList.contains('collapsed')) {
	            printStateSnapshot.collapsedTopActions = true;
	        }
	        // Remember hide-completed state
	        var hideToggle = document.getElementById('hideCompletedToggle');
	        if (hideToggle && hideToggle.checked) {
	            printStateSnapshot.hiddenCompletedState = true;
	            hideToggle.checked = false;
	            toggleHideCompleted();
	        }
	        // Expand ALL finding cards for print
	        document.querySelectorAll('.finding-card').forEach(function(card) {
	            card.classList.add('expanded');
	        });
	        // Expand top-actions
	        if (topActions) {
	            topActions.classList.remove('collapsed');
	            updateTopActionsToggleIcon(topActions);
	        }
	        // Build Table of Contents from section headers
	        buildPrintTOC();
	    }
	    function restoreAfterPrint() {
	        if (!printStateSnapshot) return;
	        // Collapse cards that were not expanded before print
	        printStateSnapshot.expandedCards.forEach(function(card) {
	            card.classList.remove('expanded');
	        });
	        // Restore top-actions collapsed state
	        if (printStateSnapshot.collapsedTopActions) {
	            var topActions = document.querySelector('.top-actions');
	            if (topActions) {
	                topActions.classList.add('collapsed');
	                updateTopActionsToggleIcon(topActions);
	            }
	        }
	        // Restore hide-completed state
	        if (printStateSnapshot.hiddenCompletedState) {
	            var hideToggle = document.getElementById('hideCompletedToggle');
	            if (hideToggle) {
	                hideToggle.checked = true;
	                toggleHideCompleted();
	            }
	        }
	        // Remove TOC
	        var toc = document.getElementById('printTOC');
	        if (toc) toc.remove();
	        printStateSnapshot = null;
	    }
	    function buildPrintTOC() {
	        // Remove existing TOC if any
	        var existing = document.getElementById('printTOC');
	        if (existing) existing.remove();
	        var sections = document.querySelectorAll('.section');
	        if (sections.length === 0) return;
	        var toc = document.createElement('div');
	        toc.id = 'printTOC';
	        toc.className = 'print-toc';
	        var tocTitle = document.createElement('div');
	        tocTitle.className = 'print-toc-title';
	        tocTitle.textContent = 'Table of Contents';
	        toc.appendChild(tocTitle);
	        // Build severity matrix table
	        var table = document.createElement('table');
	        table.className = 'print-toc-table';
	        // Table header
	        var thead = document.createElement('thead');
	        var headerRow = document.createElement('tr');
	        ['Section', 'Findings', 'Hints', 'Notes', 'Secure'].forEach(function(label) {
	            var th = document.createElement('th');
	            th.textContent = label;
	            headerRow.appendChild(th);
	        });
	        thead.appendChild(headerRow);
	        table.appendChild(thead);
	        // Pre-build severity counts per section using data-category attribute
	        // Note: Cards may be sorted flat outside their sections (sortCardsByScore),
	        // so we use the card's data-category to map back to section IDs (cat-<category>)
	        var sectionCounts = {};
	        document.querySelectorAll('.finding-card[data-severity][data-category]').forEach(function(card) {
	            var sid = 'cat-' + card.getAttribute('data-category');
	            if (!sectionCounts[sid]) sectionCounts[sid] = { finding: 0, hint: 0, note: 0, secure: 0 };
	            var sev = card.getAttribute('data-severity');
	            if (sectionCounts[sid][sev] !== undefined) sectionCounts[sid][sev]++;
	        });
	        // Table body
	        var tbody = document.createElement('tbody');
	        var totals = { finding: 0, hint: 0, note: 0, secure: 0 };
	        sections.forEach(function(section, index) {
	            var titleEl = section.querySelector('.section-title');
	            if (!titleEl) return;
	            var sectionTitle = titleEl.textContent.trim();
	            // Strip [N/M] prefix for cleaner display
	            sectionTitle = sectionTitle.replace(/^\[\d+\/\d+\]\s*/, '');
	            var sectionId = section.id;
	            // Get pre-computed counts for this section
	            var counts = sectionCounts[sectionId] || { finding: 0, hint: 0, note: 0, secure: 0 };
	            // Accumulate totals
	            totals.finding += counts.finding;
	            totals.hint += counts.hint;
	            totals.note += counts.note;
	            totals.secure += counts.secure;
	            // Determine highest severity for left border color
	            var severity = counts.finding > 0 ? 'finding' : counts.hint > 0 ? 'hint' : counts.secure > 0 ? 'secure' : 'note';
	            var row = document.createElement('tr');
	            row.className = 'toc-severity-' + severity;
	            // Section name cell with link
	            var nameCell = document.createElement('td');
	            nameCell.className = 'toc-section-name';
	            var link = document.createElement('a');
	            link.href = '#' + sectionId;
	            link.textContent = (index + 1) + '. ' + sectionTitle;
	            nameCell.appendChild(link);
	            row.appendChild(nameCell);
	            // Severity count cells
	            [
	                { key: 'finding', cls: 'toc-cell-finding' },
	                { key: 'hint', cls: 'toc-cell-hint' },
	                { key: 'note', cls: 'toc-cell-note' },
	                { key: 'secure', cls: 'toc-cell-secure' }
	            ].forEach(function(col) {
	                var td = document.createElement('td');
	                td.className = col.cls;
	                if (counts[col.key] > 0) {
	                    td.textContent = counts[col.key];
	                    td.classList.add('has-value');
	                } else {
	                    td.textContent = '\u2013'; // en-dash
	                    td.classList.add('no-value');
	                }
	                row.appendChild(td);
	            });
	            tbody.appendChild(row);
	        });
	        table.appendChild(tbody);
	        // Table footer with totals
	        var tfoot = document.createElement('tfoot');
	        var footerRow = document.createElement('tr');
	        var totalLabel = document.createElement('td');
	        totalLabel.className = 'toc-section-name toc-total-label';
	        totalLabel.textContent = 'Total';
	        footerRow.appendChild(totalLabel);
	        [
	            { key: 'finding', cls: 'toc-cell-finding' },
	            { key: 'hint', cls: 'toc-cell-hint' },
	            { key: 'note', cls: 'toc-cell-note' },
	            { key: 'secure', cls: 'toc-cell-secure' }
	        ].forEach(function(col) {
	            var td = document.createElement('td');
	            td.className = col.cls;
	            if (totals[col.key] > 0) {
	                td.textContent = totals[col.key];
	                td.classList.add('has-value');
	            } else {
	                td.textContent = '\u2013';
	                td.classList.add('no-value');
	            }
	            footerRow.appendChild(td);
	        });
	        tfoot.appendChild(footerRow);
	        table.appendChild(tfoot);
	        toc.appendChild(table);
	        // Insert TOC after info-bar, before card controls
	        var infoBar = document.querySelector('.info-bar');
	        if (infoBar && infoBar.parentNode) {
	            infoBar.parentNode.insertBefore(toc, infoBar.nextSibling);
	        }
	    }
	    // Register print event handlers
	    window.addEventListener('beforeprint', preparePrint);
	    window.addEventListener('afterprint', restoreAfterPrint);
	</script>
</body>
</html>
'@
}
function Convert-adPEASReport {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$InputJson,
	    [Parameter(Mandatory=$true)]
	    [string]$OutputPath,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('Text', 'HTML', 'JSON', 'All')]
	    [string]$Format = 'All',
	    [Parameter(Mandatory=$false)]
	    [string]$License,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoColor
	)
	begin {
	}
	process {
	    if (-not (Test-Path $InputJson)) {
	        Write-Error "[Convert-adPEASReport] Input file not found: $InputJson"
	        return
	    }
	    $previousLDAPContext = $Script:LDAPContext
	    $previousOutputfile = $Script:adPEAS_Outputfile
	    $previousOutputColor = $Script:adPEAS_OutputColor
	    $previousFindingsEnabled = $Script:adPEAS_FindingsCollectionEnabled
	    $previousDisclaimer = $Script:adPEASDisclaimer
	    try {
	        $rawJson = Get-Content -Path $InputJson -Raw -Encoding UTF8
	        $cache = $rawJson | ConvertFrom-Json
	        if (-not $cache.CacheVersion) {
	            Write-Error "[Convert-adPEASReport] Invalid JSON file - missing CacheVersion field"
	            return
	        }
	        if ($cache.CacheVersion -ne 1) {
	            Write-Error "[Convert-adPEASReport] Unsupported cache version $($cache.CacheVersion) - expected 1"
	            return
	        }
	        $sourceDomain = if ($cache.Domain -and $cache.Domain -ne 'Unknown') { $cache.Domain } else { 'Unknown' }
	        $sourceServer = if ($cache.Server) { $cache.Server } else { 'Unknown' }
	        $sourceVersion = if ($cache.adPEASVersion) { $cache.adPEASVersion } else { 'Unknown' }
	        $sourceDate = if ($cache.ExportDate) { $cache.ExportDate } else { 'Unknown' }
	        $findingCount = if ($cache.FindingCount) { $cache.FindingCount } else { 0 }
	        Show-Line "Source: $InputJson" -Class Note -NoCollect
	        Show-Line "Domain: $sourceDomain, Server: $sourceServer" -Class Note -NoCollect
	        Show-Line "Original scan: $sourceDate (adPEAS $sourceVersion)" -Class Note -NoCollect
	        Show-Line "Findings: $findingCount" -Class Note -NoCollect
	        $currentVersion = if ($Script:adPEASVersion) { $Script:adPEASVersion } else { '2.0.0' }
	        if ($sourceVersion -ne $currentVersion -and $sourceVersion -ne 'Unknown') {
	            Show-Line "Regenerating with adPEAS $currentVersion (updated definitions/scoring)" -Class Hint -NoCollect
	        }
	        $findings = Import-FindingsFromCache -Cache $cache
	        if (@($findings).Count -eq 0) {
	            Write-Warning "[Convert-adPEASReport] No findings loaded from JSON file"
	            return
	        }
	        $Script:LDAPContext = @{
	            Domain   = $sourceDomain
	            Server   = $sourceServer
	            DomainDN = $null
	            Username = 'Offline'
	        }
	        $_licJson = $null
	        if ($License) {
	            if (Test-Path $License) {
	                $_licJson = Get-Content -Path $License -Raw -Encoding UTF8
	            } else {
	                Write-Warning "[Convert-adPEASReport] License file not found: $License"
	            }
	        } elseif ($Script:RuntimeLicense) {
	            $_licJson = $Script:RuntimeLicense
	        } elseif ($Script:EmbeddedLicense) {
	            $_licJson = [System.Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($Script:EmbeddedLicense))
	        }
	        $_licResult = if ($_licJson) { Test-adPEASLicense -LicenseJson $_licJson } else { $null }
	        if ($_licResult -and $_licResult.IsValid -and -not $_licResult.Expired) {
	            $Script:adPEASDisclaimer = $_licResult.Message
	        } else {
	            $_lm="GCQlP2w+KTwjPjhsOy0/bCspIik+LTgpKGw5PyUiK2wtbDgjIyBsOCQtOGw+KT05JT4pP2wtbDotICUobC8jISEpPi8lLSBsICUvKSI/KWwqIz5sLyMiPzkgOCUiK2wjPmwhLSItKykobD8pPjolLylsOT8pYg==";$_lk=0x4C
	            $Script:adPEASDisclaimer=(-join([Convert]::FromBase64String($_lm)|ForEach-Object{[char]($_-bxor$_lk)}))
	        }
	        $resolvedBase = $ExecutionContext.SessionState.Path.GetUnresolvedProviderPathFromPSPath($OutputPath)
	        if ([System.IO.Path]::HasExtension($resolvedBase)) {
	            $resolvedBase = [System.IO.Path]::ChangeExtension($resolvedBase, $null).TrimEnd('.')
	        }
	        $resolvedInput = $ExecutionContext.SessionState.Path.GetUnresolvedProviderPathFromPSPath($InputJson)
	        $outputJsonPath = "$resolvedBase.json"
	        if ($Format -in @('All', 'JSON') -and $resolvedInput -eq $outputJsonPath) {
	            Write-Warning "[Convert-adPEASReport] Output path '$outputJsonPath' is the same as input file. JSON will be re-exported in place."
	        }
	        $outputDir = Split-Path -Parent $resolvedBase
	        if ($outputDir -and -not (Test-Path $outputDir)) {
	            New-Item -ItemType Directory -Path $outputDir -Force | Out-Null
	        }
	        if ($Format -in @('HTML', 'All')) {
	            Initialize-FindingsCollection
	            Set-FindingsCollection -Findings $findings
	            $htmlPath = "$resolvedBase.html"
	            try {
	                Export-HTMLReport -OutputPath $htmlPath
	                Show-Line "HTML report saved to: $htmlPath" -Class Hint -NoCollect
	            } catch {
	                Write-Warning "[Convert-adPEASReport] Error generating HTML report: $_"
	            }
	            Clear-FindingsCollection
	        }
	        if ($Format -in @('All', 'JSON')) {
	            Initialize-FindingsCollection
	            Set-FindingsCollection -Findings $findings
	            $jsonPath = "$resolvedBase.json"
	            try {
	                Export-FindingsCache -Path $jsonPath
	                Show-Line "JSON export saved to: $jsonPath" -Class Hint -NoCollect
	            } catch {
	                Write-Warning "[Convert-adPEASReport] Error saving JSON: $_"
	            }
	            Clear-FindingsCollection
	        }
	        if ($Format -in @('Text', 'All')) {
	            $textPath = "$resolvedBase.txt"
	            $Script:adPEAS_Outputfile = $textPath
	            $Script:adPEAS_OutputColor = if ($NoColor) { $false } else { $null }
	            $utf8Encoding = [System.Text.Encoding]::UTF8
	            [System.IO.File]::WriteAllText($textPath, "", $utf8Encoding)
	            Invoke-FindingsReplay -Findings $findings
	            $Script:adPEAS_Outputfile = $null
	            Show-Line "Text report saved to: $textPath" -Class Hint -NoCollect
	        }
	        if ($Format -eq 'All' -and $htmlPath) {
	            Show-Line "HTML report saved to: $htmlPath" -Class Hint -NoCollect
	        }
	    } finally {
	        $Script:LDAPContext = $previousLDAPContext
	        $Script:adPEAS_Outputfile = $previousOutputfile
	        $Script:adPEAS_OutputColor = $previousOutputColor
	        $Script:adPEAS_FindingsCollectionEnabled = $previousFindingsEnabled
	        $Script:adPEASDisclaimer = $previousDisclaimer
	        Clear-FindingsCollection
	    }
	}
	end {
	}
}
function Invoke-FindingsReplay {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [array]$Findings
	)
	foreach ($finding in $Findings) {
	    switch ($finding.Type) {
	        'Header' {
	            Show-Output -Class Info -Value $finding.Text -NoCollect
	        }
	        'SubHeader' {
	            Show-SubHeader $finding.Text -ObjectType $finding.ObjectType -NoCollect
	        }
	        'Object' {
	            if ($finding.Object) {
	                Show-Object $finding.Object -Class $finding.Class -NoCollect
	            }
	        }
	        'KeyValue' {
	            $kvParams = @{
	                Key       = $finding.Key
	                Value     = $finding.Value
	                Class     = $finding.Class
	                NoCollect = $true
	            }
	            if ($finding.FindingId) { $kvParams['FindingId'] = $finding.FindingId }
	            Show-Output @kvParams
	        }
	        'Line' {
	            $lineParams = @{
	                Text      = $finding.Text
	                Class     = $finding.Class
	                NoCollect = $true
	            }
	            if ($finding.FindingId) { $lineParams['FindingId'] = $finding.FindingId }
	            Show-Line @lineParams
	        }
	    }
	}
}
function Compare-adPEASReport {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$Baseline,
	    [Parameter(Mandatory=$true)]
	    [string]$Current,
	    [Parameter(Mandatory=$false)]
	    [string]$OutputPath,
	    [Parameter(Mandatory=$false)]
	    [switch]$NoColor
	)
	begin {
	}
	process {
	    if (-not (Test-Path $Baseline)) {
	        Write-Error "[Compare-adPEASReport] Baseline file not found: $Baseline"
	        return
	    }
	    if (-not (Test-Path $Current)) {
	        Write-Error "[Compare-adPEASReport] Current file not found: $Current"
	        return
	    }
	    $previousOutputfile = $Script:adPEAS_Outputfile
	    $previousOutputColor = $Script:adPEAS_OutputColor
	    try {
	        if ($OutputPath) {
	            $resolvedBase = $ExecutionContext.SessionState.Path.GetUnresolvedProviderPathFromPSPath($OutputPath)
	            if ([System.IO.Path]::HasExtension($resolvedBase)) {
	                $resolvedBase = [System.IO.Path]::ChangeExtension($resolvedBase, $null).TrimEnd('.')
	            }
	            $outputDir = Split-Path -Parent $resolvedBase
	            if ($outputDir -and -not (Test-Path $outputDir)) {
	                New-Item -ItemType Directory -Path $outputDir -Force | Out-Null
	            }
	            $textPath = "$resolvedBase.txt"
	            $Script:adPEAS_Outputfile = $textPath
	            [System.IO.File]::WriteAllText($textPath, "", [System.Text.Encoding]::UTF8)
	        }
	        $Script:adPEAS_OutputColor = if ($NoColor) { $false } else { $null }
	        $baselineCache = (Get-Content -Path $Baseline -Raw -Encoding UTF8) | ConvertFrom-Json
	        $currentCache = (Get-Content -Path $Current -Raw -Encoding UTF8) | ConvertFrom-Json
	        foreach ($entry in @(@{Name='Baseline'; Cache=$baselineCache; Path=$Baseline}, @{Name='Current'; Cache=$currentCache; Path=$Current})) {
	            if (-not $entry.Cache.CacheVersion) {
	                Write-Error "[Compare-adPEASReport] Invalid JSON file ($($entry.Name)): $($entry.Path)"
	                return
	            }
	            if ($entry.Cache.CacheVersion -ne 1) {
	                Write-Error "[Compare-adPEASReport] Unsupported cache version $($entry.Cache.CacheVersion) in $($entry.Name): $($entry.Path)"
	                return
	            }
	        }
	        $baselineMeta = @{
	            Domain  = if ($baselineCache.Domain) { $baselineCache.Domain } else { 'Unknown' }
	            Date    = if ($baselineCache.ExportDate) { try { ([datetime]::Parse($baselineCache.ExportDate)).ToString('yyyy-MM-dd HH:mm') } catch { $baselineCache.ExportDate } } else { 'Unknown' }
	            Version = if ($baselineCache.adPEASVersion) { $baselineCache.adPEASVersion } else { 'Unknown' }
	            Count   = if ($baselineCache.FindingCount) { $baselineCache.FindingCount } else { 0 }
	        }
	        $currentMeta = @{
	            Domain  = if ($currentCache.Domain) { $currentCache.Domain } else { 'Unknown' }
	            Date    = if ($currentCache.ExportDate) { try { ([datetime]::Parse($currentCache.ExportDate)).ToString('yyyy-MM-dd HH:mm') } catch { $currentCache.ExportDate } } else { 'Unknown' }
	            Version = if ($currentCache.adPEASVersion) { $currentCache.adPEASVersion } else { 'Unknown' }
	            Count   = if ($currentCache.FindingCount) { $currentCache.FindingCount } else { 0 }
	        }
	        if ($baselineMeta.Domain -ne 'Unknown' -and $currentMeta.Domain -ne 'Unknown' -and
	            $baselineMeta.Domain -ne $currentMeta.Domain) {
	            Write-Warning "[Compare-adPEASReport] Domain mismatch: Baseline='$($baselineMeta.Domain)' vs Current='$($currentMeta.Domain)'"
	            Write-Warning "[Compare-adPEASReport] Comparison results may not be meaningful across different domains"
	        }
	        $baselineFindings = Import-FindingsFromCache -Cache $baselineCache
	        $currentFindings = Import-FindingsFromCache -Cache $currentCache
	        $baselineComparable = @($baselineFindings | Where-Object {
	            $_.Type -notin @('Header', 'SubHeader') -and $_.Category -ne 'Unknown'
	        })
	        $currentComparable = @($currentFindings | Where-Object {
	            $_.Type -notin @('Header', 'SubHeader') -and $_.Category -ne 'Unknown'
	        })
	        $baselineMap = @{}
	        foreach ($f in $baselineComparable) {
	            $id = Get-FindingIdentity -Finding $f
	            if ($id) { $baselineMap[$id] = $f }
	        }
	        $currentMap = @{}
	        foreach ($f in $currentComparable) {
	            $id = Get-FindingIdentity -Finding $f
	            if ($id) { $currentMap[$id] = $f }
	        }
	        $added = [System.Collections.ArrayList]::new()
	        $removed = [System.Collections.ArrayList]::new()
	        $changed = [System.Collections.ArrayList]::new()
	        $unchangedCount = 0
	        foreach ($id in $currentMap.Keys) {
	            if (-not $baselineMap.ContainsKey($id)) {
	                [void]$added.Add($currentMap[$id])
	            } else {
	                $bf = $baselineMap[$id]
	                $cf = $currentMap[$id]
	                $severityChanged = $bf.Severity -ne $cf.Severity
	                $valueChanged = $cf.Type -eq 'KeyValue' -and $bf.Value -ne $cf.Value
	                $textChanged = $cf.Type -eq 'Line' -and $bf.Text -ne $cf.Text
	                if ($severityChanged -or $valueChanged -or $textChanged) {
	                    [void]$changed.Add(@{ Baseline = $bf; Current = $cf; Identity = $id })
	                } else {
	                    $unchangedCount++
	                }
	            }
	        }
	        foreach ($id in $baselineMap.Keys) {
	            if (-not $currentMap.ContainsKey($id)) {
	                [void]$removed.Add($baselineMap[$id])
	            }
	        }
	        $baselineCategories = @($baselineComparable | ForEach-Object { $_.Category } | Select-Object -Unique | Sort-Object)
	        $currentCategories = @($currentComparable | ForEach-Object { $_.Category } | Select-Object -Unique | Sort-Object)
	        $onlyInBaseline = @($baselineCategories | Where-Object { $_ -notin $currentCategories })
	        $onlyInCurrent = @($currentCategories | Where-Object { $_ -notin $baselineCategories })
	        $sharedCategories = @($baselineCategories | Where-Object { $_ -in $currentCategories })
	        $scopeOnlyBaseline = @()
	        $scopeOnlyCurrent = @()
	        if ($onlyInBaseline.Count -gt 0) {
	            $scopeOnlyBaseline = @($removed | Where-Object { $_.Category -in $onlyInBaseline })
	            $removed = [System.Collections.ArrayList]@($removed | Where-Object { $_.Category -notin $onlyInBaseline })
	        }
	        if ($onlyInCurrent.Count -gt 0) {
	            $scopeOnlyCurrent = @($added | Where-Object { $_.Category -in $onlyInCurrent })
	            $added = [System.Collections.ArrayList]@($added | Where-Object { $_.Category -notin $onlyInCurrent })
	        }
	        Show-Output -Class Info -Value "adPEAS Report Comparison" -NoCollect
	        Show-Line "Baseline: $(Split-Path -Leaf $Baseline) ($($baselineMeta.Date), $($baselineMeta.Domain), adPEAS $($baselineMeta.Version))" -Class Note -NoCollect
	        Show-Line "Current:  $(Split-Path -Leaf $Current) ($($currentMeta.Date), $($currentMeta.Domain), adPEAS $($currentMeta.Version))" -Class Note -NoCollect
	        Show-Output -Class Info -Value "Comparison Summary" -NoCollect
	        Show-Output -Key "New findings (added)" -Value "$($added.Count)" -Class $(if ($added.Count -gt 0) { 'Finding' } else { 'Note' }) -NoCollect
	        Show-Output -Key "Remediated findings (removed)" -Value "$($removed.Count)" -Class $(if ($removed.Count -gt 0) { 'Secure' } else { 'Note' }) -NoCollect
	        Show-Output -Key "Changed findings" -Value "$($changed.Count)" -Class $(if ($changed.Count -gt 0) { 'Hint' } else { 'Note' }) -NoCollect
	        Show-Output -Key "Unchanged findings" -Value "$unchangedCount" -Class Note -NoCollect
	        Show-Output -Key "Compared categories" -Value "$($sharedCategories.Count) ($($sharedCategories -join ', '))" -Class Note -NoCollect
	        if ($added.Count -gt 0) {
	            Show-Output -Class Info -Value "New Findings ($($added.Count))" -NoCollect
	            $addedGroups = $added | Group-Object -Property { "$($_.Category) > $($_.CheckTitle)" }
	            foreach ($group in ($addedGroups | Sort-Object Name)) {
	                Show-SubHeader $group.Name -NoCollect
	                foreach ($f in $group.Group) {
	                    $displayName = Get-FindingDisplayName -Finding $f
	                    Show-Line "$displayName ($($f.Severity))" -Class Finding -NoCollect
	                }
	            }
	        }
	        if ($removed.Count -gt 0) {
	            Show-Output -Class Info -Value "Remediated Findings ($($removed.Count))" -NoCollect
	            $removedGroups = $removed | Group-Object -Property { "$($_.Category) > $($_.CheckTitle)" }
	            foreach ($group in ($removedGroups | Sort-Object Name)) {
	                Show-SubHeader $group.Name -NoCollect
	                foreach ($f in $group.Group) {
	                    $displayName = Get-FindingDisplayName -Finding $f
	                    Show-Line "$displayName (was: $($f.Severity))" -Class Secure -NoCollect
	                }
	            }
	        }
	        if ($changed.Count -gt 0) {
	            Show-Output -Class Info -Value "Changed Findings ($($changed.Count))" -NoCollect
	            $changedGroups = $changed | Group-Object -Property { "$($_.Current.Category) > $($_.Current.CheckTitle)" }
	            foreach ($group in ($changedGroups | Sort-Object Name)) {
	                Show-SubHeader $group.Name -NoCollect
	                foreach ($entry in $group.Group) {
	                    $displayName = Get-FindingDisplayName -Finding $entry.Current
	                    $changeDesc = @()
	                    if ($entry.Baseline.Severity -ne $entry.Current.Severity) {
	                        $changeDesc += "severity: $($entry.Baseline.Severity) -> $($entry.Current.Severity)"
	                    }
	                    if ($entry.Current.Type -eq 'KeyValue' -and $entry.Baseline.Value -ne $entry.Current.Value) {
	                        $changeDesc += "value: $($entry.Baseline.Value) -> $($entry.Current.Value)"
	                    }
	                    if ($entry.Current.Type -eq 'Line' -and $entry.Baseline.Text -ne $entry.Current.Text) {
	                        $changeDesc += "text changed"
	                    }
	                    $changeText = $changeDesc -join ', '
	                    Show-Line "$displayName ($changeText)" -Class Hint -NoCollect
	                }
	            }
	        }
	        if ($onlyInBaseline.Count -gt 0 -or $onlyInCurrent.Count -gt 0) {
	            Show-Output -Class Info -Value "Scan Scope Differences" -NoCollect
	            Show-Line "The following categories were not scanned in both reports and are excluded from the comparison above." -Class Note -NoCollect
	            if ($onlyInCurrent.Count -gt 0) {
	                Show-Line "Only in current scan: $($onlyInCurrent -join ', ') ($($scopeOnlyCurrent.Count) finding(s) not compared)" -Class Hint -NoCollect
	            }
	            if ($onlyInBaseline.Count -gt 0) {
	                Show-Line "Only in baseline scan: $($onlyInBaseline -join ', ') ($($scopeOnlyBaseline.Count) finding(s) not compared)" -Class Hint -NoCollect
	            }
	        }
	        if ($OutputPath) {
	            $htmlPath = "$resolvedBase.html"
	            try {
	                Export-DiffHtmlReport -OutputPath $htmlPath `
	                    -BaselineMeta $baselineMeta -CurrentMeta $currentMeta `
	                    -BaselineFile (Split-Path -Leaf $Baseline) -CurrentFile (Split-Path -Leaf $Current) `
	                    -Added $added -Removed $removed -Changed $changed `
	                    -UnchangedCount $unchangedCount `
	                    -SharedCategories $sharedCategories `
	                    -OnlyInBaseline $onlyInBaseline -OnlyInCurrent $onlyInCurrent `
	                    -ScopeOnlyBaseline $scopeOnlyBaseline -ScopeOnlyCurrent $scopeOnlyCurrent
	                Show-Line "HTML diff report saved to: $htmlPath" -Class Hint -NoCollect
	            } catch {
	                Write-Warning "[Compare-adPEASReport] Error generating HTML diff report: $_"
	            }
	        }
	        if ($OutputPath) {
	            Show-Line "Text diff report saved to: $textPath" -Class Hint -NoCollect
	        }
	    } finally {
	        $Script:adPEAS_Outputfile = $previousOutputfile
	        $Script:adPEAS_OutputColor = $previousOutputColor
	    }
	}
	end {
	}
}
function Get-FindingIdentity {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    $Finding
	)
	$prefix = "$($Finding.Category)|$($Finding.CheckName)"
	switch ($Finding.Type) {
	    'Object' {
	        $op = $Finding.Object
	        if (-not $op) { $op = $Finding.ObjectProperties }
	        $oid = $null
	        if ($op) {
	            if ($op.distinguishedName) { $oid = $op.distinguishedName }
	            elseif ($op.sAMAccountName) { $oid = $op.sAMAccountName }
	            elseif ($op.Name) { $oid = $op.Name }
	            elseif ($op.cn) { $oid = $op.cn }
	            elseif ($op.displayName) { $oid = $op.displayName }
	            elseif ($op.PrincipalName -and $op.TargetObject) { $oid = "$($op.PrincipalName)->$($op.TargetObject)" }
	            elseif ($op.PrincipalName) { $oid = $op.PrincipalName }
	            elseif ($op.userName -and $op.filePath) { $oid = "$($op.userName)|$($op.filePath)" }
	            elseif ($op.filePath) { $oid = $op.filePath }
	            elseif ($op.credentialType) { $oid = $op.credentialType }
	            elseif ($op._adPEASObjectType) { $oid = $op._adPEASObjectType }
	            else {
	                foreach ($p in $op.PSObject.Properties) {
	                    if ($p.Name -notin @('_adPEASObjectType', '_adPEASContext', '_Severity', '_Risk') -and $p.Value) {
	                        $oid = "$($p.Name)=$($p.Value)"; break
	                    }
	                }
	            }
	        }
	        if (-not $oid) { $oid = 'unknown' }
	        return "$prefix|Object|$oid"
	    }
	    'KeyValue' {
	        return "$prefix|KV|$($Finding.Key)"
	    }
	    'Line' {
	        $normalizedText = $Finding.Text -replace '\d+', '#'
	        return "$prefix|Line|$normalizedText"
	    }
	    default {
	        return $null
	    }
	}
}
function Get-FindingDisplayName {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    $Finding
	)
	switch ($Finding.Type) {
	    'Object' {
	        $op = $Finding.Object
	        if (-not $op) { return '[Object]' }
	        if ($op.sAMAccountName) { return $op.sAMAccountName }
	        if ($op.Name) { return $op.Name }
	        if ($op.cn) { return $op.cn }
	        if ($op.displayName) { return $op.displayName }
	        if ($op.distinguishedName) {
	            if ($op.distinguishedName -match '^CN=([^,]+)') { return $Matches[1] }
	            return $op.distinguishedName
	        }
	        if ($op.PrincipalName) { return "$($op.PrincipalName) -> $($op.TargetObject)" }
	        if ($op._adPEASObjectType) { return $op._adPEASObjectType }
	        foreach ($p in $op.PSObject.Properties) {
	            if ($p.Name -notin @('_adPEASObjectType', '_adPEASContext', '_Severity', '_Risk') -and $p.Value) {
	                $val = [string]$p.Value
	                if ($val.Length -gt 60) { $val = $val.Substring(0, 57) + '...' }
	                return $val
	            }
	        }
	        return '[Object]'
	    }
	    'KeyValue' {
	        if ($Finding.Value) {
	            return "$($Finding.Key): $($Finding.Value)"
	        }
	        return $Finding.Key
	    }
	    'Line' {
	        return $Finding.Text
	    }
	    default {
	        return $Finding.Text
	    }
	}
}
function Export-DiffHtmlReport {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$true)]
	    [string]$OutputPath,
	    [hashtable]$BaselineMeta,
	    [hashtable]$CurrentMeta,
	    [string]$BaselineFile,
	    [string]$CurrentFile,
	    $Added,
	    $Removed,
	    $Changed,
	    [int]$UnchangedCount,
	    [string[]]$SharedCategories,
	    [string[]]$OnlyInBaseline,
	    [string[]]$OnlyInCurrent,
	    $ScopeOnlyBaseline,
	    $ScopeOnlyCurrent
	)
	$html = Get-DiffHTMLTemplate
	if (-not $html) {
	    Write-Warning "[Export-DiffHtmlReport] Failed to load diff HTML template"
	    return
	}
	$sectionsHtml = [System.Text.StringBuilder]::new()
	if ($Added.Count -gt 0) {
	    [void]$sectionsHtml.Append((Build-DiffSectionHtml -Title "New Findings" -Findings $Added -SectionType 'new'))
	}
	if ($Removed.Count -gt 0) {
	    [void]$sectionsHtml.Append((Build-DiffSectionHtml -Title "Remediated Findings" -Findings $Removed -SectionType 'remediated'))
	}
	if ($Changed.Count -gt 0) {
	    [void]$sectionsHtml.Append((Build-DiffChangedSectionHtml -Title "Changed Findings" -ChangedEntries $Changed))
	}
	if ($OnlyInBaseline.Count -gt 0 -or $OnlyInCurrent.Count -gt 0) {
	    $scopeHtml = [System.Text.StringBuilder]::new()
	    [void]$scopeHtml.AppendLine('<section class="section">')
	    [void]$scopeHtml.AppendLine('  <div class="section-header" onclick="toggleSection(this)">')
	    [void]$scopeHtml.AppendLine('    <div class="section-title">Scan Scope Differences</div>')
	    [void]$scopeHtml.AppendLine('    <span class="section-toggle">&#9660;</span>')
	    [void]$scopeHtml.AppendLine('  </div>')
	    [void]$scopeHtml.AppendLine('  <div class="section-content">')
	    [void]$scopeHtml.AppendLine('    <div class="scope-info">')
	    [void]$scopeHtml.AppendLine('      The following categories were not scanned in both reports and are excluded from the comparison above.<br>')
	    if ($OnlyInCurrent.Count -gt 0) {
	        $cats = (ConvertTo-HtmlEncode ($OnlyInCurrent -join ', '))
	        [void]$scopeHtml.AppendLine("      <strong>Only in current scan:</strong> $cats ($($ScopeOnlyCurrent.Count) finding(s) not compared)<br>")
	    }
	    if ($OnlyInBaseline.Count -gt 0) {
	        $cats = (ConvertTo-HtmlEncode ($OnlyInBaseline -join ', '))
	        [void]$scopeHtml.AppendLine("      <strong>Only in baseline scan:</strong> $cats ($($ScopeOnlyBaseline.Count) finding(s) not compared)")
	    }
	    [void]$scopeHtml.AppendLine('    </div>')
	    [void]$scopeHtml.AppendLine('  </div>')
	    [void]$scopeHtml.AppendLine('</section>')
	    [void]$sectionsHtml.Append($scopeHtml.ToString())
	}
	if ($Added.Count -eq 0 -and $Removed.Count -eq 0 -and $Changed.Count -eq 0 -and
	    $OnlyInBaseline.Count -eq 0 -and $OnlyInCurrent.Count -eq 0) {
	    [void]$sectionsHtml.AppendLine('<div class="empty-state">No differences found between the two scans.</div>')
	}
	$baselineInfo = "$BaselineFile ($($BaselineMeta.Date), $($BaselineMeta.Domain), adPEAS $($BaselineMeta.Version))"
	$currentInfo = "$CurrentFile ($($CurrentMeta.Date), $($CurrentMeta.Domain), adPEAS $($CurrentMeta.Version))"
	$comparedCats = if ($SharedCategories.Count -gt 0) { "$($SharedCategories.Count) ($($SharedCategories -join ', '))" } else { "None" }
	$version = if ($Script:adPEASVersion) { $Script:adPEASVersion } else { "2.0.0" }
	$generatedDate = Get-Date -Format "yyyy-MM-dd HH:mm:ss"
	$domain = $BaselineMeta.Domain
	$html = $html -replace '{{DOMAIN}}', (ConvertTo-HtmlEncode $domain)
	$html = $html -replace '{{NEW_COUNT}}', $Added.Count
	$html = $html -replace '{{REMEDIATED_COUNT}}', $Removed.Count
	$html = $html -replace '{{CHANGED_COUNT}}', $Changed.Count
	$html = $html -replace '{{UNCHANGED_COUNT}}', $UnchangedCount
	$html = $html -replace '{{BASELINE_INFO}}', (ConvertTo-HtmlEncode $baselineInfo)
	$html = $html -replace '{{CURRENT_INFO}}', (ConvertTo-HtmlEncode $currentInfo)
	$html = $html -replace '{{COMPARED_CATEGORIES}}', (ConvertTo-HtmlEncode $comparedCats)
	$html = $html -replace '{{GENERATED}}', $generatedDate
	$html = $html -replace '{{VERSION}}', $version
	$html = $html.Replace('{{DIFF_SECTIONS}}', $sectionsHtml.ToString())
	$utf8NoBom = New-Object System.Text.UTF8Encoding $false
	$resolvedPath = $ExecutionContext.SessionState.Path.GetUnresolvedProviderPathFromPSPath($OutputPath)
	[System.IO.File]::WriteAllText($resolvedPath, $html, $utf8NoBom)
}
function Build-DiffSectionHtml {
	[CmdletBinding()]
	param(
	    [string]$Title,
	    [array]$Findings,
	    [string]$SectionType
	)
	$sb = [System.Text.StringBuilder]::new()
	[void]$sb.AppendLine('<section class="section">')
	[void]$sb.AppendLine("  <div class=`"section-header`" onclick=`"toggleSection(this)`">")
	$escapedTitle = ConvertTo-HtmlEncode $Title
	[void]$sb.AppendLine("    <div class=`"section-title`">$escapedTitle <span class=`"section-count`">$($Findings.Count)</span></div>")
	[void]$sb.AppendLine('    <span class="section-toggle">&#9660;</span>')
	[void]$sb.AppendLine('  </div>')
	[void]$sb.AppendLine('  <div class="section-content">')
	$groups = $Findings | Group-Object -Property { "$($_.Category) > $($_.CheckTitle)" }
	foreach ($group in ($groups | Sort-Object Name)) {
	    foreach ($f in $group.Group) {
	        $displayName = ConvertTo-HtmlEncode (Get-FindingDisplayName -Finding $f)
	        $severity = if ($f.Severity) { $f.Severity.ToLower() } else { 'standard' }
	        $category = ConvertTo-HtmlEncode $group.Name
	        $badgeClass = if ($SectionType -eq 'new') { 'badge-new' } else { 'badge-fixed' }
	        $badgeText = if ($SectionType -eq 'new') { 'NEW' } else { 'FIXED' }
	        [void]$sb.AppendLine("    <div class=`"diff-item`">")
	        [void]$sb.AppendLine("      <div class=`"severity-bar $severity`"></div>")
	        [void]$sb.AppendLine("      <div class=`"diff-item-name`">$displayName</div>")
	        [void]$sb.AppendLine("      <div class=`"diff-item-meta`">$category</div>")
	        [void]$sb.AppendLine("      <span class=`"diff-item-badge $badgeClass`">$badgeText</span>")
	        [void]$sb.AppendLine('    </div>')
	    }
	}
	[void]$sb.AppendLine('  </div>')
	[void]$sb.AppendLine('</section>')
	return $sb.ToString()
}
function Build-DiffChangedSectionHtml {
	[CmdletBinding()]
	param(
	    [string]$Title,
	    [array]$ChangedEntries
	)
	$sb = [System.Text.StringBuilder]::new()
	[void]$sb.AppendLine('<section class="section">')
	[void]$sb.AppendLine("  <div class=`"section-header`" onclick=`"toggleSection(this)`">")
	$escapedTitle = ConvertTo-HtmlEncode $Title
	[void]$sb.AppendLine("    <div class=`"section-title`">$escapedTitle <span class=`"section-count`">$($ChangedEntries.Count)</span></div>")
	[void]$sb.AppendLine('    <span class="section-toggle">&#9660;</span>')
	[void]$sb.AppendLine('  </div>')
	[void]$sb.AppendLine('  <div class="section-content">')
	$groups = $ChangedEntries | Group-Object -Property { "$($_.Current.Category) > $($_.Current.CheckTitle)" }
	foreach ($group in ($groups | Sort-Object Name)) {
	    foreach ($entry in $group.Group) {
	        $displayName = ConvertTo-HtmlEncode (Get-FindingDisplayName -Finding $entry.Current)
	        $severity = if ($entry.Current.Severity) { $entry.Current.Severity.ToLower() } else { 'standard' }
	        $category = ConvertTo-HtmlEncode $group.Name
	        $changeDesc = @()
	        if ($entry.Baseline.Severity -ne $entry.Current.Severity) {
	            $changeDesc += "$($entry.Baseline.Severity) &#8594; $($entry.Current.Severity)"
	        }
	        if ($entry.Current.Type -eq 'KeyValue' -and $entry.Baseline.Value -ne $entry.Current.Value) {
	            $oldVal = ConvertTo-HtmlEncode ([string]$entry.Baseline.Value)
	            $newVal = ConvertTo-HtmlEncode ([string]$entry.Current.Value)
	            if ($oldVal.Length -gt 40) { $oldVal = $oldVal.Substring(0, 37) + '...' }
	            if ($newVal.Length -gt 40) { $newVal = $newVal.Substring(0, 37) + '...' }
	            $changeDesc += "$oldVal &#8594; $newVal"
	        }
	        if ($entry.Current.Type -eq 'Line' -and $entry.Baseline.Text -ne $entry.Current.Text) {
	            $changeDesc += "text changed"
	        }
	        $changeHtml = $changeDesc -join ', '
	        [void]$sb.AppendLine("    <div class=`"diff-item`">")
	        [void]$sb.AppendLine("      <div class=`"severity-bar $severity`"></div>")
	        [void]$sb.AppendLine("      <div class=`"diff-item-name`">$displayName <span style=`"font-size:12px;color:var(--text-muted)`">($changeHtml)</span></div>")
	        [void]$sb.AppendLine("      <div class=`"diff-item-meta`">$category</div>")
	        [void]$sb.AppendLine('      <span class="diff-item-badge badge-changed">CHANGED</span>')
	        [void]$sb.AppendLine('    </div>')
	    }
	}
	[void]$sb.AppendLine('  </div>')
	[void]$sb.AppendLine('</section>')
	return $sb.ToString()
}
function Get-DiffHTMLTemplate {
	return @'
<!DOCTYPE html>
<html lang="en" data-theme="dark">
<head>
	<meta charset="UTF-8">
	<meta name="viewport" content="width=device-width, initial-scale=1.0">
	<title>adPEAS Comparison Report - {{DOMAIN}}</title>
	<script>
	    (function() {
	        try {
	            var savedTheme = localStorage.getItem('adpeas-theme');
	            if (savedTheme === 'dark' || savedTheme === 'light') {
	                document.documentElement.setAttribute('data-theme', savedTheme);
	            }
	        } catch (e) {}
	    })();
	</script>
	<style>
	    /* ============================================================
	       adPEAS Diff Report - Embedded Styles
	       Color scheme matches the main adPEAS report
	       ============================================================ */
	    :root {
	        --finding: #d32f2f;
	        --finding-bg-light: #ffebee;
	        --finding-bg-dark: #4a1a1a;
	        --hint: #f57c00;
	        --hint-bg-light: #fff3e0;
	        --hint-bg-dark: #4a3010;
	        --note: #388e3c;
	        --note-bg-light: #e8f5e9;
	        --note-bg-dark: #1a3a1a;
	        --secure: #2196f3;
	        --secure-bg-light: #e3f2fd;
	        --secure-bg-dark: #1a2a4a;
	    }
	    [data-theme="light"] {
	        --bg-main: #e2e8f0;
	        --bg-card: #ffffff;
	        --bg-header: #1a365d;
	        --bg-hover: #f1f5f9;
	        --text: #1a202c;
	        --text-muted: #64748b;
	        --border: #e2e8f0;
	        --finding-bg: var(--finding-bg-light);
	        --hint-bg: var(--hint-bg-light);
	        --note-bg: var(--note-bg-light);
	        --secure-bg: var(--secure-bg-light);
	    }
	    [data-theme="dark"] {
	        --bg-main: #0d1117;
	        --bg-card: #161b22;
	        --bg-header: #21262d;
	        --bg-hover: #1c2128;
	        --text: #e6edf3;
	        --text-muted: #8b949e;
	        --border: #30363d;
	        --finding-bg: var(--finding-bg-dark);
	        --hint-bg: var(--hint-bg-dark);
	        --note-bg: var(--note-bg-dark);
	        --secure-bg: var(--secure-bg-dark);
	    }
	    * { margin: 0; padding: 0; box-sizing: border-box; }
	    body {
	        font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
	        background: var(--bg-main);
	        color: var(--text);
	        line-height: 1.6;
	    }
	    /* Header */
	    .header {
	        position: fixed; top: 0; left: 0; right: 0; z-index: 100;
	        height: 64px;
	        background: var(--bg-header);
	        color: #fff;
	        display: flex;
	        align-items: center;
	        justify-content: space-between;
	        padding: 0 24px;
	        border-bottom: 1px solid rgba(255,255,255,0.1);
	    }
	    .header-brand {
	        display: flex; align-items: center; gap: 12px;
	    }
	    .header-logo { height: 36px; width: 36px; }
	    .header-title { font-size: 20px; font-weight: 700; }
	    .header-subtitle { font-size: 13px; color: rgba(255,255,255,0.6); margin-left: 8px; }
	    .header-actions { display: flex; gap: 8px; align-items: center; }
	    .btn {
	        padding: 6px 14px; border-radius: 6px;
	        border: 1px solid rgba(255,255,255,0.2);
	        background: transparent; color: #fff;
	        cursor: pointer; font-size: 13px;
	    }
	    .btn:hover { background: rgba(255,255,255,0.1); }
	    /* Theme toggle */
	    .theme-toggle {
	        position: relative; width: 52px; height: 28px;
	        border-radius: 14px; border: none; cursor: pointer;
	        background: #334155; transition: background 0.3s;
	    }
	    .theme-toggle-slider {
	        position: absolute; top: 3px; left: 3px;
	        width: 22px; height: 22px; border-radius: 50%;
	        background: #fff; transition: transform 0.3s;
	    }
	    [data-theme="light"] .theme-toggle { background: #93c5fd; }
	    [data-theme="light"] .theme-toggle-slider { transform: translateX(24px); }
	    .theme-icon { position: absolute; right: 7px; top: 5px; font-size: 14px; }
	    [data-theme="light"] .theme-icon { left: 7px; right: auto; }
	    /* Main content */
	    .main {
	        max-width: 1100px;
	        margin: 88px auto 40px;
	        padding: 0 24px;
	    }
	    /* Summary cards */
	    .summary-grid {
	        display: grid;
	        grid-template-columns: repeat(4, 1fr);
	        gap: 16px;
	        margin-bottom: 24px;
	    }
	    .summary-card {
	        background: var(--bg-card);
	        border-radius: 12px;
	        padding: 20px;
	        border: 1px solid var(--border);
	        display: flex;
	        align-items: center;
	        gap: 16px;
	    }
	    .summary-card .icon {
	        width: 52px; height: 52px;
	        border-radius: 12px;
	        display: flex; align-items: center; justify-content: center;
	        font-size: 22px; font-weight: bold;
	    }
	    .summary-card .value { font-size: 32px; font-weight: 700; line-height: 1; }
	    .summary-card .label { font-size: 13px; color: var(--text-muted); margin-top: 4px; }
	    .summary-card.new-findings .icon { background: var(--finding-bg); color: var(--finding); }
	    .summary-card.new-findings .value { color: var(--finding); }
	    .summary-card.remediated .icon { background: var(--secure-bg); color: var(--secure); }
	    .summary-card.remediated .value { color: var(--secure); }
	    .summary-card.changed .icon { background: var(--hint-bg); color: var(--hint); }
	    .summary-card.changed .value { color: var(--hint); }
	    .summary-card.unchanged .icon { background: var(--note-bg); color: var(--note); }
	    .summary-card.unchanged .value { color: var(--note); }
	    /* Info bar */
	    .info-bar {
	        display: flex; flex-wrap: wrap; gap: 8px 24px;
	        background: var(--bg-card);
	        border: 1px solid var(--border);
	        border-radius: 8px;
	        padding: 14px 20px;
	        margin-bottom: 24px;
	    }
	    .info-item .label { font-size: 11px; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.5px; }
	    .info-item .value { font-size: 13px; font-weight: 500; }
	    /* Sections */
	    .section {
	        background: var(--bg-card);
	        border: 1px solid var(--border);
	        border-radius: 8px;
	        margin-bottom: 16px;
	        overflow: hidden;
	    }
	    .section-header {
	        padding: 14px 20px;
	        display: flex;
	        align-items: center;
	        justify-content: space-between;
	        cursor: pointer;
	        user-select: none;
	    }
	    .section-header:hover { background: var(--bg-hover); }
	    .section-title {
	        font-size: 16px; font-weight: 600;
	        display: flex; align-items: center; gap: 10px;
	    }
	    .section-count {
	        font-size: 13px; color: var(--text-muted);
	        background: var(--bg-main); border-radius: 12px;
	        padding: 2px 10px;
	    }
	    .section-toggle { font-size: 12px; color: var(--text-muted); transition: transform 0.2s; }
	    .section-toggle.collapsed { transform: rotate(-90deg); }
	    .section-content { padding: 0 20px 16px; }
	    .section-content.hidden { display: none; }
	    /* Finding items */
	    .diff-item {
	        display: flex;
	        align-items: center;
	        gap: 12px;
	        padding: 10px 12px;
	        border-radius: 6px;
	        margin-bottom: 4px;
	    }
	    .diff-item:hover { background: var(--bg-hover); }
	    .severity-bar {
	        width: 4px; height: 28px;
	        border-radius: 2px; flex-shrink: 0;
	    }
	    .severity-bar.finding { background: var(--finding); }
	    .severity-bar.hint { background: var(--hint); }
	    .severity-bar.note { background: var(--note); }
	    .severity-bar.secure { background: var(--secure); }
	    .severity-bar.standard { background: var(--text-muted); }
	    .diff-item-name { flex: 1; font-size: 14px; }
	    .diff-item-meta { font-size: 12px; color: var(--text-muted); }
	    .diff-item-badge {
	        font-size: 11px; font-weight: 600;
	        padding: 2px 8px; border-radius: 4px;
	        text-transform: uppercase; letter-spacing: 0.3px;
	    }
	    .badge-new { background: var(--finding-bg); color: var(--finding); }
	    .badge-fixed { background: var(--secure-bg); color: var(--secure); }
	    .badge-changed { background: var(--hint-bg); color: var(--hint); }
	    /* Scope info */
	    .scope-info {
	        padding: 14px 16px;
	        background: var(--bg-hover);
	        border-radius: 6px;
	        font-size: 13px;
	        color: var(--text-muted);
	        line-height: 1.8;
	    }
	    .scope-info strong { color: var(--text); }
	    /* Empty state */
	    .empty-state {
	        text-align: center;
	        padding: 20px;
	        color: var(--text-muted);
	        font-size: 14px;
	    }
	    /* Print */
	    @media print {
	        .header { position: static; }
	        .main { margin-top: 16px; }
	        .section { break-inside: avoid; }
	        .btn, .theme-toggle { display: none; }
	    }
	    /* Responsive */
	    @media (max-width: 768px) {
	        .summary-grid { grid-template-columns: repeat(2, 1fr); }
	        .info-bar { flex-direction: column; }
	    }
	</style>
</head>
<body>
	<header class="header" role="banner">
	    <div class="header-brand">
	        <img class="header-logo" src="data:image/png;base64," alt="adPEAS Logo">
	        <span class="header-title">adPEAS</span>
	        <span class="header-subtitle">Comparison Report</span>
	    </div>
	    <div class="header-actions">
	        <button class="theme-toggle" onclick="toggleTheme()" aria-label="Toggle theme">
	            <span class="theme-toggle-slider"></span>
	            <span class="theme-icon" aria-hidden="true">&#9788;</span>
	        </button>
	        <button class="btn" onclick="window.print()">Print / PDF</button>
	    </div>
	</header>
	<main class="main">
	    <div class="summary-grid">
	        <div class="summary-card new-findings">
	            <div class="icon" aria-hidden="true">&#33;</div>
	            <div>
	                <div class="value">{{NEW_COUNT}}</div>
	                <div class="label">New</div>
	            </div>
	        </div>
	        <div class="summary-card remediated">
	            <div class="icon" aria-hidden="true">&#10003;</div>
	            <div>
	                <div class="value">{{REMEDIATED_COUNT}}</div>
	                <div class="label">Remediated</div>
	            </div>
	        </div>
	        <div class="summary-card changed">
	            <div class="icon" aria-hidden="true">&#9650;</div>
	            <div>
	                <div class="value">{{CHANGED_COUNT}}</div>
	                <div class="label">Changed</div>
	            </div>
	        </div>
	        <div class="summary-card unchanged">
	            <div class="icon" aria-hidden="true">&#9679;</div>
	            <div>
	                <div class="value">{{UNCHANGED_COUNT}}</div>
	                <div class="label">Unchanged</div>
	            </div>
	        </div>
	    </div>
	    <div class="info-bar">
	        <div class="info-item">
	            <div class="label">Baseline</div>
	            <div class="value">{{BASELINE_INFO}}</div>
	        </div>
	        <div class="info-item">
	            <div class="label">Current</div>
	            <div class="value">{{CURRENT_INFO}}</div>
	        </div>
	        <div class="info-item">
	            <div class="label">Compared</div>
	            <div class="value">{{COMPARED_CATEGORIES}}</div>
	        </div>
	        <div class="info-item">
	            <div class="label">Generated</div>
	            <div class="value">{{GENERATED}}</div>
	        </div>
	        <div class="info-item">
	            <div class="label">Version</div>
	            <div class="value">{{VERSION}}</div>
	        </div>
	    </div>
	    {{DIFF_SECTIONS}}
	</main>
	<script>
	    function toggleTheme() {
	        var current = document.documentElement.getAttribute('data-theme');
	        var next = current === 'dark' ? 'light' : 'dark';
	        document.documentElement.setAttribute('data-theme', next);
	        try { localStorage.setItem('adpeas-theme', next); } catch (e) {}
	    }
	    function toggleSection(el) {
	        var content = el.parentElement.querySelector('.section-content');
	        var toggle = el.querySelector('.section-toggle');
	        if (content.classList.contains('hidden')) {
	            content.classList.remove('hidden');
	            toggle.classList.remove('collapsed');
	        } else {
	            content.classList.add('hidden');
	            toggle.classList.add('collapsed');
	        }
	    }
	</script>
</body>
</html>
'@
}
function Invoke-adPEASCollector {
	[CmdletBinding()]
	param(
	    [Parameter(Mandatory=$false)]
	    [string]$Domain,
	    [Parameter(Mandatory=$false)]
	    [string]$Server,
	    [Parameter(Mandatory=$false)]
	    [System.Management.Automation.PSCredential]$Credential,
	    [Parameter(Mandatory=$false)]
	    [string]$OutputPath,
	    [Parameter(Mandatory=$false)]
	    [ValidateSet('DCOnly', 'ACL', 'ObjectProps', 'Trusts', 'Container', 'CertServices')]
	    [string]$CollectionMethod = 'DCOnly',
	    [Parameter(Mandatory=$false)]
	    [switch]$NoZip,
	    [Parameter(Mandatory=$false)]
	    [switch]$PrettyPrint
	)
	begin {
	    $Script:CollectorVersion = "1.0.0"
	    $Script:JsonVersion = 6
	    $Script:CollectionTimestamp = Get-Date -Format "yyyyMMddHHmmss"
	}
	process {
	    try {
	        $connectionParams = @{}
	        if ($Domain) { $connectionParams['Domain'] = $Domain }
	        if ($Server) { $connectionParams['Server'] = $Server }
	        if ($Credential) { $connectionParams['Credential'] = $Credential }
	        if (-not (Ensure-LDAPConnection @connectionParams)) {
	            return
	        }
	        $domainName = $Script:LDAPContext.Domain.ToUpper()
	        $domainDN = $Script:LDAPContext.DomainDN
	        $domainSID = $null
	        Show-SubHeader "Collecting BloodHound CE data..." -ObjectType "BloodHoundCollector"
	        $domainObj = @(Get-DomainObject -LDAPFilter "(distinguishedName=$domainDN)" @connectionParams)[0]
	        if ($domainObj.objectSid) {
	            $domainSID = Convert-SidToString -SidInput $domainObj.objectSid
	        }
	        $defaultFileName = "$($Script:CollectionTimestamp)_$($domainName)_BloodHound.zip"
	        if ([string]::IsNullOrEmpty($OutputPath)) {
	            $OutputPath = Join-Path (Get-Location) $defaultFileName
	        }
	        elseif (Test-Path $OutputPath -PathType Container) {
	            $OutputPath = Join-Path $OutputPath $defaultFileName
	        }
	        elseif ($OutputPath -match '[\\/]$') {
	            if (-not (Test-Path $OutputPath)) {
	                New-Item -ItemType Directory -Path $OutputPath -Force | Out-Null
	            }
	            $OutputPath = Join-Path $OutputPath $defaultFileName
	        }
	        $tempDir = Join-Path $env:TEMP "adPEAS_BH_$Script:CollectionTimestamp"
	        if (-not (Test-Path $tempDir)) {
	            New-Item -ItemType Directory -Path $tempDir -Force | Out-Null
	        }
	        $collectedData = @{
	            Users             = @()
	            Groups            = @()
	            Computers         = @()
	            Domains           = @()
	            OUs               = @()
	            Containers        = @()
	            GPOs              = @()
	            CertTemplates     = @()
	            EnterpriseCAs     = @()
	            RootCAs           = @()
	            AIACAs            = @()
	            NTAuthStores      = @()
	            IssuancePolicies  = @()
	        }
	        $collectUsers = $CollectionMethod -in @('DCOnly', 'ObjectProps', 'ACL')
	        $collectGroups = $CollectionMethod -in @('DCOnly', 'ObjectProps', 'ACL')
	        $collectComputers = $CollectionMethod -in @('DCOnly', 'ObjectProps', 'ACL')
	        $collectDomains = $CollectionMethod -in @('DCOnly', 'Trusts')
	        $collectOUs = $CollectionMethod -in @('DCOnly', 'Container', 'ACL')
	        $collectContainers = $CollectionMethod -in @('DCOnly', 'Container')
	        $collectGPOs = $CollectionMethod -in @('DCOnly', 'Container', 'ACL')
	        $collectACLs = $CollectionMethod -in @('DCOnly', 'ACL')
	        $collectADCS = $CollectionMethod -in @('DCOnly', 'ACL', 'CertServices')
	        $totalSteps = 0
	        if ($collectDomains) { $totalSteps++ }          # Domain
	        if ($collectUsers) { $totalSteps++ }            # Users
	        if ($collectGroups) { $totalSteps++ }           # Groups
	        if ($collectComputers) { $totalSteps++ }        # Computers
	        if ($collectOUs) { $totalSteps++ }              # OUs
	        if ($collectContainers) { $totalSteps++ }       # Containers
	        if ($collectGPOs) { $totalSteps++ }             # GPOs
	        if ($collectADCS) { $totalSteps += 6 }          # 6 ADCS object types
	        $totalSteps++                                    # Writing JSON
	        $currentStep = 0
	        $Script:CollectedParts = [System.Collections.Generic.List[string]]::new()
	        $Script:ProgressPadWidth = 100
	        $esc = [char]0x1B
	        $Script:CursorUp = "$esc[1A"
	        $Script:CursorDown = "$esc[1B"
	        $Script:WriteCollectionStatus = {
	            param([string]$Status, [int]$Step, [int]$Total, [switch]$Complete, [switch]$Init)
	            $pw = $Script:ProgressPadWidth
	            $up = $Script:CursorUp
	            $dn = $Script:CursorDown
	            if ($Init) {
	                Write-Host "Collected: (starting...)".PadRight($pw) -NoNewline -ForegroundColor DarkGray
	                Write-Host ""
	                Write-Host "Collecting: $Status".PadRight($pw) -NoNewline
	            } elseif ($Complete) {
	                Write-Host "`r$(' ' * $pw)" -NoNewline
	                Write-Host "$up`r$(' ' * $pw)$dn`r" -NoNewline
	                Write-Host "$up`r" -NoNewline
	            } else {
	                $collectedLine = if ($Script:CollectedParts.Count -gt 0) {
	                    "Collected: $($Script:CollectedParts -join ', ')"
	                } else {
	                    "Collected: (starting...)"
	                }
	                $activeLine = "Collecting: $Status  [$Step/$Total]"
	                Write-Host "$up`r$($collectedLine.PadRight($pw))" -NoNewline -ForegroundColor DarkGray
	                Write-Host "$dn`r$($activeLine.PadRight($pw))" -NoNewline
	            }
	        }
	        function Write-CollectionStatus {
	            param([string]$Status, [switch]$Complete, [switch]$Init)
	            & $Script:WriteCollectionStatus -Status $Status -Step $currentStep -Total $totalSteps -Complete:$Complete -Init:$Init
	        }
	        function Add-CollectedPart {
	            param([string]$Label, [int]$Count)
	            if ($Count -gt 0) { $Script:CollectedParts.Add("$Count $Label") }
	        }
	        Write-CollectionStatus -Init "Building caches..."
	        Build-ComputerHostnameCache -ConnectionParams $connectionParams
	        Build-DNIdentityCache -ConnectionParams $connectionParams
	        if ($collectADCS) {
	            Build-TemplateCNToOIDCache -ConnectionParams $connectionParams
	        }
	        if ($collectDomains) {
	            $currentStep++
	            Write-CollectionStatus "Domain..."
	            $collectedData.Domains = @(Collect-BHDomain -DomainDN $domainDN -DomainSID $domainSID @connectionParams)
	            Add-CollectedPart -Label "domains" -Count @($collectedData.Domains).Count
	        }
	        if ($collectUsers) {
	            $currentStep++
	            Write-CollectionStatus "Users..."
	            $collectedData.Users = @(Collect-BHUsers -DomainSID $domainSID -CollectACLs:$collectACLs @connectionParams)
	            Add-CollectedPart -Label "users" -Count @($collectedData.Users).Count
	        }
	        if ($collectGroups) {
	            $currentStep++
	            Write-CollectionStatus "Groups..."
	            $collectedData.Groups = @(Collect-BHGroups -DomainSID $domainSID -CollectACLs:$collectACLs @connectionParams)
	            Add-CollectedPart -Label "groups" -Count @($collectedData.Groups).Count
	        }
	        if ($collectComputers) {
	            $currentStep++
	            Write-CollectionStatus "Computers..."
	            $collectedData.Computers = @(Collect-BHComputers -DomainSID $domainSID -CollectACLs:$collectACLs @connectionParams)
	            Add-CollectedPart -Label "computers" -Count @($collectedData.Computers).Count
	        }
	        if ($collectOUs) {
	            $currentStep++
	            Write-CollectionStatus "OUs..."
	            $collectedData.OUs = @(Collect-BHOUs -DomainSID $domainSID -CollectACLs:$collectACLs @connectionParams)
	            Add-CollectedPart -Label "OUs" -Count @($collectedData.OUs).Count
	        }
	        if ($collectContainers) {
	            $currentStep++
	            Write-CollectionStatus "Containers..."
	            $collectedData.Containers = @(Collect-BHContainers -DomainSID $domainSID -CollectACLs:$collectACLs @connectionParams)
	            Add-CollectedPart -Label "containers" -Count @($collectedData.Containers).Count
	        }
	        if ($collectGPOs) {
	            $currentStep++
	            Write-CollectionStatus "GPOs..."
	            $collectedData.GPOs = @(Collect-BHGPOs -DomainSID $domainSID -CollectACLs:$collectACLs @connectionParams)
	            Add-CollectedPart -Label "GPOs" -Count @($collectedData.GPOs).Count
	        }
	        if ($collectADCS) {
	            $currentStep++
	            Write-CollectionStatus "Certificate Templates..."
	            $collectedData.CertTemplates = @(Collect-BHCertTemplates -DomainSID $domainSID -CollectACLs:$collectACLs @connectionParams)
	            $currentStep++
	            Write-CollectionStatus "Enterprise CAs..."
	            $collectedData.EnterpriseCAs = @(Collect-BHEnterpriseCAs -DomainSID $domainSID -CollectACLs:$collectACLs @connectionParams)
	            $currentStep++
	            Write-CollectionStatus "Root CAs..."
	            $collectedData.RootCAs = @(Collect-BHRootCAs -DomainSID $domainSID -CollectACLs:$collectACLs @connectionParams)
	            $currentStep++
	            Write-CollectionStatus "AIA CAs..."
	            $collectedData.AIACAs = @(Collect-BHAIACAs -DomainSID $domainSID -CollectACLs:$collectACLs @connectionParams)
	            $currentStep++
	            Write-CollectionStatus "NTAuth Stores..."
	            $collectedData.NTAuthStores = @(Collect-BHNTAuthStores -DomainSID $domainSID -CollectACLs:$collectACLs @connectionParams)
	            $currentStep++
	            Write-CollectionStatus "Issuance Policies..."
	            $collectedData.IssuancePolicies = @(Collect-BHIssuancePolicies -DomainSID $domainSID -CollectACLs:$collectACLs @connectionParams)
	            $adcsTotal = @($collectedData.CertTemplates).Count + @($collectedData.EnterpriseCAs).Count +
	                         @($collectedData.RootCAs).Count + @($collectedData.AIACAs).Count +
	                         @($collectedData.NTAuthStores).Count + @($collectedData.IssuancePolicies).Count
	            Add-CollectedPart -Label "ADCS objects" -Count $adcsTotal
	        }
	        $currentStep++
	        Write-CollectionStatus "Writing JSON..."
	        $jsonFiles = @()
	        if (@($collectedData.Users).Count -gt 0) {
	            $usersFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_users.json"
	            Write-BHJsonFile -Data $collectedData.Users -Type "users" -FilePath $usersFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $usersFile
	        }
	        if (@($collectedData.Groups).Count -gt 0) {
	            $groupsFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_groups.json"
	            Write-BHJsonFile -Data $collectedData.Groups -Type "groups" -FilePath $groupsFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $groupsFile
	        }
	        if (@($collectedData.Computers).Count -gt 0) {
	            $computersFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_computers.json"
	            Write-BHJsonFile -Data $collectedData.Computers -Type "computers" -FilePath $computersFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $computersFile
	        }
	        if (@($collectedData.Domains).Count -gt 0) {
	            $domainsFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_domains.json"
	            Write-BHJsonFile -Data $collectedData.Domains -Type "domains" -FilePath $domainsFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $domainsFile
	        }
	        if (@($collectedData.OUs).Count -gt 0) {
	            $ousFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_ous.json"
	            Write-BHJsonFile -Data $collectedData.OUs -Type "ous" -FilePath $ousFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $ousFile
	        }
	        if (@($collectedData.Containers).Count -gt 0) {
	            $containersFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_containers.json"
	            Write-BHJsonFile -Data $collectedData.Containers -Type "containers" -FilePath $containersFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $containersFile
	        }
	        if (@($collectedData.GPOs).Count -gt 0) {
	            $gposFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_gpos.json"
	            Write-BHJsonFile -Data $collectedData.GPOs -Type "gpos" -FilePath $gposFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $gposFile
	        }
	        if (@($collectedData.CertTemplates).Count -gt 0) {
	            $certTemplatesFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_certtemplates.json"
	            Write-BHJsonFile -Data $collectedData.CertTemplates -Type "certtemplates" -FilePath $certTemplatesFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $certTemplatesFile
	        }
	        if (@($collectedData.EnterpriseCAs).Count -gt 0) {
	            $enterpriseCAsFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_enterprisecas.json"
	            Write-BHJsonFile -Data $collectedData.EnterpriseCAs -Type "enterprisecas" -FilePath $enterpriseCAsFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $enterpriseCAsFile
	        }
	        if (@($collectedData.RootCAs).Count -gt 0) {
	            $rootCAsFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_rootcas.json"
	            Write-BHJsonFile -Data $collectedData.RootCAs -Type "rootcas" -FilePath $rootCAsFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $rootCAsFile
	        }
	        if (@($collectedData.AIACAs).Count -gt 0) {
	            $aiaCAsFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_aiacas.json"
	            Write-BHJsonFile -Data $collectedData.AIACAs -Type "aiacas" -FilePath $aiaCAsFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $aiaCAsFile
	        }
	        if (@($collectedData.NTAuthStores).Count -gt 0) {
	            $ntAuthStoresFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_ntauthstores.json"
	            Write-BHJsonFile -Data $collectedData.NTAuthStores -Type "ntauthstores" -FilePath $ntAuthStoresFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $ntAuthStoresFile
	        }
	        if (@($collectedData.IssuancePolicies).Count -gt 0) {
	            $issuancePoliciesFile = Join-Path $tempDir "$($Script:CollectionTimestamp)_issuancepolicies.json"
	            Write-BHJsonFile -Data $collectedData.IssuancePolicies -Type "issuancepolicies" -FilePath $issuancePoliciesFile -PrettyPrint:$PrettyPrint
	            $jsonFiles += $issuancePoliciesFile
	        }
	        Write-CollectionStatus -Complete
	        if ($NoZip) {
	            $outputDir = Split-Path $OutputPath -Parent
	            if ([string]::IsNullOrEmpty($outputDir)) {
	                $outputDir = Get-Location
	            }
	            foreach ($file in $jsonFiles) {
	                Copy-Item -Path $file -Destination $outputDir -Force
	            }
	        }
	        else {
	            if (Test-Path $OutputPath -PathType Leaf) {
	                Remove-Item $OutputPath -Force
	            }
	            elseif (Test-Path $OutputPath -PathType Container) {
	                Write-Warning "OutputPath '$OutputPath' is a directory. Adding default filename."
	                $OutputPath = Join-Path $OutputPath "$($Script:CollectionTimestamp)_BloodHound.zip"
	            }
	            $outputDir = Split-Path $OutputPath -Parent
	            if (-not [string]::IsNullOrEmpty($outputDir) -and -not (Test-Path $outputDir)) {
	                New-Item -ItemType Directory -Path $outputDir -Force | Out-Null
	            }
	            Add-Type -AssemblyName System.IO.Compression.FileSystem
	            [System.IO.Compression.ZipFile]::CreateFromDirectory($tempDir, $OutputPath)
	        }
	        Remove-Item -Path $tempDir -Recurse -Force -ErrorAction SilentlyContinue
	        $totalObjects = @($collectedData.Users).Count + @($collectedData.Groups).Count + @($collectedData.Computers).Count +
	                       @($collectedData.OUs).Count + @($collectedData.Containers).Count + @($collectedData.GPOs).Count +
	                       @($collectedData.CertTemplates).Count + @($collectedData.EnterpriseCAs).Count +
	                       @($collectedData.RootCAs).Count + @($collectedData.AIACAs).Count +
	                       @($collectedData.NTAuthStores).Count + @($collectedData.IssuancePolicies).Count
	        $summaryString = $Script:CollectedParts -join ", "
	        Show-Line "Collected $totalObjects objects from $domainName`: $summaryString" -Class Hint -FindingId 'BLOODHOUND_COLLECTION_COMPLETE'
	        if ($NoZip) {
	            Show-Line "Output: $outputDir (JSON files)" -Class Note
	        }
	        else {
	            $outputFileName = Split-Path $OutputPath -Leaf
	            Show-Line "Output: $outputFileName" -Class Note
	        }
	    }
	    catch {
	        if ($Script:WriteCollectionStatus) {
	            & $Script:WriteCollectionStatus -Complete -Step 0 -Total 0
	        }
	        Write-Warning "[Invoke-adPEASCollector] BloodHound collection failed: $_"
	    }
	}
	end {
	    $Script:DNToIdentityCache = $null
	    $Script:ParentDNToChildren = $null
	    $Script:ComputerHostnameCache = $null
	    $Script:TemplateCNToOID = $null
	}
}
function Get-SafeInt {
	param(
	    $Value,
	    [int]$Default = 0
	)
	if ($null -eq $Value) {
	    return $Default
	}
	if ($Value -is [array]) {
	    $Value = $Value[0]
	}
	try {
	    return [int]$Value
	}
	catch {
	    return $Default
	}
}
function Convert-SidToString {
	param(
	    [Parameter(Mandatory=$true)]
	    $SidInput
	)
	try {
	    if ($SidInput -is [string]) {
	        if ($SidInput -match '^S-1-') {
	            return $SidInput
	        }
	        return (New-Object System.Security.Principal.SecurityIdentifier($SidInput)).Value
	    }
	    if ($SidInput -is [byte[]]) {
	        return (New-Object System.Security.Principal.SecurityIdentifier($SidInput, 0)).Value
	    }
	    if ($SidInput -is [System.Security.Principal.SecurityIdentifier]) {
	        return $SidInput.Value
	    }
	    if ($SidInput -is [array]) {
	        $bytes = [byte[]]$SidInput
	        return (New-Object System.Security.Principal.SecurityIdentifier($bytes, 0)).Value
	    }
	    return (New-Object System.Security.Principal.SecurityIdentifier($SidInput, 0)).Value
	}
	catch {
	    return $null
	}
}
function ConvertTo-ISODuration {
	param([byte[]]$PeriodBytes)
	if (-not $PeriodBytes -or $PeriodBytes.Length -ne 8) { return "P0D" }
	try {
	    $int64Value = [BitConverter]::ToInt64($PeriodBytes, 0)
	    $seconds = [Math]::Abs($int64Value) / 10000000
	    if ($seconds -ge 31536000) {
	        $years = [Math]::Floor($seconds / 31536000)
	        return "P${years}Y"
	    }
	    elseif ($seconds -ge 86400) {
	        $days = [Math]::Floor($seconds / 86400)
	        return "P${days}D"
	    }
	    elseif ($seconds -ge 3600) {
	        $hours = [Math]::Floor($seconds / 3600)
	        return "PT${hours}H"
	    }
	    else {
	        $minutes = [Math]::Floor($seconds / 60)
	        if ($minutes -le 0) { $minutes = 1 }
	        return "PT${minutes}M"
	    }
	}
	catch {
	    return "P0D"
	}
}
function Get-CertificateProperties {
	param([byte[]]$CertificateBytes)
	$defaultResult = @{ Thumbprint = ""; Name = ""; HasBasicConstraints = $false; PathLength = 0 }
	if (-not $CertificateBytes -or $CertificateBytes.Length -eq 0) {
	    return $defaultResult
	}
	try {
	    $cert = New-Object System.Security.Cryptography.X509Certificates.X509Certificate2(,$CertificateBytes)
	    $thumbprint = $cert.Thumbprint
	    $subject = $cert.Subject
	    $hasBC = $false
	    $pathLen = 0
	    foreach ($ext in $cert.Extensions) {
	        if ($ext.Oid.Value -eq '2.5.29.19') {
	            $hasBC = $true
	            $bcExt = [System.Security.Cryptography.X509Certificates.X509BasicConstraintsExtension]$ext
	            if ($bcExt.HasPathLengthConstraint) {
	                $pathLen = $bcExt.PathLengthConstraint
	            }
	            break
	        }
	    }
	    return @{
	        Thumbprint          = $thumbprint
	        Name                = $subject
	        HasBasicConstraints = $hasBC
	        PathLength          = $pathLen
	    }
	}
	catch {
	    return $defaultResult
	}
}
function Build-ComputerHostnameCache {
	param([hashtable]$ConnectionParams = @{})
	if ($Script:ComputerHostnameCache) { return }
	$Script:ComputerHostnameCache = @{}
	$computers = Get-DomainComputer -Properties sAMAccountName,dNSHostName,objectSid @ConnectionParams
	foreach ($comp in @($computers)) {
	    if ($comp.objectSid) {
	        $sid = Convert-SidToString -SidInput $comp.objectSid
	        if ($sid) {
	            if ($comp.dNSHostName) {
	                $Script:ComputerHostnameCache[$comp.dNSHostName.ToLower()] = $sid
	            }
	            if ($comp.sAMAccountName) {
	                $shortName = $comp.sAMAccountName.TrimEnd('$').ToLower()
	                $Script:ComputerHostnameCache[$shortName] = $sid
	            }
	        }
	    }
	}
}
function Build-DNIdentityCache {
	param([hashtable]$ConnectionParams = @{})
	if ($Script:DNToIdentityCache) { return }
	$Script:DNToIdentityCache = @{}
	$Script:ParentDNToChildren = @{}
	$allObjects = Get-DomainObject -LDAPFilter "(|(objectClass=user)(objectClass=group)(objectClass=organizationalUnit)(objectClass=container)(objectClass=groupPolicyContainer))" `
	    -Properties 'distinguishedName','objectSid','objectGuid','objectClass','name' @ConnectionParams
	foreach ($obj in @($allObjects)) {
	    $dn = $obj.distinguishedName
	    if (-not $dn) { continue }
	    $objType = Get-BHObjectType -ObjectClass $obj.objectClass
	    $objId = $null
	    if ($obj.objectSid) {
	        $objId = Convert-SidToString -SidInput $obj.objectSid
	    } elseif ($obj.objectGuid) {
	        $objId = $obj.objectGuid.ToString().ToUpper()
	    }
	    if (-not $objId) { continue }
	    $Script:DNToIdentityCache[$dn] = @{
	        ObjectIdentifier = $objId
	        ObjectType       = $objType
	    }
	    $parentDN = $dn -replace '^[^,]+,', ''
	    if (-not $Script:ParentDNToChildren.ContainsKey($parentDN)) {
	        $Script:ParentDNToChildren[$parentDN] = [System.Collections.Generic.List[hashtable]]::new()
	    }
	    $Script:ParentDNToChildren[$parentDN].Add(@{
	        ObjectIdentifier = $objId
	        ObjectType       = $objType
	    })
	}
}
function Resolve-SPNToTarget {
	param([string]$SPN)
	if (-not $SPN -or -not $Script:ComputerHostnameCache) { return $null }
	if ($SPN -match '^[^/]+/([^:/]+)') {
	    $hostname = $Matches[1].ToLower()
	    if ($Script:ComputerHostnameCache.ContainsKey($hostname)) {
	        return @{ ObjectIdentifier = $Script:ComputerHostnameCache[$hostname]; ObjectType = 'Computer' }
	    }
	    $shortHost = ($hostname -split '\.')[0].ToLower()
	    if ($Script:ComputerHostnameCache.ContainsKey($shortHost)) {
	        return @{ ObjectIdentifier = $Script:ComputerHostnameCache[$shortHost]; ObjectType = 'Computer' }
	    }
	}
	return $null
}
function Build-TemplateCNToOIDCache {
	param([hashtable]$ConnectionParams = @{})
	$Script:TemplateCNToOID = @{}
	$configNC = $Script:LDAPContext.ConfigurationNamingContext
	if (-not $configNC) {
	    return
	}
	$searchBase = "CN=Certificate Templates,CN=Public Key Services,CN=Services,$configNC"
	try {
	    $templates = Invoke-LDAPSearch -Filter "(objectClass=pKICertificateTemplate)" -SearchBase $searchBase -Properties cn,'msPKI-Cert-Template-OID' -Raw
	    foreach ($t in @($templates)) {
	        $cn = $null
	        $oid = $null
	        if ($t.cn) { $cn = if ($t.cn -is [array]) { $t.cn[0] } else { $t.cn } }
	        if ($t.'msPKI-Cert-Template-OID') {
	            $oid = if ($t.'msPKI-Cert-Template-OID' -is [array]) { $t.'msPKI-Cert-Template-OID'[0] } else { $t.'msPKI-Cert-Template-OID' }
	        }
	        if ($cn -and $oid) {
	            if ($oid -is [byte[]]) {
	                $oid = [System.Text.Encoding]::UTF8.GetString($oid)
	            }
	            if ($cn -is [byte[]]) {
	                $cn = [System.Text.Encoding]::UTF8.GetString($cn)
	            }
	            $Script:TemplateCNToOID[$cn] = $oid
	        }
	    }
	}
	catch {
	}
}
function Write-BHJsonFile {
	param(
	    [array]$Data,
	    [string]$Type,
	    [string]$FilePath,
	    [switch]$PrettyPrint
	)
	$methodsBitmask = switch ($Type) {
	    'users'            { 1 -bor 64 -bor 512 -bor 1024 }  # Group + ACL + ObjectProps + SPNTargets
	    'groups'           { 1 -bor 64 -bor 512 }             # Group + ACL + ObjectProps
	    'computers'        { 1 -bor 64 -bor 512 }             # Group + ACL + ObjectProps
	    'domains'          { 32 -bor 64 -bor 128 -bor 512 }   # Trusts + ACL + Container + ObjectProps
	    'ous'              { 64 -bor 128 }                     # ACL + Container
	    'containers'       { 128 }                             # Container
	    'gpos'             { 64 -bor 128 }                     # ACL + Container
	    'certtemplates'    { 64 -bor 262144 }                  # ACL + CertServices
	    'enterprisecas'    { 64 -bor 262144 }                  # ACL + CertServices
	    'rootcas'          { 64 -bor 262144 }                  # ACL + CertServices
	    'aiacas'           { 64 -bor 262144 }                  # ACL + CertServices
	    'ntauthstores'     { 64 -bor 262144 }                  # ACL + CertServices
	    'issuancepolicies' { 64 -bor 262144 }                  # ACL + CertServices
	    default            { 0 }
	}
	$jsonObject = @{
	    data = $Data
	    meta = @{
	        type    = $Type
	        count   = @($Data).Count
	        version = $Script:JsonVersion
	        methods = $methodsBitmask
	    }
	}
	$exportResult = Export-adPEASFile -Path $FilePath -Content $jsonObject -Type Json -JsonDepth 20 -Force
	if (-not $exportResult.Success) {
	    Write-Error "[Export-BloodHoundJson] Failed to export: $($exportResult.Message)"
	}
}
function ConvertTo-UnixTimestamp {
	param($FileTime)
	if ($null -eq $FileTime -or $FileTime -eq 0 -or $FileTime -eq 9223372036854775807) {
	    return -1
	}
	try {
	    $date = [DateTime]::FromFileTimeUtc($FileTime)
	    return [int64]($date - [DateTime]::UnixEpoch).TotalSeconds
	}
	catch {
	    return -1
	}
}
function Get-BHObjectType {
	param($ObjectClass)
	if ($ObjectClass -is [array]) {
	    $ObjectClass = $ObjectClass[-1]  # Last element is most specific
	}
	switch -Regex ($ObjectClass) {
	    'user'                  { return 'User' }
	    'computer'              { return 'Computer' }
	    'group'                 { return 'Group' }
	    'organizationalUnit'    { return 'OU' }
	    'container'             { return 'Container' }
	    'groupPolicyContainer'  { return 'GPO' }
	    'domain'                { return 'Domain' }
	    'trustedDomain'         { return 'Domain' }
	    default                 { return 'Base' }
	}
}
function ConvertTo-BHAces {
	param(
	    [string]$DistinguishedName,
	    [string]$ObjectType = 'Base',
	    [hashtable]$ConnectionParams = @{}
	)
	$bhAces = @()
	if (-not $Script:BHPropertyGUIDs) {
	    $Script:BHPropertyGUIDs = @{
	        'f3a64788-5306-11d1-a9c5-0000f80367c1' = 'WriteSPN'
	        '5b47d60f-6090-40b2-9f37-2a4de88f3063' = 'AddKeyCredentialLink'
	        '3f78c3e5-f79a-46bd-a0b8-9d18116ddc79' = 'AddAllowedToAct'
	        '4c164200-20c0-11d0-a768-00aa006e0529' = 'WriteAccountRestrictions'
	        'bf9679c0-0de6-11d0-a285-00aa003049e2' = 'AddMember'
	        'f30e3bbe-9ff0-11d1-b603-0000f80367c1' = 'WriteGPLink'
	        'd15ef7d8-f226-46db-ae79-b34e560bd12c' = 'WritePKIEnrollmentFlag'
	        'ea1dddc4-60ff-416e-8cc0-17cee534bce7' = 'WritePKINameFlag'
	    }
	    $Script:BHExtendedRightGUIDs = @{
	        '1131f6aa-9c07-11d1-f79f-00c04fc2dcd2' = 'GetChanges'
	        '1131f6ad-9c07-11d1-f79f-00c04fc2dcd2' = 'GetChangesAll'
	        '89e95b76-444d-4c62-991a-0facbeda640c' = 'GetChangesInFilteredSet'
	        '00299570-246d-11d0-a768-00aa006e0529' = 'ForceChangePassword'
	        'e362ed86-b728-0842-b27d-2dea7a9df218' = 'ReadLAPSPassword'
	        '00000000-0000-0000-0000-000000000000' = 'AllExtendedRights'
	        '0e10c968-78fb-11d2-90d4-00c04f79dc55' = 'Enroll'
	        'a05b8cc2-17bc-4802-a710-e7c15ab866a2' = 'AutoEnroll'
	        'ee138f32-c3ec-11d1-bbc5-0080c76670c0' = 'ManageCA'
	        '98291c0c-7fd7-11d2-9917-00c04fc2d4cf' = 'ManageCertificates'
	    }
	    $Script:BHGMSAReadGUID = '5b47d60f-6090-40b2-9f37-2a4de88f3063'
	}
	try {
	    $escapedDN = Escape-LDAPFilterDN -DistinguishedName $DistinguishedName
	    $adObject = @(Get-DomainObject -LDAPFilter "(distinguishedName=$escapedDN)" -Properties nTSecurityDescriptor,objectClass,'msDS-GroupMSAMembership' -Raw @ConnectionParams)[0]
	    if (-not $adObject -or -not $adObject.nTSecurityDescriptor) {
	        return $bhAces
	    }
	    if ($adObject.'msDS-GroupMSAMembership') {
	        try {
	            $gmsaSD = New-Object System.DirectoryServices.ActiveDirectorySecurity
	            $gmsaSD.SetSecurityDescriptorBinaryForm($adObject.'msDS-GroupMSAMembership')
	            $gmsaDACL = $gmsaSD.GetAccessRules($true, $true, [System.Security.Principal.SecurityIdentifier])
	            foreach ($gmsaAce in $gmsaDACL) {
	                if ($gmsaAce.AccessControlType -eq 'Allow') {
	                    $gmsaTrusteeSID = $gmsaAce.IdentityReference.Value
	                    if ($gmsaTrusteeSID -notin @('S-1-5-18', 'S-1-3-0', 'S-1-5-10')) {
	                        $bhAces += @{
	                            PrincipalSID  = $gmsaTrusteeSID
	                            PrincipalType = Get-BHPrincipalType -SID $gmsaTrusteeSID
	                            RightName     = 'ReadGMSAPassword'
	                            IsInherited   = $false
	                        }
	                    }
	                }
	            }
	        }
	        catch {
	        }
	    }
	    $RawSD = New-Object System.DirectoryServices.ActiveDirectorySecurity
	    $RawSD.SetSecurityDescriptorBinaryForm($adObject.nTSecurityDescriptor)
	    $ownerSID = $RawSD.GetOwner([System.Security.Principal.SecurityIdentifier]).Value
	    $skipOwners = @(
	        'S-1-5-18',          # SYSTEM (not user-controllable)
	        'S-1-3-0',           # Creator Owner (placeholder)
	        'S-1-5-10'           # Self (placeholder)
	    )
	    if ($ownerSID -and $ownerSID -notin $skipOwners) {
	        $bhAces += @{
	            PrincipalSID  = $ownerSID
	            PrincipalType = Get-BHPrincipalType -SID $ownerSID
	            RightName     = 'Owns'
	            IsInherited   = $false
	        }
	    }
	    $DACL = $RawSD.GetAccessRules($true, $true, [System.Security.Principal.SecurityIdentifier])
	    foreach ($ace in $DACL) {
	        if ($ace.AccessControlType -ne 'Allow') { continue }
	        $trusteeSID = $ace.IdentityReference.Value
	        $skipPrincipals = @(
	            'S-1-3-0',       # Creator Owner (placeholder, not actionable)
	            'S-1-5-10',      # Self (placeholder, not actionable)
	            'S-1-5-18'       # SYSTEM (not user-controllable, no attack path)
	        )
	        if ($trusteeSID -in $skipPrincipals) { continue }
	        $principalType = Get-BHPrincipalType -SID $trusteeSID
	        $adRights = $ace.ActiveDirectoryRights
	        $objectTypeGuid = if ($ace.ObjectType -and $ace.ObjectType -ne [System.Guid]::Empty) {
	            $ace.ObjectType.ToString().ToLower()
	        } else { $null }
	        $isInherited = $ace.IsInherited
	        if (($adRights -band [System.DirectoryServices.ActiveDirectoryRights]::GenericAll) -eq [System.DirectoryServices.ActiveDirectoryRights]::GenericAll) {
	            $bhAces += @{
	                PrincipalSID  = $trusteeSID
	                PrincipalType = $principalType
	                RightName     = 'GenericAll'
	                IsInherited   = $isInherited
	            }
	            continue  # GenericAll encompasses everything, skip other checks
	        }
	        if (($adRights -band [System.DirectoryServices.ActiveDirectoryRights]::GenericWrite) -eq [System.DirectoryServices.ActiveDirectoryRights]::GenericWrite) {
	            $bhAces += @{
	                PrincipalSID  = $trusteeSID
	                PrincipalType = $principalType
	                RightName     = 'GenericWrite'
	                IsInherited   = $isInherited
	            }
	        }
	        if (($adRights -band [System.DirectoryServices.ActiveDirectoryRights]::WriteDacl) -eq [System.DirectoryServices.ActiveDirectoryRights]::WriteDacl) {
	            $bhAces += @{
	                PrincipalSID  = $trusteeSID
	                PrincipalType = $principalType
	                RightName     = 'WriteDacl'
	                IsInherited   = $isInherited
	            }
	        }
	        if (($adRights -band [System.DirectoryServices.ActiveDirectoryRights]::WriteOwner) -eq [System.DirectoryServices.ActiveDirectoryRights]::WriteOwner) {
	            $bhAces += @{
	                PrincipalSID  = $trusteeSID
	                PrincipalType = $principalType
	                RightName     = 'WriteOwner'
	                IsInherited   = $isInherited
	            }
	        }
	        if (($adRights -band [System.DirectoryServices.ActiveDirectoryRights]::WriteProperty) -eq [System.DirectoryServices.ActiveDirectoryRights]::WriteProperty) {
	            if ($objectTypeGuid) {
	                if ($Script:BHPropertyGUIDs.ContainsKey($objectTypeGuid)) {
	                    $rightName = $Script:BHPropertyGUIDs[$objectTypeGuid]
	                    $bhAces += @{
	                        PrincipalSID  = $trusteeSID
	                        PrincipalType = $principalType
	                        RightName     = $rightName
	                        IsInherited   = $isInherited
	                    }
	                }
	            }
	            else {
	                if ($ObjectType -eq 'User') {
	                    $bhAces += @{ PrincipalSID = $trusteeSID; PrincipalType = $principalType; RightName = 'WriteSPN'; IsInherited = $isInherited }
	                    $bhAces += @{ PrincipalSID = $trusteeSID; PrincipalType = $principalType; RightName = 'AddKeyCredentialLink'; IsInherited = $isInherited }
	                }
	                elseif ($ObjectType -eq 'Computer') {
	                    $bhAces += @{ PrincipalSID = $trusteeSID; PrincipalType = $principalType; RightName = 'AddAllowedToAct'; IsInherited = $isInherited }
	                    $bhAces += @{ PrincipalSID = $trusteeSID; PrincipalType = $principalType; RightName = 'AddKeyCredentialLink'; IsInherited = $isInherited }
	                }
	                elseif ($ObjectType -eq 'Group') {
	                    $bhAces += @{ PrincipalSID = $trusteeSID; PrincipalType = $principalType; RightName = 'AddMember'; IsInherited = $isInherited }
	                }
	            }
	        }
	        if (($adRights -band [System.DirectoryServices.ActiveDirectoryRights]::Self) -eq [System.DirectoryServices.ActiveDirectoryRights]::Self) {
	            if ($ObjectType -eq 'Group') {
	                $bhAces += @{
	                    PrincipalSID  = $trusteeSID
	                    PrincipalType = $principalType
	                    RightName     = 'AddSelf'
	                    IsInherited   = $isInherited
	                }
	            }
	        }
	        if (($adRights -band [System.DirectoryServices.ActiveDirectoryRights]::ExtendedRight) -eq [System.DirectoryServices.ActiveDirectoryRights]::ExtendedRight) {
	            if ($objectTypeGuid) {
	                if ($Script:BHExtendedRightGUIDs.ContainsKey($objectTypeGuid)) {
	                    $rightName = $Script:BHExtendedRightGUIDs[$objectTypeGuid]
	                    $bhAces += @{
	                        PrincipalSID  = $trusteeSID
	                        PrincipalType = $principalType
	                        RightName     = $rightName
	                        IsInherited   = $isInherited
	                    }
	                }
	            }
	            else {
	                $bhAces += @{
	                    PrincipalSID  = $trusteeSID
	                    PrincipalType = $principalType
	                    RightName     = 'AllExtendedRights'
	                    IsInherited   = $isInherited
	                }
	            }
	        }
	        if (($adRights -band [System.DirectoryServices.ActiveDirectoryRights]::ReadProperty) -eq [System.DirectoryServices.ActiveDirectoryRights]::ReadProperty) {
	            if ($objectTypeGuid -eq 'e362ed86-b728-0842-b27d-2dea7a9df218') {
	                $bhAces += @{
	                    PrincipalSID  = $trusteeSID
	                    PrincipalType = $principalType
	                    RightName     = 'ReadLAPSPassword'
	                    IsInherited   = $isInherited
	                }
	            }
	        }
	    }
	}
	catch {
	}
	$uniqueAces = @()
	$seen = @{}
	foreach ($ace in $bhAces) {
	    $key = "$($ace.PrincipalSID)|$($ace.RightName)"
	    if (-not $seen.ContainsKey($key)) {
	        $seen[$key] = $true
	        $uniqueAces += $ace
	    }
	}
	return $uniqueAces
}
function Get-BHPrincipalType {
	param([string]$SID)
	if (-not $SID) { return 'Base' }
	if ($SID -match '^S-1-5-32-') { return 'Group' }  # Builtin groups
	if ($SID -match '-5\d{2}$') {
	    $rid = [int]($SID -split '-')[-1]
	    if ($rid -eq 500 -or $rid -eq 501 -or $rid -eq 502) {
	        return 'User'  # Administrator, Guest, krbtgt
	    }
	    elseif ($rid -ge 512 -and $rid -le 527) {
	        return 'Group'  # Domain groups (DA, DU, DC, etc.)
	    }
	}
	if ($SID -match '-\d{4,}$') {
	    $rid = [int]($SID -split '-')[-1]
	    if ($rid -ge 1000) {
	        return 'Base'
	    }
	}
	return 'Base'
}
function Collect-BHDomain {
	param(
	    [string]$DomainDN,
	    [string]$DomainSID,
	    [string]$Domain,
	    [string]$Server,
	    [System.Management.Automation.PSCredential]$Credential
	)
	$connectionParams = @{}
	if ($Domain) { $connectionParams['Domain'] = $Domain }
	if ($Server) { $connectionParams['Server'] = $Server }
	if ($Credential) { $connectionParams['Credential'] = $Credential }
	$escapedDomainDN = Escape-LDAPFilterDN -DistinguishedName $DomainDN
	$domainObj = @(Get-DomainObject -LDAPFilter "(distinguishedName=$escapedDomainDN)" @connectionParams)[0]
	if (-not $domainObj) { return @() }
	$domainName = $Script:LDAPContext.Domain.ToUpper()
	$functionalLevel = switch ($domainObj.'msDS-Behavior-Version') {
	    0 { 'Windows 2000' }
	    1 { 'Windows 2003 Interim' }
	    2 { 'Windows 2003' }
	    3 { 'Windows 2008' }
	    4 { 'Windows 2008 R2' }
	    5 { 'Windows 2012' }
	    6 { 'Windows 2012 R2' }
	    7 { 'Windows 2016' }
	    10 { 'Windows 2025' }
	    default { 'Unknown' }
	}
	$trusts = @()
	$trustObjects = Get-DomainObject -LDAPFilter "(objectClass=trustedDomain)" @connectionParams
	foreach ($trust in $trustObjects) {
	    $trustDirInt = switch ($trust.trustDirection) {
	        'Disabled'      { 0 }
	        'Inbound'       { 1 }
	        'Outbound'      { 2 }
	        'Bidirectional' { 3 }
	        default         { 0 }
	    }
	    $trustTypeInt = switch ($trust.trustType) {
	        'Windows NT (Downlevel)'      { 1 }
	        'Active Directory (Uplevel)'  { 2 }
	        'MIT Kerberos Realm'          { 3 }
	        'DCE'                         { 4 }
	        default                       { 2 }
	    }
	    $attrFlags = @($trust.trustAttributes)
	    $trusts += @{
	        TargetDomainSid     = if ($trust.securityIdentifier) { Convert-SidToString -SidInput $trust.securityIdentifier } else { "" }
	        TargetDomainName    = $trust.name.ToUpper()
	        IsTransitive        = ($attrFlags -notcontains 'NON_TRANSITIVE')
	        TrustDirection      = $trustDirInt
	        TrustType           = $trustTypeInt
	        SidFilteringEnabled = ($attrFlags -contains 'QUARANTINED_DOMAIN')
	    }
	}
	$childObjects = @()
	if ($Script:ParentDNToChildren -and $Script:ParentDNToChildren.ContainsKey($DomainDN)) {
	    $childObjects = @($Script:ParentDNToChildren[$DomainDN])
	}
	$gpoLinks = @()
	if ($domainObj.gPLink) {
	    $gpLinkString = $domainObj.gPLink
	    $linkMatches = [regex]::Matches($gpLinkString, '\[LDAP://([^\]]+);(\d)\]')
	    foreach ($match in $linkMatches) {
	        $gpoDN = $match.Groups[1].Value
	        $enforced = $match.Groups[2].Value -eq '2'
	        if ($gpoDN -match '\{([A-Fa-f0-9-]+)\}') {
	            $gpoGuid = $Matches[1].ToUpper()
	            $gpoLinks += @{
	                GUID       = $gpoGuid
	                IsEnforced = $enforced
	            }
	        }
	    }
	}
	return @{
	    ObjectIdentifier = $DomainSID
	    Properties       = @{
	        name              = $domainName
	        domain            = $domainName
	        domainsid         = $DomainSID
	        distinguishedname = $DomainDN
	        description       = if ($domainObj.description) { $domainObj.description } else { $null }
	        functionallevel   = $functionalLevel
	        highvalue         = $true
	        whencreated       = ConvertTo-UnixTimestamp $domainObj.whenCreated
	    }
	    Trusts           = $trusts
	    ChildObjects     = $childObjects
	    Links            = $gpoLinks
	    Aces             = @(ConvertTo-BHAces -DistinguishedName $DomainDN -ObjectType 'Domain' @connectionParams)
	    IsDeleted        = $false
	}
}
function Collect-BHUsers {
	param(
	    [string]$DomainSID,
	    [switch]$CollectACLs,
	    [string]$Domain,
	    [string]$Server,
	    [System.Management.Automation.PSCredential]$Credential
	)
	$connectionParams = @{}
	if ($Domain) { $connectionParams['Domain'] = $Domain }
	if ($Server) { $connectionParams['Server'] = $Server }
	if ($Credential) { $connectionParams['Credential'] = $Credential }
	$domainName = $Script:LDAPContext.Domain.ToUpper()
	$users = Get-DomainUser @connectionParams
	$bhUsers = @()
	foreach ($user in $users) {
	    $sid = $null
	    if ($user.objectSid) {
	        $sid = Convert-SidToString -SidInput $user.objectSid
	        if (-not $sid) {
	            continue
	        }
	    }
	    else {
	        continue
	    }
	    $uac = Get-SafeInt -Value $user.userAccountControl -Default 0
	    $spns = @()
	    if ($user.servicePrincipalName) {
	        if ($user.servicePrincipalName -is [array]) {
	            $spns = $user.servicePrincipalName
	        }
	        else {
	            $spns = @($user.servicePrincipalName)
	        }
	    }
	    $sidHistory = @()
	    if ($user.sIDHistory) {
	        $historyItems = if ($user.sIDHistory -is [array]) { $user.sIDHistory } else { @($user.sIDHistory) }
	        foreach ($histSid in $historyItems) {
	            $convertedSid = Convert-SidToString -SidInput $histSid
	            if ($convertedSid) {
	                $sidHistory += $convertedSid
	            }
	        }
	    }
	    $allowedToDelegate = @()
	    if ($user.'msDS-AllowedToDelegateTo') {
	        $delegateTargets = $user.'msDS-AllowedToDelegateTo'
	        if ($delegateTargets -isnot [array]) { $delegateTargets = @($delegateTargets) }
	        foreach ($target in $delegateTargets) {
	            $resolved = Resolve-SPNToTarget -SPN $target
	            if ($resolved) {
	                $allowedToDelegate += $resolved
	            } else {
	                $allowedToDelegate += @{ ObjectIdentifier = $target; ObjectType = 'Computer' }
	            }
	        }
	    }
	    $spnTargets = @()
	    foreach ($spn in $spns) {
	        $resolved = Resolve-SPNToTarget -SPN $spn
	        if ($resolved) {
	            $port = 0
	            if ($spn -match ':(\d+)') { $port = [int]$Matches[1] }
	            $spnTargets += @{
	                ObjectIdentifier = $resolved.ObjectIdentifier
	                ObjectType       = $resolved.ObjectType
	                Port             = $port
	            }
	        }
	    }
	    $primaryGroupRid = Get-SafeInt -Value $user.primaryGroupID -Default 513
	    $primaryGroupSID = "$DomainSID-$primaryGroupRid"
	    $bhUser = @{
	        ObjectIdentifier   = $sid
	        Properties         = @{
	            name                    = "$($user.sAMAccountName)@$domainName"
	            domain                  = $domainName
	            domainsid               = $DomainSID
	            distinguishedname       = $user.distinguishedName
	            highvalue               = $false
	            samaccountname          = $user.sAMAccountName
	            description             = if ($user.description) { $user.description } else { $null }
	            whencreated             = ConvertTo-UnixTimestamp $user.whenCreated
	            sensitive               = ($uac -band 0x100000) -ne 0  # NOT_DELEGATED
	            dontreqpreauth          = ($uac -band 0x400000) -ne 0  # DONT_REQ_PREAUTH
	            passwordnotreqd         = ($uac -band 0x20) -ne 0     # PASSWD_NOTREQD
	            unconstraineddelegation = ($uac -band 0x80000) -ne 0  # TRUSTED_FOR_DELEGATION
	            pwdneverexpires         = ($uac -band 0x10000) -ne 0  # DONT_EXPIRE_PASSWORD
	            enabled                 = ($uac -band 0x2) -eq 0      # ACCOUNTDISABLE
	            trustedtoauth           = ($uac -band 0x1000000) -ne 0 # TRUSTED_TO_AUTH_FOR_DELEGATION
	            lastlogon               = ConvertTo-UnixTimestamp $user.lastLogon
	            lastlogontimestamp      = ConvertTo-UnixTimestamp $user.lastLogonTimestamp
	            pwdlastset              = ConvertTo-UnixTimestamp $user.pwdLastSet
	            serviceprincipalnames   = $spns
	            hasspn                  = @($spns).Count -gt 0
	            displayname             = $user.displayName
	            email                   = $user.mail
	            title                   = $user.title
	            homedirectory           = $user.homeDirectory
	            userpassword            = $null
	            unixpassword            = $null
	            unicodepassword         = $null
	            sfupassword             = $null
	            logonscript             = $user.scriptPath
	            admincount              = (Get-SafeInt -Value $user.adminCount) -gt 0
	            sidhistory              = $sidHistory
	        }
	        PrimaryGroupSID    = $primaryGroupSID
	        AllowedToDelegate  = $allowedToDelegate
	        HasSIDHistory      = @($sidHistory).Count -gt 0
	        SPNTargets         = $spnTargets
	        Aces               = @()
	        IsDeleted          = $false
	    }
	    if ($CollectACLs) {
	        $bhUser.Aces = @(ConvertTo-BHAces -DistinguishedName $user.distinguishedName -ObjectType 'User' @connectionParams)
	    }
	    $bhUsers += $bhUser
	}
	return $bhUsers
}
function Collect-BHGroups {
	param(
	    [string]$DomainSID,
	    [switch]$CollectACLs,
	    [string]$Domain,
	    [string]$Server,
	    [System.Management.Automation.PSCredential]$Credential
	)
	$connectionParams = @{}
	if ($Domain) { $connectionParams['Domain'] = $Domain }
	if ($Server) { $connectionParams['Server'] = $Server }
	if ($Credential) { $connectionParams['Credential'] = $Credential }
	$domainName = $Script:LDAPContext.Domain.ToUpper()
	$groups = Get-DomainGroup @connectionParams
	$bhGroups = @()
	foreach ($group in $groups) {
	    $sid = $null
	    if ($group.objectSid) {
	        $sid = Convert-SidToString -SidInput $group.objectSid
	        if (-not $sid) {
	            continue
	        }
	    }
	    else {
	        continue
	    }
	    $highValueRids = @('-512', '-519', '-518', '-516', '-498', '-500')
	    $highValue = $false
	    foreach ($rid in $highValueRids) {
	        if ($sid.EndsWith($rid)) {
	            $highValue = $true
	            break
	        }
	    }
	    $members = @()
	    if ($group.member) {
	        $memberDNs = if ($group.member -is [array]) { $group.member } else { @($group.member) }
	        foreach ($memberDN in $memberDNs) {
	            if ($Script:DNToIdentityCache -and $Script:DNToIdentityCache.ContainsKey($memberDN)) {
	                $members += $Script:DNToIdentityCache[$memberDN]
	            } else {
	                $escapedMemberDN = Escape-LDAPFilterDN -DistinguishedName $memberDN
	                $memberObj = @(Get-DomainObject -LDAPFilter "(distinguishedName=$escapedMemberDN)" -Properties objectSid,objectClass @connectionParams)[0]
	                if ($memberObj -and $memberObj.objectSid) {
	                    $memberSID = Convert-SidToString -SidInput $memberObj.objectSid
	                    if ($memberSID) {
	                        $members += @{
	                            ObjectIdentifier = $memberSID
	                            ObjectType       = Get-BHObjectType -ObjectClass $memberObj.objectClass
	                        }
	                    }
	                }
	            }
	        }
	    }
	    $bhGroup = @{
	        ObjectIdentifier = $sid
	        Properties       = @{
	            name              = "$($group.sAMAccountName)@$domainName"
	            domain            = $domainName
	            domainsid         = $DomainSID
	            distinguishedname = $group.distinguishedName
	            highvalue         = $highValue
	            samaccountname    = $group.sAMAccountName
	            description       = if ($group.description) { $group.description } else { $null }
	            whencreated       = ConvertTo-UnixTimestamp $group.whenCreated
	            admincount        = (Get-SafeInt -Value $group.adminCount) -gt 0
	        }
	        Members          = $members
	        Aces             = @()
	        IsDeleted        = $false
	    }
	    if ($CollectACLs) {
	        $bhGroup.Aces = @(ConvertTo-BHAces -DistinguishedName $group.distinguishedName -ObjectType 'Group' @connectionParams)
	    }
	    $bhGroups += $bhGroup
	}
	return $bhGroups
}
function Collect-BHComputers {
	param(
	    [string]$DomainSID,
	    [switch]$CollectACLs,
	    [string]$Domain,
	    [string]$Server,
	    [System.Management.Automation.PSCredential]$Credential
	)
	$connectionParams = @{}
	if ($Domain) { $connectionParams['Domain'] = $Domain }
	if ($Server) { $connectionParams['Server'] = $Server }
	if ($Credential) { $connectionParams['Credential'] = $Credential }
	$domainName = $Script:LDAPContext.Domain.ToUpper()
	$computers = Get-DomainComputer @connectionParams
	$bhComputers = @()
	foreach ($computer in $computers) {
	    $sid = $null
	    if ($computer.objectSid) {
	        $sid = Convert-SidToString -SidInput $computer.objectSid
	        if (-not $sid) {
	            continue
	        }
	    }
	    else {
	        continue
	    }
	    $uac = Get-SafeInt -Value $computer.userAccountControl -Default 0
	    $isDC = ($uac -band 0x2000) -ne 0  # SERVER_TRUST_ACCOUNT
	    $primaryGroupRid = Get-SafeInt -Value $computer.primaryGroupID -Default 515
	    $primaryGroupSID = "$DomainSID-$primaryGroupRid"
	    $allowedToDelegate = @()
	    if ($computer.'msDS-AllowedToDelegateTo') {
	        $delegateTargets = $computer.'msDS-AllowedToDelegateTo'
	        if ($delegateTargets -isnot [array]) { $delegateTargets = @($delegateTargets) }
	        foreach ($target in $delegateTargets) {
	            $resolved = Resolve-SPNToTarget -SPN $target
	            if ($resolved) {
	                $allowedToDelegate += $resolved
	            } else {
	                $allowedToDelegate += @{ ObjectIdentifier = $target; ObjectType = 'Computer' }
	            }
	        }
	    }
	    $allowedToAct = @()
	    if ($computer.'msDS-AllowedToActOnBehalfOfOtherIdentity') {
	        try {
	            $sd = New-Object System.DirectoryServices.ActiveDirectorySecurity
	            $sd.SetSecurityDescriptorBinaryForm($computer.'msDS-AllowedToActOnBehalfOfOtherIdentity')
	            foreach ($ace in $sd.Access) {
	                $sidValue = $null
	                $identRef = $ace.IdentityReference
	                if ($identRef -is [System.Security.Principal.SecurityIdentifier]) {
	                    $sidValue = $identRef.Value
	                } else {
	                    $sidValue = ConvertTo-SID -Identity $identRef.Value
	                }
	                if ($sidValue) {
	                    $allowedToAct += @{
	                        ObjectIdentifier = $sidValue
	                        ObjectType       = 'Unknown'
	                    }
	                }
	            }
	        }
	        catch {
	        }
	    }
	    $sidHistory = @()
	    if ($computer.sIDHistory) {
	        $historyItems = if ($computer.sIDHistory -is [array]) { $computer.sIDHistory } else { @($computer.sIDHistory) }
	        foreach ($histSid in $historyItems) {
	            $convertedSid = Convert-SidToString -SidInput $histSid
	            if ($convertedSid) {
	                $sidHistory += $convertedSid
	            }
	        }
	    }
	    $bhComputer = @{
	        ObjectIdentifier    = $sid
	        Properties          = @{
	            name                    = "$($computer.dNSHostName)".ToUpper()
	            domain                  = $domainName
	            domainsid               = $DomainSID
	            distinguishedname       = $computer.distinguishedName
	            highvalue               = $isDC
	            samaccountname          = $computer.sAMAccountName
	            description             = if ($computer.description) { $computer.description } else { $null }
	            whencreated             = ConvertTo-UnixTimestamp $computer.whenCreated
	            operatingsystem         = $computer.operatingSystem
	            enabled                 = ($uac -band 0x2) -eq 0
	            unconstraineddelegation = ($uac -band 0x80000) -ne 0
	            trustedtoauth           = ($uac -band 0x1000000) -ne 0
	            lastlogon               = ConvertTo-UnixTimestamp $computer.lastLogon
	            lastlogontimestamp      = ConvertTo-UnixTimestamp $computer.lastLogonTimestamp
	            pwdlastset              = ConvertTo-UnixTimestamp $computer.pwdLastSet
	            serviceprincipalnames   = if ($computer.servicePrincipalName) { @($computer.servicePrincipalName) } else { @() }
	            haslaps                 = ($null -ne $computer.'ms-Mcs-AdmPwdExpirationTime') -or ($null -ne $computer.'msLAPS-PasswordExpirationTime')
	            sidhistory              = $sidHistory
	            isdc                    = $isDC
	        }
	        PrimaryGroupSID     = $primaryGroupSID
	        AllowedToDelegate   = $allowedToDelegate
	        AllowedToAct        = $allowedToAct
	        HasSIDHistory       = @($sidHistory).Count -gt 0
	        Sessions            = @{
	            Collected     = $false
	            FailureReason = "Not collected in Phase 1 (LDAP-only)"
	            Results       = @()
	        }
	        PrivilegedSessions  = @{
	            Collected     = $false
	            FailureReason = "Not collected in Phase 1 (LDAP-only)"
	            Results       = @()
	        }
	        RegistrySessions    = @{
	            Collected     = $false
	            FailureReason = "Not collected in Phase 1 (LDAP-only)"
	            Results       = @()
	        }
	        LocalAdmins         = @{
	            Collected     = $false
	            FailureReason = "Not collected in Phase 1 (LDAP-only)"
	            Results       = @()
	        }
	        RemoteDesktopUsers  = @{
	            Collected     = $false
	            FailureReason = "Not collected in Phase 1 (LDAP-only)"
	            Results       = @()
	        }
	        DcomUsers           = @{
	            Collected     = $false
	            FailureReason = "Not collected in Phase 1 (LDAP-only)"
	            Results       = @()
	        }
	        PSRemoteUsers       = @{
	            Collected     = $false
	            FailureReason = "Not collected in Phase 1 (LDAP-only)"
	            Results       = @()
	        }
	        Aces                = @()
	        IsDeleted           = $false
	    }
	    if ($CollectACLs) {
	        $bhComputer.Aces = @(ConvertTo-BHAces -DistinguishedName $computer.distinguishedName -ObjectType 'Computer' @connectionParams)
	    }
	    $bhComputers += $bhComputer
	}
	return $bhComputers
}
function Collect-BHOUs {
	param(
	    [string]$DomainSID,
	    [switch]$CollectACLs,
	    [string]$Domain,
	    [string]$Server,
	    [System.Management.Automation.PSCredential]$Credential
	)
	$connectionParams = @{}
	if ($Domain) { $connectionParams['Domain'] = $Domain }
	if ($Server) { $connectionParams['Server'] = $Server }
	if ($Credential) { $connectionParams['Credential'] = $Credential }
	$domainName = $Script:LDAPContext.Domain.ToUpper()
	$domainDN = $Script:LDAPContext.DomainDN
	$ous = Get-DomainObject -LDAPFilter "(objectClass=organizationalUnit)" @connectionParams
	$bhOUs = @()
	foreach ($ou in $ous) {
	    $ouGuid = $ou.objectGuid.ToString().ToUpper()
	    $childObjects = @()
	    $ouDN = $ou.distinguishedName
	    if ($Script:ParentDNToChildren.ContainsKey($ouDN)) {
	        $childObjects = @($Script:ParentDNToChildren[$ouDN])
	    }
	    $gpoLinks = @()
	    if ($ou.gPLink) {
	        $gpLinkString = $ou.gPLink
	        $linkMatches = [regex]::Matches($gpLinkString, '\[LDAP://([^\]]+);(\d)\]')
	        foreach ($match in $linkMatches) {
	            $gpoDN = $match.Groups[1].Value
	            $enforced = $match.Groups[2].Value -eq '2'
	            if ($gpoDN -match '\{([A-Fa-f0-9-]+)\}') {
	                $gpoGuid = $Matches[1].ToUpper()
	                $gpoLinks += @{
	                    GUID       = $gpoGuid
	                    IsEnforced = $enforced
	                }
	            }
	        }
	    }
	    $bhOU = @{
	        ObjectIdentifier   = $ouGuid
	        Properties         = @{
	            name              = "$($ou.name)@$domainName"
	            domain            = $domainName
	            domainsid         = $DomainSID
	            distinguishedname = $ou.distinguishedName
	            highvalue         = $false
	            description       = if ($ou.description) { $ou.description } else { $null }
	            whencreated       = ConvertTo-UnixTimestamp $ou.whenCreated
	            blocksinheritance = ((Get-SafeInt -Value $ou.gPOptions) -band 1) -ne 0
	        }
	        ChildObjects       = $childObjects
	        Links              = $gpoLinks
	        Aces               = @()
	        IsDeleted          = $false
	    }
	    if ($CollectACLs) {
	        $bhOU.Aces = @(ConvertTo-BHAces -DistinguishedName $ou.distinguishedName -ObjectType 'OU' @connectionParams)
	    }
	    $bhOUs += $bhOU
	}
	return $bhOUs
}
function Collect-BHContainers {
	param(
	    [string]$DomainSID,
	    [switch]$CollectACLs,
	    [string]$Domain,
	    [string]$Server,
	    [System.Management.Automation.PSCredential]$Credential
	)
	$connectionParams = @{}
	if ($Domain) { $connectionParams['Domain'] = $Domain }
	if ($Server) { $connectionParams['Server'] = $Server }
	if ($Credential) { $connectionParams['Credential'] = $Credential }
	$domainName = $Script:LDAPContext.Domain.ToUpper()
	$containers = Get-DomainObject -LDAPFilter "(&(objectClass=container)(!(objectClass=groupPolicyContainer)))" @connectionParams
	$bhContainers = @()
	foreach ($container in $containers) {
	    $containerGuid = $container.objectGuid.ToString().ToUpper()
	    $containerDN = $container.distinguishedName
	    $childObjects = @()
	    if ($Script:ParentDNToChildren.ContainsKey($containerDN)) {
	        $childObjects = @($Script:ParentDNToChildren[$containerDN])
	    }
	    $bhContainer = @{
	        ObjectIdentifier = $containerGuid
	        Properties       = @{
	            name              = "$($container.name)@$domainName"
	            domain            = $domainName
	            domainsid         = $DomainSID
	            distinguishedname = $containerDN
	            highvalue         = $false
	        }
	        ChildObjects     = $childObjects
	        Aces             = @()
	        IsDeleted        = $false
	    }
	    if ($CollectACLs) {
	        $bhContainer.Aces = @(ConvertTo-BHAces -DistinguishedName $containerDN -ObjectType 'Container' @connectionParams)
	    }
	    $bhContainers += $bhContainer
	}
	return $bhContainers
}
function Collect-BHGPOs {
	param(
	    [string]$DomainSID,
	    [switch]$CollectACLs,
	    [string]$Domain,
	    [string]$Server,
	    [System.Management.Automation.PSCredential]$Credential
	)
